DECLARE @DatabaseName sysname = DB_NAME()
DECLARE @DataPath nvarchar(4000)
DECLARE @Sql nvarchar(max)
IF @DatabaseName IN (N'master', N'model', N'msdb', N'tempdb')
BEGIN
THROW 50000, N'Abort: Please select the empty target database first.', 1
END
IF EXISTS (
SELECT 1
FROM sys.objects
WHERE is_ms_shipped = 0
)
OR EXISTS (
SELECT 1
FROM sys.types
WHERE is_user_defined = 1
)
BEGIN
THROW 50003, N'Abort: The selected target database is not empty. Please select an empty target database first.', 1
END
IF ISNULL(CONVERT(int, SERVERPROPERTY(N'FilestreamEffectiveLevel')), 0) < 1
BEGIN
THROW 50001, N'Abort: FILESTREAM is not enabled for this SQL Server instance. Enable FILESTREAM before running this script.', 1
END
SELECT @DataPath =
LEFT(physical_name, LEN(physical_name) - CHARINDEX(N'\', REVERSE(physical_name)) + 1)
FROM sys.database_files
WHERE file_id = 1
IF @DataPath IS NULL
BEGIN
THROW 50002, N'Abort: Could not determine the database data path for the FILESTREAM file.', 1
END
IF NOT EXISTS (
SELECT 1
FROM sys.filegroups
WHERE name = N'FileStreamGroup'
AND type = N'FD'
)
BEGIN
SET @Sql = N'
ALTER DATABASE ' + QUOTENAME(@DatabaseName) + N'
ADD FILEGROUP [FileStreamGroup] CONTAINS FILESTREAM'
EXEC sys.sp_executesql @Sql
END
IF NOT EXISTS (
SELECT 1
FROM sys.database_files
WHERE name = @DatabaseName + N'_FileStream'
)
BEGIN
SET @Sql = N'
ALTER DATABASE ' + QUOTENAME(@DatabaseName) + N'
ADD FILE
(
NAME = N''' + REPLACE(@DatabaseName, N'''', N'''''') + N'_FileStream''
, FILENAME = N''' + REPLACE(@DataPath + @DatabaseName + N'_FileStream', N'''', N'''''') + N'''
)
TO FILEGROUP [FileStreamGroup]'
EXEC sys.sp_executesql @Sql
END
GO
 CREATE TABLE AspNetRoles ( 
Id nvarchar(450) CONSTRAINT PK_AspNetRoles_Id PRIMARY KEY (Id)
, Name nvarchar(256) 
, NormalizedName nvarchar(256) 
, ConcurrencyStamp nvarchar(max) 
, ShowHome bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowHome DEFAULT (1)
, ShowSales bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowSales DEFAULT (1)
, ShowPurchase bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowPurchase DEFAULT (1)
, ShowWarehousing bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowWarehousing DEFAULT (1)
, ShowProduction bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowProduction DEFAULT (1)
, ShowService bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowService DEFAULT (1)
, ShowFinance bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowFinance DEFAULT (1)
, ShowManagement bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowManagement DEFAULT (1)
, ShowCrm bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowCrm DEFAULT (1)
, ShowIntercom bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowIntercom DEFAULT (1)
, ShowEmail bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowEmail DEFAULT (1)
, ShowCalendar bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowCalendar DEFAULT (1)
, ShowPortal bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowPortal DEFAULT (1)
, ShowAdministration bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowAdministration DEFAULT (1)
, ShowHelp bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowHelp DEFAULT (1)
, ShowInfo bit NOT NULL CONSTRAINT DF_AspNetRoles_ShowInfo DEFAULT (1)
, CONSTRAINT CHK_AspNetRoles_Id_ValidChars CHECK (Id <> N'' AND Id COLLATE Latin1_General_100_BIN2 NOT LIKE N'%[^ABCDEFGHIJKLMNOPQRSTUVWXYZ]%')
)
ON [PRIMARY] TEXTIMAGE_ON [PRIMARY]
CREATE UNIQUE NONCLUSTERED INDEX IX_AspNetRoles_NormalizedName 
ON dbo.AspNetRoles(NormalizedName)
WHERE (NormalizedName IS NOT NULL)
