 CREATE TABLE AspNetRoleClaims ( 
Id int IDENTITY(1,1) CONSTRAINT PK_AspNetRoleClaims_Id PRIMARY KEY (Id)
, RoleId nvarchar(450) NOT NULL CONSTRAINT FK_AspNetRoleClaims_RoleId FOREIGN KEY (RoleId) REFERENCES AspNetRoles ON DELETE CASCADE
, ClaimType nvarchar(max) 
, ClaimValue nvarchar(max) 
)
 CREATE TABLE AspNetUsers ( 
Id nvarchar(450) CONSTRAINT PK_AspNetUsers_Id PRIMARY KEY (Id)
, UserName nvarchar(256)  CONSTRAINT UQ_AspNetUsers_UserName UNIQUE (UserName)
, NormalizedUserName nvarchar(256)  CONSTRAINT UQ_AspNetUsers_NormalizedUserName UNIQUE (NormalizedUserName)
, Email nvarchar(256)  CONSTRAINT UQ_AspNetUsers_Email UNIQUE (Email)
, NormalizedEmail nvarchar(256)  CONSTRAINT UQ_AspNetUsers_NormalizedEmail UNIQUE (NormalizedEmail)
, EmailConfirmed bit NOT NULL CONSTRAINT DF_AspNetUsers_EmailConfirmed DEFAULT (0)
, PasswordHash nvarchar(max) 
, ChangePasswordAtNextLogin bit NOT NULL CONSTRAINT DF_AspNetUsers_ChangePasswordAtNextLogin DEFAULT (1)
, SecurityStamp nvarchar(max) 
, ConcurrencyStamp nvarchar(max) 
, PhoneNumber nvarchar(max) 
, PhoneNumberConfirmed bit NOT NULL CONSTRAINT DF_AspNetUsers_PhoneNumberConfirmed DEFAULT (0)
, TwoFactorEnabled bit NOT NULL CONSTRAINT DF_AspNetUsers_TwoFactorEnabled DEFAULT (0)
, LockoutEnd datetimeoffset(7) 
, LockoutEnabled bit NOT NULL CONSTRAINT DF_AspNetUsers_LockoutEnabled DEFAULT (0)
, AccessFailedCount int NOT NULL
, LastName nvarchar(250) 
, FirstName nvarchar(250) 
, Active bit NOT NULL CONSTRAINT DF_AspNetUsers_Active DEFAULT (1)
, EmployeeId int NOT NULL CONSTRAINT UQ_AspNetUsers_EmployeeId UNIQUE (EmployeeId)
, CultureCode nvarchar(5)  CONSTRAINT DF_AspNetUsers_CultureCode DEFAULT ('de-DE')
, RoleId nvarchar(450) NOT NULL CONSTRAINT FK_AspNetUsers_RoleId FOREIGN KEY (RoleId) REFERENCES AspNetRoles CONSTRAINT DF_AspNetUsers_RoleId DEFAULT ('ADMIN')
)
ON [PRIMARY] TEXTIMAGE_ON [PRIMARY];
 CREATE TABLE AspNetUserClaims ( 
Id int IDENTITY(1,1) CONSTRAINT PK_AspNetUserClaims_Id PRIMARY KEY (Id)
, UserId nvarchar(450) NOT NULL CONSTRAINT FK_AspNetUserClaims_AspNetUsers_UserId FOREIGN KEY (UserId) REFERENCES dbo.AspNetUsers(Id) ON DELETE CASCADE
, ClaimType nvarchar(max) 
, ClaimValue nvarchar(max) 
)
ON [PRIMARY] TEXTIMAGE_ON [PRIMARY]
