 CREATE TABLE AuthorizationRolePagePermission ( 
Id int IDENTITY(1,1) CONSTRAINT PK_AuthorizationRolePagePermission_Id PRIMARY KEY (Id)
, RoleId nvarchar(450) NOT NULL CONSTRAINT FK_AuthorizationRolePagePermission_RoleId FOREIGN KEY (RoleId) REFERENCES AspNetRoles CONSTRAINT DF_AuthorizationRolePagePermission_RoleId DEFAULT ('ADMIN')
, PageId nvarchar(100) NOT NULL CONSTRAINT FK_AuthorizationRolePagePermission_PageId FOREIGN KEY (PageId) REFERENCES AuthorizationPage
, CreatePermission bit NOT NULL CONSTRAINT DF_AuthorizationRolePagePermission_CreatePermission DEFAULT (1)
, ReadPermission bit NOT NULL CONSTRAINT DF_AuthorizationRolePagePermission_ReadPermission DEFAULT (1)
, UpdatePermission bit NOT NULL CONSTRAINT DF_AuthorizationRolePagePermission_UpdatePermission DEFAULT (1)
, DeletePermission bit NOT NULL CONSTRAINT DF_AuthorizationRolePagePermission_DeletePermission DEFAULT (1)
, RowVersion rowversion 
, CONSTRAINT UQ_AuthorizationRolePagePermission_RoleIdPageId UNIQUE (RoleId, PageId)
)
