 CREATE TABLE AuthorizationRoleWebApiPermission ( 
Id int IDENTITY(1,1) CONSTRAINT PK_AuthorizationRoleWebApiPermission_Id PRIMARY KEY (Id)
, RoleId nvarchar(450) NOT NULL CONSTRAINT FK_AuthorizationRoleWebApiPermission_RoleId FOREIGN KEY (RoleId) REFERENCES AspNetRoles CONSTRAINT DF_AuthorizationRoleWebApiPermission_RoleId DEFAULT ('ADMIN')
, WebApiId nvarchar(100) NOT NULL CONSTRAINT FK_AuthorizationRoleWebApiPermission_WebApiId FOREIGN KEY (WebApiId) REFERENCES AuthorizationWebApi
, CreatePermission bit NOT NULL CONSTRAINT DF_AuthorizationRoleWebApiPermission_CreatePermission DEFAULT (1)
, ReadPermission bit NOT NULL CONSTRAINT DF_AuthorizationRoleWebApiPermission_ReadPermission DEFAULT (1)
, UpdatePermission bit NOT NULL CONSTRAINT DF_AuthorizationRoleWebApiPermission_UpdatePermission DEFAULT (1)
, DeletePermission bit NOT NULL CONSTRAINT DF_AuthorizationRoleWebApiPermission_DeletePermission DEFAULT (1)
, RowVersion rowversion 
, CONSTRAINT UQ_AuthorizationRoleWebApiPermission_RoleIdWebApiId UNIQUE (RoleId, WebApiId)
)
