 CREATE TABLE SystemDatabaseChangeLog ( 
Id int IDENTITY(1,1) CONSTRAINT PK_SystemDatabaseChangeLog_Id PRIMARY KEY (Id)
, Name nvarchar(255) NOT NULL CONSTRAINT UQ_SystemDatabaseChangeLog_Name UNIQUE (Name)
, ObjectType nvarchar(50) NOT NULL
, ObjectSchema nvarchar(50) NOT NULL CONSTRAINT DF_SystemDatabaseChangeLog_ObjectSchema DEFAULT ('dbo')
, ObjectName nvarchar(50) NOT NULL
, ChangeType nvarchar(50) NOT NULL
, ChangeText nvarchar(max) NOT NULL
, UpdateScript nvarchar(max) NOT NULL
, AppVersion nvarchar(50) NOT NULL
, AppliedOn datetimeoffset(0) NOT NULL CONSTRAINT DF_SystemDatabaseChangeLog_AppliedOn DEFAULT (SYSUTCDATETIME())
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_SystemDatabaseChangeLog_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_SystemDatabaseChangeLog_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, CONSTRAINT CK_DatabaseChangeLog_ObjectType CHECK (ObjectType IN (N'TABLE', N'COLUMN', N'VIEW', N'PROCEDURE', N'FUNCTION', N'INDEX', N'CONSTRAINT', N'TRIGGER', N'DATA'))
, CONSTRAINT CK_DatabaseChangeLog_ChangeType CHECK (ChangeType IN (N'ADD', N'ALTER', N'DROP', N'RENAME', N'REBUILD', N'FIX'))
);
