, RateDate date NOT NULL CONSTRAINT DF_AdminCurrencyRate_RateDate DEFAULT ((CONVERT(date, GETDATE())))
, Rate decimal(19,6) NOT NULL
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_AdminCurrencyRate_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_AdminCurrencyRate_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
