 CREATE TABLE AdminSvg ( 
Id nvarchar(50) CONSTRAINT PK_AdminSvg_Id PRIMARY KEY (Id)
, SvgCode nvarchar(4000) NOT NULL
)
BULK INSERT dbo.AdminSvg FROM 'C:\X-ERP\X-IMPORT\SYSTEM\AdminSvg.CSV' with (FORMAT='CSV',CODEPAGE = '65001', FIELDTERMINATOR = ';', FIRSTROW=2)
 CREATE TABLE WorkspaceRoleMenu ( 
Id nvarchar(50) CONSTRAINT PK_WorkspaceRoleMenu_Id PRIMARY KEY (Id)
, RoleId nvarchar(450) NOT NULL CONSTRAINT FK_WorkspaceRoleMenu_RoleId FOREIGN KEY (RoleId) REFERENCES AspNetRoles
, SystemDesktopId nvarchar(50) NOT NULL CONSTRAINT FK_WorkspaceRoleMenu_SystemDesktopId FOREIGN KEY (SystemDesktopId) REFERENCES SystemDesktop
, GridRowCount int NOT NULL CONSTRAINT DF_WorkspaceRoleMenu_GridRowCount DEFAULT (1)
, GridColumnCount int NOT NULL CONSTRAINT DF_WorkspaceRoleMenu_GridColumnCount DEFAULT (16)
, ShowIcons bit NOT NULL CONSTRAINT DF_WorkspaceRoleMenu_ShowIcons DEFAULT (1)
, ShowText bit NOT NULL CONSTRAINT DF_WorkspaceRoleMenu_ShowText DEFAULT (1)
, FontSize int NOT NULL CONSTRAINT DF_WorkspaceRoleMenu_FontSize DEFAULT (12)
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceRoleMenu_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceRoleMenu_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, CONSTRAINT UQ_WorkspaceRoleMenu_RoleId_SystemDesktopId UNIQUE (RoleId, SystemDesktopId)
, CONSTRAINT CHK_WorkspaceRoleMenu_GridRowCount CHECK (GridRowCount BETWEEN 1 AND 7)
, CONSTRAINT CHK_WorkspaceRoleMenu_GridColumnCount CHECK (GridColumnCount BETWEEN 8 AND 40)
, CONSTRAINT CHK_WorkspaceRoleMenu_Id_ValidChars CHECK (Id <> N'' AND Id COLLATE Latin1_General_100_BIN2 NOT LIKE N'%[^-ABCDEFGHIJKLMNOPQRSTUVWXYZ]%')
)
