, WorkspaceRoleMenuId nvarchar(50) NOT NULL CONSTRAINT FK_WorkspaceRoleMenuButton_WorkspaceRoleMenuId FOREIGN KEY (WorkspaceRoleMenuId) REFERENCES WorkspaceRoleMenu
, RowIndex int NOT NULL
, ColumnIndex int NOT NULL
, AdminRouteId nvarchar(200) NOT NULL CONSTRAINT FK_WorkspaceRoleMenuButton_AdminRouteId FOREIGN KEY (AdminRouteId) REFERENCES AdminRoute
, DisplayText nvarchar(50) NOT NULL
, AdminSvgId nvarchar(50) NOT NULL CONSTRAINT FK_WorkspaceRoleMenuButton_AdminSvgId FOREIGN KEY (AdminSvgId) REFERENCES AdminSvg
, FontColor nvarchar(9) NOT NULL CONSTRAINT DF_WorkspaceRoleMenuButton_FontColor DEFAULT ('#FFFFFF')
, BackgroundColor nvarchar(9) NOT NULL CONSTRAINT DF_WorkspaceRoleMenuButton_BackgroundColor DEFAULT ('#444444')
, FrameColor nvarchar(9) NOT NULL CONSTRAINT DF_WorkspaceRoleMenuButton_FrameColor DEFAULT ('#FFFFFF')
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceRoleMenuButton_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceRoleMenuButton_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, CONSTRAINT CHK_WorkspaceRoleMenuButton_RowIndex CHECK (RowIndex BETWEEN 1 AND 8)
, CONSTRAINT CHK_WorkspaceRoleMenuButton_ColumnIndex CHECK (ColumnIndex BETWEEN 1 AND 40)
, CONSTRAINT UQ_WorkspaceRoleMenuButton_WorkspaceRoleMenuId_RowIndex_ColumnIndex UNIQUE (WorkspaceRoleMenuId, RowIndex, ColumnIndex)
)
