, UserId nvarchar(450) NOT NULL CONSTRAINT FK_WorkspaceUserColumnSetting_UserId FOREIGN KEY (UserId) REFERENCES AspNetUsers
, GridKey nvarchar(50) NOT NULL
, GridLayout nvarchar(4000) NOT NULL
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceUserColumnSetting_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceUserColumnSetting_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
)
CREATE NONCLUSTERED INDEX IDX_WorkspaceUserColumnSetting_UserId ON WorkspaceUserColumnSetting (UserId)
 CREATE TABLE WorkspaceUserFieldSetting ( 
