, PageKey nvarchar(200) NOT NULL
, FieldKey nvarchar(200) NOT NULL
, IsVisible bit NOT NULL CONSTRAINT DF_WorkspaceUserFieldSetting_IsVisible DEFAULT (1)
, DisplayOrder int 
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceUserFieldSetting_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_WorkspaceUserFieldSetting_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
)
CREATE NONCLUSTERED INDEX IDX_WorkspaceUserFieldSetting_UserId ON WorkspaceUserFieldSetting (UserId)
