, ReceivedDateTime datetimeoffset(0) 
, SenderName nvarchar(255) 
, SenderEmail nvarchar(255) NOT NULL
, Receiver nvarchar(1000) 
, Cc nvarchar(1000) 
, Bcc nvarchar(1000) 
, Subject nvarchar(255) 
, BodyHtml nvarchar(max) 
, BodyHtmlSent nvarchar(max) 
, BodyText nvarchar(max) 
