CREATE NONCLUSTERED INDEX IX_Email_Account_Folder_Received ON Email (EmailAccountId, EmailFolderId, ReceivedDateTime DESC) INCLUDE (SenderName, SenderEmail, Subject, Seen, Done, PrioHigh) WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_Email_Account_Folder_Sent ON Email (EmailAccountId, EmailFolderId, SentDateTime DESC) INCLUDE (SenderName, SenderEmail, Subject, Seen, Done, PrioHigh) WHERE IsSent = 1 WITH (DATA_COMPRESSION = PAGE);
