 CREATE TABLE ArticleTemplate ( 
Id int IDENTITY(1,1) CONSTRAINT PK_ArticleTemplate_Id PRIMARY KEY (Id)
, Name nvarchar(50) NOT NULL CONSTRAINT UQ_ArticleTemplate_Name UNIQUE (Name)
, ArticleTypeId nvarchar(20) NOT NULL CONSTRAINT FK_ArticleTemplate_ArticleTypeId FOREIGN KEY (ArticleTypeId) REFERENCES ArticleType
, IsEndProduct bit NOT NULL CONSTRAINT DF_ArticleTemplate_IsEndProduct DEFAULT (0)
, IsProductionStep bit NOT NULL CONSTRAINT DF_ArticleTemplate_IsProductionStep DEFAULT (0)
, IsProductionTime bit NOT NULL CONSTRAINT DF_ArticleTemplate_IsProductionTime DEFAULT (0)
, IsPrepayment bit NOT NULL CONSTRAINT DF_ArticleTemplate_IsPrepayment DEFAULT (0)
, Warehousing bit NOT NULL CONSTRAINT DF_ArticleTemplate_Warehousing DEFAULT (0)
, WithMacro bit NOT NULL CONSTRAINT DF_ArticleTemplate_WithMacro DEFAULT (0)
, WithSet bit NOT NULL CONSTRAINT DF_ArticleTemplate_WithSet DEFAULT (0)
, WithAccessory bit NOT NULL CONSTRAINT DF_ArticleTemplate_WithAccessory DEFAULT (0)
, IndividualizationTypeId nvarchar(6) NOT NULL CONSTRAINT FK_ArticleTemplate_IndividualizationTypeId FOREIGN KEY (IndividualizationTypeId) REFERENCES ArticleIndividualizationType CONSTRAINT DF_ArticleTemplate_IndividualizationTypeId DEFAULT ('None')
, SalesArticle bit NOT NULL CONSTRAINT DF_ArticleTemplate_SalesArticle DEFAULT (0)
, PurchaseArticle bit NOT NULL CONSTRAINT DF_ArticleTemplate_PurchaseArticle DEFAULT (0)
, ProcurementTypeId nvarchar(4) NOT NULL CONSTRAINT FK_ArticleTemplate_ProcurementTypeId FOREIGN KEY (ProcurementTypeId) REFERENCES ArticleProcurementType CONSTRAINT DF_ArticleTemplate_ProcurementTypeId DEFAULT ('none')
, TransferToPurchase bit NOT NULL CONSTRAINT DF_ArticleTemplate_TransferToPurchase DEFAULT (0)
, UoMId int NOT NULL CONSTRAINT FK_ArticleTemplate_UoMId FOREIGN KEY (UoMId) REFERENCES ArticleUoM
, DecimalPlacesQuantitiesId int NOT NULL CONSTRAINT FK_ArticleTemplate_DecimalPlacesQuantitiesId FOREIGN KEY (DecimalPlacesQuantitiesId) REFERENCES AdminDecimalPlace CONSTRAINT DF_ArticleTemplate_DecimalPlacesQuantitiesId DEFAULT (0)
, PriceUnitId int NOT NULL CONSTRAINT FK_ArticleTemplate_PriceUnitId FOREIGN KEY (PriceUnitId) REFERENCES ArticlePriceUnit CONSTRAINT DF_ArticleTemplate_PriceUnitId DEFAULT (1)
, PercentageMarkup1 decimal(19,6) NOT NULL CONSTRAINT DF_ArticleTemplate_PercentageMarkup1 DEFAULT (0)
, FixedMarkup1 decimal(19,6) NOT NULL CONSTRAINT DF_ArticleTemplate_FixedMarkup1 DEFAULT (0)
, PercentageMarkup2 decimal(19,6) NOT NULL CONSTRAINT DF_ArticleTemplate_PercentageMarkup2 DEFAULT (0)
, FixedMarkup2 decimal(19,6) NOT NULL CONSTRAINT DF_ArticleTemplate_FixedMarkup2 DEFAULT (0)
, Active bit NOT NULL CONSTRAINT DF_ArticleTemplate_Active DEFAULT (1)
, Info nvarchar(200) 
, AutoNumbering bit NOT NULL CONSTRAINT DF_ArticleTemplate_AutoNumbering DEFAULT (0)
, Prefix nvarchar(20) 
, NextNumber int NOT NULL CONSTRAINT DF_ArticleTemplate_NextNumber DEFAULT (1)
, Increment int NOT NULL CONSTRAINT DF_ArticleTemplate_Increment DEFAULT (1)
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_ArticleTemplate_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_ArticleTemplate_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, CONSTRAINT CHK_ArticleTemplate_OnlyOneStructureFlag CHECK ((CAST(WithMacro AS int) + CAST(WithAccessory AS int) + CAST(WithSet AS int)) <= 1) -- Only one structure flag.
, CONSTRAINT CHK_ArticleTemplate_IsEndProduct_Consistency CHECK (ArticleTypeId <> 'ENDPRODUCT' OR (IsEndProduct = 1 AND Warehousing = 1)) -- End product requires warehousing.
, CONSTRAINT CHK_ArticleTemplate_IsProductionStep_Consistency CHECK (ArticleTypeId <> 'PRODUCTION-STEP' OR IsProductionStep = 1) -- Production step required.
, CONSTRAINT CHK_ArticleTemplate_IsProductionTime_Consistency CHECK (ArticleTypeId <> 'PRODUCTION-TIME' OR IsProductionTime = 1) -- Production time required.
, CONSTRAINT CHK_ArticleTemplate_IsPrepayment_Consistency CHECK (ArticleTypeId <> 'PREPAYMENT' OR IsPrepayment = 1) -- Prepayment required.
, CONSTRAINT CHK_ArticleTemplate_Warehousing_Consistency CHECK (ArticleTypeId <> 'WAREHOUSING' OR Warehousing = 1) -- Warehousing required.
, CONSTRAINT CHK_ArticleTemplate_NonWarehousing_Consistency CHECK (ArticleTypeId <> 'NON-WAREHOUSING' OR Warehousing = 0) -- No warehousing allowed.
, CONSTRAINT CHK_ArticleTemplate_OnlyOneArticleKind CHECK ((CAST(IsEndProduct AS int) + CAST(IsProductionStep AS int) + CAST(IsProductionTime AS int) + CAST(IsPrepayment AS int)) <= 1) -- Only one article kind.
, CONSTRAINT CHK_ArticleTemplate_PurchaseTransfer_Consistency CHECK (TransferToPurchase = 0 OR PurchaseArticle = 1) -- Transfer requires purchase.
, CONSTRAINT CHK_ArticleTemplate_Individualization_Warehousing CHECK (IndividualizationTypeId NOT IN ('Serial', 'Batch') OR Warehousing = 1) -- Serial/batch requires warehousing.
)
