 CREATE TABLE ArticleGroup ( 
Id int IDENTITY(1,1) CONSTRAINT PK_ArticleGroup_Id PRIMARY KEY NONCLUSTERED WITH (DATA_COMPRESSION = PAGE) 
, Name nvarchar(50) NOT NULL
, ParentId int CONSTRAINT FK_ArticleGroup_ParentId REFERENCES ArticleGroup(Id)
, HierarchyNode hierarchyid NOT NULL
, HierarchyLevel AS HierarchyNode.GetLevel() PERSISTED
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_ArticleGroup_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_ArticleGroup_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, CONSTRAINT UQ_ArticleGroup_ParentId_Name UNIQUE NONCLUSTERED (ParentId, Name) WITH (DATA_COMPRESSION = PAGE) -- UniqueSiblingName
, CONSTRAINT CHK_ArticleGroup_Name_NotEmpty CHECK (LEN(LTRIM(RTRIM(Name))) > 0) -- NameRequired
, CONSTRAINT UQ_ArticleGroup_HierarchyNode UNIQUE CLUSTERED (HierarchyNode) -- UniqueTreePath
, CONSTRAINT CHK_ArticleGroup_Id_NotEqual_ParentId CHECK (Id <> ParentId) -- NoSelfParent
, CONSTRAINT CHK_ArticleGroup_Root_ParentId CHECK (HierarchyNode <> hierarchyid::GetRoot() OR ParentId IS NULL) -- RootHasNoParent
)
WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_ArticleGroup_ParentId_HierarchyNode ON dbo.ArticleGroup (ParentId, HierarchyNode) INCLUDE (Id, Name, HierarchyLevel) WITH (DATA_COMPRESSION = PAGE);
INSERT INTO ArticleGroup (Name, HierarchyNode) VALUES (N'Standard', hierarchyid::GetRoot());
 CREATE TABLE Article ( 
Id nvarchar(30) CONSTRAINT PK_Article_Id PRIMARY KEY (Id)
, ArticleTypeId nvarchar(20)  CONSTRAINT FK_Article_ArticleTypeId FOREIGN KEY (ArticleTypeId) REFERENCES ArticleType
, Name1 nvarchar(100) NOT NULL
, Name2 nvarchar(100) 
, Matchcode nvarchar(50) NOT NULL
, ArticleGroupId int NOT NULL CONSTRAINT FK_Article_ArticleGroupId FOREIGN KEY (ArticleGroupId) REFERENCES ArticleGroup CONSTRAINT DF_Article_ArticleGroupId DEFAULT (1)
, UoMId int NOT NULL CONSTRAINT FK_Article_UoMId FOREIGN KEY (UoMId) REFERENCES ArticleUoM CONSTRAINT DF_Article_UoMId DEFAULT (1)
, DecimalPlacesQuantitiesId int NOT NULL CONSTRAINT FK_Article_DecimalPlacesQuantitiesId FOREIGN KEY (DecimalPlacesQuantitiesId) REFERENCES AdminDecimalPlace CONSTRAINT DF_Article_DecimalPlacesQuantitiesId DEFAULT (0)
, Warehousing bit NOT NULL CONSTRAINT DF_Article_Warehousing DEFAULT (0)
, Active bit NOT NULL CONSTRAINT DF_Article_Active DEFAULT (1)
, Favorite bit NOT NULL CONSTRAINT DF_Article_Favorite DEFAULT (1)
, PriceUnitId int NOT NULL CONSTRAINT FK_Article_PriceUnitId FOREIGN KEY (PriceUnitId) REFERENCES ArticlePriceUnit CONSTRAINT DF_Article_PriceUnitId DEFAULT (1)
, ManufacturerId int 
, ManufacturerOrderNumber nvarchar(30) 
, WarehouseInfoId int 
, Shop bit NOT NULL CONSTRAINT DF_Article_Shop DEFAULT (0)
, Printing bit NOT NULL CONSTRAINT DF_Article_Printing DEFAULT (1)
, Weight decimal(19,6) 
, Length decimal(19,6) 
, Width decimal(19,6) 
, Height decimal(19,6) 
, Volume decimal(19,6) 
, Content decimal(19,6) 
, ContentUoMId int  CONSTRAINT FK_Article_ContentUoMId FOREIGN KEY (ContentUoMId) REFERENCES ArticleUoM
, Gtin nvarchar(18) 
, SalesArticle bit NOT NULL CONSTRAINT DF_Article_SalesArticle DEFAULT (1)
, SalesFinanceGroupId int NOT NULL CONSTRAINT DF_Article_SalesFinanceGroupId DEFAULT (1)
, LotSize decimal(19,6) NOT NULL CONSTRAINT DF_Article_LotSize DEFAULT (0)
, MinimumQuantity decimal(19,6) NOT NULL CONSTRAINT DF_Article_MinimumQuantity DEFAULT (0)
, DeliveryTime int NOT NULL CONSTRAINT DF_Article_DeliveryTime DEFAULT (0)
, PurchaseArticle bit NOT NULL CONSTRAINT DF_Article_PurchaseArticle DEFAULT (1)
, TransferToPurchase bit NOT NULL CONSTRAINT DF_Article_TransferToPurchase DEFAULT (1)
, ProcurementFinanceGroupId int NOT NULL CONSTRAINT DF_Article_ProcurementFinanceGroupId DEFAULT (3)
, ProcurementTypeId nvarchar(4) NOT NULL CONSTRAINT FK_Article_ProcurementTypeId FOREIGN KEY (ProcurementTypeId) REFERENCES ArticleProcurementType CONSTRAINT DF_Article_ProcurementTypeId DEFAULT ('none')
, ProcurementTime int NOT NULL CONSTRAINT DF_Article_ProcurementTime DEFAULT (1)
, StandardSupplierId int 
, StandardWarehouseId int 
, NegativeInventoryAllowed bit NOT NULL CONSTRAINT DF_Article_NegativeInventoryAllowed DEFAULT (0)
, IndividualizationTypeId nvarchar(6) NOT NULL CONSTRAINT FK_Article_IndividualizationTypeId FOREIGN KEY (IndividualizationTypeId) REFERENCES ArticleIndividualizationType CONSTRAINT DF_Article_IndividualizationTypeId DEFAULT ('None')
, WithMacro bit NOT NULL CONSTRAINT DF_Article_WithMacro DEFAULT (0)
, WithSet bit NOT NULL CONSTRAINT DF_Article_WithSet DEFAULT (0)
, WithAccessory bit NOT NULL CONSTRAINT DF_Article_WithAccessory DEFAULT (0)
, IsEndProduct bit NOT NULL CONSTRAINT DF_Article_IsEndProduct DEFAULT (0)
, IsProductionStep bit NOT NULL CONSTRAINT DF_Article_IsProductionStep DEFAULT (0)
, IsProductionTime bit NOT NULL CONSTRAINT DF_Article_IsProductionTime DEFAULT (0)
, IsPrepayment bit NOT NULL CONSTRAINT DF_Article_IsPrepayment DEFAULT (0)
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_Article_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_Article_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, SysStartTime DATETIME2(0) GENERATED ALWAYS AS ROW START NOT NULL
, SysEndTime DATETIME2(0) GENERATED ALWAYS AS ROW END NOT NULL
, PERIOD FOR SYSTEM_TIME (SysStartTime, SysEndTime)
, CONSTRAINT CHK_Article_Id_ValidChars CHECK (LEN(Id) > 0 AND Id COLLATE Latin1_General_CS_AS NOT LIKE '%[^ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._/-]%')
, CONSTRAINT CHK_Article_Warehousing_StandardWarehouse CHECK (Warehousing = 0 OR (Warehousing = 1 AND StandardWarehouseId IS NOT NULL))
)
WITH (
SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.ArticleHistory)
, DATA_COMPRESSION = PAGE
);
CREATE NONCLUSTERED INDEX IX_Article_Favorite1_Active1 ON Article (ArticleGroupId, Matchcode, Id) INCLUDE (Name1, Name2, Warehousing) WHERE Favorite = 1 AND Active = 1 WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_Article_Favorite0_Active1 ON Article (ArticleGroupId, Id) INCLUDE (Matchcode, Name1, Name2, Warehousing) WHERE Favorite = 0 AND Active = 1 WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_Article_Favorite0_Active0 ON Article (ArticleGroupId, Id) INCLUDE (Matchcode, Name1, Name2, Warehousing) WHERE Favorite = 0 AND Active = 0 WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_Article_ManufacturerId ON Article (ManufacturerId) WHERE ManufacturerId IS NOT NULL WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_Article_StandardSupplierId ON Article (StandardSupplierId) WHERE StandardSupplierId IS NOT NULL WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_Article_StandardWarehouseId ON Article (StandardWarehouseId) WHERE StandardWarehouseId IS NOT NULL WITH (DATA_COMPRESSION = PAGE);
