 CREATE TABLE ArticlePriceCalculation ( 
ArticleId nvarchar(30) CONSTRAINT PK_ArticlePriceCalculation_ArticleId PRIMARY KEY (ArticleId) CONSTRAINT FK_ArticlePriceCalculation_ArticleId FOREIGN KEY (ArticleId) REFERENCES Article ON DELETE CASCADE
, ProcurementPrice decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_ProcurementPrice DEFAULT (0)
, Factor decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_Factor DEFAULT (1)
, WarehouseCost decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_WarehouseCost DEFAULT (0)
, OverheadCost decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_OverheadCost DEFAULT (0)
, OtherCost decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_OtherCost DEFAULT (0)
, ChangeInValue decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_ChangeInValue DEFAULT (0)
, CostPrice AS (CAST(ROUND((ProcurementPrice * Factor + WarehouseCost + OverheadCost + OtherCost + ChangeInValue), 2) AS decimal(19,2))) PERSISTED
, PercentageMarkup1 decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_PercentageMarkup1 DEFAULT (0)
, FixedMarkup1 decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_FixedMarkup1 DEFAULT (0)
, IntermediateCalculatedSalesPrice AS (CAST(ROUND(((ProcurementPrice * Factor + WarehouseCost + OverheadCost + OtherCost + ChangeInValue) * (1 + PercentageMarkup1 / 100.0)) + FixedMarkup1, 2) AS decimal(19,2))) PERSISTED
, PercentageMarkup2 decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_PercentageMarkup2 DEFAULT (0)
, FixedMarkup2 decimal(19,6) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_FixedMarkup2 DEFAULT (0)
, CalculatedSalesPrice AS (CAST(ROUND(((((ProcurementPrice * Factor + WarehouseCost + OverheadCost + OtherCost + ChangeInValue) * (1 + PercentageMarkup1 / 100.0)) + FixedMarkup1) * (1 + PercentageMarkup2 / 100.0) + FixedMarkup2), 2) AS decimal(19,2))) PERSISTED
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_ArticlePriceCalculation_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
)
