 CREATE TABLE WarehouseBinLocation ( 
Id int IDENTITY(1,1) CONSTRAINT PK_WarehouseBinLocation_Id PRIMARY KEY NONCLUSTERED WITH (DATA_COMPRESSION = PAGE) 
, WarehouseId int NOT NULL CONSTRAINT FK_WarehouseBinLocation_WarehouseId FOREIGN KEY (WarehouseId) REFERENCES Warehouse(Id)
, Name nvarchar(50) NOT NULL
, ParentId int 
, HierarchyNode hierarchyid NOT NULL
, HierarchyLevel AS HierarchyNode.GetLevel() PERSISTED
, CONSTRAINT UQ_WarehouseBinLocation_WarehouseId_ParentId_Name UNIQUE NONCLUSTERED (WarehouseId, ParentId, Name)  WITH (DATA_COMPRESSION = PAGE) -- UniqueSiblingNamePerWarehouse
, CONSTRAINT CHK_WarehouseBinLocation_Name_NotEmpty CHECK (LEN(LTRIM(RTRIM(Name))) > 0) -- NameRequired
, CONSTRAINT UQ_WarehouseBinLocation_WarehouseId_HierarchyNode UNIQUE CLUSTERED (WarehouseId, HierarchyNode) -- UniqueTreePathPerWarehouse
, CONSTRAINT UQ_WarehouseBinLocation_Id_WarehouseId UNIQUE NONCLUSTERED (Id, WarehouseId)  WITH (DATA_COMPRESSION = PAGE) -- SameWarehouseParentKey
, CONSTRAINT FK_WarehouseBinLocation_Parent_SameWarehouse FOREIGN KEY (ParentId, WarehouseId) REFERENCES dbo.WarehouseBinLocation (Id, WarehouseId) -- ParentInSameWarehouse
, CONSTRAINT CHK_WarehouseBinLocation_Id_NotEqual_ParentId CHECK (Id <> ParentId) -- NoSelfParent
, CONSTRAINT CHK_WarehouseBinLocation_Root_ParentId CHECK (HierarchyNode <> hierarchyid::GetRoot() OR ParentId IS NULL) -- RootHasNoParent
)
WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_WarehouseBinLocation_WarehouseId_ParentId_HierarchyNode ON dbo.WarehouseBinLocation (WarehouseId, ParentId, HierarchyNode) INCLUDE (Id, Name, HierarchyLevel) WITH (DATA_COMPRESSION = PAGE);
CREATE NONCLUSTERED INDEX IX_WarehouseBinLocation_ParentId_WarehouseId ON dbo.WarehouseBinLocation (ParentId, WarehouseId) INCLUDE (Id, Name, HierarchyNode, HierarchyLevel) WHERE ParentId IS NOT NULL WITH (DATA_COMPRESSION = PAGE);
