 CREATE TABLE PartnerDiscountGroup ( 
Id int IDENTITY(1,1) CONSTRAINT PK_PartnerDiscountGroup_Id PRIMARY KEY (Id)
, DiscountGroupNameId int NOT NULL CONSTRAINT FK_PartnerDiscountGroup_DiscountGroupNameId FOREIGN KEY (DiscountGroupNameId) REFERENCES PartnerDiscountGroupName
, ArticleGroupId int NOT NULL CONSTRAINT FK_PartnerDiscountGroup_ArticleGroupId FOREIGN KEY (ArticleGroupId) REFERENCES ArticleGroup
, DiscountPercent decimal(19,6) NOT NULL CONSTRAINT DF_PartnerDiscountGroup_DiscountPercent DEFAULT (0)
, QuantityLevelA decimal(19,6) 
, QuantityDiscountA decimal(19,6) 
, QuantityLevelB decimal(19,6) 
, QuantityDiscountB decimal(19,6) 
, QuantityLevelC decimal(19,6) 
, QuantityDiscountC decimal(19,6) 
, QuantityLevelD decimal(19,6) 
, QuantityDiscountD decimal(19,6) 
, QuantityLevelE decimal(19,6) 
, QuantityDiscountE decimal(19,6) 
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_PartnerDiscountGroup_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_PartnerDiscountGroup_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, SysStartTime DATETIME2(0) GENERATED ALWAYS AS ROW START
, SysEndTime DATETIME2(0) GENERATED ALWAYS AS ROW END
, PERIOD FOR SYSTEM_TIME (SysStartTime, SysEndTime)
, CONSTRAINT UQ_PartnerDiscountGroup_DiscountGroupNameId_ArticleGroupId UNIQUE (DiscountGroupNameId, ArticleGroupId)
-- Quantity and QuantityDiscount should not be 0
, CONSTRAINT CHK_Quantity_Not_Zero CHECK (
(QuantityLevelA IS NULL OR QuantityLevelA > 0)
AND (QuantityLevelB IS NULL OR QuantityLevelB > 0)
AND (QuantityLevelC IS NULL OR QuantityLevelC > 0)
AND (QuantityLevelD IS NULL OR QuantityLevelD > 0)
AND (QuantityLevelE IS NULL OR QuantityLevelE > 0)
)
, CONSTRAINT CHK_QuantityDiscount_Not_Zero CHECK (
(QuantityDiscountA IS NULL OR QuantityDiscountA > 0)
AND (QuantityDiscountB IS NULL OR QuantityDiscountB > 0)
AND (QuantityDiscountC IS NULL OR QuantityDiscountC > 0)
AND (QuantityDiscountD IS NULL OR QuantityDiscountD > 0)
AND (QuantityDiscountE IS NULL OR QuantityDiscountE > 0)
)
-- If a Quantity is NULL, corresponding QuantityDiscount and following Quantities and Discounts must be NULL
, CONSTRAINT CHK_Quantity_Cascade_NULL CHECK (
(QuantityLevelA IS NOT NULL OR (QuantityDiscountA IS NULL AND QuantityLevelB IS NULL AND QuantityDiscountB IS NULL AND QuantityLevelC IS NULL AND QuantityDiscountC IS NULL AND QuantityLevelD IS NULL AND QuantityDiscountD IS NULL AND QuantityLevelE IS NULL AND QuantityDiscountE IS NULL))
AND (QuantityLevelB IS NOT NULL OR (QuantityDiscountB IS NULL AND QuantityLevelC IS NULL AND QuantityDiscountC IS NULL AND QuantityLevelD IS NULL AND QuantityDiscountD IS NULL AND QuantityLevelE IS NULL AND QuantityDiscountE IS NULL))
AND (QuantityLevelC IS NOT NULL OR (QuantityDiscountC IS NULL AND QuantityLevelD IS NULL AND QuantityDiscountD IS NULL AND QuantityLevelE IS NULL AND QuantityDiscountE IS NULL))
AND (QuantityLevelD IS NOT NULL OR (QuantityDiscountD IS NULL AND QuantityLevelE IS NULL AND QuantityDiscountE IS NULL))
AND (QuantityLevelE IS NOT NULL OR QuantityDiscountE IS NULL)
)
-- Quantities must be in ascending order if they are not NULL
, CONSTRAINT CHK_Quantity_Ascending CHECK (
(QuantityLevelA IS NULL OR QuantityLevelB IS NULL OR QuantityLevelA < QuantityLevelB)
AND (QuantityLevelB IS NULL OR QuantityLevelC IS NULL OR QuantityLevelB < QuantityLevelC)
AND (QuantityLevelC IS NULL OR QuantityLevelD IS NULL OR QuantityLevelC < QuantityLevelD)
AND (QuantityLevelD IS NULL OR QuantityLevelE IS NULL OR QuantityLevelD < QuantityLevelE)
)
-- Quantity Discounts must be in ascending order if they are not NULL
, CONSTRAINT CHK_QuantityDiscount_Ascending CHECK (
(QuantityDiscountA IS NULL OR QuantityDiscountB IS NULL OR QuantityDiscountA < QuantityDiscountB)
AND (QuantityDiscountB IS NULL OR QuantityDiscountC IS NULL OR QuantityDiscountB < QuantityDiscountC)
AND (QuantityDiscountC IS NULL OR QuantityDiscountD IS NULL OR QuantityDiscountC < QuantityDiscountD)
AND (QuantityDiscountD IS NULL OR QuantityDiscountE IS NULL OR QuantityDiscountD < QuantityDiscountE)
)
-- A QuantityLevel must have a corresponding QuantityDiscount, and vice versa
, CONSTRAINT CHK_Quantity_QuantityDiscount_Pair CHECK (
(QuantityLevelA IS NULL AND QuantityDiscountA IS NULL OR QuantityLevelA IS NOT NULL AND QuantityDiscountA IS NOT NULL)
AND (QuantityLevelB IS NULL AND QuantityDiscountB IS NULL OR QuantityLevelB IS NOT NULL AND QuantityDiscountB IS NOT NULL)
AND (QuantityLevelC IS NULL AND QuantityDiscountC IS NULL OR QuantityLevelC IS NOT NULL AND QuantityDiscountC IS NOT NULL)
AND (QuantityLevelD IS NULL AND QuantityDiscountD IS NULL OR QuantityLevelD IS NOT NULL AND QuantityDiscountD IS NOT NULL)
AND (QuantityLevelE IS NULL AND QuantityDiscountE IS NULL OR QuantityLevelE IS NOT NULL AND QuantityDiscountE IS NOT NULL)
)
--Total Discount <= 100
, CONSTRAINT CHK_DiscountPercent_TotalMax100 CHECK (
DiscountPercent + ISNULL(QuantityDiscountA, 0) <= 100
AND DiscountPercent + ISNULL(QuantityDiscountB, 0) <= 100
AND DiscountPercent + ISNULL(QuantityDiscountC, 0) <= 100
AND DiscountPercent + ISNULL(QuantityDiscountD, 0) <= 100
AND DiscountPercent + ISNULL(QuantityDiscountE, 0) <= 100
)
)
WITH (SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.PartnerDiscountGroupHistory, DATA_CONSISTENCY_CHECK = ON));
