, CONSTRAINT UQ_Partner_Matchcode UNIQUE NONCLUSTERED (Matchcode)
, CONSTRAINT UQ_Partner_Email UNIQUE NONCLUSTERED (Email)
, CONSTRAINT CHK_Partner_Name1_NotEmpty CHECK (LEN(LTRIM(RTRIM(Name1))) > 0)
, CONSTRAINT CHK_Partner_Matchcode_NotEmpty CHECK (LEN(LTRIM(RTRIM(Matchcode))) > 0)
