, DeliveryTime int NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_DeliveryTime DEFAULT (0)
, MinimumQuantity decimal(19,6) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_MinimumQuantity DEFAULT (0)
