, DiscountGroupAssigned bit NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_DiscountGroupAssigned DEFAULT (0)
, PurchasePrice decimal(19,6) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_PurchasePrice DEFAULT (0)
, DiscountPercent decimal(19,6) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_DiscountPercent DEFAULT (0)
, LogisticCost decimal(19,6) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_LogisticCost DEFAULT (0)
, CustomsCost decimal(19,6) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_CustomsCost DEFAULT (0)
, RiskCost decimal(19,6) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_RiskCost DEFAULT (0)
