, PriceUnitId int NOT NULL CONSTRAINT FK_PartnerPurchasePriceList_PriceUnitId FOREIGN KEY (PriceUnitId) REFERENCES ArticlePriceUnit CONSTRAINT DF_PartnerPurchasePriceList_PriceUnitId DEFAULT (1)
, UnitPrice AS CAST(ROUND(((PurchasePrice *(1 - (DiscountPercent/100))) + LogisticCost + CustomsCost + RiskCost) / PriceUnitId, 6) AS decimal(19,6)) PERSISTED
, Comment nvarchar(255) 
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_PartnerPurchasePriceList_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, CONSTRAINT UQ_PartnerPurchasePriceList_PartnerIdAndArticleId UNIQUE (PartnerId, ArticleId)
, CONSTRAINT CHK_PartnerPurchasePriceList_DiscountPercent_Valid CHECK (DiscountPercent <= 100)
, SysStartTime DATETIME2(0) GENERATED ALWAYS AS ROW START
, SysEndTime DATETIME2(0) GENERATED ALWAYS AS ROW END
, PERIOD FOR SYSTEM_TIME (SysStartTime, SysEndTime)
)
WITH (SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.PartnerPurchasePriceListHistory));
