, CONSTRAINT CHK_Doc_PostingDate_GE_DocDate CHECK (PostingDate IS NULL OR PostingDate >= DocDate)
, CONSTRAINT CHK_Doc_Rate_RequiredWithCurrency CHECK ((ForeignCurrencyId IS NULL AND Rate IS NULL) OR (ForeignCurrencyId IS NOT NULL AND Rate > 0))
, CONSTRAINT CHK_Doc_PartnerDetail_RequiresPartner CHECK (PartnerDetailId IS NULL OR PartnerId IS NOT NULL)
)
WITH (DATA_COMPRESSION = PAGE);
