 CREATE TABLE DocContract ( 
DocId int CONSTRAINT PK_DocContract_DocId PRIMARY KEY (DocId) CONSTRAINT FK_DocContract_DocId FOREIGN KEY (DocId) REFERENCES Doc ON DELETE CASCADE
, ContractNumber nvarchar(50) 
, Subject nvarchar(200) 
, TargetDocTypeId nvarchar(35)  CONSTRAINT FK_DocContract_TargetDocTypeId FOREIGN KEY (TargetDocTypeId) REFERENCES DocType
, StartDate date NOT NULL CONSTRAINT DF_DocContract_StartDate DEFAULT ((CONVERT(date, GETDATE())))
, CyclePeriodId int  CONSTRAINT FK_DocContract_CyclePeriodId FOREIGN KEY (CyclePeriodId) REFERENCES DocContractCyclePeriod
, NextAppointment date 
, LeadTimeDays int NOT NULL CONSTRAINT DF_DocContract_LeadTimeDays DEFAULT (0)
, NextExecutionDate date 
, EndDate date NOT NULL CONSTRAINT DF_DocContract_EndDate DEFAULT ((CONVERT(date, '99991231', 112)))
, StatusId nvarchar(10)  CONSTRAINT FK_DocContract_StatusId FOREIGN KEY (StatusId) REFERENCES DocContractStatus CONSTRAINT DF_DocContract_StatusId DEFAULT ('DRAFT')
, Prepayment bit NOT NULL CONSTRAINT DF_DocContract_Prepayment DEFAULT (1)
, CycleQuantity int NOT NULL CONSTRAINT DF_DocContract_CycleQuantity DEFAULT (0)
, ExecutedCycles int NOT NULL CONSTRAINT DF_DocContract_ExecutedCycles DEFAULT (0)
, PendingCycles AS (CycleQuantity - ExecutedCycles) PERSISTED NOT NULL
, PossibleTerminationDate date 
, TerminatedOnDate date 
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_DocContract_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_DocContract_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, SysStartTime DATETIME2(0) GENERATED ALWAYS AS ROW START
, SysEndTime DATETIME2(0) GENERATED ALWAYS AS ROW END
, PERIOD FOR SYSTEM_TIME (SysStartTime, SysEndTime)
, CONSTRAINT CHK_DocContract_StartDate_LessOrEqual_EndDate CHECK (StartDate <= EndDate)
, CONSTRAINT CHK_DocContract_CycleQuantity_GreaterOrEqual_Zero CHECK (CycleQuantity >= 0)
, CONSTRAINT CHK_DocContract_ExecutedCycles_GreaterOrEqual_Zero CHECK (ExecutedCycles >= 0)
)
WITH (SYSTEM_VERSIONING = ON (HISTORY_TABLE = dbo.DocContractHistory));
