 CREATE TABLE DocPosition ( 
Id int IDENTITY(1,1) CONSTRAINT PK_DocPosition_Id PRIMARY KEY NONCLUSTERED (Id)
, DocId int NOT NULL CONSTRAINT FK_DocPosition_DocId FOREIGN KEY (DocId) REFERENCES Doc ON DELETE CASCADE
, RowNumber int NOT NULL
, PositionTypeId nvarchar(15) NOT NULL CONSTRAINT FK_DocPosition_PositionTypeId FOREIGN KEY (PositionTypeId) REFERENCES DocPositionType CONSTRAINT DF_DocPosition_PositionTypeId DEFAULT ('Article')
, PositionNumber int NOT NULL
, ParentPositionId int  CONSTRAINT FK_DocPosition_ParentPositionId FOREIGN KEY (ParentPositionId) REFERENCES DocPosition
, ChildPositionNumber int 
, StatusId nvarchar(12)  CONSTRAINT FK_DocPosition_StatusId FOREIGN KEY (StatusId) REFERENCES DocPositionStatus CONSTRAINT DF_DocPosition_StatusId DEFAULT ('open')
, ArticleId nvarchar(30)  CONSTRAINT FK_DocPosition_ArticleId FOREIGN KEY (ArticleId) REFERENCES Article
, Name1 nvarchar(100) 
, Name2 nvarchar(100) 
, Quantity decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_Quantity DEFAULT (1)
, QuantityOpen decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_QuantityOpen DEFAULT (1)
, UoMId int  CONSTRAINT FK_DocPosition_UoMId FOREIGN KEY (UoMId) REFERENCES ArticleUoM
, ShippingDate date NOT NULL CONSTRAINT DF_DocPosition_ShippingDate DEFAULT ((CONVERT(date, GETDATE())))
, DeliveryDate date NOT NULL CONSTRAINT DF_DocPosition_DeliveryDate DEFAULT ((CONVERT(date, GETDATE())))
, Price decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_Price DEFAULT (0)
, PriceUnitId int NOT NULL CONSTRAINT FK_DocPosition_PriceUnitId FOREIGN KEY (PriceUnitId) REFERENCES ArticlePriceUnit CONSTRAINT DF_DocPosition_PriceUnitId DEFAULT (1)
, PredecessorId int  CONSTRAINT FK_DocPosition_PredecessorId FOREIGN KEY (PredecessorId) REFERENCES DocPosition
, QuantityTransferred decimal(19,6)  CONSTRAINT DF_DocPosition_QuantityTransferred DEFAULT (0)
, Level int  CONSTRAINT DF_DocPosition_Level DEFAULT (1)
, PositionLabel nvarchar(30) 
, CatalogNumberId int  CONSTRAINT FK_DocPosition_CatalogNumberId FOREIGN KEY (CatalogNumberId) REFERENCES PartnerCatalogNumber
, Dissolve bit NOT NULL CONSTRAINT DF_DocPosition_Dissolve DEFAULT (0)
, PositionWeight decimal(19,6)  CONSTRAINT DF_DocPosition_PositionWeight DEFAULT (0)
, RelatedPositionId int  CONSTRAINT FK_DocPosition_RelatedPositionId FOREIGN KEY (RelatedPositionId) REFERENCES DocPosition
, ProjectId int  CONSTRAINT FK_DocPosition_ProjectId FOREIGN KEY (ProjectId) REFERENCES Project
, Start datetimeoffset(0) 
, Stop datetimeoffset(0) 
, ArticleCostPrice decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_ArticleCostPrice DEFAULT (0)
, CostPriceFactor int NOT NULL CONSTRAINT DF_DocPosition_CostPriceFactor DEFAULT (1)
, CostPriceTotal AS (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(ArticleCostPrice,0) * ISNULL(CostPriceFactor,0) * ISNULL(Quantity,0), 2)), 0)) PERSISTED NOT NULL
, DiscountPercent decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_DiscountPercent DEFAULT (0)
, QuantityDiscountPercent decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_QuantityDiscountPercent DEFAULT (0)
, DocDiscountPercent decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_DocDiscountPercent DEFAULT (0)
, DiscountedPrice AS (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0), 2)), 0)) PERSISTED NOT NULL
, PrepaymentFactor int NOT NULL CONSTRAINT DF_DocPosition_PrepaymentFactor DEFAULT (0)
, TotalPrice AS (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0) * ISNULL(Quantity,0) * ISNULL(PrepaymentFactor,0), 2)), 0)) PERSISTED NOT NULL
, RevenueEffective int  CONSTRAINT FK_DocPosition_RevenueEffective FOREIGN KEY (RevenueEffective) REFERENCES DocTypeRevenueEffective
, Revenue AS (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0) * ISNULL(Quantity,0) * ISNULL(PrepaymentFactor,0) * ISNULL(RevenueEffective,0), 2)), 0)) PERSISTED NOT NULL
, SalesPersonId int  CONSTRAINT FK_DocPosition_SalesPersonId FOREIGN KEY (SalesPersonId) REFERENCES Employee
, CommissionPercent decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_CommissionPercent DEFAULT (0)
, CommissionAmount AS (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0) * ISNULL(Quantity,0) * ISNULL(PrepaymentFactor,0) * (ISNULL(CommissionPercent,0) / 100.0), 2)), 0)) PERSISTED NOT NULL
, ProfitFactor int NOT NULL CONSTRAINT DF_DocPosition_ProfitFactor DEFAULT (1)
, ProfitAmount AS (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0) * ISNULL(Quantity,0), 2) - ROUND(ISNULL(ArticleCostPrice,0) * ISNULL(Quantity,0), 2)), 0) * ISNULL(ProfitFactor,0)  * ISNULL(CostPriceFactor,0)) PERSISTED NOT NULL
, ProfitPercent AS (ROUND(ISNULL(((ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0) * ISNULL(Quantity,0), 2) - ROUND(ISNULL(ArticleCostPrice,0) * ISNULL(Quantity,0), 2)), 0) * ISNULL(ProfitFactor,0)  * ISNULL(CostPriceFactor,0)) / NULLIF(ABS(ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0) * ISNULL(Quantity,0), 2)), 0)), 0)) * 100, 0), 2)) PERSISTED NOT NULL
, FinanceGroupArticleId int 
, FinanceGroupPartnerDetailId int 
, TaxKeyId nvarchar(3) 
, TaxFactor int NOT NULL CONSTRAINT DF_DocPosition_TaxFactor DEFAULT (1)
, TaxPercent decimal(19,6) NOT NULL CONSTRAINT DF_DocPosition_TaxPercent DEFAULT (0)
, Tax AS (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(Price,0) * (1 - ((ISNULL(DiscountPercent,0) + ISNULL(QuantityDiscountPercent,0) + ISNULL(DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(PriceUnitId,1), 0) * ISNULL(Quantity,0) * ISNULL(PrepaymentFactor,0), 2) * ISNULL(TaxFactor,0) * (ISNULL(TaxPercent,0) / 100.0)), 0)) PERSISTED NOT NULL
, AccountId int 
, CostCenterId int 
, CostBearerId int 
, ForeignCurrencyPrice decimal(19,6) 
, Warehousing bit NOT NULL CONSTRAINT DF_DocPosition_Warehousing DEFAULT (0)
, WarehousingEffective int  CONSTRAINT FK_DocPosition_WarehousingEffective FOREIGN KEY (WarehousingEffective) REFERENCES DocTypeWarehousingEffective
, WarehousingQuantity AS (ISNULL(CONVERT(decimal(19,6), ISNULL(Quantity,0) * ISNULL(WarehousingEffective,0) * ISNULL(Warehousing,0)), 0)) PERSISTED NOT NULL
, Pending bit NOT NULL CONSTRAINT DF_DocPosition_Pending DEFAULT (0)
, RowVersion rowversion 
, CONSTRAINT CHK_DocPosition_Id_NotEqual_ParentPositionId CHECK (Id <> ParentPositionId)
, CONSTRAINT CHK_DocPosition_Id_NotEqual_PredecessorId     CHECK (Id <> PredecessorId)
, CONSTRAINT CHK_DocPosition_Id_NotEqual_RelatedPositionId CHECK (Id <> RelatedPositionId)
)
WITH (DATA_COMPRESSION = PAGE);
