 CREATE TABLE FinanceFixedAssetDepreciationType ( 
Id int IDENTITY(1,1) CONSTRAINT PK_FinanceFixedAssetDepreciationType_Id PRIMARY KEY (Id)
, Name nvarchar(100) NOT NULL CONSTRAINT UQ_FinanceFixedAssetDepreciationType_Name UNIQUE (Name)
, MethodId nvarchar(20) NOT NULL CONSTRAINT FK_FinanceFixedAssetDepreciationType_MethodId FOREIGN KEY (MethodId) REFERENCES FinanceFixedAssetDepreciationMethod
, UsefulLifeMonthsQuantity int 
, MinimumAmount decimal(19,6) 
, MaximumAmount decimal(19,6) 
, ValidFrom datetimeoffset(0) 
, ValidUntil datetimeoffset(0) 
, IsActive bit NOT NULL CONSTRAINT DF_FinanceFixedAssetDepreciationType_IsActive DEFAULT (1)
, DateCreated datetimeoffset(0) NOT NULL CONSTRAINT DF_FinanceFixedAssetDepreciationType_DateCreated DEFAULT (SYSUTCDATETIME())
, CreatedBy int 
, DateModified datetimeoffset(0) NOT NULL CONSTRAINT DF_FinanceFixedAssetDepreciationType_DateModified DEFAULT (SYSUTCDATETIME())
, ModifiedBy int 
, RowVersion rowversion 
, CONSTRAINT CHK_FinanceFixedAssetDepreciationType_MinimumAmount_LessOrEqual_MaximumAmount
CHECK (
MinimumAmount IS NULL
OR MaximumAmount IS NULL
OR MinimumAmount <= MaximumAmount
)
, CONSTRAINT CHK_FinanceFixedAssetDepreciationType_ValidFrom_LessOrEqual_ValidUntil
CHECK (
ValidFrom IS NULL
OR ValidUntil IS NULL
OR ValidFrom <= ValidUntil
)
, CONSTRAINT CHK_FinanceFixedAssetDepreciationType_UsefulLifeMonthsQuantity_GreaterThan_Zero
CHECK (
UsefulLifeMonthsQuantity IS NULL
OR UsefulLifeMonthsQuantity > 0
)
, CONSTRAINT CHK_FinanceFixedAssetDepreciationType_MinimumAmount_GreaterOrEqual_Zero
CHECK (
MinimumAmount IS NULL
OR MinimumAmount >= 0
)
, CONSTRAINT CHK_FinanceFixedAssetDepreciationType_MaximumAmount_GreaterOrEqual_Zero
CHECK (
MaximumAmount IS NULL
OR MaximumAmount >= 0
)
)
