CREATE OR ALTER FUNCTION
dbo.xFUNCTION001_GetCurrentPostingPeriodId()
RETURNS INT
AS
BEGIN
DECLARE @currentYear INT, @currentMonth INT, @result INT;
SET @currentYear = YEAR(GETDATE());
SET @currentMonth = MONTH(GETDATE());
SELECT @result = Id FROM dbo.FinancePostingPeriod
WHERE CalendarYearId = @currentYear AND CalendarMonthId = @currentMonth;
RETURN @result;
END;
GO
-- End: dbo.xFUNCTION001_GetCurrentPostingPeriodId--------------------
--------------------------------------------------------------
CREATE OR ALTER FUNCTION
dbo.xFUNCTION002_GetPostingPeriodIdByDate(@parxDate DATE)
RETURNS INT
AS
BEGIN
DECLARE @currentYear INT, @currentMonth INT, @result INT;
SET @currentYear = YEAR(@parxDate);
SET @currentMonth = MONTH(@parxDate);
SELECT @result = Id FROM FinancePostingPeriod
WHERE CalendarYearId = @currentYear AND CalendarMonthId = @currentMonth;
RETURN @result;
END;
GO
-- End dbo.xFUNCTION002_GetPostingPeriodIdByDate--------------------------
--dbo.xFUNCTION003_GetNextOpenPostingPeriodId-----------------------------------------------------------------------
CREATE OR ALTER FUNCTION 
dbo.xFUNCTION003_GetNextOpenPostingPeriodId(@currentPeriodId INT)
RETURNS INT
AS
BEGIN
DECLARE @Year INT, @Month INT, @result INT;
SELECT @Year = CalendarYearId, @Month = CalendarMonthId
FROM dbo.FinancePostingPeriod
WHERE Id = @currentPeriodId;
SELECT TOP 1 @result = Id
FROM dbo.FinancePostingPeriod
WHERE (CalendarYearId > @Year OR (CalendarYearId = @Year AND CalendarMonthId >= @Month))
AND StatusId = 'open'
ORDER BY CalendarYearId, CalendarMonthId;
RETURN @result;
END;
GO
-- End dbo.xFUNCTION003_GetNextOpenPostingPeriodId-----------------------------------------------------------------------
--------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER FUNCTION
dbo.xFUNCTION_REPORT_GetConfirmedQuantity
(
@ParentId INT
, @Qtype INT
, @DocType nvarchar(35) 
)
RETURNS NUMERIC(19,6)
AS
BEGIN
DECLARE @OrderQuantity NUMERIC(19,6) = 0;
DECLARE @IsDelivery BIT
SELECT
@IsDelivery = IsDelivery
FROM dbo.DocType
WHERE
Id = @DocType
IF @IsDelivery = 1
BEGIN
WITH MyCTE(ParentID,ID,Quantity,QuantityOpen,DocTypeId, IsDelivery, IsOrderConfirmation)
AS
(
SELECT
PredecessorId AS ParentID
, DP.Id AS ID
, Quantity AS Quantity
, QuantityOpen AS QuantityOpen
, D.DocTypeId
, DT.IsDelivery
, DT.IsOrderConfirmation
FROM dbo.DocPosition DP
INNER JOIN dbo.Doc D ON DP.DocId = D.Id
INNER JOIN DocType DT ON DT.Id = D.DocTypeId
WHERE
DP.Id = @ParentId
UNION ALL
SELECT
DP.PredecessorId AS ParentID
, DP.Id AS ID
, DP.Quantity AS Quantity
, DP.QuantityOpen AS QuantityOpen
, D.DocTypeId
, DT.IsDelivery
, DT.IsOrderConfirmation
FROM dbo.DocPosition DP
INNER JOIN dbo.Doc D ON DP.DocId = D.Id
INNER JOIN MyCTE H ON H.ParentId = DP.Id
INNER JOIN DocType DT ON DT.Id = D.DocTypeId
)
SELECT
@OrderQuantity =
SUM(
CASE
WHEN @Qtype = 1 THEN
CASE WHEN IsOrderConfirmation = 1
THEN Quantity
ELSE 0 END
WHEN @Qtype = 0
THEN
CASE
WHEN IsDelivery = 1 THEN 0
ELSE
CASE WHEN IsOrderConfirmation = 0 THEN 0 ELSE QuantityOpen END
END
--WHEN DocTypeId = 'CustomerQuotation' THEN 0
--WHEN IsOrderConfirmation = 1 THEN QuantityOpen
--ELSE QuantityOpen END
ELSE 0
END
)
FROM MyCTE
END;
RETURN ISNULL(@OrderQuantity,0);
END
GO
-- END dbo.xFUNCTION_REPORT_GetConfirmedQuantity ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER TRIGGER
xTRIGGER100_Article_AfterInsert_InsertArticleQuantity
ON [dbo].[Article]
AFTER INSERT
AS
BEGIN
SET NOCOUNT ON;
------------------------------------------------------------------------------------
--Purpose: Insert matching ArticleQuantity for new Article row.
------------------------------------------------------------------------------------
INSERT INTO ArticleQuantity (
ArticleId
,Stock
,InventoryCountingPosition
,DocPosition
,ProductionPosition
)
SELECT
i.Id
,CASE WHEN i.Warehousing = 1 THEN 0 ELSE NULL END
,NULL
,NULL
,NULL
FROM inserted i
WHERE NOT EXISTS (
SELECT 1 FROM ArticleQuantity aq WHERE aq.ArticleId = i.Id
);
END
GO
