CREATE OR ALTER TRIGGER
xTRIGGER110_ArticleIndividualizationQuantity_SerialNumberOnly0or1
ON ArticleIndividualizationQuantity
AFTER INSERT, UPDATE
AS
BEGIN
SET NOCOUNT ON;
-------------------------------------------------------------------------------------------------------------
--Purpose: Enforces total serial number stock is exactly 0 or 1.
-------------------------------------------------------------------------------------------------------------
IF EXISTS (
SELECT 1
FROM ArticleIndividualizationQuantity a
JOIN inserted i
ON a.ArticleIndividualizationId = i.ArticleIndividualizationId
JOIN ArticleIndividualization AI ON AI.Id = a.ArticleIndividualizationId AND AI.IsBatch = 0
GROUP BY a.ArticleIndividualizationId
HAVING SUM(a.Stock) NOT IN (0, 1) -- Only allows total stock to be exactly 0 or 1
)
BEGIN
RAISERROR('The total stock of a serial number across all warehouses must be exactly 0 or 1, without any fractional or negative values.', 16, 1);
ROLLBACK TRANSACTION;
END
END;
GO
--END xTRIGGER110_ArticleIndividualizationQuantity_SerialNumberOnly0or1-----------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER TRIGGER
xTRIGGER165_New_PartnerDetail_PartnerDetailOutput
ON PartnerDetail
AFTER INSERT
AS
BEGIN
SET NOCOUNT ON;
-------------------------------------------------------------------------------------------------------------
--Purpose: Inserts default DocType output configurations for new PartnerDetail records.
-------------------------------------------------------------------------------------------------------------
INSERT INTO PartnerDetailOutput(PartnerDetailId, DocTypeId, OutputControlFormatId, ReportTemplateId, EmailTemplateId)
SELECT
i.Id AS PartnerDetailId
, d.Id AS DocTypeId
, o.Id AS OutputControlFormatId
, d.DefaultReportTemplateId AS ReportTemplateId
, NULL AS EmailTemplateId
FROM Inserted i
CROSS JOIN DocType d
INNER JOIN OutputControlFormat o
ON o.Id = (SELECT DefaultOutputControlFormatId FROM DocType WHERE DocType.Id = d.Id)
WHERE NOT EXISTS (
SELECT 1
FROM PartnerDetailOutput PDO
WHERE PDO.PartnerDetailId = i.Id
AND PDO.DocTypeId = d.Id
);
END;
GO
-- END xTRIGGER165_New_PartnerDetail_PartnerDetailOutput ----------------------------------------
-------------------------------------------------------------------------------------------------------------
