CREATE OR ALTER TRIGGER
xTRIGGER200_DocType_MaintainSequence
ON DocType
AFTER INSERT, UPDATE, DELETE
AS
BEGIN
SET NOCOUNT ON;
-------------------------------------------------------------------------------------------------------------
--Purpose: Automatically creates/drops sequences matching DocType insert/delete/update operations.
-------------------------------------------------------------------------------------------------------------
DECLARE @SQLString NVARCHAR(500);
-- INSERT (multiple rows possible)
IF EXISTS (SELECT 1 FROM inserted) AND NOT EXISTS (SELECT 1 FROM deleted)
BEGIN
DECLARE inserted_cursor CURSOR FOR SELECT Id FROM inserted;
DECLARE @IdInserted NVARCHAR(50);
OPEN inserted_cursor;
FETCH NEXT FROM inserted_cursor INTO @IdInserted;
WHILE @@FETCH_STATUS = 0
BEGIN
SET @SQLString = N'CREATE SEQUENCE [dbo].[Doc_' + @IdInserted + N'_Sequence] AS [int] START WITH 1 INCREMENT BY 1 MINVALUE 1 MAXVALUE 2147483647 NO CACHE';
EXECUTE sp_executesql @SQLString;
FETCH NEXT FROM inserted_cursor INTO @IdInserted;
END
CLOSE inserted_cursor;
DEALLOCATE inserted_cursor;
END
-- DELETE (multiple rows possible)
IF NOT EXISTS (SELECT 1 FROM inserted) AND EXISTS (SELECT 1 FROM deleted)
BEGIN
DECLARE deleted_cursor CURSOR FOR SELECT Id FROM deleted;
DECLARE @IdDeleted NVARCHAR(50);
OPEN deleted_cursor;
FETCH NEXT FROM deleted_cursor INTO @IdDeleted;
WHILE @@FETCH_STATUS = 0
BEGIN
SET @SQLString = N'DROP SEQUENCE [dbo].[Doc_' + @IdDeleted + N'_Sequence]';
EXECUTE sp_executesql @SQLString;
FETCH NEXT FROM deleted_cursor INTO @IdDeleted;
END
CLOSE deleted_cursor;
DEALLOCATE deleted_cursor;
END
-- UPDATE (Id changed – if allowed, multiple rows possible)
IF EXISTS (SELECT 1 FROM inserted) AND EXISTS (SELECT 1 FROM deleted)
BEGIN
DECLARE update_cursor CURSOR FOR
SELECT d.Id, i.Id
FROM deleted d
INNER JOIN inserted i ON d.Id <> i.Id;
DECLARE @OldId NVARCHAR(50), @NewId NVARCHAR(50);
OPEN update_cursor;
FETCH NEXT FROM update_cursor INTO @OldId, @NewId;
WHILE @@FETCH_STATUS = 0
BEGIN
SET @SQLString = N'DROP SEQUENCE [dbo].[Doc_' + @OldId + N'_Sequence]';
EXECUTE sp_executesql @SQLString;
SET @SQLString = N'CREATE SEQUENCE [dbo].[Doc_' + @NewId + N'_Sequence] AS [int] START WITH 1 INCREMENT BY 1 MINVALUE 1 MAXVALUE 2147483647 NO CACHE';
EXECUTE sp_executesql @SQLString;
FETCH NEXT FROM update_cursor INTO @OldId, @NewId;
END
CLOSE update_cursor;
DEALLOCATE update_cursor;
END
END
GO
-- End: xTRIGGER200_DocType_MaintainSequence-------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
