CREATE OR ALTER VIEW
xVIEW124_ArticleQuantityInventorySum
/*
-----------------------------------------------------------------------------------------
-----------------------------------------------------------------------------------------
*/
AS
SELECT
A.Id AS ArticleId
, A.Matchcode
, A.Warehousing
, AG.Name AS ArticleGroupName
, ISNULL(p.[confirmed], 0) + ISNULL(PPV.Confirmed, 0) AS Confirmed
, ISNULL(p.[packed], 0) + ISNULL(PPV.Packed, 0) AS Packed
, ISNULL(p.[ordered], 0) + ISNULL(PPV.Ordered, 0) AS Ordered
, ISNULL(p.[announced], 0) + ISNULL(PPV.Announced, 0) AS Announced
, AQ.Stock
, ISNULL(WQ.ArticleMinimumStock, 0)       AS MinimumStock
, ISNULL(WQ.ArticleMessageThreshold, 0)    AS MessageThreshold
, ISNULL(WQ.ArticleMaximumStock, 0)        AS MaximumStock
, AQ.Stock - ISNULL(p.[packed], 0) - ISNULL(PPV.Packed, 0) AS NowAvailable
, AQ.Stock - ISNULL(p.[packed], 0) - ISNULL(PPV.Packed, 0) - ISNULL(p.[confirmed], 0) - ISNULL(PPV.Confirmed, 0) AS AvailableToPromise
, AQ.Stock - ISNULL(p.[packed], 0) - ISNULL(PPV.Packed, 0) - ISNULL(p.[confirmed], 0) - ISNULL(PPV.Confirmed, 0) + ISNULL(p.[ordered], 0) + ISNULL(PPV.Ordered, 0) + ISNULL(p.[announced], 0) + ISNULL(PPV.Announced, 0) AS LaterAvailable
FROM
Article A
LEFT JOIN ArticleQuantity AQ ON AQ.ArticleId = A.Id
LEFT JOIN ArticleGroup AG ON AG.Id = A.ArticleGroupId
LEFT JOIN (
SELECT
DP.ArticleId
, D.InventoryStatusId
, SUM(DP.QuantityOpen) AS QuantityOpenSum
FROM dbo.DocPosition AS DP
INNER JOIN dbo.Doc AS D ON DP.DocId = D.Id
WHERE
D.StatusId IN ('open', 'partially')
AND DP.PositionTypeId = 'Article'
AND DP.StatusId IN ('open', 'partially')
AND D.InventoryStatusId IN ('confirmed', 'packed', 'ordered', 'announced')
GROUP BY
DP.ArticleId
, D.InventoryStatusId
) AS src
PIVOT
(
SUM(QuantityOpenSum)
FOR InventoryStatusId IN ([confirmed], [packed], [ordered], [announced])
) AS p ON p.ArticleId = A.Id
LEFT JOIN (
SELECT
PP.ArticleId
, ISNULL(SUM(PP.PositionQuantityConfirmed), 0) + ISNULL(SUM(PP.PositionQuantityPick), 0) AS Confirmed
, ISNULL(SUM(PP.PositionQuantityPacked), 0) AS Packed
, ISNULL(SUM(PP.PositionQuantityOrdered), 0) AS Ordered
, ISNULL(SUM(PP.PositionQuantityAnnounced), 0) AS Announced
FROM 
dbo.ProductionPosition AS PP
WHERE
(PP.PositionQuantityConfirmed != 0 OR PP.PositionQuantityPick != 0 OR PP.PositionQuantityPacked != 0 OR PP.PositionQuantityIssued != 0 OR PP.PositionQuantityOrdered != 0 OR PP.PositionQuantityAnnounced != 0)
GROUP BY
PP.ArticleId
) AS PPV
ON PPV.ArticleId = A.Id
OUTER APPLY (
SELECT
SUM(ISNULL(WQ.MinimumStock, 0)) AS ArticleMinimumStock
, SUM(ISNULL(WQ.MessageThreshold, 0)) AS ArticleMessageThreshold
, SUM(ISNULL(WQ.MaximumStock, 0)) AS ArticleMaximumStock
FROM dbo.WarehouseQuantity WQ
WHERE WQ.ArticleId = A.Id
) WQ
GO
-- END xVIEW124_ArticleQuantityInventorySum ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW124_ArticlePositionQuantityOpenSum
/*
-----------------------------------------------------------------------------------------
-----------------------------------------------------------------------------------------
*/
AS
WITH DocData AS (
SELECT
DP.ArticleId
, ISNULL(SUM(CASE WHEN D.InventoryStatusId = 'confirmed' THEN DP.QuantityOpen ELSE 0 END), 0) AS Confirmed
, ISNULL(SUM(CASE WHEN D.InventoryStatusId = 'packed'    THEN DP.QuantityOpen ELSE 0 END), 0) AS Packed
, ISNULL(SUM(CASE WHEN D.InventoryStatusId = 'ordered'   THEN DP.QuantityOpen ELSE 0 END), 0) AS Ordered
, ISNULL(SUM(CASE WHEN D.InventoryStatusId = 'announced' THEN DP.QuantityOpen ELSE 0 END), 0) AS Announced
FROM dbo.DocPosition DP
INNER JOIN dbo.Doc D ON D.Id = DP.DocId
WHERE
D.StatusId IN ('open', 'partially')
AND DP.PositionTypeId = 'Article'
AND DP.StatusId IN ('open', 'partially')
AND D.InventoryStatusId IN ('confirmed','packed','ordered','announced')
GROUP BY
DP.ArticleId
)
, ProdData AS (
SELECT
PP.ArticleId
, ISNULL(SUM(PP.PositionQuantityConfirmed), 0) + ISNULL(SUM(PP.PositionQuantityPick), 0) AS Confirmed
, ISNULL(SUM(PP.PositionQuantityPacked), 0) AS Packed
, ISNULL(SUM(PP.PositionQuantityOrdered), 0) AS Ordered
, ISNULL(SUM(PP.PositionQuantityAnnounced), 0) AS Announced
FROM dbo.ProductionPosition PP
INNER JOIN dbo.Production P ON PP.ProductionId = P.Id
WHERE
(PP.PositionQuantityConfirmed != 0 OR PP.PositionQuantityPick != 0 OR PP.PositionQuantityPacked != 0 OR PP.PositionQuantityIssued != 0 OR PP.PositionQuantityOrdered != 0 OR PP.PositionQuantityAnnounced!= 0)
GROUP BY
PP.ArticleId
)
, CombinedArticles AS (
SELECT ArticleId FROM DocData
UNION
SELECT ArticleId FROM ProdData
)
SELECT
CA.ArticleId
, A.Matchcode
, A.Warehousing
, AG.Name AS ArticleGroupName
, ISNULL(D.Confirmed,0) + ISNULL(P.Confirmed,0) AS Confirmed
, ISNULL(D.Packed,0)    + ISNULL(P.Packed,0)    AS Packed
, ISNULL(D.Ordered,0)   + ISNULL(P.Ordered,0)   AS Ordered
, ISNULL(D.Announced,0)   + ISNULL(P.Announced,0) AS Announced
, AQ.Stock
, AIS.MinimumStock
, AIS.MessageThreshold
, AIS.MaximumStock
, AQ.Stock - (ISNULL(D.Packed,0) + ISNULL(P.Packed,0)) AS NowAvailable
, AQ.Stock - (ISNULL(D.Packed,0) + ISNULL(P.Packed,0)) - (ISNULL(D.Confirmed,0) + ISNULL(P.Confirmed,0)) AS AvailableToPromise
, AQ.Stock - (ISNULL(D.Packed,0) + ISNULL(P.Packed,0)) - (ISNULL(D.Confirmed,0) + ISNULL(P.Confirmed,0)) + ISNULL(D.Ordered,0) + ISNULL(P.Ordered,0) + ISNULL(D.Announced,0) + ISNULL(P.Announced,0) AS LaterAvailable
FROM CombinedArticles CA
LEFT JOIN DocData D   ON D.ArticleId = CA.ArticleId
LEFT JOIN ProdData P  ON P.ArticleId = CA.ArticleId
LEFT JOIN Article A   ON A.Id = CA.ArticleId
LEFT JOIN ArticleGroup AG ON AG.Id = A.ArticleGroupId
LEFT JOIN ArticleQuantity AQ ON AQ.ArticleId = CA.ArticleId
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON AIS.ArticleId = A.Id
GO
-- END xVIEW124_ArticlePositionQuantityOpenSum ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW124_ArticleProductionPositionQuantityOpenSum
/*
-----------------------------------------------------------------------------------------
-----------------------------------------------------------------------------------------
*/
AS
SELECT
PP.ArticleId
,   A.Matchcode
,   A.Warehousing
,   AG.Name AS ArticleGroupName
, ISNULL(SUM(PP.PositionQuantityConfirmed), 0) + ISNULL(SUM(PP.PositionQuantityPick), 0) AS Confirmed
, ISNULL(SUM(PP.PositionQuantityPacked), 0) AS Packed
, ISNULL(SUM(PP.PositionQuantityOrdered), 0) AS Ordered
, ISNULL(SUM(PP.PositionQuantityAnnounced), 0) AS Announced
,   AQ.Stock
,   AQ.Stock - ISNULL(SUM(PP.PositionQuantityPacked), 0) + ISNULL(SUM(PP.PositionQuantityIssued), 0) AS NowAvailable
,   AQ.Stock - ISNULL(SUM(PP.PositionQuantityPacked), 0) + ISNULL(SUM(PP.PositionQuantityIssued), 0) -
ISNULL(SUM(PP.PositionQuantityConfirmed), 0) + ISNULL(SUM(PP.PositionQuantityPick), 0) +
ISNULL(SUM(PP.PositionQuantityOrdered), 0) +  ISNULL(SUM(PP.PositionQuantityAnnounced), 0) AS LaterAvailable
FROM
dbo.ProductionPosition AS PP
INNER JOIN dbo.Production AS P ON PP.ProductionId = P.Id
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN ArticleGroup AG ON AG.Id = A.ArticleGroupId
LEFT JOIN ArticleQuantity AQ ON AQ.ArticleId = PP.ArticleId
WHERE
(PP.PositionQuantityOpen != 0 OR PP.PositionQuantityConfirmed != 0 OR PP.PositionQuantityPick != 0 OR PP.PositionQuantityPacked != 0 OR PP.PositionQuantityIssued != 0 OR PP.PositionQuantityOrdered != 0 OR PP.PositionQuantityAnnounced!= 0)
GROUP BY
PP.ArticleId
,   A.Matchcode
,   A.Warehousing
,   AG.Name
,   AQ.Stock
GO
-- END xVIEW124_ArticleProductionPositionQuantityOpenSum ----------------------------------------------------------------------
-----------------------------------------------------------------------------------------
-----------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
