CREATE OR ALTER VIEW
xVIEW_Partner
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns all partners with their full details.
-----------------------------------------------------------------------------------------
*/
AS
WITH PD AS
(
SELECT
pd.PartnerId
, CustomerSupplierNumberConcatenated = STRING_AGG(CONVERT(varchar(20), pd.Id), ',') WITHIN GROUP (ORDER BY pd.Id)
, CustomerPartnerDetailId = MIN(CASE WHEN pd.PartnerTypeId = 'Customer' THEN pd.Id END)
, SupplierPartnerDetailId = MIN(CASE WHEN pd.PartnerTypeId = 'Supplier' THEN pd.Id END)
FROM dbo.PartnerDetail AS pd
GROUP BY
pd.PartnerId
)
SELECT
P.*
, PD.CustomerSupplierNumberConcatenated
, IsCustomer = CONVERT(bit, CASE WHEN PD.CustomerPartnerDetailId IS NULL THEN 0 ELSE 1 END)
, CustomerNumber = CONVERT(varchar(20), PD.CustomerPartnerDetailId)
, PD.CustomerPartnerDetailId
, IsSupplier = CONVERT(bit, CASE WHEN PD.SupplierPartnerDetailId IS NULL THEN 0 ELSE 1 END)
, SupplierNumber = CONVERT(varchar(20), PD.SupplierPartnerDetailId)
, PD.SupplierPartnerDetailId
, AC.Country
, PartnerGroupName = PG.Name
FROM dbo.Partner AS P
LEFT JOIN dbo.PartnerGroup AS PG
ON PG.Id = P.PartnerGroupId
LEFT JOIN dbo.AdminCountry AS AC
ON AC.Id = P.CountryId
LEFT JOIN PD
ON PD.PartnerId = P.Id;
GO
-- END xVIEW_Partner ----------------------------------------------------------------------
