CREATE OR ALTER VIEW
xVIEW204_DocSum_PERSISTED
/*
-----------------------------------------------------------------------------------------
-----------------------------------------------------------------------------------------
*/
WITH SCHEMABINDING
AS
SELECT
D.Id AS DocId
, SUM(DP.CostPriceTotal) AS CostPriceSum
, SUM(DP.TotalPrice) AS TotalPriceSum
, SUM(DP.CommissionAmount) AS CommissionSum
, SUM(DP.ProfitAmount) AS ProfitSum
-- , SUM(DP.ProfitAmount) * 100.0 / SUM(DP.TotalPrice) AS ProfitPercent
, SUM(DP.ProfitAmount - DP.CommissionAmount) AS ProfitAfterCommissionSum
--, CASE WHEN SUM(DP.TotalPrice) = 0 THEN 0 ELSE ROUND(100.0 * SUM(DP.ProfitAmount - DP.CommissionAmount) / NULLIF(SUM(DP.TotalPrice), 0), 2) END AS ProfitAfterCommissionPercent
, SUM(DP.Tax) AS TaxSum
, SUM(DP.TotalPrice + DP.Tax) AS TotalPriceSumGross
, COUNT_BIG(*) AS Count
FROM
dbo.Doc AS D
INNER JOIN
dbo.DocPosition AS DP ON DP.DocId = D.Id
GROUP BY
D.Id
;
GO
CREATE UNIQUE CLUSTERED INDEX IX_xVIEW204_DocSum_PERSISTED ON dbo.xVIEW204_DocSum_PERSISTED (DocId);
GO
-- END xVIEW204_DocSum_PERSISTED ----------------------------------------------------------------------
