CREATE OR ALTER VIEW
xVIEW_Doc
/*
-----------------------------------------------------------------------------------------
-----------------------------------------------------------------------------------------
*/
AS
SELECT
D.*
, P.[Matchcode]
, PD.Id AS BusinessPartnerNumber
, DC.Name AS DocCategory
, DT.Name AS DocType
, DT.PrepaymentTrueArticleFactor
, DCON.NextAppointment
, DCON.NextExecutionDate
, ISNULL(xDS.CostPriceSum, 0) AS CostPriceSum
, ISNULL(xDS.TotalPriceSum, 0) AS TotalPriceSum
, ISNULL(xDS.CommissionSum, 0) AS CommissionSum
, ISNULL(xDS.ProfitSum, 0) AS ProfitSum
, ISNULL(xDS.ProfitAfterCommissionSum, 0) AS ProfitAfterCommissionSum
, ROUND(ISNULL(xDS.TaxSum, 0), 2) AS TaxSum
, ROUND(ISNULL(xDS.TotalPriceSumGross, 0), 2) AS TotalPriceSumGross
, ISNULL(xDS.Count, 0) AS Count
, ISNULL(ROUND(ISNULL(xDS.ProfitSum, 0) / NULLIF(xDS.ProfitSum + xDS.CostPriceSum, 0) * 100, 2), 0) AS ProfitPercent
, ISNULL(ROUND(ISNULL(xDS.ProfitAfterCommissionSum, 0) / NULLIF(xDS.ProfitSum + xDS.CostPriceSum, 0) * 100, 2), 0) AS ProfitAfterCommissionPercent
, ISNULL(FC.TotalPriceSumForeignCurrency, 0)        AS TotalPriceSumForeignCurrency
, ISNULL(FC.TaxSumForeignCurrency, 0)               AS TaxSumForeignCurrency
, ISNULL(FC.TotalPriceSumGrossForeignCurrency, 0)   AS TotalPriceSumGrossForeignCurrency
FROM [Doc] D
INNER JOIN [Partner] P ON D.PartnerId = P.Id
INNER JOIN [PartnerDetail] PD ON D.PartnerDetailId = PD.Id
INNER JOIN DocCategory DC ON D.DocCategoryId = DC.Id
INNER JOIN DocType DT ON D.DocTypeId = DT.Id
LEFT JOIN DocContract DCON ON DCON.DocId = D.Id
LEFT JOIN xVIEW204_DocSum_PERSISTED xDS ON xDS.DocId = D.Id
LEFT JOIN (
SELECT
DP.DocId
,   SUM(
ROUND(
(ISNULL(DP.ForeignCurrencyPrice, 0))
* (1 - ((ISNULL(DP.DiscountPercent, 0) + ISNULL(DP.QuantityDiscountPercent, 0) + ISNULL(DP.DocDiscountPercent, 0)) / 100.0))
/ NULLIF(ISNULL(DP.PriceUnitId, 1), 0)
* ISNULL(DP.Quantity, 0)
* ISNULL(DP.PrepaymentFactor, 0)
, 2)
)                                               AS TotalPriceSumForeignCurrency
,   SUM(
ROUND(
ROUND(
(ISNULL(DP.ForeignCurrencyPrice, 0))
* (1 - ((ISNULL(DP.DiscountPercent, 0) + ISNULL(DP.QuantityDiscountPercent, 0) + ISNULL(DP.DocDiscountPercent, 0)) / 100.0))
/ NULLIF(ISNULL(DP.PriceUnitId, 1), 0)
* ISNULL(DP.Quantity, 0)
* ISNULL(DP.PrepaymentFactor, 0)
, 2)
* ISNULL(DP.TaxFactor, 0)
* (ISNULL(DP.TaxPercent, 0) / 100.0)
, 2)
)                                               AS TaxSumForeignCurrency
,   SUM(
ROUND(
(ISNULL(DP.ForeignCurrencyPrice, 0))
* (1 - ((ISNULL(DP.DiscountPercent, 0) + ISNULL(DP.QuantityDiscountPercent, 0) + ISNULL(DP.DocDiscountPercent, 0)) / 100.0))
/ NULLIF(ISNULL(DP.PriceUnitId, 1), 0)
* ISNULL(DP.Quantity, 0)
* ISNULL(DP.PrepaymentFactor, 0)
, 2) + ROUND(
ROUND(
(ISNULL(DP.ForeignCurrencyPrice, 0))
* (1 - ((ISNULL(DP.DiscountPercent, 0) + ISNULL(DP.QuantityDiscountPercent, 0) + ISNULL(DP.DocDiscountPercent, 0)) / 100.0))
/ NULLIF(ISNULL(DP.PriceUnitId, 1), 0)
* ISNULL(DP.Quantity, 0)
* ISNULL(DP.PrepaymentFactor, 0)
, 2)
* ISNULL(DP.TaxFactor, 0)
* (ISNULL(DP.TaxPercent, 0) / 100.0)
, 2)
)                                               AS TotalPriceSumGrossForeignCurrency
FROM DocPosition DP
INNER JOIN Doc D2
ON D2.Id = DP.DocId
WHERE
DP.PositionTypeId = 'Article'
GROUP BY
DP.DocId
) FC
ON FC.DocId = D.Id
GO
-- ENDxVIEW_Doc ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW_DocPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns all document positions with related article, quantity, cost, and status details.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
DP.*
, DP.RowNumber AS ViewRowNumber
, FORMAT(DP.Quantity, 'N' + CAST(A.DecimalPlacesQuantitiesId AS varchar)) AS FormattedQuantity
, CASE
WHEN DP.ChildPositionNumber IS NULL THEN CAST(DP.PositionNumber AS NVARCHAR(10))
ELSE CONCAT(CAST(DP.PositionNumber AS NVARCHAR(10)), '.', CAST(DP.ChildPositionNumber AS NVARCHAR(10)))
END AS PositionNumberConcat
, NULLIF(DP.Revenue, 0) AS ViewRevenue
, NULLIF(DP.WarehousingQuantity, 0) AS ViewWarehousingQuantity
, CASE
WHEN A.Warehousing = 1 THEN AIS.NowAvailable
ELSE NULLIF(A.Warehousing, 0)
END AS ViewNowAvailable
, D.DocNumber
, D.DocCategoryId
, D.DocTypeId
, D.InventoryStatusId
, D.WarehousingEffective as DocWarehousingEffective
, D.RevenueEffective as DocRevenueEffective
, D.StatusId as DocStatusId
, D.PartnerId
, D.DocDate
, D.PostingDate
, D.Draft
, D.DocXmlId
, DPT.Name AS PositionTypeName
, AIS.Stock
, AIS.Confirmed
, AIS.Packed
, AIS.Ordered
, AIS.Announced
, AIS.NowAvailable
, AIS.AvailableToPromise
, AIS.LaterAvailable
, AIS.MinimumStock
, AIS.MaximumStock
, A.IndividualizationTypeId
, A.DecimalPlacesQuantitiesId
, A.MinimumQuantity
, A.DeliveryTime
, A.LotSize
, APC.PercentageMarkup1
, APC.FixedMarkup1
, APC.IntermediateCalculatedSalesPrice
, APC.PercentageMarkup2
, APC.FixedMarkup2
, APC.CalculatedSalesPrice
, APC.ProcurementPrice
, APC.Factor
, APC.WarehouseCost
, APC.OverheadCost
, APC.OtherCost
, APC.ChangeInValue
, APC.CostPrice
, ROUND(APC.CostPrice * DP.Quantity/A.PriceUnitId, 2) AS CurrentCostPriceTotal
, ROUND(APC.CostPrice * DP.Quantity/A.PriceUnitId, 2) - DP.CostPriceTotal AS CostPriceDifference
, DPIT.InfoText
, DPOT.OrderText
, DPDT.DimensionText
, P.Matchcode
, PD.Id AS BusinessPartnerNumber
, UOM.Name AS UoMName
, AParent.WithSet AS ParentWithSet
, AParent.WithMacro  AS ParentWithMacro
, AParent.WithAccessory AS ParentWithAccessory
, ROUND(
(ISNULL(DP.ForeignCurrencyPrice, 0))
* (1 - ((ISNULL(DP.DiscountPercent, 0) + ISNULL(DP.QuantityDiscountPercent, 0) + ISNULL(DP.DocDiscountPercent, 0)) / 100.0))
/ NULLIF(ISNULL(DP.PriceUnitId, 1), 0)
* ISNULL(DP.Quantity, 0)
* ISNULL(DP.PrepaymentFactor, 0)
, 2) AS TotalPriceForeignCurrency
, (ISNULL(CONVERT(decimal(19,6), ROUND(ISNULL(DP.ForeignCurrencyPrice,0) * (1 - ((ISNULL(DP.DiscountPercent,0) + ISNULL(DP.QuantityDiscountPercent,0) + ISNULL(DP.DocDiscountPercent,0)) / 100.0)) / NULLIF(ISNULL(DP.PriceUnitId,1), 0) * ISNULL(DP.Quantity,0) * ISNULL(DP.PrepaymentFactor,0), 2) * ISNULL(DP.TaxFactor,0) * (ISNULL(DP.TaxPercent,0) / 100.0)), 0)) AS TaxForeignCurrency
FROM DocPosition DP
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON DP.ArticleId = AIS.ArticleId
LEFT JOIN [Article] A ON DP.ArticleId = A.Id
LEFT JOIN ArticleUoM UOM ON A.UoMId = UOM.Id
LEFT JOIN DocPositionInfoText DPIT ON DP.Id = DPIT.DocPositionId
LEFT JOIN DocPositionOrderText DPOT ON DP.Id = DPOT.DocPositionId
LEFT JOIN DocPositionDimensionText DPDT ON DP.Id = DPDT.DocPositionId
LEFT JOIN DocPositionType DPT ON DP.PositionTypeId = DPT.Id
LEFT JOIN ArticlePriceCalculation APC ON DP.ArticleId = APC.ArticleId
INNER JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN Partner P ON D.PartnerId = P.Id
LEFT JOIN PartnerDetail PD ON PD.Id= D.PartnerDetailId
LEFT JOIN DocPosition DPParent ON DPParent.Id= DP.ParentPositionId
LEFT JOIN Article AParent ON AParent.Id= DPParent.ArticleId
GO
-- END xVIEW_DocPosition ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW_Crm
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns CRM entries with partner, contact person, and employee matchcodes.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
C.PartnerId As Id
, C.*
, P.Matchcode AS PartnerMatchcode
, PCP.Matchcode AS PartnerContactPersonMatchcode
, E.Matchcode AS EmployeeMatchcode
