CREATE OR ALTER VIEW
xVIEW_ProductionPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns all production positions with related article, quantity, availability, production and cost details.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
PP.*
, PP.RowNumber AS ViewRowNumber
, FORMAT(PP.PositionQuantityPlanned, 'N' + CAST(A.DecimalPlacesQuantitiesId AS varchar)) AS FormattedQuantity
, CASE
WHEN PP.ChildPositionNumber IS NULL THEN CAST(PP.PositionNumber AS NVARCHAR(10))
ELSE CONCAT(CAST(PP.PositionNumber AS NVARCHAR(10)), '.', CAST(PP.ChildPositionNumber AS NVARCHAR(10)))
END AS PositionNumberConcat
, CASE
WHEN A.Warehousing = 1 THEN AIS.NowAvailable
ELSE NULLIF(A.Warehousing, 0)
END AS ViewNowAvailable
, PROD.ProductionNumber
, PPT.Name AS PositionTypeName
, AIS.Stock
, AIS.Confirmed
, AIS.Packed
, AIS.Ordered
, AIS.Announced
, AIS.NowAvailable
, AIS.LaterAvailable
, AIS.MinimumStock
, AIS.MaximumStock
, A.IndividualizationTypeId
, A.DecimalPlacesQuantitiesId
, A.MinimumQuantity
, A.DeliveryTime
, A.LotSize
, APC.PercentageMarkup1
, APC.FixedMarkup1
, APC.IntermediateCalculatedSalesPrice
, APC.PercentageMarkup2
, APC.FixedMarkup2
, APC.CalculatedSalesPrice
, APC.ProcurementPrice
, APC.Factor
, APC.WarehouseCost
, APC.OverheadCost
, APC.OtherCost
, APC.ChangeInValue
, APC.CostPrice
, UOM.Name AS UoMName
, UOM.ProductionDurationUnitId
, AParent.WithSet AS ParentWithSet
, AParent.WithMacro  AS ParentWithMacro
, AParent.WithAccessory AS ParentWithAccessory
FROM ProductionPosition PP
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON PP.ArticleId = AIS.ArticleId
LEFT JOIN [Article] A ON PP.ArticleId = A.Id
LEFT JOIN ArticleUoM UOM ON A.UoMId = UOM.Id
LEFT JOIN ProductionPositionType PPT ON PP.PositionTypeId = PPT.Id
LEFT JOIN ArticlePriceCalculation APC ON PP.ArticleId = APC.ArticleId
INNER JOIN Production PROD ON PP.ProductionId = PROD.Id
LEFT JOIN ProductionPosition PPParent ON PPParent.Id= PP.ParentPositionId
LEFT JOIN Article AParent ON AParent.Id= PPParent.ArticleId
GO
-- END xVIEW_ProductionPosition ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
