CREATE OR ALTER VIEW
xVIEW131_ArticleProduct
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns article production components with associated article matchcode, component matchcode, and decimal places for quantities.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
AP.*
, A.Matchcode ArticleMatchcode
, C.UoMId
, C.DecimalPlacesQuantitiesId
, C.Matchcode ComponentMatchcode
, C.PriceUnitId
, APC.CostPrice / C.PriceUnitId AS CostPrice 
, APC.CalculatedSalesPrice / C.PriceUnitId AS CalculatedSalesPrice 
, APC.CostPrice * QuantityFactor / C.PriceUnitId AS TotalCostPrice
, APC.CalculatedSalesPrice * QuantityFactor / C.PriceUnitId AS TotalCalculatedSalesPrice 
, ((APC.CalculatedSalesPrice * QuantityFactor) - (APC.CostPrice * QuantityFactor)) / C.PriceUnitId AS Profit 
FROM [dbo].[ArticleProduct] AP
INNER JOIN Article A ON AP.[ArticleId] = A.Id
INNER JOIN Article C ON AP.[ComponentId] = C.Id
LEFT JOIN ArticlePriceCalculation APC ON APC.ArticleId = C.Id
GO
