xVIEW139_ArticleIndividualizationQuantityHistory
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns current and historical article individualization quantity data with related document, inventory counting, production, and Transfer details, including time-travel metadata.
-----------------------------------------------------------------------------------------
*/
AS
WITH CombinedData AS (
SELECT
AIQ.WarehouseId
, AIQ.BinLocationId
, AIQ.ArticleIndividualizationId
, NULLIF(AIQ.Stock, 0) AS Stock
, NULLIF(AIQ.Packed, 0) AS Packed
, NULLIF(AIQ.NowAvailable, 0) AS NowAvailable
, AIQ.InventoryCountingPosition
, AIQ.DocPosition
, AIQ.ProductionPosition
, AIQ.TransferPosition
, AIQ.SysStartTime
, AIQ.SysEndTime
, DP.Id AS DocPositionId
, D.DocNumber
, 'Current' AS DataStatus
, NULLIF(WIC.Id, 0) AS WarehouseInventoryCountingId
, P.Id AS ProductionId
, WM.Id AS TransferId
, A.DecimalPlacesQuantitiesId
, A.Warehousing
FROM dbo.ArticleIndividualizationQuantity AIQ
LEFT JOIN DocPosition DP ON AIQ.DocPosition = DP.Id
LEFT JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN WarehouseInventoryCountingPosition WICP ON AIQ.InventoryCountingPosition = WICP.Id
LEFT JOIN WarehouseInventoryCounting WIC ON WICP.WarehouseInventoryCountingId = WIC.Id
LEFT JOIN ProductionPosition PP ON AIQ.ProductionPosition = PP.Id
LEFT JOIN Production P ON PP.ProductionId = P.Id
LEFT JOIN WarehouseTransferPosition WMP ON AIQ.TransferPosition = WMP.Id
LEFT JOIN WarehouseTransfer WM ON WMP.WarehouseTransferId = WM.Id
INNER JOIN ArticleIndividualization AI ON AI.Id= AIQ.ArticleIndividualizationId
INNER JOIN Article A ON AI.ArticleId = A.Id
UNION ALL
SELECT
AIQH.WarehouseId
, AIQH.BinLocationId
, AIQH.ArticleIndividualizationId
, NULLIF(AIQH.Stock, 0) AS Stock
, NULLIF(AIQH.Packed, 0) AS Packed
, NULLIF(AIQH.NowAvailable, 0) AS NowAvailable
, AIQH.InventoryCountingPosition
, AIQH.DocPosition
, AIQH.ProductionPosition
, AIQH.TransferPosition
, AIQH.SysStartTime
, AIQH.SysEndTime
, DP.Id AS DocPositionId
, D.DocNumber
, 'Historical' AS DataStatus
, NULLIF(WIC.Id, 0) AS WarehouseInventoryCountingId
, P.Id AS ProductionId
, WM.Id AS TransferId
, A.DecimalPlacesQuantitiesId
, A.Warehousing
FROM dbo.ArticleIndividualizationQuantityHistory AIQH
LEFT JOIN DocPosition DP ON AIQH.DocPosition = DP.Id
LEFT JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN WarehouseInventoryCountingPosition WICP ON AIQH.InventoryCountingPosition = WICP.Id
LEFT JOIN WarehouseInventoryCounting WIC ON WICP.WarehouseInventoryCountingId = WIC.Id
LEFT JOIN ProductionPosition PP ON AIQH.ProductionPosition = PP.Id
LEFT JOIN Production P ON PP.ProductionId = P.Id
LEFT JOIN WarehouseTransferPosition WMP ON AIQH.TransferPosition = WMP.Id
LEFT JOIN WarehouseTransfer WM ON WMP.WarehouseTransferId = WM.Id
INNER JOIN ArticleIndividualization AI ON AI.Id= AIQH.ArticleIndividualizationId
INNER JOIN Article A ON AI.ArticleId = A.Id
)
SELECT
CAST(ROW_NUMBER() OVER (ORDER BY SysStartTime DESC, ArticleIndividualizationId) AS int) AS HistoryId
, *
FROM CombinedData
GO
