CREATE OR ALTER VIEW
xVIEW145_ArticleRevenueMonthly
/*
-----------------------------------------------------------------------------------------
Purpose: Provides monthly aggregated purchase and sales quantities and revenues for each article.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
CAST(
ROW_NUMBER() OVER (
ORDER BY
DP.ArticleId
, YEAR(D.DocDate)
, MONTH(D.DocDate)
) AS int
) AS Id
, DP.ArticleId AS [ArticleId]
, YEAR(D.DocDate) AS [YEAR]
, MONTH(D.DocDate) AS [MONTH]
, SUM(CASE WHEN D.DocCategoryId = 'Purchase' THEN DP.Quantity*D.RevenueEffective ELSE 0 END) AS [PurchaseQuantity]
, ROUND(SUM(CASE WHEN D.DocCategoryId = 'Purchase' THEN TotalPrice*D.RevenueEffective ELSE 0 END), 2) AS [PurchaseAmount]
, SUM(CASE WHEN D.DocCategoryId = 'Sales' THEN DP.Quantity*D.RevenueEffective ELSE 0 END) AS [SalesQuantity]
, ROUND(SUM(CASE WHEN D.DocCategoryId = 'Sales' THEN TotalPrice*D.RevenueEffective ELSE 0 END), 2) AS [SalesRevenue]
, A.DecimalPlacesQuantitiesId
, SUM(DP.ProfitAmount) AS ProfitAmount
, ISNULL(SUM(DP.ProfitAmount) / NULLIF(ROUND(SUM(CASE WHEN D.DocCategoryId = 'Sales' THEN TotalPrice*D.RevenueEffective ELSE 0 END), 2) , 0), 0) * 100 AS ProfitPercent
FROM DocPosition DP
JOIN Doc D ON DP.DocId = D.Id
JOIN Article A ON DP.ArticleId = A.Id
WHERE D.RevenueEffective != 0
GROUP BY DP.ArticleId, A.DecimalPlacesQuantitiesId, YEAR(D.DocDate), MONTH(D.DocDate);
GO
-- END xVIEW145_ArticleRevenueMonthly ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
