CREATE OR ALTER VIEW
xVIEW150_PartnerRevenueMonthly
/*
-----------------------------------------------------------------------------------------
Purpose: Provides monthly aggregated revenue by partner with year and month grouping.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
CAST(
ROW_NUMBER() OVER (
ORDER BY
D.PartnerId
, YEAR(D.DocDate)
, MONTH(D.DocDate)
) AS int
) AS Id
, D.PartnerId
, YEAR(D.DocDate) AS [Year]
, MONTH(D.DocDate) AS [Month]
, ROUND(SUM(D.TotalPriceSum * D.RevenueEffective), 2) AS [Revenue]
FROM dbo.xVIEW_Doc AS D
WHERE D.RevenueEffective != 0
GROUP BY D.PartnerId , YEAR(D.DocDate) , MONTH(D.DocDate);
GO
-- END xVIEW150_PartnerRevenueMonthly ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
