CREATE OR ALTER VIEW
xVIEW156_PartnerHistory
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns current and historical Partner quantity data with related document, inventory counting, and production details, including time-travel metadata.
-----------------------------------------------------------------------------------------
*/
AS
WITH CombinedData AS (
SELECT
U.*
,PG.Name AS PartnerGroupName
,AL.Location LocationName
,E.Matchcode AS CreatedByName
,E2.Matchcode AS ModifiedByName
FROM
(SELECT * FROM dbo.[Partner]
UNION ALL
SELECT * FROM dbo.[PartnerHistory]) U
INNER JOIN PartnerGroup PG ON U.PartnerGroupId = PG.Id
INNER JOIN AdminLocation AL ON U.LocationId = AL.Id
LEFT JOIN Employee E ON U.CreatedBy = E.Id
LEFT JOIN Employee E2 ON U.ModifiedBy = E2.Id
)
SELECT
CAST(ROW_NUMBER() OVER (PARTITION BY Id ORDER BY SysStartTime DESC) AS INT) AS HistoryId
, *
FROM CombinedData
GO
-- END xVIEW156_PartnerHistory ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW156_PartnerDetailHistory
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns current and historical PartnerDetail quantity data with related document, inventory counting, and production details, including time-travel metadata.
-----------------------------------------------------------------------------------------
*/
AS
WITH CombinedData AS (
SELECT
U.*
, P.Matchcode AS PartnerName
, P2.Matchcode AS DivergentInvoiceRecipientName
, PT.Name AS PartnerTypeName
, PTOP.Name AS TermsOfPaymentName
, PDB.Name AS BankingName
, PTOD.Name AS TermsOfDeliveryName
, FGP.Name AS FinanceGroupPartnerName
, FCC.CostCenter AS CostCenterName
, PCP.Matchcode AS StandardContactPersonName
, PDA.Matchcode AS StandardDeliveryAddressName
, PBA.Matchcode AS StandardBillingAddressName
, PDGN.Name AS DiscountGroupName
, ASPN.Name AS PriceListSalesName
, AEDT.EDocType AS EDocTypeName
, E.Matchcode AS SalesPersonName
, E2.Matchcode AS EmployeeName
FROM
(SELECT * FROM dbo.[PartnerDetail]
UNION ALL
SELECT * FROM dbo.[PartnerDetailHistory]) U
INNER JOIN [Partner] P ON U.PartnerId = P.Id
INNER JOIN [PartnerType] PT ON U.PartnerTypeId = PT.Id
INNER JOIN [PartnerTermsOfPayment] PTOP ON U.TermsOfPaymentId = PTOP.Id
INNER JOIN [PartnerDetailBanking] PDB ON U.BankingId = PDB.Id
INNER JOIN [PartnerTermsOfDelivery] PTOD ON U.TermsOfDeliveryId = PTOD.Id
INNER JOIN [FinanceGroupPartner] FGP ON U.FinanceGroupPartnerDetailId = FGP.Id
LEFT JOIN [FinanceCostCenter] FCC ON U.CostCenterId = FCC.Id
LEFT JOIN [PartnerContactPerson] PCP ON U.StandardContactPersonId = PCP.Id
LEFT JOIN [PartnerDeliveryAddress] PDA ON U.StandardDeliveryAddressId = PDA.Id
INNER JOIN [PartnerBillingAddress] PBA ON U.StandardBillingAddressId = PBA.Id
LEFT JOIN [PartnerDiscountGroupName] PDGN ON U.DiscountGroupNameId = PDGN.Id
LEFT JOIN [ArticleSalesPriceListName] ASPN ON U.PriceListSalesId = ASPN.Id
INNER JOIN [AdminEDocType] AEDT ON U.EDocTypeId = AEDT.Id
LEFT JOIN [Partner] P2 ON U.DivergentInvoiceRecipientId = P2.Id
LEFT JOIN [Employee] E ON U.SalesPersonId = E.Id
LEFT JOIN [Employee] E2 ON U.EmployeeId = E2.Id
)
SELECT
CAST(ROW_NUMBER() OVER (PARTITION BY PartnerId ORDER BY PartnerTypeId ASC, SysStartTime DESC) AS INT) AS HistoryId
, *
FROM CombinedData
GO
-- END xVIEW156_PartnerDetailHistory ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
