CREATE OR ALTER VIEW
xVIEW181_EmployeeVacationEntitlement
/*
-----------------------------------------------------------------------------------------
Purpose: Calculates Used and Remaining Vacation Days.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
EVE.*
, Used = ISNULL(EVR.Used, 0)
, Remaining = ISNULL(EVE.Entitlement, 0) - ISNULL(EVR.Used, 0)
FROM dbo.EmployeeVacationEntitlement AS EVE
OUTER APPLY
(
SELECT
Used = SUM(ISNULL(R.VacationDays, 0))
FROM dbo.EmployeeVacationRequest AS R
WHERE R.YearId = EVE.YearId
AND R.EmployeeId = EVE.EmployeeId
AND R.Approved = 1
) AS EVR
GO
-- END xVIEW181_EmployeeVacationEntitlement ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
