CREATE OR ALTER VIEW
xVIEW193_WarehouseQuantity
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns current warehouse quantity including stock, packed, availability, thresholds, document references, inventory counting and Transfer details, production number, system-time metadata, and decimal precision.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
WQ.Id
, WQ.WarehouseId
, WQ.BinLocationId
, WQ.ArticleId
, WQ.Stock
, WQ.Packed
, WQ.NowAvailable
, WQ.MinimumStock
, WQ.MessageThreshold
, WQ.MaximumStock
, WQ.InventoryCountingPosition
, WQ.DocPosition
, WQ.ProductionPosition
, WQ.TransferPosition
, WQ.RowVersion
, WQ.SysStartTime
, WQ.SysEndTime
, DP.Id AS DocPositionId
, D.DocNumber
, 'Current' AS DataStatus
, NULLIF(WIC.Id, 0) AS WarehouseInventoryCountingId
, P.ProductionNumber AS ProductionNumber
, WM.Id AS TransferId
, A.DecimalPlacesQuantitiesId
, A.Warehousing
, W.WarehouseName
, WBL.Name AS WarehouseBinLocationName
FROM dbo.WarehouseQuantity WQ
LEFT JOIN DocPosition DP ON WQ.DocPosition = DP.Id
LEFT JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN WarehouseInventoryCountingPosition WICP ON WQ.InventoryCountingPosition = WICP.Id
LEFT JOIN WarehouseInventoryCounting WIC ON WICP.WarehouseInventoryCountingId = WIC.Id
LEFT JOIN ProductionPosition PP ON WQ.ProductionPosition = PP.Id
LEFT JOIN Production P ON PP.ProductionId = P.Id
LEFT JOIN WarehouseTransferPosition WMP ON WQ.TransferPosition = WMP.Id
LEFT JOIN WarehouseTransfer WM ON WMP.WarehouseTransferId = WM.Id
LEFT JOIN Warehouse W ON W.Id = WQ.WarehouseId
LEFT JOIN WarehouseBinLocation WBL ON WBL.Id = WQ.BinLocationId
INNER JOIN Article A ON WQ.ArticleId = A.Id
GO
-- END xVIEW193_WarehouseQuantity ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW193_WarehouseQuantityHistoryTable
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns combined current and historical warehouse quantity data with related document, inventory counting, production, Transfer details, and system-time metadata, including a sequential HistoryId.
-----------------------------------------------------------------------------------------
*/
AS
WITH CombinedData AS (
SELECT
WQ.WarehouseId
, WQ.BinLocationId
, WQ.ArticleId
, WQ.Stock
, WQ.Packed
, WQ.NowAvailable
, WQ.MinimumStock
, WQ.MessageThreshold
, WQ.MaximumStock
, WQ.InventoryCountingPosition
, WQ.DocPosition
, WQ.ProductionPosition
, WQ.TransferPosition
, WQ.RowVersion
, WQ.SysStartTime
, WQ.SysEndTime
, DP.Id AS DocPositionId
, D.DocNumber
, 'Current' AS DataStatus
, NULLIF(WIC.Id, 0) AS WarehouseInventoryCountingId
, P.ProductionNumber AS ProductionNumber 
, WM.Id AS TransferId
, A.DecimalPlacesQuantitiesId
, A.Warehousing
FROM dbo.WarehouseQuantity WQ
LEFT JOIN DocPosition DP ON WQ.DocPosition = DP.Id
LEFT JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN WarehouseInventoryCountingPosition WICP ON WQ.InventoryCountingPosition = WICP.Id
LEFT JOIN WarehouseInventoryCounting WIC ON WICP.WarehouseInventoryCountingId = WIC.Id
LEFT JOIN ProductionPosition PP ON WQ.ProductionPosition = PP.Id
LEFT JOIN Production P ON PP.ProductionId = P.Id
LEFT JOIN WarehouseTransferPosition WMP ON WQ.TransferPosition = WMP.Id
LEFT JOIN WarehouseTransfer WM ON WMP.WarehouseTransferId = WM.Id
INNER JOIN Article A ON WQ.ArticleId = A.Id
UNION ALL
SELECT
WQH.WarehouseId
, WQH.BinLocationId
, WQH.ArticleId
, WQH.Stock
, WQH.Packed
, WQH.NowAvailable
, WQH.MinimumStock
, WQH.MessageThreshold
, WQH.MaximumStock
, WQH.InventoryCountingPosition
, WQH.DocPosition
, WQH.ProductionPosition
, WQH.TransferPosition
, WQH.RowVersion
, WQH.SysStartTime
, WQH.SysEndTime
, DP.Id AS DocPositionId
, D.DocNumber
, 'Historical' AS DataStatus  -- Änderung zu 'Historical' für Klarheit
, NULLIF(WIC.Id, 0) AS WarehouseInventoryCountingId
, P.ProductionNumber AS ProductionNumber 
, WM.Id AS TransferId
, A.DecimalPlacesQuantitiesId
, A.Warehousing
FROM dbo.WarehouseQuantityHistory WQH
LEFT JOIN DocPosition DP ON WQH.DocPosition = DP.Id
LEFT JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN WarehouseInventoryCountingPosition WICP ON WQH.InventoryCountingPosition = WICP.Id
LEFT JOIN WarehouseInventoryCounting WIC ON WICP.WarehouseInventoryCountingId = WIC.Id
LEFT JOIN ProductionPosition PP ON WQH.ProductionPosition = PP.Id
LEFT JOIN Production P ON PP.ProductionId = P.Id
LEFT JOIN WarehouseTransferPosition WMP ON WQH.TransferPosition = WMP.Id
LEFT JOIN WarehouseTransfer WM ON WMP.WarehouseTransferId = WM.Id
INNER JOIN Article A ON WQH.ArticleId = A.Id
)
SELECT
CAST(ROW_NUMBER() OVER (ORDER BY SysEndTime ASC, WarehouseId, BinLocationId, ArticleId) AS int) AS HistoryId
, *
FROM CombinedData
GO
-- END xVIEW193_WarehouseQuantityHistoryTable ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW200_DocTypeSequence
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns document history records with a sequential HistoryId based on SysStartTime.
-----------------------------------------------------------------------------------------
