COALESCE(
(
SELECT s.current_value
FROM sys.sequences AS s
WHERE s.name = 'Doc_' + CAST(DT.Id AS NVARCHAR(100)) + '_sequence'
),
0
) AS INT
) AS CurrentSequenceValue
FROM DocType AS DT;
