CREATE OR ALTER VIEW
xVIEW207_DocRevenue
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns Posting date, costs, revenue, profit, partner detail number, and partner matchcode for each document.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
CAST(D.DocDate AS DATETIME) AS DocDate
, CASE WHEN DocCategoryId = 'Purchase' THEN TotalPrice * D.RevenueEffective ELSE 0 END AS Costs
, CASE WHEN DocCategoryId = 'Sales' THEN TotalPrice * D.RevenueEffective ELSE 0 END AS Revenue
, TotalPrice * D.RevenueEffective AS Profit
, PD.Id AS BusinessPartnerNumber
, P.Matchcode
, P.PartnerGroupId
, A.ArticleGroupId
, AG.Name AS ArticleGroupName
, PG.Name AS PartnerGroupName
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Article A ON A.Id = DP.ArticleId
LEFT JOIN PartnerDetail PD ON D.PartnerDetailId = PD.Id
LEFT JOIN Partner P ON PD.PartnerId = P.Id
LEFT JOIN PartnerGroup PG ON P.PartnerGroupId = PG.Id
LEFT JOIN ArticleGroup AG ON A.ArticleGroupId = AG.Id
WHERE
D.PostingDate IS NOT NULL;
GO
-- END xVIEW207_DocRevenue ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
