GO
CREATE OR ALTER VIEW
xVIEW220_DocPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns document positions with formatted quantities, view-specific revenue and availability fields, and related document, article, partner, and cost details.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
DP.*
, DP.RowNumber AS ViewRowNumber
, FORMAT(DP.Quantity, 'N' + CAST(A.DecimalPlacesQuantitiesId AS varchar)) AS FormattedQuantity
, CASE
WHEN DP.ChildPositionNumber IS NULL THEN CAST(DP.PositionNumber AS NVARCHAR(10))
ELSE CONCAT(CAST(DP.PositionNumber AS NVARCHAR(10)), '.', CAST(DP.ChildPositionNumber AS NVARCHAR(10)))
END AS PositionNumberConcat
, NULLIF(DP.Revenue, 0) AS ViewRevenue
, NULLIF(DP.WarehousingQuantity, 0) AS ViewWarehousingQuantity
, CASE
WHEN A.Warehousing = 1 THEN AIS.NowAvailable
ELSE NULLIF(A.Warehousing, 0)
END AS ViewNowAvailable
, D.DocNumber
, D.DocCategoryId
, D.DocTypeId
, D.InventoryStatusId
, D.WarehousingEffective as DocWarehousingEffective
, D.RevenueEffective as DocRevenueEffective
, D.StatusId as DocStatusId
, D.PartnerId
, D.DocDate
, D.PostingDate
, D.Draft
, D.DocXmlId
, DPT.Name AS PositionTypeName
, AIS.Stock
, AIS.Confirmed
, AIS.Packed
, AIS.Ordered
, AIS.Announced
, AIS.NowAvailable
, AIS.LaterAvailable
, AIS.MinimumStock
, AIS.MaximumStock
, A.IndividualizationTypeId
, A.DecimalPlacesQuantitiesId
, A.MinimumQuantity
, A.DeliveryTime
, A.LotSize
, APC.PercentageMarkup1
, APC.FixedMarkup1
, APC.IntermediateCalculatedSalesPrice
, APC.PercentageMarkup2
, APC.FixedMarkup2
, APC.CalculatedSalesPrice
, APC.ProcurementPrice
, APC.Factor
, APC.WarehouseCost
, APC.OverheadCost
, APC.OtherCost
, APC.ChangeInValue
, APC.CostPrice
, DPIT.InfoText
, DPOT.OrderText
, DPDT.DimensionText
, P.Matchcode
, PD.Id AS BusinessPartnerNumber
, UOM.Name AS UoMName
, AParent.WithSet AS ParentWithSet
, AParent.WithMacro  AS ParentWithMacro
, AParent.WithAccessory AS ParentWithAccessory
FROM DocPosition DP
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON DP.ArticleId = AIS.ArticleId
LEFT JOIN [Article] A ON DP.ArticleId = A.Id
LEFT JOIN ArticleUoM UOM ON A.UoMId = UOM.Id
LEFT JOIN DocPositionInfoText DPIT ON DP.Id = DPIT.DocPositionId
LEFT JOIN DocPositionOrderText DPOT ON DP.Id = DPOT.DocPositionId
LEFT JOIN DocPositionDimensionText DPDT ON DP.Id = DPDT.DocPositionId
LEFT JOIN DocPositionType DPT ON DP.PositionTypeId = DPT.Id
LEFT JOIN ArticlePriceCalculation APC ON DP.ArticleId = APC.ArticleId
INNER JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN Partner P ON D.PartnerId = P.Id
LEFT JOIN PartnerDetail PD ON PD.Id= D.PartnerDetailId
LEFT JOIN DocPosition DPParent ON DPParent.Id= DP.ParentPositionId
LEFT JOIN Article AParent ON AParent.Id= DPParent.ArticleId
GO
-- END xVIEW220_DocPosition ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
