CREATE OR ALTER VIEW
xVIEW223_DocPosition_Prices
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns article-type document positions with quantity, UoM, pricing, discounts, total and cost prices, profit for sales, article group, document category and type, partner matchcode, status, and related metadata.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
DP.ArticleId AS ArticleNumber
, DP.Name1 AS Name1
, DP.Quantity AS Quantity
, AUOM.Name AS UoM
, DP.Price AS Price
, DP.DiscountPercent AS DiscountPercent
, DP.QuantityDiscountPercent AS QuantityDiscountPercent
, DP.DocDiscountPercent AS DocDiscountPercent 
, DP.TotalPrice AS TotalPrice
, DP.CostPriceTotal AS CostPriceTotal
, CASE WHEN D.DocCategoryId = 'Sales' THEN (DP.TotalPrice - DP.CostPriceTotal) ELSE NULL END AS Profit
, AG.Name AS ArticleGroup
, DC.Name AS DocCategory
, D.DocNumber
, DT.Name AS DocType
, DP.DeliveryDate AS DeliveryDate
, DP.Revenue AS Revenue
, DP.WarehousingQuantity AS Warehousing
, PD.Id AS BusinessPartnerNumber
, P.Matchcode AS PartnerMatchcode
, DPS.Name AS Status
FROM DocPosition DP
INNER JOIN Doc D ON DP.DocId = D.Id
INNER JOIN DocCategory DC ON D.DocCategoryId = DC.Id
INNER JOIN DocType DT ON D.DocTypeId = DT.Id
INNER JOIN Partner P ON D.PartnerId = P.Id
INNER JOIN DocPositionStatus DPS ON DP.StatusId = DPS.Id
INNER JOIN PartnerDetail PD ON D.PartnerDetailId = PD.Id
INNER JOIN ArticleUoM AUOM ON DP.UoMId = AUOM.Id
INNER JOIN Article A ON DP.ArticleId = A.Id
INNER JOIN ArticleGroup AG ON A.ArticleGroupId = AG.Id
WHERE
DP.PositionTypeId = 'Article'
GO
-- END xVIEW223_DocPosition_Prices ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW224_DocPosition_Backlog
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns backlog quantities for document positions by inventory status with total open price and related document, partner, article, and category metadata for backlog dashboard.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
DP.ArticleId AS ArticleNumber
, DP.Name1 AS Name1
, CASE
WHEN D.InventoryStatusId = 'confirmed' THEN DP.QuantityOpen
ELSE 0
END AS Confirmed
, CASE
WHEN D.InventoryStatusId = 'packed' THEN DP.QuantityOpen
ELSE 0
END AS Packed
, CASE
WHEN D.InventoryStatusId = 'ordered' THEN DP.QuantityOpen
ELSE 0
END AS Ordered
, CASE
WHEN D.InventoryStatusId = 'announced' THEN DP.QuantityOpen
ELSE 0
END AS Announced
, AUOM.Name AS UoM
, CASE
WHEN D.DocCategoryId = 'Purchase' THEN DP.Price * DP.QuantityOpen * -1
ELSE DP.Price * DP.QuantityOpen
END AS TotalPriceOpen
, D.DocCategoryId
, D.DocNumber
, DC.Name AS DocCategory
, D.DocTypeId
, DT.Name AS DocType
, CAST(DP.DeliveryDate AS DATETIME) AS DeliveryDate
, PD.Id AS BusinessPartnerNumber
, P.Matchcode AS PartnerMatchcode
, AG.Name AS ArticleGroup
, A.Matchcode AS ArticleMatchcode
FROM DOC D
INNER JOIN DocPosition DP ON D.Id = DP.DocId
INNER JOIN DocCategory DC ON D.DocCategoryId = DC.Id
INNER JOIN DocType DT ON D.DocTypeId = DT.Id
INNER JOIN Partner P ON D.PartnerId = P.Id
INNER JOIN PartnerDetail PD ON D.PartnerDetailId = PD.Id
INNER JOIN ArticleUoM AUOM ON DP.UoMId = AUOM.Id
INNER JOIN Article A ON DP.ArticleId = A.Id
INNER JOIN ArticleGroup AG ON A.ArticleGroupId = AG.Id
WHERE
D.InventoryStatusId IN ('confirmed', 'packed', 'ordered', 'announced')
AND
D.StatusId IN ('open', 'partially')
AND
DP.StatusId IN ('open', 'partially')
GO
-- END xVIEW224_DocPosition_Backlog ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW225_DocPositionWarehousing
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns warehousing details for document positions, including warehouse/bin info, quantities, availability, individualization data, and related document and article metadata.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
DPWHG.[Id]
, DPWHG.[DocPositionId]
, DPWHG.[WarehouseId]
, DPWHG.[BinLocationId]
, DPWHG.[Quantity]
, DPWHG.[IndividualizationTypeId]
, DPWHG.[IndividualizationNumberId]
, DPWHG.[WarehousingEffective]
, DPWHG.[WarehousingQuantity]
, DPWHG.[WarehouseMediumId]
, W.BinLocation HasBinLocation
, WBL.[Name] BinLocationName
, WQ.Stock
, WQ.NowAvailable
, D.DocCategoryId
, DP.ArticleId
, AI.IsBatch
, AIQ.Stock AS IndividualizationStock
, AIQ.Packed AS IndividualizationPacked
, AIQ.NowAvailable AS IndividualizationNowAvailable
FROM [dbo].[DocPositionWarehousing] DPWHG
INNER JOIN Warehouse W ON DPWHG.WarehouseId = W.Id
LEFT JOIN WarehouseBinLocation WBL ON DPWHG.BinLocationId = WBL.Id
INNER JOIN DocPosition DP ON DP.Id = DPWHG.DocPositionId
LEFT JOIN WarehouseQuantity WQ ON WQ.WarehouseId = DPWHG.WarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(DPWHG.BinLocationId,0) AND WQ.ArticleId = DP.ArticleId
INNER JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN ArticleIndividualization AI ON DPWHG.IndividualizationNumberId = AI.Id
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = DPWHG.IndividualizationNumberId AND AIQ.WarehouseId = DPWHG.WarehouseId AND ISNULL(DPWHG.BinLocationId,0) = ISNULL(AIQ.BinLocationId,0) 
GO
-- END xVIEW225_DocPositionWarehousing ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW265_DocXmlPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns XML document positions with formatted quantities, view‐specific revenue and availability fields, article match flag, and related document, partner-detail, and article metadata.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
DXP.*
, DXP.RowNumber AS ViewRowNumber
, FORMAT(DXP.Quantity, 'N' + CAST(A.DecimalPlacesQuantitiesId AS varchar)) AS FormattedQuantity
, CASE
WHEN DXP.ChildPositionNumber IS NULL THEN CAST(DXP.PositionNumber AS NVARCHAR(10))
ELSE CONCAT(CAST(DXP.PositionNumber AS NVARCHAR(10)), '.', CAST(DXP.ChildPositionNumber AS NVARCHAR(10)))
END AS PositionNumberConcat
, NULLIF(DXP.Revenue, 0) AS ViewRevenue
, NULLIF(DXP.WarehousingQuantity, 0) AS ViewWarehousingQuantity
, CASE
WHEN A.Warehousing = 1 THEN AIS.NowAvailable
ELSE NULLIF(A.Warehousing, 0)
END AS ViewNowAvailable
, DX.DocNumber
, DX.DocCategoryId
, DX.DocTypeId
, DX.DocDate
, DX.PostingDate
, DX.Draft
, DPT.Name AS PositionTypeName
, AIS.Stock
, AIS.Confirmed
, AIS.Packed
, AIS.Ordered
, AIS.Announced
, AIS.NowAvailable
, AIS.LaterAvailable
, AIS.MinimumStock
, AIS.MaximumStock
, A.Matchcode ArticleMatchcode
, A.IndividualizationTypeId
, A.DecimalPlacesQuantitiesId
, A.MinimumQuantity
, A.DeliveryTime
, A.LotSize
, APC.PercentageMarkup1
, APC.FixedMarkup1
, APC.IntermediateCalculatedSalesPrice
, APC.PercentageMarkup2
, APC.FixedMarkup2
, APC.CalculatedSalesPrice
, APC.ProcurementPrice
, APC.Factor
, APC.WarehouseCost
, APC.OverheadCost
, APC.OtherCost
, APC.ChangeInValue
, APC.CostPrice
, P.Matchcode
, PD.Id AS BusinessPartnerNumber
, AUOM.Name AS UoMName
, AParent.WithSet AS ParentWithSet
, AParent.WithMacro  AS ParentWithMacro
, AParent.WithAccessory AS ParentWithAccessory
, CONVERT(BIT, CASE WHEN DXP.ArticleId IS NULL THEN 0 ELSE 1 END) AS ArticleMatched
FROM DocXmlPosition DXP
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON DXP.ArticleId = AIS.ArticleId
LEFT JOIN [Article] A ON DXP.ArticleId = A.Id
LEFT JOIN ArticleUoM AUOM ON A.UoMId = AUOM.Id
LEFT JOIN DocPositionType DPT ON DXP.PositionTypeId = DPT.Id
LEFT JOIN ArticlePriceCalculation APC ON DXP.ArticleId = APC.ArticleId
INNER JOIN DocXml DX ON DXP.DocXmlId = DX.Id
LEFT JOIN PartnerDetail PD ON PD.Id= DX.PartnerDetailId
LEFT JOIN [Partner] P ON PD.PartnerId = P.Id AND PD.PartnerTypeId = 'Supplier'
LEFT JOIN DocXmlPosition DXPParent ON DXPParent.Id= DXP.ParentPositionId
LEFT JOIN Article AParent ON AParent.Id= DXPParent.ArticleId
GO
-- END xVIEW265_DocXmlPosition ----------------------------------------------------------------------
