CREATE OR ALTER VIEW
xVIEW420_ProductionPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns production positions with formatted planned quantities, concatenated position numbers, warehousing and availability metrics, production number, position type, stock and cost details, unit of measure, production duration unit, and parent article flags.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
PP.*
, PP.RowNumber AS ViewRowNumber
, FORMAT(PP.PositionQuantityPlanned, 'N' + CAST(A.DecimalPlacesQuantitiesId AS varchar)) AS FormattedQuantity
, CASE
WHEN PP.ChildPositionNumber IS NULL THEN CAST(PP.PositionNumber AS NVARCHAR(10))
ELSE CONCAT(CAST(PP.PositionNumber AS NVARCHAR(10)), '.', CAST(PP.ChildPositionNumber AS NVARCHAR(10)))
END AS PositionNumberConcat
, CASE
WHEN A.Warehousing = 1 THEN AIS.NowAvailable
ELSE NULLIF(A.Warehousing, 0)
END AS ViewNowAvailable
, PROD.ProductionNumber
, PPT.Name AS PositionTypeName
, AIS.Stock
, AIS.Confirmed
, AIS.Packed
, AIS.Ordered
, AIS.Announced
, AIS.NowAvailable
, AIS.LaterAvailable
, AIS.MinimumStock
, AIS.MaximumStock
, A.IndividualizationTypeId
, A.DecimalPlacesQuantitiesId
, A.MinimumQuantity
, A.DeliveryTime
, A.LotSize
, APC.PercentageMarkup1
, APC.FixedMarkup1
, APC.IntermediateCalculatedSalesPrice
, APC.PercentageMarkup2
, APC.FixedMarkup2
, APC.CalculatedSalesPrice
, APC.ProcurementPrice
, APC.Factor
, APC.WarehouseCost
, APC.OverheadCost
, APC.OtherCost
, APC.ChangeInValue
, APC.CostPrice
, UOM.Name AS UoMName
, UOM.ProductionDurationUnitId
, AParent.WithSet AS ParentWithSet
, AParent.WithMacro  AS ParentWithMacro
, AParent.WithAccessory AS ParentWithAccessory
, A.Matchcode AS ArticleMatchcode
FROM ProductionPosition PP
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON PP.ArticleId = AIS.ArticleId
LEFT JOIN [Article] A ON PP.ArticleId = A.Id
LEFT JOIN ArticleUoM UOM ON A.UoMId = UOM.Id
LEFT JOIN ProductionPositionType PPT ON PP.PositionTypeId = PPT.Id
LEFT JOIN ArticlePriceCalculation APC ON PP.ArticleId = APC.ArticleId
INNER JOIN Production PROD ON PP.ProductionId = PROD.Id
LEFT JOIN ProductionPosition PPParent ON PPParent.Id= PP.ParentPositionId
LEFT JOIN Article AParent ON AParent.Id= PPParent.ArticleId
GO
-- END xVIEW420_ProductionPosition ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW425_ProductionPositionWarehousing
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns warehousing details for production positions, including warehouse and bin location info, quantities, availability, individualization data, and related article and production metadata.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
DPWHG.[Id]
, DPWHG.[ProductionPositionId]
, DPWHG.[WarehouseId]
, DPWHG.[BinLocationId]
, DPWHG.[Quantity]
, DPWHG.[IndividualizationTypeId]
, DPWHG.[IndividualizationNumberId]
, DPWHG.[WarehousingEffective]
, DPWHG.[WarehousingQuantity]
, DPWHG.[WarehouseMediumId]
, W.BinLocation HasBinLocation
, WBL.[Name] BinLocationName
, WQ.Stock
, WQ.NowAvailable
, DP.ArticleId
, AI.IsBatch
, AIQ.Stock AS IndividualizationStock
, AIQ.Packed AS IndividualizationPacked
, AIQ.NowAvailable AS IndividualizationNowAvailable
FROM [dbo].[ProductionPositionWarehousing] DPWHG
INNER JOIN Warehouse W ON DPWHG.WarehouseId = W.Id
LEFT JOIN WarehouseBinLocation WBL ON DPWHG.BinLocationId = WBL.Id
INNER JOIN ProductionPosition DP ON DP.Id = DPWHG.ProductionPositionId
LEFT JOIN WarehouseQuantity WQ ON WQ.WarehouseId = DPWHG.WarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(DPWHG.BinLocationId,0) AND WQ.ArticleId = DP.ArticleId
INNER JOIN Production D ON DP.ProductionId = D.Id
LEFT JOIN ArticleIndividualization AI ON DPWHG.IndividualizationNumberId = AI.Id
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = DPWHG.IndividualizationNumberId AND AIQ.WarehouseId = DPWHG.WarehouseId AND ISNULL(DPWHG.BinLocationId,0) = ISNULL(AIQ.BinLocationId,0) 
GO
-- END xVIEW425_ProductionPositionWarehousing ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
