CREATE OR ALTER VIEW
xVIEW500_WarehouseInventoryList
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns all articles with non-zero warehouse stock or packed quantities, including article details, unit of measure, warehouse and bin location names, and a sequential identifier.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
 CAST(ROW_NUMBER() OVER (ORDER BY  A.Id DESC) AS int) AS Id
, A.Id AS [ArticleNumber]
, A.[Name1] AS Name1
, A.[Name2] AS Name2
, A.DecimalPlacesQuantitiesId
, WQ.Stock
, WQ.Packed
, AU.Name AS UoM
, W.[WarehouseName] AS WarehouseName
, BL.Name AS BinLocationName
FROM Article A
INNER JOIN dbo.WarehouseQuantity WQ ON A.Id = WQ.ArticleId
LEFT JOIN dbo.Warehouse W ON WQ.WarehouseId = W.Id
LEFT JOIN dbo.WarehouseBinLocation BL ON ISNULL(WQ.BinLocationId,0) = ISNULL(BL.Id,0)
LEFT JOIN ArticleUoM AU ON A.UoMId = AU.Id
WHERE (WQ.Stock != 0 OR WQ.Packed != 0) ;
GO
-- END xVIEW500_WarehouseInventoryList ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW501_WarehouseInventoryIndividualized
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns warehouse inventory entries, individualized or not, with a sequential Id, article details, stock, packed quantities, unit of measure, warehouse and bin location names, and individualization type.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
ROW_NUMBER() OVER (ORDER BY A.Id) AS Id
, A.Id AS [ArticleNumber]
, A.[Name1] AS Name1
, A.[Name2] AS Name2
, A.DecimalPlacesQuantitiesId
, CASE WHEN A.IndividualizationTypeId != 'None' THEN AI.Id ELSE NULL END AS ArticleIndividualizationId
, CASE WHEN A.IndividualizationTypeId != 'None' THEN AIQ.Stock ELSE WQ.Stock END AS Stock
, CASE WHEN A.IndividualizationTypeId != 'None' THEN AIQ.Packed ELSE WQ.Packed END AS Packed
, AU.Name AS UoM
, W.[WarehouseName] AS WarehouseName
, BL.Name AS BinLocationName
, AIT.Name AS IndividualizationType
FROM Article A
LEFT JOIN ArticleIndividualization AI ON AI.ArticleId = A.Id AND A.IndividualizationTypeId != 'None'
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AI.Id = AIQ.ArticleIndividualizationId AND (AIQ.Stock != 0 OR AIQ.Packed != 0)
LEFT JOIN WarehouseQuantity WQ ON A.Id = WQ.ArticleId AND (WQ.Stock != 0 OR WQ.Packed != 0) AND A.IndividualizationTypeId = 'None'
LEFT JOIN Warehouse W ON W.Id = COALESCE(AIQ.WarehouseId, WQ.WarehouseId)
LEFT JOIN WarehouseBinLocation BL ON BL.Id = COALESCE(AIQ.BinLocationId, WQ.BinLocationId)
LEFT JOIN ArticleUoM AU ON A.UoMId = AU.Id
LEFT JOIN ArticleIndividualizationType AIT ON A.IndividualizationTypeId = AIT.Id
WHERE (AIQ.Stock != 0 OR AIQ.Packed != 0 OR WQ.Stock != 0 OR WQ.Packed != 0)
GO
-- END xVIEW501_WarehouseInventoryIndividualized ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW502_WarehouseInventoryValuationList
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns non-zero stock article quantities with their procurement prices and calculates total valuation per article including unit of measure and article details.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
ROW_NUMBER() OVER (ORDER BY A.Id) AS Id
, AQ.ArticleId AS ArticleNumber
, A.Name1
, A.Name2
, AU.Name AS UoMName
, AQ.Stock
, ISNULL(APC.ProcurementPrice, 0) AS ProcurementPrice
, (AQ.Stock * ISNULL(APC.ProcurementPrice, 0) / A.PriceUnitId) AS ArticleValuationTotal
FROM ArticleQuantity AQ
LEFT JOIN Article A on AQ.ArticleId = A.Id
LEFT JOIN ArticlePriceCalculation APC on AQ.ArticleId = APC.ArticleId
LEFT JOIN ArticleUoM AU ON A.UoMId = AU.Id
WHERE AQ.Stock != 0
GO
-- END xVIEW502_WarehouseInventoryValuationList ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
