CREATE OR ALTER VIEW
xVIEW522_WarehouseTransferPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns warehouse Transfer positions with article details, source and destination warehouse/bin locations, quantity, individualization info, unit of measure, warehousing flag, and current stock at the source location.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
WMP.Id
, WMP.WarehouseTransferId
, WMP.ArticleId
, WMP.PositionNumber
, WMP.Quantity
, WMP.IndividualizationNumberId
, WMP.SourceWarehouseId
, WMP.SourceBinLocationId
, WMP.DestinationWarehouseId
, WMP.DestinationBinLocationId
, WMP.WarehouseMediumId
, WMP.Pending
, A.Name1
, A.Name2
, A.UoMId
, A.IndividualizationTypeId
, A.DecimalPlacesQuantitiesId
, A.Warehousing
, AU.[Name] UoMName
, CASE WHEN A.IndividualizationTypeId = 'None' THEN WQ.Stock ELSE AIQ.Stock END AS Stock
FROM WarehouseTransferPosition WMP
INNER JOIN Article A ON WMP.ArticleId = A.Id
INNER JOIN ArticleUoM AU ON A.UoMId = AU.Id
LEFT JOIN WarehouseQuantity WQ ON WQ.ArticleId = A.Id AND WQ.WarehouseId = WMP.SourceWarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(WMP.SourceBinLocationId,0) 
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = WMP.IndividualizationNumberId AND AIQ.WarehouseId = WMP.SourceWarehouseId AND ISNULL(AIQ.BinLocationId,0)= ISNULL(WMP.SourceBinLocationId,0) 
GO
