GO
CREATE OR ALTER VIEW
xVIEW552_ProcurementPurchase
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns procurement purchase entries (ProcurementTypeId = 'buy') with article matchcode, quantity precision, customer and supplier matchcodes, related document and position numbers for order confirmations, purchase orders, announcements, and availability details.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
PROCU.*
, A.Matchcode AS ArticleMatchcode
, A.DecimalPlacesQuantitiesId
, A.Warehousing
, AU.Name AS UoMName
, PCustomer.Matchcode AS CustomerMatchcode
, PSupplier.Matchcode AS SupplierMatchcode
, DOrderConfirmation.DocNumber AS OrderConfirmationDocNumber
, DPurchaseOrder.DocNumber AS PurchaseOrderDocNumber
, DPurchaseOrder.Id AS PurchaseOrderDocId
, DPOrderConfirmation.PositionNumber AS OrderConfirmationPositionNumber
, DPPurchaseOrder.PositionNumber AS PurchaseOrderPositionNumber
, DPOrderConfirmation.ShippingDate AS OrderConfirmationShippingDate
, DPPurchaseOrder.DeliveryDate AS PurchaseOrderDeliveryDate
, AIS.NowAvailable
, AIS.LaterAvailable
, AIS.MinimumStock
, AIS.MessageThreshold
, AIS.MaximumStock
, DPPurchaseOrder.QuantityOpen AS OrderedQuantityOpen
, Ann.AnnouncedQuantityOpen
, Ann.ReceivedQuantity
FROM Procurement AS PROCU
LEFT JOIN Article AS A
ON PROCU.ArticleId = A.Id
LEFT JOIN ArticleUoM AS AU
ON A.UoMId= AU.Id
LEFT JOIN DocPosition AS DPOrderConfirmation
ON PROCU.OrderConfirmationPositionId = DPOrderConfirmation.Id
LEFT JOIN Doc AS DOrderConfirmation
ON DPOrderConfirmation.DocId = DOrderConfirmation.Id
LEFT JOIN DocPosition AS DPPurchaseOrder
ON PROCU.PurchaseOrderPosId = DPPurchaseOrder.Id
LEFT JOIN Doc AS DPurchaseOrder
ON DPPurchaseOrder.DocId = DPurchaseOrder.Id
LEFT JOIN Partner AS PCustomer
ON DOrderConfirmation.PartnerId = PCustomer.Id
LEFT JOIN Partner AS PSupplier
ON PROCU.SupplierId = PSupplier.Id
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AS AIS
ON PROCU.ArticleId = AIS.ArticleId
OUTER APPLY (
SELECT
SUM(DP2.QuantityOpen) AS AnnouncedQuantityOpen
, (
SELECT SUM(DP3.Quantity)
FROM DocPosition AS DP3
JOIN Doc AS D3
ON D3.Id = DP3.DocId
WHERE
(
DP3.PredecessorId IN (
SELECT DP2a.Id
FROM DocPosition AS DP2a
JOIN Doc AS D2a
ON D2a.Id = DP2a.DocId
WHERE DP2a.PredecessorId = DPPurchaseOrder.Id
AND D2a.InventoryStatusId = 'announced'
)
OR DP3.PredecessorId = DPPurchaseOrder.Id -- direkt aus Bestellung → Empfang
)
AND D3.WarehousingEffective = 1
AND D3.Draft = 0
) AS ReceivedQuantity
FROM DocPosition AS DP2
JOIN Doc AS D2
ON D2.Id = DP2.DocId
WHERE DP2.PredecessorId = DPPurchaseOrder.Id
AND D2.InventoryStatusId = 'announced'
) AS Ann
WHERE PROCU.ProcurementTypeId = 'buy' OR PROCU.ProcurementTypeId = 'ask';
GO
-- END xVIEW552_ProcurementPurchase ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
