LEFT JOIN Production ProductionOrder on PROCU.ProductionId = ProductionOrder.Id
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON PROCU.ArticleId = AIS.ArticleId
WHERE PROCU.ProcurementTypeId = 'make' OR PROCU.ProcurementTypeId = 'ask'
