CREATE OR ALTER VIEW
xVIEW600_FinancePostingDraft
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns finance Posting draft entries.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
ROW_NUMBER() OVER (ORDER BY FB.Id ASC) AS RowNumber
, FB.Id
, FB.[Name] PostingName
, FB.DocNumber
, FB.StatusId PostingStatusId
, FB.ReversalReferenceId
, FB.PostingTemplateId
, FB.DateCreated
, CAST(FB.DateCreated AS DATETIME) AS DateCreatedDATETIME
, FB.ReceiptNumber
, FB.ReceiptDate
, CAST(FB.ReceiptDate AS DATETIME) AS ReceiptDateDATETIME
, FB.PostingPeriodId
, FB.Subject
, FB.BatchNumber
, FB.SourceId
, FB.CreatedBy
, FB.ForeignCurrencyId
, FB.Rate
, CASE                                                                                     
WHEN EXISTS (                                                                       
SELECT 1
FROM FinancePostingPositionDraft FBPD
INNER JOIN FinanceAccountPlan FAP
ON FAP.Id = FBPD.AccountId
WHERE FAP.ForeignCurrencyId IS NOT NULL AND FBPD.PostingId = FB.Id
) THEN CAST(1 AS bit)
ELSE CAST(0 AS bit)
END AS ShowForeignCurrency                                                        
FROM FinancePostingDraft AS FB
LEFT JOIN FinancePostingPeriod FBPE ON FBPE.Id = FB.PostingPeriodId
GO
-- END xVIEW600_FinancePostingDraft ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW600_FinancePostingPositionDraft
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns finance Posting draft entries with detail positions, metadata, and running balances by account, partner detail, cost center, cost bearer, and cost type.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
ROW_NUMBER() OVER (ORDER BY FB.Id ASC, ISNULL(FBP.Position, 0) DESC) AS RowNumber
, FBP.Id
, FBP.PostingId
, FBP.Position
, FBP.ParentPosition
, FBP.StatusId PositionStatusId
, FBP.ReversalReferencePositionId
, FBP.PartnerDetailId
, FBP.BusinessPartnerNumber
, FBP.AccountId 
, FBP.PostingPositionAccountTypeId
, FBP.AccountName
, FBP.OpenItemId
, FBP.Debit
, FBP.Credit
, FBP.ContraAccountId
, FBP.GrossValue
, FBP.DivergentPerformanceDate
, FBP.TaxKeyId
, FBP.TaxPercent
, FBP.TaxAmount
, FBP.CostCenterId
, FBP.CostBearerId
, FBP.OpenAmount
, FBP.VatNumber
, FBP.ProjectId
, FBP.ForeignCurrencyDebit
, FBP.ForeignCurrencyCredit
, FBP.ForeignCurrencyGrossValue
, FBP.ForeignCurrencyOpenAmount
, FBP.ForeignCurrencyTaxAmount
, FB.[Name] PostingName
, FB.DocNumber
, FB.StatusId PostingStatusId
, FB.ReversalReferenceId
, FB.PostingTemplateId
, FB.DateCreated
, CAST(FB.DateCreated AS DATETIME) AS DateCreatedDATETIME
, FB.ReceiptNumber
, FB.ReceiptDate
, CAST(FB.ReceiptDate AS DATETIME) AS ReceiptDateDATETIME
, FB.PostingPeriodId
, FB.Subject
, FB.BatchNumber
, FB.SourceId
, FB.CreatedBy
, FB.ForeignCurrencyId
, FB.Rate
, FBP.Archived
, PD.PartnerId
, PD.PartnerTypeId
, FAP.CostTypeId
, FAP.ForeignCurrencyId AS AccountForeignCurrencyId 
, SUM(Debit - Credit) OVER (
PARTITION BY AccountId 
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
) AS RunningBalanceAccount
, CASE
WHEN PartnerDetailId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY PartnerDetailId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalancePartnerDetail
, CASE
WHEN FBP.CostCenterId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY FBP.CostCenterId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalanceCostCenter
, CASE
WHEN FBP.CostBearerId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY FBP.CostBearerId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalanceCostBearer
, CASE
WHEN FAP.CostTypeId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY FAP.CostTypeId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalanceCostTypeId
, FBPAT.Name AS PostingPositionAccountTypeName
, FBPE.Name AS PostingPeriodName
, FBS.Name AS StatusName
, FBPE.CalendarYearId
, FBPE.CalendarMonthId
, FBPE.FiscalPeriodId
, CASE
WHEN FBP.PostingPositionAccountTypeId = 1
THEN CONCAT(FAP.AccountNumber, ' - ', FBP.AccountName)
ELSE CONCAT(PD.Id, ' - ', FBP.AccountName)
END AS AccountNameAndNumber
FROM FinancePostingPositionDraft AS FBP
LEFT JOIN FinancePostingDraft AS FB ON FB.Id = FBP.PostingId
LEFT JOIN PartnerDetail PD ON PD.Id = FBP.PartnerDetailId
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FBP.AccountId AND FBP.PostingPositionAccountTypeId = 1
LEFT JOIN FinancePostingPositionAccountType FBPAT ON FBPAT.Id = FBP.PostingPositionAccountTypeId
LEFT JOIN FinancePostingPeriod FBPE ON FBPE.Id = FB.PostingPeriodId
LEFT JOIN FinancePostingStatus FBS ON FBS.Id = FBP.StatusId
GO
-- END xVIEW600_FinancePostingPositionDraft ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
