AS
SELECT
FBP.Id As FinancePostingPositionId
, FB.Id
, FB.[Name] PostingName
, FB.DocNumber
, FB.StatusId PostingStatusId
, FB.ReversalReferenceId
, FB.PostingTemplateId
, FB.DateCreated
, CAST(FB.DateCreated AS DATETIME) AS DateCreatedDATETIME
, FB.ReceiptNumber
, FB.ReceiptDate
, CAST(FB.ReceiptDate AS DATETIME) AS ReceiptDateDATETIME
, FB.PostingPeriodId
, FB.Subject
, FB.BatchNumber
, FB.[SourceId]
, FB.CreatedBy
, FB.FixedAssetId
, FBP.Position
, FBP.ParentPosition
, FBP.StatusId PositionStatusId
, FBP.ReversalReferencePositionId
, FBP.BusinessPartnerNumber
, FBP.AccountId
, FBP.PostingPositionAccountTypeId
, FBP.AccountName
, FBP.OpenItemId
, FBP.Debit
, FBP.Credit
, FBP.ContraAccountId
, FBP.GrossValue
, FBP.DivergentPerformanceDate
, FBP.TaxKeyId
, FBP.TaxPercent
, FBP.TaxAmount
, FBP.CostCenterId
, FBP.CostBearerId
, FBP.OpenAmount
, FBP.VatNumber
, FBP.ProjectId
, FB.ForeignCurrencyId
, FB.Rate
, FBP.ForeignCurrencyDebit
, FBP.ForeignCurrencyCredit
, FBP.ForeignCurrencyGrossValue
, FBP.ForeignCurrencyOpenAmount
, FBP.ForeignCurrencyTaxAmount
, FBP.Archived
, PD.PartnerId
, PD.PartnerTypeId
, FAP.CostTypeId
, SUM(Debit - Credit) OVER (
PARTITION BY AccountId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
) AS RunningBalanceAccount
, CASE
WHEN PartnerDetailId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY PartnerDetailId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalancePartnerDetail
, CASE
WHEN FBP.CostCenterId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY FBP.CostCenterId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalanceCostCenter
, CASE
WHEN FBP.CostBearerId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY FBP.CostBearerId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalanceCostBearer
, CASE
WHEN FAP.CostTypeId IS NOT NULL THEN
SUM(Debit - Credit) OVER (
PARTITION BY FAP.CostTypeId
ORDER BY ReceiptDate, FB.Id, Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalanceCostTypeId
, CASE
WHEN FB.FixedAssetId IS NOT NULL AND FBP.AccountId = FA.AssetAccountId THEN
SUM(FBP.Debit- FBP.Credit) OVER (
PARTITION BY FB.FixedAssetId, FBP.AccountId
ORDER BY FB.ReceiptDate, FB.Id, FBP.Position
ROWS UNBOUNDED PRECEDING
)
ELSE
NULL
END AS RunningBalanceFixedAsset
, FBPAT.Name AS PostingPositionAccountTypeName
, FBPE.Name AS PostingPeriodName
, FBS.Name AS StatusName
, FBPE.CalendarYearId
, FBPE.CalendarMonthId
, FBPE.FiscalYearId
, FBPE.FiscalPeriodId
, CASE
WHEN FBP.PartnerDetailId IS NULL
THEN FAP.Matchcode
ELSE CONCAT(PD.Id, ' - ', P.Matchcode)
END AS AccountNameAndNumber
FROM FinancePosting AS FB
INNER JOIN FinancePostingPosition AS FBP ON FB.Id = FBP.PostingId
LEFT JOIN PartnerDetail PD ON PD.Id = FBP.PartnerDetailId
LEFT JOIN Partner P ON P.Id = PD.PartnerId
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FBP.AccountId AND FBP.PostingPositionAccountTypeId = 1
LEFT JOIN FinancePostingPositionAccountType FBPAT ON FBPAT.Id = FBP.PostingPositionAccountTypeId
LEFT JOIN FinancePostingPeriod FBPE ON FBPE.Id = FB.PostingPeriodId
LEFT JOIN FinancePostingStatus FBS ON FBS.Id = FBP.StatusId
LEFT JOIN FinanceFixedAsset FA ON FA.Id = FB.FixedAssetId
GO
-- END xVIEW600_FinancePostingList ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW601_FinanceOpenItemList
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns finance open items with status name, origin, account plan matchcode, cost center and cost bearer, partner type name, document type name, combined partner detail number and matchcode, dunning level info, open item type name, and editable amounts for amount and cash discount.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
FOI.*
, FOIS.Name AS FinanceOpenItemStatusName
, FOIO.Name AS OpenItemOrigin
, FAP.Matchcode AS AccountPlanMatchcode
, FCC.CostCenter AS CostCenter
, FCB.CostBearer AS CostBearer
, PT.Name AS PartnerTypeName
, DT.Name AS DocTypeName
, CONVERT(NVARCHAR,VW.BusinessPartnerNumber) + ' - ' + VW.Matchcode AS BusinessPartnerNumberAndMatchcode
, FDL.Info AS FinanceDunningLevelInfo
, FOIT.Name AS OpenItemTypeName
,  FOI.Amount AS EditableAmount
, CAST(0 AS DECIMAL(19,6)) AS EditableCashDiscountAmount
, CAST(0 AS DECIMAL(19,6)) AS ApplicableTodayDiscountPercentage
, CAST(0 AS DECIMAL(19,6)) AS UserCanKeepWithHimAmount
FROM FinanceOpenItem FOI
JOIN FinanceOpenItemStatus FOIS on FOI.StatusId = FOIS.Id
JOIN FinanceOpenItemOrigin FOIO on FOI.OpenItemOriginId = FOIO.Id
LEFT JOIN FinanceAccountPlan FAP on FOI.ContraAccountId = FAP.Id
LEFT JOIN FinanceCostCenter FCC on FOI.CostCenterId = FCC.Id
LEFT JOIN FinanceCostBearer FCB on FOI.CostBearerId = FCB.Id
JOIN PartnerType PT ON FOI.PartnerTypeId = PT.Id
LEFT JOIN DocType DT ON FOI.DocTypeId = DT.Id
JOIN xVIEW150_PartnerJoinPartnerDetail VW ON FOI.PartnerDetailId = VW.Id
LEFT JOIN FinanceDunningLevel FDL ON FOI.DunningLevelId = FDL.Id
LEFT JOIN FinanceOpenItemType FOIT ON FOIT.Id= FOI.OpenItemTypeId
GO
-- END xVIEW601_FinanceOpenItemList ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
