CREATE OR ALTER VIEW
xVIEW604_FinanceOpenItemHistoryList
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns finance open item history entries with status, origin, account plan matchcode, cost center and bearer, partner and document metadata, payment document date, reconciliation ID, and calculated remaining open amount based on reconciliation history.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
FOI.*
, FOIS.Name AS FinanceOpenItemStatusName
, FOIO.Name AS OpenItemOrigin
, FAP.Matchcode AS AccountPlanMatchcode
, FCC.CostCenter AS CostCenter
, FCB.CostBearer AS CostBearer
, PT.Name AS PartnerTypeName
, DT.Name AS DocTypeName
, CONVERT(NVARCHAR,VW.BusinessPartnerNumber) + ' - ' + VW.Matchcode AS BusinessPartnerNumberAndMatchcode
, VW.BusinessPartnerNumber
, VW.Matchcode
, FDL.Info AS FinanceDunningLevelInfo
, FOIT.Name AS OpenItemTypeName
, FOIRP_Top1.DocDate AS PaymentDocDate
,  FOIRP_Top1.ReconciliationId AS ReconciliationId
, CASE
WHEN SIGN(FOI.Amount) = SIGN(FOI.Amount + ISNULL((
SELECT
SUM(FOIRP_Sub.Amount)
FROM xVIEW603_FinanceOpenItemReconciliationPosition FOIRP_Sub
WHERE FOIRP_Sub.ReconciliationId IN (
SELECT ReconciliationId
FROM xVIEW603_FinanceOpenItemReconciliationPosition
WHERE OpenItemId = FOI.Id
)
AND FOIRP_Sub.DocDate <= FOIRP_Top1.DocDate
AND (
(FOIRP_Sub.OpenItemTypeId IN ('CD', 'SD') AND FOIRP.OpenItemTypeId IN ('CW', 'CI', 'SW', 'SC'))
OR (FOIRP_Sub.OpenItemTypeId IN ('CW', 'SW') AND FOIRP.OpenItemTypeId IN ('CD', 'CC', 'SD', 'SI'))
OR (FOIRP_Sub.OpenItemTypeId IN ('CI', 'SI') AND FOIRP.OpenItemTypeId IN ('CC', 'CD', 'SC', 'SW'))
OR (FOIRP_Sub.OpenItemTypeId IN ('CC', 'SC') AND FOIRP.OpenItemTypeId IN ('CI', 'CW', 'SI', 'SD'))
)
), 0))
THEN FOI.Amount + ISNULL((
SELECT SUM(FOIRP_Sub.Amount)
FROM xVIEW603_FinanceOpenItemReconciliationPosition FOIRP_Sub
WHERE FOIRP_Sub.ReconciliationId IN (
SELECT
ReconciliationId
FROM xVIEW603_FinanceOpenItemReconciliationPosition
WHERE OpenItemId = FOI.Id
)
AND FOIRP_Sub.DocDate <= FOIRP_Top1.DocDate
AND (
(FOIRP_Sub.OpenItemTypeId IN ('CD', 'SD') AND FOIRP.OpenItemTypeId IN ('CW', 'CI', 'SW', 'SC'))
OR (FOIRP_Sub.OpenItemTypeId IN ('CW', 'SW') AND FOIRP.OpenItemTypeId IN ('CD', 'CC', 'SD', 'SI'))
OR (FOIRP_Sub.OpenItemTypeId IN ('CI', 'SI') AND FOIRP.OpenItemTypeId IN ('CC', 'CD', 'SC', 'SW'))
OR (FOIRP_Sub.OpenItemTypeId IN ('CC', 'SC') AND FOIRP.OpenItemTypeId IN ('CI', 'CW', 'SI', 'SD'))
)
), 0)
ELSE 0
END AS CalculatedAmountOpen
, ROW_NUMBER() OVER (
PARTITION BY FOI.Id
ORDER BY FOIRP_Top1.DocDate DESC
) AS RowNum
FROM FinanceOpenItem FOI
JOIN xVIEW603_FinanceOpenItemReconciliationPosition FOIRP ON FOIRP.OpenItemId = FOI.Id
JOIN FinanceOpenItemStatus FOIS on FOI.StatusId = FOIS.Id
JOIN FinanceOpenItemOrigin FOIO on FOI.OpenItemOriginId = FOIO.Id
LEFT JOIN FinanceAccountPlan FAP on FOI.ContraAccountId = FAP.Id
LEFT JOIN FinanceCostCenter FCC on FOI.CostCenterId = FCC.Id
LEFT JOIN FinanceCostBearer FCB on FOI.CostBearerId = FCB.Id
JOIN PartnerType PT ON FOI.PartnerTypeId = PT.Id
LEFT JOIN DocType DT ON FOI.DocTypeId = DT.Id
JOIN xVIEW150_PartnerJoinPartnerDetail VW ON FOI.PartnerDetailId = VW.Id
LEFT JOIN FinanceDunningLevel FDL ON FOI.DunningLevelId = FDL.Id
LEFT JOIN FinanceOpenItemType FOIT ON FOIT.Id= FOI.OpenItemTypeId
CROSS APPLY (
SELECT TOP 1 *
FROM xVIEW603_FinanceOpenItemReconciliationPosition FOIRP_Sub
WHERE FOIRP_Sub.ReconciliationId = FOIRP.ReconciliationId
ORDER BY FOIRP_Sub.DocDate DESC
) FOIRP_Top1
GO
-- END xVIEW604_FinanceOpenItemHistoryList ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
