CREATE OR ALTER VIEW
xVIEW650_FinanceDunningPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns finance dunning positions with open item type name, document date, reference document, amount, due date, and calculated interest based on the interest rate and days past due.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
FDP.*
, FOIT.Name AS OpenItemTypeName
, FOI.DocDate
, FOI.ReferenceDoc
, FOI.Amount
, FOI.DueDate
, (FOI.OpenAmount * (FDP.Interest/100)) * DATEDIFF(DAY, DATEADD(DAY, 1, FOI.DueDate), GETDATE())/360 AS CalculatedInterest
FROM FinanceDunningPosition FDP
LEFT JOIN FinanceOpenItem FOI ON FOI.Id= FDP.OpenItemId
LEFT JOIN FinanceOpenItemType FOIT ON FOIT.Id= FOI.OpenItemTypeId
LEFT JOIN FinanceDunningLevel FDL ON FDL.Id= FOI.DunningLevelId
GO
-- END xVIEW650_FinanceDunningPosition ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW660_FinanceTransferPosition
/*
-----------------------------------------------------------------------------------------
Purpose: Provides a view that returns finance transfer positions with full transfer metadata, combined customer and supplier partner-detail matchcodes, and summed assigned amounts from open items and account plans.
-----------------------------------------------------------------------------------------
*/
AS
SELECT
FTP.[Id]
, FTP.[TransferId]
, FTP.[StatementID]
, FTP.[Position]
, FTP.[PostingPeriodId]
, FTP.[EntryReference]
, FTP.[MessageID]
, FTP.[Amount]
, FTP.[ForeignCurrencyAmount]
, FTP.[Rate]
, FTP.[Balance]
, FTP.[Charge]
, FTP.[Interest]
, FTP.[AccountId]
, FTP.[DebitSide]
, FTP.[StatementDate]
, FTP.[ValueDate]
, FTP.[CategoryName]
, FTP.[TransferCategoryId]
, FTP.[TransactionType]
, FTP.[TextKeyId]
, FTP.[Memo1]
, FTP.[Memo2]
, FTP.[Memo3]
, FTP.[Memo4]
, FTP.[Memo5]
, FTP.[Memo6]
, FTP.[Memo7]
, FTP.[Memo8]
, FTP.[Memo9]
, FTP.[Memo10]
, FTP.[Memo11]
, FTP.[Memo12]
, FTP.[Memo13]
, FTP.[Memo14]
, FTP.[MandateReference]
, FTP.[Name]
, FTP.[CustomerPartnerDetailId]
, FTP.[SupplierPartnerDetailId]
, FTP.[OpenItemReference]
, FTP.[OpenItemId]
, FTP.[Email]
, FTP.[PayPalArt]
, FTP.[PayPalStatus]
, FTP.[Reference]
, FTP.[BankTransactionCode]
, FTP.[XMLLevel]
, FTP.[MsgId]
, FTP.[EndToEndId]
, FTP.[DateCreated]
, FTP.[CreatedBy]
, FTP.[RowVersion]
, FTP.[Subject]
, FT.Draft
, FT.CompanyBankAccountId
, FT.ReceiptNumber
, FT.ReceiptDate
, CONVERT(VARCHAR, PDCustomer.Id) + ' - ' + PCustomer.Matchcode AS CustomerNumberAndMatchcode
, CONVERT(VARCHAR, PDSupplier.Id) + ' - ' + PSupplier.Matchcode AS SupplierNumberAndMatchcode
, ISNULL(OA.TotalAmount, 0) + ISNULL(AP.TotalAmount, 0) AS SumAssignedAmount
, FAP.Matchcode
, CASE                                                                                     
WHEN EXISTS (                                                                       
SELECT 1
FROM FinanceTransferPositionOpenItem FTPOI
INNER JOIN FinanceOpenItem FOI
ON FOI.Id = FTPOI.OpenItemId
WHERE FTPOI.TransferPositionId = FTP.Id
AND FOI.ForeignCurrencyId IS NOT NULL
) THEN CAST(1 AS bit)
ELSE CAST(0 AS bit)
END AS ShowForeignCurrency                                                        
FROM FinanceTransferPosition FTP 
OUTER APPLY (                                     
SELECT SUM(PaymentAmount) AS TotalAmount
FROM FinanceTransferPositionOpenItem
WHERE TransferPositionId = FTP.Id
) OA
OUTER APPLY (                                  
SELECT SUM(Amount) AS TotalAmount
FROM FinanceTransferPositionAccountPlan
WHERE TransferPositionId = FTP.Id
) AP
LEFT JOIN PartnerDetail PDCustomer  ON FTP.CustomerPartnerDetailId = PDCustomer.Id       
LEFT JOIN Partner       PCustomer   ON PCustomer.Id = PDCustomer.PartnerId           
LEFT JOIN PartnerDetail PDSupplier  ON FTP.SupplierPartnerDetailId = PDSupplier.Id      
LEFT JOIN Partner       PSupplier   ON PSupplier.Id = PDSupplier.PartnerId                
LEFT JOIN FinanceTransfer FT        ON FT.Id = FTP.TransferId                       
LEFT JOIN FinanceAccountPlan FAP    ON FAP.Id = FTP.AccountId
GO
-- END xVIEW660_FinanceTransferPosition ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
