FTPOI.CurrencyDifferenceSubject,
FOI.StatusId,
FOI.OpenItemOriginId,
FOI.OpenItemTypeId,
FOI.DocTypeId,
FOI.PartnerTypeId,
FOI.PartnerId,
FOI.PartnerDetailId,
FOI.PostingId,
FOI.PostingDate,
FOI.DocDate,
FOI.DocNumber,
FOI.Amount AS OpenItemAmount,
FOI.ForeignCurrencyId,
FOI.Rate,
FOI.Discountable,
FOI.DueDate,
FOI.CashDiscountDate1,
FOI.CashDiscountPercentage1,
FOI.CashDiscountDate2,
FOI.CashDiscountPercentage2,
FOI.CashDiscountAmount AS OpenItemCashDiscountAmount,
FOI.OpenAmount,
FTPOI.Remaining,
FOI.Remark1,
FOI.Remark2,
FOI.ReferenceDoc,
FOI.ContraAccountId,
FOI.CostCenterId,
FOI.CostBearerId,
FOI.DunningBlock,
FOI.PaymentBlock,
FOI.DunningLevelId,
FOI.DunningDate,
FOI.NewDueDate,
FOI.TaxSplit,
FOI.DocSplit,
FOI.TermsOfPaymentId,
FOI.Archived,
FOI.ProbabilityOfPayment,
FOI.ForeignCurrencyAmount,
FOI.ForeignCurrencyCashDiscountAmount AS OpenItemForeignCurrencyCashDiscountAmount,
FOI.ForeignCurrencyOpenAmount,
FOIS.Name AS FinanceOpenItemStatusName,
FOIO.Name AS OpenItemOrigin,
FAP.Matchcode AS AccountPlanMatchcode,
FCC.CostCenter AS CostCenter,
FCB.CostBearer AS CostBearer,
PT.Name AS PartnerTypeName,
DT.Name AS DocTypeName,
CONVERT(NVARCHAR, VW.BusinessPartnerNumber) + ' - ' + VW.Matchcode AS BusinessPartnerNumberAndMatchcode,
FDL.Info AS FinanceDunningLevelInfo,
FOIT.Name AS OpenItemTypeName,
FTPOI.ApplicablePercent,
FTPOI.PermissibleAmount,
CurrencyDifferenceAccountIdFAP.Matchcode AS CurrencyDifferenceAccountMatchcode
FROM FinanceTransferPositionOpenItem FTPOI
JOIN FinanceTransferPosition FTP ON FTPOI.TransferPositionId = FTP.Id
JOIN FinanceOpenItem FOI ON FTPOI.OpenItemId = FOI.Id
JOIN FinanceOpenItemStatus FOIS ON FOI.StatusId = FOIS.Id
JOIN FinanceOpenItemOrigin FOIO ON FOI.OpenItemOriginId = FOIO.Id
LEFT JOIN FinanceAccountPlan FAP ON FOI.ContraAccountId = FAP.Id
LEFT JOIN FinanceAccountPlan CurrencyDifferenceAccountIdFAP ON FTPOI.CurrencyDifferenceAccountId= CurrencyDifferenceAccountIdFAP.Id
LEFT JOIN FinanceCostCenter FCC ON FOI.CostCenterId = FCC.Id
LEFT JOIN FinanceCostBearer FCB ON FOI.CostBearerId = FCB.Id
JOIN PartnerType PT ON FOI.PartnerTypeId = PT.Id
LEFT JOIN DocType DT ON FOI.DocTypeId = DT.Id
JOIN xVIEW150_PartnerJoinPartnerDetail VW ON FOI.PartnerDetailId = VW.Id
LEFT JOIN FinanceDunningLevel FDL ON FOI.DunningLevelId = FDL.Id
LEFT JOIN FinanceOpenItemType FOIT ON FOIT.Id = FOI.OpenItemTypeId;
GO
