CREATE OR ALTER VIEW
xVIEW695_FinanceFixedAsset
-----------------------------------------------------------------------------------------
AS
WITH
E1 AS (SELECT 1 AS X UNION ALL SELECT 1 UNION ALL SELECT 1 UNION ALL SELECT 1
UNION ALL SELECT 1 UNION ALL SELECT 1 UNION ALL SELECT 1 UNION ALL SELECT 1
UNION ALL SELECT 1 UNION ALL SELECT 1),
E2 AS (SELECT 1 AS X FROM E1 A CROSS JOIN E1 B),
E3 AS (SELECT 1 AS X FROM E2 A CROSS JOIN E1 B),
Numbers AS (SELECT ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1 AS N FROM E3),
PostedSummary AS (
SELECT
DP.FixedAssetId,
SUM(DP.DepreciationAmount) AS PostedTotal,
COUNT(*) AS PostedCount
FROM dbo.FinanceFixedAssetDepreciationPlan DP
WHERE DP.IsPosted = 1
GROUP BY DP.FixedAssetId
),
AssetBase AS (
SELECT
FA.*
, DT.Name AS DepreciationTypeName
, DM.Id AS DepreciationMethodId
, DM.Name AS DepreciationMethodName
-- Effective schedule start month: linear mid-life takeover starts at the
-- calculation start, every other case keeps the depreciation start.
, CASE
WHEN DM.Id = 'STRAIGHTLINE'
AND FA.CalculationStartDate IS NOT NULL
AND DATEDIFF(MONTH, FA.DepreciationStartDate, FA.CalculationStartDate) > 0
THEN FA.CalculationStartDate
ELSE FA.DepreciationStartDate
END AS EffectiveStartDate
-- Months already depreciated in the legacy system before the calculation start.
, CASE
WHEN DM.Id = 'STRAIGHTLINE'
AND FA.CalculationStartDate IS NOT NULL
AND DATEDIFF(MONTH, FA.DepreciationStartDate, FA.CalculationStartDate) > 0
THEN DATEDIFF(MONTH, FA.DepreciationStartDate, FA.CalculationStartDate)
ELSE 0
END AS ElapsedMonths
-- Net book value the going-forward calculation must start from. For linear
-- depreciation this is ALWAYS the calculation-start net acquisition cost
-- (Berechnung Start Anschaffungskosten netto), independent of any date offset.
-- Only if that value is missing in legacy data do we fall back to the full
-- net acquisition cost. Non-linear methods keep the full net acquisition cost.
, CASE
WHEN DM.Id = 'STRAIGHTLINE'
AND FA.CalculationStartAcquisitionCostNet > 0
THEN FA.CalculationStartAcquisitionCostNet
ELSE FA.AcquisitionCostNet
END AS EffectiveBasis
FROM dbo.FinanceFixedAsset FA
INNER JOIN dbo.FinanceFixedAssetDepreciationType DT ON FA.DepreciationTypeId = DT.Id
INNER JOIN dbo.FinanceFixedAssetDepreciationMethod DM ON DT.MethodId = DM.Id
),
BaseCalc AS (
SELECT
AB.*
, N.N + 1 AS CycleNumber
, YEAR(DATEADD(MONTH, N.N, AB.EffectiveStartDate)) AS DepreciationYear
, MONTH(DATEADD(MONTH, N.N, AB.EffectiveStartDate)) AS DepreciationMonth
-- Posting Period Information
, BP.Id AS PostingPeriodId
, BP.FiscalYearPeriod
, BP.Name AS PostingPeriodName
, BP.FiscalYearId
, BP.FiscalPeriodId
, BP.CalendarYearId
, BP.CalendarMonthId
, BP.StatusId AS PostingPeriodStatus
-- Depreciation Plan Information
, DP.Id AS DepreciationPlanId
, ISNULL(DP.IsPosted, 0) AS IsPosted
-- Effective Depreciation Amount (posted value overrides calculated)
, CASE
WHEN DP.IsPosted = 1 THEN DP.DepreciationAmount
ELSE
CASE
WHEN AB.DepreciationMethodId = 'STRAIGHTLINE' THEN
(
CASE
WHEN MONTH(DATEADD(MONTH, N.N, AB.EffectiveStartDate)) = 12
OR ((N.N + 1) - ISNULL(PS.PostedCount, 0)) >= ((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths) - ISNULL(PS.PostedCount, 0))
THEN (AB.EffectiveBasis - ISNULL(PS.PostedTotal, 0))
- ROUND(
CAST(AB.EffectiveBasis - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
- CAST(AB.EffectiveBasis - AB.MemorandumValue - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths) - ISNULL(PS.PostedCount, 0), 0)
* ((N.N + 1) - ISNULL(PS.PostedCount, 0))
, 0)
ELSE ROUND(
CAST(AB.EffectiveBasis - AB.MemorandumValue - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths) - ISNULL(PS.PostedCount, 0), 0)
* ((N.N + 1) - ISNULL(PS.PostedCount, 0))
, 2)
END
)
- (
CASE
WHEN ((N.N + 1) - ISNULL(PS.PostedCount, 0) - 1) <= 0 THEN 0
WHEN MONTH(DATEADD(MONTH, N.N, AB.EffectiveStartDate)) = 1
THEN (AB.EffectiveBasis - ISNULL(PS.PostedTotal, 0))
- ROUND(
CAST(AB.EffectiveBasis - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
- CAST(AB.EffectiveBasis - AB.MemorandumValue - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths) - ISNULL(PS.PostedCount, 0), 0)
* ((N.N + 1) - ISNULL(PS.PostedCount, 0) - 1)
, 0)
ELSE ROUND(
CAST(AB.EffectiveBasis - AB.MemorandumValue - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths) - ISNULL(PS.PostedCount, 0), 0)
* ((N.N + 1) - ISNULL(PS.PostedCount, 0) - 1)
, 2)
END
)
-- Manual Depreciation
WHEN AB.DepreciationMethodId = 'MANUAL' THEN
CASE
WHEN FAD.DepreciationPercent IS NOT NULL THEN
AB.AcquisitionCostNet * (FAD.DepreciationPercent / 100.0)
ELSE
0
END
-- Declining Balance (degressive)
WHEN AB.DepreciationMethodId = 'DECLININGBALANCE' THEN
(AB.AcquisitionCostNet / NULLIF(AB.UsefulLifeMonthsQuantity, 0)) *
POWER(1.0 - (1.0 / NULLIF(AB.UsefulLifeMonthsQuantity, 0)), N.N)
-- Immediate Depreciation (sofort) - full depreciation from start month to December.
WHEN AB.DepreciationMethodId = 'IMMEDIATE' THEN
ROUND(
CAST(AB.AcquisitionCostNet - AB.MemorandumValue - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
/ NULLIF((13 - MONTH(AB.DepreciationStartDate)) - ISNULL(PS.PostedCount, 0), 0)
* ((N.N + 1) - ISNULL(PS.PostedCount, 0))
, 2)
- ROUND(
CAST(AB.AcquisitionCostNet - AB.MemorandumValue - ISNULL(PS.PostedTotal, 0) AS DECIMAL(19,6))
/ NULLIF((13 - MONTH(AB.DepreciationStartDate)) - ISNULL(PS.PostedCount, 0), 0)
* ((N.N + 1) - ISNULL(PS.PostedCount, 0) - 1)
, 2)
ELSE
0
END
END AS DepreciationAmount
-- "Clean" per-month amount: identical formulas but WITHOUT any posted-plan
-- override and WITHOUT the posted totals/counts offset. The YEARLY branch sums
-- this over a calendar year to obtain the original annual depreciation, which
-- stays stable as individual years get posted.
, CASE
WHEN AB.DepreciationMethodId = 'STRAIGHTLINE' THEN
(
CASE
WHEN MONTH(DATEADD(MONTH, N.N, AB.EffectiveStartDate)) = 12
OR ((N.N + 1)) >= ((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths))
THEN (AB.EffectiveBasis)
- ROUND(
CAST(AB.EffectiveBasis AS DECIMAL(19,6))
- CAST(AB.EffectiveBasis - AB.MemorandumValue AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths), 0)
* ((N.N + 1))
, 0)
ELSE ROUND(
CAST(AB.EffectiveBasis - AB.MemorandumValue AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths), 0)
* ((N.N + 1))
, 2)
END
)
- (
CASE
WHEN ((N.N + 1) - 1) <= 0 THEN 0
WHEN MONTH(DATEADD(MONTH, N.N, AB.EffectiveStartDate)) = 1
THEN (AB.EffectiveBasis)
- ROUND(
CAST(AB.EffectiveBasis AS DECIMAL(19,6))
- CAST(AB.EffectiveBasis - AB.MemorandumValue AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths), 0)
* ((N.N + 1) - 1)
, 0)
ELSE ROUND(
CAST(AB.EffectiveBasis - AB.MemorandumValue AS DECIMAL(19,6))
/ NULLIF((AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths), 0)
* ((N.N + 1) - 1)
, 2)
END
)
WHEN AB.DepreciationMethodId = 'MANUAL' THEN
CASE
WHEN FAD.DepreciationPercent IS NOT NULL THEN
AB.AcquisitionCostNet * (FAD.DepreciationPercent / 100.0)
ELSE
0
END
WHEN AB.DepreciationMethodId = 'DECLININGBALANCE' THEN
(AB.AcquisitionCostNet / NULLIF(AB.UsefulLifeMonthsQuantity, 0)) *
POWER(1.0 - (1.0 / NULLIF(AB.UsefulLifeMonthsQuantity, 0)), N.N)
WHEN AB.DepreciationMethodId = 'IMMEDIATE' THEN
ROUND(
CAST(AB.AcquisitionCostNet - AB.MemorandumValue AS DECIMAL(19,6))
/ NULLIF((13 - MONTH(AB.DepreciationStartDate)), 0)
* ((N.N + 1))
, 2)
- ROUND(
CAST(AB.AcquisitionCostNet - AB.MemorandumValue AS DECIMAL(19,6))
/ NULLIF((13 - MONTH(AB.DepreciationStartDate)), 0)
* ((N.N + 1) - 1)
, 2)
ELSE
0
END AS DepreciationAmountClean
FROM AssetBase AB
INNER JOIN Numbers N ON N.N < CASE
WHEN AB.DepreciationMethodId = 'IMMEDIATE' THEN (13 - MONTH(AB.DepreciationStartDate))
WHEN AB.DepreciationMethodId = 'STRAIGHTLINE' THEN (AB.UsefulLifeMonthsQuantity - AB.ElapsedMonths)
ELSE AB.UsefulLifeMonthsQuantity
END
LEFT JOIN PostedSummary PS ON PS.FixedAssetId = AB.Id
LEFT JOIN dbo.FinancePostingPeriod BP
ON BP.CalendarYearId = YEAR(DATEADD(MONTH, N.N, AB.EffectiveStartDate))
AND BP.CalendarMonthId = MONTH(DATEADD(MONTH, N.N, AB.EffectiveStartDate))
LEFT JOIN dbo.FinanceFixedAssetDetail FAD
ON FAD.FixedAssetId = AB.Id
AND FAD.Months = N.N + 1
LEFT JOIN dbo.FinanceFixedAssetDepreciationPlan DP
ON DP.FixedAssetId = AB.Id
AND DP.Year = YEAR(DATEADD(MONTH, N.N, AB.EffectiveStartDate))
AND DP.Month = MONTH(DATEADD(MONTH, N.N, AB.EffectiveStartDate))
WHERE AB.DepreciationStartDate IS NOT NULL
AND (
(AB.DepreciationMethodId = 'IMMEDIATE')
OR (AB.UsefulLifeMonthsQuantity IS NOT NULL AND AB.UsefulLifeMonthsQuantity > 0)
)
),
-- MONTHLY (and legacy NULL) assets: pass the per-month rows through unchanged.
MonthlyCalc AS (
SELECT
BC.Id, BC.AssetNumber, BC.Info, BC.AcquisitionCostGross, BC.TaxKeyId, BC.AcquisitionCostNet,
BC.DepreciationTypeId, BC.CyclePeriodId, BC.AssetGroupId, BC.AcquisitionDate, BC.InServiceDate,
BC.DepreciationStartDate, BC.CalculationStartDate, BC.CalculationStartAcquisitionCostNet,
BC.UsefulLifeMonthsQuantity, BC.DepreciationAccountId, BC.AssetAccountId, BC.MemorandumValue,
BC.LocationId, BC.StatusId, BC.CostCenterId, BC.CostBearerId, BC.SwitchToLinearDate,
BC.DateCreated, BC.CreatedBy, BC.DateModified, BC.ModifiedBy, BC.RowVersion,
BC.DepreciationTypeName, BC.DepreciationMethodId, BC.DepreciationMethodName, BC.EffectiveBasis,
BC.CycleNumber, BC.DepreciationYear, BC.DepreciationMonth,
BC.PostingPeriodId, BC.FiscalYearPeriod, BC.PostingPeriodName, BC.FiscalYearId, BC.FiscalPeriodId,
BC.CalendarYearId, BC.CalendarMonthId, BC.PostingPeriodStatus,
BC.DepreciationPlanId, BC.IsPosted, BC.DepreciationAmount
FROM BaseCalc BC
WHERE ISNULL(BC.CyclePeriodId, 'MONTHLY') <> 'YEARLY'
),
-- YEARLY assets: aggregate the clean per-month amounts to a single annual value
-- anchored to the last scheduled month of each calendar year.
YearlyAgg AS (
SELECT
BC.Id,
BC.DepreciationYear,
MAX(BC.DepreciationMonth) AS BookMonth,
SUM(BC.DepreciationAmountClean) AS AnnualAmountCalc
FROM BaseCalc BC
WHERE ISNULL(BC.CyclePeriodId, 'MONTHLY') = 'YEARLY'
GROUP BY BC.Id, BC.DepreciationYear
),
YearlyCalc AS (
SELECT
AB.Id, AB.AssetNumber, AB.Info, AB.AcquisitionCostGross, AB.TaxKeyId, AB.AcquisitionCostNet,
AB.DepreciationTypeId, AB.CyclePeriodId, AB.AssetGroupId, AB.AcquisitionDate, AB.InServiceDate,
AB.DepreciationStartDate, AB.CalculationStartDate, AB.CalculationStartAcquisitionCostNet,
AB.UsefulLifeMonthsQuantity, AB.DepreciationAccountId, AB.AssetAccountId, AB.MemorandumValue,
AB.LocationId, AB.StatusId, AB.CostCenterId, AB.CostBearerId, AB.SwitchToLinearDate,
AB.DateCreated, AB.CreatedBy, AB.DateModified, AB.ModifiedBy, AB.RowVersion,
AB.DepreciationTypeName, AB.DepreciationMethodId, AB.DepreciationMethodName, AB.EffectiveBasis,
ROW_NUMBER() OVER (PARTITION BY AB.Id ORDER BY YA.DepreciationYear) AS CycleNumber,
YA.DepreciationYear,
YA.BookMonth AS DepreciationMonth,
BP.Id AS PostingPeriodId,
BP.FiscalYearPeriod,
BP.Name AS PostingPeriodName,
BP.FiscalYearId,
BP.FiscalPeriodId,
BP.CalendarYearId,
BP.CalendarMonthId,
BP.StatusId AS PostingPeriodStatus,
DP.Id AS DepreciationPlanId,
ISNULL(DP.IsPosted, 0) AS IsPosted,
CASE WHEN DP.IsPosted = 1 THEN DP.DepreciationAmount ELSE YA.AnnualAmountCalc END AS DepreciationAmount
FROM YearlyAgg YA
INNER JOIN AssetBase AB ON AB.Id = YA.Id
LEFT JOIN dbo.FinancePostingPeriod BP
ON BP.CalendarYearId = YA.DepreciationYear
AND BP.CalendarMonthId = YA.BookMonth
LEFT JOIN dbo.FinanceFixedAssetDepreciationPlan DP
ON DP.FixedAssetId = YA.Id
AND DP.Year = YA.DepreciationYear
AND DP.Month = YA.BookMonth
),
Unified AS (
SELECT * FROM MonthlyCalc
UNION ALL
SELECT * FROM YearlyCalc
)
SELECT
U.*
-- Calculated Percent (derived from effective depreciation amount)
, ROUND(
CASE
WHEN NULLIF(U.AcquisitionCostNet, 0) IS NULL THEN 0
ELSE (U.DepreciationAmount / U.AcquisitionCostNet) * 100.0
END
, 2) AS CalculatedPercent
-- Cumulative Depreciation (running sum of effective amounts)
, SUM(U.DepreciationAmount) OVER (PARTITION BY U.Id ORDER BY U.CycleNumber) AS CumulativeDepreciation
-- Remaining Book Value (book value runs down from the effective starting basis)
, U.EffectiveBasis - SUM(U.DepreciationAmount) OVER (PARTITION BY U.Id ORDER BY U.CycleNumber) AS RemainingBookValue
FROM Unified U;
GO
-- END xVIEW695_FinanceFixedAsset ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER VIEW
xVIEW750_Email
/*
-----------------------------------------------------------------------------------------
Purpose: 
-----------------------------------------------------------------------------------------
*/
AS
SELECT
E.Id
, E.EmailAccountId
, E.EmailFolderId
, E.ReceivedDateTime
, E.SenderName
, E.SenderEmail
, E.Receiver
, E.Cc
, E.Bcc
, E.Subject
, E.Pop3Ident
, E.ImapIdent
, E.Seen
, E.EntryDateTime
, E.IsSent
, E.SentDateTime
, E.NumOfSendingTries
, E.PrioHigh
, E.FollowUp
, E.Done
, E.MessageId
, E.AnsweredParentId
, E.ForwardedParentId
, E.Importance
, E.Tag
, E.IsEditable
, E.RowVersion
, CAST(
CASE
WHEN EXISTS
(
SELECT 1
FROM dbo.Email AS EAns
WHERE EAns.AnsweredParentId = E.Id
AND EAns.IsSent = 1
)
THEN 1 ELSE 0
END
AS bit
) AS Answered
, CAST(
CASE
WHEN EXISTS
(
SELECT 1
FROM dbo.Email AS EFwd
WHERE EFwd.ForwardedParentId = E.Id
AND EFwd.IsSent = 1
)
THEN 1 ELSE 0
END
AS bit
) AS Forwarded
, CAST(
CASE
WHEN EXISTS
(
SELECT 1
FROM dbo.EmailAttachment AS EA
WHERE EA.EmailId = E.Id
)
THEN 1 ELSE 0
END
AS bit
) AS HasAttachment
, CAST(
CASE
WHEN EXISTS
(
SELECT 1
FROM dbo.EmailCalendarInvite AS ECI
WHERE ECI.EmailId = E.Id
AND ECI.IcsUid IS NOT NULL
)
THEN 1 ELSE 0
END
AS bit
) AS IsAppointment
FROM dbo.Email AS E;
GO
-- END xVIEW750_Email ----------------------------------------------------------------------
