CREATE OR ALTER VIEW
xVIEW_DashboardRevenue
/*
-----------------------------------------------------------------------------------------
Purpose: Provide Data for Revenue Dashboards from DocPosition
-----------------------------------------------------------------------------------------
*/
AS
SELECT     DP.Id, D.DocDate, P.Name1 AS Partner, P.PartnerGroupId, DP.Quantity, DP.Revenue, DP.ProfitAmount, DP.ArticleId, A.Matchcode AS Article, A.ArticleGroupId, PD.PartnerTypeId, PG.Name AS PartnerGroupName, AG.Name AS ArticleGroup, DP.RevenueEffective
FROM        dbo.Doc AS D INNER JOIN
dbo.DocPosition AS DP ON D.Id = DP.DocId INNER JOIN
dbo.Partner AS P ON D.PartnerId = P.Id INNER JOIN
dbo.PartnerGroup AS PG ON P.PartnerGroupId = PG.Id INNER JOIN
dbo.PartnerDetail AS PD ON PD.PartnerId = P.Id AND PD.Id = D.PartnerDetailId INNER JOIN
dbo.Article AS A ON DP.ArticleId = A.Id INNER JOIN
dbo.ArticleGroup AS AG ON AG.Id = A.ArticleGroupId
WHERE     (D.PostingDate IS NOT NULL) AND (DP.RevenueEffective <> 0)
GO
