CREATE OR ALTER PROCEDURE 
xPROC001_SystemDatabaseChangeLog
@Name          NVARCHAR(255)
, @ObjectType    NVARCHAR(50)
, @ObjectName    NVARCHAR(50)
, @ChangeType    NVARCHAR(50)
, @ChangeText    NVARCHAR(MAX)   = NULL
, @ObjectSchema  NVARCHAR(50)    = NULL
, @UpdateScript  NVARCHAR(MAX)   = NULL
, @AppVersion    NVARCHAR(50)    = NULL
, @CreatedBy     INT             = NULL
AS
BEGIN
SET NOCOUNT ON;
IF @AppVersion IS NULL
BEGIN
SELECT TOP (1) @AppVersion = CONVERT(NVARCHAR(50), DbVersion)
FROM dbo.SystemVersion
WHERE Id = 1;
SET @AppVersion = ISNULL(@AppVersion, N'''');
END;
IF @ChangeText IS NULL
SET @ChangeText = @Name;
IF @UpdateScript IS NULL
SET @UpdateScript = @Name;
-- Idempotent insert: relies on UQ_SystemDatabaseChangeLog_Name.
IF NOT EXISTS (SELECT 1 FROM dbo.SystemDatabaseChangeLog WHERE Name = @Name)
BEGIN
INSERT INTO dbo.SystemDatabaseChangeLog
(Name, ObjectType, ObjectSchema, ObjectName, ChangeType,
ChangeText, UpdateScript, AppVersion, AppliedOn,
DateCreated, CreatedBy, DateModified, ModifiedBy)
VALUES
(@Name, @ObjectType, @ObjectSchema, @ObjectName, @ChangeType,
@ChangeText, @UpdateScript, @AppVersion, SYSUTCDATETIME(),
SYSUTCDATETIME(), @CreatedBy, SYSUTCDATETIME(), @CreatedBy);
END;
END;
GO
-- END xPROC001_SystemDatabaseChangeLog -------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC015_Number_Partner_Id
@NextId INT
AS
BEGIN
SET NOCOUNT ON;
IF NOT EXISTS
(
SELECT 1
FROM sys.tables t
JOIN sys.schemas s
ON s.schema_id = t.schema_id
WHERE s.name = 'dbo'
AND t.name = 'Partner'
)
BEGIN
THROW 50000, 'Tabelle dbo.Partner existiert nicht.', 1;
END;
DECLARE
@TargetIdInt INT
, @CurrentMax  INT
, @rc          INT
, @ReseedValue INT;
SET @TargetIdInt = TRY_CONVERT(INT, @NextId);
IF @TargetIdInt IS NULL OR @NextId <> @TargetIdInt
BEGIN
THROW 50001, 'Parameter @NextId muss ein ganzzahliger Wert im INT-Bereich sein.', 1;
END;
IF @TargetIdInt < 1
BEGIN
THROW 50002, '@NextId muss >= 1 sein.', 1;
END;
EXEC @rc = sp_getapplock
@Resource    = 'dbo.Partner.Identity.Reseed'
, @LockMode    = 'Exclusive'
, @LockOwner   = 'Session'
, @LockTimeout = 10000;
IF @rc < 0
BEGIN
THROW 50003, 'Konnte keinen exklusiven Lock erhalten.', 1;
END;
SELECT
@CurrentMax = MAX(p.Id)
FROM
dbo.Partner AS p;
IF @TargetIdInt <= ISNULL(@CurrentMax, 0)
BEGIN
EXEC sp_releaseapplock @Resource='dbo.Partner.Identity.Reseed', @LockOwner='Session';
THROW 50004, 'Der gewünschte nächste Id-Wert ist nicht größer als die vorhandene MAX(Id).', 1;
END;
-- Reseed-Wert: Bei leerer Tabelle nutzt DBCC CHECKIDENT den Wert direkt,
-- bei vorhandenen Zeilen wird der nächste Wert = Reseed + 1.
IF @CurrentMax IS NULL
SET @ReseedValue = @TargetIdInt;
ELSE
SET @ReseedValue = @TargetIdInt - 1;
DBCC CHECKIDENT ('dbo.Partner', RESEED, @ReseedValue) WITH NO_INFOMSGS;
-- Optional: Lock freigeben
EXEC sp_releaseapplock @Resource='dbo.Partner.Identity.Reseed', @LockOwner='Session';
SELECT
[ReseededTo] = IDENT_CURRENT('dbo.Partner')
, [NextIdentity] = IDENT_CURRENT('dbo.Partner') + 1;
END
GO
-- END xPROC015_Number_Partner_Id -------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
