CREATE OR ALTER PROCEDURE 
xPROC005_GetExtraFieldData
-- PURPOSE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) CREATE New Article
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
-- 25.04.13 23:27
@TableName NVARCHAR(MAX),
@Ids dbo.xTYPE_IdList READONLY -- Table-valued parameter containing the list of IDs
AS
BEGIN
SET NOCOUNT ON;
-- Declare a variable to hold the dynamic SQL query
DECLARE @Sql NVARCHAR(MAX);
-- Check if there are any columns starting with 'XX' in the given table
IF EXISTS (
SELECT 1
FROM INFORMATION_SCHEMA.COLUMNS
WHERE
TABLE_NAME = @TableName
AND
COLUMN_NAME LIKE 'XX%'
)
BEGIN
-- Build the dynamic SQL to select Id and construct the propertybag column
SELECT @Sql = N'
SELECT
CAST(Id AS NVARCHAR(500)) AS Id,
JSON_QUERY((
SELECT ' + STRING_AGG(QUOTENAME(COLUMN_NAME) + ' AS ' + QUOTENAME(COLUMN_NAME), ', ') WITHIN GROUP (ORDER BY COLUMN_NAME) + N'
FOR JSON PATH, WITHOUT_ARRAY_WRAPPER)) AS PropertyBag
FROM ' + QUOTENAME(@TableName) + N'
WHERE CAST(Id AS NVARCHAR(500)) IN (SELECT Id FROM @Ids)'
FROM INFORMATION_SCHEMA.COLUMNS
WHERE TABLE_NAME = @TableName
AND COLUMN_NAME LIKE 'XX%';
END
ELSE
BEGIN
-- If no 'XX' columns exist, return Id and an empty propertybag
SET @Sql = N'
SELECT
CAST(Id AS NVARCHAR(500)) AS Id,'''' AS PropertyBag
FROM ' + QUOTENAME(@TableName) + N'
WHERE CAST(Id AS NVARCHAR(500)) IN (SELECT Id FROM @Ids)'
;
END
-- Execute the dynamic SQL
EXEC sp_executesql @Sql, N'@Ids dbo.xTYPE_IdList READONLY', @Ids;
END
GO
-- END xPROC005_GetExtraFieldData ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC018_GetBusinessPartnerNumberConcatenated
