BEGIN
SET NOCOUNT ON;
SELECT
p.Id,
ISNULL(STRING_AGG(d.Id, ',') WITHIN GROUP (ORDER BY d.Id),'') AS BusinessPartnerNumberConcatenated
FROM dbo.Partner AS p
