CREATE OR ALTER PROCEDURE 
xPROC109_ArticleSalesPriceWizard
-- xPROC109_ArticleSalesPriceWizard ----------------------------------------------------------------------
@ArticleGroupId        INT
, @PriceListId           INT
, @ValidFrom             DATE
, @SalesPrice            DECIMAL(19,6) = NULL
, @Factor                DECIMAL(19,6) = NULL
, @Difference            DECIMAL(19,6) = NULL
AS
BEGIN
SET NOCOUNT ON
BEGIN TRY
BEGIN TRANSACTION
IF @SalesPrice IS NULL AND @Factor IS NULL AND @Difference IS NULL
BEGIN
RAISERROR('Mindestens ein Preisparameter (SalesPrice, Factor, Difference) muss angegeben werden.', 16, 1)
ROLLBACK TRANSACTION
RETURN
END
IF
(@SalesPrice IS NOT NULL AND @Factor IS NOT NULL)
OR (@SalesPrice IS NOT NULL AND @Difference IS NOT NULL)
OR (@Factor IS NOT NULL AND @Difference IS NOT NULL)
BEGIN
RAISERROR('Es darf nur EIN Preisparameter angegeben werden.', 16, 1)
ROLLBACK TRANSACTION
RETURN
END
;WITH Articles AS (
SELECT
A.Id AS ArticleId
,COALESCE(ASP.SalesPrice, 0) AS OldPrice
FROM
Article A
LEFT JOIN
ArticleSalesPriceList ASP
ON  ASP.ArticleId = A.Id
AND ASP.PriceListId = @PriceListId
AND ASP.ValidFrom = (
SELECT MAX(ValidFrom)
FROM ArticleSalesPriceList
WHERE ArticleId = A.Id
AND PriceListId = @PriceListId
AND ValidFrom <= @ValidFrom
)
WHERE
A.ArticleGroupId = @ArticleGroupId
)
INSERT INTO ArticleSalesPriceList
(
ArticleId
,PriceListId
,ValidFrom
,SalesPrice
)
SELECT
ArticleId
,@PriceListId
,@ValidFrom
,CASE
WHEN @SalesPrice IS NOT NULL THEN @SalesPrice
WHEN @Factor     IS NOT NULL THEN OldPrice * @Factor
WHEN @Difference IS NOT NULL THEN OldPrice + @Difference
END
FROM
Articles
COMMIT TRANSACTION
END TRY
BEGIN CATCH
IF XACT_STATE() <> 0
ROLLBACK TRANSACTION
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
,@ErrorLine INT = ERROR_LINE()
,@ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE()
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage)
END CATCH
END
GO
-- END xPROC109_ArticleSalesPriceWizard ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC150U_PartnerPurchasePriceList
-- xPROC150U_PartnerPurchasePriceList ----------------------------------------------------------------------
-- Purpose: UNCLEAR
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) UPDATE or INSERT PartnerPurchasePriceList
-- 30.) UPDATE DocPosition
-- 90.) END TRANSACTION
-------------------------------------------------------------------------------------------------------------
-- 26.06.26 03:45
@parxDocPositionId INT,
@parxPrice DECIMAL(19,6),
@parxDiscountPercent DECIMAL(19,6)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @ArticleId NVARCHAR(30)
DECLARE @DocId INT
DECLARE @PriceUnitId INT
SELECT
@ArticleId = ArticleId
, @DocId = DocId
, @PriceUnitId = PriceUnitId 
FROM DocPosition
WHERE Id = @parxDocPositionId
DECLARE @PartnerId INT
DECLARE @DocCategoryId NVARCHAR(10)
SELECT
@PartnerId = PartnerId
, @DocCategoryId = DocCategoryId
FROM Doc
WHERE Id = @DocId
DECLARE @DiscountGroupAssigned BIT = 0
SELECT
@DiscountGroupAssigned = ISNULL(DiscountGroupAssigned, 0)
FROM PartnerPurchasePriceList
WHERE PartnerId = @PartnerId AND ArticleId = @ArticleId
DECLARE @DiscountGroupNameId INT
SELECT
@DiscountGroupNameId = DiscountGroupNameId 
FROM PartnerDetail
WHERE PartnerId = @PartnerId AND PartnerTypeId = 'Supplier'
DECLARE @ArticleGroupId INT
SELECT
@ArticleGroupId = ArticleGroupId 
FROM Article
WHERE Id = @ArticleId
DECLARE @DiscountGroupDiscountPercent DECIMAL(19,6)
SELECT
@DiscountGroupDiscountPercent = DiscountPercent
FROM PartnerDiscountGroup
WHERE DiscountGroupNameId = @DiscountGroupNameId AND ArticleGroupId = @ArticleGroupId 
-- 20.) UPDATE or INSERT PartnerPurchasePriceList
IF(@DocCategoryId = 'Purchase')
BEGIN
IF EXISTS (SELECT 1 FROM PartnerPurchasePriceList WHERE PartnerId = @PartnerId AND ArticleId = @ArticleId)
BEGIN
UPDATE PartnerPurchasePriceList SET
PurchasePrice = @parxPrice,
DiscountPercent = CASE WHEN @DiscountGroupAssigned = 0 THEN @parxDiscountPercent ELSE DiscountPercent END
WHERE PartnerId = @PartnerId AND ArticleId = @ArticleId;
END
ELSE
BEGIN
INSERT INTO PartnerPurchasePriceList (PartnerId, ArticleId, PurchasePrice, DiscountPercent, PriceUnitId, DiscountGroupAssigned)
VALUES (@PartnerId, @ArticleId, @parxPrice, CASE WHEN @DiscountGroupDiscountPercent IS NULL THEN @parxDiscountPercent ELSE @DiscountGroupDiscountPercent END, @PriceUnitId, CASE WHEN @DiscountGroupDiscountPercent IS NULL THEN 0 ELSE 1 END);
-- 30.) UPDATE DocPosition
UPDATE DocPosition
SET
DiscountPercent = CASE WHEN @DiscountGroupDiscountPercent IS NULL THEN @parxDiscountPercent ELSE @DiscountGroupDiscountPercent END
, QuantityDiscountPercent = 
CASE
WHEN DP.Quantity >= PDG.QuantityLevelE AND PDG.QuantityLevelE > 0 AND @DiscountGroupAssigned = 1 THEN PDG.QuantityDiscountE
WHEN DP.Quantity >= PDG.QuantityLevelD AND PDG.QuantityLevelD > 0 AND @DiscountGroupAssigned = 1 THEN PDG.QuantityDiscountD
WHEN DP.Quantity >= PDG.QuantityLevelC AND PDG.QuantityLevelC > 0 AND @DiscountGroupAssigned = 1 THEN PDG.QuantityDiscountC
WHEN DP.Quantity >= PDG.QuantityLevelB AND PDG.QuantityLevelB > 0 AND @DiscountGroupAssigned = 1 THEN PDG.QuantityDiscountB
WHEN DP.Quantity >= PDG.QuantityLevelA AND PDG.QuantityLevelA > 0 AND @DiscountGroupAssigned = 1 THEN PDG.QuantityDiscountA
ELSE 0 END
FROM DocPosition DP
LEFT JOIN PartnerDiscountGroup PDG ON PDG.DiscountGroupNameId = @DiscountGroupNameId AND PDG.ArticleGroupId = @ArticleGroupId
WHERE DP.Id = @parxDocPositionId
END
END
-- 90.) END TRANSACTION
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC150U_PartnerPurchasePriceList ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
