xPROC150U_PartnerPurchasePriceList_DiscountGroup
/*
-------------------------------------------------------------------------------------------------------------
-- 26.06.26 03:45
-- PURPOSE: UPDATE DiscountPercent in Purchase Price List for all assigned records
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) UPDATE PartnerDiscountGroup
-- 30.) UPDATE PartnerPurchasePriceList
