@DiscountGroupNameId = DiscountGroupNameId 
FROM PartnerDiscountGroup
WHERE Id = @parxDiscountGroupId 
-- 20.) UPDATE PartnerDiscountGroup
UPDATE PartnerDiscountGroup
SET
DiscountPercent = @parxDiscountPercent 
WHERE Id = @parxDiscountGroupId 
-- 30.) UPDATE PartnerPurchasePriceList
UPDATE PartnerPurchasePriceList
SET
DiscountPercent = PDG.DiscountPercent
FROM PartnerPurchasePriceList PPPL
LEFT JOIN Article A ON A.Id = PPPL.ArticleId
