CREATE OR ALTER PROCEDURE 
xPROC150U_PartnerPurchasePriceList_Supplier
/*
-------------------------------------------------------------------------------------------------------------
-- 26.06.26 03:45
-- PURPOSE: Set all Discounts in the Purchase Price List to Zero and Update the records that match a Discount Group with the DiscountPercent after change of Discount Group
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) UPDATE PartnerDetail
-- 30.) UPDATE PartnerPurchasePriceList
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
*/
@parxDiscountGroupNameId INT,
@parxPartnerDetailId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @PartnerId INT 
SELECT
@PartnerId = PartnerId
FROM PartnerDetail
WHERE Id = @parxPartnerDetailId
-- 20.) UPDATE PartnerDetail
UPDATE PartnerDetail 
SET
DiscountGroupNameId = CASE WHEN @parxDiscountGroupNameId = -1 THEN NULL ELSE @parxDiscountGroupNameId END
WHERE Id = @parxPartnerDetailId
-- 30.) UPDATE PartnerPurchasePriceList
UPDATE PPPL
SET
DiscountPercent = ISNULL(PDG.DiscountPercent, 0)
, DiscountGroupAssigned = CASE WHEN @parxDiscountGroupNameId = -1 OR PDG.DiscountPercent IS NULL THEN 0 ELSE 1 END
FROM PartnerPurchasePriceList PPPL
LEFT JOIN Article A ON A.Id = PPPL.ArticleId
LEFT JOIN PartnerDiscountGroup PDG ON PDG.DiscountGroupNameId = @parxDiscountGroupNameId AND PDG.ArticleGroupId = A.ArticleGroupId
WHERE PPPL.PartnerId = @PartnerId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
