CREATE OR ALTER PROCEDURE 
xPROC159_PartnerPurchasePriceListImportWizard
-- Purpose: Imports into PartnerPurchasePriceList from CSV file
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) UPDATE or INSERT PartnerPurchasePriceList
-- 90.) END TRANSACTION
----------xPROC159_PartnerPurchasePriceListImportWizard---------------------------------------------------------------------------------------------------
@CsvContent NVARCHAR(MAX)
AS
BEGIN
SET NOCOUNT ON;
SET XACT_ABORT ON;
BEGIN TRANSACTION;
BEGIN TRY
CREATE TABLE #PartnerPurchasePriceListImport
(
PartnerId INT NOT NULL
,   ArticleId NVARCHAR(30) NOT NULL
,   DeliveryTime INT NOT NULL
,   MinimumQuantity DECIMAL(19,6) NOT NULL
,   LotSize DECIMAL(19,6) NOT NULL
,   DiscountGroupAssigned BIT NOT NULL
,   PurchasePrice DECIMAL(19,6) NOT NULL
,   DiscountPercent DECIMAL(19,6) NOT NULL
,   LogisticCost DECIMAL(19,6) NOT NULL
,   CustomsCost DECIMAL(19,6) NOT NULL
,   RiskCost DECIMAL(19,6) NOT NULL
,   PriceUnitId INT NOT NULL
,   Comment NVARCHAR(255) NULL
);
CREATE TABLE #CsvLines
(
LineIndex INT IDENTITY(1,1) PRIMARY KEY
,   Line NVARCHAR(MAX) NOT NULL
);
CREATE TABLE #Parsed
(
LineIndex INT NOT NULL
,   ColNo INT NOT NULL
,   Col NVARCHAR(MAX) NULL
);
DECLARE @s NVARCHAR(MAX) = REPLACE(@CsvContent, CHAR(13), '');
DECLARE @pos INT = 1;
DECLARE @next INT;
DECLARE @len INT = LEN(@s);
DECLARE @line NVARCHAR(MAX);
WHILE @pos <= @len
BEGIN
SET @next = CHARINDEX(CHAR(10), @s, @pos);
IF @next = 0
BEGIN
SET @line = SUBSTRING(@s, @pos, @len - @pos + 1);
SET @pos = @len + 1;
END
ELSE
BEGIN
SET @line = SUBSTRING(@s, @pos, @next - @pos);
SET @pos = @next + 1;
END;
SET @line = LTRIM(RTRIM(@line));
IF @line <> ''
INSERT INTO #CsvLines (Line)
VALUES (@line);
END;
DELETE FROM #CsvLines
WHERE LineIndex = (SELECT MIN(LineIndex) FROM #CsvLines);
INSERT INTO #Parsed
(
LineIndex
,   ColNo
,   Col
)
SELECT
L.LineIndex
,   ROW_NUMBER() OVER (PARTITION BY L.LineIndex ORDER BY (SELECT 1)) AS ColNo
,   LTRIM(RTRIM(S.value)) AS Col
FROM #CsvLines AS L
CROSS APPLY STRING_SPLIT(L.Line, ';') AS S;
INSERT INTO #PartnerPurchasePriceListImport
(
PartnerId
,   ArticleId
,   DeliveryTime
,   MinimumQuantity
,   LotSize
,   DiscountGroupAssigned
,   PurchasePrice
,   DiscountPercent
,   LogisticCost
,   CustomsCost
,   RiskCost
,   PriceUnitId
,   Comment
)
SELECT
CONVERT(INT, MAX(CASE WHEN ColNo = 2 THEN Col END)) AS PartnerId
,   MAX(CASE WHEN ColNo = 3 THEN Col END) AS ArticleId
,   CONVERT(INT, MAX(CASE WHEN ColNo = 5 THEN Col END)) AS DeliveryTime
,   CONVERT(DECIMAL(19,6), MAX(CASE WHEN ColNo = 6 THEN Col END)) AS MinimumQuantity
,   CONVERT(DECIMAL(19,6), MAX(CASE WHEN ColNo = 7 THEN Col END)) AS LotSize
,   CONVERT(BIT, MAX(CASE WHEN ColNo = 8 THEN Col END)) AS DiscountGroupAssigned
,   CONVERT(DECIMAL(19,6), MAX(CASE WHEN ColNo = 9 THEN Col END)) AS PurchasePrice
,   CONVERT(DECIMAL(19,6), MAX(CASE WHEN ColNo = 10 THEN Col END)) AS DiscountPercent
,   CONVERT(DECIMAL(19,6), MAX(CASE WHEN ColNo = 11 THEN Col END)) AS LogisticCost
,   CONVERT(DECIMAL(19,6), MAX(CASE WHEN ColNo = 12 THEN Col END)) AS CustomsCost
,   CONVERT(DECIMAL(19,6), MAX(CASE WHEN ColNo = 13 THEN Col END)) AS RiskCost
,   CONVERT(INT, MAX(CASE WHEN ColNo = 15 THEN Col END)) AS PriceUnitId
,   NULLIF(MAX(CASE WHEN ColNo = 17 THEN Col END), '') AS Comment
FROM #Parsed AS P
GROUP BY
P.LineIndex;
UPDATE
PPPL
SET
PPPL.DeliveryTime = PPPLI.DeliveryTime
,   PPPL.MinimumQuantity = PPPLI.MinimumQuantity
,   PPPL.LotSize = PPPLI.LotSize
,   PPPL.DiscountGroupAssigned = PPPLI.DiscountGroupAssigned
,   PPPL.PurchasePrice = PPPLI.PurchasePrice
,   PPPL.DiscountPercent = PPPLI.DiscountPercent
,   PPPL.LogisticCost = PPPLI.LogisticCost
,   PPPL.CustomsCost = PPPLI.CustomsCost
,   PPPL.RiskCost = PPPLI.RiskCost
,   PPPL.PriceUnitId = PPPLI.PriceUnitId
,   PPPL.Comment = PPPLI.Comment
FROM PartnerPurchasePriceList AS PPPL
JOIN #PartnerPurchasePriceListImport AS PPPLI
ON PPPLI.PartnerId = PPPL.PartnerId
AND PPPLI.ArticleId = PPPL.ArticleId;
INSERT INTO PartnerPurchasePriceList
(
PartnerId
,   ArticleId
,   DeliveryTime
,   MinimumQuantity
,   LotSize
,   DiscountGroupAssigned
,   PurchasePrice
,   DiscountPercent
,   LogisticCost
,   CustomsCost
,   RiskCost
,   PriceUnitId
,   Comment
)
SELECT
PPPLI.PartnerId
,   PPPLI.ArticleId
,   PPPLI.DeliveryTime
,   PPPLI.MinimumQuantity
,   PPPLI.LotSize
,   PPPLI.DiscountGroupAssigned
,   PPPLI.PurchasePrice
,   PPPLI.DiscountPercent
,   PPPLI.LogisticCost
,   PPPLI.CustomsCost
,   PPPLI.RiskCost
,   PPPLI.PriceUnitId
,   PPPLI.Comment
FROM #PartnerPurchasePriceListImport AS PPPLI
LEFT JOIN PartnerPurchasePriceList AS PPPL
ON PPPLI.PartnerId = PPPL.PartnerId
AND PPPLI.ArticleId = PPPL.ArticleId
WHERE PPPL.Id IS NULL;
IF OBJECT_ID('tempdb..#PartnerPurchasePriceListImport') IS NOT NULL
DROP TABLE #PartnerPurchasePriceListImport;
IF OBJECT_ID('tempdb..#CsvLines') IS NOT NULL
DROP TABLE #CsvLines;
IF OBJECT_ID('tempdb..#Parsed') IS NOT NULL
DROP TABLE #Parsed;
-- 90.) END TRANSACTION
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
------------------END xPROC159_PartnerPurchasePriceListImportWizard------------------------------------------------------------------------------------------
