-- xPROC192_WarehouseBinLocation_Wizard ----------------------------------------------------------------------
-- PURPOSE: Create records in WarehouseBinLocation
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC192_WarehouseBinLocation_Wizard
-- 26.06.26 03:45
@parxWarehouseId INT,
@parxTvpDimensions [dbo].[xTYPE_WarehouseBinLocationWizardDimension] READONLY
AS
BEGIN
SET NOCOUNT ON;
SET XACT_ABORT ON;
BEGIN TRANSACTION;
BEGIN TRY
DECLARE @DimensionCount INT = (
SELECT COUNT(*)
FROM @parxTvpDimensions
);
IF @DimensionCount = 0
BEGIN
COMMIT TRANSACTION;
RETURN;
END;
IF NOT EXISTS (
SELECT 1
FROM dbo.Warehouse
WHERE Id = @parxWarehouseId
)
BEGIN
THROW 50000, 'Warehouse does not exist.', 1;
END;
IF EXISTS (
SELECT 1
FROM @parxTvpDimensions
WHERE FromValue > ToValue
)
BEGIN
THROW 50001, 'From must be less than or equal To for every dimension.', 1;
END;
DECLARE @Dims TABLE (
Position INT NOT NULL PRIMARY KEY
, Name NVARCHAR(50) NOT NULL
, FromValue INT NOT NULL
, ToValue INT NOT NULL
);
INSERT INTO @Dims (
Position
, Name
, FromValue
, ToValue
)
SELECT
Position
, Name
, FromValue
, ToValue
FROM @parxTvpDimensions;
IF EXISTS (
SELECT 1
FROM @Dims
WHERE LEN(LTRIM(RTRIM(Name))) = 0
)
BEGIN
THROW 50004, 'Dimension name must not be empty.', 1;
END;
IF EXISTS (
SELECT 1
FROM @Dims
WHERE Position < 1
OR Position > @DimensionCount
)
OR EXISTS (
SELECT 1
FROM (
SELECT TOP (@DimensionCount)
ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS Position
FROM sys.all_objects
) AS Expected
WHERE NOT EXISTS (
SELECT 1
FROM @Dims AS D
WHERE D.Position = Expected.Position
)
)
BEGIN
THROW 50003, 'Dimension positions must be continuous starting with 1.', 1;
END;
DECLARE @Created TABLE (
LevelNo INT NOT NULL
, Id INT NOT NULL
, ParentId INT NULL
, Name NVARCHAR(50) NOT NULL
, HierarchyNode hierarchyid NOT NULL
, PRIMARY KEY (LevelNo, Id)
);
DECLARE @CurrentLevel TABLE (
Id INT NOT NULL PRIMARY KEY
, ParentId INT NULL
, Name NVARCHAR(50) NOT NULL
, HierarchyNode hierarchyid NOT NULL
);
DECLARE @NewNames TABLE (
RowId INT IDENTITY(1,1) NOT NULL PRIMARY KEY
, ParentId INT NULL
, ParentHierarchyNode hierarchyid NOT NULL
, Name NVARCHAR(4000) NOT NULL
);
DECLARE @Level INT = 1;
DECLARE @CurrentName NVARCHAR(50);
DECLARE @CurrentFrom INT;
DECLARE @CurrentTo INT;
DECLARE @PadLen INT;
DECLARE @RowId INT;
DECLARE @ParentId INT;
DECLARE @ParentHierarchyNode hierarchyid;
DECLARE @Name NVARCHAR(4000);
DECLARE @NewHierarchyNode hierarchyid;
WHILE @Level <= @DimensionCount
BEGIN
SELECT
@CurrentName = Name
, @CurrentFrom = FromValue
, @CurrentTo = ToValue
FROM @Dims
WHERE Position = @Level;
SET @PadLen = LEN(CONVERT(NVARCHAR(20), @CurrentTo));
DELETE FROM @CurrentLevel;
DELETE FROM @NewNames;
;WITH N AS (
SELECT TOP (@CurrentTo - @CurrentFrom + 1)
@CurrentFrom + ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1 AS n
FROM sys.all_objects AS ao1
CROSS JOIN sys.all_objects AS ao2
)
, ParentCandidates AS (
SELECT
CAST(NULL AS INT) AS Id
, CAST(N'' AS NVARCHAR(4000)) AS ParentName
, hierarchyid::GetRoot() AS ParentHierarchyNode
WHERE @Level = 1
UNION ALL
SELECT
C.Id
, CAST(C.Name AS NVARCHAR(4000)) AS ParentName
, C.HierarchyNode
FROM @Created AS C
WHERE C.LevelNo = @Level - 1
AND @Level > 1
)
INSERT INTO @NewNames (
ParentId
, ParentHierarchyNode
, Name
)
SELECT
P.Id
, P.ParentHierarchyNode
, CONCAT(
P.ParentName
, @CurrentName
, RIGHT(REPLICATE(N'0', @PadLen) + CONVERT(NVARCHAR(20), N.n), @PadLen)
)
FROM N
CROSS JOIN ParentCandidates AS P;
IF EXISTS (
SELECT 1
FROM @NewNames
WHERE LEN(Name) > 50
)
BEGIN
THROW 50002, 'Generated bin location name exceeds 50 characters.', 1;
END;
SELECT @RowId = MIN(RowId)
FROM @NewNames;
WHILE @RowId IS NOT NULL
BEGIN
SELECT
@ParentId = ParentId
, @ParentHierarchyNode = ParentHierarchyNode
, @Name = Name
FROM @NewNames
WHERE RowId = @RowId;
IF NOT EXISTS (
SELECT 1
FROM dbo.WarehouseBinLocation AS Existing
WHERE Existing.WarehouseId = @parxWarehouseId
AND (
(Existing.ParentId IS NULL AND @ParentId IS NULL)
OR Existing.ParentId = @ParentId
)
AND Existing.Name = @Name
)
BEGIN
SELECT @NewHierarchyNode = @ParentHierarchyNode.GetDescendant(MAX(Existing.HierarchyNode), NULL)
FROM dbo.WarehouseBinLocation AS Existing WITH (UPDLOCK, HOLDLOCK)
WHERE Existing.WarehouseId = @parxWarehouseId
AND (
(Existing.ParentId IS NULL AND @ParentId IS NULL)
OR Existing.ParentId = @ParentId
);
INSERT INTO dbo.WarehouseBinLocation (
WarehouseId
, Name
, ParentId
, HierarchyNode
)
VALUES (
@parxWarehouseId
, CONVERT(NVARCHAR(50), @Name)
, @ParentId
, @NewHierarchyNode
);
END;
SELECT @RowId = MIN(RowId)
FROM @NewNames
WHERE RowId > @RowId;
END;
INSERT INTO @CurrentLevel (
Id
, ParentId
, Name
, HierarchyNode
)
SELECT
Existing.Id
, Existing.ParentId
, Existing.Name
, Existing.HierarchyNode
FROM dbo.WarehouseBinLocation AS Existing
INNER JOIN @NewNames AS NN
ON Existing.WarehouseId = @parxWarehouseId
AND (
(Existing.ParentId IS NULL AND NN.ParentId IS NULL)
OR Existing.ParentId = NN.ParentId
)
AND Existing.Name = NN.Name;
INSERT INTO @Created (
LevelNo
, Id
, ParentId
, Name
, HierarchyNode
)
SELECT
@Level
, Id
, ParentId
, Name
, HierarchyNode
FROM @CurrentLevel;
SET @Level = @Level + 1;
END;
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
IF @@TRANCOUNT > 0
BEGIN
ROLLBACK TRANSACTION;
END;
THROW;
END CATCH
END
GO
-- END xPROC192_WarehouseBinLocation_Wizard ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE
xPROC200_GenerateNewDocNumber
-- xPROC200_GenerateNewDocNumber -------------------------------------
-- PURPOSE: Get Number from Sequence of passed Doc Type and put it together with Prefix and Date to generate the new Doc Number
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@DocTypeId NVARCHAR(35)
AS
BEGIN
SET NOCOUNT ON;
DECLARE @DocNumberPrefix NVARCHAR(3)  -- Präfix ist NVARCHAR(3)
DECLARE @NextNumber INT
DECLARE @NewDocNumber NVARCHAR(30)
DECLARE @SQLString NVARCHAR(4000) -- Dynamisches SQL für die Sequenz
DECLARE @ParmDefinition NVARCHAR(100)
-- Abrufen des Prefix für den gegebenen DocTypeId
SELECT @DocNumberPrefix = DocNumberPrefix
FROM dbo.DocType
WHERE Id = @DocTypeId
SET @SQLString = N'SELECT @NextNumberOUT = NEXT VALUE FOR dbo.Doc_' + @DocTypeId + N'_Sequence';
SET @ParmDefinition = N'@NextNumberOUT INT OUTPUT';
-- Ausführen des dynamischen SQL
EXECUTE sp_executesql @SQLString, @ParmDefinition, @NextNumberOUT = @NextNumber OUTPUT;
-- Erstellen der neuen Dokumentnummer mit Datum und Sequenznummer
DECLARE @Now date = GETDATE();
SET @NewDocNumber =
@DocNumberPrefix +
RIGHT(CONVERT(char(4), YEAR(@Now)), 2) +
RIGHT('0' + CONVERT(varchar(2), MONTH(@Now)), 2) +
CAST(@NextNumber AS nvarchar(10))
-- Rückgabe der neuen Dokumentnummer
SELECT @NewDocNumber AS NewDocumentNumber
-- 91.) ERROR HANDLING
END
GO
-- xPROC200_GenerateNewDocNumber --------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE
dbo.xPROC200N_Doc
-- xPROC200N_Doc -------------------------------------
-- PURPOSE: Create New Doc for selected Partner and Doc type with Addresses and possible extension
-- 1.) Create and prefill Doc 
-- 2.) Create and prefill DeliveryAddress
-- 3.) Create and prefill BillingAddress
-- 4.) Create DocContract record
-- 5.) Create FieldService record
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxDocCategoryId NVARCHAR(10),
@parxDocTypeId NVARCHAR(35),
@parxPartnerDetailId INT,
@parxEmployeeId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 1.) Create and prefill Doc 
-- Declare Variables
-- From Scope
DECLARE @newxDocId INT
-- FROM Code
DECLARE @locxDocCategoryId NVARCHAR(10)
DECLARE @locxDocTypeId NVARCHAR(35)
DECLARE @locxPartnerDetailId INT
-- Generate new DocNumber
DECLARE @SQLString NVARCHAR(100)
DECLARE @ParmDefinition NVARCHAR(75)
DECLARE @NextNumber NVARCHAR(10)
DECLARE @newxDocNumber NVARCHAR(20)
-- FROM FinancePostingPeriod
DECLARE @CurrentPostingPeriodId INT
SET @CurrentPostingPeriodId = dbo.xFUNCTION001_GetCurrentPostingPeriodId()
-- FROM DocType
DECLARE @InventoryStatusId NVARCHAR(10)
DECLARE @WarehousingEffective INT
DECLARE @RevenueEffective INT
DECLARE @DocNumberPrefix NVARCHAR(3)
DECLARE @Draft BIT
DECLARE @IsContract BIT
DECLARE @IsFieldService BIT
-- FROM PartnerDetail
DECLARE @PartnerId INT
DECLARE @PartnerContactPersonId INT
DECLARE @ClerkId INT
DECLARE @SalesPersonId INT
DECLARE @DivergentInvoiceRecipientId INT
DECLARE @TermsOfDeliveryId INT
DECLARE @TermsOfPaymentId INT
DECLARE @PriceListId INT
DECLARE @StandardDeliveryAddressId INT
DECLARE @StandardBillingAddressId INT
DECLARE @ForeignCurrencyId NVARCHAR(3)
DECLARE @DocDiscountPercent DECIMAL(19,6)
-- FROM Partner
DECLARE @LanguageId NVARCHAR(5)
DECLARE @LocationId INT
-- FROM AdminCurrencyRate
DECLARE @Rate DECIMAL(19,6) = NULL
-- FROM PartnerDetailOutput
DECLARE @OutputControlFormatId INT
DECLARE @ReportTemplateId INT
-- Select From
-- FROM Code
SET @locxDocCategoryId = @parxDocCategoryId
SET @locxDocTypeId = @parxDocTypeId
SET @locxPartnerDetailId = @parxPartnerDetailId
-- FROM DocType
SELECT
@InventoryStatusId = InventoryStatusId
, @WarehousingEffective = WarehousingEffective
, @RevenueEffective = RevenueEffective
, @DocNumberPrefix = DocNumberPrefix
, @Draft = Draft
, @IsContract = IsContract
, @IsFieldService = IsFieldService
FROM DocType
WHERE Id = @locxDocTypeId
-- FROM PartnerDetail
SELECT
@PartnerId = PartnerId
, @PartnerContactPersonId = StandardContactPersonId
, @ClerkId = EmployeeId
, @SalesPersonId = SalesPersonId
, @DivergentInvoiceRecipientId = DivergentInvoiceRecipientId
, @TermsOfDeliveryId = TermsOfDeliveryId
, @TermsOfPaymentId = TermsOfPaymentId
, @PriceListId = PriceListSalesId
,@StandardDeliveryAddressId = StandardDeliveryAddressId
, @StandardBillingAddressId = StandardBillingAddressId
, @ForeignCurrencyId = ForeignCurrencyId
, @DocDiscountPercent = DocDiscountPercent
FROM PartnerDetail WHERE Id= @locxPartnerDetailId
-- FROM Partner
SELECT
@LanguageId = LanguageId,
@LocationId = LocationId
FROM Partner WHERE Id = @PartnerId 
-- FROM AdminCurrencyRate
IF @ForeignCurrencyId IS NOT NULL
BEGIN
SELECT
@Rate = ACR.Rate
FROM dbo.AdminCurrencyRate AS ACR
WHERE
ACR.ForeignCurrencyId = @ForeignCurrencyId
AND ACR.RateDate = CONVERT(date, GETDATE());
END
--Generate new DocNumber
CREATE TABLE #DocNumberResult (NewDocumentNumber NVARCHAR(30));
-- Aufruf der Prozedur und speichere den Rückgabewert in der temporären Tabelle
INSERT INTO #DocNumberResult
EXEC dbo.xPROC200_GenerateNewDocNumber
@DocTypeId = @parxDocTypeId  -- Übergabe des DocTypeId
-- Zuweisung des Wertes aus der temporären Tabelle in die Variable @newxDocNumber
SELECT @newxDocNumber = NewDocumentNumber
FROM #DocNumberResult;
-- FROM PartnerDetailOutput
SELECT
@OutputControlFormatId = OutputControlFormatId
, @ReportTemplateId = ReportTemplateId
FROM PartnerDetailOutput WHERE PartnerDetailId = @locxPartnerDetailId AND DocTypeId = @locxDocTypeId 
-- INSERT INTO Doc
INSERT INTO Doc(
DocNumber,
DocCategoryId,
DocTypeId,
InventoryStatusId,
WarehousingEffective,
RevenueEffective,
PartnerId,
PartnerDetailId,
Draft,
PostingPeriodId,
PartnerContactPersonId,
ClerkId,
SalesPersonId,
DivergentInvoiceRecipientId,
TermsOfDeliveryId,
LanguageId,
ReportTemplateId,
TermsOfPaymentId,
PriceListId,
DocDiscountPercent,
DownPaymentSum,
ForeignCurrencyId,
LocationId,
Rate,
OutputControlFormatId,
CreatedBy,
ModifiedBy
)
-- VALUES
VALUES (
@newxDocNumber
, @locxDocCategoryId
, @locxDocTypeId
, @InventoryStatusId
, @WarehousingEffective
, @RevenueEffective
, @PartnerId
, @locxPartnerDetailId
, @Draft
, CASE WHEN @RevenueEffective != 0 THEN @CurrentPostingPeriodId ELSE NULL END
, @PartnerContactPersonId
, CASE WHEN @ClerkId IS NOT NULL THEN @ClerkId ELSE @parxEmployeeId END
, @SalesPersonId
, @DivergentInvoiceRecipientId
, @TermsOfDeliveryId
, @LanguageId
, @ReportTemplateId 
, @TermsOfPaymentId
, @PriceListId
, @DocDiscountPercent
, 0
, @ForeignCurrencyId 
, @LocationId
, @Rate
, @OutputControlFormatId
, @parxEmployeeId 
, @parxEmployeeId 
)
SET @newxDocId = SCOPE_IDENTITY()
-- UPDATE Doc with Extra Fields
DROP TABLE IF EXISTS #ExtraFieldMapping;
CREATE TABLE #ExtraFieldMapping (
DocColumnName sysname NOT NULL
, PartnerColumnName sysname NOT NULL
, TargetTypeSql nvarchar(128) NOT NULL
);
INSERT INTO #ExtraFieldMapping (
DocColumnName
, PartnerColumnName
, TargetTypeSql
)
SELECT
DocColumn.name
, PartnerColumn.name
, CASE
WHEN DocType.name IN (N'nvarchar', N'nchar') AND DocColumn.max_length = -1 THEN CONCAT(DocType.name, N'(max)')
WHEN DocType.name IN (N'nvarchar', N'nchar') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.max_length / 2), N')')
WHEN DocType.name IN (N'varchar', N'char', N'varbinary', N'binary') AND DocColumn.max_length = -1 THEN CONCAT(DocType.name, N'(max)')
WHEN DocType.name IN (N'varchar', N'char', N'varbinary', N'binary') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.max_length), N')')
WHEN DocType.name IN (N'decimal', N'numeric') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.precision), N',', CONVERT(nvarchar(10), DocColumn.scale), N')')
WHEN DocType.name IN (N'datetime2', N'datetimeoffset', N'time') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.scale), N')')
ELSE DocType.name
END
FROM dbo.ExtraField AS DocExtraField
JOIN dbo.ExtraField AS PartnerExtraField
ON PartnerExtraField.Name = DocExtraField.Name
AND PartnerExtraField.SystemTableId = N'Partner'
JOIN sys.columns AS DocColumn
ON DocColumn.object_id = OBJECT_ID(N'dbo.Doc')
AND DocColumn.name = DocExtraField.Id
JOIN sys.types AS DocType
ON DocType.user_type_id = DocColumn.user_type_id
JOIN sys.columns AS PartnerColumn
ON PartnerColumn.object_id = OBJECT_ID(N'dbo.Partner')
AND PartnerColumn.name = PartnerExtraField.Id
JOIN sys.types AS PartnerType
ON PartnerType.user_type_id = PartnerColumn.user_type_id
WHERE DocExtraField.SystemTableId = N'Doc'
AND DocExtraField.Id LIKE N'XX%'
AND PartnerExtraField.Id LIKE N'XX%'
AND DocExtraField.SystemDataTypeId = PartnerExtraField.SystemDataTypeId
AND DocColumn.is_computed = 0
AND PartnerColumn.is_computed = 0
AND DocType.name NOT IN (N'timestamp', N'rowversion')
AND PartnerType.name NOT IN (N'timestamp', N'rowversion');
DECLARE @ExtraFieldValidationSql nvarchar(max);
DECLARE @ExtraFieldInvalidCondition nvarchar(max);
DECLARE @ExtraFieldInvalidCount int;
SELECT
@ExtraFieldInvalidCondition = STRING_AGG(
CAST(
CONCAT(
N'(P.'
, QUOTENAME(PartnerColumnName)
, N' IS NOT NULL AND TRY_CONVERT('
, TargetTypeSql
, N', P.'
, QUOTENAME(PartnerColumnName)
, N') IS NULL)'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N'OR '
)
FROM #ExtraFieldMapping;
IF @ExtraFieldInvalidCondition IS NOT NULL
BEGIN
SET @ExtraFieldValidationSql = CONCAT(
N'SELECT @ExtraFieldInvalidCount = COUNT(1)
FROM dbo.Partner AS P
WHERE P.Id = @PartnerId
AND ('
, @ExtraFieldInvalidCondition
, N'
);'
);
EXEC sys.sp_executesql
@ExtraFieldValidationSql
, N'@PartnerId int, @ExtraFieldInvalidCount int OUTPUT'
, @PartnerId = @PartnerId
, @ExtraFieldInvalidCount = @ExtraFieldInvalidCount OUTPUT;
IF @ExtraFieldInvalidCount > 0
BEGIN
THROW 50000, 'ExtraField value cannot be converted from Partner to Doc target data type.', 1;
END
END
DECLARE @ExtraFieldUpdateSql nvarchar(max);
DECLARE @ExtraFieldSetList nvarchar(max);
SELECT
@ExtraFieldSetList = STRING_AGG(
CAST(
CONCAT(
QUOTENAME(DocColumnName)
, N' = TRY_CONVERT('
, TargetTypeSql
, N', P.'
, QUOTENAME(PartnerColumnName)
, N')'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM #ExtraFieldMapping;
IF @ExtraFieldSetList IS NOT NULL
BEGIN
SET @ExtraFieldUpdateSql = CONCAT(
N'UPDATE D
SET '
, @ExtraFieldSetList
, N'
FROM dbo.Doc AS D
JOIN dbo.Partner AS P
ON P.Id = @PartnerId
WHERE D.Id = @newxDocId;'
);
EXEC sys.sp_executesql
@ExtraFieldUpdateSql
, N'@newxDocId int, @PartnerId int'
, @newxDocId = @newxDocId
, @PartnerId = @PartnerId;
END
-- 2.) Create and prefill DeliveryAddress
INSERT INTO dbo.DocDeliveryAddress (
DocId
, PartnerDeliveryAddressId
, Matchcode
, Name1
, Name2
, Name3
, Position
, Title
, Salutation
, FirstName
, LastName
, Street
, Extension
, Zip
, City
, CountryId
, Tel1
, Tel2
, Mobile
, Fax
, Email
, Homepage
, Keyword
, VatNumber
, TaxNumber
, ShippingZoneId
)
SELECT
@newxDocId
, PD.StandardDeliveryAddressId
, PDA.Matchcode
, PDA.Name1
, PDA.Name2
, PDA.Name3
, PDA.Position
, PDA.Title
, PDA.Salutation
, PDA.FirstName
, PDA.LastName
, PDA.Street
, PDA.Extension
, PDA.Zip
, PDA.City
, PDA.CountryId
, PDA.Tel1
, PDA.Tel2
, PDA.Mobile
, PDA.Fax
, PDA.Email
, PDA.Homepage
, PDA.Keyword
, PDA.VatNumber
, PDA.TaxNumber
, PDA.ShippingZoneId
FROM dbo.PartnerDetail AS PD
JOIN dbo.PartnerDeliveryAddress AS PDA
ON PDA.Id = PD.StandardDeliveryAddressId
WHERE PD.Id = @locxPartnerDetailId;
-- 3.) Create and prefill BillingAddress
INSERT INTO dbo.DocBillingAddress (
DocId
, PartnerBillingAddressId
, Matchcode
, Name1
, Name2
, Name3
, Position
, Title
, Salutation
, FirstName
, LastName
, Street
, Extension
, Zip
, City
, CountryId
, Tel1
, Tel2
, Mobile
, Fax
, Email
, Homepage
, Keyword
, VatNumber
, TaxNumber
, EInvoiceRoutingId
)
SELECT
@newxDocId
, PD.StandardBillingAddressId
, PBA.Matchcode
, PBA.Name1
, PBA.Name2
, PBA.Name3
, PBA.Position
, PBA.Title
, PBA.Salutation
, PBA.FirstName
, PBA.LastName
, PBA.Street
, PBA.Extension
, PBA.Zip
, PBA.City
, PBA.CountryId
, PBA.Tel1
, PBA.Tel2
, PBA.Mobile
, PBA.Fax
, PBA.Email
, PBA.Homepage
, PBA.Keyword
, PBA.VatNumber
, PBA.TaxNumber
, CASE WHEN PD.PartnerTypeId = N'Customer' THEN PBA.EInvoiceRoutingId ELSE NULL END
FROM dbo.PartnerDetail AS PD
JOIN dbo.PartnerBillingAddress AS PBA
ON PBA.Id = PD.StandardBillingAddressId
WHERE PD.PartnerId = CASE WHEN @DivergentInvoiceRecipientId IS NULL THEN @PartnerId ELSE @DivergentInvoiceRecipientId END
AND PD.PartnerTypeId = CASE WHEN @locxDocCategoryId = N'Sales' THEN N'Customer' ELSE N'Supplier' END;
-- 4.) Create DocContract record
IF( @IsContract = 1) BEGIN
INSERT INTO DocContract(
DocId
, TargetDocTypeId
, StartDate
, EndDate
, CyclePeriodId
, NextAppointment
, Prepayment
, CycleQuantity
, ExecutedCycles
)
VALUES(
@newxDocId
, NULL
, GETDATE()
, (CONVERT(date, '99991231', 112))
, NULL
, NULL
, 1
, 0
, 0
)
END
-- 5.) Create FieldService record
IF @IsFieldService = 1 BEGIN
