CREATE OR ALTER PROCEDURE 
-- xPROC200U_Doc_ForeignCurrencyId--------------------------------------------------------------------------------------------------
-- PURPOSE: Update the ForeignCurrencyId with passed value
xPROC200U_Doc_ForeignCurrencyId
-- 26.06.26
@parxDocId INT,
@parxEmployeeId INT,
@parxForeignCurrencyId nvarchar(3)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE Doc SET ForeignCurrencyId = CASE WHEN LEN(TRIM(@parxForeignCurrencyId)) = 0 THEN NULL ELSE @parxForeignCurrencyId END
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
, Rate = ACR.Rate
From Doc D
LEFT JOIN AdminCurrencyRate AS ACR ON ACR.ForeignCurrencyId = @parxForeignCurrencyId AND  ACR.RateDate = D.DocDate
WHERE D.Id = @parxDocId;
UPDATE DocPosition SET
Price = CASE WHEN (ASPLN.ForeignCurrencyId IS NOT NULL AND D.DocCategoryId = 'Sales') OR (D.ForeignCurrencyId IS NOT NULL AND D.DocCategoryId = 'Purchase') THEN CASE WHEN D.Rate IS NULL OR D.Rate = 0 OR DP.ForeignCurrencyPrice IS NULL THEN 0 ELSE ROUND(DP.ForeignCurrencyPrice / NULLIF(D.Rate, 0), 2) END ELSE DP.Price END
, ForeignCurrencyPrice = CASE WHEN ASPLN.ForeignCurrencyId IS NULL THEN CASE WHEN D.Rate IS NULL OR D.Rate = 0 THEN 0 ELSE ROUND(DP.Price * D.Rate, 2) END ELSE ISNULL(DP.ForeignCurrencyPrice, 0) END
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN ArticleSalesPriceListName ASPLN ON ASPLN.Id = D.PriceListId
WHERE D.Id = @parxDocId AND D.ForeignCurrencyId IS NOT NULL;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC200U_Doc_ForeignCurrencyId----------------------------------------------------------------------------------------
