CREATE OR ALTER PROCEDURE 
xPROC200U_Doc_CostPrice
-- 26.06.26
@parxDocId INT,
@parxEmployeeId INT
-- PURPOSE: Update the CostPrice with passed value
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE DocPosition SET
ArticleCostPrice =  CASE WHEN D.DocCategoryId = 'Sales' THEN ISNULL(APC.CostPrice,0) / DP.PriceUnitId ELSE 0 END
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN ArticlePriceCalculation APC ON APC.ArticleId = DP.ArticleId
WHERE DP.DocId = @parxDocId
UPDATE Doc SET
ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
