CREATE OR ALTER PROCEDURE 
xPROC200U_Doc_Rate
-- PURPOSE: Update the Rate with passed value
-- 26.06.26
@parxDocId INT,
@parxEmployeeId INT,
@parxRate decimal(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE Doc SET Rate = @parxRate
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
UPDATE DocPosition SET
Price = CASE WHEN (ASPLN.ForeignCurrencyId IS NOT NULL AND D.DocCategoryId = 'Sales') OR (D.ForeignCurrencyId IS NOT NULL AND D.DocCategoryId = 'Purchase') THEN ROUND(DP.ForeignCurrencyPrice / COALESCE(NULLIF(@parxRate, 0), 1), 2) ELSE DP.Price END
, ForeignCurrencyPrice = CASE WHEN D.ForeignCurrencyId IS NOT NULL THEN CASE WHEN (ASPLN.ForeignCurrencyId IS NULL AND D.DocCategoryId = 'Sales') OR (D.ForeignCurrencyId IS NULL AND D.DocCategoryId = 'Purchase') THEN ROUND(DP.Price* COALESCE(NULLIF(@parxRate, 0), 1), 2) ELSE DP.ForeignCurrencyPrice END ELSE NULL END
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN ArticleSalesPriceListName ASPLN ON ASPLN.Id = D.PriceListId
WHERE D.Id = @parxDocId AND DP.PositionTypeId = 'Article';
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
