, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
END
ELSE BEGIN
UPDATE Doc SET ClerkId = NULL
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
END
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
