CREATE OR ALTER PROCEDURE 
xPROC200U_Doc_SalesPersonId
-- PURPOSE: Update the SalesPersonId with passed value and overwrite and update DocPositions
-- 26.06.26
@parxDocId INT,
@parxEmployeeId INT,
@parxSalesPersonId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
IF @parxSalesPersonId != -1 BEGIN
UPDATE Doc SET SalesPersonId = @parxSalesPersonId
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
END
ELSE BEGIN
UPDATE Doc SET SalesPersonId = NULL
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
END
UPDATE DocPosition SET
SalesPersonId = CASE WHEN @parxSalesPersonId = -1 THEN NULL ELSE @parxSalesPersonId END
, CommissionPercent = ISNULL(ECG.CommissionPercent,0)
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Employee E ON E.Id = @parxSalesPersonId
LEFT JOIN Article A ON A.Id = DP.ArticleId
LEFT JOIN Partner P ON P.Id = D.PartnerId
LEFT JOIN EmployeeCommissionGroupName ECGN ON ECGN.Id = E.CommissionGroupId
LEFT JOIN EmployeeCommissionGroup ECG ON ECG.CommissionGroupId = E.CommissionGroupId AND ((ECGN.PerArticleGroup = 0 OR ECG.ArticleGroupId = A.ArticleGroupId) AND (ECGN.PerPartnerGroup= 0 OR ECG.PartnerGroupId = P.PartnerGroupId))
WHERE DP.DocId = @parxDocId 
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
