CREATE OR ALTER PROCEDURE 
xPROC200U_Doc_DivergentInvoiceRecipientId
-- PURPOSE: Update the DivergentInvoiceRecipientId with passed value and change Doc Addresses
-- 26.06.26
@parxDocId INT,
@parxEmployeeId INT,
@parxDivergentInvoiceRecipientId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
IF @parxDivergentInvoiceRecipientId != -1 BEGIN
UPDATE Doc SET DivergentInvoiceRecipientId = @parxDivergentInvoiceRecipientId
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
END
ELSE BEGIN
UPDATE Doc SET DivergentInvoiceRecipientId = NULL
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
END
DECLARE @PartnerTypeId NVARCHAR(10)
SELECT
@PartnerTypeId = CASE DocCategoryId
WHEN  'Sales' THEN 'Customer'
WHEN 'Purchase' THEN 'Supplier'
ELSE 'Error'
END
FROM Doc
WHERE Id = @parxDocId
DECLARE @DivergentBillingAddressId INT
DECLARE @PartnerId INT
IF @parxDivergentInvoiceRecipientId != -1 BEGIN
SELECT
@DivergentBillingAddressId = StandardBillingAddressId
FROM PartnerDetail
WHERE PartnerId = @parxDivergentInvoiceRecipientId AND PartnerTypeId = @PartnerTypeId
END
ELSE BEGIN
SELECT
@PartnerId = PartnerId
FROM Doc
WHERE Id = @parxDocId
SELECT
@DivergentBillingAddressId = StandardBillingAddressId
FROM PartnerDetail
WHERE PartnerId = @PartnerId AND PartnerTypeId = @PartnerTypeId
END
IF EXISTS (SELECT 1 FROM DocBillingAddress WHERE DocId = @parxDocId)
BEGIN
UPDATE DocBillingAddress
SET
PartnerBillingAddressId = PBA.Id,
Matchcode = PBA.Matchcode,
Name1 = PBA.Name1,
Name2 = PBA.Name2,
Name3 = PBA.Name3,
Position = PBA.Position,
Title = PBA.Title,
Salutation = PBA.Salutation,
FirstName = PBA.FirstName,
LastName = PBA.LastName,
Street = PBA.Street,
Extension = PBA.Extension,
Zip = PBA.Zip,
City = PBA.City,
CountryId = PBA.CountryId,
Tel1 = PBA.Tel1,
Tel2 = PBA.Tel2,
Mobile = PBA.Mobile,
Fax = PBA.Fax,
Email = PBA.Email,
Homepage = PBA.Homepage,
Keyword = PBA.Keyword,
VatNumber = PBA.VatNumber,
TaxNumber = PBA.TaxNumber,
EInvoiceRoutingId= PBA.EInvoiceRoutingId
FROM PartnerBillingAddress AS PBA
WHERE
DocBillingAddress.DocId = @parxDocId AND
PBA.Id = @DivergentBillingAddressId;
END
ELSE
BEGIN
INSERT INTO DocBillingAddress (
DocId
, PartnerBillingAddressId
, Matchcode
, Name1
, Name2
, Name3
, Position
, Title
, Salutation
, FirstName
, LastName
, Street
, Extension
, Zip
, City
, CountryId
, Tel1
, Tel2
, Mobile
, Fax
, Email
, Homepage
, Keyword
, VatNumber
, TaxNumber
, EInvoiceRoutingId
)
SELECT
@parxDocId,
PBA.Id,
PBA.Matchcode,
PBA.Name1,
PBA.Name2,
PBA.Name3,
PBA.Position,
PBA.Title,
PBA.Salutation,
PBA.FirstName,
PBA.LastName,
PBA.Street,
PBA.Extension,
PBA.Zip,
PBA.City,
PBA.CountryId,
PBA.Tel1,
PBA.Tel2,
PBA.Mobile,
PBA.Fax,
PBA.Email,
PBA.Homepage,
PBA.Keyword,
PBA.VatNumber,
PBA.TaxNumber,
PBA.EInvoiceRoutingId
FROM PartnerBillingAddress AS PBA
WHERE PBA.Id = @DivergentBillingAddressId
END
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- xPROC201U_Doc_SaveDraftWarehousing ----------------------------------------------------------------------
-- PURPOSE: Process the Warehouse Transfer created by the passed Doc. Update Positions and Stock and set Doc.Draft to false
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 30.) DocPosition
-- 35.) DocPositionWarehousing
-- 40.) Doc
-- 50.) ArticleQuantity
-- 60.) WarehouseQuantity
-- 70.) ArticleIndividualizationQuantity
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC201U_Doc_SaveDraftWarehousing
-- 26.06.26 03:45
@parxDocId INT,
@parxReturnInvalidPositions BIT = 1
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
--From Doc
DECLARE @InventoryStatusId NVARCHAR(10);
DECLARE @WarehousingEffective INT;
SELECT
@InventoryStatusId = D.InventoryStatusId 
, @WarehousingEffective = D.WarehousingEffective 
FROM Doc D
WHERE D.Id = @parxDocId;
-- 20.) VALIDATION
DECLARE @InvalidDocPositions TABLE (WarehousingId INT, PositionNumber INT, ChildPositionNumber INT, DocPositionId INT, ArticleId NVARCHAR(30), TEXT NVARCHAR(100));
-- Einfügen der berechneten Werte in die temporäre Tabelle
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
MIN(W.Id) AS WarehousingId,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.PositionNumber) AS PositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.ChildPositionNumber) AS ChildPositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.Id) AS DocPositionId, -- Verwendet die erste DocPositionId für jede Gruppe
DP.ArticleId
, 'Insufficient warehousing stock available.'
FROM DocPositionWarehousing W
LEFT JOIN DocPosition DP ON DP.Id = W.DocPositionId
LEFT JOIN WarehouseQuantity WQ ON WQ.WarehouseId = W.WarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(W.BinLocationId,0) AND WQ.ArticleId = DP.ArticleId
WHERE DP.DocId = @parxDocId AND DP.Warehousing = 1
GROUP BY DP.ArticleId, W.WarehouseId, ISNULL(W.BinLocationId,0)
HAVING
(SUM(W.Quantity) > MAX(WQ.NowAvailable) AND @InventoryStatusId = 'confirmed') OR
(SUM(W.Quantity) > MAX(WQ.Stock) AND @WarehousingEffective = -1) OR
(MAX(WQ.NowAvailable) IS NULL AND @WarehousingEffective != 1)
-- Einfügen der berechneten Werte in die temporäre Tabelle
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
W.Id
, DP.PositionNumber
, DP.ChildPositionNumber
, DP.Id
, DP.ArticleId
, 'Quantity in position does not match quantity in warehousing.'
FROM DocPositionWarehousing W
LEFT JOIN DocPosition DP ON DP.Id = W.DocPositionId
LEFT JOIN (
SELECT
W.DocPositionId,
SUM(W.Quantity) AS TotalWarehousingQuantity
FROM DocPositionWarehousing W
GROUP BY W.DocPositionId
) AS WQ ON WQ.DocPositionId = DP.Id
WHERE DP.DocId = @parxDocId AND DP.Warehousing = 1
AND DP.Quantity != WQ.TotalWarehousingQuantity;
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
W.Id
, DP.PositionNumber
, DP.ChildPositionNumber
, DP.Id
, DP.ArticleId
, W.IndividualizationTypeId + ' Number is missing.'
FROM DocPositionWarehousing W
LEFT JOIN DocPosition DP ON DP.Id = W.DocPositionId
WHERE DP.DocId = @parxDocId AND W.IndividualizationTypeId != 'None' AND W.IndividualizationNumberId IS NULL ;
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
WDP.Id
, DP.PositionNumber
, DP.ChildPositionNumber
, DP.Id
, DP.ArticleId
, 'A Bin Location needs to be selected with the chosen Warehouse.'
FROM DocPositionWarehousing WDP
LEFT JOIN DocPosition DP ON DP.Id = WDP.DocPositionId
LEFT JOIN Warehouse W ON W.Id = WDP.WarehouseId
WHERE DP.DocId = @parxDocId AND W.BinLocation = 1 AND WDP.BinLocationId IS NULL ;
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
MIN(W.Id) AS WarehousingId,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.PositionNumber) AS PositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.ChildPositionNumber) AS ChildPositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.Id) AS DocPositionId, -- Verwendet die erste DocPositionId für jede Gruppe
MIN(DP.ArticleId)
, 'Insufficient warehousing stock available with this ' + MIN(W.IndividualizationTypeId) + ' Number.'
FROM DocPositionWarehousing W
LEFT JOIN DocPosition DP ON DP.Id = W.DocPositionId
LEFT JOIN Article A ON A.Id = DP.ArticleId
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.WarehouseId = W.WarehouseId AND ISNULL(AIQ.BinLocationId,0) = ISNULL(W.BinLocationId,0) AND AIQ.ArticleIndividualizationId = W.IndividualizationNumberId
WHERE DP.DocId = @parxDocId AND A.IndividualizationTypeId != 'None'
GROUP BY W.IndividualizationNumberId, W.WarehouseId, ISNULL(W.BinLocationId,0)
HAVING
(SUM(W.Quantity) > MAX(AIQ.NowAvailable) AND @InventoryStatusId = 'confirmed') OR
(SUM(W.Quantity) > MAX(AIQ.Stock) AND @WarehousingEffective = -1) OR
(MAX(AIQ.NowAvailable) IS NULL AND @WarehousingEffective != 1)
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
NULL
, DP.PositionNumber
, DP.ChildPositionNumber
, DP.Id
, DP.ArticleId
, 'Warehousing records are missing'
FROM DocPosition DP
LEFT JOIN DocPositionWarehousing W ON W.DocPositionId = DP.Id
LEFT JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.DocId = @parxDocId AND W.Id IS NULL AND DP.PositionTypeId = 'Article' AND DP.Warehousing = 1;
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
MIN(W.Id) AS WarehousingId,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.PositionNumber) AS PositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.ChildPositionNumber) AS ChildPositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(DP.Id) AS DocPositionId, -- Verwendet die erste DocPositionId für jede Gruppe
DP.ArticleId
, 'There is not enough packed Quantity for this process'
FROM DocPositionWarehousing W
LEFT JOIN DocPosition DP ON DP.Id = W.DocPositionId
LEFT JOIN WarehouseQuantity WQ ON WQ.WarehouseId = W.WarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(W.BinLocationId,0) AND WQ.ArticleId = DP.ArticleId
LEFT JOIN DocPosition PredecessorDP ON PredecessorDP.Id = DP.PredecessorId
LEFT JOIN Doc PredecessorD ON PredecessorD.Id = PredecessorDP.DocId
WHERE DP.DocId = @parxDocId AND PredecessorD.InventoryStatusId = 'packed' AND DP.Warehousing = 1
GROUP BY DP.ArticleId, W.WarehouseId, ISNULL(W.BinLocationId,0)
HAVING
(SUM(W.Quantity) > MAX(WQ.Packed) AND @WarehousingEffective = -1)
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
W.Id
, DP.PositionNumber
, DP.ChildPositionNumber
, DP.Id
, DP.ArticleId
, 'Serial Number exists more than once in this Doc.'
FROM DocPositionWarehousing W
JOIN DocPositionWarehousing DuplicateW ON W.IndividualizationNumberId = DuplicateW.IndividualizationNumberId AND W.Id != DuplicateW.Id
JOIN DocPosition DP ON DP.Id = W.DocPositionId
JOIN DocPosition DuplicateDP ON DuplicateDP.Id = DuplicateW.DocPositionId
WHERE DP.DocId = @parxDocId AND DuplicateDP.DocId = @parxDocId AND W.IndividualizationTypeId = 'Serial' ;
INSERT INTO @InvalidDocPositions (WarehousingId, PositionNumber, ChildPositionNumber, DocPositionId, ArticleId, TEXT)
SELECT
W.Id
, DP.PositionNumber
, DP.ChildPositionNumber
, DP.Id
, DP.ArticleId
, 'Serial Number is already on stock.'
FROM DocPositionWarehousing W
JOIN DocPosition DP ON DP.Id = W.DocPositionId
JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = W.IndividualizationNumberId 
LEFT JOIN Doc D ON D.Id = DP.DocId
WHERE DP.DocId = @parxDocId AND W.IndividualizationTypeId = 'Serial' AND AIQ.Stock != 0 AND D.WarehousingEffective = 1;
UPDATE DP
SET DP.Pending = 1 
FROM DocPosition DP
JOIN @InvalidDocPositions IDP ON DP.Id = IDP.DocPositionId;
IF (SELECT COUNT(*) FROM @InvalidDocPositions ) = 0 BEGIN
-- 30.) DocPosition
UPDATE DocPosition 
SET
WarehousingEffective = @WarehousingEffective
, Pending = 0
WHERE DocId = @parxDocId;
-- 35.) DocPositionWarehousing
UPDATE DocPositionWarehousing
SET
WarehousingEffective = @WarehousingEffective
FROM DocPositionWarehousing DPW
JOIN DocPosition DP ON DP.Id = DPW.DocPositionId
WHERE DP.DocId = @parxDocId;
-- 40.) Doc
UPDATE Doc
SET
DRAFT = 0
, InventoryStatusId = CASE WHEN InventoryStatusId = 'confirmed' THEN 'packed' ELSE InventoryStatusId END
WHERE Id = @parxDocId;
-- 50.) ArticleQuantity
;WITH cte AS
(
SELECT DP.ArticleId
, CASE WHEN DP.WarehousingEffective != 0 THEN AQ.Stock + SUM(DP.WarehousingQuantity) ELSE AQ.Stock END AS TotalQty
, MAX(DP.Id) DocPositionId
FROM DocPosition DP
JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN DocPosition PredecessorDP ON PredecessorDP.Id = DP.PredecessorId
LEFT JOIN Doc PredecessorD ON PredecessorD.Id = PredecessorDP.DocId
LEFT JOIN ArticleQuantity AQ ON AQ.ArticleId = DP.ArticleId
WHERE DP.DocId = @parxDocId
AND DP.PositionTypeId = 'Article'
AND DP.WarehousingEffective != 0
GROUP BY 
DP.ArticleId
, AQ.Stock
, DP.WarehousingEffective
)
UPDATE AQ
SET
Stock = cte.TotalQty
, DocPosition = cte.DocPositionId
, ProductionPosition = NULL
, InventoryCountingPosition = NULL
FROM ArticleQuantity AQ
JOIN cte ON AQ.ArticleId = cte.ArticleId
-- 60.) WarehouseQuantity
-- Sum Quantities
CREATE TABLE #SummedWarehouse
(
ArticleId NVARCHAR(30)
, WarehouseId INT
, BinLocationId INT
, SumQuantity DECIMAL(19,6)
, SumWarehousingQuantity DECIMAL(19,6)
);
INSERT INTO #SummedWarehouse
SELECT
DP.ArticleId
, W.WarehouseId
, ISNULL(W.BinLocationId,0)
, SUM(W.Quantity)
, SUM(W.Quantity) * @WarehousingEffective
FROM DocPosition DP
JOIN DocPositionWarehousing W ON W.DocPositionId = DP.Id
WHERE DP.DocId = @parxDocId
AND DP.PositionTypeId = 'Article'
GROUP BY
DP.ArticleId
, W.WarehouseId
, ISNULL(W.BinLocationId,0);
--INSERT MISSING WarehouseQuantity Records
INSERT INTO WarehouseQuantity(WarehouseId, ArticleId, BinLocationId)
SELECT
S.WarehouseId
, S.ArticleId
, NULLIF(ISNULL(S.BinLocationId, 0),0)
FROM #SummedWarehouse S
LEFT JOIN WarehouseQuantity WQ ON WQ.ArticleId = S.ArticleId AND WQ.WarehouseId = S.WarehouseId AND ISNULL(WQ.BinLocationId,0)=S.BinLocationId
WHERE WQ.ArticleId IS NULL;
--Update WarehouseQuantity Records
UPDATE WQ
SET Stock = CASE WHEN DP.WarehousingEffective != 0 THEN WQ.Stock + S.SumWarehousingQuantity ELSE WQ.Stock END
, Packed = CASE
WHEN D.InventoryStatusId = 'packed' THEN WQ.Packed + S.SumQuantity
WHEN PredecessorD.InventoryStatusId = 'packed' AND D.DocCategoryId = PredecessorD.DocCategoryId THEN WQ.Packed - S.SumQuantity
ELSE WQ.Packed
END
, DocPosition = DP.Id
, ProductionPosition = NULL
, InventoryCountingPosition = NULL
, TransferPosition = NULL
FROM WarehouseQuantity WQ
JOIN #SummedWarehouse S ON S.ArticleId = WQ.ArticleId AND S.WarehouseId = WQ.WarehouseId AND ISNULL(WQ.BinLocationId,0)=S.BinLocationId
JOIN DocPosition DP ON DP.ArticleId = S.ArticleId AND DP.DocId = @parxDocId
JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocPosition PredecessorDP ON PredecessorDP.Id = DP.PredecessorId
LEFT JOIN Doc PredecessorD ON PredecessorD.Id = PredecessorDP.DocId;
DROP TABLE #SummedWarehouse;
-- 70.) ArticleIndividualizationQuantity
-- Sum Quantities
CREATE TABLE #SummedAIQ
(
ArticleIndividualizationId NVARCHAR(30)
, WarehouseId INT
, BinLocationId INT
, SumQuantity DECIMAL(19,6)
, SumWarehousingQuantity DECIMAL(19,6)
);
INSERT INTO #SummedAIQ
SELECT
W.IndividualizationNumberId
, W.WarehouseId
, ISNULL(W.BinLocationId,0)
, SUM(W.Quantity)
, SUM(W.Quantity) * @WarehousingEffective
FROM DocPosition DP
JOIN DocPositionWarehousing W ON W.DocPositionId = DP.Id
JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.DocId = @parxDocId
AND DP.PositionTypeId = 'Article'
AND A.IndividualizationTypeId != 'None'
GROUP BY
W.IndividualizationNumberId
, W.WarehouseId
, ISNULL(W.BinLocationId,0);
--INSERT MISSING WarehouseQuantity Records
INSERT INTO ArticleIndividualizationQuantity
(
WarehouseId
, ArticleIndividualizationId
, BinLocationId
)
SELECT
S.WarehouseId
, S.ArticleIndividualizationId
, NULLIF(S.BinLocationId,0)
FROM #SummedAIQ S
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = S.ArticleIndividualizationId AND AIQ.WarehouseId = S.WarehouseId AND ISNULL(AIQ.BinLocationId,0)=S.BinLocationId
WHERE AIQ.ArticleIndividualizationId IS NULL;
--Update WarehouseQuantity Records
UPDATE AIQ
SET Stock = CASE WHEN DP.WarehousingEffective != 0 THEN AIQ.Stock + S.SumWarehousingQuantity ELSE AIQ.Stock END
, Packed = CASE
WHEN D.InventoryStatusId = 'packed' THEN AIQ.Packed + S.SumQuantity
WHEN PredecessorD.InventoryStatusId = 'packed' AND D.DocCategoryId = PredecessorD.DocCategoryId THEN AIQ.Packed - S.SumQuantity
ELSE AIQ.Packed
END
, DocPosition = DP.Id
, ProductionPosition = NULL
, InventoryCountingPosition = NULL
, TransferPosition = NULL
FROM ArticleIndividualizationQuantity AIQ
JOIN #SummedAIQ S ON S.ArticleIndividualizationId = AIQ.ArticleIndividualizationId AND S.WarehouseId = AIQ.WarehouseId AND ISNULL(AIQ.BinLocationId,0)=S.BinLocationId
JOIN DocPositionWarehousing W ON W.IndividualizationNumberId = AIQ.ArticleIndividualizationId AND W.WarehouseId = AIQ.WarehouseId AND ISNULL(W.BinLocationId,0)=S.BinLocationId
JOIN DocPosition DP ON DP.Id = W.DocPositionId AND DP.DocId = @parxDocId
JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocPosition PredecessorDP ON PredecessorDP.Id = DP.PredecessorId
LEFT JOIN Doc PredecessorD ON PredecessorD.Id = PredecessorDP.DocId;
DROP TABLE #SummedAIQ;
-- 90.) RETURN
-- RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidDocPositions) = 0 BEGIN
IF @parxReturnInvalidPositions = 1
BEGIN
SELECT * FROM @InvalidDocPositions 
END
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC201U_Doc_SaveDraftWarehousing ----------------------------------------------------------------------
-- xPROC201U_Doc_Unpack ----------------------------------------------------------------------
-- PURPOSE: Process the Warehouse Transfer created by the passed Doc. Update Positions and Stock and set Doc.Draft to false
-- USAGE:
-- 40.) Doc
-- 50.) ArticleQuantity
-- 60.) WarehouseQuantity
-- 70.) ArticleIndividualizationQuantity
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC201U_Doc_Unpack
-- 26.06.26 03:45
@parxDocId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 40.) Doc
UPDATE Doc
SET
DRAFT = 1
, InventoryStatusId = 'confirmed'
WHERE Id = @parxDocId;
-- 50.) ArticleQuantity
UPDATE AQ
SET
DocPosition = DP.Id
, ProductionPosition = NULL
, InventoryCountingPosition = NULL
FROM ArticleQuantity AQ
JOIN DocPosition DP ON AQ.ArticleId = DP.ArticleId
JOIN Doc D ON DP.DocId = D.Id
LEFT JOIN DocPosition PredecessorDP ON PredecessorDP.Id = DP.PredecessorId
LEFT JOIN Doc PredecessorD ON PredecessorD.Id = PredecessorDP.DocId
WHERE DP.DocId = @parxDocId
AND DP.PositionTypeId = 'Article';
-- 60.) WarehouseQuantity
-- Sum Quantities
CREATE TABLE #SummedWarehouse
(
ArticleId NVARCHAR(30)
, WarehouseId INT
, BinLocationId INT
, SumQuantity DECIMAL(19,6)
);
INSERT INTO #SummedWarehouse
SELECT
DP.ArticleId
, W.WarehouseId
, ISNULL(W.BinLocationId,0)
, SUM(W.Quantity)
FROM DocPosition DP
JOIN DocPositionWarehousing W ON W.DocPositionId = DP.Id
WHERE DP.DocId = @parxDocId
AND DP.PositionTypeId = 'Article'
GROUP BY
DP.ArticleId
, W.WarehouseId
, ISNULL(W.BinLocationId,0);
--Update WarehouseQuantity Records
UPDATE WQ
SET
Packed = WQ.Packed - S.SumQuantity
, DocPosition = DP.Id
, ProductionPosition = NULL
, InventoryCountingPosition = NULL
, TransferPosition = NULL
FROM WarehouseQuantity WQ
JOIN #SummedWarehouse S ON S.ArticleId = WQ.ArticleId AND S.WarehouseId = WQ.WarehouseId AND ISNULL(WQ.BinLocationId,0)=S.BinLocationId
JOIN DocPosition DP ON DP.ArticleId = S.ArticleId AND DP.DocId = @parxDocId
JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocPosition PredecessorDP ON PredecessorDP.Id = DP.PredecessorId
LEFT JOIN Doc PredecessorD ON PredecessorD.Id = PredecessorDP.DocId;
DROP TABLE #SummedWarehouse;
-- 70.) ArticleIndividualizationQuantity
-- Sum Quantities
CREATE TABLE #SummedAIQ
(
ArticleIndividualizationId NVARCHAR(30)
, WarehouseId INT
, BinLocationId INT
, SumQuantity DECIMAL(19,6)
);
INSERT INTO #SummedAIQ
SELECT
W.IndividualizationNumberId
, W.WarehouseId
, ISNULL(W.BinLocationId,0)
, SUM(W.Quantity)
FROM DocPosition DP
JOIN DocPositionWarehousing W ON W.DocPositionId = DP.Id
JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.DocId = @parxDocId
AND DP.PositionTypeId = 'Article'
AND A.IndividualizationTypeId != 'None'
GROUP BY
W.IndividualizationNumberId
, W.WarehouseId
, ISNULL(W.BinLocationId,0);
--Update WarehouseQuantity Records
UPDATE AIQ
SET
Packed = AIQ.Packed - S.SumQuantity
, DocPosition = DP.Id
, ProductionPosition = NULL
, InventoryCountingPosition = NULL
, TransferPosition = NULL
FROM ArticleIndividualizationQuantity AIQ
JOIN #SummedAIQ S ON S.ArticleIndividualizationId = AIQ.ArticleIndividualizationId AND S.WarehouseId = AIQ.WarehouseId AND ISNULL(AIQ.BinLocationId,0)=S.BinLocationId
JOIN DocPositionWarehousing W ON W.IndividualizationNumberId = AIQ.ArticleIndividualizationId AND W.WarehouseId = AIQ.WarehouseId AND ISNULL(W.BinLocationId,0)=S.BinLocationId
JOIN DocPosition DP ON DP.Id = W.DocPositionId AND DP.DocId = @parxDocId
JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocPosition PredecessorDP ON PredecessorDP.Id = DP.PredecessorId
LEFT JOIN Doc PredecessorD ON PredecessorD.Id = PredecessorDP.DocId;
DROP TABLE #SummedAIQ;
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC201U_Doc_Unpack ----------------------------------------------------------------------
-- xPROC202U_Doc_DocCloseManually ----------------------------------------------------------------------
-- Purpose: Set the Doc.StatusId to manually and update InventoryStatuses
-- 10.) DECLARE and SELECT InventoryStatusId
-- 21.) UPDATE Doc
-- 22.) UPDATE DocPosition
-- 90.) END TRANSACTION
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC202U_Doc_DocCloseManually
-- 26.06.26 03:46
@parxDocId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE and SELECT InventoryStatusId
DECLARE @InventoryStatusId NVARCHAR(10)
SELECT
@InventoryStatusId = InventoryStatusId
FROM Doc
WHERE Id = @parxDocId;
-- 21.) UPDATE Doc
UPDATE Doc
SET
StatusId = 'manually' 
WHERE Id = @parxDocId
-- 22.) UPDATE DocPosition
