-- xPROC206U_Doc_Posting ----------------------------------------------------------------------
-- Purpose: Create Posting and OpenItem and set Doc.PostingDate = GETDATE()
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) CREATE Posting (HEADER)
-- 30.) CREATE PostingPositions Sums (LINE1)
-- 40.) CREATE PostingPositions Net
-- 50.) CREATE PostingPositions Tax
-- 60.) CREATE PostingPositions EU-Tax
-- 65.) UPDATE LINE 1 with Conta Account
-- 70.) UPDATE Doc and DocPosition StatusId
-- 80.) CREATE FinanceOpenItem
-- 85.) UPDATE FinanceAccountPlan Balance
-- 86.) UPDATE PartnerDetail Balance
-- 87.) UPDATE DocXml
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC206U_Doc_Posting
@parxDocId INT,
@parxCreatedBy INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @InvalidValues TABLE (PositionNumber INT, TEXT NVARCHAR(100));
--FROM Doc
DECLARE @DocCategoryId NVARCHAR(10)
DECLARE @DocNumber NVARCHAR(20)
DECLARE @RevenueEffective INT = 0
DECLARE @PartnerId INT
DECLARE @PartnerDetailId INT
DECLARE @DocDate DATETIME
DECLARE @PostingPeriodId INT
DECLARE @YourDoc NVARCHAR(20)
DECLARE @YourDocDate DATETIME
DECLARE @DivergentInvoiceRecipientId INT
DECLARE @Subject NVARCHAR(100)
DECLARE @EuWork BIT
DECLARE @ForeignCurrencyId NVARCHAR(3)
DECLARE @Rate DECIMAL(19,6)
DECLARE @TermsOfPaymentId INT
DECLARE @DocTypeName NVARCHAR(50)
DECLARE @TotalPriceSumGross DECIMAL(19,6)
DECLARE @TotalPriceSumForeignCurrency DECIMAL(19,6)
DECLARE @TaxSumForeignCurrency DECIMAL(19,6)
DECLARE @TotalPriceSumGrossForeignCurrency DECIMAL(19,6)
SELECT
@DocCategoryId = D.DocCategoryId
, @DocNumber = D.DocNumber
, @RevenueEffective = D.RevenueEffective
, @PartnerId = D.PartnerId
, @PartnerDetailId = D.PartnerDetailId
, @DocDate = D.DocDate
, @PostingPeriodId = D.PostingPeriodId
, @YourDoc = D.YourDoc
, @YourDocDate = D.YourDocDate
, @DivergentInvoiceRecipientId = D.DivergentInvoiceRecipientId
, @Subject = D.Subject
, @EuWork = D.EuWork
, @ForeignCurrencyId = D.ForeignCurrencyId
, @Rate = D.Rate
, @TermsOfPaymentId = D.TermsOfPaymentId
, @TotalPriceSumGross = D.TotalPriceSumGross 
, @TotalPriceSumForeignCurrency = D.TotalPriceSumForeignCurrency 
, @TaxSumForeignCurrency = D.TaxSumForeignCurrency 
, @TotalPriceSumGrossForeignCurrency = D.TotalPriceSumGrossForeignCurrency 
, @DocTypeName = DT.Name
FROM xVIEW_Doc D
JOIN DocType DT ON DT.Id = D.DocTypeId
WHERE D.Id = @parxDocId
-- FROM DocBillingAddress
DECLARE @VatNumber NVARCHAR(20)
SELECT
@VatNumber = VatNumber
FROM DocBillingAddress
WHERE DocId = @parxDocId
-- FROM Partner
DECLARE @Matchcode NVARCHAR(50)
SELECT
@Matchcode = Matchcode
FROM Partner
WHERE (Id = @PartnerId AND @DivergentInvoiceRecipientId IS NULL) OR Id = @DivergentInvoiceRecipientId
-- FROM PartnerDetail
DECLARE @PartnerTypeId NVARCHAR(10)
DECLARE @BusinessPartnerNumber INT
DECLARE @FinanceGroupPartnerDetailId INT
DECLARE @DivergentPartnerDetailId INT
SELECT
@PartnerTypeId = PartnerTypeId
, @BusinessPartnerNumber = Id
, @FinanceGroupPartnerDetailId = FinanceGroupPartnerDetailId
, @DivergentPartnerDetailId = CASE WHEN @DivergentInvoiceRecipientId IS NULL THEN NULL ELSE Id END
FROM PartnerDetail
WHERE (Id = @PartnerDetailId AND @DivergentInvoiceRecipientId IS NULL) OR (PartnerId = @DivergentInvoiceRecipientId AND PartnerTypeId = 'Customer')
-- FROM FinanceGroupPartner
DECLARE @CollectiveAccountId INT
SELECT
@CollectiveAccountId = CollectiveAccountId
FROM FinanceGroupPartner
WHERE Id = @FinanceGroupPartnerDetailId
-- FROM AdminCompanySetting
DECLARE @CompanyCurrencyId NVARCHAR(3)
SELECT
@CompanyCurrencyId = CompanyCurrencyId
FROM AdminCompanySetting
WHERE Id = 1
-- 15.) CREATE PostingPositions Net
-- Temporäre Tabelle erstellen
CREATE TABLE #TempCTE (
DocId INT
, RowNumber INT
, PositionNumber INT
, TotalPrice DECIMAL(19, 6)
, TaxKeyId NVARCHAR(3)
, TaxPercent DECIMAL(19, 6)
, Tax DECIMAL(19, 6)
, AccountId INT
, CostCenterId INT
, CostBearerId INT
, ProjectId INT
, AccountName NVARCHAR(200)
, TaxAccountId INT
, TaxAccountName NVARCHAR(200)
, NotDueAccountId INT
, NotDueAccountName NVARCHAR(200)
, TotalPriceForeignCurrency DECIMAL(19, 6)
, TaxForeignCurrency DECIMAL(19, 6)
);
-- Ergebnisse der CTE in die temporäre Tabelle einfügen
INSERT INTO #TempCTE (DocId, RowNumber, PositionNumber,TotalPrice, TaxKeyId, TaxPercent, Tax, AccountId, CostCenterId, CostBearerId, ProjectId, AccountName, TaxAccountId, TaxAccountName, NotDueAccountId, NotDueAccountName, TotalPriceForeignCurrency, TaxForeignCurrency )
SELECT
DP.DocId
, DP.RowNumber
, DP.PositionNumber 
, DP.TotalPrice
, DP.TaxKeyId
, DP.TaxPercent
, DP.Tax
, DP.AccountId
, DP.CostCenterId
, DP.CostBearerId
, DP.ProjectId
, FAP.Name AS AccountName
, FTKD.TaxAccountId
, FAPT.Name AS TaxAccountName
, FTKD.NotDueAccountId 
, FAPN.Name AS NotDueAccountName
, DP.TotalPriceForeignCurrency
, DP.TaxForeignCurrency 
FROM xVIEW_DocPosition DP
LEFT JOIN FinanceAccountPlan FAP ON DP.AccountId = FAP.Id
LEFT JOIN FinanceTaxKeyDetail FTKD ON DP.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= @DocDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
WHERE DP.DocId = @parxDocId
AND DP.PositionTypeId = 'Article'
AND (FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= @DocDate
) OR DP.TaxKeyId IS NULL);
INSERT INTO @InvalidValues(PositionNumber, TEXT)
SELECT
TC.PositionNumber
, 'This position is missing an assigned Account'
FROM #TempCTE TC
WHERE TC.AccountId IS NULL
INSERT INTO @InvalidValues(PositionNumber, TEXT)
SELECT
NULL
, 'This period cannot be posted.'
FROM FinancePostingPeriod
WHERE Id = @PostingPeriodId AND StatusId != 'open'
IF @PostingPeriodId IS NULL BEGIN
INSERT INTO @InvalidValues(PositionNumber, TEXT)
SELECT
NULL
, 'Posting Period is missing'
END
DECLARE @SumTotalPrice DECIMAL(19,6);
SELECT @SumTotalPrice = SUM(TotalPrice) FROM #TempCTE;
DECLARE @SumTax DECIMAL(19,6);
SELECT @SumTax = ROUND(SUM(Tax),2) FROM #TempCTE;
IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
IF @TotalPriceSumGross != 0 BEGIN
-- 20.) CREATE Posting (HEADER)
INSERT INTO FinancePosting
(
Name
, DocNumber
, StatusId
, DateCreated
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, BatchNumber
, SourceId
, ForeignCurrencyId
, Rate
, CreatedBy
)
-- VALUES FinancePosting
VALUES
(
@DocTypeName
, @DocNumber
, 'valid'
, sysutcdatetime()
, CASE WHEN @DocCategoryId = 'Sales' THEN @DocNumber ELSE @YourDoc END
, CASE WHEN @DocCategoryId = 'Sales' THEN @DocDate ELSE @YourDocDate END
, @PostingPeriodId
, ISNULL(NULLIF(LTRIM(RTRIM(@Subject)), ''), '-')
, 0
, @DocCategoryId
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN @ForeignCurrencyId ELSE NULL END
, CASE WHEN @Rate IS NOT NULL THEN @Rate ELSE NULL END
, @parxCreatedBy
)
DECLARE @newxPostingId INT = SCOPE_IDENTITY();
-- 30.) CREATE PostingPositions Sums (LINE1)
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber 
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
)
-- VALUES FinancePostingPosition
VALUES
(
@newxPostingId
, 1
, NULL
, 'valid'
, NULL
, @CollectiveAccountId
, CASE WHEN @DocCategoryId = 'Sales' THEN 2 ELSE 3 END
, @Matchcode
, NULL
, CASE WHEN @RevenueEffective = 1 THEN @TotalPriceSumGross ELSE 0 END
, CASE WHEN @RevenueEffective = -1 THEN @TotalPriceSumGross ELSE 0 END
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, @TotalPriceSumGross * @RevenueEffective
, @VatNumber
, NULL
, CASE WHEN @DivergentPartnerDetailId IS NULL THEN @PartnerDetailId ELSE @DivergentPartnerDetailId END
, @BusinessPartnerNumber 
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = 1 THEN @TotalPriceSumGrossForeignCurrency ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = -1 THEN @TotalPriceSumGrossForeignCurrency ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN @TotalPriceSumGrossForeignCurrency * @RevenueEffective ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, 0
)
-- Erster INSERT für Nettowerte
INSERT INTO FinancePostingPosition (
PostingId
, Position
, ParentPosition
, StatusId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, Debit
, Credit
, ContraAccountId
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, ProjectId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
)
SELECT
@newxPostingId
, 1 + ROW_NUMBER() OVER (ORDER BY (MIN(RowNumber)))
, NULL
, 'valid'
, AccountId
, 1
, AccountName
, CASE WHEN @RevenueEffective = -1 THEN SUM(TotalPrice) ELSE 0 END
, CASE WHEN @RevenueEffective = 1 THEN SUM(TotalPrice) ELSE 0 END
, @CollectiveAccountId
, TaxKeyId
, TaxPercent
, CASE WHEN FTK.TaxKeyKindId != 3 THEN ROUND(SUM(Tax),2) ELSE ROUND((SUM(TotalPrice) * TaxPercent)/100,2) END
, CostCenterId
, CostBearerId
, SUM(TotalPrice) * @RevenueEffective * -1
, ProjectId
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = -1 THEN SUM(TotalPriceForeignCurrency) ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = 1 THEN SUM(TotalPriceForeignCurrency) ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN SUM(TotalPriceForeignCurrency) * @RevenueEffective * -1 ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTK.TaxKeyKindId != 3 THEN ROUND(SUM(TaxForeignCurrency),2) ELSE ROUND((SUM(TotalPriceForeignCurrency) * TaxPercent)/100,2) END ELSE NULL END
, 0
FROM #TempCTE CTE
LEFT JOIN FinanceTaxKey FTK ON CTE.TaxKeyId= FTK.Id
GROUP BY AccountId, ProjectId, TaxKeyId, TaxPercent, CostCenterId, CostBearerId, AccountName, FTK.TaxKeyKindId;
DECLARE @MaxPosition INT
SELECT TOP 1
@MaxPosition = Position
FROM FinancePostingPosition
WHERE PostingId = @newxPostingId
ORDER BY Id desc
-- Zweiter INSERT für Steuerwerte
INSERT INTO FinancePostingPosition (
PostingId
, Position
, ParentPosition
, StatusId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, Debit
, Credit
, ContraAccountId
, TaxKeyId
, TaxPercent
, CostCenterId
, CostBearerId
, OpenAmount
, ProjectId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyOpenAmount
, Archived
)
SELECT
@newxPostingId
, @MaxPosition + ROW_NUMBER() OVER (ORDER BY FBP.Id)
, FBP.Id
, 'valid'
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FTKD.TaxAccountId ELSE FTKD.NotDueAccountId END
, 1
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FAPT.Name ELSE FAPN.Name END
, CASE WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId != 3 THEN FBP.TaxAmount WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.Debit * FBP.TaxPercent)/100,2) ELSE 0 END
, CASE WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId != 3 THEN FBP.TaxAmount WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.Credit * FBP.TaxPercent)/100,2) ELSE 0 END
, FirstFBP.AccountId
, NULL
, NULL
, NULL
, NULL
, CASE WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId != 3 THEN FBP.TaxAmount WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.Debit * FBP.TaxPercent)/100,2) ELSE 0 END - CASE WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId != 3 THEN FBP.TaxAmount WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.Credit * FBP.TaxPercent)/100,2) ELSE 0 END
, FBP.ProjectId
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId != 3 THEN FBP.ForeignCurrencyTaxAmount WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.ForeignCurrencyDebit * FBP.TaxPercent)/100,2) ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId != 3 THEN FBP.ForeignCurrencyTaxAmount WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.ForeignCurrencyCredit * FBP.TaxPercent)/100,2) ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId != 3 THEN FBP.ForeignCurrencyTaxAmount WHEN @RevenueEffective = -1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.ForeignCurrencyDebit * FBP.TaxPercent)/100,2) ELSE 0 END - CASE WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId != 3 THEN FBP.ForeignCurrencyTaxAmount WHEN @RevenueEffective = 1 AND FTK.TaxKeyKindId = 3 THEN ROUND((FBP.ForeignCurrencyCredit * FBP.TaxPercent)/100,2) ELSE 0 END ELSE NULL END
, 0
FROM dbo.FinancePostingPosition FBP
LEFT JOIN FinanceAccountPlan FAP ON FBP.AccountId = FAP.Id
LEFT JOIN FinanceTaxKeyDetail FTKD ON FBP.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= @DocDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
LEFT JOIN FinancePostingPosition FirstFBP ON FirstFBP.PostingId = @newxPostingId AND FirstFBP.Position = 1
WHERE FBP.TaxKeyId IS NOT NULL AND FBP.PostingId = @newxPostingId
AND (FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= @DocDate
));
SELECT TOP 1
@MaxPosition = Position
FROM FinancePostingPosition
WHERE PostingId = @newxPostingId
ORDER BY Id desc
-- Dritter INSERT für ErwerbsSteuerwerte
INSERT INTO FinancePostingPosition (
PostingId
, Position
, ParentPosition
, StatusId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, Debit
, Credit
, ContraAccountId
, TaxKeyId
, TaxPercent
, CostCenterId
, CostBearerId
, OpenAmount
, ProjectId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyOpenAmount
, Archived
)
SELECT
@newxPostingId
, @MaxPosition + ROW_NUMBER() OVER (ORDER BY FBP.Id)
, FBP.Id
, 'valid'
, FTKD.TaxAccountId
, 1
, FAPT.Name
, CASE WHEN @RevenueEffective = 1 THEN ROUND((FBP.Credit * FBP.TaxPercent)/100,2) ELSE 0 END
, CASE WHEN @RevenueEffective = -1 THEN ROUND((FBP.Debit * FBP.TaxPercent)/100,2) ELSE 0 END
, FBP.AccountId
, NULL
, NULL
, NULL
, NULL
, CASE WHEN @RevenueEffective = 1 THEN ROUND((FBP.Credit * FBP.TaxPercent)/100,2) ELSE 0 END - CASE WHEN @RevenueEffective = -1 THEN ROUND((FBP.Debit * FBP.TaxPercent)/100,2) ELSE 0 END
, FBP.ProjectId
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = 1 THEN ROUND((FBP.ForeignCurrencyCredit * FBP.TaxPercent)/100,2) ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = -1 THEN ROUND((FBP.ForeignCurrencyDebit * FBP.TaxPercent)/100,2) ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @RevenueEffective = 1 THEN ROUND((FBP.ForeignCurrencyCredit * FBP.TaxPercent)/100,2) ELSE 0 END - CASE WHEN @RevenueEffective = -1 THEN ROUND((FBP.ForeignCurrencyDebit * FBP.TaxPercent)/100,2) ELSE 0 END ELSE NULL END
, 0
FROM dbo.FinancePostingPosition FBP
LEFT JOIN FinanceAccountPlan FAP ON FBP.AccountId = FAP.Id
LEFT JOIN FinanceTaxKeyDetail FTKD ON FBP.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= @DocDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
LEFT JOIN FinancePostingPosition FirstFBP ON FirstFBP.PostingId = @newxPostingId AND FirstFBP.Position = 1
WHERE FBP.TaxKeyId IS NOT NULL AND FBP.PostingId = @newxPostingId AND FTK.TaxKeyKindId = 3
AND FTKD.ValidFrom = (
SELECT
MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FBP.TaxKeyId
AND ValidFrom <= @DocDate);
-- 65.) UPDATE LINE 1 with Conta Account
UPDATE FBP
SET ContraAccountId = InsertedFBP.AccountId
FROM FinancePostingPosition FBP
LEFT JOIN FinancePostingPosition InsertedFBP
ON InsertedFBP.ContraAccountId = @CollectiveAccountId
AND InsertedFBP.PostingId = @newxPostingId
WHERE FBP.PostingId = @newxPostingId
AND FBP.Position = 1;
END --IF @TotalPriceSumGross != 0 BEGIN
-- 70.) UPDATE Doc and DocPosition StatusId
UPDATE Doc SET PostingDate = GETDATE() WHERE Id = @parxDocId
-- 80.) CREATE FinanceOpenItem
IF @TotalPriceSumGross != 0 BEGIN
INSERT INTO FinanceOpenItem (
StatusId
, OpenItemOriginId
, OpenItemTypeId
, DocTypeId
, PartnerTypeId
, PartnerId
, PartnerDetailId
, PostingId
, PostingDate
, DocDate
, DocNumber
, Amount
, ForeignCurrencyId
, Rate
, Discountable
, DueDate
, CashDiscountDate1
, CashDiscountPercentage1
, CashDiscountDate2
, CashDiscountPercentage2
, CashDiscountAmount
, OpenAmount
, Remark1
, Remark2
, ReferenceDoc
, ContraAccountId
, CostCenterId
, CostBearerId
, DunningBlock
, PaymentBlock
, DunningLevelId
, TaxSplit
, DocSplit
, TermsOfPaymentId
, Archived
, ProbabilityOfPayment
, ForeignCurrencyAmount
, ForeignCurrencyCashDiscountAmount
, ForeignCurrencyOpenAmount
)
SELECT
'open'
, D.DocCategoryId
, CASE WHEN D.DocCategoryId = 'Sales' AND D.RevenueEffective = 1 THEN 'CI' WHEN D.DocCategoryId = 'Sales' AND D.RevenueEffective = -1 THEN 'CC' WHEN D.DocCategoryId = 'Purchase' AND D.RevenueEffective = -1 THEN 'SI' WHEN D.DocCategoryId = 'Purchase' AND D.RevenueEffective = 1 THEN 'SC' ELSE 'ERROR' END
, D.DocTypeId
, PD.PartnerTypeId
, CASE WHEN @DivergentInvoiceRecipientId IS NULL THEN @PartnerId ELSE @DivergentInvoiceRecipientId END
, CASE WHEN @DivergentPartnerDetailId IS NULL THEN @PartnerDetailId ELSE @DivergentPartnerDetailId END
, @newxPostingId
, GETDATE()
, Case
WHEN D.DocCategoryId = 'Sales' THEN D.DocDate
WHEN D.DocCategoryId = 'Purchase' THEN D.YourDocDate
ELSE NULL
END
, D.DocNumber
, D.TotalPriceSumGross * D.RevenueEffective
, CASE WHEN D.ForeignCurrencyId IS NOT NULL THEN D.ForeignCurrencyId ELSE NULL END
, D.Rate
, 1
, CASE WHEN D.DocCategoryId = 'Sales' THEN DATEADD(Day, PTOP.DaysUntilDue, D.DocDate) WHEN D.DocCategoryId = 'Purchase' THEN DATEADD(Day, PTOP.DaysUntilDue, D.YourDocDate) ELSE NULL END
, CASE WHEN D.DocCategoryId = 'Sales' AND PTOP.CashDiscountPercentage1 IS NOT NULL THEN DATEADD(Day, PTOP.CashDiscountDays1, D.DocDate)  WHEN D.DocCategoryId = 'Purchase' AND PTOP.CashDiscountPercentage1 IS NOT NULL THEN DATEADD(Day, PTOP.CashDiscountDays1, D.YourDocDate) ELSE NULL END
, PTOP.CashDiscountPercentage1
, CASE WHEN D.DocCategoryId = 'Sales' AND PTOP.CashDiscountPercentage2 IS NOT NULL THEN DATEADD(Day, PTOP.CashDiscountDays2, D.DocDate) WHEN D.DocCategoryId = 'Purchase' AND PTOP.CashDiscountPercentage2 IS NOT NULL THEN DATEADD(Day, PTOP.CashDiscountDays2, D.YourDocDate) ELSE NULL END
, PTOP.CashDiscountPercentage2
, 0
, D.TotalPriceSumGross * D.RevenueEffective
, D.DocNumber
, NULL
, Case
WHEN D.DocCategoryId = 'Sales' THEN D.DocNumber
WHEN D.DocCategoryId = 'Purchase' THEN D.YourDoc
ELSE NULL
END
, NULL
, NULL
, NULL
, 0
, 0
, NULL
, NULL
, NULL
, D.TermsOfPaymentId
, 0
, 100
, CASE WHEN D.ForeignCurrencyId IS NOT NULL THEN D.TotalPriceSumGrossForeignCurrency * D.RevenueEffective ELSE NULL END
, CASE WHEN D.ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN D.ForeignCurrencyId IS NOT NULL THEN D.TotalPriceSumGrossForeignCurrency * D.RevenueEffective ELSE NULL END
FROM xVIEW_Doc AS D
JOIN PartnerDetail AS PD ON D.PartnerDetailId = PD.Id
JOIN DocType AS DT ON D.DocTypeId = DT.Id
JOIN PartnerTermsOfPayment AS PTOP ON D.TermsOfPaymentId = PTOP.Id
LEFT JOIN PartnerDetail DivergentPD ON DivergentPD.Id = @DivergentPartnerDetailId
WHERE D.Id= @parxDocId;
-- 85.) UPDATE FinanceAccountPlan Balance
UPDATE FAP SET
FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, FAP.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL THEN ISNULL(FAP.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT AccountId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition
WHERE PostingId = @newxPostingId
GROUP BY AccountId
) AS FBP ON FBP.AccountId= FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 86.) UPDATE PartnerDetail Balance
UPDATE PD SET
PD.Balance = PD.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, PD.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL THEN ISNULL(PD.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM PartnerDetail PD
INNER JOIN (
SELECT PartnerDetailId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition
WHERE PostingId = @newxPostingId
GROUP BY PartnerDetailId
) AS FBP ON FBP.PartnerDetailId = PD.Id
WHERE FBP.PartnerDetailId IS NOT NULL;
END --IF @TotalPriceSumGross != 0 BEGIN
-- 87.) UPDATE DocXml
UPDATE DocXml
SET
PostingDate = GETDATE()
WHERE DocId = @parxDocId
DECLARE @DebitSum DECIMAL(19,6) = 0
DECLARE @CreditSum DECIMAL(19,6) = 0
SELECT
@DebitSum = ISNULL(SUM(Debit), 0)
, @CreditSum = ISNULL(SUM(Credit), 0)
FROM FinancePostingPosition
WHERE PostingId = @newxPostingId
END -- IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
IF @DebitSum <> @CreditSum
BEGIN
ROLLBACK TRANSACTION
INSERT INTO @InvalidValues(PositionNumber, TEXT)
SELECT
0
, 'SYSTEM ERROR: Debit does not equal Credit'
RETURN;
END
SELECT * FROM @InvalidValues
IF OBJECT_ID('tempdb..#TempCTE') IS NOT NULL DROP TABLE #TempCTE;
COMMIT;
END TRY
BEGIN CATCH
IF @@TRANCOUNT > 0 ROLLBACK;
THROW;
END CATCH
END;
GO
-------------- END xPROC206U_Doc_Posting------------------------------------------
