CREATE OR ALTER PROCEDURE 
xPROC207U_Doc_ApprovalRequired
-- PURPOSE: Update the ApprovalRequired with passed value
-- 26.06.26
@parxDocId INT,
@parxEmployeeId INT,
@parxApprovalRequired BIT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE Doc SET ApprovalRequired = @parxApprovalRequired
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @parxDocId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
