-- xPROC217_Doc_TransferFromPreviousDoc ----------------------------------------------------------------------
-- Purpose: Insert passed positions into Doc and update Sums and Predecessor
-- 10.) DECLARE, SELECT, CALCULATE
-- 29.) CREATE new Transfer Text Position (INSERT, SELECT)
-- 30.) CREATE new Doc Positions and CALCULATE DocPosition Sums (INSERT, SELECT)
-- 32.) CREATE new DocPosition Texts (INSERT, SELECT)
-- 33.) CREATE new Warehousing (INSERT, SELECT)
-- 34.) UPDATE PackingListBox
-- 50.) UPDATE Predecessor.DocPositions QuantityOpen = 0 and StatusId = 'closed'
-- 51.) UPDATE Predecessor.Doc.StatusId to 'closed', 'manually', 'partially' or 'Error'
-- 80.) CALCULATE and Update ArticleQuantity Sums
-- 85.) xPROC200U_Doc_CostPrice
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE
xPROC217_Doc_TransferFromPreviousDoc
-- 26.06.26 03:46
@parxDocId INT,
@parxDocPositionIds NVARCHAR(MAX),
@parxEmployeeId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
-- 10.1 FROM Doc
DECLARE @DocCategoryId NVARCHAR(10)
DECLARE @RevenueEffective INT
DECLARE @InventoryStatusId NVARCHAR(10)
DECLARE @WarehousingEffective INT
DECLARE @Draft BIT
DECLARE @Rate DECIMAL(19,6)
SELECT
@DocCategoryId = DocCategoryId
, @RevenueEffective = RevenueEffective
, @InventoryStatusId = InventoryStatusId
, @WarehousingEffective = WarehousingEffective 
, @Draft = Draft
, @Rate = Rate 
FROM Doc
WHERE Id = @parxDocId
-- Temporäre Tabelle zum Speichern der IDs
CREATE TABLE #ForPositionInsert (Id INT);
CREATE TABLE #KeepPredecessorPositionIds (Id INT);
-- String mit IDs in die temporäre Tabelle zerlegen
DECLARE @Xml AS XML;
SET @Xml = CAST(('<root><r>' + REPLACE(@parxDocPositionIds , ',', '</r><r>') + '</r></root>') AS XML);
INSERT INTO #ForPositionInsert 
SELECT r.value('.', 'INT') AS Id
FROM @Xml.nodes('//root/r') AS records(r);
INSERT INTO #KeepPredecessorPositionIds
SELECT r.value('.', 'INT') AS Id
FROM @Xml.nodes('//root/r') AS records(r);
-- Variablen für die WHILE-Schleife
DECLARE @TotalRows INT = (SELECT COUNT(*) FROM #ForPositionInsert);
DECLARE @CurrentRow INT = 1;
DECLARE @CurrentId INT;
-- WHILE-Schleife zur Iteration durch die IDs
WHILE @CurrentRow <= @TotalRows
BEGIN
SELECT TOP 1 @CurrentId = Id
FROM #ForPositionInsert
ORDER BY Id ASC;
-- 29.) CREATE new Transfer Text Position (INSERT, SELECT)
DECLARE @LastDocId INT
DECLARE @DocId INT
SELECT
@DocId = DocId 
FROM DocPosition WHERE Id = @CurrentId
DECLARE @calxNewRowNumber INT
SELECT 
@calxNewRowNumber = ISNULL(MAX(RowNumber), 0) + 1 
FROM DocPosition 
WHERE DocId = @parxDocId;
IF ((@DocId IS NULL OR @LastDocId IS NULL) OR (@DocId != @LastDocId)) BEGIN
DECLARE @DocNumber NVARCHAR(20)
SELECT
@DocNumber = DocNumber 
FROM Doc WHERE Id = @DocId
DECLARE @TextFromTransfer NVARCHAR(MAX)
SELECT
@TextFromTransfer = TextContent
FROM TextBlock WHERE Id = 'Transfer'
DECLARE @TransferText NVARCHAR(MAX)
SET @TransferText = CONCAT(@TextFromTransfer, @DocNumber)
INSERT INTO DocPosition
(
DocId
, RowNumber
,PositionTypeId
,PositionNumber
,ParentPositionId
,ChildPositionNumber
,StatusId
,ArticleId
,Name1
,Name2
,Quantity
,QuantityOpen
,UoMId
,ShippingDate
,DeliveryDate
,Price
,PredecessorId
,QuantityTransferred
,Level
,PositionLabel
,CatalogNumberId
,Dissolve
,PositionWeight
,ProjectId
,Start
,Stop
,PriceUnitId
,ArticleCostPrice
,DiscountPercent
,QuantityDiscountPercent
,DocDiscountPercent
,RevenueEffective
,SalesPersonId
,CommissionPercent
,FinanceGroupArticleId
,FinanceGroupPartnerDetailId
,TaxKeyId
,TaxPercent
,AccountId
,CostCenterId
,CostBearerId
,Warehousing
,WarehousingEffective
)
-- VALUES DocPosition
VALUES
(
@parxDocId
, @calxNewRowNumber
, 'Auto'
, 0
, NULL
, NULL
, 'Text'
, NULL
, 'Transfer' 
, @TransferText
, 0
, 0
, NULL
, GETDATE()
, GETDATE()
, 0
, NULL
, 0
, NULL
, CONCAT(@DocId, '-',0)
, NULL
, 0
, 0
, NULL
, NULL
, NULL
, 1
, 0
, 0
, 0
, 0
, 0
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, NULL
)
SET @calxNewRowNumber = @calxNewRowNumber+ 1
END -- IF @DocId != @LastDocId BEGIN
SET @LastDocId = @DocId
-- 30.) CREATE new Doc Positions (INSERT, SELECT)
INSERT INTO DocPosition (
[DocId]
, RowNumber
,[PositionTypeId]
,[PositionNumber]
,[ParentPositionId]
, ChildPositionNumber
,[StatusId]
,[ArticleId]
,[Name1]
,[Name2]
,[Quantity]
,[QuantityOpen]
,[UoMId]
,[ShippingDate]
,[DeliveryDate]
,[Price]
, ForeignCurrencyPrice 
,[PredecessorId]
,[QuantityTransferred]
,[Level]
,[PositionLabel]
,[CatalogNumberId]
,[Dissolve]
,[PositionWeight]
,[ProjectId]
,[Start]
,[Stop]
,[PriceUnitId]
,[ArticleCostPrice]
,[DiscountPercent]
,[QuantityDiscountPercent]
,[DocDiscountPercent]
, PrepaymentFactor
,[RevenueEffective]
,[SalesPersonId]
,[CommissionPercent]
, ProfitFactor
, CostPriceFactor
,[FinanceGroupArticleId]
,[FinanceGroupPartnerDetailId]
,[TaxKeyId]
, TaxFactor
,[TaxPercent]
,[AccountId]
,[CostCenterId]
,[CostBearerId]
,[Warehousing]
,[WarehousingEffective]
)
SELECT
@parxDocId
, @calxNewRowNumber + ISNULL(ChildPositionNumber,0)
, PositionTypeId
, PositionNumber
, ParentPositionId
, ChildPositionNumber
, CASE WHEN DP.StatusId = 'Text' THEN 'Text' ELSE 'open' END
, DP.ArticleId
, DP.Name1
, DP.Name2
, QuantityOpen
, QuantityOpen
, DP.UoMId
, DP.ShippingDate
, DP.DeliveryDate
, CASE WHEN (ASPLN.ForeignCurrencyId IS NOT NULL AND D.DocCategoryId = 'Sales') OR (D.ForeignCurrencyId IS NOT NULL AND D.DocCategoryId = 'Purchase') THEN CASE WHEN D.Rate IS NULL OR D.Rate = 0 OR DP.ForeignCurrencyPrice IS NULL THEN 0 ELSE ROUND(DP.ForeignCurrencyPrice / NULLIF(@Rate, 0), 2) END ELSE DP.Price END
, CASE WHEN (ASPLN.ForeignCurrencyId IS NULL AND D.DocCategoryId = 'Sales') OR (D.ForeignCurrencyId IS NULL AND D.DocCategoryId = 'Purchase') THEN CASE WHEN D.Rate IS NULL OR D.Rate = 0 THEN 0 ELSE ROUND(DP.Price * @Rate, 2) END ELSE ISNULL(DP.ForeignCurrencyPrice, 0) END
, DP.Id
, QuantityOpen
, Level
, CONCAT(DocId, '-', DP.Id)
, CatalogNumberId
, Dissolve
, QuantityOpen* A.Weight
, DP.ProjectId
, Start
, Stop
, DP.PriceUnitId
, ISNULL(APC.CostPrice,0) / A.PriceUnitId
, DiscountPercent
, QuantityDiscountPercent
, DP.DocDiscountPercent
, CASE WHEN A.IsPrepayment = 1 THEN DT.PrepaymentTrueArticleFactor ELSE DT.PrepaymentFalseArticleFactor END
, @RevenueEffective
, DP.SalesPersonId
, CommissionPercent
, CASE WHEN A.IsPrepayment = 1 THEN 0 ELSE 1 END
, CASE WHEN DT.DocCategoryId= 'Purchase'  THEN 0 ELSE 1 END
, FinanceGroupArticleId
, FinanceGroupPartnerDetailId
, TaxKeyId
, CASE WHEN FTK.TaxKeyKindId = 3 THEN 0 ELSE 1 END
, TaxPercent
, AccountId
, CostCenterId
, CostBearerId
, DP.Warehousing
, 0
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocType DT ON DT.Id = D.DocTypeId
LEFT JOIN Article A ON DP.ArticleId = A.Id
LEFT JOIN ArticlePriceCalculation APC ON DP.ArticleId = APC.ArticleId
LEFT JOIN ArticleSalesPriceListName ASPLN ON ASPLN.Id = D.PriceListId
LEFT JOIN FinanceTaxKey FTK ON DP.TaxKeyId = FTK.Id
WHERE DP.Id = @CurrentId AND DP.PositionTypeId != 'Auto'
DECLARE @newxDocPositionId INT;
SET @newxDocPositionId = SCOPE_IDENTITY()
-- 30b.) UPDATE DocPosition with Extra Fields from predecessor DocPosition
DECLARE @ExtraFieldDocPositionSetList nvarchar(max);
DECLARE @ExtraFieldDocPositionUpdateSql nvarchar(max);
SELECT
@ExtraFieldDocPositionSetList = STRING_AGG(
CAST(
CONCAT(
N'TargetDP.'
, QUOTENAME(TargetColumn.name)
, N' = SourceDP.'
, QUOTENAME(SourceColumn.name)
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM dbo.ExtraField AS TargetExtraField
JOIN dbo.ExtraField AS SourceExtraField
ON SourceExtraField.Name = TargetExtraField.Name
AND SourceExtraField.SystemTableId = N'DocPosition'
JOIN sys.columns AS TargetColumn
ON TargetColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND TargetColumn.name = TargetExtraField.Id
JOIN sys.columns AS SourceColumn
ON SourceColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND SourceColumn.name = SourceExtraField.Id
WHERE TargetExtraField.SystemTableId = N'DocPosition'
AND TargetExtraField.Id LIKE N'XX%'
AND SourceExtraField.Id LIKE N'XX%'
AND TargetColumn.is_computed = 0
AND SourceColumn.is_computed = 0;
IF @ExtraFieldDocPositionSetList IS NOT NULL
BEGIN
SET @ExtraFieldDocPositionUpdateSql = CONCAT(
N'UPDATE TargetDP
SET '
, @ExtraFieldDocPositionSetList
, N'
FROM dbo.DocPosition AS TargetDP
JOIN dbo.DocPosition AS SourceDP
ON SourceDP.Id = @SourceDocPositionId
WHERE TargetDP.Id = @TargetDocPositionId;'
);
EXEC sys.sp_executesql
@ExtraFieldDocPositionUpdateSql
, N'@SourceDocPositionId int, @TargetDocPositionId int'
, @SourceDocPositionId = @CurrentId
, @TargetDocPositionId = @newxDocPositionId;
END
-- 30a.) UPDATE DocPosition ParentPositionId 
UPDATE DP
SET
ParentPositionId = DPNewParent.Id
FROM DocPosition DP
LEFT JOIN DocPosition DPNewParent ON DPNewParent.PredecessorId = DP.ParentPositionId AND DP.DocId = DPNewParent.DocId
WHERE DP.Id = @newxDocPositionId
-- 32.) INSERT DocPosition Texts
INSERT INTO DocPositionInfoText (DocPositionId, InfoText)
SELECT @newxDocPositionId, InfoText FROM DocPositionInfoText WHERE DocPositionInfoText.DocPositionId = @CurrentId
INSERT INTO DocPositionOrderText (DocPositionId, OrderText)
SELECT @newxDocPositionId, OrderText FROM DocPositionOrderText WHERE DocPositionOrderText.DocPositionId = @CurrentId
INSERT INTO DocPositionDimensionText (DocPositionId, DimensionText)
SELECT @newxDocPositionId, DimensionText FROM DocPositionDimensionText WHERE DocPositionDimensionText.DocPositionId = @CurrentId
-- 33.) CREATE new Warehousing (INSERT, SELECT)
IF (@Draft = 1) BEGIN
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
@newxDocPositionId
, W.WarehouseId
, W.BinLocationId
, W.IndividualizationTypeId
, W.IndividualizationNumberId
, W.Quantity
, 0
FROM DocPositionWarehousing W
JOIN DocPosition DP ON DP.Id = W.DocPositionId
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Article A ON A.Id = DP.ArticleId
WHERE A.Warehousing = 1 AND DP.Id = @CurrentId AND D.WarehousingEffective = 0
IF NOT EXISTS(SELECT 1 FROM DocPositionWarehousing WHERE DocPositionId = @newxDocPositionId) BEGIN
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
@newxDocPositionId
, CASE WHEN D.StandardWarehouseId IS NOT NULL THEN D.StandardWarehouseId ELSE A.StandardWarehouseId END
, NULL
, A.IndividualizationTypeId
, NULL
, CASE WHEN A.IndividualizationTypeId = 'Serial' THEN 1 ELSE DP.Quantity END
, 0
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.Id = @newxDocPositionId AND DP.Warehousing = 1
END -- IF NOT EXISTS(SELECT 1 FROM Warehousing WHERE DocPositionId = newxDocPositionId) BEGIN
-- 34.) UPDATE PackingListBox
UPDATE PackingListBox SET 
DeliveryNoteDocId = @parxDocId
WHERE PickingListDocId = @DocId
END -- IF (@Draft = 1) BEGIN
-- DELETE processed Id
DELETE FROM #ForPositionInsert WHERE Id = @CurrentId;
-- Next Row
SET @CurrentRow = @CurrentRow + 1;
END
-- DROP #ForPositionInsert
DROP TABLE #ForPositionInsert;
-- 50.) UPDATE Predecessor.DocPositions QuantityOpen = 0 and StatusId = 'closed'
UPDATE DocPosition
SET QuantityOpen = 0, StatusId = 'closed'
WHERE Id IN (SELECT PredecessorId FROM DocPosition WHERE DocId = @parxDocId AND DocPosition.PredecessorId IN (SELECT Id FROM #KeepPredecessorPositionIds));
-- 51.) UPDATE Predecessor.Doc.StatusId to 'closed', 'manually' or 'partially'
-- CTE, um die Doc-IDs zu ermitteln, die aktualisiert werden sollen
WITH DocIdsToUpdate AS (
SELECT DISTINCT predecessor.DocId
FROM DocPosition DP
INNER JOIN DocPosition predecessor ON DP.PredecessorId = predecessor.Id
INNER JOIN Doc PredecessorD ON predecessor.DocId = PredecessorD.Id
WHERE DP.DocId = @parxDocId AND PredecessorD.StatusId IN ('open', 'partially') AND DP.PredecessorId IN (SELECT Id FROM #KeepPredecessorPositionIds)
)
-- Aktualisierung der Doc.StatusId basierend auf den StatusId der zugehörigen Positionen
UPDATE Doc
SET StatusId =
CASE
WHEN EXISTS (
SELECT 1
FROM DocPosition
WHERE DocId = Doc.Id AND StatusId IN ('open', 'partially') AND PositionTypeId = 'Article'
) THEN 'partially'
WHEN NOT EXISTS (
SELECT 1
FROM DocPosition
WHERE DocId = Doc.Id AND StatusId NOT IN ('closed', 'manually') AND PositionTypeId = 'Article'
) AND EXISTS (
SELECT 1
FROM DocPosition
WHERE DocId = Doc.Id AND StatusId = 'manually' AND PositionTypeId = 'Article'
) THEN 'manually'
WHEN NOT EXISTS (
SELECT 1
FROM DocPosition
WHERE DocId = Doc.Id AND StatusId != 'closed' AND PositionTypeId = 'Article'
) THEN 'closed'
ELSE 'Error'
END
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id IN (SELECT DocId FROM DocIdsToUpdate);
-- 80.) CALCULATE and UPDATE ArticleQuantity Sums IF (@PredecessorInventoryStatusId != @InventoryStatusId)
DECLARE @PredecessorInventoryStatusId NVARCHAR(10)
SELECT TOP 1 
@PredecessorInventoryStatusId = D2.InventoryStatusId
FROM DocPosition AS DP1
JOIN DocPosition AS DP2 ON DP1.PredecessorId = DP2.Id
JOIN Doc AS D2 ON DP2.DocId = D2.Id
WHERE DP1.DocId = @parxDocId
AND DP1.PositionTypeId = 'Article' AND DP1.PredecessorId IN (SELECT Id FROM #KeepPredecessorPositionIds);
-- DROP #KeepPredecessorPositionIds
DROP TABLE #KeepPredecessorPositionIds;
-- 85.) xPROC200U_Doc_CostPrice
EXEC xPROC200U_Doc_CostPrice
@parxDocId = @parxDocId 
, @parxEmployeeId = @parxEmployeeId
-- 90.) RETURN
SELECT @parxDocId AS DocId
-- 91.) ERROR HANDLING
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC217_Doc_TransferFromPreviousDoc ----------------------------------------------------------------------
-- xPROC218_Doc_TransferToNextDoc ----------------------------------------------------------------------
-- Purpose: Create Doc of selected DocType and Transfer Positions of selected Doc to new Doc
-- 10.) DECLARE and SELECT
-- 20.) CREATE new Doc (INSERT, SELECT)
-- 21.) CREATE new Doc Texts (INSERT, SELECT)
-- 22.) CREATE new Doc Delivery Address (INSERT, SELECT) 
-- 23.) CREATE new Doc Billing Address (INSERT, SELECT) 
-- 29.) CREATE new Transfer Text Position (INSERT, SELECT)
-- 30.) CREATE new Doc Positions (INSERT, SELECT)
-- 30a.) UPDATE DocPosition ParentPositionId 
-- 31.) INSERT DocPosition Texts
-- 32.) INSERT Warehousing
-- 50.) UPDATE Predecessor.DocPositions QuantityOpen = 0 and StatusId = 'closed'
-- 51.) UPDATE Predecessor.Doc.StatusId to 'closed'
-- 52.) UPDATE PackingListBox
-- 60.) Create DocContract record
-- 85.) xPROC200U_Doc_CostPrice
-- 86.) xPROC201U_Doc_SaveDraftWarehousing if InventoryStatusId has been switched to packed
-- 90.) RETURN
-------------------------------------------------------------------------------------------------------------
