CREATE OR ALTER PROCEDURE
xPROC218_Doc_TransferToNextDoc
-- 26.06.26 03:45
@parxFromDocId INT,
@parxToDocTypeId NVARCHAR(35),
@parxEmployeeId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE and SELECT
-- 0 DECLARE FROM parameter
DECLARE @locxFromDocId INT = @parxFromDocId
DECLARE @locxToDocTypeId NVARCHAR(35) = @parxToDocTypeId
-- Generate new DocNumber
DECLARE @SQLString NVARCHAR(100)
DECLARE @ParmDefinition NVARCHAR(75)
DECLARE @NextNumber NVARCHAR(10)
DECLARE @newxDocNumber NVARCHAR(20)
DECLARE @DocNumberPrefix NVARCHAR(3)
DECLARE @WarehousingEffective INT
DECLARE @InventoryStatusId NVARCHAR(10)
DECLARE @IsContract BIT
-- FROM DocType
SELECT
@DocNumberPrefix = DocNumberPrefix
, @WarehousingEffective = WarehousingEffective 
, @InventoryStatusId = InventoryStatusId 
, @IsContract = IsContract 
FROM DocType
WHERE Id = @locxToDocTypeId
--Generate new DocNumber
CREATE TABLE #DocNumberResult (NewDocumentNumber NVARCHAR(30));
-- Aufruf der Prozedur und speichere den Rückgabewert in der temporären Tabelle
INSERT INTO #DocNumberResult
EXEC dbo.xPROC200_GenerateNewDocNumber
@DocTypeId = @locxToDocTypeId  -- Übergabe des DocTypeId
-- Zuweisung des Wertes aus der temporären Tabelle in die Variable @newxDocNumber
SELECT @newxDocNumber = NewDocumentNumber
FROM #DocNumberResult;
-- 3 FROM FinancePostingPeriod
DECLARE @CurrentPostingPeriodId INT;
SET @CurrentPostingPeriodId = dbo.xFUNCTION001_GetCurrentPostingPeriodId();
-- 20.) CREATE new Doc (INSERT, SELECT)
INSERT INTO Doc (
DocNumber
, DocCategoryId
, DocTypeId
, InventoryStatusId
, WarehousingEffective
, RevenueEffective
, PartnerId
, PartnerDetailId
, StatusId
, Draft
, DocDate
, PostingPeriodId
, ShippingDate
, DeliveryDate
, PartnerContactPersonId
, ClerkId
, SalesPersonId
, OurReference
, YourDoc
, YourDocDate
, InternalRemark
, Subject
, Version
, DivergentInvoiceRecipientId
, TermsOfDeliveryId
, EuWork
, LanguageId
, ReportTemplateId
, TermsOfPaymentId
, ProjectId
, PriceListId
, DocDiscountPercent
, DownPaymentSum
, ForeignCurrencyId
, Rate
, OutputControlFormatId
, CreatedBy
, ModifiedBy
)
SELECT
@newxDocNumber
, DT.DocCategoryId
, @locxToDocTypeId
, DT.InventoryStatusId
, DT.WarehousingEffective
, DT.RevenueEffective
, PartnerId
, D.PartnerDetailId
, 'open'
, DT.Draft
, GETDATE()
, CASE WHEN DT.RevenueEffective != 0 THEN @CurrentPostingPeriodId ELSE NULL END
, ShippingDate
, DeliveryDate
, PartnerContactPersonId
, ClerkId
, SalesPersonId
, OurReference
, YourDoc
, YourDocDate
, InternalRemark
, Subject
, '1'
, DivergentInvoiceRecipientId
, TermsOfDeliveryId
, EuWork
, LanguageId
, PDO.ReportTemplateId
, TermsOfPaymentId
, ProjectId
, PriceListId
, DocDiscountPercent
, DownPaymentSum
, ForeignCurrencyId
, Rate
, PDO.OutputControlFormatId
, @parxEmployeeId
, @parxEmployeeId
FROM Doc D
JOIN DocType DT ON @locxToDocTypeId = DT.Id
LEFT JOIN PartnerDetailOutput PDO ON PDO.PartnerDetailId = D.PartnerDetailId AND PDO.DocTypeId = DT.Id
WHERE D.Id = @locxFromDocId
DECLARE @newxDocId INT;
SET @newxDocId = SCOPE_IDENTITY();
-- 20a.) UPDATE Doc with Extra Fields from predecessor Doc
DECLARE @ExtraFieldDocSetList nvarchar(max);
DECLARE @ExtraFieldDocUpdateSql nvarchar(max);
SELECT
@ExtraFieldDocSetList = STRING_AGG(
CAST(
CONCAT(
N'TargetD.'
, QUOTENAME(TargetColumn.name)
, N' = SourceD.'
, QUOTENAME(SourceColumn.name)
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM dbo.ExtraField AS TargetExtraField
JOIN dbo.ExtraField AS SourceExtraField
ON SourceExtraField.Name = TargetExtraField.Name
AND SourceExtraField.SystemTableId = N'Doc'
JOIN sys.columns AS TargetColumn
ON TargetColumn.object_id = OBJECT_ID(N'dbo.Doc')
AND TargetColumn.name = TargetExtraField.Id
JOIN sys.columns AS SourceColumn
ON SourceColumn.object_id = OBJECT_ID(N'dbo.Doc')
AND SourceColumn.name = SourceExtraField.Id
WHERE TargetExtraField.SystemTableId = N'Doc'
AND TargetExtraField.Id LIKE N'XX%'
AND SourceExtraField.Id LIKE N'XX%'
AND TargetColumn.is_computed = 0
AND SourceColumn.is_computed = 0;
IF @ExtraFieldDocSetList IS NOT NULL
BEGIN
SET @ExtraFieldDocUpdateSql = CONCAT(
N'UPDATE TargetD
SET '
, @ExtraFieldDocSetList
, N'
FROM dbo.Doc AS TargetD
JOIN dbo.Doc AS SourceD
ON SourceD.Id = @SourceDocId
WHERE TargetD.Id = @TargetDocId;'
);
EXEC sys.sp_executesql
@ExtraFieldDocUpdateSql
, N'@SourceDocId int, @TargetDocId int'
, @SourceDocId = @locxFromDocId
, @TargetDocId = @newxDocId;
END
-- 21.) CREATE new Doc Texts (INSERT, SELECT)
-- Header
INSERT INTO DocHeaderText (DocId,Header)
SELECT @newxDocId,[Header] FROM DocHeaderText WHERE DocId = @locxFromDocId
-- Footer
INSERT INTO DocFooterText (DocId,Footer)
SELECT @newxDocId,[Footer] FROM DocFooterText WHERE DocId = @locxFromDocId
-- 22.) CREATE new Doc Delivery Address (INSERT, SELECT) 
INSERT INTO DocDeliveryAddress (DocId, PartnerDeliveryAddressId, Matchcode, Name1, Name2, Name3, Position, Title, Salutation, FirstName, LastName, Street, Extension, Zip, City, CountryId, Tel1, Tel2, Mobile, Fax, Email, Homepage, Keyword, VatNumber, TaxNumber, ShippingZoneId)
SELECT @newxDocId,  PartnerDeliveryAddressId, Matchcode, Name1, Name2, Name3, Position, Title, Salutation, FirstName, LastName, Street, Extension, Zip, City, CountryId, Tel1, Tel2, Mobile, Fax, Email, Homepage, Keyword, VatNumber, TaxNumber, ShippingZoneId FROM DocDeliveryAddress WHERE DocId = @locxFromDocId
-- 23.) CREATE new Doc Billing Address (INSERT, SELECT) 
INSERT INTO DocBillingAddress (DocId, PartnerBillingAddressId, Matchcode, Name1, Name2, Name3, Position, Title, Salutation, FirstName, LastName, Street, Extension, Zip, City, CountryId, Tel1, Tel2, Mobile, Fax, Email, Homepage, Keyword, VatNumber, TaxNumber, EInvoiceRoutingId)
SELECT @newxDocId,  PartnerBillingAddressId, Matchcode, Name1, Name2, Name3, Position, Title, Salutation, FirstName, LastName, Street, Extension, Zip, City, CountryId, Tel1, Tel2, Mobile, Fax, Email, Homepage, Keyword, VatNumber, TaxNumber, EInvoiceRoutingId FROM DocBillingAddress WHERE DocId = @locxFromDocId
-- 29.) CREATE new Transfer Text Position (INSERT, SELECT)
DECLARE @TextFromTransfer NVARCHAR(MAX)
SELECT
@TextFromTransfer = TextContent
FROM TextBlock WHERE Id = 'Transfer'
DECLARE @DocNumber NVARCHAR(20)
DECLARE @FromDocInventoryStatusId NVARCHAR(10)
SELECT
@DocNumber = DocNumber 
, @FromDocInventoryStatusId = InventoryStatusId
FROM Doc WHERE Id = @parxFromDocId
DECLARE @TransferText NVARCHAR(MAX)
SET @TransferText = CONCAT(@TextFromTransfer, @DocNumber)
INSERT INTO DocPosition
(
DocId
, RowNumber
,PositionTypeId
,PositionNumber
,ParentPositionId
,ChildPositionNumber
,StatusId
,ArticleId
,Name1
,Name2
,Quantity
,QuantityOpen
,UoMId
,ShippingDate
,DeliveryDate
,Price
,PredecessorId
,QuantityTransferred
,Level
,PositionLabel
,CatalogNumberId
,Dissolve
,PositionWeight
,ProjectId
,Start
,Stop
,PriceUnitId
,ArticleCostPrice
,DiscountPercent
,QuantityDiscountPercent
,DocDiscountPercent
,RevenueEffective
,SalesPersonId
,CommissionPercent
,FinanceGroupArticleId
,FinanceGroupPartnerDetailId
,TaxKeyId
,TaxPercent
,AccountId
,CostCenterId
,CostBearerId
,Warehousing
,WarehousingEffective
)
-- VALUES DocPosition
VALUES
(
@newxDocId
, 1
, 'Auto'
, 0
, NULL
, NULL
, 'Text'
, NULL
, 'Transfer' 
, @TransferText
, 0
, 0
, NULL
, GETDATE()
, GETDATE()
, 0
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, 0
, NULL
, NULL
, NULL
, 1
, 0
, 0
, 0
, 0
, 0
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, NULL
)
DECLARE @newxDocPositionId INT = SCOPE_IDENTITY();
INSERT INTO DocPositionInfoText (DocPositionId, InfoText)
VALUES (@newxDocPositionId, @TransferText)
-- 30.) CREATE new Doc Positions (INSERT, SELECT)
INSERT INTO DocPosition (
[DocId]
, RowNumber
,[PositionTypeId]
,[PositionNumber]
,[ParentPositionId]
,[ChildPositionNumber]
,[StatusId]
,[ArticleId]
,[Name1]
,[Name2]
,[Quantity]
,[QuantityOpen]
,[UoMId]
,[ShippingDate]
,[DeliveryDate]
,[Price]
, ForeignCurrencyPrice 
,[PredecessorId]
,[QuantityTransferred]
,[Level]
,[PositionLabel]
,[CatalogNumberId]
,[Dissolve]
,[PositionWeight]
,[ProjectId]
,[Start]
,[Stop]
,[PriceUnitId]
,[ArticleCostPrice]
,[DiscountPercent]
,[QuantityDiscountPercent]
,[DocDiscountPercent]
, PrepaymentFactor
,[RevenueEffective]
,[SalesPersonId]
,[CommissionPercent]
, ProfitFactor
, CostPriceFactor
,[FinanceGroupArticleId]
,[FinanceGroupPartnerDetailId]
,[TaxKeyId]
, TaxFactor
,[TaxPercent]
,[AccountId]
,[CostCenterId]
,[CostBearerId]
,[Warehousing]
,[WarehousingEffective]
)
-- Select from predecessor Doc Position ----------------------
SELECT
@newxDocId
, DP.RowNumber + 1
, DP.PositionTypeId
, DP.PositionNumber
, DP.ParentPositionId
, DP.ChildPositionNumber
, CASE WHEN DP.StatusId = 'Text' THEN 'Text' ELSE 'open' END
, DP.ArticleId
, DP.Name1
, DP.Name2
, DP.QuantityOpen
, DP.QuantityOpen
, DP.UoMId
, DP.ShippingDate
, DP.DeliveryDate
, DP.Price
, DP.ForeignCurrencyPrice 
, DP.Id
, DP.QuantityOpen
, DP.Level
, DP.PositionLabel
, DP.CatalogNumberId
, DP.Dissolve
, DP.QuantityOpen * A.Weight
, DP.ProjectId
, NULL
, NULL
, DP.PriceUnitId
, ISNULL(APC.CostPrice,0) / A.PriceUnitId
, DP.DiscountPercent
, DP.QuantityDiscountPercent
, DP.DocDiscountPercent
, CASE WHEN A.IsPrepayment = 1 THEN DT_ToDoc.PrepaymentTrueArticleFactor ELSE DT_ToDoc.PrepaymentFalseArticleFactor END
, DT_ToDoc.RevenueEffective
, DP.SalesPersonId
, DP.CommissionPercent
, CASE WHEN A.IsPrepayment = 1 THEN 0 ELSE 1 END
, CASE WHEN DT_ToDoc.DocCategoryId= 'Purchase'  THEN 0 ELSE 1 END
, DP.FinanceGroupArticleId
, DP.FinanceGroupPartnerDetailId
, DP.TaxKeyId
, CASE WHEN FTK.TaxKeyKindId = 3 THEN 0 ELSE 1 END
, DP.TaxPercent
, DP.AccountId
, DP.CostCenterId
, DP.CostBearerId
, DP.Warehousing
, 0
FROM DocPosition DP
JOIN Doc ON DP.DocId = Doc.Id
JOIN DocType DT ON Doc.DocTypeId = DT.Id
LEFT JOIN Article A ON DP.ArticleId = A.Id  -- Geändert zu LEFT JOIN
LEFT JOIN ArticlePriceCalculation APC ON DP.ArticleId = APC.ArticleId
LEFT JOIN FinanceTaxKey FTK ON DP.TaxKeyId = FTK.Id
LEFT JOIN DocType AS DT_ToDoc ON DT_ToDoc.Id = @locxToDocTypeId
WHERE DP.DocId = @locxFromDocId AND ((DP.QuantityOpen != 0 AND DP.PositionTypeId <> 'Rejected') OR DP.PositionTypeId = 'Text') AND DP.PositionTypeId != 'Auto'
-- 30a.) UPDATE DocPosition ParentPositionId 
UPDATE DP
SET
ParentPositionId = DPNewParent.Id
FROM DocPosition DP
LEFT JOIN DocPosition DPNewParent ON DPNewParent.PredecessorId = DP.ParentPositionId AND DPNewParent.DocId = @newxDocId
WHERE DP.DocId = @newxDocId
-- 30b.) UPDATE DocPosition with Extra Fields from predecessor DocPosition
DECLARE @ExtraFieldDocPositionSetList nvarchar(max);
DECLARE @ExtraFieldDocPositionUpdateSql nvarchar(max);
SELECT
@ExtraFieldDocPositionSetList = STRING_AGG(
CAST(
CONCAT(
N'TargetDP.'
, QUOTENAME(TargetColumn.name)
, N' = SourceDP.'
, QUOTENAME(SourceColumn.name)
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM dbo.ExtraField AS TargetExtraField
JOIN dbo.ExtraField AS SourceExtraField
ON SourceExtraField.Name = TargetExtraField.Name
AND SourceExtraField.SystemTableId = N'DocPosition'
JOIN sys.columns AS TargetColumn
ON TargetColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND TargetColumn.name = TargetExtraField.Id
JOIN sys.columns AS SourceColumn
ON SourceColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND SourceColumn.name = SourceExtraField.Id
WHERE TargetExtraField.SystemTableId = N'DocPosition'
AND TargetExtraField.Id LIKE N'XX%'
AND SourceExtraField.Id LIKE N'XX%'
AND TargetColumn.is_computed = 0
AND SourceColumn.is_computed = 0;
IF @ExtraFieldDocPositionSetList IS NOT NULL
BEGIN
SET @ExtraFieldDocPositionUpdateSql = CONCAT(
N'UPDATE TargetDP
SET '
, @ExtraFieldDocPositionSetList
, N'
FROM dbo.DocPosition AS TargetDP
JOIN dbo.DocPosition AS SourceDP
ON SourceDP.Id = TargetDP.PredecessorId
WHERE TargetDP.DocId = @TargetDocId
AND TargetDP.PredecessorId IS NOT NULL;'
);
EXEC sys.sp_executesql
@ExtraFieldDocPositionUpdateSql
, N'@TargetDocId int'
, @TargetDocId = @newxDocId;
END
-- 31.) INSERT DocPosition Texts
DECLARE @NewDocPositionIds TABLE (
Id INT
);
INSERT INTO @NewDocPositionIds (
Id
)
SELECT Id
From DocPosition 
WHERE DocId = @newxDocId;
INSERT INTO DocPositionInfoText (DocPositionId, InfoText)
SELECT N.Id, D.InfoText
FROM @NewDocPositionIds N
JOIN DocPosition DP ON DP.Id = N.Id
JOIN DocPositionInfoText D ON D.DocPositionId = DP.PredecessorId;
INSERT INTO DocPositionOrderText (DocPositionId, OrderText)
SELECT N.Id, D.OrderText
FROM @NewDocPositionIds N
JOIN DocPosition DP ON DP.Id = N.Id
JOIN DocPositionOrderText D ON D.DocPositionId = DP.PredecessorId;
INSERT INTO DocPositionDimensionText (DocPositionId, DimensionText)
SELECT N.Id, D.DimensionText
FROM @NewDocPositionIds N
JOIN DocPosition DP ON DP.Id = N.Id
JOIN DocPositionDimensionText D ON D.DocPositionId = DP.PredecessorId;
-- 32.) INSERT Warehousing
DECLARE @Draft BIT
SELECT
@Draft = Draft 
FROM Doc
WHERE Id = @newxDocId;
IF (@Draft = 1) BEGIN
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
NewDP.Id
, W.WarehouseId
, W.BinLocationId
, W.IndividualizationTypeId
, W.IndividualizationNumberId
, W.Quantity
, 0
FROM DocPositionWarehousing W
LEFT JOIN DocPosition DP ON DP.Id = W.DocPositionId
LEFT JOIN DocPosition NewDP ON NewDP.PredecessorId = DP.Id
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Article A ON A.Id = DP.ArticleId
WHERE A.Warehousing = 1 AND DP.DocId = @parxFromDocId AND D.WarehousingEffective = 0 AND NewDP.Id IS NOT NULL
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
N.Id
, CASE WHEN D.StandardWarehouseId IS NOT NULL THEN D.StandardWarehouseId ELSE A.StandardWarehouseId END
, NULL
, A.IndividualizationTypeId
, NULL
, CASE WHEN A.IndividualizationTypeId = 'Serial' THEN 1 ELSE DP.Quantity END
, 0
FROM @NewDocPositionIds N
JOIN DocPosition DP ON DP.Id = N.Id
JOIN Doc D ON D.Id = DP.DocId
JOIN Article A ON A.Id = DP.ArticleId
LEFT JOIN DocPositionWarehousing W ON W.DocPositionId = DP.Id
WHERE W.Id IS NULL AND DP.Warehousing = 1
END -- IF (@WarehousingEffective != 0) BEGIN
-- 50.) UPDATE Predecessor.DocPositions QuantityOpen = 0 and StatusId = 'closed'
UPDATE [dbo].[DocPosition] SET [QuantityOpen] = 0, [StatusId] = 'closed' WHERE [DocId] = @locxFromDocId AND [StatusId] IN ('open', 'partially')
-- 51.) UPDATE Predecessor.Doc.StatusId to 'closed'
UPDATE Doc
SET StatusId = CASE
WHEN EXISTS (
SELECT 1
FROM DocPosition
WHERE DocId = @locxFromDocId
AND StatusId = 'manually'
) THEN 'manually'
ELSE 'closed'
END
, ModifiedBy = @parxEmployeeId
, DateModified = SYSDATETIMEOFFSET() AT TIME ZONE 'UTC'
WHERE Id = @locxFromDocId;
-- 52.) UPDATE PackingListBox
UPDATE PackingListBox SET 
DeliveryNoteDocId = @newxDocId
WHERE PickingListDocId = @locxFromDocId
-- 60.) Create DocContract record
IF (@IsContract = 1)
BEGIN
INSERT INTO DocContract
(
DocId
, TargetDocTypeId
, StartDate
, EndDate
, CyclePeriodId
, NextAppointment
, StatusId
, Prepayment
, CycleQuantity
, ExecutedCycles
)
VALUES
(
@newxDocId
, NULL
, GETDATE()
, GETDATE()
, NULL
, NULL
, 'DRAFT'
, 1
, 0
, 0
);
END
-- 85.) xPROC200U_Doc_CostPrice
EXEC xPROC200U_Doc_CostPrice
@parxDocId = @newxDocId
, @parxEmployeeId = @parxEmployeeId
-- 86.) xPROC201U_Doc_SaveDraftWarehousing if InventoryStatusId has been switched to packed
DECLARE @xPROC201U_Doc_SaveDraftWarehousingReturn INT;
IF(@FromDocInventoryStatusId = 'packed' AND @WarehousingEffective = -1) BEGIN
EXEC @xPROC201U_Doc_SaveDraftWarehousingReturn = xPROC201U_Doc_SaveDraftWarehousing
@parxDocId = @newxDocId
, @parxReturnInvalidPositions = 0
END
SELECT @newxDocId AS ToDocId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC218_Doc_TransferToNextDoc ----------------------------------------------------------------------
-- xPROC219_Doc_TransferToPurchase ----------------------------------------------------------------------
-- Purpose: Create Purchase Doc and Insert selected Positions. Then Update Sums
-- 10.) DECLARE and SELECT
-- 20.) CREATE new Doc (INSERT, SELECT)
-- 21.) CREATE new Doc Texts (INSERT, SELECT)
-- 22.) CREATE new Doc Delivery Address (INSERT, SELECT) 
-- 23.) CREATE new Doc Billing Address (INSERT, SELECT) 
-- 30.) CREATE new Doc Positions (INSERT, SELECT)
-- 32.) CREATE new DocPosition Texts (INSERT, SELECT)
-- 33.) CREATE new Warehousing (INSERT, SELECT)
-- 90.) RETURN
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
