CREATE OR ALTER PROCEDURE
xPROC219_Doc_TransferToPurchase
-- 26.06.26 03:45
@parxFromDocId INT,
@parxToDocTypeId NVARCHAR(35),
@parxPartnerId INT, --(Supplier)
@parxDocPositionIds NVARCHAR(MAX)
--@parx-TableOfPositions
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE and SELECT
-- 0 DECLARE FROM parameter
-- Generate new DocNumber
DECLARE @SQLString NVARCHAR(100)
DECLARE @ParmDefinition NVARCHAR(75)
DECLARE @NextNumber NVARCHAR(10)
DECLARE @newxDocNumber NVARCHAR(20)
DECLARE @DocNumberPrefix NVARCHAR(3)
DECLARE @WarehousingEffective INT
DECLARE @Draft BIT
-- FROM DocType
SELECT
@DocNumberPrefix = DocNumberPrefix
, @WarehousingEffective = WarehousingEffective 
, @Draft = Draft 
FROM DocType
WHERE Id = @parxToDocTypeId 
--Generate new DocNumber
CREATE TABLE #DocNumberResult (NewDocumentNumber NVARCHAR(30));
-- Aufruf der Prozedur und speichere den Rückgabewert in der temporären Tabelle
INSERT INTO #DocNumberResult
EXEC dbo.xPROC200_GenerateNewDocNumber
@DocTypeId = @parxToDocTypeId -- Übergabe des DocTypeId
-- Zuweisung des Wertes aus der temporären Tabelle in die Variable @newxDocNumber
SELECT @newxDocNumber = NewDocumentNumber
FROM #DocNumberResult;
-- 3 FROM FinancePostingPeriod
DECLARE @CurrentPostingPeriodId INT;
SET @CurrentPostingPeriodId = dbo.xFUNCTION001_GetCurrentPostingPeriodId();
DECLARE @PartnerDetailId INT
DECLARE @DivergentInvoiceRecipientId INT
DECLARE @FinanceGroupPartnerDetailId INT
DECLARE @ForeignCurrencyId NVARCHAR(3)
SELECT
@PartnerDetailId = Id
, @FinanceGroupPartnerDetailId = FinanceGroupPartnerDetailId 
, @DivergentInvoiceRecipientId = DivergentInvoiceRecipientId
, @ForeignCurrencyId = ForeignCurrencyId
FROM PartnerDetail
WHERE PartnerId = @parxPartnerId AND PartnerTypeId = 'Supplier'
-- FROM AdminCurrencyRate
DECLARE @Rate DECIMAL(19,6) = NULL
IF @ForeignCurrencyId IS NOT NULL
BEGIN
SELECT
@Rate = ACR.Rate
FROM dbo.AdminCurrencyRate AS ACR
WHERE
ACR.ForeignCurrencyId = @ForeignCurrencyId
AND ACR.RateDate = CONVERT(date, GETDATE());
END
-- 20.) CREATE new Doc (INSERT, SELECT)
INSERT INTO Doc (
DocNumber
, DocCategoryId
, DocTypeId
, InventoryStatusId
, WarehousingEffective
, RevenueEffective
, PartnerId
, PartnerDetailId
, StatusId
, Draft
, DocDate
, PostingPeriodId
, ShippingDate
, DeliveryDate
, PartnerContactPersonId
, ClerkId
, SalesPersonId
, OurReference
, YourDoc
, YourDocDate
, InternalRemark
, Subject
, Version
, DivergentInvoiceRecipientId
, TermsOfDeliveryId
, EuWork
, LanguageId
, ReportTemplateId
, TermsOfPaymentId
, ProjectId
, PriceListId
, DocDiscountPercent
, DownPaymentSum
, ForeignCurrencyId
, Rate
, OutputControlFormatId
)
SELECT
@newxDocNumber
, DT.DocCategoryId
, @parxToDocTypeId
, DT.InventoryStatusId
, DT.WarehousingEffective
, DT.RevenueEffective
, @parxPartnerId 
, @PartnerDetailId
, 'open'
, DT.Draft
, GETDATE()
, CASE WHEN DT.RevenueEffective != 0 THEN @CurrentPostingPeriodId ELSE NULL END
, GETDATE()
, GETDATE()
, PD.StandardContactPersonId
, ClerkId
, PD.SalesPersonId
, NULL
, NULL
, GETDATE()
, InternalRemark
, Subject
, '1'
, PD.DivergentInvoiceRecipientId
, PD.TermsOfDeliveryId
, EuWork
, P.LanguageId
, PDO.ReportTemplateId
, PD.TermsOfPaymentId
, ProjectId
, NULL
, PD.DocDiscountPercent
, 0
, PD.ForeignCurrencyId
, @Rate
, PDO.OutputControlFormatId
FROM Doc D
JOIN DocType DT ON @parxToDocTypeId = DT.Id
JOIN PartnerDetail PD ON PD.Id = @PartnerDetailId
JOIN Partner P ON PD.PartnerId = P.Id
LEFT JOIN PartnerDetailOutput PDO ON PDO.PartnerDetailId = @PartnerDetailId AND PDO.DocTypeId = DT.Id
WHERE D.Id = @parxFromDocId
DECLARE @newxDocId INT;
SET @newxDocId = SCOPE_IDENTITY();
-- 20a.) UPDATE Doc with Extra Fields from Partner
DROP TABLE IF EXISTS #ExtraFieldMappingPartnerDoc;
CREATE TABLE #ExtraFieldMappingPartnerDoc (
DocColumnName sysname NOT NULL
, PartnerColumnName sysname NOT NULL
, TargetTypeSql nvarchar(128) NOT NULL
);
INSERT INTO #ExtraFieldMappingPartnerDoc (
DocColumnName
, PartnerColumnName
, TargetTypeSql
)
SELECT
DocColumn.name
, PartnerColumn.name
, CASE
WHEN DocType.name IN (N'nvarchar', N'nchar') AND DocColumn.max_length = -1 THEN CONCAT(DocType.name, N'(max)')
WHEN DocType.name IN (N'nvarchar', N'nchar') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.max_length / 2), N')')
WHEN DocType.name IN (N'varchar', N'char', N'varbinary', N'binary') AND DocColumn.max_length = -1 THEN CONCAT(DocType.name, N'(max)')
WHEN DocType.name IN (N'varchar', N'char', N'varbinary', N'binary') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.max_length), N')')
WHEN DocType.name IN (N'decimal', N'numeric') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.precision), N',', CONVERT(nvarchar(10), DocColumn.scale), N')')
WHEN DocType.name IN (N'datetime2', N'datetimeoffset', N'time') THEN CONCAT(DocType.name, N'(', CONVERT(nvarchar(10), DocColumn.scale), N')')
ELSE DocType.name
END
FROM dbo.ExtraField AS DocExtraField
JOIN dbo.ExtraField AS PartnerExtraField
ON PartnerExtraField.Name = DocExtraField.Name
AND PartnerExtraField.SystemTableId = N'Partner'
JOIN sys.columns AS DocColumn
ON DocColumn.object_id = OBJECT_ID(N'dbo.Doc')
AND DocColumn.name = DocExtraField.Id
JOIN sys.types AS DocType
ON DocType.user_type_id = DocColumn.user_type_id
JOIN sys.columns AS PartnerColumn
ON PartnerColumn.object_id = OBJECT_ID(N'dbo.Partner')
AND PartnerColumn.name = PartnerExtraField.Id
JOIN sys.types AS PartnerType
ON PartnerType.user_type_id = PartnerColumn.user_type_id
WHERE DocExtraField.SystemTableId = N'Doc'
AND DocExtraField.Id LIKE N'XX%'
AND PartnerExtraField.Id LIKE N'XX%'
AND DocExtraField.SystemDataTypeId = PartnerExtraField.SystemDataTypeId
AND DocColumn.is_computed = 0
AND PartnerColumn.is_computed = 0
AND DocType.name NOT IN (N'timestamp', N'rowversion')
AND PartnerType.name NOT IN (N'timestamp', N'rowversion');
DECLARE @ExtraFieldPartnerDocValidationSql nvarchar(max);
DECLARE @ExtraFieldPartnerDocInvalidCondition nvarchar(max);
DECLARE @ExtraFieldPartnerDocInvalidCount int;
SELECT
@ExtraFieldPartnerDocInvalidCondition = STRING_AGG(
CAST(
CONCAT(
N'(P.'
, QUOTENAME(PartnerColumnName)
, N' IS NOT NULL AND TRY_CONVERT('
, TargetTypeSql
, N', P.'
, QUOTENAME(PartnerColumnName)
, N') IS NULL)'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N'OR '
)
FROM #ExtraFieldMappingPartnerDoc;
IF @ExtraFieldPartnerDocInvalidCondition IS NOT NULL
BEGIN
SET @ExtraFieldPartnerDocValidationSql = CONCAT(
N'SELECT @ExtraFieldPartnerDocInvalidCount = COUNT(1)
FROM dbo.Partner AS P
WHERE P.Id = @PartnerId
AND ('
, @ExtraFieldPartnerDocInvalidCondition
, N'
);'
);
EXEC sys.sp_executesql
@ExtraFieldPartnerDocValidationSql
, N'@PartnerId int, @ExtraFieldPartnerDocInvalidCount int OUTPUT'
, @PartnerId = @parxPartnerId
, @ExtraFieldPartnerDocInvalidCount = @ExtraFieldPartnerDocInvalidCount OUTPUT;
IF @ExtraFieldPartnerDocInvalidCount > 0
BEGIN
THROW 50000, 'ExtraField value cannot be converted from Partner to Doc target data type.', 1;
END
END
DECLARE @ExtraFieldPartnerDocUpdateSql nvarchar(max);
DECLARE @ExtraFieldPartnerDocSetList nvarchar(max);
SELECT
@ExtraFieldPartnerDocSetList = STRING_AGG(
CAST(
CONCAT(
QUOTENAME(DocColumnName)
, N' = TRY_CONVERT('
, TargetTypeSql
, N', P.'
, QUOTENAME(PartnerColumnName)
, N')'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM #ExtraFieldMappingPartnerDoc;
IF @ExtraFieldPartnerDocSetList IS NOT NULL
BEGIN
SET @ExtraFieldPartnerDocUpdateSql = CONCAT(
N'UPDATE D
SET '
, @ExtraFieldPartnerDocSetList
, N'
FROM dbo.Doc AS D
JOIN dbo.Partner AS P
ON P.Id = @PartnerId
WHERE D.Id = @newxDocId;'
);
EXEC sys.sp_executesql
@ExtraFieldPartnerDocUpdateSql
, N'@newxDocId int, @PartnerId int'
, @newxDocId = @newxDocId
, @PartnerId = @parxPartnerId;
END
