-- 30.) CREATE new Doc Positions (INSERT, SELECT)
-- Temporäre Tabelle zum Speichern der IDs
CREATE TABLE #DocPositionIds (Id INT);
-- String mit IDs in die temporäre Tabelle zerlegen
DECLARE @Xml AS XML;
SET @Xml = CAST(('<root><r>' + REPLACE(@parxDocPositionIds , ',', '</r><r>') + '</r></root>') AS XML);
INSERT INTO #DocPositionIds 
SELECT r.value('.', 'INT') AS Id
FROM @Xml.nodes('//root/r') AS records(r);
CREATE TABLE #NewDocPositions (
SourceDocPositionId INT,
NewDocPositionId INT
);
INSERT INTO DocPosition (
[DocId]
, RowNumber
,[PositionTypeId]
,[PositionNumber]
,[ParentPositionId]
,[StatusId]
,[ArticleId]
,[Name1]
,[Name2]
,[Quantity]
,[QuantityOpen]
,[UoMId]
,[ShippingDate]
,[DeliveryDate]
,[Price]
, ForeignCurrencyPrice
,[PredecessorId]
,[QuantityTransferred]
,[Level]
,[PositionLabel]
,[CatalogNumberId]
,[Dissolve]
,[PositionWeight]
,[ProjectId]
,[Start]
,[Stop]
,[PriceUnitId]
,[ArticleCostPrice]
,[DiscountPercent]
,[QuantityDiscountPercent]
,[DocDiscountPercent]
, PrepaymentFactor
,[RevenueEffective]
,[SalesPersonId]
,[CommissionPercent]
, ProfitFactor
, CostPriceFactor
,[FinanceGroupArticleId]
,[FinanceGroupPartnerDetailId]
,[TaxKeyId]
, TaxFactor
,[TaxPercent]
,[AccountId]
,[CostCenterId]
,[CostBearerId]
,[Warehousing]
,[WarehousingEffective]
)
OUTPUT INSERTED.PredecessorId, INSERTED.Id INTO #NewDocPositions(SourceDocPositionId, NewDocPositionId)
SELECT
@newxDocId
, ROW_NUMBER() OVER (ORDER BY DP.Id)
, PositionTypeId
, ROW_NUMBER() OVER (ORDER BY DP.Id)
, NULL
, 'open'
, DP.ArticleId
, DP.Name1
, DP.Name2
, ISNULL(QuantityOpen,0)
, ISNULL(QuantityOpen,0)
, DP.UoMId
, GETDATE()
, ISNULL(DATEADD(DAY, PPPL.DeliveryTime , GETDATE()), GETDATE())
, ISNULL(PPPL.PurchasePrice,0)
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN ISNULL(PPPL.PurchasePrice,0) * ISNULL(@Rate,0) ELSE NULL END
, DP.Id
, 0
, Level
, PositionLabel
, PCN.Id
, Dissolve
, QuantityOpen* A.Weight
, DP.ProjectId
, NULL
, NULL
, ISNULL(PPPL.PriceUnitId,1)
, ISNULL(APC.CostPrice,0) / A.PriceUnitId
, CASE WHEN D.DocCategoryId = 'Sales' THEN ISNULL(PDG.DiscountPercent,0) ELSE ISNULL(PPPL.DiscountPercent, 0) END
, CASE WHEN PPPL.DiscountGroupAssigned = 1 THEN
CASE
WHEN DP.QuantityOpen >= QuantityLevelE AND QuantityLevelE > 0 THEN QuantityDiscountE
WHEN DP.QuantityOpen >= QuantityLevelD AND QuantityLevelD > 0 THEN QuantityDiscountD
WHEN DP.QuantityOpen >= QuantityLevelC AND QuantityLevelC > 0 THEN QuantityDiscountC
WHEN DP.QuantityOpen >= QuantityLevelB AND QuantityLevelB > 0 THEN QuantityDiscountB
WHEN DP.QuantityOpen >= QuantityLevelA AND QuantityLevelA > 0 THEN QuantityDiscountA
ELSE 0
END
ELSE 0 END
, ISNULL(PD.DocDiscountPercent,0)
, CASE WHEN A.IsPrepayment = 1 THEN DT_ToDoc.PrepaymentTrueArticleFactor ELSE DT_ToDoc.PrepaymentFalseArticleFactor END
, DT_ToDoc.RevenueEffective
, D.SalesPersonId
, 0
, CASE WHEN A.IsPrepayment = 1 THEN 0 ELSE 1 END
, 0
, A.ProcurementFinanceGroupId
, @FinanceGroupPartnerDetailId
, FGAD.TaxKeyId
, CASE WHEN FTK.TaxKeyKindId = 3 THEN 0 ELSE 1 END
, FTKD.TaxPercent
, FGAD.RevenueExpenditureAccountId
, PD.CostCenterId
, DP.CostBearerId
, A.Warehousing
, 0
FROM DocPosition DP
JOIN Doc D ON DP.DocId = D.Id
JOIN Article A ON DP.ArticleId = A.Id
JOIN #DocPositionIds TMP ON TMP.Id = DP.Id
LEFT JOIN ArticlePriceCalculation APC ON DP.ArticleId = APC.ArticleId
LEFT JOIN PartnerDetail PD ON PD.Id= @PartnerDetailId
LEFT JOIN PartnerPurchasePriceList PPPL ON PPPL.PartnerId = @parxPartnerId AND PPPL.ArticleId = DP.ArticleId
LEFT JOIN PartnerDiscountGroup PDG ON PDG.DiscountGroupNameId = PD.DiscountGroupNameId AND PDG.ArticleGroupId = A.ArticleGroupId
LEFT JOIN FinanceGroupArticleDetail FGAD ON FGAD.FinanceGroupArticleId =  A.ProcurementFinanceGroupId AND FGAD.FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId
LEFT JOIN FinanceTaxKeyDetail FTKD ON FTKD.TaxKeyId = FGAD.TaxKeyId AND FTKD.ValidFrom = (SELECT MAX(ValidFrom) FROM FinanceTaxKeyDetail WHERE TaxKeyId = FGAD.TaxKeyId AND ValidFrom <= D.DocDate)
LEFT JOIN FinanceTaxKey FTK ON FTKD.TaxKeyId = FTK.Id
LEFT JOIN DocType AS DT_ToDoc ON DT_ToDoc.Id = @parxToDocTypeId
LEFT JOIN PartnerCatalogNumber PCN ON PCN.PartnerId = @parxPartnerId AND PCN.ArticleId = DP.ArticleId AND PCN.Active = 1
WHERE (FTKD.ValidFrom IS NULL OR FTKD.ValidFrom <= D.DocDate) AND DP.PositionTypeId != 'Auto' AND DP.PositionTypeId != 'Text'
-- 30a.) UPDATE DocPosition with Extra Fields from predecessor DocPosition
DECLARE @ExtraFieldDocPositionSetList nvarchar(max);
DECLARE @ExtraFieldDocPositionUpdateSql nvarchar(max);
SELECT
@ExtraFieldDocPositionSetList = STRING_AGG(
CAST(
CONCAT(
N'TargetDP.'
, QUOTENAME(TargetColumn.name)
, N' = SourceDP.'
, QUOTENAME(SourceColumn.name)
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM dbo.ExtraField AS TargetExtraField
JOIN dbo.ExtraField AS SourceExtraField
ON SourceExtraField.Name = TargetExtraField.Name
AND SourceExtraField.SystemTableId = N'DocPosition'
JOIN sys.columns AS TargetColumn
ON TargetColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND TargetColumn.name = TargetExtraField.Id
JOIN sys.columns AS SourceColumn
ON SourceColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND SourceColumn.name = SourceExtraField.Id
WHERE TargetExtraField.SystemTableId = N'DocPosition'
AND TargetExtraField.Id LIKE N'XX%'
AND SourceExtraField.Id LIKE N'XX%'
AND TargetColumn.is_computed = 0
AND SourceColumn.is_computed = 0;
IF @ExtraFieldDocPositionSetList IS NOT NULL
BEGIN
SET @ExtraFieldDocPositionUpdateSql = CONCAT(
N'UPDATE TargetDP
SET '
, @ExtraFieldDocPositionSetList
, N'
FROM dbo.DocPosition AS TargetDP
JOIN #NewDocPositions AS NDP
ON NDP.NewDocPositionId = TargetDP.Id
JOIN dbo.DocPosition AS SourceDP
ON SourceDP.Id = NDP.SourceDocPositionId;'
);
EXEC sys.sp_executesql
@ExtraFieldDocPositionUpdateSql;
END
-- 32.) CREATE new DocPosition Texts (INSERT, SELECT)
-- OrderText
INSERT INTO DocPositionOrderText (DocPositionId, OrderText)
SELECT NDP.NewDocPositionId, DPOT.OrderText
FROM #NewDocPositions NDP
JOIN DocPositionOrderText DPOT ON DPOT.DocPositionId = NDP.SourceDocPositionId;
-- InfoText
INSERT INTO DocPositionInfoText (DocPositionId, InfoText)
SELECT NDP.NewDocPositionId, AIT.InfoText
FROM #NewDocPositions NDP
JOIN DocPosition DP ON DP.Id = NDP.SourceDocPositionId
JOIN ArticleInfoText AIT ON AIT.ArticleId = DP.ArticleId;
-- 33.) CREATE new Warehousing (INSERT, SELECT)
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
NDP.NewDocPositionId
, COALESCE(W.WarehouseId, A.StandardWarehouseId)
, W.BinLocationId
, COALESCE(W.IndividualizationTypeId, A.IndividualizationTypeId)
, NULL
, COALESCE(W.Quantity, DP.Quantity)
, 0
FROM #NewDocPositions NDP
JOIN DocPosition DP ON DP.Id = NDP.SourceDocPositionId
LEFT JOIN DocPositionWarehousing W ON W.DocPositionId = DP.Id
JOIN Article A ON DP.ArticleId = A.Id
WHERE A.Warehousing = 1 AND @Draft = 1;
DROP TABLE #DocPositionIds;
DROP TABLE #NewDocPositions;
SELECT @newxDocId AS ToDocId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC219_Doc_TransferToPurchase ----------------------------------------------------------------------
--xPROC220I_DocPosition_InsertArticle-------------------------------------
-- PURPOSE: Create Position and possible Subpositions for passed Article. Update Sums
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) CALCULATE DocPosition Sums
-- 21.) INSERT DocPosition (Sales + Purchase)
-- 28.) INSERT Warehousing
-- 29.) INSERT DocPositionTexts
-- 31.) INSERT DocPositions (For Set)
-- 50.) CALCULATE DocSums
-- 51.) CALCULATE DocStatus
-- 59.) UPDATE Doc Status
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC220I_DocPosition_InsertArticle
-- xPROC220I_DocPosition_InsertArticle
@parxDocId INT,
@parxArticleId NVARCHAR(30),
@parxComponentIds NVARCHAR(MAX)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @locxDocId INT = @parxDocId
DECLARE @locxArticleId NVARCHAR(30) = @parxArticleId
-- 10.) DECLARE, SELECT, CALCULATE
-- 10.1 FROM Doc
DECLARE @DocCategoryId NVARCHAR(10)
DECLARE @DocType NVARCHAR(35)
DECLARE @PartnerDetailId INT
DECLARE @PartnerId INT
DECLARE @SalesPersonId INT
DECLARE @ProjectId INT
DECLARE @PriceListId INT
DECLARE @RevenueEffective INT
DECLARE @WarehousingEffective INT
DECLARE @InventoryStatusId NVARCHAR(10)
DECLARE @DocDate DATETIME
DECLARE @Draft BIT
DECLARE @DocDiscountPercent DECIMAL(19,6) = 0
DECLARE @ForeignCurrencyId NVARCHAR(3)
DECLARE @Rate DECIMAL(19,6)
SELECT
@DocCategoryId = DocCategoryId
, @DocType = DocTypeId
, @PartnerDetailId = PartnerDetailId
, @PartnerId = PartnerId
, @SalesPersonId = SalesPersonId
, @ProjectId = ProjectId
, @PriceListId = PriceListId
, @RevenueEffective = RevenueEffective
, @WarehousingEffective = WarehousingEffective
, @InventoryStatusId = InventoryStatusId
, @DocDate = DocDate 
, @Draft = Draft 
, @DocDiscountPercent = DocDiscountPercent
, @ForeignCurrencyId = ForeignCurrencyId 
, @Rate= Rate
FROM Doc
WHERE Id = @locxDocId
DECLARE @PrepaymentFalseArticleFactor INT
DECLARE @PrepaymentTrueArticleFactor INT
SELECT
@PrepaymentFalseArticleFactor = PrepaymentFalseArticleFactor
, @PrepaymentTrueArticleFactor = PrepaymentTrueArticleFactor 
FROM DocType
WHERE Id = @DocType
-- 10.2 FROM DocPosition
DECLARE @calxNewPositionNumber INT
DECLARE @calxNewRowNumber INT
SELECT 
@calxNewPositionNumber = ISNULL(MAX(PositionNumber), 0) + 1 
, @calxNewRowNumber = ISNULL(MAX(RowNumber), 0) + 1 
FROM DocPosition 
WHERE DocId = @locxDocId;
-- 10.3 FROM PartnerDetail
DECLARE @FinanceGroupPartnerDetailId INT
DECLARE @DiscountGroupNameId INT
DECLARE @CostCenterId INT
SELECT
@FinanceGroupPartnerDetailId = FinanceGroupPartnerDetailId
, @DiscountGroupNameId = DiscountGroupNameId
, @CostCenterId = CostCenterId
FROM PartnerDetail 
WHERE Id = @PartnerDetailId;
-- 10.4 FROM EmployeeCommissionGroup
DECLARE @CommissionPercent DECIMAL(19,6) = 0
SELECT 
@CommissionPercent = CASE WHEN @SalesPersonId IS NOT NULL THEN ISNULL(MAX(ECG.CommissionPercent),0) ELSE 0 END
FROM
Employee E
LEFT JOIN Article A ON A.Id = @locxArticleId
LEFT JOIN PartnerDetail PD ON PD.Id = @PartnerDetailId
LEFT JOIN Partner P ON P.Id = PD.PartnerId
LEFT JOIN EmployeeCommissionGroupName ECGN ON ECGN.Id = E.CommissionGroupId
LEFT JOIN EmployeeCommissionGroup ECG ON ECG.CommissionGroupId = E.CommissionGroupId AND ((ECGN.PerArticleGroup = 0 OR ECG.ArticleGroupId = A.ArticleGroupId) AND (ECGN.PerPartnerGroup= 0 OR ECG.PartnerGroupId = P.PartnerGroupId))
WHERE
E.Id= @SalesPersonId
-- 10.5 Article Master Data, Quantities and Prices
DECLARE @CatalogNumberId INT
DECLARE @ArticleName1 NVARCHAR(100)
DECLARE @ArticleName2 NVARCHAR(100)
DECLARE @WithMacro BIT
DECLARE @WithSet BIT
DECLARE @WithAccessory  BIT
DECLARE @UoMId INT
DECLARE @Warehousing BIT
DECLARE @Weight DECIMAL(19,6)
DECLARE @FinanceGroupArticleId INT
DECLARE @ArticleGroupId INT
DECLARE @PriceUnitId INT
DECLARE @LotSize DECIMAL(19,6)
DECLARE @MinimumQuantity DECIMAL(19,6)
DECLARE @calxDeliveryDate DATETIME
DECLARE @Price DECIMAL(19,6)
DECLARE @calxQuantity DECIMAL(19,6)
DECLARE @IsPrepayment BIT
DECLARE @DiscountPercent DECIMAL(19,6) = 0
DECLARE @DiscountGroupAssigned BIT = 1
DECLARE @ArticleSalesPriceListNameForeignCurrencyId NVARCHAR(3)
-- SALES: PartnerCatalogNumber
SELECT 
@CatalogNumberId = Id
FROM PartnerCatalogNumber
WHERE ArticleId = @locxArticleId AND PartnerId = @PartnerId AND Active = 1;
IF @DocCategoryId = 'Sales' BEGIN
-- SALES: Article Master Data
SELECT
@ArticleName1 = Name1
, @ArticleName2 = Name2
, @WithMacro = WithMacro
, @WithSet = WithSet
, @WithAccessory = WithAccessory
, @UoMId = UoMId
, @Warehousing = Warehousing
, @Weight = Weight
, @FinanceGroupArticleId = SalesFinanceGroupId
, @ArticleGroupId = ArticleGroupId
, @PriceUnitId = PriceUnitId
, @LotSize = LotSize
, @MinimumQuantity = MinimumQuantity
, @IsPrepayment = IsPrepayment
, @calxDeliveryDate = DATEADD(DAY, DeliveryTime , GETDATE())
FROM Article WHERE Id = @locxArticleId;
-- SALES: ArticleSalesPriceList
SELECT TOP 1
@Price = SalesPrice
, @ArticleSalesPriceListNameForeignCurrencyId = ASPLN.ForeignCurrencyId
FROM ArticleSalesPriceList ASPL
LEFT JOIN ArticleSalesPriceListName ASPLN ON ASPLN.Id = ASPL.PriceListId
WHERE ArticleId = @locxArticleId AND PriceListId = @PriceListId AND ValidFrom <= GETDATE() ORDER BY ValidFrom DESC;
SELECT
@DiscountPercent = ISNULL(DiscountPercent, 0)
FROM PartnerDiscountGroup
WHERE 
ArticleGroupId = @ArticleGroupId 
AND DiscountGroupNameId= @DiscountGroupNameId
END -- IF Sales
ELSE IF @DocCategoryId = 'Purchase' BEGIN
-- PURCHASE: FROM Article Master Data
SELECT
@ArticleName1 = Name1
, @ArticleName2 = Name2
, @WithMacro = WithMacro
, @WithSet = WithSet
, @WithAccessory = WithAccessory
, @UoMId = UoMId
, @Weight = Weight
, @Warehousing = Warehousing
, @FinanceGroupArticleId = ProcurementFinanceGroupId
, @ArticleGroupId = ArticleGroupId
, @PriceUnitId = PriceUnitId
, @IsPrepayment = IsPrepayment
FROM Article WHERE Id = @locxArticleId;
-- PURCHASE: FROM PartnerPurchasePriceList
SELECT
@LotSize = ISNULL(LotSize,0)
, @MinimumQuantity = MinimumQuantity
, @calxDeliveryDate = DATEADD(DAY, DeliveryTime , GETDATE())
, @Price = PurchasePrice
, @DiscountPercent = ISNULL(DiscountPercent, 0)
, @DiscountGroupAssigned = DiscountGroupAssigned
FROM PartnerPurchasePriceList 
WHERE PartnerId = @PartnerId AND ArticleId = @locxArticleId;
END -- IF Purchase
-- 10.7) Calculate Quantity
SET @calxQuantity = ISNULL(
CASE
WHEN @LotSize != 0 AND @MinimumQuantity IS NOT NULL THEN CEILING(@MinimumQuantity / @LotSize) * @LotSize
WHEN @LotSize = 0 AND @MinimumQuantity >1 THEN @MinimumQuantity
ELSE 1
END -- CASE
, 1);
IF @calxQuantity < 1 SET @calxQuantity = 1;
IF @calxQuantity < @LotSize SET @calxQuantity = @LotSize;
-- 10.8) FROM ArticlePriceCalculation
DECLARE @CostPrice DECIMAL(19,6)
SELECT
@CostPrice = CostPrice
FROM ArticlePriceCalculation
WHERE ArticleId = @locxArticleId
-- 10.9) FROM PartnerDiscountGroup
DECLARE @calxQuantityDiscountPercent DECIMAL(19,6) = 0
SELECT
@calxQuantityDiscountPercent = ISNULL(
CASE
WHEN @calxQuantity >= QuantityLevelE AND QuantityLevelE > 0 THEN QuantityDiscountE
WHEN @calxQuantity >= QuantityLevelD AND QuantityLevelD > 0 THEN QuantityDiscountD
WHEN @calxQuantity >= QuantityLevelC AND QuantityLevelC > 0 THEN QuantityDiscountC
WHEN @calxQuantity >= QuantityLevelB AND QuantityLevelB > 0 THEN QuantityDiscountB
WHEN @calxQuantity >= QuantityLevelA AND QuantityLevelA > 0 THEN QuantityDiscountA
ELSE 0
END -- CASE
, 0)
FROM PartnerDiscountGroup
WHERE 
ArticleGroupId = @ArticleGroupId 
AND DiscountGroupNameId= @DiscountGroupNameId
AND @DiscountGroupAssigned = 1
-- 10.10) DECLARE FROM FinanceGroupArticleDetail
DECLARE @TaxKeyId NVARCHAR(3)
DECLARE @RevenueExpenditureAccountId INT
SELECT
@TaxKeyId = TaxKeyId
, @RevenueExpenditureAccountId = RevenueExpenditureAccountId
FROM FinanceGroupArticleDetail
WHERE FinanceGroupArticleId = @FinanceGroupArticleId  AND FinanceGroupPartnerDetailId = @FinanceGroupPartnerDetailId
-- 10.11) DECLARE FROM FinanceTaxKeyDetail
DECLARE @calxTaxPercent DECIMAL(19,6) = 0
SELECT TOP (1) 
@calxTaxPercent = TaxPercent
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = @TaxKeyId AND ValidFrom <= GETDATE()
ORDER BY ValidFrom DESC
-- 10.12) DECLARE FROM FinanceTaxKey
DECLARE @TaxKeyKindId INT
SELECT
@TaxKeyKindId = TaxKeyKindId
FROM FinanceTaxKey
WHERE Id = @TaxKeyId
-- 20.) CALCULATE DocPosition Sums
DECLARE @calxPositionWeight DECIMAL(19, 6) = ISNULL(@calxQuantity * @Weight, 0);
DECLARE @calxCostPriceTotal DECIMAL(19,6) = ISNULL(@calxQuantity * @CostPrice/@PriceUnitId, 0);
DECLARE @calxTotalPrice DECIMAL(19,6) = ROUND(ISNULL(@calxQuantity * (@Price / @PriceUnitId) * (1 - ((@DiscountPercent + @calxQuantityDiscountPercent + @DocDiscountPercent) / 100)), 0),2);
DECLARE @calxDiscountedPrice DECIMAL(19,6) = ISNULL(IIF(@calxQuantity = 0, 0, (ISNULL(@calxQuantity * (@Price / @PriceUnitId) * (1 - ((@DiscountPercent + @calxQuantityDiscountPercent + @DocDiscountPercent) / 100)), 0))/ @calxQuantity), 0);
DECLARE @calxCommissionAmount DECIMAL(19,6) = ROUND(ISNULL((@calxTotalPrice * @CommissionPercent / 100), 0),2);
DECLARE @calxProfitAmount DECIMAL(19,6) = CASE WHEN @DocCategoryId = 'Sales' THEN ROUND(ISNULL(@calxTotalPrice - @calxCostPriceTotal, 0),2) ELSE 0 END;
DECLARE @calxProfitPercent DECIMAL(19,6) = CASE WHEN @DocCategoryId = 'Sales' THEN ISNULL(ROUND(ABS(@calxProfitAmount / NULLIF(@calxTotalPrice, 0)) * 100, 2) * SIGN(@calxProfitAmount),0) ELSE 0 END;
DECLARE @calxTax DECIMAL(19,6) = CASE WHEN @TaxKeyKindId = 3 THEN 0 ELSE ISNULL((@calxTotalPrice * @calxTaxPercent / 100), 0) END;
DECLARE @calxRevenue DECIMAL(19,6) = ISNULL(@RevenueEffective * @calxTotalPrice, 0);
-- 21.) INSERT DocPosition (Sales + Purchase)
DROP TABLE IF EXISTS #ExtraFieldMappingArticleDocPosition;
CREATE TABLE #ExtraFieldMappingArticleDocPosition (
DocPositionColumnName sysname NOT NULL
, ArticleColumnName sysname NOT NULL
, TargetTypeSql nvarchar(128) NOT NULL
);
INSERT INTO #ExtraFieldMappingArticleDocPosition (
DocPositionColumnName
, ArticleColumnName
, TargetTypeSql
)
SELECT
DocPositionColumn.name
, ArticleColumn.name
, CASE
WHEN DocPositionType.name IN (N'nvarchar', N'nchar') AND DocPositionColumn.max_length = -1 THEN CONCAT(DocPositionType.name, N'(max)')
WHEN DocPositionType.name IN (N'nvarchar', N'nchar') THEN CONCAT(DocPositionType.name, N'(', CONVERT(nvarchar(10), DocPositionColumn.max_length / 2), N')')
WHEN DocPositionType.name IN (N'varchar', N'char', N'varbinary', N'binary') AND DocPositionColumn.max_length = -1 THEN CONCAT(DocPositionType.name, N'(max)')
WHEN DocPositionType.name IN (N'varchar', N'char', N'varbinary', N'binary') THEN CONCAT(DocPositionType.name, N'(', CONVERT(nvarchar(10), DocPositionColumn.max_length), N')')
WHEN DocPositionType.name IN (N'decimal', N'numeric') THEN CONCAT(DocPositionType.name, N'(', CONVERT(nvarchar(10), DocPositionColumn.precision), N',', CONVERT(nvarchar(10), DocPositionColumn.scale), N')')
WHEN DocPositionType.name IN (N'datetime2', N'datetimeoffset', N'time') THEN CONCAT(DocPositionType.name, N'(', CONVERT(nvarchar(10), DocPositionColumn.scale), N')')
ELSE DocPositionType.name
END
FROM dbo.ExtraField AS DocPositionExtraField
JOIN dbo.ExtraField AS ArticleExtraField
ON ArticleExtraField.Name = DocPositionExtraField.Name
AND ArticleExtraField.SystemTableId = N'Article'
JOIN sys.columns AS DocPositionColumn
ON DocPositionColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND DocPositionColumn.name = DocPositionExtraField.Id
JOIN sys.types AS DocPositionType
ON DocPositionType.user_type_id = DocPositionColumn.user_type_id
JOIN sys.columns AS ArticleColumn
ON ArticleColumn.object_id = OBJECT_ID(N'dbo.Article')
AND ArticleColumn.name = ArticleExtraField.Id
JOIN sys.types AS ArticleType
ON ArticleType.user_type_id = ArticleColumn.user_type_id
WHERE DocPositionExtraField.SystemTableId = N'DocPosition'
AND DocPositionExtraField.Id LIKE N'XX%'
AND ArticleExtraField.Id LIKE N'XX%'
AND DocPositionExtraField.SystemDataTypeId = ArticleExtraField.SystemDataTypeId
AND DocPositionColumn.is_computed = 0
AND ArticleColumn.is_computed = 0
AND DocPositionType.name NOT IN (N'timestamp', N'rowversion')
AND ArticleType.name NOT IN (N'timestamp', N'rowversion');
DECLARE @newxDocPositionId INT
IF @WithMacro = 0 BEGIN
INSERT INTO DocPosition
(
DocId
, RowNumber
, PositionTypeId
, PositionNumber
, ParentPositionId
, ChildPositionNumber
, StatusId
, ArticleId
, Name1
, Name2
, Quantity
, QuantityOpen
, UoMId
, ShippingDate
, DeliveryDate
, Price 
, ForeignCurrencyPrice 
, PredecessorId
, QuantityTransferred
, Level
, PositionLabel
, CatalogNumberId
, Dissolve
, PositionWeight
, ProjectId
, Start
, Stop
, PriceUnitId
, ArticleCostPrice
, DiscountPercent
, QuantityDiscountPercent
, DocDiscountPercent
, PrepaymentFactor
, RevenueEffective
, SalesPersonId
, CommissionPercent
, ProfitFactor
, CostPriceFactor
, FinanceGroupArticleId
, FinanceGroupPartnerDetailId
, TaxKeyId
, TaxFactor
, TaxPercent
, AccountId
, CostCenterId
, CostBearerId
, Warehousing
, WarehousingEffective
)
-- VALUES DocPosition
VALUES
(
@locxDocId
, @calxNewRowNumber
, 'Article'
, @calxNewPositionNumber
, NULL
, NULL
, 'open'
, @locxArticleId
, @ArticleName1
, @ArticleName2
, @calxQuantity
, @calxQuantity
, @UoMId
, GETDATE()
, COALESCE(@calxDeliveryDate, GETDATE())
, CASE WHEN (@ArticleSalesPriceListNameForeignCurrencyId IS NULL AND @DocCategoryId = 'Sales') OR (@DocCategoryId = 'Purchase') THEN ISNULL(@Price, 0) ELSE CASE WHEN ISNULL(@Rate, 0) = 0 THEN 0 ELSE ROUND(ISNULL(@Price, 0) / ISNULL(@Rate, 0), 2) END END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN (@ArticleSalesPriceListNameForeignCurrencyId IS NULL AND @DocCategoryId = 'Sales') OR (@DocCategoryId = 'Purchase')  THEN ROUND(ISNULL(@Price, 0) * ISNULL(@Rate, 0), 2) ELSE ISNULL(@Price, 0) END ELSE NULL END
, NULL
, 0
, NULL
, CONCAT(FORMAT(@locxDocId, 'D10'), '-', FORMAT(CAST((SELECT COUNT(*) + 1 FROM DocPosition WHERE DocId = @locxDocId) AS INT), 'D6'))
, @CatalogNumberId
, 0
, @calxPositionWeight
, @ProjectId
, NULL
, NULL
, ISNULL(@PriceUnitId, 1)
, @CostPrice
, ISNULL(@DiscountPercent , 0)
, @calxQuantityDiscountPercent
, @DocDiscountPercent
, CASE WHEN @IsPrepayment = 1 THEN @PrepaymentTrueArticleFactor ELSE @PrepaymentFalseArticleFactor END
, @RevenueEffective
, @SalesPersonId
, @CommissionPercent
, CASE WHEN @IsPrepayment = 1 THEN 0 ELSE 1 END
, CASE WHEN @DocCategoryId= 'Purchase' THEN 0 ELSE 1 END
, @FinanceGroupArticleId
, @FinanceGroupPartnerDetailId
, @TaxKeyId
, CASE WHEN @TaxKeyKindId = 3 THEN 0 ELSE 1 END
, @calxTaxPercent
, @RevenueExpenditureAccountId
, @CostCenterId
, NULL
, @Warehousing
, 0
)
SET @newxDocPositionId = SCOPE_IDENTITY();
-- UPDATE DocPosition with Extra Fields from Article
DECLARE @ExtraFieldArticleDocPositionValidationSql nvarchar(max);
DECLARE @ExtraFieldArticleDocPositionInvalidCondition nvarchar(max);
DECLARE @ExtraFieldArticleDocPositionInvalidCount int;
SELECT
@ExtraFieldArticleDocPositionInvalidCondition = STRING_AGG(
CAST(
CONCAT(
N'(A.'
, QUOTENAME(ArticleColumnName)
, N' IS NOT NULL AND TRY_CONVERT('
, TargetTypeSql
, N', A.'
, QUOTENAME(ArticleColumnName)
, N') IS NULL)'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N'OR '
)
FROM #ExtraFieldMappingArticleDocPosition;
IF @ExtraFieldArticleDocPositionInvalidCondition IS NOT NULL
BEGIN
SET @ExtraFieldArticleDocPositionValidationSql = CONCAT(
N'SELECT @ExtraFieldArticleDocPositionInvalidCount = COUNT(1)
FROM dbo.Article AS A
WHERE A.Id = @ArticleId
AND ('
, @ExtraFieldArticleDocPositionInvalidCondition
, N'
);'
);
EXEC sys.sp_executesql
@ExtraFieldArticleDocPositionValidationSql
, N'@ArticleId nvarchar(30), @ExtraFieldArticleDocPositionInvalidCount int OUTPUT'
, @ArticleId = @locxArticleId
, @ExtraFieldArticleDocPositionInvalidCount = @ExtraFieldArticleDocPositionInvalidCount OUTPUT;
IF @ExtraFieldArticleDocPositionInvalidCount > 0
BEGIN
THROW 50000, 'ExtraField value cannot be converted from Article to DocPosition target data type.', 1;
END
END
DECLARE @ExtraFieldArticleDocPositionUpdateSql nvarchar(max);
DECLARE @ExtraFieldArticleDocPositionSetList nvarchar(max);
SELECT
@ExtraFieldArticleDocPositionSetList = STRING_AGG(
CAST(
CONCAT(
QUOTENAME(DocPositionColumnName)
, N' = TRY_CONVERT('
, TargetTypeSql
, N', A.'
, QUOTENAME(ArticleColumnName)
, N')'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM #ExtraFieldMappingArticleDocPosition;
IF @ExtraFieldArticleDocPositionSetList IS NOT NULL
BEGIN
SET @ExtraFieldArticleDocPositionUpdateSql = CONCAT(
N'UPDATE DP
SET '
, @ExtraFieldArticleDocPositionSetList
, N'
FROM dbo.DocPosition AS DP
JOIN dbo.Article AS A
ON A.Id = DP.ArticleId
WHERE DP.Id = @DocPositionId;'
);
EXEC sys.sp_executesql
@ExtraFieldArticleDocPositionUpdateSql
, N'@DocPositionId int'
, @DocPositionId = @newxDocPositionId;
END
-- 28.) INSERT Warehousing
IF @Draft= 1 BEGIN
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
@newxDocPositionId
, CASE WHEN D.StandardWarehouseId IS NOT NULL THEN D.StandardWarehouseId ELSE A.StandardWarehouseId END
, NULL
, A.IndividualizationTypeId
, NULL
, CASE WHEN A.IndividualizationTypeId = 'Serial' THEN 1 ELSE DP.Quantity END
, 0
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.Id = @newxDocPositionId AND DP.Warehousing = 1
END -- IF @Draft= 1
-- 29.) INSERT DocPositionTexts
DECLARE @DocPositionInfoText NVARCHAR(MAX) = (SELECT InfoText FROM ArticleInfoText WHERE ArticleId = @locxArticleId);
DECLARE @DocPositionDimensionText NVARCHAR(MAX) = (SELECT DimensionText FROM ArticleDimensionText WHERE ArticleId = @locxArticleId);
DECLARE @DocPositionOrderText NVARCHAR(MAX) = (SELECT OrderText FROM ArticleOrderText WHERE ArticleId = @locxArticleId);
INSERT INTO DocPositionInfoText (DocPositionId, InfoText)
VALUES (@newxDocPositionId, @DocPositionInfoText)
INSERT INTO DocPositionOrderText (DocPositionId, OrderText)
VALUES (@newxDocPositionId, @DocPositionOrderText)
INSERT INTO DocPositionDimensionText (DocPositionId, DimensionText)
VALUES (@newxDocPositionId, @DocPositionDimensionText)
END --IF @WithMacro = 0 BEGIN
-- 31.) INSERT DocPositions (For Child Positions)
IF(@WithSet  = 1 OR @WithMacro = 1 OR EXISTS (SELECT 1 FROM ArticleAccessory WHERE ArticleId = @parxArticleId))
BEGIN
-- Get Ids From @parxComponentIds
--Table for new PositionIds
DECLARE @InsertedDocPositions TABLE (DocPositionId INT);
CREATE TABLE #ComponentIds (Id NVARCHAR(30));
DECLARE @Xml AS XML;
SET @Xml = CAST(('<root><r>' + REPLACE(@parxComponentIds , ',', '</r><r>') + '</r></root>') AS XML);
INSERT INTO #ComponentIds
SELECT r.value('.', 'NVARCHAR(30)') AS Id
FROM @Xml.nodes('//root/r') AS records(r);
DECLARE @MaxPositionNumber INT
DECLARE @MaxRowNumber INT
SELECT @MaxPositionNumber = ISNULL(MAX(PositionNumber), 0) FROM DocPosition WHERE DocId = @locxDocId;
SELECT @MaxRowNumber = ISNULL(MAX(RowNumber), 0) FROM DocPosition WHERE DocId = @locxDocId;
WITH DataSource AS (
SELECT Id, ComponentId, QuantityFactor, AdditionalQuantity, ArticleId, ForFree, 'Article' AS PositionTypeId
FROM ArticleSet
WHERE @WithSet = 1 AND ArticleId = @locxArticleId
UNION ALL
SELECT Id, ComponentId, QuantityFactor, AdditionalQuantity, ArticleId, ForFree, PositionTypeId 
FROM ArticleMacro
WHERE @WithMacro = 1 AND ArticleId = @locxArticleId
UNION ALL
SELECT Id, ComponentId, QuantityFactor, AdditionalQuantity, ArticleId, ForFree, PositionTypeId 
FROM ArticleAccessory
WHERE ArticleId = @locxArticleId AND ComponentId IN (SELECT Id FROM #ComponentIds)
),
CalcValuesCTE AS (
SELECT
DS.Id AS Id
, DP.Id AS DocPositionId
, DS.ComponentId AS ComponentId
, CASE WHEN @WithMacro = 0 THEN @calxNewPositionNumber ELSE @MaxPositionNumber + ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) END AS PositionNumber
, CASE WHEN @WithMacro = 1 THEN @MaxRowNumber + ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) END AS MacroRowNumber
, CASE
WHEN @WithMacro = 0 THEN ROW_NUMBER() OVER (ORDER BY DP.Id) 
ELSE NULL
END AS ChildPositionNumber
, CASE
WHEN DS.ForFree  = 1 THEN 0
WHEN DS.ForFree  = 0 AND D.DocCategoryId = 'Sales' THEN ASPL.SalesPrice
WHEN DS.ForFree  = 0 AND D.DocCategoryId = 'Purchase' THEN PPPL.PurchasePrice
END AS CalcPrice
, CASE
WHEN @WithSet = 0 AND (@calxQuantity * QuantityFactor) + AdditionalQuantity >= PDG.QuantityLevelE AND PDG.QuantityLevelE > 0 THEN PDG.QuantityDiscountE
WHEN @WithSet = 0 AND (@calxQuantity * QuantityFactor) + AdditionalQuantity >= PDG.QuantityLevelD AND PDG.QuantityLevelD > 0 THEN PDG.QuantityDiscountD
WHEN @WithSet = 0 AND (@calxQuantity * QuantityFactor) + AdditionalQuantity >= PDG.QuantityLevelC AND PDG.QuantityLevelC > 0 THEN PDG.QuantityDiscountC
WHEN @WithSet = 0 AND (@calxQuantity * QuantityFactor) + AdditionalQuantity >= PDG.QuantityLevelB AND PDG.QuantityLevelB > 0 THEN PDG.QuantityDiscountB
WHEN @WithSet = 0 AND (@calxQuantity * QuantityFactor) + AdditionalQuantity >= PDG.QuantityLevelA AND PDG.QuantityLevelA > 0 THEN PDG.QuantityDiscountA
ELSE 0
END AS CalcQuantityDiscountPercent
, PCN.Id AS CalcCatalogNumberId
, CASE
WHEN D.DocCategoryId = 'Sales' THEN A.SalesFinanceGroupId
WHEN D.DocCategoryId = 'Purchase' THEN A.ProcurementFinanceGroupId
END AS CalcFinanceGroup
, (ISNULL(DP.Quantity,1) * DS.QuantityFactor) + DS.AdditionalQuantity AS CalcQuantity
,  RIGHT('000000' + CAST((SELECT COUNT(*) + ROW_NUMBER() OVER (ORDER BY DP.Id)  FROM DocPosition WHERE DocId = @locxDocId) AS VARCHAR(6)), 6) AS PositionCount
FROM DataSource DS
LEFT JOIN Article A ON DS.ComponentId = A.Id
LEFT JOIN DocPosition DP ON DP.Id = @newxDocPositionId
LEFT JOIN Doc D ON D.Id = @parxDocId
LEFT JOIN PartnerDetail PD ON PD.Id = @PartnerDetailId
LEFT JOIN ArticleSalesPriceList ASPL ON ASPL.ArticleId = A.Id AND ASPL.PriceListId = D.PriceListId AND ASPL.ValidFrom = (SELECT MAX(ValidFrom) FROM ArticleSalesPriceList WHERE ArticleId = A.Id AND PriceListId = D.PriceListId AND ValidFrom <= D.DocDate)
LEFT JOIN PartnerCatalogNumber PCN ON PCN.PartnerId = @PartnerId AND PCN.ArticleId = A.Id AND PCN.Active = 1
LEFT JOIN PartnerPurchasePriceList PPPL ON PPPL.PartnerId = @PartnerId AND PPPL.ArticleId = A.Id
LEFT JOIN PartnerDiscountGroup PDG ON PDG.DiscountGroupNameId = PD.DiscountGroupNameId AND PDG.ArticleGroupId = A.ArticleGroupId
WHERE DS.ArticleId = @locxArticleId
)
INSERT INTO DocPosition
(
DocId
, RowNumber
, PositionTypeId
, PositionNumber
, ParentPositionId
, ChildPositionNumber
,StatusId
,ArticleId
,Name1
,Name2
,Quantity
,QuantityOpen
,UoMId
,ShippingDate
,DeliveryDate
,Price
, ForeignCurrencyPrice 
,PredecessorId
,QuantityTransferred
,Level
,PositionLabel
,CatalogNumberId
,Dissolve
,PositionWeight
,ProjectId
,Start
,Stop
,PriceUnitId
,ArticleCostPrice
,DiscountPercent
,QuantityDiscountPercent
,DocDiscountPercent
, PrepaymentFactor
,RevenueEffective
,SalesPersonId
,CommissionPercent
, ProfitFactor
, CostPriceFactor
,FinanceGroupArticleId
,FinanceGroupPartnerDetailId
,TaxKeyId
, TaxFactor
,TaxPercent
,AccountId
,CostCenterId
,CostBearerId
,Warehousing
,WarehousingEffective
)
OUTPUT INSERTED.Id INTO @InsertedDocPositions
-- SELECT for Set DocPositions
SELECT
@locxDocId
, CASE WHEN @WithMacro = 0 THEN @calxNewRowNumber + CTE.ChildPositionNumber ELSE CTE.MacroRowNumber END
, DS.PositionTypeId
, CTE.PositionNumber
, CASE WHEN @WithMacro = 0 THEN @newxDocPositionId ELSE NULL END
, CTE.ChildPositionNumber
, 'open'
, DS.ComponentId
, A.Name1
, A.Name2
, CTE.CalcQuantity
, CTE.CalcQuantity
, A.UoMId
, GETDATE()
, ISNULL(DP.DeliveryDate, GETDATE())
, CASE WHEN (@ArticleSalesPriceListNameForeignCurrencyId IS NULL AND D.DocCategoryId = 'Sales') OR (D.DocCategoryId = 'Purchase') THEN ISNULL(CTE.CalcPrice, 0) ELSE CASE WHEN ISNULL(@Rate, 0) = 0 THEN 0 ELSE ROUND(ISNULL(CTE.CalcPrice, 0) / ISNULL(@Rate, 0), 2) END END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN (@ArticleSalesPriceListNameForeignCurrencyId IS NULL AND D.DocCategoryId = 'Sales') OR (D.DocCategoryId = 'Purchase') THEN ROUND(ISNULL(CTE.CalcPrice, 0) * ISNULL(@Rate, 0), 2) ELSE ISNULL(CTE.CalcPrice, 0) END ELSE NULL END
, NULL
, 0
, NULL
, CONCAT(FORMAT(@locxDocId, 'D10'), '-', FORMAT(CTE.PositionNumber, 'D6'), '-', FORMAT(CTE.ChildPositionNumber, 'D4'))
, CTE.CalcCatalogNumberId
, 0
, CTE.CalcQuantity * A.Weight
, @ProjectId
, NULL
, NULL
, A.PriceUnitId
, ISNULL(APC.CostPrice,0) / A.PriceUnitId
, CASE WHEN D.DocCategoryId = 'Sales' THEN ISNULL(PDG.DiscountPercent,0) ELSE ISNULL(PPPL.DiscountPercent, 0) END
, ISNULL(CTE.CalcQuantityDiscountPercent,0)
, ISNULL(PD.DocDiscountPercent,0)
, CASE WHEN A.IsPrepayment = 1 THEN DT.PrepaymentTrueArticleFactor ELSE DT.PrepaymentFalseArticleFactor END
, @RevenueEffective
, @SalesPersonId
, ISNULL(ECG.CommissionPercent,0)
, CASE WHEN A.IsPrepayment = 1 THEN 0 ELSE 1 END
, CASE WHEN @DocCategoryId= 'Purchase' THEN 0 ELSE 1 END
, CalcFinanceGroup
, @FinanceGroupPartnerDetailId
, FGAD.TaxKeyId
, CASE WHEN FTK.TaxKeyKindId = 3 THEN 0 ELSE 1 END
, ISNULL(FTKD.TaxPercent,0)
, FGAD.RevenueExpenditureAccountId
, PD.CostCenterId
, NULL
, A.Warehousing
, 0
FROM DataSource DS
LEFT JOIN Article A ON DS.ComponentId = A.Id
LEFT JOIN ArticlePriceCalculation APC ON APC.ArticleId = A.Id
LEFT JOIN DocPosition DP ON DP.Id = @newxDocPositionId
LEFT JOIN Doc D ON D.Id = @parxDocId
LEFT JOIN DocType DT ON DT.Id = D.DocTypeId
LEFT JOIN PartnerDetail PD ON PD.Id = @PartnerDetailId
LEFT JOIN PartnerDiscountGroup PDG ON PD.DiscountGroupNameId = PDG.DiscountGroupNameId AND A.ArticleGroupId = PDG.ArticleGroupId
LEFT JOIN CalcValuesCTE CTE ON CTE.Id = DS.Id
LEFT JOIN FinanceGroupArticleDetail FGAD ON FGAD.FinanceGroupArticleId = CTE.CalcFinanceGroup AND FGAD.FinanceGroupPartnerDetailId = @FinanceGroupPartnerDetailId
LEFT JOIN FinanceTaxKeyDetail FTKD ON FTKD.TaxKeyId = FGAD.TaxKeyId AND FTKD.ValidFrom = (SELECT MAX(ValidFrom) FROM FinanceTaxKeyDetail WHERE TaxKeyId = FGAD.TaxKeyId AND ValidFrom <= @DocDate)
LEFT JOIN FinanceTaxKey FTK ON FTK.Id = FTKD.TaxKeyId
LEFT JOIN Employee E ON E.Id = D.SalesPersonId
LEFT JOIN EmployeeCommissionGroup ECG ON ECG.ArticleGroupId = A.ArticleGroupId AND ECG.CommissionGroupId = E.CommissionGroupId
LEFT JOIN PartnerPurchasePriceList PPPL ON PPPL.PartnerId = PD.PartnerId AND PPPL.ArticleId = A.Id
-- UPDATE Child DocPositions with Extra Fields from Article
DECLARE @ExtraFieldChildArticleDocPositionValidationSql nvarchar(max);
DECLARE @ExtraFieldChildArticleDocPositionInvalidCondition nvarchar(max);
DECLARE @ExtraFieldChildArticleDocPositionInvalidCount int;
SELECT
@ExtraFieldChildArticleDocPositionInvalidCondition = STRING_AGG(
CAST(
CONCAT(
N'(A.'
, QUOTENAME(ArticleColumnName)
, N' IS NOT NULL AND TRY_CONVERT('
, TargetTypeSql
, N', A.'
, QUOTENAME(ArticleColumnName)
, N') IS NULL)'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N'OR '
)
FROM #ExtraFieldMappingArticleDocPosition;
IF @ExtraFieldChildArticleDocPositionInvalidCondition IS NOT NULL
BEGIN
SET @ExtraFieldChildArticleDocPositionValidationSql = CONCAT(
N'SELECT @ExtraFieldChildArticleDocPositionInvalidCount = COUNT(1)
FROM dbo.DocPosition AS DP
JOIN dbo.Article AS A
ON A.Id = DP.ArticleId
WHERE DP.Id IN (SELECT DocPositionId FROM #InsertedDocPositionsForExtraFields)
AND ('
, @ExtraFieldChildArticleDocPositionInvalidCondition
, N'
);'
);
DROP TABLE IF EXISTS #InsertedDocPositionsForExtraFields;
CREATE TABLE #InsertedDocPositionsForExtraFields (
DocPositionId int NOT NULL
);
INSERT INTO #InsertedDocPositionsForExtraFields (
DocPositionId
)
SELECT
DocPositionId
FROM @InsertedDocPositions;
EXEC sys.sp_executesql
@ExtraFieldChildArticleDocPositionValidationSql
, N'@ExtraFieldChildArticleDocPositionInvalidCount int OUTPUT'
, @ExtraFieldChildArticleDocPositionInvalidCount = @ExtraFieldChildArticleDocPositionInvalidCount OUTPUT;
IF @ExtraFieldChildArticleDocPositionInvalidCount > 0
BEGIN
THROW 50000, 'ExtraField value cannot be converted from Article to child DocPosition target data type.', 1;
END
END
DECLARE @ExtraFieldChildArticleDocPositionUpdateSql nvarchar(max);
DECLARE @ExtraFieldChildArticleDocPositionSetList nvarchar(max);
SELECT
@ExtraFieldChildArticleDocPositionSetList = STRING_AGG(
CAST(
CONCAT(
QUOTENAME(DocPositionColumnName)
, N' = TRY_CONVERT('
, TargetTypeSql
, N', A.'
, QUOTENAME(ArticleColumnName)
, N')'
)
AS nvarchar(max))
, CHAR(13) + CHAR(10) + N', '
)
FROM #ExtraFieldMappingArticleDocPosition;
IF @ExtraFieldChildArticleDocPositionSetList IS NOT NULL
BEGIN
SET @ExtraFieldChildArticleDocPositionUpdateSql = CONCAT(
N'UPDATE DP
SET '
, @ExtraFieldChildArticleDocPositionSetList
, N'
FROM dbo.DocPosition AS DP
JOIN dbo.Article AS A
ON A.Id = DP.ArticleId
JOIN #InsertedDocPositionsForExtraFields AS IDP
ON IDP.DocPositionId = DP.Id;'
);
EXEC sys.sp_executesql
@ExtraFieldChildArticleDocPositionUpdateSql;
END
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
IDP.DocPositionId
, CASE WHEN D.StandardWarehouseId IS NOT NULL THEN D.StandardWarehouseId ELSE A.StandardWarehouseId END
, NULL
, A.IndividualizationTypeId
, NULL
, DP.Quantity
, 0
FROM @InsertedDocPositions IDP
LEFT JOIN DocPosition DP ON DP.Id = IDP.DocPositionId
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.Warehousing = 1 AND @Draft= 1
INSERT INTO DocPositionInfoText (DocPositionId, InfoText)
SELECT IDP.DocPositionId, AIT.InfoText
FROM @InsertedDocPositions IDP
LEFT JOIN DocPosition DP ON IDP.DocPositionId = DP.Id
JOIN ArticleInfoText AIT On AIT.ArticleId= DP.ArticleId
INSERT INTO DocPositionOrderText (DocPositionId, OrderText)
SELECT IDP.DocPositionId, AOT.OrderText
FROM @InsertedDocPositions IDP
LEFT JOIN DocPosition DP ON IDP.DocPositionId = DP.Id
JOIN ArticleOrderText AOT On AOT.ArticleId= DP.ArticleId
INSERT INTO DocPositionDimensionText (DocPositionId, DimensionText)
SELECT IDP.DocPositionId, ADT.DimensionText
FROM @InsertedDocPositions IDP
LEFT JOIN DocPosition DP ON IDP.DocPositionId = DP.Id
JOIN ArticleDimensionText ADT On ADT.ArticleId= DP.ArticleId
DROP TABLE #ComponentIds;
END --IF(@WithSet  = 1 OR @WithMacro = 1 OR EXISTS (SELECT 1 FROM ArticleAccessory WHERE ArticleId = @parxArticleId))
-- 51.) CALCULATE DocStatus
DECLARE @NewStatus NVARCHAR(50);
IF EXISTS (SELECT 1 FROM DocPosition WHERE DocId = @locxDocId AND StatusId NOT IN ('open', 'Text'))
BEGIN
SET @NewStatus = 'partially';
END
ELSE
BEGIN
SET @NewStatus = 'open';
END
-- 59.) UPDATE Doc Status
UPDATE Doc
SET
StatusId = @NewStatus
, Transferable = CASE
WHEN EXISTS (
SELECT 1
FROM DocPosition
WHERE DocId = @locxDocId AND PositionTypeId IN ('Alternative', 'Possible', 'Optional')
) THEN 0
ELSE Transferable
END
FROM Doc D
WHERE D.Id = @locxDocId;
-- 90.) RETURN
DECLARE @ISERROR BIT = 0
IF EXISTS (
SELECT 1
FROM xVIEW220_DocPosition
WHERE (Id = @newxDocPositionId OR ParentPositionId = @newxDocPositionId OR Id IN (SELECT DocPositionId FROM @InsertedDocPositions))
AND (RevenueEffective != 0 OR WarehousingEffective != 0 OR InventoryStatusId IS NOT NULL)
AND PositionTypeId IN ('Optional', 'Alternative', 'Rejected', 'Possible')
)
BEGIN
SET @ISERROR = 1
SELECT 0 AS ID, 'Invalid position type for this document type' AS ERROR_MESS
END
ELSE
BEGIN
SELECT xVIEW220_DocPosition.Id, '' AS ERROR_MESS FROM xVIEW220_DocPosition WHERE Id = @newxDocPositionId OR ParentPositionId = @newxDocPositionId OR Id IN (SELECT DocPositionId FROM @InsertedDocPositions)
END
-- 91.) ERROR HANDLING
IF @ISERROR = 1
ROLLBACK TRANSACTION;
ELSE
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC220I_DocPosition_InsertArticle ----------------------------------------------------------------------
-- xPROC220I_DocPosition_GetComponentHierarchy ----------------------------------------------------------------------
-- PURPOSE: Recursively builds a multi-level component hierarchy for a given article and partner type
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) SPECIAL OPERATION
-- 30.) DocPosition
-- 40.) Doc
-- 60.) PredecessorPosition.QuantityOpen and PredecessorPosition.StatusId 
-- 70.) PredecessorDoc.DocStatusId
-- 80.) ArticleQuantity
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC220I_DocPosition_GetComponentHierarchy
-- 26.06.26 03:45
@parxArticleId NVARCHAR(30),
@parxPartnerType NVARCHAR(30)
AS
BEGIN
SET NOCOUNT ON;
DECLARE @ArticleId NVARCHAR(30);
DECLARE @PartnerType NVARCHAR(30);
BEGIN TRY
SET @ArticleId = @parxArticleId;
SET @PartnerType = @parxPartnerType;
CREATE TABLE #hierarchaldata (
Id INT PRIMARY KEY IDENTITY
,ArticleId VARCHAR(50)
,ParentId INT NULL
,Inserting BIT
, QuantityFactor DECIMAL(19,6) NULL
, PositionTypeId NVARCHAR(15)
);
--[[LEVEL -0 MASTER
INSERT INTO #hierarchaldata(
ArticleId
,ParentId
,Inserting
, QuantityFactor
, PositionTypeId
)
SELECT @ArticleId
,NULL
, 0
,NULL
, DPT.Name
FROM DocPositionType DPT
WHERE Id = 'Article'
--]]
--[[LEVEL -1
DECLARE @ParentId1 INT
SET @ParentId1 = 1
INSERT INTO #hierarchaldata(
ArticleId
, ParentId
, Inserting
, QuantityFactor
, PositionTypeId
)
SELECT ComponentId
,@ParentId1
,Inserting
, QuantityFactor
, DPT.Name
FROM ArticleAccessory AA
LEFT JOIN DocPositionType DPT ON DPT.Id = AA.PositionTypeId
WHERE ArticleId = @ArticleId
AND ( (@PartnerType = 'Customer' AND CustomerSide = 1) OR (@PartnerType = 'Supplier' AND SupplierSide = 1) );
--AND 1 =
