,PredecessorId
,QuantityTransferred
,Level
,PositionLabel
,Dissolve
,PositionWeight
,ProjectId
,Start
,Stop
,PriceUnitId
,ArticleCostPrice
,DiscountPercent
,QuantityDiscountPercent
,DocDiscountPercent
,RevenueEffective
,SalesPersonId
,CommissionPercent
,FinanceGroupArticleId
,FinanceGroupPartnerDetailId
,TaxKeyId
,TaxPercent
,AccountId
,CostCenterId
,CostBearerId
,Warehousing
,WarehousingEffective
)
-- VALUES DocPosition
VALUES
(
@parxDocId
, 'Text'
