, NULL
, 0
, 0
, NULL
, GETDATE()
, GETDATE()
, 0
, NULL
, 0
, NULL
, NULL
, 0
, 0
, NULL
, NULL
, NULL
, 1
, 0
, 0
, 0
, 0
, 0
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, NULL
, 0
, NULL
)
