-- xPROC220D_DocPosition_Delete
-- Creator: MH
-- Created: 2023-07-19
-- PURPOSE: Delete Position and possible Subpositions for passed Article. Update Sums
-- 5.) DECLARE, SELECT, CALCULATE
-- 10.) UPDATE Procurement
-- 11.) RECURSIVE DELETE for child positions
-- 19.) DELETE from DocPositionWarehousing 
-- 20.) DELETE DocPosition
-- 2.) Update Predecessor DocPosition.QuantityOpen, Predecessor PositionStatusId
-- 3.) Update Predecessor Doc.StatusId
-- 4.) Calculate Doc.Transferable
-- 5.) Calculate Doc Status
-- 7.) Update Doc Sums and Status
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE xPROC220D_DocPosition_Delete
@parxDocPositionId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
-- DECLARE FROM parameter
DECLARE @locxDocPositionId INT = @parxDocPositionId
IF NOT EXISTS (SELECT 1 FROM DocPosition WHERE PredecessorId = @locxDocPositionId OR (Id = @locxDocPositionId AND StatusId = 'manually'))
BEGIN
-- 10.) UPDATE Procurement
DELETE FROM Procurement
WHERE OrderConfirmationPositionId = @parxDocPositionId 
UPDATE Procurement SET
PurchaseOrderPosId = null
FROM Procurement P
LEFT JOIN DocPosition DP ON DP.Id = @parxDocPositionId 
WHERE PurchaseOrderPosId = @parxDocPositionId 
-- 11.) RECURSIVE DELETE for child positions
CREATE TABLE #TempTable (ChildDocPositionId INT);
INSERT INTO #TempTable (ChildDocPositionId)
SELECT Id
FROM DocPosition
WHERE ParentPositionId = @parxDocPositionId;
WHILE EXISTS (SELECT 1 FROM #TempTable)
BEGIN
DECLARE @ChildDocPositionId INT;
-- Get first Id
SELECT TOP 1 @ChildDocPositionId = ChildDocPositionId FROM #TempTable;
-- Execute Delete Procedure with new Id
EXEC xPROC220D_DocPosition_Delete @ChildDocPositionId;
-- Delete Id from temp table
DELETE FROM #TempTable WHERE ChildDocPositionId = @ChildDocPositionId;
END
DROP TABLE #TempTable;
-- FROM DocPosition
DECLARE @DocId INT
DECLARE @ArticleId NVARCHAR(30)
DECLARE @Quantity DECIMAL(19,6)
DECLARE @QuantityOpen DECIMAL(19,6)
DECLARE @WarehousingQuantity DECIMAL(19,6)
DECLARE @PredecessorId INT
DECLARE @QuantityTransferred DECIMAL(19,6)
DECLARE @StatusId  NVARCHAR(12)
DECLARE @PositionTypeId NVARCHAR(15)
DECLARE @Warehousing BIT
SELECT
@DocId = DocId
, @ArticleId = ArticleId
, @Quantity = Quantity
, @QuantityOpen = QuantityOpen
, @WarehousingQuantity = WarehousingQuantity
, @PredecessorId = PredecessorId
, @QuantityTransferred = QuantityTransferred
, @StatusId = StatusId
, @PositionTypeId = PositionTypeId 
, @Warehousing = A.Warehousing 
FROM DocPosition DP
JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.Id = @locxDocPositionId
IF @StatusId != 'Text'
BEGIN
-- FROM Doc
DECLARE @InventoryStatusId NVARCHAR(10)
DECLARE @RevenueEffective INT
SELECT
@InventoryStatusId = InventoryStatusId
, @RevenueEffective = RevenueEffective 
FROM Doc
WHERE Id = @DocId
-- FROM Predecessor DocPosition
DECLARE @PredecessorDocId INT
SELECT
@PredecessorDocId = DocId
From DocPosition 
WHERE Id = @PredecessorId
-- FROM Predecessor Doc
DECLARE @PredecessorInventoryStatusId NVARCHAR(10)
SELECT
@PredecessorInventoryStatusId = InventoryStatusId
FROM Doc
WHERE Id = @PredecessorDocId
END -- IF @StatusId != 'Text'
-- 19.) DELETE from DocPositionWarehousing 
DELETE FROM DocPositionWarehousing WHERE DocPositionId = @locxDocPositionId
-- 20.) DELETE DocPosition
DELETE FROM DocPosition WHERE Id = @locxDocPositionId
IF @StatusId != 'Text'
BEGIN
-- 2.) Update Predecessor DocPosition.QuantityOpen, Predecessor PositionStatusId
UPDATE DocPosition
SET
QuantityOpen = QuantityOpen + @QuantityTransferred
,StatusId = CASE
WHEN QuantityOpen + @QuantityTransferred = Quantity THEN 'open'
WHEN QuantityOpen + @QuantityTransferred < Quantity AND QuantityOpen - @QuantityTransferred > 0 THEN 'partially'
WHEN QuantityOpen + @QuantityTransferred = 0 THEN 'closed'
END
WHERE Id = @PredecessorId;
-- 3.) Update Predecessor Doc.StatusId
UPDATE Doc
SET StatusId = (
SELECT
CASE
WHEN SUM(CASE WHEN StatusId = 'closed' THEN 1 ELSE 0 END) = SUM(1) THEN 'closed'
WHEN SUM(CASE WHEN StatusId = 'open' THEN 1 ELSE 0 END) = SUM(1) THEN 'open'
ELSE 'partially'
END
FROM DocPosition
WHERE DocId = @PredecessorDocId AND PositionTypeId = 'Article'
)
WHERE Id = @PredecessorDocId ;
-- 4.) Calculate Doc.Transferable
DECLARE @Transferable BIT
SET @Transferable = (
SELECT
CASE WHEN EXISTS
(SELECT 1 FROM DocPosition WHERE DocId = @DocId AND PositionTypeId IN ('Optional', 'Alternative', 'Possible')) THEN 0
ELSE 1
END );
-- 5.) Calculate Doc Status
DECLARE @TotalCount INT, @OpenCount INT, @ClosedCount INT, @ManuallyCount INT;
SELECT
@TotalCount = COUNT(*),
@OpenCount = COUNT(CASE WHEN StatusId = 'open' THEN 1 END),
@ClosedCount = COUNT(CASE WHEN StatusId = 'closed' THEN 1 END),
@ManuallyCount = COUNT(CASE WHEN StatusId = 'manually' THEN 1 END)
FROM DocPosition 
WHERE DocId = @DocId AND PositionTypeId = 'Article';
DECLARE @NewStatus NVARCHAR(50);
IF @OpenCount = @TotalCount
SET @NewStatus = 'open';
ELSE IF @ClosedCount = @TotalCount
SET @NewStatus = 'closed';
ELSE IF @ManuallyCount > 0 AND (@ManuallyCount + @ClosedCount = @TotalCount)
SET @NewStatus = 'manually';
ELSE
SET @NewStatus = 'partially';
-- 7.) Update Doc Sums and Status
UPDATE Doc
SET
StatusId = @NewStatus
, Transferable = @Transferable
FROM Doc D
WHERE D.Id = @DocId;
END -- IF @StatusId != 'Text'
END --IF NOT EXISTS (SELECT 1 FROM DocPosition WHERE PredecessorId = @locxDocPositionId) BEGIN
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH;
END
GO
-- END xPROC220D_DocPosition_Delete---------------------------------------------------------------
-- xPROC220U_DocPosition_Update ----------------------------------------------------------------------
-- PURPOSE: Update Position and possible Subposition values for changes Quantity, Price or Discount. Update Sums
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) IF @PredecessorId IS NOT NULL: Calculating Predecessor.QuantityOpen
-- 30.) Updating Predecessor.QuantityOpen and PredecessorPosition.StatusId
-- 40.) Updating Predecessor.DocStatus.Id
-- 50.) Calculating DocPosition Sums
-- 60.) Updating DocPosition
-- 61.) Updating Warehousing
-- 65.) UPDATE Set Doc Positions
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC220U_DocPosition_Update
@parxDocPositionId INT,
@parxQuantity DECIMAL (19,6),
@parxPrice DECIMAL (19,6),
@parxDiscountPercent DECIMAL (19,6)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
-- 11.) FROM parameter
DECLARE @locxDocPositionId INT= @parxDocPositionId
DECLARE @locxQuantity DECIMAL(19,6) = @parxQuantity
DECLARE @locxPrice DECIMAL(19,6) = @parxPrice
DECLARE @locxDiscountPercent DECIMAL (19,6) = @parxDiscountPercent
-- 12.) FROM DocPosition
DECLARE @DocId INT
DECLARE @ArticleId NVARCHAR(30)
DECLARE @Quantity DECIMAL(19,6)
DECLARE @PredecessorId INT
DECLARE @QuantityTransferred DECIMAL(19,6)
DECLARE @QuantityOpen DECIMAL(19,6)
DECLARE @QuantityDiscountPercent DECIMAL(19,6)
DECLARE @DocDiscountPercent DECIMAL(19,6)
DECLARE @StatusId NVARCHAR(12)
SELECT
@DocId = DocId,
@ArticleId= ArticleId,
@Quantity = Quantity,
@PredecessorId = PredecessorId,
@QuantityTransferred = QuantityTransferred,
@QuantityOpen = QuantityOpen,
@QuantityDiscountPercent = ISNULL(QuantityDiscountPercent,0),
@DocDiscountPercent = ISNULL(DocDiscountPercent,0),
@StatusId = StatusId
FROM DocPosition WHERE Id = @locxDocPositionId
-- 13.) FROM Doc
DECLARE @DocCategoryId NVARCHAR(10)
DECLARE @PriceListId INT
DECLARE @PartnerDetailId INT
DECLARE @PartnerId INT
DECLARE @QuantityDiscountRecalculation BIT
DECLARE @InventoryStatusId NVARCHAR(10)
DECLARE @DocStatusId NVARCHAR(12)
DECLARE @Draft BIT
DECLARE @ForeignCurrencyId NVARCHAR(3)
DECLARE @Rate DECIMAL(19,6)
SELECT
@DocCategoryId = D.DocCategoryId
, @PriceListId= D.PriceListId
, @PartnerDetailId = D.PartnerDetailId
, @PartnerId = D.PartnerId
, @QuantityDiscountRecalculation = DT.QuantityDiscountRecalculation
, @InventoryStatusId = D.InventoryStatusId
, @DocStatusId = D.StatusId 
, @Draft = D.Draft 
, @ForeignCurrencyId = D.ForeignCurrencyId 
, @Rate= D.Rate
FROM Doc D
INNER JOIN DocType DT ON D.DocTypeId = DT.Id 
WHERE D.Id = @DocId
-- 14.) FROM Article
DECLARE @Weight DECIMAL(19,6)
DECLARE @ArticleGroupId INT
DECLARE @Warehousing BIT
SELECT
@Weight = Weight
, @ArticleGroupId = ArticleGroupId
, @Warehousing = Warehousing 
FROM Article WHERE Id = @ArticleId
-- 15.) FROM ArticlePriceCalculation
DECLARE @CostPrice DECIMAL(19,6)
SELECT
@CostPrice = CostPrice
FROM ArticlePriceCalculation WHERE ArticleId = @ArticleId
-- 16.) FROM PartnerDetail
DECLARE @DiscountGroupNameId INT
SELECT
@DiscountGroupNameId = DiscountGroupNameId
FROM PartnerDetail WHERE Id = @PartnerDetailId
-- 17.) FROM Predecessor Doc Position
DECLARE @PredecessorDocId INT
SELECT
@PredecessorDocId = DocId 
FROM DocPosition WHERE Id = @PredecessorId
-- 18.) FROM Predecessor Doc
DECLARE @PredecessorDocCategoryId NVARCHAR(10)
SELECT
@PredecessorDocCategoryId = DocCategoryId 
FROM Doc WHERE Id = @PredecessorDocId
DECLARE @SalesPriceListForeignCurrencyId NVARCHAR(3)
SELECT
@SalesPriceListForeignCurrencyId = ForeignCurrencyId
FROM ArticleSalesPriceListName
WHERE Id = @PriceListId
DECLARE @calxQuantityDifference DECIMAL(19, 6) = @locxQuantity - @Quantity
DECLARE @calxQuantityTransferredDifference DECIMAL(19, 6) = @locxQuantity - @QuantityTransferred
-- 20.) IF @PredecessorId IS NOT NULL: Calculating Predecessor.QuantityOpen
IF @PredecessorId IS NOT NULL AND @DocCategoryId = @PredecessorDocCategoryId BEGIN
DECLARE @oldxPredecessorQuantityOpen DECIMAL(19, 6)
DECLARE @PredecessorQuantity DECIMAL(19,6)
DECLARE @PredecessorStatusId NVARCHAR(11)
DECLARE @PredecessorInventoryStatusId NVARCHAR(10)
SELECT
@oldxPredecessorQuantityOpen = DP.QuantityOpen
, @PredecessorQuantity = DP.Quantity
, @PredecessorStatusId = DP.StatusId
, @PredecessorInventoryStatusId = D.InventoryStatusId
FROM DocPosition DP
JOIN Doc D ON D.Id = DP.DocId
WHERE DP.Id = @PredecessorId
DECLARE @calxPredecessorQuantityOpen DECIMAL(19,6)
IF @calxQuantityDifference > 0 AND @oldxPredecessorQuantityOpen - @calxQuantityDifference > 0 BEGIN 
SET @calxPredecessorQuantityOpen = @oldxPredecessorQuantityOpen - @calxQuantityDifference ;
SET @QuantityTransferred = ISNULL(@QuantityTransferred + @calxQuantityDifference,0) ;
SET @PredecessorStatusId = 'partially'
END
ELSE IF @calxQuantityDifference > 0 AND @oldxPredecessorQuantityOpen - @calxQuantityDifference <= 0 BEGIN
SET @QuantityTransferred = ISNULL(@QuantityTransferred + @oldxPredecessorQuantityOpen,0)
SET @calxPredecessorQuantityOpen = 0
SET @PredecessorStatusId = 'closed'
END
ELSE IF @calxQuantityDifference < 0 AND @calxQuantityTransferredDifference < 0 BEGIN
SET @QuantityTransferred = ISNULL(@QuantityTransferred + @calxQuantityTransferredDifference,0)
SET @calxPredecessorQuantityOpen = @oldxPredecessorQuantityOpen - @calxQuantityTransferredDifference
IF @PredecessorQuantity = @calxPredecessorQuantityOpen BEGIN
SET @PredecessorStatusId = 'open' END
IF @PredecessorQuantity > @calxPredecessorQuantityOpen BEGIN
SET @PredecessorStatusId = 'partially' END
END
ELSE IF @calxQuantityDifference < 0 AND (@calxQuantityTransferredDifference > 0 OR @calxQuantityTransferredDifference = 0) BEGIN
SET @QuantityTransferred = ISNULL(@QuantityTransferred,0)
SET @calxPredecessorQuantityOpen = @oldxPredecessorQuantityOpen
END
ELSE IF @calxQuantityDifference = 0
SET @calxPredecessorQuantityOpen = @oldxPredecessorQuantityOpen;
-- 30.) Updating Predecessor.QuantityOpen and PredecessorPosition.StatusId
UPDATE DocPosition SET
QuantityOpen = @calxPredecessorQuantityOpen
,StatusId = @PredecessorStatusId
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocContract DC ON DC.DocId = D.Id
WHERE DP.Id = @PredecessorId AND DC.DocId IS NULL
UPDATE DP SET
DP.QuantityOpen = ISNULL(@calxPredecessorQuantityOpen * (DP.Quantity/NULLIF(ParentDP.Quantity,0)),0)
,DP.StatusId = @PredecessorStatusId
FROM DocPosition DP
LEFT JOIN DocPosition ParentDP ON ParentDP.Id = DP.ParentPositionId
LEFT JOIN Article ParentA ON ParentA.Id = ParentDP.ArticleId
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocContract DC ON DC.DocId = D.Id
WHERE DP.ParentPositionId = @PredecessorId AND DP.StatusId != 'manually' AND ParentA.WithSet= 1 AND DC.DocId IS NULL
DECLARE @calxPredecessorQuantityOpenDifference DECIMAL(19,6)
IF @PredecessorId IS NOT NULL BEGIN
SET @calxPredecessorQuantityOpenDifference = @calxPredecessorQuantityOpen - @oldxPredecessorQuantityOpen END
ELSE BEGIN
SET @calxPredecessorQuantityOpenDifference = 0 END
-- 40.) Updating Predecessor.DocStatus.Id
UPDATE Doc
SET StatusId = (
SELECT
CASE
WHEN SUM(CASE WHEN StatusId = 'closed' THEN 1 ELSE 0 END) = SUM(1) THEN 'closed'
WHEN SUM(CASE WHEN StatusId = 'open' THEN 1 ELSE 0 END) = SUM(1) THEN 'open'
WHEN SUM(CASE WHEN StatusId = 'closed' OR StatusId = 'manually' THEN 1 ELSE 0 END) = SUM(1) THEN 'manually'
ELSE 'partially'
END
FROM DocPosition
WHERE DocId = @PredecessorDocId AND PositionTypeId = 'Article'
)
FROM Doc D
LEFT JOIN DocContract DC ON DC.DocId = D.Id
WHERE D.Id = @PredecessorDocId AND DC.DocId IS NULL;
END
-- 50.) Calculating DocPosition Sums
DECLARE @calxQuantityDiscountPercent DECIMAL(19,6)
IF @QuantityDiscountRecalculation = 1 AND @DiscountGroupNameId IS NOT NULL BEGIN 
SELECT
@calxQuantityDiscountPercent = CASE
WHEN @locxQuantity >= QuantityLevelE AND QuantityLevelE > 0 AND (ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 OR @DocCategoryId = 'Sales') THEN QuantityDiscountE
WHEN @locxQuantity >= QuantityLevelD AND QuantityLevelD > 0 AND  (ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 OR @DocCategoryId = 'Sales') THEN QuantityDiscountD
WHEN @locxQuantity >= QuantityLevelC AND QuantityLevelC > 0 AND  (ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 OR @DocCategoryId = 'Sales') THEN QuantityDiscountC
WHEN @locxQuantity >= QuantityLevelB AND QuantityLevelB > 0 AND  (ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 OR @DocCategoryId = 'Sales') THEN QuantityDiscountB
WHEN @locxQuantity >= QuantityLevelA AND QuantityLevelA > 0 AND  (ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 OR @DocCategoryId = 'Sales') THEN QuantityDiscountA
ELSE 0
END --- CASE
FROM PartnerDiscountGroup PDG
LEFT JOIN PartnerPurchasePriceList PPPL ON PPPL.ArticleId = @ArticleId AND PPPL.PartnerId = @PartnerId AND @DocCategoryId = 'Purchase'
WHERE ArticleGroupId = @ArticleGroupId AND DiscountGroupNameId= @DiscountGroupNameId;
END --IF @QuantityDiscountRecalculation = 1 BEGIN
ELSE BEGIN SET @calxQuantityDiscountPercent = @QuantityDiscountPercent
END --ELSE 
DECLARE @calxPositionWeight DECIMAL(19, 6) = ISNULL(@locxQuantity * @Weight, 0);
-- 60.) Updating DocPosition
UPDATE DocPosition SET
Quantity = @locxQuantity
, QuantityOpen = CASE WHEN StatusId = 'open' THEN @locxQuantity ELSE @QuantityOpen END
, Price = @locxPrice 
, ForeignCurrencyPrice = CASE WHEN @ForeignCurrencyId IS NOT NULL AND ((@SalesPriceListForeignCurrencyId IS NULL AND @DocCategoryId = 'Sales') OR (@DocCategoryId = 'Purchase')) THEN ROUND(@locxPrice * ISNULL(@Rate, 0), 2) ELSE ForeignCurrencyPrice END
, QuantityTransferred = @QuantityTransferred
, PositionWeight = @calxPositionWeight
, ArticleCostPrice = @CostPrice
, DiscountPercent = @locxDiscountPercent
, QuantityDiscountPercent = ISNULL(@calxQuantityDiscountPercent,0)
WHERE Id = @locxDocPositionId;
-- 61.) Updating DocPositionWarehousing 
IF (SELECT COUNT(*) FROM DocPositionWarehousing WHERE DocPositionId = @locxDocPositionId) = 1 BEGIN
UPDATE DocPositionWarehousing 
SET
Quantity = @locxQuantity
WHERE DocPositionId= @locxDocPositionId AND IndividualizationTypeId != 'Serial'
END -- IF @Warehousing == 1 BEGIN
-- 65.) UPDATE Set Doc Positions
CREATE TABLE #DataSource (
DocPositionId INT,
CalculatedQuantityDiscountPercent DECIMAL(19,6)
);
INSERT INTO #DataSource (DocPositionId, CalculatedQuantityDiscountPercent)
SELECT
DocPositionId
, CalculatedQuantityDiscountPercent
FROM (
SELECT
DP.Id AS DocPositionId,
CASE
WHEN IIF(@Quantity = 0, 0, DP.Quantity * (@parxQuantity/@Quantity)) >= PDG.QuantityLevelE AND PDG.QuantityLevelE > 0 AND ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 THEN PDG.QuantityDiscountE
WHEN IIF(@Quantity = 0, 0, DP.Quantity * (@parxQuantity/@Quantity)) >= PDG.QuantityLevelD AND PDG.QuantityLevelD > 0 AND ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 THEN PDG.QuantityDiscountD
WHEN IIF(@Quantity = 0, 0, DP.Quantity * (@parxQuantity/@Quantity)) >= PDG.QuantityLevelC AND PDG.QuantityLevelC > 0 AND ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 THEN PDG.QuantityDiscountC
WHEN IIF(@Quantity = 0, 0, DP.Quantity * (@parxQuantity/@Quantity)) >= PDG.QuantityLevelB AND PDG.QuantityLevelB > 0 AND ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 THEN PDG.QuantityDiscountB
WHEN IIF(@Quantity = 0, 0, DP.Quantity * (@parxQuantity/@Quantity)) >= PDG.QuantityLevelA AND PDG.QuantityLevelA > 0 AND ISNULL(PPPL.DiscountGroupAssigned, 0) = 1 THEN PDG.QuantityDiscountA
ELSE 0
END AS CalculatedQuantityDiscountPercent
FROM DocPosition DP
LEFT JOIN PartnerDetail PD ON PD.Id = @PartnerDetailId
LEFT JOIN Article A ON A.Id = DP.ArticleId
LEFT JOIN PartnerDiscountGroup PDG ON PDG.DiscountGroupNameId = PD.DiscountGroupNameId AND PDG.ArticleGroupId = A.ArticleGroupId
LEFT JOIN PartnerPurchasePriceList PPPL ON PPPL.ArticleId = A.Id AND PPPL.PartnerId = PD.PartnerId AND @DocCategoryId = 'Purchase'
WHERE DP.ParentPositionId = @parxDocPositionId
) AS DataSource
UPDATE DP
SET
Quantity = Q.NewQuantity
, QuantityOpen = CASE WHEN @StatusId = 'open' THEN Q.NewQuantity ELSE DP.QuantityOpen END
, QuantityTransferred = Q.NewQuantityTransferred
, PositionWeight = Q.NewQuantity * ISNULL(A.Weight, 0)
, ArticleCostPrice = ISNULL(APC.CostPrice, 0) / NULLIF(A.PriceUnitId, 0)
, QuantityDiscountPercent = CASE WHEN DP.Price = 0 THEN 0 ELSE DS.CalculatedQuantityDiscountPercent END
FROM DocPosition DP
LEFT JOIN Article A
ON DP.ArticleId = A.Id
LEFT JOIN ArticlePriceCalculation APC
ON DP.ArticleId = APC.ArticleId
LEFT JOIN DocPosition ParentDP
ON ParentDP.Id = @locxDocPositionId
LEFT JOIN Article ParentA
ON ParentA.Id = ParentDP.ArticleId
LEFT JOIN #DataSource DS
ON DS.DocPositionId = DP.Id
CROSS APPLY
(
SELECT
IIF(@Quantity = 0, 0, DP.Quantity * (@parxQuantity / @Quantity)) AS NewQuantity
, IIF(@Quantity = 0, 0, DP.QuantityTransferred * (@parxQuantity / @Quantity)) AS NewQuantityTransferred
) Q
WHERE DP.ParentPositionId = @locxDocPositionId
AND ParentA.WithSet = 1;
-- 66.) Updating DocPositionWarehousing for Set
UPDATE DocPositionWarehousing 
SET
Quantity = DP.Quantity
FROM DocPositionWarehousing DPW
LEFT JOIN DocPosition DP ON DP.Id = DPW.DocPositionId
LEFT JOIN Article A ON A.Id = DP.ArticleId
LEFT JOIN DocPosition ParentDP ON ParentDP.Id = DP.ParentPositionId
LEFT JOIN Article ParentA ON ParentA.Id= ParentDP.ArticleId
WHERE DP.ParentPositionId = @locxDocPositionId AND A.Warehousing = 1   AND (SELECT COUNT(*) FROM DocPositionWarehousing AS DPW2 WHERE DPW2.DocPositionId = DPW.DocPositionId) = 1 AND DPW.IndividualizationTypeId != 'Serial' AND ParentA.WithSet = 1
IF EXISTS (SELECT * FROM sys.tables WHERE name = '#DataSource')
DROP TABLE #DataSource;
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC220U_DocPosition_Update ----------------------------------------------------------------------
-- xPROC220U_DocPosition_ForeignCurrencyPrice--------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC220U_DocPosition_ForeignCurrencyPrice
-- PURPOSE: Update the ForeignCurrencyPrice with passed value
@parDocPositionId INT,
@parForeignCurrencyPrice DECIMAL(19,6)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE DocPosition SET ForeignCurrencyPrice = @parForeignCurrencyPrice WHERE Id = @parDocPositionId;
DECLARE @Quantity DECIMAL(19,6)
DECLARE @DiscountPercent DECIMAL(19,6)
DECLARE @Price DECIMAL(19,6)
SELECT
@Quantity = Quantity
, @DiscountPercent = DiscountPercent 
, @Price = ROUND(@parForeignCurrencyPrice/COALESCE(NULLIF(D.Rate,0), 1), 2)
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
WHERE DP.Id = @parDocPositionId
EXEC xPROC220U_DocPosition_Update
@parxDocPositionId = @parDocPositionId ,
@parxQuantity = @Quantity ,
@parxPrice = @Price,
@parxDiscountPercent = @DiscountPercent;
SELECT @Price AS NewPrice
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC220U_DocPosition_ForeignCurrencyPrice--------------------------------------------------------------------------------------------
