-- PURPOSE: Set Position and Children to manually after Position close manually is pressed (QuantityOpen gets set to 0, following values like OrderedQuantity are handled by a View)
--1 DECLARE and SELECT
--3 UPDATE DocPosition
--4 UPDATE Doc.StatusId
--5 RETURN
-- xPROC226U_DocPosition_StatusId --------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC226U_DocPosition_StatusId
@parxDocPositionId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 11.) RECURSIVE DELETE for child positions
CREATE TABLE #TempTable (ChildDocPositionId INT);
INSERT INTO #TempTable (ChildDocPositionId)
SELECT Id
FROM DocPosition
WHERE ParentPositionId = @parxDocPositionId;
WHILE EXISTS (SELECT 1 FROM #TempTable)
BEGIN
DECLARE @ChildDocPositionId INT;
-- Get first Id
SELECT TOP 1 @ChildDocPositionId = ChildDocPositionId FROM #TempTable;
-- Execute StatusId Procedure with new Id
EXEC xPROC226U_DocPosition_StatusId @ChildDocPositionId;
-- Delete Id from temp table
DELETE FROM #TempTable WHERE ChildDocPositionId = @ChildDocPositionId;
END
DROP TABLE #TempTable;
DECLARE @DocId INT
SELECT 
@DocId = DocId
FROM DocPosition
WHERE Id = @parxDocPositionId
UPDATE DocPosition SET
StatusId = 'manually' 
, QuantityOpen = 0
WHERE Id = @parxDocPositionId;
IF NOT EXISTS (SELECT 1 FROM DocPosition WHERE DocId = @DocId AND PositionTypeId != 'Text' AND PositionTypeId != 'Auto' AND StatusId NOT IN ('closed', 'manually'))
BEGIN
-- Wenn ja, aktualisiere den Status des zugehörigen Doc
UPDATE Doc
SET StatusId = 'manually'
WHERE Id = @DocId;
END
ELSE BEGIN
UPDATE Doc
SET StatusId = 'partially'
WHERE Id = @DocId;
END
-- 90.) RETURN
SELECT * FROM xVIEW220_DocPosition WHERE Id = @parxDocPositionId OR ParentPositionId = @parxDocPositionId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC226U_DocPosition_StatusId----------------------------------------------------------------
-- xPROC226U_DocPosition_SalesPersonId-------------------------------------------------------------------------
-- PURPOSE: Update the SalesPersonId with passed value and recalculate the commission
-- 1.)  Declare and Select
-- 2.) Select DocPosition.CommissionPercent
-- 3.) Calculate DocPosition.CommissionAmount
-- 4.) Update DocPosition.CommissionPercent, DocPosition.CommissionAmount
-- 5.) Calculate Doc Sums
-- 6.) Update Doc Sums
-- 7.) Return
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC226U_DocPosition_SalesPersonId
@parxDocPositionId INT
, @parxSalesPersonId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @DocId INT
, @ArticleId NVARCHAR(30)
, @TotalPrice DECIMAL(19,6)
, @PartnerId INT
, @PartnerGroupId INT
, @ArticleGroupId INT
, @PartnerDetailId INT
SELECT
@DocId = DP.DocId
, @ArticleId = DP.ArticleId
, @TotalPrice = DP.TotalPrice
FROM DocPosition DP
WHERE DP.Id = @parxDocPositionId
SELECT
@PartnerId = D.PartnerId
, @PartnerDetailId = D.PartnerDetailId
FROM Doc D
WHERE D.Id = @DocId
SELECT
@PartnerGroupId = P.PartnerGroupId
FROM Partner P
WHERE P.Id = @PartnerId
SELECT
@ArticleGroupId = A.ArticleGroupId
FROM Article A
WHERE A.Id = @ArticleId
DECLARE @CommissionPercent DECIMAL(19,6)
-- Prüfe Spaltennamen in EmployeeCommissionGroup!
SELECT TOP 1
@CommissionPercent = ECG.CommissionPercent
FROM Employee AS E
LEFT JOIN Article A ON A.Id = @ArticleId
LEFT JOIN Partner P ON P.Id = @PartnerId
LEFT JOIN EmployeeCommissionGroupName ECGN ON ECGN.Id = E.CommissionGroupId
LEFT JOIN EmployeeCommissionGroup ECG ON ECG.CommissionGroupId = E.CommissionGroupId AND ((ECGN.PerArticleGroup = 0 OR ECG.ArticleGroupId = A.ArticleGroupId) AND (ECGN.PerPartnerGroup= 0 OR ECG.PartnerGroupId = P.PartnerGroupId))
WHERE E.Id = @parxSalesPersonId
DECLARE @calxCommissionAmount DECIMAL(19,6) = ISNULL((@TotalPrice * @CommissionPercent / 100), 0)
UPDATE DocPosition SET
SalesPersonId = CASE WHEN @parxSalesPersonId = 0 THEN NULL ELSE @parxSalesPersonId END
, CommissionPercent = ISNULL(@CommissionPercent,0)
WHERE Id = @parxDocPositionId
SELECT @CommissionPercent CommissionPercent, @calxCommissionAmount CommissionAmount
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC226U_DocPosition_SalesPersonId-----------------------------------------------------------------------------------------------
-- xPROC226U_DocPosition_FinanceGroupArticleId---------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC226U_DocPosition_FinanceGroupArticleId
-- PURPOSE: Update the FinanceGroupArticleId with passed value and recalculate the Taxes
@parxDocPositionId INT,
@parxFinanceGroupArticleId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @FinanceGroupPartnerDetailId INT
DECLARE @TotalPrice DECIMAL(19,6)
DECLARE @DocId INT
SELECT
@FinanceGroupPartnerDetailId = FinanceGroupPartnerDetailId
, @TotalPrice = TotalPrice
, @DocId = DocId
FROM DocPosition
WHERE Id = @parxDocPositionId
DECLARE @CostCenterId INT
DECLARE @CostBearerId INT
DECLARE @TaxKeyId NVARCHAR(3)
DECLARE @RevenueExpenditureAccountId INT
SELECT
@CostCenterId = CostCenterId
, @CostBearerId = CostBearerId
, @TaxKeyId = TaxKeyId
, @RevenueExpenditureAccountId = RevenueExpenditureAccountId
FROM FinanceGroupArticleDetail
WHERE FinanceGroupArticleId = @parxFinanceGroupArticleId  AND FinanceGroupPartnerDetailId = @FinanceGroupPartnerDetailId
DECLARE @calxTaxPercent DECIMAL(19,6)
SELECT TOP (1) @calxTaxPercent = TaxPercent
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = @TaxKeyId AND ValidFrom <= GETDATE()
ORDER BY ValidFrom DESC
DECLARE @calxTax DECIMAL(19,6) = ISNULL((@TotalPrice * @calxTaxPercent / 100), 0);
DECLARE @TaxKeyKindId INT
SELECT
@TaxKeyKindId = TaxKeyKindId
FROM FinanceTaxKey WHERE Id = @TaxKeyId
UPDATE DocPosition SET
CostCenterId = @CostCenterId
, CostBearerId = @CostBearerId
, AccountId = @RevenueExpenditureAccountId
, TaxKeyId = @TaxKeyId
, TaxPercent = @calxTaxPercent
WHERE Id = @parxDocPositionId;
SELECT
@calxTax = Tax
FROM DocPosition
WHERE Id = @parxDocPositionId
SELECT 
@TaxKeyId TaxKeyId
, @calxTaxPercent TaxPercent
, @calxTax Tax
, @RevenueExpenditureAccountId AccountId
, @CostCenterId CostCenterId
, @CostBearerId CostBearerId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC226U_DocPosition_FinanceGroupArticleId-------------------------------
