-- xPROC226U_DocPosition_TaxKeyId---------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE
xPROC226U_DocPosition_TaxKeyId
-- PURPOSE: Update the TaxKeyId with passed value and recalculate the taxes
@parxDocPositionId INT,
@parxTaxKeyId NVARCHAR(3)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 1 DECLARE FROM FinanceTaxKeyDetail
DECLARE @calxTaxPercent DECIMAL(19,6)
-- 2 DECLARE FROM DocPosition
DECLARE @DocId INT
DECLARE @TotalPrice DECIMAL(19,6)
-- 3 DECLARE FROM FinanceTaxKey 
DECLARE @TaxKeyKindId INT
-- 1 SELECT FROM FinanceTaxKeyDetail
SELECT TOP (1) @calxTaxPercent = TaxPercent
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = @parxTaxKeyId AND ValidFrom <= GETDATE()
ORDER BY ValidFrom DESC
-- 2 SELECT FROM DocPosition
SELECT
@DocId = DocId
,@TotalPrice = TotalPrice
FROM DocPosition WHERE Id = @parxDocPositionId
-- 3 SELECT FROM FinanceTaxKey 
SELECT
@TaxKeyKindId = TaxKeyKindId
FROM FinanceTaxKey WHERE Id = @parxTaxKeyId
-- CALCULATE DocPosition Sums
DECLARE @calxTax DECIMAL(19,6) = @TotalPrice * @calxTaxPercent / 100;
UPDATE DocPosition
SET
TaxKeyId = @parxTaxKeyId
,TaxPercent = @calxTaxPercent
,TaxFactor = CASE
WHEN @TaxKeyKindId= 3 THEN 0 ELSE 1 END
WHERE Id = @parxDocPositionId 
SELECT
@calxTax = Tax
FROM DocPosition
WHERE Id = @parxDocPositionId
SELECT @calxTaxPercent TaxPercent, @calxTax Tax
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC226U_DocPosition_TaxKeyId-----------------------
-- xPROC226U_DocPosition_PositionTypeId--------------------------
-- PURPOSE: Update the PositionTypeId with passed value and recalculate the Sums
-- 20.) Declare and Select
-- 30.) DocPosition UPDATE PositionTypeId
-- 50.) Doc.Transferable CALCULATE
-- 60.) Update Transferable
-- 90.) RETURN
-- 91.) ERROR HANDLING
------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
