CREATE OR ALTER PROCEDURE 
xPROC226U_DocPosition_PositionTypeId
@parxDocPositionId INT,
@parxPositionTypeId NVARCHAR(15)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 20.) Declare and Select
DECLARE @DocId INT
SELECT
@DocId = DocId
FROM DocPosition
WHERE Id = @parxDocPositionId
-- 30.) DocPosition UPDATE PositionTypeId
UPDATE DocPosition SET PositionTypeId = @parxPositionTypeId WHERE Id = @parxDocPositionId OR ParentPositionId = @parxDocPositionId ;
-- 50.) Doc.Transferable CALCULATE
DECLARE @Transferable BIT
SET @Transferable = (
SELECT
CASE 
WHEN EXISTS (SELECT 1 FROM DocPosition WHERE DocId = @DocId AND PositionTypeId IN ('Optional', 'Alternative', 'Possible')) THEN 0
ELSE 1
END );
-- 60.) Update Transferable
UPDATE Doc
SET
Transferable = @Transferable
FROM Doc D
WHERE D.Id = @DocId
-- 90.) RETURN
SELECT * FROM xVIEW220_DocPosition WHERE Id = @parxDocPositionId OR ParentPositionId = @parxDocPositionId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC226U_DocPosition_PositionTypeId----------------------------
-- xPROC227U_DocPosition_ReduceToNowAvailableQuantity ----------------------------------------------------------------------
-- PURPOSE: Reduce Positions Quantities to Now Available and calling the update Procedure to calculate further values
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE OR ALTER PROCEDURE 
xPROC227U_DocPosition_ReduceToNowAvailableQuantity
-- 23.09.21 18:59
@parxDocId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
CREATE TABLE #TempDocPosition
(
RowNumber INT PRIMARY KEY,
DocPositionId INT,
ParentPositionId INT,
Price DECIMAL(19,6),
DiscountPercent DECIMAL(19,6),
Quantity DECIMAL(19,6),
ArticleId NVARCHAR(30),
NowAvailable DECIMAL(19,6),
SetNowAvailable DECIMAL(19,6),
Warehousing BIT,
ParentWithSet BIT
);
-- Daten in die temporäre Tabelle einfügen und Zeilennummer hinzufügen
INSERT INTO #TempDocPosition (RowNumber, DocPositionId, ParentPositionId, Price , DiscountPercent, Quantity, ArticleId, NowAvailable, SetNowAvailable , Warehousing, ParentWithSet )
SELECT
ROW_NUMBER() OVER (ORDER BY dp.Id),
dp.Id,
dp.ParentPositionId,
dp.Price,
dp.DiscountPercent,
dp.Quantity,
dp.ArticleId,
AIS.NowAvailable,
CASE WHEN dp.Quantity != 0 AND ParentA.WithSet = 1 THEN ISNULL(FLOOR(AIS.NowAvailable / NULLIF(dp.Quantity / ISNULL(NULLIF(ParentDP.Quantity, 0), dp.Quantity), 0)),0)  WHEN dp.Quantity != 0 THEN AIS.NowAvailable ELSE 0 END,
a.Warehousing,
ParentA.WithSet
FROM DocPosition dp
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AIS ON dp.ArticleId = AIS.ArticleId
LEFT JOIN Article a ON dp.ArticleId = a.Id
LEFT JOIN DocPosition ParentDP ON ParentDP.Id= dp.ParentPositionId
LEFT JOIN Article ParentA ON ParentA.Id = ParentDP.ArticleId
WHERE dp.DocId = @parxDocId AND dp.PositionTypeId = 'Article' AND dp.StatusId = 'open';
-- Variablen für die WHILE-Schleife
DECLARE @TotalRows INT = (SELECT COUNT(*) FROM #TempDocPosition);
DECLARE @CurrentRow INT = 1;
-- WHILE-Schleife zur Iteration durch die temporäre Tabelle
WHILE @CurrentRow <= @TotalRows
BEGIN
DECLARE @DocPositionId INT, @Price DECIMAL(19,6), @DiscountPercent DECIMAL(19,6),
@Quantity DECIMAL(19,6), @NewQuantity DECIMAL(19,6), @ParentPositionId INT, @ParentWithSet BIT;
SELECT
@DocPositionId = DocPositionId,
@ParentPositionId = ParentPositionId,
@Price = Price,
@DiscountPercent = DiscountPercent,
@Quantity = Quantity,
@ParentWithSet = ParentWithSet 
FROM #TempDocPosition
WHERE RowNumber = @CurrentRow
SELECT @NewQuantity = ISNULL(MIN(TDP.SetNowAvailable), @Quantity)
FROM #TempDocPosition TDP
WHERE (TDP.DocPositionId = @DocPositionId OR (TDP.ParentPositionId = @DocPositionId AND ParentWithSet  = 1)) AND TDP.Quantity > TDP.SetNowAvailable AND TDP.Warehousing = 1
IF @NewQuantity < 0 BEGIN
SET @NewQuantity = 0 END
IF @ParentPositionId IS NULL  OR @ParentWithSet = 0
BEGIN
-- EXEC xPROC
EXEC xPROC220U_DocPosition_Update
@parxDocPositionId = @DocPositionId,
@parxQuantity = @NewQuantity,
@parxPrice = @Price,
@parxDiscountPercent = @DiscountPercent;
END
-- Nächste Zeile
SET @CurrentRow = @CurrentRow + 1;
END
-- Temporäre Tabelle löschen
DROP TABLE #TempDocPosition;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END
GO
--- END xPROC227U_DocPosition_ReduceToNowAvailableQuantity-----------
-- xPROC228U_DocPosition_Renumber ----------------------------------------------------------------------
-- Purpose: Update PositionNumbers and ChildPositionNumbers by renumbering with the RowNumber
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) SPECIAL OPERATION
-- 30.) CALCULATE and UPDATE DocPosition and Sums
-- 40.) CALCULATE and UPDATE Doc Sums and DocStatusId
-- 60.) CALCULATE and UPDATE PredecessorPosition.QuantityOpen and PredecessorPosition.StatusId PredecessorDoc.DocStatus.Id
-- 80.) RETURN
-- 90.) END TRANSACTION
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC228U_DocPosition_Renumber
-- 26.06.26 03:46
@parxDocId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 30.) CREATE new Doc Positions (INSERT, SELECT)
-- Temporäre Tabelle zum Speichern der IDs
WITH CTE AS (
SELECT
Id,
DocId,
RowNumber,
ParentPositionId,
ROW_NUMBER() OVER (ORDER BY RowNumber) AS NewPositionNumber
FROM DocPosition
WHERE DocId = @parxDocId AND ParentPositionId IS NULL AND PositionTypeId != 'Auto'
),
CTE_ChildPositionNumber AS (
SELECT
dp.Id,
ROW_NUMBER() OVER (PARTITION BY dp.ParentPositionId ORDER BY dp.RowNumber) AS NewChildPositionNumber
FROM DocPosition dp
WHERE dp.DocId = @parxDocId AND dp.ParentPositionId IS NOT NULL 
),
CTE_Update as (
SELECT
dp.Id,
CASE
WHEN dp.ParentPositionId IS NULL THEN cte.NewPositionNumber
ELSE parent.NewPositionNumber
END as NewPositionNumber,
cte_child.NewChildPositionNumber
FROM DocPosition dp
LEFT JOIN CTE ON dp.Id = CTE.Id
LEFT JOIN CTE parent ON dp.ParentPositionId = parent.Id
LEFT JOIN CTE_ChildPositionNumber cte_child ON dp.Id = cte_child.Id
WHERE dp.DocId = @parxDocId AND dp.PositionTypeId != 'Auto'
)
-- Kombinierte Aktualisierung von PositionNumber und ChildPositionNumber
UPDATE DocPosition
SET
PositionNumber = CTE_Update.NewPositionNumber,
ChildPositionNumber = CASE WHEN ParentPositionId IS NOT NULL THEN CTE_Update.NewChildPositionNumber ELSE ChildPositionNumber END
FROM DocPosition
INNER JOIN CTE_Update ON DocPosition.Id = CTE_Update.Id;
-- 90.) END TRANSACTION
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC228U_DocPosition_Renumber ----------------------------------------------------------------------
-- xPROC228U_DocPosition_CloseManually ----------------------------------------------------------------------
-- Purpose: Set Position Status to manually and update Inventory Statuses
-- 10.) DECLARE and SELECT InventoryStatusId
-- 21.) UPDATE DocPosition
-- 22.) UPDATE Doc
-- 80.) RETURN
-- 90.) END TRANSACTION
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC228U_DocPosition_CloseManually
-- 26.06.26 03:45
@parxDocPositionId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE and SELECT InventoryStatusId
DECLARE @DocId INT
SELECT
@DocId = DocId 
FROM DocPosition
WHERE Id = @parxDocPositionId;
DECLARE @InventoryStatusId NVARCHAR(10)
SELECT
@InventoryStatusId = InventoryStatusId
FROM Doc
WHERE Id = @DocId;
-- 21.) UPDATE DocPosition
UPDATE DocPosition
SET
StatusId = 'manually'
, QuantityOpen = 0
WHERE (Id = @parxDocPositionId OR ParentPositionId = @parxDocPositionId) AND (StatusId = 'open' OR StatusId = 'partially')
-- 22.) UPDATE Doc
DECLARE @TotalCount INT, @OpenCount INT, @ClosedCount INT, @ManuallyCount INT;
SELECT
@TotalCount = COUNT(*),
@OpenCount = COUNT(CASE WHEN StatusId = 'open' THEN 1 END),
@ClosedCount = COUNT(CASE WHEN StatusId = 'closed' THEN 1 END),
@ManuallyCount = COUNT(CASE WHEN StatusId = 'manually' THEN 1 END)
FROM DocPosition 
WHERE DocId = @DocId AND PositionTypeId = 'Article';
DECLARE @NewStatus NVARCHAR(50);
IF @ManuallyCount > 0 AND (@ManuallyCount + @ClosedCount = @TotalCount)
SET @NewStatus = 'manually';
ELSE
SET @NewStatus = 'partially';
UPDATE Doc
SET
StatusId = @NewStatus
WHERE Id = @DocId
-- 80.) RETURN
SELECT * FROM xVIEW220_DocPosition WHERE Id = @parxDocPositionId OR ParentPositionId = @parxDocPositionId
-- 90.) END TRANSACTION
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
