CREATE OR ALTER PROCEDURE 
xPROC229U_DocPositionWarehousing_WarehouseId
-- PURPOSE: Update the WarehouseId with passed value and return Stock Value of the Warehouse
@parxWarehousingId INT,
@parxWarehouseId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE DocPositionWarehousing SET WarehouseId = NULLIF(@parxWarehouseId,0) WHERE Id = @parxWarehousingId;
DECLARE @NowAvailable DECIMAL(19,6)
DECLARE @Stock DECIMAL(19,6)
SELECT
@NowAvailable = WQ.NowAvailable
, @Stock = WQ.Stock 
FROM WarehouseQuantity WQ
JOIN DocPosition DP ON DP.ArticleId = WQ.ArticleId
JOIN DocPositionWarehousing DPW ON DPW.DocPositionId = DP.Id AND DPW.WarehouseId= WQ.WarehouseId AND ISNULL(DPW.BinLocationId,0) = ISNULL(WQ.BinLocationId,0)
WHERE DPW.Id = @parxWarehousingId AND WQ.WarehouseId = @parxWarehouseId 
SELECT @NowAvailable NowAvailable, @Stock Stock
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
