-- xPROC260_XInvoice_Export----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC260_XInvoice_Export
-- PURPOSE: Create XML Code for ZUGFeRD and XInvoice Reports
-- 26.06.26
@DocId INT
, @Format NCHAR(1) --'Z' = Export a ZUGFeRD, 'X' = Export an XInvoice
AS
BEGIN -- Procedure
SET NOCOUNT ON;
-- 1. Root
DECLARE @XMLResult XML;
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS [udt]
, 'http://www.w3.org/2001/XMLSchema' AS [xs]
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS [ram]
, 'urn:un:unece:uncefact:data:standard:QualifiedDataType:10' AS [qdt]
, 'urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS [rsm]
, 'urn:un:unece:uncefact:data:standard:QualifiedDataType:100' AS [a]
)
-- 2. Document Context
SELECT @XMLResult = (
SELECT
(
SELECT
CASE WHEN @Format = 'Z' THEN NULL ELSE
(
SELECT 'urn:fdc:peppol.eu:2017:poacc:billing:01:1.0' AS [ram:ID]
FOR XML PATH('ram:BusinessProcessSpecifiedDocumentContextParameter'), TYPE
)
END
, (SELECT CASE WHEN @Format = 'Z' THEN 'urn:cen.eu:en16931:2017' ELSE 'urn:cen.eu:en16931:2017#compliant#urn:xeinkauf.de:kosit:xrechnung_3.0' END AS [ram:ID]
FOR XML PATH('ram:GuidelineSpecifiedDocumentContextParameter'), TYPE
)
FOR XML PATH(''), TYPE
) AS [rsm:ExchangedDocumentContext]
--3. Document
,(
SELECT
D.DocNumber AS [ram:ID]
, CASE WHEN D.RevenueEffective = 1 THEN 380 WHEN D.RevenueEffective = -1 THEN 381 ELSE 0 END AS [ram:TypeCode]
, (
SELECT '102' AS "@format"
, FORMAT(D.DocDate, 'yyyyMMdd') AS "text()"
FOR XML PATH('udt:DateTimeString'), TYPE
) AS "ram:IssueDateTime"
, (
SELECT ISNULL(DTH.Header, '') FROM DocHeaderText DTH WHERE DTH.DocId = D.Id FOR XML PATH('ram:IncludedNote'), TYPE
) AS [ram:Content]
FOR XML PATH(''), TYPE
) AS [rsm:ExchangedDocument]
-- 4. Transaction
, (
SELECT
--4.1 Lines
(
SELECT
(
SELECT
ISNULL(DP.PositionNumber,'') AS [ram:LineID]
FOR XML PATH(''), TYPE
) AS [ram:AssociatedDocumentLineDocument]
, (
SELECT
CASE WHEN DP.PositionTypeId = 'Text' THEN NULL ELSE DP.ArticleId END AS [ram:SellerAssignedID]
, CASE WHEN DP.PositionTypeId = 'Text' THEN DP.Name1 ELSE DP.Name1 + CASE WHEN DP.Name2 IS NULL THEN '' ELSE ' ' + DP.Name2 END END AS [ram:Name]
FOR XML PATH(''), TYPE
) AS [ram:SpecifiedTradeProduct]
, (
SELECT
(
SELECT
(SELECT CASE WHEN DP.PositionTypeId = 'Text' THEN 0.00 ELSE CAST(DP.Price AS DECIMAL(19, 2)) END AS "text()" FOR XML PATH('ram:ChargeAmount'), TYPE)
, (SELECT ISNULL(AU.EInvoiceUoMId,'C62') AS "@unitCode", CASE WHEN DP.PositionTypeId = 'Text' THEN 1 ELSE DP.PriceUnitId END AS "text()" FOR XML PATH('ram:BasisQuantity'), TYPE)
, (
SELECT
CASE WHEN DP.PositionTypeId = 'Text' THEN NULL ELSE
CASE WHEN (DP.Quantity * DP.Price) = DP.TotalPrice THEN NULL
ELSE
(
SELECT
(CASE WHEN (DP.Quantity * DP.Price) < DP.TotalPrice THEN 'true' ELSE 'false' END) AS [ram:ChargeIndicator/udt:Indicator]
, (CAST((DP.Price - DP.DiscountedPrice)  AS DECIMAL(19, 2))) AS [ram:ActualAmount]
, 'Rabatt' AS [ram:Reason]
FOR XML PATH(''), TYPE
)
END
END
)  AS [ram:AppliedTradeAllowanceCharge]
FOR XML PATH(''), TYPE
) AS [ram:GrossPriceProductTradePrice]
, (
SELECT
(SELECT CASE WHEN DP.PositionTypeId = 'Text' THEN 0.00 ELSE CAST(DP.Price AS DECIMAL(19, 2)) END AS "text()"
FOR XML PATH('ram:ChargeAmount'), TYPE)
, (SELECT ISNULL(AU.EInvoiceUoMId,'C62') AS "@unitCode", CASE WHEN DP.PositionTypeId = 'Text' THEN 1 ELSE DP.PriceUnitId END AS "text()" FOR XML PATH('ram:BasisQuantity'), TYPE)
FOR XML PATH(''), TYPE
) AS [ram:NetPriceProductTradePrice]
FOR XML PATH(''), TYPE
) AS [ram:SpecifiedLineTradeAgreement]
, (SELECT ISNULL(AU.EInvoiceUoMId,'') AS "@unitCode", CASE WHEN DP.PositionTypeId = 'Text' THEN 1 ELSE CAST(DP.Quantity AS DECIMAL(19, 4)) END AS "text()" FOR XML PATH('ram:BilledQuantity'), TYPE) AS [ram:SpecifiedLineTradeDelivery]
, (SELECT 'VAT' FOR XML PATH('ram:TypeCode'), TYPE) AS [ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax]
, (SELECT CASE WHEN DP.PositionTypeId = 'Text' THEN 'O' ELSE FTK.EInvoiceTaxKeyCategoryId END FOR XML PATH('ram:CategoryCode'), TYPE) AS [ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax]
, (SELECT CASE WHEN DP.PositionTypeId = 'Text' THEN 0.00 ELSE CAST(DP.TaxPercent AS DECIMAL(19, 2)) END FOR XML PATH('ram:RateApplicablePercent'), TYPE) AS [ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax]
, (SELECT CASE WHEN DP.PositionTypeId = 'Text' THEN 0.00 ELSE CAST(DP.TotalPrice AS DECIMAL(19, 2)) END AS "text()" FOR XML PATH('ram:LineTotalAmount'), TYPE) AS [ram:SpecifiedLineTradeSettlement/ram:SpecifiedTradeSettlementLineMonetarySummation]
FROM
DocPosition DP
LEFT JOIN Article A ON DP.ArticleId = A.Id
LEFT JOIN ArticleUoM AU ON A.UoMId = AU.Id
LEFT JOIN DocPositionInfoText DPIT ON DP.Id = DPIT.DocPositionId
LEFT JOIN FinanceTaxKey FTK ON DP.TaxKeyId = FTK.Id
WHERE
DP.DocId = D.Id
And DP.PositionTypeId IN ('Article') -- Text Positions won't be exported for the moment
FOR XML PATH('ram:IncludedSupplyChainTradeLineItem'), TYPE
)
--4.2.1Article Seller
, (
SELECT
--ram:SellerTradeParty
(SELECT DBA.EInvoiceRoutingId) AS [ram:BuyerReference]
, (SELECT
ISNULL(ACS.CompanyName,'') AS [ram:Name]
, CASE
WHEN NULLIF(LTRIM(RTRIM(ISNULL(E.FirstName, '') + ' ' + ISNULL(E.LastName, ''))), '') IS NULL
AND NULLIF(E.Tel1, '') IS NULL
AND NULLIF(E.Email, '') IS NULL
THEN NULL
ELSE
(
SELECT
NULLIF(LTRIM(RTRIM(ISNULL(E.FirstName, '') + ' ' + ISNULL(E.LastName, ''))), '') AS [ram:PersonName]
, CASE
WHEN NULLIF(E.Tel1, '') IS NULL THEN NULL
ELSE
(
SELECT NULLIF(E.Tel1, '') AS [ram:CompleteNumber]
FOR XML PATH('ram:TelephoneUniversalCommunication'), TYPE
)
END
, CASE
WHEN NULLIF(E.Email, '') IS NULL THEN NULL
ELSE
(
SELECT E.Email AS "text()"
FOR XML PATH('ram:URIID'), TYPE
)
END AS [ram:EmailURIUniversalCommunication]
FOR XML PATH('ram:DefinedTradeContact'), TYPE
)
END
, (
SELECT
ISNULL(ACS.Zip,'') AS [ram:PostcodeCode]
, ISNULL(ACS.Street,'') AS [ram:LineOne]
, ISNULL(ACS.City,'') AS [ram:CityName]
, ISNULL(ACS.CountryId,'') AS [ram:CountryID]
FOR XML PATH(''), TYPE
) AS [ram:PostalTradeAddress]
, CASE
WHEN NULLIF(ACS.Email, '') IS NULL THEN NULL
ELSE
(
SELECT 'EM' AS "@schemeID"
, ACS.Email AS "text()"
FOR XML PATH('ram:URIID'), TYPE
)
END AS [ram:URIUniversalCommunication]
, (
SELECT
CASE
WHEN ACS.VatNumber IS NOT NULL
THEN ((
SELECT 'VA' AS "@schemeID"
, ACS.VatNumber AS "text()"
FOR XML PATH('ram:ID'), TYPE)
)
WHEN ACS.VatNumber IS NULL And ACS.TaxNumber IS NOT NULL
THEN ((
SELECT 'FC' AS "@schemeID"
, ACS.TaxNumber AS "text()"
FOR XML PATH('ram:ID'), TYPE)
)
END
) AS [ram:SpecifiedTaxRegistration]
FOR XML PATH(''), TYPE
) AS [ram:SellerTradeParty]
-- 4.2.2 Buyer
, (
SELECT
D.PartnerId AS [ram:ID]
, DBA.Name1 AS [ram:Name]
, CASE
WHEN NULLIF(LTRIM(RTRIM(ISNULL(PCP.FirstName, '') + ' ' + ISNULL(PCP.LastName, ''))), '') IS NULL
AND NULLIF(PCP.Tel1, '') IS NULL
AND NULLIF(PCP.Email, '') IS NULL
THEN NULL
ELSE
(
SELECT
NULLIF(LTRIM(RTRIM(ISNULL(PCP.FirstName, '') + ' ' + ISNULL(PCP.LastName, ''))), '') AS [ram:PersonName]
, CASE
WHEN NULLIF(PCP.Tel1, '') IS NULL THEN NULL
ELSE
(
SELECT NULLIF(PCP.Tel1, '') AS [ram:CompleteNumber]
FOR XML PATH('ram:TelephoneUniversalCommunication'), TYPE
)
END
, CASE
WHEN NULLIF(PCP.Email, '') IS NULL THEN NULL
ELSE
(
SELECT PCP.Email AS "text()"
FOR XML PATH('ram:URIID'), TYPE
)
END AS [ram:EmailURIUniversalCommunication]
FOR XML PATH('ram:DefinedTradeContact'), TYPE
)
END
, (
SELECT
ISNULL(DBA.Zip,'') AS [ram:PostcodeCode]
, ISNULL(DBA.Street,'') AS [ram:LineOne]
, ISNULL(DBA.City,'') AS [ram:CityName]
, ISNULL(DBA.CountryId,'') AS [ram:CountryID]
FOR XML PATH(''), TYPE
) AS [ram:PostalTradeAddress]
, CASE
WHEN NULLIF(ISNULL(DBA.EInvoiceRoutingId, DBA.Email), '') IS NULL THEN NULL
ELSE
(
SELECT
CASE
WHEN NULLIF(DBA.EInvoiceRoutingId, '') IS NOT NULL THEN '0204'
ELSE 'EM'
END AS "@schemeID"
, ISNULL(NULLIF(DBA.EInvoiceRoutingId, ''), DBA.Email) AS "text()"
FOR XML PATH('ram:URIID'), TYPE
)
END AS [ram:URIUniversalCommunication]
, (
SELECT 'VA' AS "@schemeID"
, ISNULL(DBA.VatNumber,'') AS "text()"
FOR XML PATH('ram:ID'), TYPE
) AS [ram:SpecifiedTaxRegistration]
FOR XML PATH(''), TYPE
) AS [ram:BuyerTradeParty]
FOR XML PATH(''), TYPE
) AS [ram:ApplicableHeaderTradeAgreement]
--ram:ApplicableHeaderTradeDelivery
, (
SELECT
(
SELECT
(
SELECT '102' AS "@format"
, FORMAT(D.DeliveryDate, 'yyyyMMdd') AS "text()"
FOR XML PATH('udt:DateTimeString'), TYPE)
FOR XML PATH('ram:OccurrenceDateTime'), TYPE) AS [ram:ActualDeliverySupplyChainEvent]
FOR XML PATH(''), TYPE
) AS [ram:ApplicableHeaderTradeDelivery]
-- 4.3 ApplicableHeaderTradeSettlement
--ram:ApplicableHeaderTradeSettlement
, (
SELECT
(
CASE WHEN PTP.UNTDIDId= 59 THEN ISNULL(ACS.SepaCreditorNumber, '') ELSE NULL END
) AS [ram:CreditorReferenceID]
, ISNULL(D.DocNumber,'') AS [ram:PaymentReference]
, ISNULL(D.ForeignCurrencyId, ACS.CompanyCurrencyId) AS [ram:InvoiceCurrencyCode]
, (
SELECT
ISNULL(PTP.UNTDIDId,'') AS [ram:TypeCode]
, ISNULL(PTP.Name,'') AS [ram:Information]
, (
SELECT
CASE WHEN PTP.UNTDIDId IN (30,58) THEN (
SELECT
ISNULL(FCBA.Id, '') AS [ram:IBANID]
, ISNULL(FCBA.AccountOwner, '') AS [ram:AccountName]
FOR XML PATH(''), TYPE
)
ELSE NULL
END
AS [ram:PayeePartyCreditorFinancialAccount]
FOR XML PATH(''), TYPE
)
, (
SELECT
CASE WHEN PTP.UNTDIDId IN (59) THEN (
SELECT
ISNULL(PBA.Id, '') AS [ram:IBANID]
, ISNULL(PBA.AccountOwner, '') AS [ram:AccountName]
FOR XML PATH(''), TYPE
)
ELSE
NULL
END AS [ram:PayerPartyDebtorFinancialAccount]
FOR XML PATH(''), TYPE
)
, (
SELECT
CASE
WHEN PTP.UNTDIDId IN (59) THEN ISNULL(PBA.BankId, '')
ELSE ISNULL(FCBA.BankId, '')
END AS [ram:BICID]
FOR XML PATH(''), TYPE
) AS [ram:PayeeSpecifiedCreditorFinancialInstitution]
FOR XML PATH(''), TYPE
) AS [ram:SpecifiedTradeSettlementPaymentMeans]
, (
SELECT
(SELECT CAST(ROUND(SUM(DP.Tax), 2) AS DECIMAL(19, 2)) AS "text()" FOR XML PATH('ram:CalculatedAmount'), TYPE)
, (SELECT 'VAT' FOR XML PATH('ram:TypeCode'), TYPE)
, (CASE WHEN DP.TaxPercent <> 0 THEN NULL ELSE 'Steuerbefreit' END) AS [ram:ExemptionReason]
, (SELECT SUM(CAST(DP.TotalPrice AS DECIMAL(19, 2))) AS "text()" FOR XML PATH('ram:BasisAmount'), TYPE)
, FTK.EInvoiceTaxKeyCategoryId AS [ram:CategoryCode]
, (SELECT CAST(DP.TaxPercent AS DECIMAL(19, 2)) FOR XML PATH('ram:RateApplicablePercent'), TYPE)
FROM
DocPosition DP
LEFT JOIN FinanceTaxKey FTK ON DP.TaxKeyId = FTK.Id
LEFT JOIN DocPositionInfoText DPIT ON DP.Id = DPIT.DocPositionId
WHERE
DP.DocId = D.Id
And DP.PositionTypeId = 'Article'
GROUP BY DP.TaxPercent, FTK.EInvoiceTaxKeyCategoryId
FOR XML PATH('ram:ApplicableTradeTax'), TYPE
)
, (
SELECT
(
SELECT
CASE WHEN PTP.CashDiscountDays1 IS NULL THEN NULL
ELSE
CASE WHEN PTP.CashDiscountDays1 IS NULL THEN '' ELSE '#SKONTO#TAGE=' + CONVERT(VARCHAR, PTP.CashDiscountDays1)+'#PROZENT='+CONVERT(VARCHAR, CAST(PTP.CashDiscountPercentage1 AS DECIMAL(19,2)))+'#' + CHAR(13) END +
CASE WHEN PTP.CashDiscountDays2 IS NULL THEN '' ELSE '#SKONTO#TAGE=' + CONVERT(VARCHAR, PTP.CashDiscountDays2)+'#PROZENT='+CONVERT(VARCHAR, CAST(PTP.CashDiscountPercentage2 AS DECIMAL(19,2)))+'#' + CHAR(13) END
END AS [ram:Description]
FOR XML PATH(''), TYPE
)
, (
SELECT
(
SELECT '102' AS "@format"
, FORMAT(CASE WHEN D.DocCategoryId = 'Sales' THEN DATEADD(Day, PTP.DaysUntilDue, D.DocDate) WHEN D.DocCategoryId = 'Purchase' THEN DATEADD(Day, PTP.DaysUntilDue, D.YourDocDate) ELSE NULL END, 'yyyyMMdd') AS "text()"
FOR XML PATH('udt:DateTimeString'), TYPE) FOR XML PATH('ram:DueDateDateTime'), TYPE)
, (
SELECT
CASE WHEN PBA.MandateReference IS NULL THEN NULL ELSE PBA.MandateReference END AS [ram:DirectDebitMandateID]
FOR XML PATH(''), TYPE
)
FOR XML PATH(''), TYPE
) AS [ram:SpecifiedTradePaymentTerms]
, (
SELECT
(SELECT CAST(D.TotalPriceSum AS DECIMAL(19, 2)) AS "text()" FOR XML PATH('ram:LineTotalAmount'), TYPE)
, (SELECT CAST(D.TotalPriceSum AS DECIMAL(19, 2)) AS "text()" FOR XML PATH('ram:TaxBasisTotalAmount'), TYPE)
, (
SELECT
CASE WHEN D.ForeignCurrencyId IS NULL THEN ACS.CompanyCurrencyId ELSE D.ForeignCurrencyId END AS "@currencyID"
, CAST(D.TaxSum AS DECIMAL(19, 2)) AS "text()"
FOR XML PATH('ram:TaxTotalAmount'), TYPE)
, (SELECT CAST(D.TotalPriceSumGross AS DECIMAL(19, 2)) AS "text()" FOR XML PATH('ram:GrandTotalAmount'), TYPE)
, (SELECT '0.00' AS "text()" FOR XML PATH('ram:TotalPrepaidAmount'), TYPE)
, (SELECT CAST(D.TotalPriceSumGross AS DECIMAL(19, 2)) FOR XML PATH('ram:DuePayableAmount'), TYPE)
FOR XML PATH(''), TYPE
) AS [ram:SpecifiedTradeSettlementHeaderMonetarySummation]
FOR XML PATH(''), TYPE
) AS [ram:ApplicableHeaderTradeSettlement]
-- End 4
FOR XML PATH(''), TYPE ) AS [rsm:SupplyChainTradeTransaction]
-- 5. Referenced Document
--<!-- 5. <ram:AdditionalReferencedDocument> (optional)
--(
--SELECT d.DocNumber FOR XML PATH('ram:IssuerAssignedID'), TYPE
--) AS "ram:AdditionalReferencedDocument",
--(
--SELECT 130 FOR XML PATH('ram:TypeCode'), TYPE
--) AS "ram:AdditionalReferencedDocument",
--(
--SELECT d.Subject FOR XML PATH('ram:Name'), TYPE
--) AS "ram:AdditionalReferencedDocument",
-- 6. Procuring Project
--<!-- 6. <ram:SpecifiedProcuringProject> (optional) -->
--(
--SELECT
--ISNULL(P.Id,'') AS [ram:ID],
--ISNULL(P.Name,'') AS [ram:Name],
--ISNULL(P.SubjectCustomer,'') AS [ram:Description]
--FOR XML PATH(''), TYPE
--) AS [ram:SpecifiedProcuringProject]
-- 7. End
--<!-- 7. End of Root Element -->
FROM xVIEW_Doc D
LEFT JOIN Project P ON D.ProjectId = P.Id
LEFT JOIN PartnerBankAccount PBA ON D.PartnerId = PBA.PartnerId AND PBA.Active = 1
LEFT JOIN PartnerTermsOfPayment PTP ON PTP.Id = D.TermsOfPaymentId
LEFT JOIN DocBillingAddress DBA ON DBA.DocId = D.Id
LEFT JOIN DocDeliveryAddress DDA ON DDA.DocId = D.Id
LEFT JOIN Employee E ON D.ClerkId = E.Id
LEFT JOIN PartnerContactPerson PCP ON PCP.Id = D.PartnerContactPersonId
LEFT JOIN PartnerDetail PD ON PD.Id = D.PartnerDetailId And PD.PartnerTypeId = (CASE WHEN D.DocCategoryId = 'Sales' THEN 'Customer' ELSE 'Supplier' END)
LEFT JOIN FinanceCompanyBankAccount FCBA ON FCBA.Id = PTP.CompanyBankAccountId
LEFT JOIN AdminBank AB ON FCBA.BankId = AB.Id
CROSS JOIN (SELECT TOP 1 * FROM AdminCompanySetting) ACS
WHERE  D.Id = @DocId
FOR XML PATH(''), ROOT('rsm:CrossIndustryInvoice')
);
-- Return the XML result
SELECT @XMLResult AS XMLResult;
--  End Procedure
END -- Transaction
GO
-- END xPROC260_XInvoice_Export----------------------------------------------------------------------------------------------------
-- xPROC261_DocXml_Import----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC261_DocXml_Import
-- PURPOSE: Insert DocXml record with positions from previously imported EInvoice file
@DocId INT, @CurrentUser INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @IssueDate DATETIME, @ShippingDate DATETIME, @DeliveryDate DATETIME, @DocCategoryId NVARCHAR(100), @DocTypeId NVARCHAR(100), @DocNumber NVARCHAR(100), @YourDocNumber NVARCHAR(100), @YourDocDate DATETIME;
DECLARE @EInvoiceRoutingId NVARCHAR(50), @SellerNameInfo NVARCHAR(100), @PartnerId INT, @PostingPeriodId INT, @PersonName NVARCHAR(50), @PartnerVatNumber NVARCHAR(50);
DECLARE @InventoryStatusId NVARCHAR(10), @WarehousingEffective INT, @RevenueEffective INT, @DocNumberPrefix NVARCHAR(3), @PartnerDetailId INT, @PartnerContactPersonId INT;
DECLARE @EmployeeId INT, @TermOfPaymentId INT, @TermsOfPaymentInfo NVARCHAR(200), @TermOfDeliveryId INT, @FinanceGroupPartnerDetailId INT;
DECLARE @RoutingInfo NVARCHAR(100), @SellerStreetInfo NVARCHAR(100), @SellerZipInfo NVARCHAR(30), @SellerCityInfo NVARCHAR(100), @SellerCountryInfo NVARCHAR(30);
DECLARE @SellerTaxInfo NVARCHAR(30), @SellerVatIdInfo NVARCHAR(30), @SellerContactPersonInfo NVARCHAR(50), @SellerEmailInfo NVARCHAR(50), @SellerPhoneInfo NVARCHAR(50);
DECLARE @BuyerNameInfo NVARCHAR(100), @BuyerStreetInfo NVARCHAR(100);
DECLARE @BuyerZipInfo NVARCHAR(30), @BuyerCityInfo NVARCHAR(100), @BuyerCountryInfo NVARCHAR(30), @BuyerTaxInfo NVARCHAR(30), @BuyerVatIdInfo NVARCHAR(30);
DECLARE @BuyerContactPersonInfo NVARCHAR(50), @BuyerEmailInfo NVARCHAR(50), @BuyerPhoneInfo NVARCHAR(50);
DECLARE @NextDocNum NUMERIC(10),@NextDocNumber NVARCHAR(60), @SumLineTotalAmount NUMERIC(19,2);
DECLARE @DocCurrencyCode NVARCHAR(3), @CompanyCurrencyCode NVARCHAR(3) , @LanguageId NVARCHAR(5), @CalculatedTotalPriceSumGross NUMERIC(19,2), @TotalPriceSumGrossDifference NUMERIC(19,2);
DECLARE @LineTotalAmount NUMERIC(19,2), @TaxTotalAmount NUMERIC(19,2), @DuePayableAmount NUMERIC(19,2), @TotalPrepaidAmount NUMERIC(19,2), @AllowanceTotalAmount NUMERIC(19,2), @TotalPriceSum NUMERIC(19,2), @TotalPriceSumGross NUMERIC(19,2);
DECLARE @EDocTypeId INT, @DocXmlType NVARCHAR(30), @XMLType NVARCHAR(MAX), @XMLContent XML;
DECLARE @FetchedDate NVARCHAR(50);
SELECT  @XMLType = Content.value('local-name(/*[1])', 'varchar(max)') FROM DocXml DX WHERE DX.Id = @DocId;
SELECT @PostingPeriodId = dbo.xFUNCTION001_GetCurrentPostingPeriodId();
SELECT TOP 1 @CompanyCurrencyCode = ACS.CompanyCurrencyId FROM AdminCompanySetting ACS;
SELECT @XMLContent =  DX.Content  FROM DocXml DX WHERE DX.Id = @DocId;
IF @XMLType = 'CrossIndustryInvoice'
BEGIN --@XMLType = 'CrossIndustryInvoice'
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT
@EDocTypeId = CASE WHEN E.value('(ram:GuidelineSpecifiedDocumentContextParameter/ram:ID)[1]', 'NVARCHAR(200)') = 'urn:cen.eu:en16931:2017' THEN 3
WHEN E.value('(ram:GuidelineSpecifiedDocumentContextParameter/ram:ID)[1]', 'NVARCHAR(200)') = 'urn:cen.eu:en16931:2017#compliant#urn:xeinkauf.de:kosit:xrechnung_3.0' OR E.value('(ram:GuidelineSpecifiedDocumentContextParameter/ram:ID)[1]', 'NVARCHAR(200)') = 'urn:cen.eu:en16931:2017#compliant#urn:xoev-de:kosit:standard:xrechnung_2.3' THEN 2
ELSE 1 END
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:ExchangedDocumentContext') AS E(E);
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT
@FetchedDate = E.value('(ram:IssueDateTime/udt:DateTimeString)[1]', 'NVARCHAR(50)')
, @YourDocNumber = E.value('(ram:ID)[1]', 'NVARCHAR(100)')
, @DocTypeId = DXA.DocTypeId
, @DocXmlType = DXA.DocXmlType
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:ExchangedDocument') AS E(E)
JOIN DocXmlAssignment DXA ON E.value('(ram:TypeCode)[1]', 'NVARCHAR(20)') = DXA.DocXmlType;
IF @FetchedDate LIKE '%.%.%'  -- German format
BEGIN
SET @IssueDate = TRY_PARSE(@FetchedDate AS datetime USING 'de-DE');
END
ELSE IF @FetchedDate LIKE '%/%/%'  -- US format
BEGIN
SET @IssueDate = TRY_PARSE(@FetchedDate AS datetime USING 'en-US');
END
ELSE  -- ISO compact format (yyyyMMdd) per ZUGFeRD/UNTDID 2379 Format 102
BEGIN
SET @IssueDate = CONVERT(DATETIME, @FetchedDate, 112);
END
SELECT
@DocCategoryId= DT.DocCategoryId
, @InventoryStatusId = DT.InventoryStatusId
, @WarehousingEffective = DT.WarehousingEffective
, @RevenueEffective = DT.RevenueEffective
, @DocNumberPrefix = DT.DocNumberPrefix
FROM DocType DT
WHERE DT.Id = @DocTypeId;
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT
@EInvoiceRoutingId = E.value('(ram:BuyerReference)[1]', 'NVARCHAR(100)')
, @RoutingInfo = E.value('(ram:BuyerReference)[1]', 'NVARCHAR(100)')
, @SellerNameInfo = E.value('(ram:SellerTradeParty/ram:Name)[1]', 'NVARCHAR(100)')
, @SellerStreetInfo = E.value('(ram:SellerTradeParty/ram:PostalTradeAddress/ram:LineOne)[1]', 'NVARCHAR(100)')
, @SellerZipInfo = E.value('(ram:SellerTradeParty/ram:PostalTradeAddress/ram:PostcodeCode)[1]', 'NVARCHAR(30)')
, @SellerCityInfo = E.value('(ram:SellerTradeParty/ram:PostalTradeAddress/ram:CityName)[1]', 'NVARCHAR(100)')
, @SellerCountryInfo = E.value('(ram:SellerTradeParty/ram:PostalTradeAddress/ram:CountryID)[1]', 'NVARCHAR(30)')
, @SellerTaxInfo = E.value('(ram:SellerTradeParty/ram:SpecifiedTaxRegistration/ram:ID[@schemeID="FC"])[1]', 'NVARCHAR(30)')
, @SellerVatIdInfo = E.value('(ram:SellerTradeParty/ram:SpecifiedTaxRegistration/ram:ID[@schemeID="VA"])[1]', 'NVARCHAR(30)')
, @SellerContactPersonInfo = E.value('(ram:SellerTradeParty/ram:DefinedTradeContact/ram:PersonName)[1]', 'NVARCHAR(30)')
, @SellerEmailInfo =  E.value('(ram:SellerTradeParty/ram:DefinedTradeContact/ram:EmailURIUniversalCommunication/ram:URIID)[1]', 'NVARCHAR(50)')
, @SellerPhoneInfo = E.value('(ram:SellerTradeParty/ram:DefinedTradeContact/ram:TelephoneUniversalCommunication/ram:CompleteNumber)[1]', 'NVARCHAR(50)')
, @BuyerNameInfo = E.value('(ram:BuyerTradeParty/ram:Name)[1]', 'NVARCHAR(100)')
, @BuyerStreetInfo = E.value('(ram:BuyerTradeParty/ram:PostalTradeAddress/ram:LineOne)[1]', 'NVARCHAR(100)')
, @BuyerZipInfo = E.value('(ram:BuyerTradeParty/ram:PostalTradeAddress/ram:PostcodeCode)[1]', 'NVARCHAR(30)')
, @BuyerCityInfo = E.value('(ram:BuyerTradeParty/ram:PostalTradeAddress/ram:CityName)[1]', 'NVARCHAR(100)')
, @BuyerCountryInfo = E.value('(ram:BuyerTradeParty/ram:PostalTradeAddress/ram:CountryID)[1]', 'NVARCHAR(30)')
, @BuyerTaxInfo = E.value('(ram:BuyerTradeParty/ram:SpecifiedTaxRegistration/ram:ID[@schemeID="FC"])[1]', 'NVARCHAR(30)')
, @BuyerVatIdInfo = E.value('(ram:BuyerTradeParty/ram:SpecifiedTaxRegistration/ram:ID[@schemeID="VA"])[1]', 'NVARCHAR(30)')
, @BuyerContactPersonInfo = E.value('(ram:BuyerTradeParty/ram:DefinedTradeContact/ram:PersonName)[1]', 'NVARCHAR(30)')
, @BuyerEmailInfo =  E.value('(ram:BuyerTradeParty/ram:DefinedTradeContact/ram:EmailURIUniversalCommunication/ram:URIID)[1]', 'NVARCHAR(50)')
, @BuyerPhoneInfo = E.value('(ram:BuyerTradeParty/ram:DefinedTradeContact/ram:TelephoneUniversalCommunication/ram:CompleteNumber)[1]', 'NVARCHAR(50)')
, @PersonName = E.value('(ram:SellerTradeParty/ram:DefinedTradeContact/ram:PersonName)[1]', 'NVARCHAR(50)')
, @PartnerVatNumber = E.value('(ram:SellerTradeParty/ram:SpecifiedTaxRegistration/ram:ID)[1]', 'NVARCHAR(50)')
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:SupplyChainTradeTransaction/ram:ApplicableHeaderTradeAgreement') AS E(E);
IF (
SELECT COUNT(*)
FROM PartnerDetail PD
LEFT JOIN PartnerBillingAddress PBA ON PBA.Id =PD. StandardBillingAddressId
WHERE PD.PartnerTypeId = CASE WHEN @DocCategoryId = 'Purchase' THEN 'Supplier' ELSE 'Customer' END And PBA.EInvoiceRoutingId = @EInvoiceRoutingId
) = 1
BEGIN
SELECT
@PartnerId = PD.PartnerId
, @PartnerDetailId = PD.Id
, @PartnerContactPersonId = PD.StandardContactPersonId
, @TermOfDeliveryId = PD.TermsOfDeliveryId
, @TermOfPaymentId = PD.TermsOfPaymentId
, @FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId
FROM PartnerDetail PD
LEFT JOIN PartnerBillingAddress PBA ON PBA.Id =PD. StandardBillingAddressId
WHERE PD.PartnerTypeId = CASE WHEN @DocCategoryId = 'Purchase' THEN 'Supplier' ELSE 'Customer' END And PBA.EInvoiceRoutingId = @EInvoiceRoutingId
END
ELSE
BEGIN --Setting NULL if zero or morethan one rows in PD
SET @PartnerId = NULL;
SET @PartnerDetailId = NULL;
SET @PartnerContactPersonId = NULL;
SET @TermOfDeliveryId = NULL;
SET @TermOfPaymentId = NULL;
SET @FinanceGroupPartnerDetailId = NULL;
END
SELECT
@LanguageId= LanguageId
FROM Partner
WHERE Id = @PartnerId
SELECT
@ShippingDate = @IssueDate
, @DeliveryDate = @IssueDate
, @YourDocDate = @IssueDate;
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT
@DocCurrencyCode = E.value('(ram:InvoiceCurrencyCode)[1]', 'NVARCHAR(3)')
, @LineTotalAmount = ISNULL(CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:LineTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TotalPriceSum = ISNULL(CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:TaxBasisTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @AllowanceTotalAmount = ISNULL(CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:AllowanceTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TaxTotalAmount = ISNULL(CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:TaxTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TotalPrepaidAmount = ISNULL(CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:TotalPrepaidAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @DuePayableAmount = ISNULL(CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:DuePayableAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TermsOfPaymentInfo = E.value('(ram:SpecifiedTradeSettlementPaymentMeans/ram:Information)[1]', 'NVARCHAR(200)')
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:SupplyChainTradeTransaction/ram:ApplicableHeaderTradeSettlement') AS E(E);
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT
@SumLineTotalAmount = ISNULL(SUM(CAST(E.value('(ram:SpecifiedLineTradeSettlement/ram:SpecifiedTradeSettlementLineMonetarySummation/ram:LineTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))),0)
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:SupplyChainTradeTransaction/ram:IncludedSupplyChainTradeLineItem') AS E(E);
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
UPDATE DocXml
SET
DocId = NULL
, DocCategoryId = @DocCategoryId
, DocTypeId = @DocTypeId
, DocNumber = NULL
, InventoryStatusId = NULL
, RoutingInfo = @RoutingInfo   --@EInvoiceRoutingId
, SyntaxInfo = CASE WHEN @EDocTypeId IS NOT NULL THEN 'Cross Industry Invoice' ELSE NULL END
, CodeInfo = @DocXmlType
, SellerNameInfo = @SellerNameInfo
, SellerStreetInfo = @SellerStreetInfo
, SellerZipInfo= @SellerZipInfo
, SellerCityInfo = @SellerCityInfo
, SellerCountryInfo = @SellerCountryInfo
, SellerTaxInfo = @SellerTaxInfo
, SellerVatIdInfo = @SellerVatIdInfo
, SellerContactPersonInfo = @SellerContactPersonInfo
, SellerEmailInfo = @SellerEmailInfo
, SellerPhoneInfo = @SellerPhoneInfo
, BuyerNameInfo = @BuyerNameInfo
, BuyerZipInfo = @BuyerZipInfo
, BuyerStreetInfo = @BuyerStreetInfo
, BuyerCityInfo = @BuyerCityInfo
, BuyerCountryInfo = @BuyerCountryInfo
, BuyerTaxInfo = @BuyerTaxInfo
, BuyerVatIdInfo = @BuyerVatIdInfo
, BuyerContactPersonInfo = @BuyerContactPersonInfo
, BuyerEmailInfo = @BuyerEmailInfo
, BuyerPhoneInfo = @BuyerPhoneInfo
, Block = 0
, Remark = NULL
, PeppolParticipantId = NULL
, PeppolProcessId = NULL
, PeppolDocTypeId = NULL
, SenderAccessPointUrl = NULL
, ReceiverAccessPointUrl = NULL
, PeppolTransmissionStatus = NULL
, PeppolTransmissionDate = NULL
, PeppolResponseCode = NULL
, PeppolResponseMessage = NULL
, WarehousingEffective = @WarehousingEffective
, RevenueEffective = @RevenueEffective
, PartnerId =@PartnerId
, StatusId = 'open'
, Transferable = 1
, ShippingDate = @ShippingDate
, DeliveryDate = @DeliveryDate
, PartnerContactPersonId = NULL
, ClerkId = @CurrentUser
, SalesPersonId = NULL
, OurReference = NULL
, DocDate = @IssueDate
, EDocTypeId = @EDocTypeId
, PartnerDetailId = @PartnerDetailId
, PostingPeriodId = @PostingPeriodId
, PostingDate = NULL
, YourDoc = @YourDocNumber
, YourDocDate = @YourDocDate
, InternalRemark = NULL
, Subject = NULL
, Version = 1
, VatNumber = @PartnerVatNumber
, DivergentInvoiceRecipientId = NULL
, TermsOfDeliveryId = NULL
, EuWork = 0
, TermsOfPaymentInfo = @TermsOfPaymentInfo
, TermsOfPaymentId = @TermOfPaymentId
, ProjectId = NULL
, PriceListId = NULL
, DocDiscountPercent = IIF(@LineTotalAmount = 0, 0, (@AllowanceTotalAmount / @LineTotalAmount) * 100)
, CostPriceSum = 0
, ProfitSum = 0
, ProfitPercent = 0
, CommissionSum = 0
, ProfitAfterCommissionSum = 0
, ProfitAfterCommissionPercent = 0
, TotalPriceSum = @TotalPriceSum
, TaxSum = @TaxTotalAmount
, TotalPriceSumGross = @DuePayableAmount
, CalculatedTotalPriceSumGross = @SumLineTotalAmount + @TaxTotalAmount - @AllowanceTotalAmount
, TotalPriceSumGrossDifference = @SumLineTotalAmount + @TaxTotalAmount - @AllowanceTotalAmount - @DuePayableAmount
, DownPaymentSum = @TotalPrepaidAmount
, DownPaymentPercent = (IIF(@DuePayableAmount = 0, 0, (@TotalPrepaidAmount/@DuePayableAmount)*100))
, BalanceDue = @DuePayableAmount
, ForeignCurrencyId = CASE WHEN @DocCurrencyCode <> @CompanyCurrencyCode THEN @DocCurrencyCode ELSE NULL END
, Rate = 1
, LocationId = 1
, StandardWarehouseId = NULL
, DocContractId = NULL
, LanguageId = @LanguageId
, ApprovalRequired = 0
, Draft = 1
, DateCreated = sysutcdatetime()
, CreatedBy = @CurrentUser
WHERE Id = @DocId;
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
INSERT INTO DocXmlPosition
(
DocXmlId
, RowNumber
, PositionTypeId
, PositionNumber
, ChildPositionNumber
, StatusId
, ArticleId
, Name1
, Name2
, Quantity
, QuantityOpen
, UoMId
, ShippingDate
, DeliveryDate
, Price
, TotalPrice
, PredecessorId
, QuantityTransferred
, Level
, PositionLabel
, CatalogNumberId
, Dissolve
, PositionWeight
, RelatedPositionId
, ProjectId
, Start
, Stop
, PriceUnitId
, CostPriceTotal
, DiscountPercent
, QuantityDiscountPercent
, DocDiscountPercent
, DiscountedPrice
, RevenueEffective
, Revenue,SalesPersonId
, CommissionPercent
, CommissionAmount
, ProfitAmount
, ProfitPercent
, FinanceGroupArticleId
, FinanceGroupPartnerDetailId
, TaxKeyId
, TaxPercent
, Tax
, AccountId
, CostCenterId
, CostBearerId
, Warehousing
, WarehousingEffective
, WarehousingQuantity
, Pending
, XmlArticle
, XmlUoM
)
SELECT
@DocId DocXmlId
, ROW_NUMBER() OVER (ORDER BY E.value('(ram:AssociatedDocumentLineDocument/ram:LineID)[1]', 'INT')) RowNumber
, 'Article' PositionTypeId
, ROW_NUMBER() OVER (ORDER BY E.value('(ram:AssociatedDocumentLineDocument/ram:LineID)[1]', 'INT')) PositionNumber
, NULL ChildPositionNumber
, 'open' StatusId
, ISNULL((SELECT PCN.ArticleId FROM PartnerCatalogNumber PCN
JOIN Article A ON A.Id = PCN.ArticleId
JOIN ArticleUoM AU ON AU.Id = A.UoMId And AU.EInvoiceUoMId =  LEFT(E.value('(ram:SpecifiedLineTradeDelivery/ram:BilledQuantity/@unitCode)[1]', 'NVARCHAR(100)'), 30)
WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 AND (PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(200)'), 30) OR PCN.CatalogNumber = LEFT(E.value('(ram:SpecifiedTradeProduct/ram:Name)[1]', 'NVARCHAR(200)'), 30))),NULL) ArticleId 
,  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:Name)[1]', 'NVARCHAR(200)'), 30) Name1
, NULL Name2
, E.value('(ram:SpecifiedLineTradeDelivery/ram:BilledQuantity)[1]', 'DECIMAL(18,4)') Quantity
, 0 QuantityOpen
, ISNULL((SELECT A.UoMId FROM Article A
JOIN ArticleUoM AU ON AU.Id = A.UoMId AND AU.EInvoiceUoMId = E.value('(ram:SpecifiedLineTradeDelivery/ram:BilledQuantity/@unitCode)[1]', 'NVARCHAR(100)')
WHERE A.Id = ISNULL((SELECT PCN.ArticleId FROM PartnerCatalogNumber PCN WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 AND (PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(200)'), 30) OR PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:Name)[1]', 'NVARCHAR(200)'), 30))),'')),NULL) UoMId
, @IssueDate ShippingDate
, @IssueDate DeliveryDate
,  CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END
, ISNULL(E.value('(ram:SpecifiedLineTradeSettlement/ram:SpecifiedTradeSettlementLineMonetarySummation/ram:LineTotalAmount)[1]', 'DECIMAL(19,2)'),0) * (1 -  IIF(@LineTotalAmount = 0, 0, (@AllowanceTotalAmount / @LineTotalAmount))) TotalPrice
, NULL PredecessorId
, 0 QuantityTransferred
, 1 Level
, NULL PositionLabel
, ISNULL((SELECT PCN.Id FROM PartnerCatalogNumber PCN
JOIN Article A ON A.Id = PCN.ArticleId
JOIN ArticleUoM AU ON AU.Id = A.UoMId And AU.EInvoiceUoMId =  LEFT(E.value('(ram:SpecifiedLineTradeDelivery/ram:BilledQuantity/@unitCode)[1]', 'NVARCHAR(100)'), 30)
WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 AND (PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(200)'), 30) OR PCN.CatalogNumber = LEFT(E.value('(ram:SpecifiedTradeProduct/ram:Name)[1]', 'NVARCHAR(200)'), 30))),NULL) CatalogNumberId
, 0 Dissolve
, 0 PositionWeight
, NULL RelatedPositionId
, NULL ProjectId
, NULL Start
, NULL Stop
, ISNULL( CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:BasisQuantity)[1]', 'DECIMAL(18,4)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:BasisQuantity)[1]', 'DECIMAL(18,4)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:BasisQuantity)[1]', 'DECIMAL(18,4)') END, 1)
, 0 CostPriceTotal
, CASE WHEN CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') END IS NULL
OR CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') END = 0
OR E.value('(ram:SpecifiedLineTradeSettlement/ram:SpecifiedTradeSettlementLineMonetarySummation/ram:LineTotalAmount)[1]', 'DECIMAL(19,2)') IS NULL
OR E.value('(ram:SpecifiedLineTradeSettlement/ram:SpecifiedTradeSettlementLineMonetarySummation/ram:LineTotalAmount)[1]', 'DECIMAL(19,2)') = 0
THEN 0
ELSE
CASE WHEN CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') END +(E.value('(ram:SpecifiedLineTradeSettlement/ram:SpecifiedTradeSettlementLineMonetarySummation/ram:LineTotalAmount)[1]', 'DECIMAL(19,2)')) = 0
THEN 0
ELSE
(
CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') END /
CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END
)*100
END
END DiscountPercent
, 0 QuantityDiscountPercent
, IIF(@LineTotalAmount = 0, 0, (@AllowanceTotalAmount / @LineTotalAmount) * 100) DocDiscountPercent
, ROUND(
CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END *
( 1 -
(
IIF(
(
ISNULL(CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END, 0)
) = 0, 0
, ISNULL(CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') END, 0) / CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END
) +
IIF(
@LineTotalAmount = 0, 0
, (@AllowanceTotalAmount / @LineTotalAmount)
)
)
), 2 ) AS DiscountedPrice
, @RevenueEffective RevenueEffective
, ROUND(
@RevenueEffective * CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END *
(
1 -
(
IIF(
(
ISNULL(CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END, 0)
) = 0, 0
, ISNULL(CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:AppliedTradeAllowanceCharge/ram:ActualAmount)[1]', 'DECIMAL(19,2)') END , 0) / CASE WHEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') IS NOT NULL THEN E.value('(ram:SpecifiedLineTradeAgreement/ram:GrossPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') ELSE E.value('(ram:SpecifiedLineTradeAgreement/ram:NetPriceProductTradePrice/ram:ChargeAmount)[1]', 'DECIMAL(19,2)') END
)) -
IIF(
@LineTotalAmount = 0, 0
, @AllowanceTotalAmount / @LineTotalAmount
)
) *
ISNULL(E.value('(ram:SpecifiedLineTradeDelivery/ram:BilledQuantity)[1]', 'DECIMAL(18,4)'), 0), 2 ) AS RevenueEffective
, NULL SalesPersonId
, 0 CommissionPercent
, 0 CommissionAmount
, 0 ProfitAmount
, 0 ProfitPercent
, (SELECT A.ProcurementFinanceGroupId FROM Article A WHERE A.Id = ISNULL((SELECT PCN.ArticleId FROM PartnerCatalogNumber PCN WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 And (PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(200)'), 30) OR PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:Name)[1]', 'NVARCHAR(200)'), 30))),'')) FinanceGroupArticleId
, @FinanceGroupPartnerDetailId FinanceGroupPartnerDetailId
,
CASE --ram:TypeCode
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:TypeCode)[1]', 'NVARCHAR(10)') = 'VAT'
THEN
CASE --ram:CategoryCode
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:CategoryCode)[1]', 'NVARCHAR(10)') = 'S'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 19.00
THEN 'V1'
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 7.00
THEN 'V2'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:CategoryCode)[1]', 'NVARCHAR(10)') = 'E'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 0.00
THEN 'V0'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:CategoryCode)[1]', 'NVARCHAR(10)') = 'Z'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 0.00
THEN 'V0'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:CategoryCode)[1]', 'NVARCHAR(10)') = 'AE'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 19.00
THEN 'E5'
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 7.00
THEN 'E6'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:CategoryCode)[1]', 'NVARCHAR(10)') = 'K'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 19.00
THEN 'E1'
WHEN E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') = 7.00
THEN 'E2'
ELSE NULL
END --ram:RateApplicablePercent
ELSE NULL
END
ELSE NULL
END TaxKeyId
, E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)') TaxPercent
, (E.value('(ram:SpecifiedLineTradeSettlement/ram:ApplicableTradeTax/ram:RateApplicablePercent)[1]', 'DECIMAL(19,2)')/100) *
E.value('(ram:SpecifiedLineTradeSettlement/ram:SpecifiedTradeSettlementLineMonetarySummation/ram:LineTotalAmount)[1]', 'DECIMAL(19,2)') *
(1 - IIF(@LineTotalAmount = 0, 0, (@AllowanceTotalAmount / @LineTotalAmount))) Tax
, FGAD.RevenueExpenditureAccountId AccountId
, FGAD.CostCenterId CostCenterId
, FGAD.CostBearerId CostBearerId
, 0 Warehousing
, @WarehousingEffective WarehousingEffective
, 0 WarehousingQuantity
, 0 Pending
, CASE WHEN  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(200)'), 30) IS NOT NULL THEN  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(200)'), 30) ELSE  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:Name)[1]', 'NVARCHAR(200)'), 30) END XmlArticle
,  E.value('(ram:SpecifiedLineTradeDelivery/ram:BilledQuantity/@unitCode)[1]', 'NVARCHAR(10)') XmlUoM
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:SupplyChainTradeTransaction/ram:IncludedSupplyChainTradeLineItem') AS E(E)
LEFT JOIN PartnerCatalogNumber PCN ON (PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(200)'), 30) OR PCN.CatalogNumber =  LEFT(E.value('(ram:SpecifiedTradeProduct/ram:Name)[1]', 'NVARCHAR(200)'), 30)) And PCN.PartnerId = @PartnerId AND PCN.Active = 1
LEFT JOIN Article A ON A.Id = PCN.ArticleId
LEFT JOIN PartnerDetail PD ON PD.PartnerTypeId = CASE WHEN @DocCategoryId = 'Purchase' THEN 'Supplier' ELSE 'Customer' END And PD.PartnerId = @PartnerId
LEFT JOIN FinanceGroupArticleDetail FGAD ON FGAD.FinanceGroupArticleId = A.ProcurementFinanceGroupId AND FGAD.FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId
END; --@XMLType = 'CrossIndustryInvoice'
ELSE IF @XMLType = 'Invoice'
BEGIN --@XMLType = 'UBL- Invoice'
WITH XMLNAMESPACES
('urn:oasis:names:specification:ubl:schema:xsd:Invoice-2' AS inv
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonBasicComponents-2' AS cbc
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonAggregateComponents-2' AS cac
)
SELECT
@DocCurrencyCode = E.value('(cbc:DocumentCurrencyCode)[1]', 'NVARCHAR(3)')
, @FetchedDate = E.value('(cbc:IssueDate)[1]', 'NVARCHAR(50)')
, @YourDocNumber = E.value('(cbc:ID)[1]', 'NVARCHAR(100)')
, @DocTypeId = DXA.DocTypeId
, @DocXmlType = DXA.DocXmlType
, @EInvoiceRoutingId = E.value('(cbc:BuyerReference)[1]', 'NVARCHAR(50)')
, @RoutingInfo = E.value('(cbc:BuyerReference)[1]', 'NVARCHAR(50)')
, @SellerNameInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:PartyName/cbc:Name)[1]', 'NVARCHAR(100)')
, @SellerStreetInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:PostalAddress/cbc:StreetName)[1]', 'NVARCHAR(100)')
, @SellerZipInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:PostalAddress/cbc:PostalZone)[1]', 'NVARCHAR(100)')
, @SellerCityInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:PostalAddress/cbc:CityName)[1]', 'NVARCHAR(100)')
, @SellerCountryInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:PostalAddress/cac:Country/cbc:IdentificationCode)[1]', 'NVARCHAR(30)')
, @SellerVatIdInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:PartyTaxScheme/cbc:CompanyID)[1]', 'NVARCHAR(30)')
, @SellerContactPersonInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:Contact/cbc:Name)[1]', 'NVARCHAR(50)')
, @SellerEmailInfo = E.value('(cac:AccountingSupplierParty/cac:Party/cac:Contact/cbc:ElectronicMail)[1]', 'NVARCHAR(50)')
, @BuyerNameInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:PartyName/cbc:Name)[1]', 'NVARCHAR(100)')
, @BuyerStreetInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:PostalAddress/cbc:StreetName)[1]', 'NVARCHAR(100)')
, @BuyerZipInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:PostalAddress/cbc:PostalZone)[1]', 'NVARCHAR(100)')
, @BuyerCityInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:PostalAddress/cbc:CityName)[1]', 'NVARCHAR(100)')
, @BuyerCountryInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:PostalAddress/cac:Country/cbc:IdentificationCode)[1]', 'NVARCHAR(30)')
, @BuyerVatIdInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:PartyTaxScheme/cbc:CompanyID)[1]', 'NVARCHAR(30)')
, @BuyerContactPersonInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:Contact/cbc:Name)[1]', 'NVARCHAR(50)')
, @BuyerEmailInfo = E.value('(cac:AccountingCustomerParty/cac:Party/cac:Contact/cbc:ElectronicMail)[1]', 'NVARCHAR(50)')
, @PartnerVatNumber = E.value('(cac:AccountingSupplierParty/cac:Party/cac:PartyTaxScheme/cbc:CompanyID)[1]', 'NVARCHAR(50)')
, @LineTotalAmount = ISNULL(CAST(E.value('(cac:LegalMonetaryTotal/cbc:LineExtensionAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0) --?LineTotal Issue
, @TotalPriceSum = ISNULL(CAST(E.value('(cac:LegalMonetaryTotal/cbc:TaxExclusiveAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TotalPriceSumGross = ISNULL(CAST(E.value('(cac:LegalMonetaryTotal/cbc:TaxInclusiveAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TaxTotalAmount = ISNULL(CAST(E.value('(cac:LegalMonetaryTotal/cbc:TaxInclusiveAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0) - ISNULL(CAST(E.value('(cac:LegalMonetaryTotal/cbc:TaxExclusiveAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TotalPrepaidAmount = ISNULL(CAST(E.value('(cac:LegalMonetaryTotal/cbc:PrepaidAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @DuePayableAmount = ISNULL(CAST(E.value('(cac:LegalMonetaryTotal/cbc:PayableAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)),0)
, @TermsOfPaymentInfo = E.value('(cac:PaymentTerms/cbc:Note)[1]', 'NVARCHAR(200)')
FROM @XMLContent.nodes('inv:Invoice') AS E(E)
JOIN DocXmlAssignment DXA ON E.value('(cbc:InvoiceTypeCode)[1]', 'NVARCHAR(20)') = DXA.DocXmlType;
IF @FetchedDate LIKE '%.%.%'  -- German format
BEGIN
SET @IssueDate = TRY_PARSE(@FetchedDate AS datetime USING 'de-DE');
END
ELSE IF @FetchedDate LIKE '%/%/%'  -- US format
BEGIN
SET @IssueDate = TRY_PARSE(@FetchedDate AS datetime USING 'en-US');
END
ELSE  -- ISO format (yyyy-MM-dd)
BEGIN
SET @IssueDate = CONVERT(DATETIME, @FetchedDate, 120);
END
SELECT
@DocCategoryId= DT.DocCategoryId
, @InventoryStatusId = DT.InventoryStatusId
, @WarehousingEffective = DT.WarehousingEffective
, @RevenueEffective = DT.RevenueEffective
, @DocNumberPrefix = DT.DocNumberPrefix
FROM DocType DT
WHERE DT.Id = @DocTypeId;
IF (
SELECT COUNT(*)
FROM PartnerDetail PD
LEFT JOIN PartnerBillingAddress PBA ON PBA.Id =PD. StandardBillingAddressId
WHERE PD.PartnerTypeId = CASE WHEN @DocCategoryId = 'Purchase' THEN 'Supplier' ELSE 'Customer' END And PBA.EInvoiceRoutingId = @EInvoiceRoutingId
) = 1
BEGIN
SELECT
@PartnerId = PD.PartnerId
, @PartnerDetailId = PD.Id
, @PartnerContactPersonId = PD.StandardContactPersonId
, @TermOfDeliveryId = PD.TermsOfDeliveryId
, @TermOfPaymentId = PD.TermsOfPaymentId
, @FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId
FROM PartnerDetail PD
LEFT JOIN PartnerBillingAddress PBA ON PBA.Id =PD. StandardBillingAddressId
WHERE PD.PartnerTypeId = CASE WHEN @DocCategoryId = 'Purchase' THEN 'Supplier' ELSE 'Customer' END And PBA.EInvoiceRoutingId = @EInvoiceRoutingId
END
ELSE
BEGIN --Setting NULL if zero or morethan one rows in PD
SET @PartnerId = NULL;
SET @PartnerDetailId = NULL;
SET @PartnerContactPersonId = NULL;
SET @TermOfDeliveryId = NULL;
SET @TermOfPaymentId = NULL;
SET @FinanceGroupPartnerDetailId = NULL;
END
SELECT
@LanguageId= LanguageId
FROM Partner
WHERE Id = @PartnerId
SELECT
@ShippingDate = @IssueDate
, @DeliveryDate = @IssueDate
, @YourDocDate = @IssueDate;
WITH XMLNAMESPACES
('urn:oasis:names:specification:ubl:schema:xsd:Invoice-2' AS inv
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonBasicComponents-2' AS cbc
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonAggregateComponents-2' AS cac
)
SELECT
@CalculatedTotalPriceSumGross = ISNULL(SUM(
CAST(E.value('(cbc:LineExtensionAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)) +
(CAST(E.value('(cbc:LineExtensionAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)) * CAST(E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)) / 100)
),0),
@TotalPriceSumGrossDifference = ISNULL(
SUM(
(CAST(E.value('(cbc:LineExtensionAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)) +
(CAST(E.value('(cbc:LineExtensionAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)) * CAST(E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2)) / 100)))-
@TotalPriceSumGross,0)
FROM @XMLContent.nodes('inv:Invoice/cac:InvoiceLine') AS E(E);
SELECT
--@TermsOfPaymentInfo = NULL
--,
@TermOfPaymentId = NULL
, @EDocTypeId = 2
, @BuyerTaxInfo = NULL
, @BuyerPhoneInfo = NULL
, @SellerTaxInfo = NULL
, @SellerPhoneInfo = NULL
, @AllowanceTotalAmount = 0
UPDATE DocXml
SET
DocId = NULL
, DocCategoryId = @DocCategoryId
, DocTypeId = @DocTypeId
, DocNumber = NULL
, InventoryStatusId = NULL
, RoutingInfo = @RoutingInfo   --@EInvoiceRoutingId
, SyntaxInfo = CASE WHEN @EDocTypeId IS NOT NULL THEN 'Invoice' ELSE NULL END
, CodeInfo = @DocXmlType
, SellerNameInfo = @SellerNameInfo
, SellerStreetInfo = @SellerStreetInfo
, SellerZipInfo= @SellerZipInfo
, SellerCityInfo = @SellerCityInfo
, SellerCountryInfo = @SellerCountryInfo
, SellerTaxInfo = @SellerTaxInfo
, SellerVatIdInfo = @SellerVatIdInfo
, SellerContactPersonInfo = @SellerContactPersonInfo
, SellerEmailInfo = @SellerEmailInfo
, SellerPhoneInfo = @SellerPhoneInfo
, BuyerNameInfo = @BuyerNameInfo
, BuyerZipInfo = @BuyerZipInfo
, BuyerStreetInfo = @BuyerStreetInfo
, BuyerCityInfo = @BuyerCityInfo
, BuyerCountryInfo = @BuyerCountryInfo
, BuyerTaxInfo = @BuyerTaxInfo
, BuyerVatIdInfo = @BuyerVatIdInfo
, BuyerContactPersonInfo = @BuyerContactPersonInfo
, BuyerEmailInfo = @BuyerEmailInfo
, BuyerPhoneInfo = @BuyerPhoneInfo
, Block = 0
, Remark = NULL
, PeppolParticipantId = NULL
, PeppolProcessId = NULL
, PeppolDocTypeId = NULL
, SenderAccessPointUrl = NULL
, ReceiverAccessPointUrl = NULL
, PeppolTransmissionStatus = NULL
, PeppolTransmissionDate = NULL
, PeppolResponseCode = NULL
, PeppolResponseMessage = NULL
, WarehousingEffective = @WarehousingEffective
, RevenueEffective = @RevenueEffective
, PartnerId =@PartnerId
, StatusId = 'open'
, Transferable = 1
, ShippingDate = @ShippingDate
, DeliveryDate = @DeliveryDate
, PartnerContactPersonId = NULL
, ClerkId = @CurrentUser
, SalesPersonId = NULL
, OurReference = NULL
, DocDate = @IssueDate
, EDocTypeId = @EDocTypeId
, PartnerDetailId = @PartnerDetailId
, PostingPeriodId = @PostingPeriodId
, PostingDate = NULL
, YourDoc = @YourDocNumber
, YourDocDate = @YourDocDate
, InternalRemark = NULL
, Subject = NULL
, Version = 1
, VatNumber = @PartnerVatNumber
, DivergentInvoiceRecipientId = NULL
, TermsOfDeliveryId = NULL
, EuWork = 0
, TermsOfPaymentInfo = @TermsOfPaymentInfo
, TermsOfPaymentId = @TermOfPaymentId
, ProjectId = NULL
, PriceListId = NULL
, DocDiscountPercent = IIF(@LineTotalAmount = 0, 0, (@AllowanceTotalAmount / @LineTotalAmount) * 100)
, CostPriceSum = 0
, ProfitSum = 0
, ProfitPercent = 0
, CommissionSum = 0
, ProfitAfterCommissionSum = 0
, ProfitAfterCommissionPercent = 0
, TotalPriceSum = @TotalPriceSum
, TaxSum = @TaxTotalAmount
, TotalPriceSumGross = @TotalPriceSumGross
, CalculatedTotalPriceSumGross = @CalculatedTotalPriceSumGross
, TotalPriceSumGrossDifference = @TotalPriceSumGrossDifference
, DownPaymentSum = @TotalPrepaidAmount
, DownPaymentPercent = (IIF(@TotalPriceSumGross= 0, 0, (@TotalPrepaidAmount/@TotalPriceSumGross)*100))
, BalanceDue = @DuePayableAmount
, ForeignCurrencyId = CASE WHEN @DocCurrencyCode <> @CompanyCurrencyCode THEN @DocCurrencyCode ELSE NULL END
, Rate = 1
, LocationId = 1
, StandardWarehouseId = NULL
, DocContractId = NULL
, LanguageId = @LanguageId
, ApprovalRequired = 0
, Draft = 1
, DateCreated = sysutcdatetime()
, CreatedBy = @CurrentUser
WHERE Id = @DocId;
WITH XMLNAMESPACES
('urn:oasis:names:specification:ubl:schema:xsd:Invoice-2' AS inv
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonBasicComponents-2' AS cbc
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonAggregateComponents-2' AS cac
)
INSERT INTO DocXmlPosition
(
DocXmlId
, RowNumber
, PositionTypeId
, PositionNumber
, ChildPositionNumber
, StatusId
, ArticleId
, Name1
, Name2
, Quantity
, QuantityOpen
, UoMId
, ShippingDate
, DeliveryDate
, Price
, TotalPrice
, PredecessorId
, QuantityTransferred
, Level
, PositionLabel
, CatalogNumberId
, Dissolve
, PositionWeight
, RelatedPositionId
, ProjectId
, Start
, Stop
, PriceUnitId
, CostPriceTotal
, DiscountPercent
, QuantityDiscountPercent
, DocDiscountPercent
, DiscountedPrice
, RevenueEffective
, Revenue
, SalesPersonId
, CommissionPercent
, CommissionAmount
, ProfitAmount
, ProfitPercent
, FinanceGroupArticleId
, FinanceGroupPartnerDetailId
, TaxKeyId
, TaxPercent
, Tax
, AccountId
, CostCenterId
, CostBearerId
, Warehousing
, WarehousingEffective
, WarehousingQuantity
, Pending
, XmlArticle
, XmlUoM
)
SELECT
@DocId DocXmlId
, ROW_NUMBER() OVER (ORDER BY E.value('(cbc:ID)[1]', 'INT')) RowNumber
, 'Article' PositionTypeId
, ROW_NUMBER() OVER (ORDER BY E.value('(cbc:ID)[1]', 'INT')) PositionNumber
, NULL ChildPositionNumber
, 'open' StatusId
, ISNULL((SELECT PCN.ArticleId FROM PartnerCatalogNumber PCN
JOIN Article A ON A.Id = PCN.ArticleId
JOIN ArticleUoM AU ON AU.Id = A.UoMId And AU.EInvoiceUoMId = E.value('(cbc:InvoicedQuantity/@unitCode)[1]', 'NVARCHAR(100)')
WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 AND PCN.CatalogNumber = E.value('(cac:Item/cac:SellersItemIdentification/cbc:ID)[1]', 'NVARCHAR(100)')),NULL) ArticleId
, E.value('(cac:Item/cbc:Name)[1]', 'NVARCHAR(100)') Name1
, E.value('(cac:Item/cbc:Description)[1]', 'NVARCHAR(100)') Name2
, E.value('(cbc:InvoicedQuantity)[1]', 'DECIMAL(18,4)') Quantity
, 0 QuantityOpen
, ISNULL((SELECT A.UoMId FROM Article A
JOIN ArticleUoM AU ON AU.Id = A.UoMId AND AU.EInvoiceUoMId = E.value('(cbc:InvoicedQuantity/@unitCode)[1]', 'NVARCHAR(100)')
WHERE A.Id = ISNULL((SELECT PCN.ArticleId FROM PartnerCatalogNumber PCN WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 AND PCN.CatalogNumber = E.value('(cac:Item/cac:SellersItemIdentification/cbc:ID)[1]', 'NVARCHAR(100)')),'')),NULL) UoMId
, @IssueDate ShippingDate
, @IssueDate DeliveryDate
, E.value('(cac:Price/cbc:PriceAmount)[1]', 'DECIMAL(19,2)') Price
, E.value('(cbc:LineExtensionAmount)[1]', 'DECIMAL(19,2)') TotalPrice
--, IIF(E.value('(cbc:InvoicedQuantity)[1]', 'DECIMAL(18,4)') = 0, 0, CAST(E.value('(cac:Price/cbc:PriceAmount)[1]', 'DECIMAL(19,2)') / E.value('(cbc:InvoicedQuantity)[1]', 'DECIMAL(18,4)') AS DECIMAL(19,2))) Price
--, E.value('(cac:Price/cbc:PriceAmount)[1]', 'DECIMAL(19,2)') TotalPrice
, NULL PredecessorId
, 0 QuantityTransferred
, 1 Level
, NULL PositionLabel
, ISNULL((SELECT PCN.Id FROM PartnerCatalogNumber PCN
JOIN Article A ON A.Id = PCN.ArticleId
JOIN ArticleUoM AU ON AU.Id = A.UoMId And AU.EInvoiceUoMId = E.value('(cbc:InvoicedQuantity/@unitCode)[1]', 'NVARCHAR(100)')
WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 AND PCN.CatalogNumber = E.value('(cac:Item/cac:SellersItemIdentification/cbc:ID)[1]', 'NVARCHAR(100)')),NULL) CatalogNumberId
, 0 Dissolve
, 0 PositionWeight
, NULL RelatedPositionId
, NULL ProjectId
, NULL Start
, NULL Stop
, E.value('(cac:Price/cbc:BaseQuantity)[1]', 'DECIMAL(19,2)') PriceUnitId
, 0 CostPriceTotal
, 0 DiscountPercent
, 0 QuantityDiscountPercent
, 0 DocDiscountPercent
, E.value('(cac:Price/cbc:PriceAmount)[1]', 'DECIMAL(19,2)') DiscountedPrice
--, IIF(E.value('(cbc:InvoicedQuantity)[1]', 'DECIMAL(18,4)') = 0, 0, CAST(E.value('(cac:Price/cbc:PriceAmount)[1]', 'DECIMAL(19,2)') / E.value('(cbc:InvoicedQuantity)[1]', 'DECIMAL(18,4)') AS DECIMAL(19,2))) DiscountedPrice
, @RevenueEffective RevenueEffective
, @RevenueEffective * E.value('(cbc:LineExtensionAmount)[1]', 'DECIMAL(19,2)') Revenue
--, @RevenueEffective * E.value('(cac:Price/cbc:PriceAmount)[1]', 'DECIMAL(19,2)') Revenue
, NULL SalesPersonId
, 0 CommissionPercent
, 0 CommissionAmount
, 0 ProfitAmount
, 0 ProfitPercent
, (SELECT A.ProcurementFinanceGroupId FROM Article A WHERE A.Id = ISNULL((SELECT PCN.ArticleId FROM PartnerCatalogNumber PCN WHERE PCN.PartnerId = @PartnerId AND PCN.Active = 1 And PCN.CatalogNumber = E.value('(cac:Item/cac:SellersItemIdentification/cbc:ID)[1]', 'NVARCHAR(100)')),'')) FinanceGroupArticleId
, @FinanceGroupPartnerDetailId FinanceGroupPartnerDetailId
,
CASE --ram:TypeCode
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cac:TaxScheme/cbc:ID)[1]', 'NVARCHAR(10)') = 'VAT'
THEN
CASE --ram:CategoryCode
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:ID)[1]', 'NVARCHAR(10)') = 'S'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 19.00
THEN 'V1'
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 7.00
THEN 'V2'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:ID)[1]', 'NVARCHAR(10)') = 'E'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 0.00
THEN 'V0'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:ID)[1]', 'NVARCHAR(10)') = 'Z'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 0.00
THEN 'V0'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:ID)[1]', 'NVARCHAR(10)') = 'AE'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 19.00
THEN 'E5'
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 7.00
THEN 'E6'
ELSE NULL
END --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:ID)[1]', 'NVARCHAR(10)') = 'K'
THEN
CASE --ram:RateApplicablePercent
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 19.00
THEN 'E1'
WHEN E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') = 7.00
THEN 'E2'
ELSE NULL
END --ram:RateApplicablePercent
ELSE NULL
END
ELSE NULL
END TaxKeyId
, E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)') TaxPercent
, (E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)')/100) * E.value('(cbc:LineExtensionAmount)[1]', 'DECIMAL(19,2)') Tax
--, (E.value('(cac:Item/cac:ClassifiedTaxCategory/cbc:Percent)[1]', 'DECIMAL(19,2)')/100) * E.value('(cac:Price/cbc:PriceAmount)[1]', 'DECIMAL(19,2)') Tax
, FGAD.RevenueExpenditureAccountId AccountId
, FGAD.CostCenterId CostCenterId
, FGAD.CostBearerId CostBearerId
, 0 Warehousing
, @WarehousingEffective WarehousingEffective
, 0 WarehousingQuantity
, 0 Pending
, E.value('(cac:Item/cac:SellersItemIdentification/cbc:ID)[1]', 'NVARCHAR(30)') XmlArticle
,  E.value('(cbc:InvoicedQuantity/@unitCode)[1]', 'NVARCHAR(10)')
FROM @XMLContent.nodes('inv:Invoice/cac:InvoiceLine') AS E(E)
LEFT JOIN PartnerCatalogNumber PCN ON PCN.CatalogNumber = E.value('(cac:Item/cac:SellersItemIdentification/cbc:ID)[1]', 'NVARCHAR(100)') And PCN.PartnerId = @PartnerId AND PCN.Active = 1
LEFT JOIN Article A ON A.Id = PCN.ArticleId
LEFT JOIN PartnerDetail PD ON PD.PartnerTypeId = CASE WHEN @DocCategoryId = 'Purchase' THEN 'Supplier' ELSE 'Customer' END And PD.PartnerId = @PartnerId
LEFT JOIN FinanceGroupArticleDetail FGAD ON FGAD.FinanceGroupArticleId = A.ProcurementFinanceGroupId AND FGAD.FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId
END; --@XMLType = 'UBL - Invoice'
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC261_DocXml_Import----------------------------------------------------------------------------------------------------
-- xPROC262_XInvoice_Import----------------------------------------------------------------------------------------------------
-- Creating a Doc based on one DocXml Record
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATING for Doc
-- 30.) VALIDATING for DocPositions
-- 40.) CREATE Doc
-- 50.) CREATE DocPositions
-- 60.) CREATE DocBillingAddress
-- 61.) CREATE DocDeliveryAddress
-- 70.) UPDATE DocXml
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC262_XInvoice_Import
@DocId INT, @CurrentUser INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @IssueDate DATETIME, @ShippingDate DATETIME, @DeliveryDate DATETIME, @DocCategoryId NVARCHAR(100), @DocTypeId NVARCHAR(100), @DocNumber NVARCHAR(100), @YourDocNumber NVARCHAR(100), @YourDocDate DATETIME;
DECLARE @EInvoiceRoutingId NVARCHAR(50), @PartnerId INT, @PostingPeriodId INT, @PersonName NVARCHAR(50), @PartnerVatNumber NVARCHAR(50), @LanguageId NVARCHAR(5);
DECLARE @InventoryStatusId NVARCHAR(10), @WarehousingEffective INT, @RevenueEffective INT, @DocNumberPrefix NVARCHAR(3), @PartnerDetailId INT, @PartnerContactPersonId INT;
DECLARE @TermOfPaymentId INT, @TermOfDeliveryId INT, @FinanceGroupPartnerDetailId INT;
DECLARE @NextDocNum NVARCHAR(10),@NextDocNumber NVARCHAR(60), @InternalRemark NVARCHAR(100), @Subject NVARCHAR(100), @EDocTypeId INT, @ProjectId INT;
DECLARE @DocCurrencyCode NVARCHAR(3), @AddedDocId INT, @CalculatedTotalPriceSumGross NUMERIC(19,2), @TotalPriceSumGrossDifference NUMERIC(19,2);
DECLARE @TotalPriceSum NUMERIC(19,2), @TaxSum NUMERIC(19,2), @TotalPriceSumGross NUMERIC(19,2);
DECLARE @LineTotalAmount NUMERIC(19,2), @TaxTotalAmount NUMERIC(19,2), @DuePayableAmount NUMERIC(19,2), @TotalPrepaidAmount NUMERIC(19,2), @AllowanceTotalAmount NUMERIC(19,2)
DECLARE @StatusId NVARCHAR(12), @Transferable BIT, @LineTotalPriceSum NUMERIC(19,2), @LineTaxSum NUMERIC(19,2), @LineTotalPriceSumGross NUMERIC(19,2)
DECLARE @XMLContent XML;
DECLARE @SQLString NVARCHAR(100);
DECLARE @ParmDefinition NVARCHAR(75), @ToDocTypeId NVARCHAR(35);
DECLARE @InvalidValues TABLE (PositionNumber INT, TEXT NVARCHAR(100));
DECLARE @OutputControlFormatId INT
DECLARE @EInvoiceUoMId NVARCHAR(20)
DECLARE
@row_PositionNum INT,@row_PositionTypeId NVARCHAR(15), @row_StatusId NVARCHAR(12), @row_ArticleId NVARCHAR(30), @row_Name1 NVARCHAR(100), @row_Name2 NVARCHAR(100),
@row_Quantity NUMERIC(19,6), @row_QuantityOpen NUMERIC(19,6), @row_UoMId INT, @row_ShippingDate DATETIME, @row_DeliveryDate DATETIME,
@row_Price NUMERIC(19,6), @row_TotalPrice NUMERIC(19,6), @row_CatalogNumberId INT, @row_PriceUnitId INT, @row_DiscountedPrice NUMERIC(19,6),
@row_RevenueEffective INT, @row_Revenue NUMERIC(19,6), @row_FinanceGroupArticleId INT, @row_FinanceGroupPartnerDetailId INT,
@row_TaxPercent NUMERIC(19,6), @row_Tax NUMERIC(19,6),@row_DiscountPercent NUMERIC(19,6), @row_DocDiscountPercent NUMERIC(19,6), @row_QuantityDiscountPercent NUMERIC(19,6), @row_XmlUoM NVARCHAR(10);
SELECT
@DocCategoryId = DX.DocCategoryId
, @DocTypeId = DX.DocTypeId
, @PartnerDetailId = DX.PartnerDetailId
, @StatusId = DX.StatusId
, @Transferable = DX.Transferable
, @IssueDate = DX.DocDate
, @PostingPeriodId = DX.PostingPeriodId
, @ShippingDate = DX.ShippingDate
, @DeliveryDate = DX.DeliveryDate
, @YourDocNumber = DX.YourDoc
, @YourDocDate = DX.YourDocDate
, @InternalRemark = DX.InternalRemark
, @Subject = DX.Subject
, @EDocTypeId = DX.EDocTypeId
, @TermOfPaymentId = DX.TermsOfPaymentId
, @ProjectId = DX.ProjectId
, @TotalPriceSum = DX.TotalPriceSum
, @TaxSum = DX.TaxSum
, @TotalPriceSumGross = DX.TotalPriceSumGross
, @CalculatedTotalPriceSumGross = DX.CalculatedTotalPriceSumGross
, @TotalPriceSumGrossDifference = DX.TotalPriceSumGrossDifference
, @XMLContent =  DX.Content
, @LanguageId =  DX.LanguageId
, @PartnerContactPersonId = DX.PartnerContactPersonId
FROM DocXml DX WHERE DX.Id = @DocId;
SELECT
@DocCategoryId = DocCategoryId
, @InventoryStatusId = InventoryStatusId
, @WarehousingEffective = 0 --WarehousingEffective
, @RevenueEffective = RevenueEffective
, @DocNumberPrefix = DocNumberPrefix
, @ToDocTypeId = Id
FROM DocType
WHERE Id = @DocTypeId;
SELECT
@LineTotalPriceSum = SUM(DXP.TotalPrice)
, @LineTaxSum = SUM(DXP.Tax)
, @LineTotalPriceSumGross = SUM(DXP.Tax + DXP.TotalPrice)
FROM DocXmlPosition DXP WHERE DXP.DocXmlId = @DocId;
SELECT
@PartnerId = PD.PartnerId
, @TermOfDeliveryId = NULL
, @FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId
FROM PartnerDetail PD WHERE PD.Id = @PartnerDetailId;
SELECT
@ShippingDate = @IssueDate
, @DeliveryDate = @IssueDate
, @YourDocDate = @IssueDate;
DECLARE @DocXmlType NVARCHAR(30), @XMLType NVARCHAR(MAX);
SELECT  @XMLType = Content.value('local-name(/*[1])', 'varchar(max)') FROM DocXml DX WHERE DX.Id = @DocId;
IF @XMLType = 'CrossIndustryInvoice'
BEGIN --@XMLType = 'CrossIndustryInvoice'
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT
@EInvoiceRoutingId = E.value('(ram:BuyerReference)[1]', 'NVARCHAR(50)')
, @PersonName = E.value('(ram:SellerTradeParty/ram:DefinedTradeContact/ram:PersonName)[1]', 'NVARCHAR(50)')
, @PartnerVatNumber = E.value('(ram:SellerTradeParty/ram:SpecifiedTaxRegistration/ram:ID[@schemeID="VA"])[1]', 'NVARCHAR(50)')
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:SupplyChainTradeTransaction/ram:ApplicableHeaderTradeAgreement') AS E(E);
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT
@DocCurrencyCode = E.value('(ram:InvoiceCurrencyCode)[1]', 'NVARCHAR(3)')
, @LineTotalAmount = CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:LineTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @AllowanceTotalAmount = CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:AllowanceTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @TaxTotalAmount = CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:TaxTotalAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @TotalPrepaidAmount = CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:TotalPrepaidAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @DuePayableAmount = CAST(E.value('(ram:SpecifiedTradeSettlementHeaderMonetarySummation/ram:DuePayableAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:SupplyChainTradeTransaction/ram:ApplicableHeaderTradeSettlement') AS E(E);
END
ELSE IF @XMLType = 'Invoice'
BEGIN --@XMLType = 'UBL- Invoice'
WITH XMLNAMESPACES
('urn:oasis:names:specification:ubl:schema:xsd:Invoice-2' AS inv
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonBasicComponents-2' AS cbc
, 'urn:oasis:names:specification:ubl:schema:xsd:CommonAggregateComponents-2' AS cac
)
SELECT
@EInvoiceRoutingId = E.value('(cbc:BuyerReference)[1]', 'NVARCHAR(50)')
, @PersonName = E.value('(cac:AccountingCustomerParty/cac:Party/cac:Contact/cbc:Name)[1]', 'NVARCHAR(50)')
, @PartnerVatNumber = E.value('(cac:AccountingCustomerParty/cac:Party/cac:PartyTaxScheme/cbc:CompanyID)[1]', 'NVARCHAR(50)')
, @DocCurrencyCode = E.value('(cbc:DocumentCurrencyCode)[1]', 'NVARCHAR(3)')
, @LineTotalAmount = CAST(E.value('(cac:LegalMonetaryTotal/cbc:LineExtensionAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @TaxTotalAmount = CAST(E.value('(cac:TaxTotal/cbc:TaxAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @TotalPrepaidAmount = CAST(E.value('(cac:LegalMonetaryTotal/cbc:PrepaidAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @DuePayableAmount = CAST(E.value('(cac:LegalMonetaryTotal/cbc:PayableAmount)[1]', 'NVARCHAR(50)') AS NUMERIC(19,2))
, @AllowanceTotalAmount = 0
FROM @XMLContent.nodes('inv:Invoice') AS E(E)
END;
SELECT @AddedDocId = D.Id FROM Doc D WHERE D.DocNumber = @NextDocNumber;
-- FROM PartnerDetailOutput
SELECT
@OutputControlFormatId = OutputControlFormatId
FROM PartnerDetailOutput WHERE PartnerDetailId = @PartnerDetailId AND DocTypeId = @DocTypeId
-- Checking for invalid Values
-- 20.) VALIDATING for Doc
IF @DocCategoryId IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('System Error: Doc Category is missing');
END
IF @DocTypeId IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('System Error: Doc Type is missing');
END
IF @PartnerId IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('System Error: Partner is missing')
END
IF @PartnerDetailId IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('System Error: Partner Detail is missing')
END
IF @StatusId IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('System Error: Doc Status is missing')
END
IF @Transferable IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('System Error: Transferable is missing')
END
IF @IssueDate IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Your Doc Date is missing');
END
IF @ShippingDate IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Shipping Date is missing');
END
IF @DeliveryDate IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Delivery Date is missing');
END
IF @YourDocNumber IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Your Doc Number is missing');
END
IF @YourDocDate IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Your Doc Date is missing');
END
IF @EDocTypeId IS NULL OR @EDocTypeId = 1
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('No valid E-Doc Type has been detected');
END
IF @TotalPriceSum <> @LineTotalPriceSum
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Total Price Sum does not match the line Total Prices');
END
IF @TaxSum <> @LineTaxSum
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Tax Sum does not match the line Taxes');
END
IF @TotalPriceSumGross <> @LineTotalPriceSumGross
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Total Price Sum Gross does not match the line Total Prices Gross');
END
IF @CalculatedTotalPriceSumGross IS NULL
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Calculated Total Price Sum Gross is missing');
END
IF @TotalPriceSumGrossDifference <> 0
BEGIN
INSERT INTO @InvalidValues (TEXT)
VALUES ('Total Price Sum Gross Difference has to be zero');
END
-- 30.) VALIDATING for DocPosition
DECLARE @PositionRowCount INT, @LoopCounter INT;
SELECT @PositionRowCount = COUNT(*) FROM DocXmlPosition DXP WHERE DXP.DocXmlId = @DocId;
SET @LoopCounter = 1;
WHILE @LoopCounter <= @PositionRowCount
BEGIN
SELECT
@row_PositionNum = DXP.PositionNumber
, @row_PositionTypeId = DXP.PositionTypeId
, @row_StatusId = DXP.StatusId
, @row_ArticleId = DXP.ArticleId
, @row_Name1 = DXP.Name1
, @row_Name2 = DXP.Name2
, @row_Quantity = DXP.Quantity
, @row_QuantityOpen = DXP.QuantityOpen
, @row_UoMId = DXP.UoMId
, @row_ShippingDate = DXP.ShippingDate
, @row_DeliveryDate = DXP.DeliveryDate
, @row_Price = DXP.Price
, @row_TotalPrice = DXP.TotalPrice
, @row_CatalogNumberId = DXP.CatalogNumberId
, @row_PriceUnitId = DXP.PriceUnitId
, @row_DiscountedPrice = DXP.DiscountedPrice
, @row_RevenueEffective = DXP.RevenueEffective
, @row_Revenue = DXP.Revenue
, @row_FinanceGroupArticleId = DXP.FinanceGroupArticleId
, @row_FinanceGroupPartnerDetailId = DXP.FinanceGroupPartnerDetailId
, @row_TaxPercent = DXP.TaxPercent
, @row_Tax = DXP.Tax
, @row_DiscountPercent = DXP.DiscountPercent
, @row_DocDiscountPercent = DXP.DocDiscountPercent
, @row_QuantityDiscountPercent = DXP.QuantityDiscountPercent
, @row_XmlUoM = DXP.XmlUoM
FROM
DocXmlPosition DXP
WHERE DXP.DocXmlId = @DocId AND DXP.RowNumber = @LoopCounter;
SELECT
@EInvoiceUoMId = EInvoiceUoMId 
FROM ArticleUoM
WHERE Id = @row_UoMId
IF @row_PositionTypeId IS NULL
BEGIN
INSERT INTO @InvalidValues (PositionNumber,TEXT)
VALUES (@row_PositionNum,'System Error: Position Type is missing');
END;
IF @row_StatusId <> 'open'
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum,'System Error: Status has to be open');
END;
IF @row_ArticleId IS NULL OR NOT EXISTS (SELECT A.Id FROM Article A WHERE A.Id = @row_ArticleId)
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Article is missing');
END;
IF @row_UoMId IS NULL OR NOT EXISTS (SELECT AU.Id FROM ArticleUoM AU WHERE AU.Id = @row_UoMId)
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'UoM is missing');
END;
IF @row_TotalPrice <> ROUND(ISNULL(@row_Quantity * (@row_Price / @row_PriceUnitId) * (1 - ((@row_DiscountPercent + @row_QuantityDiscountPercent + @row_DocDiscountPercent) / 100)), 0),2)
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Total Price does not match the calculation');
END;
IF @row_CatalogNumberId IS NULL
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Catalog Number is missing');
END;
IF @row_DiscountedPrice <> ROUND(ISNULL(@row_Price * (1 - ((@row_DiscountPercent + @row_QuantityDiscountPercent + @row_DocDiscountPercent) / 100)), 0),2)
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Discounted Price does not match the calculation');
END;
IF @row_Revenue <> ROUND(ISNULL(@row_RevenueEffective * @row_Quantity * (@row_Price * (1 - ((@row_DiscountPercent + @row_QuantityDiscountPercent + @row_DocDiscountPercent) / 100))), 0),2)
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Revenue does not match the calculation');
END;
IF @row_FinanceGroupArticleId IS NULL
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Finance Group Article is missing');
END;
IF @row_FinanceGroupPartnerDetailId IS NULL
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Finance Group Partner is missing');
END;
IF @row_Tax <> ISNULL((@row_TotalPrice * @row_TaxPercent / 100), 0)
BEGIN
INSERT INTO @InvalidValues (PositionNumber, TEXT)
VALUES (@row_PositionNum, 'Tax does not match the calculation');
END;
SET @LoopCounter = @LoopCounter + 1;
END;
IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
SET @SQLString = N'SELECT @NextNumberOUT = NEXT VALUE FOR dbo.Doc_' + @ToDocTypeId  + N'_Sequence';
SET @ParmDefinition = N'@NextNumberOUT NVARCHAR(60) OUTPUT';
EXECUTE sp_executesql @SQLString, @ParmDefinition, @NextNumberOUT = @NextDocNum OUTPUT;
SET @NextDocNumber = @DocNumberPrefix + FORMAT(GETDATE(), 'yyMM') + RIGHT('0000' + @NextDocNum, 4);
-- 40.) CREATE Doc
INSERT INTO Doc (
DocNumber
, DocCategoryId
, DocTypeId
, InventoryStatusId
, WarehousingEffective
, RevenueEffective
, PartnerId
, PartnerDetailId
, StatusId
, Transferable
, Draft
, DocDate
, PostingDate
, PostingPeriodId
, ShippingDate
, DeliveryDate
, PartnerContactPersonId
, ClerkId
, SalesPersonId
, OurReference
, YourDoc
, YourDocDate
, InternalRemark
, Subject
, Version
, DivergentInvoiceRecipientId
, TermsOfDeliveryId
, EuWork
, LanguageId
, ReportTemplateId
, ApprovalRequired
, EDocTypeId
, TermsOfPaymentId
, ProjectId
, PriceListId
, DocDiscountPercent
, DownPaymentSum
, ForeignCurrencyId
, Rate
, LocationId
, StandardWarehouseId
, DocContractId
, DocXmlId
, DateCreated
, CreatedBy
, OutputControlFormatId
)
VALUES
(
@NextDocNumber
, @DocCategoryId
, @DocTypeId
, @InventoryStatusId
, @WarehousingEffective
, @RevenueEffective
, @PartnerId
, @PartnerDetailId
, 'open'
, 1
, 0
, @IssueDate
, NULL
, @PostingPeriodId
, @ShippingDate
, @DeliveryDate
, @PartnerContactPersonId
, @CurrentUser --'Logged in User => EmployeeId'
, NULL
, NULL
, @YourDocNumber
, @YourDocDate
, @InternalRemark
, @Subject
, '1'
, NULL
, NULL --'TermsOfDeliveryId'
, 0
, @LanguageId
, @OutputControlFormatId
, 0
, @EDocTypeId
, @TermOfPaymentId --'TermsOfPaymentId'
, @ProjectId
, NULL
, ISNULL(@AllowanceTotalAmount, 0) --'<rsm:SupplyChainTradeTransaction>/<ram:SpecifiedTradeSettlementHeaderMonetarySummation>/<ram:AllowanceTotalAmount>'
, ISNULL(@TotalPrepaidAmount, 0) --'<rsm:SupplyChainTradeTransaction>/<ram:SpecifiedTradeSettlementHeaderMonetarySummation>/<ram:TotalPrepaidAmount>'
, (SELECT TOP 1 CASE WHEN ACS.CompanyCurrencyId <> @DocCurrencyCode THEN @DocCurrencyCode ELSE NULL END FROM AdminCompanySetting ACS ) --'IF <ram:ApplicableHeaderTradeSettlement>/<ram:InvoiceCurrencyCode> != AdminCompanySetting.CompanyCurrencyId THEN <ram:ApplicableHeaderTradeSettlement>/<ram:InvoiceCurrencyCode> ELSE NULL'
, NULL
, 1
, NULL
, NULL
, @DocId
, GETDATE()
, @CurrentUser --'Logged in User => EmployeeId'
, @OutputControlFormatId
);
SELECT @AddedDocId = D.Id FROM Doc D WHERE D.DocNumber = @NextDocNumber;
-- 50.) CREATE DocPositions
INSERT INTO DocPosition
(
DocId
, RowNumber
, PositionTypeId
, PositionNumber
, ParentPositionId
, ChildPositionNumber
, StatusId
, ArticleId
, Name1
, Name2
, Quantity
, QuantityOpen
, UoMId
, ShippingDate
, DeliveryDate
, Price
, PredecessorId
, QuantityTransferred
, Level
, PositionLabel
, CatalogNumberId
, Dissolve
, PositionWeight
, RelatedPositionId
, ProjectId
, Start
, Stop
, PriceUnitId
, ArticleCostPrice
, DiscountPercent
, QuantityDiscountPercent
, DocDiscountPercent
, PrepaymentFactor
, RevenueEffective
, SalesPersonId
, CommissionPercent
, ProfitFactor
, CostPriceFactor
, FinanceGroupArticleId
, FinanceGroupPartnerDetailId
, TaxKeyId
, TaxFactor
, TaxPercent
, AccountId
, CostCenterId
, CostBearerId
, Warehousing
, WarehousingEffective
, Pending
)
SELECT
@AddedDocId
, DXP1.RowNumber
, DXP1.PositionTypeId
, DXP1.PositionNumber
, DXP1.ParentPositionId
, DXP1.ChildPositionNumber
, DXP1.StatusId
, DXP1.ArticleId
, DXP1.Name1
, DXP1.Name2
, DXP1.Quantity
, DXP1.Quantity
, DXP1.UoMId
, DXP1.ShippingDate
, DXP1.DeliveryDate
, DXP1.Price
, DXP1.PredecessorId
, DXP1.QuantityTransferred
, DXP1.Level
, DXP1.PositionLabel
, DXP1.CatalogNumberId
, DXP1.Dissolve
, DXP1.PositionWeight
, DXP1.RelatedPositionId
, DXP1.ProjectId
, DXP1.Start
, DXP1.Stop
, DXP1.PriceUnitId
, ROUND(ISNULL(DXP1.CostPriceTotal/NULLIF(DXP1.Quantity,0)*DXP1.PriceUnitId, 0), 2)
, ISNULL(DXP1.DiscountPercent,0)
, DXP1.QuantityDiscountPercent
, DXP1.DocDiscountPercent
, CASE WHEN A.IsPrepayment = 1 THEN DT.PrepaymentTrueArticleFactor ELSE DT.PrepaymentFalseArticleFactor END
, DXP1.RevenueEffective
, DXP1.SalesPersonId
, DXP1.CommissionPercent
, CASE WHEN A.IsPrepayment = 1 THEN 0 ELSE 1 END
, CASE WHEN DT.DocCategoryId= 'Purchase'  THEN 0 ELSE 1 END
, DXP1.FinanceGroupArticleId
, DXP1.FinanceGroupPartnerDetailId
, DXP1.TaxKeyId
, 1
, DXP1.TaxPercent
, DXP1.AccountId
, DXP1.CostCenterId
, DXP1.CostBearerId
, DXP1.Warehousing
, DXP1.WarehousingEffective
, DXP1.Pending
FROM DocXmlPosition DXP1 
LEFT JOIN Doc D ON D.Id = @AddedDocId
LEFT JOIN DocType DT ON DT.Id = D.DocTypeId
LEFT JOIN Article A ON DXP1.ArticleId = A.Id
WHERE DXP1.DocXmlId = @DocId ORDER BY DXP1.RowNumber
-- 60.) CREATE DocBillingAddress
INSERT INTO DocBillingAddress
(
DocId
, PartnerBillingAddressId
, Matchcode
, Name1
, Name2
, Name3
, Position
, Title
, Salutation
, FirstName
, LastName
, Street
, Extension
, Zip
, City
, CountryId
, Tel1
, Tel2
, Mobile
, Fax
, Email
, Homepage
, Keyword
, VatNumber
, TaxNumber
)
SELECT
@AddedDocId DocId
, NULL PartnerBillingAddressId
, DX.SellerNameInfo Matchcode
, DX.SellerNameInfo Name1
, NULL Name2
, NULL Name3
, NULL Position
, NULL Title
, NULL Salutation
, NULL FirstName
, NULL LastName
, DX.SellerStreetInfo Street
, NULL Extension
, DX.SellerZipInfo Zip
, DX.SellerCityInfo City
, DX.SellerCountryInfo CountryId
, DX.SellerPhoneInfo Tel1
, NULL Tel2
, NULL Mobile
, NULL Fax
, DX.SellerEmailInfo Email
, NULL Homepage
, NULL Keyword
, DX.SellerVatIdInfo VatNumber
, DX.SellerTaxInfo TaxNumber
FROM DocXml DX
WHERE DX.Id = @DocId;
-- 61.) CREATE DocDeliveryAddress
INSERT INTO DocDeliveryAddress
(
DocId
, PartnerDeliveryAddressId
, Matchcode
, Name1
, Name2
, Name3
, Position
, Title
, Salutation
, FirstName
, LastName
, Street
, Extension
, Zip
, City
, CountryId
, Tel1
, Tel2
, Mobile
, Fax
, Email
, Homepage
, Keyword
, VatNumber
, TaxNumber
)
SELECT
@AddedDocId DocId
, NULL PartnerBillingAddressId
, DX.SellerNameInfo Matchcode
, DX.SellerNameInfo Name1
, NULL Name2
, NULL Name3
, NULL Position
, NULL Title
, NULL Salutation
, NULL FirstName
, NULL LastName
, DX.SellerStreetInfo Street
, NULL Extension
, DX.SellerZipInfo Zip
, DX.SellerCityInfo City
, DX.SellerCountryInfo CountryId
, DX.SellerPhoneInfo Tel1
, NULL Tel2
, NULL Mobile
, NULL Fax
, DX.SellerEmailInfo Email
, NULL Homepage
, NULL Keyword
, DX.SellerVatIdInfo VatNumber
, DX.SellerTaxInfo TaxNumber
FROM DocXml DX
WHERE DX.Id = @DocId;
-- 70.) UPDATE DocXml
UPDATE DocXml SET
DocId = @AddedDocId
, DocNumber = @NextDocNumber
, Draft = 0
WHERE Id = @DocId;
END -- IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
-- 90.) RETURN
-- RETURN
SELECT * FROM @InvalidValues
-- 91.) ERROR HANDLING
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC262_XInvoice_Import------------------------------------------------------------------------------------
-- xPROC263_DocXml_Positions_Save----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC263_DocXml_Positions_Save
-- PURPOSE: Save Relation between CatalogNumber and Article and write new ones into PartnerCatalogNumber
@parxDocXmlId INT,
@parxTvpDocXmlPosition dbo.xTYPE_DocXmlPosition READONLY
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @XMLContent XML;
DECLARE @TDXPLineId INT, @TDXPArticleId NVARCHAR(30), @DXPXmlArticle NVARCHAR(30), @ArtUoMId NVARCHAR(3), @MatchedUoMId INT;
DECLARE @InvalidValues TABLE (PositionNumber INT, ArticleId NVARCHAR(30), EInvoiceUoMIdInArticle NVARCHAR(3), XmlArticle NVARCHAR(30), EInvoiceUoMIdInXml NVARCHAR(3), TEXT NVARCHAR(100));
DECLARE @row_PositionNum INT, @Counter INT, @TotalRows INT, @row_XmlUoM NVARCHAR(20);
DECLARE @EInvoiceUoMIdInXml NVARCHAR(3);
SELECT @XMLContent = DX.Content FROM DocXml DX WHERE DX.Id = @parxDocXmlId;
SELECT @TotalRows = Count(*) FROM @parxTvpDocXmlPosition;
SET @Counter = 1;
WHILE @Counter <= @TotalRows
BEGIN
SELECT
@TDXPLineId = TDXP.DocXmlPositionId
, @TDXPArticleId = TDXP.ArticleId
, @DXPXmlArticle = DXP.XmlArticle
, @row_PositionNum = DXP.PositionNumber
, @row_XmlUoM = DXP.XmlUoM
FROM @parxTvpDocXmlPosition TDXP
JOIN DocXmlPosition DXP ON DXP.Id = TDXP.DocXmlPositionId And DXP.PositionNumber = @Counter
WHERE TDXP.ArticleId IS NOT NULL AND DXP.ArticleId IS NULL
SELECT @ArtUoMId = AU.EInvoiceUoMId
FROM Article A
JOIN ArticleUoM AU ON A.UoMId = AU.Id
WHERE A.Id = @TDXPArticleId;
WITH XMLNAMESPACES
('urn:un:unece:uncefact:data:standard:CrossIndustryInvoice:100' AS rsm
, 'urn:un:unece:uncefact:data:standard:ReusableAggregateBusinessInformationEntity:100' AS ram
, 'urn:un:unece:uncefact:data:standard:UnqualifiedDataType:100' AS udt
)
SELECT TOP(1)
@EInvoiceUoMIdInXml = E.value('(ram:SpecifiedLineTradeDelivery/ram:BilledQuantity/@unitCode)[1]', 'NVARCHAR(100)')
FROM @XMLContent.nodes('rsm:CrossIndustryInvoice/rsm:SupplyChainTradeTransaction/ram:IncludedSupplyChainTradeLineItem') AS E(E)
JOIN DocXmlPosition DXP ON DXP.Id = @TDXPLineId
WHERE
E.value('(ram:SpecifiedTradeProduct/ram:SellerAssignedID)[1]', 'NVARCHAR(30)') = @DXPXmlArticle
AND DXP.ArticleId IS NULL
INSERT INTO @InvalidValues
(
PositionNumber
, ArticleId
, EInvoiceUoMIdInArticle
, XmlArticle
, EInvoiceUoMIdInXml
, TEXT
)
SELECT
DXP.PositionNumber
, TDXP.ArticleId
, NULL
, DXP.XmlArticle
, NULL
, N'Catalog Number already exists for this Partner, Article and Catalog Number'
FROM @parxTvpDocXmlPosition TDXP
JOIN DocXmlPosition DXP ON DXP.Id = TDXP.DocXmlPositionId
JOIN DocXml DX ON DX.Id = DXP.DocXmlId
JOIN PartnerDetail PD ON PD.Id = DX.PartnerDetailId
WHERE TDXP.ArticleId IS NOT NULL
AND DXP.ArticleId IS NULL
AND NOT EXISTS
(
SELECT 1
FROM @InvalidValues IV
)
AND EXISTS
(
SELECT 1
FROM PartnerCatalogNumber PCN
WHERE PCN.PartnerId = PD.PartnerId
AND PCN.ArticleId = TDXP.ArticleId
AND PCN.CatalogNumber = DXP.XmlArticle
);
SET @Counter = @Counter + 1;
END
INSERT INTO @InvalidValues
(
PositionNumber
, ArticleId
, EInvoiceUoMIdInArticle
, XmlArticle
, EInvoiceUoMIdInXml
, TEXT
)
SELECT
MIN(DXP.PositionNumber)
, TDXP.ArticleId
, NULL
, MIN(DXP.XmlArticle)
, NULL
, N'Article is assigned to multiple Catalog Numbers'
FROM @parxTvpDocXmlPosition TDXP
JOIN DocXmlPosition DXP ON DXP.Id = TDXP.DocXmlPositionId
WHERE TDXP.ArticleId IS NOT NULL
AND DXP.ArticleId IS NULL
GROUP BY
TDXP.ArticleId
HAVING COUNT(DISTINCT DXP.XmlArticle) > 1;
IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
INSERT INTO PartnerCatalogNumber(
PartnerId
, ArticleId
, CatalogNumber
)
SELECT
DISTINCT
PD.PartnerId
, TDXP.ArticleId
, DXP.XmlArticle
FROM @parxTvpDocXmlPosition TDXP
LEFT JOIN DocXmlPosition DXP ON DXP.Id = TDXP.DocXmlPositionId
LEFT JOIN DocXml DX ON DX.Id = DXP.DocXmlId
LEFT JOIN PartnerDetail PD ON PD.Id = DX.PartnerDetailId
WHERE DXP.ArticleId IS NULL AND TDXP.ArticleId IS NOT NULL
AND NOT EXISTS
(
SELECT 1
FROM PartnerCatalogNumber PCN
WHERE PCN.PartnerId = PD.PartnerId
AND PCN.ArticleId = TDXP.ArticleId
AND PCN.CatalogNumber = DXP.XmlArticle
);
UPDATE DocXmlPosition SET
ArticleId = TDXP.ArticleId
, UoMId = A.UoMId
, FinanceGroupArticleId = A.ProcurementFinanceGroupId
, FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId 
, AccountId = FGAD.RevenueExpenditureAccountId
, CostCenterId = FGAD.CostCenterId
, CostBearerId = FGAD.CostBearerId
, CatalogNumberId = PCN.Id
FROM DocXmlPosition DXP
LEFT JOIN @parxTvpDocXmlPosition TDXP ON DXP.Id = TDXP.DocXmlPositionId
LEFT JOIN DocXml DX ON DX.Id = DXP.DocXmlId
LEFT JOIN PartnerDetail PD ON PD.Id = DX.PartnerDetailId
LEFT JOIN Article A ON A.Id = TDXP.ArticleId
LEFT JOIN FinanceGroupArticleDetail FGAD ON FGAD.FinanceGroupArticleId = A.ProcurementFinanceGroupId AND FGAD.FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId 
LEFT JOIN PartnerCatalogNumber PCN ON PCN.PartnerId = PD.PartnerId AND PCN.ArticleId = TDXP.ArticleId AND PCN.Active = 1
WHERE DXP.ArticleId IS NULL AND TDXP.ArticleId IS NOT NULL
END -- IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
SELECT * FROM @InvalidValues
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC263_DocXml_Positions_Save----------------------------------------------------------------------------------------------------
