CREATE OR ALTER PROCEDURE 
xPROC264_DocXml_PartnerId
-- PURPOSE: Assign DocXml record to a Partner and update DocXml record with Partner Data
@parxDocXmlId INT,
@parxPartnerId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
DECLARE
@PartnerDetailId INT
, @TermsOfDeliveryId INT
, @TermsOfPaymentId INT
, @PartnerContactPersonId INT
, @FinanceGroupPartnerDetailId INT
, @VatNumber NVARCHAR(20)
, @DocCategoryId NVARCHAR(17)
, @LanguageId NVARCHAR(5);
BEGIN TRANSACTION
BEGIN TRY
SELECT
@DocCategoryId = DX.DocCategoryId
FROM DocXml DX
WHERE DX.Id = @parxDocXmlId;
SELECT
@PartnerDetailId = PD.Id
, @TermsOfDeliveryId = PD.TermsOfDeliveryId
, @TermsOfPaymentId = PD.TermsOfPaymentId
, @PartnerContactPersonId = PD.StandardContactPersonId
, @FinanceGroupPartnerDetailId = PD.FinanceGroupPartnerDetailId
, @LanguageId = P.LanguageId
FROM Partner P
JOIN PartnerDetail PD ON P.Id = PD.PartnerId AND PD.PartnerTypeId = (CASE WHEN @DocCategoryId = 'Purchase' THEN 'Supplier' ELSE 'Customer' END)
WHERE P.Id = @parxPartnerId
SELECT
@VatNumber = PBA.VatNumber
FROM PartnerBillingAddress PBA
LEFT JOIN PartnerDetail PD ON PD.Id = @PartnerDetailId
WHERE PBA.Id = PD.StandardBillingAddressId
UPDATE DocXml SET
PartnerId = @parxPartnerId
, PartnerDetailId = @PartnerDetailId
, TermsOfDeliveryId = @TermsOfDeliveryId
, TermsOfPaymentId = @TermsOfPaymentId
, PartnerContactPersonId = @PartnerContactPersonId
, VatNumber = @VatNumber
, LanguageId = @LanguageId 
WHERE Id = @parxDocXmlId;
UPDATE DocXmlPosition SET
ArticleId = A.Id
, FinanceGroupArticleId= A.ProcurementFinanceGroupId
, FinanceGroupPartnerDetailId = @FinanceGroupPartnerDetailId 
, UoMId = A.UoMId
, AccountId = FGAD.RevenueExpenditureAccountId
, CostCenterId = FGAD.CostCenterId
, CostBearerId = FGAD.CostBearerId
, CatalogNumberId = PCN.Id
FROM DocXmlPosition DXP
LEFT JOIN PartnerCatalogNumber PCN ON PCN.PartnerId = @parxPartnerId AND PCN.CatalogNumber = DXP.XmlArticle AND PCN.Active = 1
LEFT JOIN Article A ON A.Id = PCN.ArticleId
LEFT JOIN FinanceGroupArticleDetail FGAD ON FGAD.FinanceGroupArticleId = A.ProcurementFinanceGroupId AND FGAD.FinanceGroupPartnerDetailId = @FinanceGroupPartnerDetailId 
WHERE DXP.DocXmlId = @parxDocXmlId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC264_DocXml_PartnerId----------------------------------------------------------------------------------------------------
