CREATE OR ALTER PROCEDURE 
xPROC270U_DocContract_StartDate
-- PURPOSE: Update the StartDate with passed value and Update followups
-- 26.06.26
@parxDocId INT,
@parxStartDate DATE
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @EndDate DATETIME;
SELECT @EndDate = EndDate FROM DocContract WHERE DocId = @parxDocId;
DECLARE @LeadTimeDays INT;
SELECT @LeadTimeDays = LeadTimeDays FROM DocContract WHERE DocId = @parxDocId;
DECLARE @DaysDiff INT = CASE WHEN @EndDate IS NOT NULL THEN DATEDIFF(DAY, @parxStartDate, @EndDate) ELSE 0 END;
DECLARE @CycleQuantity INT;
-- Bestimme die Zykluslänge basierend auf CyclePeriodId
DECLARE @CyclePeriodId INT;
SELECT @CyclePeriodId = CyclePeriodId FROM DocContract WHERE DocId = @parxDocId;
DECLARE @PrePayment BIT;
SELECT @PrePayment = PrePayment FROM DocContract WHERE DocId = @parxDocId;
DECLARE @NextAppointment DATE;
SET @CycleQuantity = CASE
WHEN @CyclePeriodId = 1 THEN @DaysDiff -- täglich
WHEN @CyclePeriodId = 2 THEN
CASE
-- Prüfen, ob das Enddatum innerhalb der Woche nach dem Startdatum liegt
WHEN DATEADD(WEEK, DATEDIFF(WEEK, DATEADD(DAY, -1, @parxStartDate), @EndDate), DATEADD(DAY, -1, @parxStartDate)) <= @EndDate THEN
DATEDIFF(WEEK, DATEADD(DAY, -1, @parxStartDate), @EndDate)
ELSE
DATEDIFF(WEEK, DATEADD(DAY, -1, @parxStartDate), @EndDate) - 1
END -- wöchentlich
WHEN @CyclePeriodId = 3 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Monat ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate), DATEADD(DAY, -1, @parxStartDate)) <= @EndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate)
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate) - 1
END -- monatlich
WHEN @CyclePeriodId = 4 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Quartal ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate) / 3 * 3, DATEADD(DAY, -1, @parxStartDate)) <= @EndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate) / 3
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate) / 3 - 1
END -- vierteljährlich
WHEN @CyclePeriodId = 5 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Halbjahr ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate) / 6 * 6, DATEADD(DAY, -1, @parxStartDate)) <= @EndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate) / 6
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @parxStartDate), @EndDate) / 6 - 1
END -- halbjährig
WHEN @CyclePeriodId = 6 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Jahr ist
WHEN DATEADD(YEAR, DATEDIFF(YEAR, DATEADD(DAY, -1, @parxStartDate), @EndDate), DATEADD(DAY, -1, @parxStartDate)) <= @EndDate THEN
DATEDIFF(YEAR, DATEADD(DAY, -1, @parxStartDate), @EndDate)
ELSE
DATEDIFF(YEAR, DATEADD(DAY, -1, @parxStartDate), @EndDate) - 1
END -- jährlich
ELSE 0
END;
SET @NextAppointment = CASE
WHEN @PrePayment = 1 THEN @parxStartDate -- Wenn PrePayment wahr ist, setze @NextAppointment auf @StartDate
ELSE CASE @CyclePeriodId
WHEN 1 THEN @parxStartDate -- täglich
WHEN 2 THEN  DATEADD(DAY, -1, DATEADD(WEEK, 1, @parxStartDate))-- wöchentlich
WHEN 3 THEN DATEADD(DAY, -1, DATEADD(MONTH, 1, @parxStartDate)) -- monatlich
WHEN 4 THEN DATEADD(DAY, -1, DATEADD(MONTH, 3, @parxStartDate)) -- vierteljährlich
WHEN 5 THEN DATEADD(DAY, -1, DATEADD(MONTH, 6, @parxStartDate)) -- halbjährlich
WHEN 6 THEN DATEADD(DAY, -1, DATEADD(YEAR, 1, @parxStartDate)) -- jährlich
ELSE @parxStartDate-- Fallback auf Startdatum, wenn keine gültige Perioden-ID vorhanden ist
END
END;
IF @NextAppointment > @EndDate
SET @NextAppointment = NULL;
DECLARE @NextExecutionDate datetimeoffset(0);
SET @NextExecutionDate = DATEADD(DAY, -@LeadTimeDays, @NextAppointment);
-- Update der EndDate und CycleQuantity
UPDATE DocContract
SET StartDate = @parxStartDate, CycleQuantity = @CycleQuantity
, NextAppointment = @NextAppointment 
, NextExecutionDate = @NextExecutionDate
WHERE DocId = @parxDocId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC270U_DocContract_StartDate----------------------------------------------------------------------------------------------------
