CREATE OR ALTER PROCEDURE 
xPROC270U_DocContract_EndDate
-- PURPOSE: Update the EndDate with passed value and Update followups
-- 26.06.26
@parxDocId INT,
@parxEndDate DATE
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @StartDate DATETIME;
SELECT @StartDate = StartDate FROM DocContract WHERE DocId = @parxDocId;
DECLARE @LeadTimeDays INT;
SELECT @LeadTimeDays = LeadTimeDays FROM DocContract WHERE DocId = @parxDocId;
DECLARE @DaysDiff INT = CASE WHEN @StartDate IS NOT NULL THEN DATEDIFF(DAY, @StartDate, @parxEndDate) ELSE 0 END;
DECLARE @CycleQuantity INT;
-- Bestimme die Zykluslänge basierend auf CyclePeriodId
DECLARE @CyclePeriodId INT;
SELECT @CyclePeriodId = CyclePeriodId FROM DocContract WHERE DocId = @parxDocId;
DECLARE @PrePayment BIT;
SELECT @PrePayment = PrePayment FROM DocContract WHERE DocId = @parxDocId;
DECLARE @ExecutedCycles INT;
SELECT @ExecutedCycles = ExecutedCycles FROM DocContract WHERE DocId = @parxDocId;
DECLARE @NextAppointment DATE;
SET @CycleQuantity = CASE
WHEN @CyclePeriodId = 1 THEN @DaysDiff -- täglich
WHEN @CyclePeriodId = 2 THEN
CASE
-- Prüfen, ob das Enddatum innerhalb der Woche nach dem Startdatum liegt
WHEN DATEADD(WEEK, DATEDIFF(WEEK, DATEADD(DAY, -1, @StartDate), @parxEndDate), DATEADD(DAY, -1, @StartDate)) <= @parxEndDate THEN
DATEDIFF(WEEK, DATEADD(DAY, -1, @StartDate), @parxEndDate)
ELSE
DATEDIFF(WEEK, DATEADD(DAY, -1, @StartDate), @parxEndDate) - 1
END -- wöchentlich
WHEN @CyclePeriodId = 3 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Monat ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate), DATEADD(DAY, -1, @StartDate)) <= @parxEndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate)
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate) - 1
END -- monatlich
WHEN @CyclePeriodId = 4 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Quartal ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate) / 3 * 3, DATEADD(DAY, -1, @StartDate)) <= @parxEndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate) / 3
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate) / 3 - 1
END -- vierteljährlich
WHEN @CyclePeriodId = 5 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Halbjahr ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate) / 6 * 6, DATEADD(DAY, -1, @StartDate)) <= @parxEndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate) / 6
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @parxEndDate) / 6 - 1
END -- halbjährig
WHEN @CyclePeriodId = 6 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Jahr ist
WHEN DATEADD(YEAR, DATEDIFF(YEAR, DATEADD(DAY, -1, @StartDate), @parxEndDate), DATEADD(DAY, -1, @StartDate)) <= @parxEndDate THEN
DATEDIFF(YEAR, DATEADD(DAY, -1, @StartDate), @parxEndDate)
ELSE
DATEDIFF(YEAR, DATEADD(DAY, -1, @StartDate), @parxEndDate) - 1
END -- jährlich
ELSE 0
END;
IF @CycleQuantity <= @ExecutedCycles
BEGIN
SET @NextAppointment = NULL;
END
ELSE
BEGIN
DECLARE @Factor INT;
-- PrePayment steuert, ob der aktuelle oder der nächste Zyklus gemeint ist
IF @PrePayment = 1
SET @Factor = @ExecutedCycles;      -- z.B. 3 ausgeführte Zyklen: Start + 3 * Periode
ELSE
SET @Factor = @ExecutedCycles + 1;  -- ohne PrePayment: Start + (Executed + 1) * Periode
SET @NextAppointment = CASE @CyclePeriodId
WHEN 1 THEN DATEADD(DAY   , @Factor    , @StartDate)         -- täglich
WHEN 2 THEN DATEADD(WEEK  , @Factor    , @StartDate)         -- wöchentlich
WHEN 3 THEN DATEADD(MONTH , @Factor    , @StartDate)         -- monatlich
WHEN 4 THEN DATEADD(MONTH , @Factor * 3, @StartDate)         -- vierteljährlich
WHEN 5 THEN DATEADD(MONTH , @Factor * 6, @StartDate)         -- halbjährlich
WHEN 6 THEN DATEADD(YEAR  , @Factor    , @StartDate)         -- jährlich
ELSE @StartDate
END;
-- falls der berechnete Termin nach dem neuen EndDate liegt → kein nächster Termin mehr
IF @NextAppointment > @parxEndDate
SET @NextAppointment = NULL;
END;
DECLARE @NextExecutionDate datetimeoffset(0);
SET @NextExecutionDate = DATEADD(DAY, -@LeadTimeDays, @NextAppointment);
-- Update der EndDate und CycleQuantity
UPDATE DocContract
SET EndDate = @parxEndDate
, CycleQuantity = @CycleQuantity
, NextAppointment = @NextAppointment 
, NextExecutionDate = @NextExecutionDate
, StatusId = CASE WHEN @NextAppointment IS NULL AND TerminatedOnDate IS NOT NULL AND ExecutedCycles != 0 THEN 'TERMINATED' WHEN @NextAppointment IS NULL AND TerminatedOnDate IS NULL AND ExecutedCycles != 0 THEN 'FULFILLED' WHEN ExecutedCycles != 0 THEN 'ACTIVE' ELSE 'DRAFT' END
WHERE DocId = @parxDocId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC270U_DocContract_EndDate----------------------------------------------------------------------------------------------------
-- xPROC270U_DocContract_CyclePeriodId----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC270U_DocContract_CyclePeriodId
-- PURPOSE: Update the CyclePeriodId with passed value and Update followups
-- 26.06.26
@parxDocId INT,
@parxCyclePeriodId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @StartDate DATETIME;
SELECT @StartDate = StartDate FROM DocContract WHERE DocId = @parxDocId;
DECLARE @LeadTimeDays INT;
SELECT @LeadTimeDays = LeadTimeDays FROM DocContract WHERE DocId = @parxDocId;
DECLARE @EndDate DATETIME;
SELECT @EndDate = EndDate FROM DocContract WHERE DocId = @parxDocId;
DECLARE @PrePayment BIT;
SELECT @PrePayment = PrePayment FROM DocContract WHERE DocId = @parxDocId;
DECLARE @DaysDiff INT = CASE WHEN @StartDate IS NOT NULL AND @EndDate IS NOT NULL THEN DATEDIFF(DAY, @StartDate, @EndDate ) ELSE 0 END;
DECLARE @CycleQuantity INT;
DECLARE @NextAppointment DATE;
SET @CycleQuantity = CASE
WHEN @parxCyclePeriodId = 1 THEN @DaysDiff -- täglich
WHEN @parxCyclePeriodId = 2 THEN
CASE
-- Prüfen, ob das Enddatum innerhalb der Woche nach dem Startdatum liegt
WHEN DATEADD(WEEK, DATEDIFF(WEEK, DATEADD(DAY, -1, @StartDate), @EndDate), DATEADD(DAY, -1, @StartDate)) <= @EndDate THEN
DATEDIFF(WEEK, DATEADD(DAY, -1, @StartDate), @EndDate)
ELSE
DATEDIFF(WEEK, DATEADD(DAY, -1, @StartDate), @EndDate) - 1
END -- wöchentlich
WHEN @parxCyclePeriodId = 3 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Monat ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate), DATEADD(DAY, -1, @StartDate)) <= @EndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate)
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate) - 1
END -- monatlich
WHEN @parxCyclePeriodId = 4 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Quartal ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate) / 3 * 3, DATEADD(DAY, -1, @StartDate)) <= @EndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate) / 3
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate) / 3 - 1
END -- vierteljährlich
WHEN @parxCyclePeriodId = 5 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Halbjahr ist
WHEN DATEADD(MONTH, DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate) / 6 * 6, DATEADD(DAY, -1, @StartDate)) <= @EndDate THEN
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate) / 6
ELSE
DATEDIFF(MONTH, DATEADD(DAY, -1, @StartDate), @EndDate) / 6 - 1
END -- halbjährig
WHEN @parxCyclePeriodId = 6 THEN
CASE
-- Prüfen, ob der Endtag gleich oder nach dem Starttag im Jahr ist
WHEN DATEADD(YEAR, DATEDIFF(YEAR, DATEADD(DAY, -1, @StartDate), @EndDate), DATEADD(DAY, -1, @StartDate)) <= @EndDate THEN
DATEDIFF(YEAR, DATEADD(DAY, -1, @StartDate), @EndDate)
ELSE
DATEDIFF(YEAR, DATEADD(DAY, -1, @StartDate), @EndDate) - 1
END -- jährlich
ELSE 0
END;
SET @NextAppointment = CASE
WHEN @PrePayment = 1 THEN @StartDate -- Wenn PrePayment wahr ist, setze @NextAppointment auf @StartDate
ELSE CASE @parxCyclePeriodId
WHEN 1 THEN @StartDate-- täglich
WHEN 2 THEN  DATEADD(DAY, -1, DATEADD(WEEK, 1, @StartDate))-- wöchentlich
WHEN 3 THEN DATEADD(DAY, -1, DATEADD(MONTH, 1, @StartDate)) -- monatlich
WHEN 4 THEN DATEADD(DAY, -1, DATEADD(MONTH, 3, @StartDate)) -- vierteljährlich
WHEN 5 THEN DATEADD(DAY, -1, DATEADD(MONTH, 6, @StartDate)) -- halbjährlich
WHEN 6 THEN DATEADD(DAY, -1, DATEADD(YEAR, 1, @StartDate)) -- jährlich
ELSE @StartDate -- Fallback auf Startdatum, wenn keine gültige Perioden-ID vorhanden ist
END
END;
IF @NextAppointment > @EndDate
SET @NextAppointment = NULL;
DECLARE @NextExecutionDate datetimeoffset(0);
SET @NextExecutionDate = DATEADD(DAY, -@LeadTimeDays, @NextAppointment);
-- Update der EndDate und CycleQuantity
UPDATE DocContract
SET CyclePeriodId = @parxCyclePeriodId , CycleQuantity = @CycleQuantity
, NextAppointment = @NextAppointment 
, NextExecutionDate = @NextExecutionDate
WHERE DocId = @parxDocId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC270U_DocContract_CyclePeriodId----------------------------------------------------------------------------------------------------
