CREATE OR ALTER PROCEDURE 
xPROC270U_DocContract_Prepayment
-- PURPOSE: Update the Prepayment with passed value and Update followups
-- 26.06.26
@parxDocId INT,
@parxPrepayment BIT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @StartDate DATETIME;
SELECT @StartDate = StartDate FROM DocContract WHERE DocId = @parxDocId;
DECLARE @LeadTimeDays INT;
SELECT @LeadTimeDays = LeadTimeDays FROM DocContract WHERE DocId = @parxDocId;
DECLARE @EndDate DATETIME;
SELECT @EndDate = EndDate FROM DocContract WHERE DocId = @parxDocId;
DECLARE @CyclePeriodId INT;
SELECT @CyclePeriodId = CyclePeriodId FROM DocContract WHERE DocId = @parxDocId;
DECLARE @NextAppointment DATE;
SET @NextAppointment = CASE
WHEN @parxPrepayment = 1 THEN @StartDate -- Wenn Prepayment wahr ist, setze @NextAppointment auf @StartDate
ELSE CASE @CyclePeriodId
WHEN 1 THEN @StartDate-- täglich
WHEN 2 THEN  DATEADD(DAY, -1, DATEADD(WEEK, 1, @StartDate))-- wöchentlich
WHEN 3 THEN DATEADD(DAY, -1, DATEADD(MONTH, 1, @StartDate)) -- monatlich
WHEN 4 THEN DATEADD(DAY, -1, DATEADD(MONTH, 3, @StartDate)) -- vierteljährlich
WHEN 5 THEN DATEADD(DAY, -1, DATEADD(MONTH, 6, @StartDate)) -- halbjährlich
WHEN 6 THEN DATEADD(DAY, -1, DATEADD(YEAR, 1, @StartDate)) -- jährlich
ELSE @StartDate -- Fallback auf Startdatum, wenn keine gültige Perioden-ID vorhanden ist
END
END;
IF @NextAppointment > @EndDate
SET @NextAppointment = NULL;
DECLARE @NextExecutionDate datetimeoffset(0);
SET @NextExecutionDate = DATEADD(DAY, -@LeadTimeDays, @NextAppointment);
UPDATE DocContract
SET Prepayment = @parxPrepayment
, NextAppointment = @NextAppointment 
, NextExecutionDate = @NextExecutionDate
WHERE DocId = @parxDocId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC270U_DocContract_Prepayment----------------------------------------------------------------------------------------------------
