-- xPROC271U_DocContract_CreateTargetDoc------------------------------------
-- Creator: MH
-- Created: 2023-07-10
-- PURPOSE: create new Doc with Data from Contract and update Contract
-- 1.) Create and prefill Doc 
-- 2.) Create and prefill DeliveryAddress
-- 3.) Create and prefill BillingAddress
-- 4.) Create and prefill DocPositionWarehousing
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE
xPROC271U_DocContract_CreateTargetDoc
@parxDocCategoryId NVARCHAR(10),
@parxDocTypeId NVARCHAR(35),
@parxPartnerId INT,
@parxSourceDocId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 1.) Create and prefill Doc 
-- Declare Variables
-- From Scope
DECLARE @newxDocId INT
-- Generate new DocNumber
DECLARE @SQLString NVARCHAR(100)
DECLARE @ParmDefinition NVARCHAR(75)
DECLARE @NextNumber NVARCHAR(10)
DECLARE @newxDocNumber NVARCHAR(20)
DECLARE @NextAppointment Date
SELECT
@NextAppointment = NextAppointment
FROM DocContract
WHERE DocId = @parxSourceDocId
-- FROM FinancePostingPeriod
DECLARE @PostingPeriodId INT
SET @PostingPeriodId = dbo.xFUNCTION001_GetCurrentPostingPeriodId()
-- FROM DocType
DECLARE @InventoryStatusId NVARCHAR(10)
DECLARE @WarehousingEffective INT
DECLARE @RevenueEffective INT
DECLARE @Draft BIT
DECLARE @DocNumberPrefix NVARCHAR(3)
-- FROM PartnerDetail
DECLARE @PartnerDetailId INT
DECLARE @PartnerContactPersonId INT
DECLARE @ClerkId INT
DECLARE @SalesPersonId INT
DECLARE @DivergentInvoiceRecipientId INT
DECLARE @TermsOfDeliveryId INT
DECLARE @TermsOfPaymentId INT
DECLARE @PriceListId INT
DECLARE @StandardDeliveryAddressId INT
DECLARE @StandardBillingAddressId INT
DECLARE @ForeignCurrencyId NVARCHAR(3)
-- FROM Partner
DECLARE @LanguageId NVARCHAR(5)
-- FROM AdminCurrencyRate
DECLARE @Rate DECIMAL(19,6)
-- FROM PartnerDetailOutput 
DECLARE @OutputControlFormatId INT
-- Select From
-- FROM DocType
SELECT
@InventoryStatusId = InventoryStatusId,
@WarehousingEffective = WarehousingEffective,
@RevenueEffective = RevenueEffective,
@Draft = Draft,
@DocNumberPrefix = DocNumberPrefix
FROM DocType
WHERE Id = @parxDocTypeId
-- FROM PartnerDetail
SELECT
@PartnerDetailId = Id
, @PartnerContactPersonId = StandardContactPersonId
, @ClerkId = EmployeeId
, @SalesPersonId = SalesPersonId
, @DivergentInvoiceRecipientId = DivergentInvoiceRecipientId
, @TermsOfDeliveryId = TermsOfDeliveryId
, @TermsOfPaymentId = TermsOfPaymentId
, @PriceListId = PriceListSalesId
,@StandardDeliveryAddressId = StandardDeliveryAddressId
, @StandardBillingAddressId = StandardBillingAddressId
, @ForeignCurrencyId = ForeignCurrencyId
FROM PartnerDetail WHERE PartnerId = @parxPartnerId AND PartnerTypeId = CASE WHEN @parxDocCategoryId = 'Sales' THEN 'Customer' ELSE 'Supplier' END
-- FROM Partner
SELECT
@LanguageId = LanguageId
FROM Partner WHERE Id = @parxPartnerId
-- FROM AdminCurrencyRate
SET @Rate = NULL
--Generate new DocNumber
CREATE TABLE #DocNumberResult (NewDocumentNumber NVARCHAR(30));
-- Aufruf der Prozedur und speichere den Rückgabewert in der temporären Tabelle
INSERT INTO #DocNumberResult
EXEC dbo.xPROC200_GenerateNewDocNumber
@DocTypeId = @parxDocTypeId  -- Übergabe des DocTypeId
-- Zuweisung des Wertes aus der temporären Tabelle in die Variable @newxDocNumber
SELECT @newxDocNumber = NewDocumentNumber
FROM #DocNumberResult;
-- FROM PartnerDetailOutput 
SELECT
@OutputControlFormatId = OutputControlFormatId
FROM PartnerDetailOutput  WHERE PartnerDetailId = @PartnerDetailId AND DocTypeId = @parxDocTypeId 
-- INSERT INTO Doc
INSERT INTO Doc(
DocCategoryId
, DocTypeId
, DocNumber
, InventoryStatusId
, WarehousingEffective
, RevenueEffective
, PartnerId
, PartnerDetailId
, StatusId
, Transferable
, Draft
, DocDate
, PostingDate
, PostingPeriodId
, ShippingDate
, DeliveryDate
, PartnerContactPersonId
, ClerkId
, SalesPersonId
, OurReference
, YourDoc
, YourDocDate
, InternalRemark
, Subject
, Version
, DivergentInvoiceRecipientId
, TermsOfDeliveryId
, EuWork
, LanguageId
, ReportTemplateId
, ApprovalRequired
, EDocTypeId
, TermsOfPaymentId
, ProjectId
, PriceListId
, DocDiscountPercent
, DownPaymentSum
, ForeignCurrencyId
, Rate
, LocationId
, StandardWarehouseId
, DateCreated
, DocContractId
, OutputControlFormatId
)
-- VALUES
SELECT
@parxDocCategoryId
, @parxDocTypeId 
, @newxDocNumber
, @InventoryStatusId
, @WarehousingEffective
, @RevenueEffective
, @parxPartnerId
, @PartnerDetailId
, 'open'
, 1
, @Draft
, GETDATE()
, NULL
, @PostingPeriodId
, DC.NextAppointment
, DC.NextAppointment
, D.PartnerContactPersonId
, D.ClerkId
, D.SalesPersonId
, D.OurReference
, D.YourDoc
, DC.NextAppointment
, D.InternalRemark
, CONCAT(
D.Subject
, ' '
, CONVERT(char(10), DC.NextAppointment, 104)
, ' - '
, CONVERT(char(10),
DATEADD(DAY, -1,
CASE DC.CyclePeriodId
WHEN 1 THEN DATEADD(DAY, 1, DC.NextAppointment)
WHEN 2 THEN DATEADD(DAY, 7, DC.NextAppointment)
WHEN 3 THEN DATEADD(MONTH, 1, DC.NextAppointment)
WHEN 4 THEN DATEADD(MONTH, 3, DC.NextAppointment)
WHEN 5 THEN DATEADD(MONTH, 6, DC.NextAppointment)
WHEN 6 THEN DATEADD(YEAR, 1, DC.NextAppointment)
ELSE DC.NextAppointment
END
)
, 104
)
)
, 1
, D.DivergentInvoiceRecipientId
, D.TermsOfDeliveryId
, D.EuWork
, D.LanguageId
, D.ReportTemplateId
, D.ApprovalRequired
, D.EDocTypeId
, D.TermsOfPaymentId
, D.ProjectId
, D.PriceListId
, D.DocDiscountPercent
, D.DownPaymentSum
, D.ForeignCurrencyId
, D.Rate
, D.LocationId
, D.StandardWarehouseId
, GETDATE()
, D.Id
, @OutputControlFormatId
FROM Doc D
LEFT JOIN DocContract DC ON DC.DocId = D.Id
WHERE D.Id = @parxSourceDocId
SET @newxDocId = SCOPE_IDENTITY()
-- 1a.) UPDATE Doc with Extra Fields from source Doc
DECLARE @ExtraFieldDocSetList nvarchar(max);
DECLARE @ExtraFieldDocUpdateSql nvarchar(max);
SELECT
@ExtraFieldDocSetList = STRING_AGG(
CAST(
CONCAT(
N'TargetD.'
, QUOTENAME(TargetColumn.name)
, N' = SourceD.'
, QUOTENAME(SourceColumn.name)
)
AS nvarchar(max))
, CONCAT(CHAR(13), CHAR(10), N', ')
)
FROM dbo.ExtraField AS TargetExtraField
JOIN dbo.ExtraField AS SourceExtraField
ON SourceExtraField.Name = TargetExtraField.Name
AND SourceExtraField.SystemTableId = N'Doc'
JOIN sys.columns AS TargetColumn
ON TargetColumn.object_id = OBJECT_ID(N'dbo.Doc')
AND TargetColumn.name = TargetExtraField.Id
JOIN sys.columns AS SourceColumn
ON SourceColumn.object_id = OBJECT_ID(N'dbo.Doc')
AND SourceColumn.name = SourceExtraField.Id
WHERE TargetExtraField.SystemTableId = N'Doc'
AND TargetExtraField.Id LIKE N'XX%'
AND SourceExtraField.Id LIKE N'XX%'
AND TargetColumn.is_computed = 0
AND SourceColumn.is_computed = 0;
IF @ExtraFieldDocSetList IS NOT NULL
BEGIN
SET @ExtraFieldDocUpdateSql = CONCAT(
N'UPDATE TargetD'
, CHAR(13)
, CHAR(10)
, N'SET '
, @ExtraFieldDocSetList
, CHAR(13)
, CHAR(10)
, N'FROM dbo.Doc AS TargetD'
, CHAR(13)
, CHAR(10)
, N'JOIN dbo.Doc AS SourceD'
, CHAR(13)
, CHAR(10)
, N'ON SourceD.Id = @SourceDocId'
, CHAR(13)
, CHAR(10)
, N'WHERE TargetD.Id = @TargetDocId;'
);
EXEC sys.sp_executesql
@ExtraFieldDocUpdateSql
, N'@SourceDocId int, @TargetDocId int'
, @SourceDocId = @parxSourceDocId
, @TargetDocId = @newxDocId;
END
-- 2.) Create and prefill DeliveryAddress
INSERT INTO dbo.DocDeliveryAddress (
DocId
, PartnerDeliveryAddressId
, Matchcode
, Name1
, Name2
, Name3
, Position
, Title
, Salutation
, FirstName
, LastName
, Street
, Extension
, Zip
, City
, CountryId
, Tel1
, Tel2
, Mobile
, Fax
, Email
, Homepage
, Keyword
, VatNumber
, TaxNumber
, ShippingZoneId
)
SELECT
@newxDocId,
DDA.PartnerDeliveryAddressId,
DDA.Matchcode,
DDA.Name1,
DDA.Name2,
DDA.Name3,
DDA.Position,
DDA.Title,
DDA.Salutation,
DDA.FirstName,
DDA.LastName,
DDA.Street,
DDA.Extension,
DDA.Zip,
DDA.City,
DDA.CountryId,
DDA.Tel1,
DDA.Tel2,
DDA.Mobile,
DDA.Fax,
DDA.Email,
DDA.Homepage,
DDA.Keyword,
DDA.VatNumber,
DDA.TaxNumber,
DDA.ShippingZoneId
FROM DocDeliveryAddress DDA
WHERE DDA.DocId= @parxSourceDocId;
-- 3.) Create and prefill BillingAddress
INSERT INTO dbo.DocBillingAddress (
DocId
, PartnerBillingAddressId
, Matchcode
, Name1
, Name2
, Name3
, Position
, Title
, Salutation
, FirstName
, LastName
, Street
, Extension
, Zip
, City
, CountryId
, Tel1
, Tel2
, Mobile
, Fax
, Email
, Homepage
, Keyword
, VatNumber
, TaxNumber
, EInvoiceRoutingId
)
SELECT
@newxDocId,
DBA.PartnerBillingAddressId,
DBA.Matchcode,
DBA.Name1,
DBA.Name2,
DBA.Name3,
DBA.Position,
DBA.Title,
DBA.Salutation,
DBA.FirstName,
DBA.LastName,
DBA.Street,
DBA.Extension,
DBA.Zip,
DBA.City,
DBA.CountryId,
DBA.Tel1,
DBA.Tel2,
DBA.Mobile,
DBA.Fax,
DBA.Email,
DBA.Homepage,
DBA.Keyword,
DBA.VatNumber,
DBA.TaxNumber,
DBA.EInvoiceRoutingId
FROM DocBillingAddress DBA
WHERE DBA.DocId= @parxSourceDocId;
INSERT INTO DocHeaderText(
DocId
, Header
)
SELECT
@newxDocId,
Header
FROM DocHeaderText
WHERE DocId= @parxSourceDocId;
INSERT INTO DocFooterText(
