WHERE DocId= @parxSourceDocId;
INSERT INTO DocPosition(
DocId
, RowNumber
, PositionTypeId
, PositionNumber
, ParentPositionId
, ChildPositionNumber
, StatusId
, ArticleId
, Name1
, Name2
, Quantity
, QuantityOpen
, UoMId
, ShippingDate
, DeliveryDate
, Price
, PredecessorId
, QuantityTransferred
, Level
, PositionLabel
, CatalogNumberId
, Dissolve
, PositionWeight
, RelatedPositionId
, ProjectId
, Start
, Stop
, PriceUnitId
, ArticleCostPrice
, DiscountPercent
, QuantityDiscountPercent
, DocDiscountPercent
, PrepaymentFactor
, RevenueEffective
, SalesPersonId
, CommissionPercent
, ProfitFactor
, CostPriceFactor
, FinanceGroupArticleId
, FinanceGroupPartnerDetailId
, TaxKeyId
, TaxFactor
, TaxPercent
, AccountId
, CostCenterId
, CostBearerId
, Warehousing
, WarehousingEffective
, Pending
)
SELECT
@newxDocId
, DP.RowNumber
, DP.PositionTypeId
, DP.PositionNumber
, DP.ParentPositionId
, DP.ChildPositionNumber
, DP.StatusId
, DP.ArticleId
, DP.Name1
, DP.Name2
, DP.Quantity
, DP.QuantityOpen
, DP.UoMId
, D.ShippingDate
, D.DeliveryDate
, DP.Price
, DP.Id
, 0
, DP.Level
, DP.PositionLabel
, DP.CatalogNumberId
, DP.Dissolve
, DP.PositionWeight
, NULL
, DP.ProjectId
, DP.Start
, DP.Stop
, DP.PriceUnitId
, DP.ArticleCostPrice
, DP.DiscountPercent
, DP.QuantityDiscountPercent
, DP.DocDiscountPercent
, CASE WHEN A.IsPrepayment = 1 THEN NewDT.PrepaymentTrueArticleFactor ELSE NewDT.PrepaymentFalseArticleFactor END
, DT.RevenueEffective
, DP.SalesPersonId
, DP.CommissionPercent
, CASE WHEN A.IsPrepayment = 1 THEN 0 ELSE 1 END
, CASE WHEN DT.DocCategoryId= 'Purchase'  THEN 0 ELSE 1 END
, DP.FinanceGroupArticleId
, DP.FinanceGroupPartnerDetailId
, DP.TaxKeyId
, DP.TaxFactor
, DP.TaxPercent
, DP.AccountId
, DP.CostCenterId
, DP.CostBearerId
, DP.Warehousing
, 0
, DP.Pending
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN DocType DT ON DT.Id = @parxDocTypeId 
LEFT JOIN Doc NewD ON NewD.Id = @newxDocId 
LEFT JOIN DocType NewDT ON NewDT.Id = NewD.DocTypeId
LEFT JOIN Article A ON DP.ArticleId = A.Id
WHERE DP.DocId = @parxSourceDocId
-- 3a.) UPDATE DocPosition with Extra Fields from source DocPosition
DECLARE @ExtraFieldDocPositionSetList nvarchar(max);
DECLARE @ExtraFieldDocPositionUpdateSql nvarchar(max);
SELECT
@ExtraFieldDocPositionSetList = STRING_AGG(
CAST(
CONCAT(
N'TargetDP.'
, QUOTENAME(TargetColumn.name)
, N' = SourceDP.'
, QUOTENAME(SourceColumn.name)
)
AS nvarchar(max))
, CONCAT(CHAR(13), CHAR(10), N', ')
)
FROM dbo.ExtraField AS TargetExtraField
JOIN dbo.ExtraField AS SourceExtraField
ON SourceExtraField.Name = TargetExtraField.Name
AND SourceExtraField.SystemTableId = N'DocPosition'
JOIN sys.columns AS TargetColumn
ON TargetColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND TargetColumn.name = TargetExtraField.Id
JOIN sys.columns AS SourceColumn
ON SourceColumn.object_id = OBJECT_ID(N'dbo.DocPosition')
AND SourceColumn.name = SourceExtraField.Id
WHERE TargetExtraField.SystemTableId = N'DocPosition'
AND TargetExtraField.Id LIKE N'XX%'
AND SourceExtraField.Id LIKE N'XX%'
AND TargetColumn.is_computed = 0
AND SourceColumn.is_computed = 0;
IF @ExtraFieldDocPositionSetList IS NOT NULL
BEGIN
SET @ExtraFieldDocPositionUpdateSql = CONCAT(
N'UPDATE TargetDP'
, CHAR(13)
, CHAR(10)
, N'SET '
, @ExtraFieldDocPositionSetList
, CHAR(13)
, CHAR(10)
, N'FROM dbo.DocPosition AS TargetDP'
, CHAR(13)
, CHAR(10)
, N'JOIN dbo.DocPosition AS SourceDP'
, CHAR(13)
, CHAR(10)
, N'ON SourceDP.Id = TargetDP.PredecessorId'
, CHAR(13)
, CHAR(10)
, N'WHERE TargetDP.DocId = @TargetDocId'
, CHAR(13)
, CHAR(10)
, N'AND SourceDP.DocId = @SourceDocId'
, CHAR(13)
, CHAR(10)
, N'AND TargetDP.PredecessorId IS NOT NULL;'
);
EXEC sys.sp_executesql
@ExtraFieldDocPositionUpdateSql
, N'@SourceDocId int, @TargetDocId int'
, @SourceDocId = @parxSourceDocId
, @TargetDocId = @newxDocId;
END
-- 4.) Create and prefill DocPositionWarehousing
IF @Draft= 1 BEGIN
INSERT INTO DocPositionWarehousing (
DocPositionId
, WarehouseId
, BinLocationId
, IndividualizationTypeId
, IndividualizationNumberId
, Quantity
, WarehousingEffective
)
SELECT
DP.Id
, CASE WHEN D.StandardWarehouseId IS NOT NULL THEN D.StandardWarehouseId ELSE A.StandardWarehouseId END
, NULL
, A.IndividualizationTypeId
, NULL
, CASE WHEN A.IndividualizationTypeId = 'Serial' THEN 1 ELSE DP.Quantity END
, 0
FROM DocPosition DP
LEFT JOIN Doc D ON D.Id = DP.DocId
LEFT JOIN Article A ON A.Id = DP.ArticleId
WHERE DP.DocId = @newxDocId AND DP.Warehousing = 1
END
INSERT INTO DocPositionInfoText (DocPositionId, InfoText)
SELECT DP.Id, AIT.InfoText
FROM DocPosition DP
LEFT JOIN DocPosition ContractDP On ContractDP.DocId= @parxSourceDocId AND DP.RowNumber = ContractDP.RowNumber
LEFT JOIN DocPositionInfoText AIT On AIT.DocPositionId= ContractDP.Id
WHERE DP.DocId = @newxDocId
INSERT INTO DocPositionOrderText (DocPositionId, OrderText)
SELECT DP.Id, AOT.OrderText
FROM DocPosition DP
LEFT JOIN DocPosition ContractDP On ContractDP.DocId= @parxSourceDocId AND DP.RowNumber = ContractDP.RowNumber
LEFT JOIN DocPositionOrderText AOT On AOT.DocPositionId = ContractDP.Id
WHERE DP.DocId = @newxDocId
INSERT INTO DocPositionDimensionText (DocPositionId, DimensionText)
SELECT DP.Id, ADT.DimensionText
FROM DocPosition DP
LEFT JOIN DocPosition ContractDP On ContractDP.DocId= @parxSourceDocId AND DP.RowNumber = ContractDP.RowNumber
LEFT JOIN DocPositionDimensionText ADT On ADT.DocPositionId= ContractDP.Id
WHERE DP.DocId = @newxDocId
DECLARE @PreviousNextAppointment DATETIME;
SELECT @PreviousNextAppointment = NextAppointment FROM DocContract WHERE DocId = @parxSourceDocId ;
DECLARE @CyclePeriodId INT;
SELECT @CyclePeriodId = CyclePeriodId FROM DocContract WHERE DocId = @parxSourceDocId;
DECLARE @EndDate DATETIME;
SELECT @EndDate = EndDate FROM DocContract WHERE DocId = @parxSourceDocId;
DECLARE @LeadTimeDays INT;
SELECT @LeadTimeDays = LeadTimeDays FROM DocContract WHERE DocId = @parxSourceDocId;
DECLARE @NewNextAppointment DATE;
SET @NewNextAppointment = CASE
@CyclePeriodId
WHEN 1 THEN DATEADD(DAY, 1, @PreviousNextAppointment ) -- täglich
WHEN 2 THEN DATEADD(DAY, 7, @PreviousNextAppointment ) -- wöchentlich
WHEN 3 THEN DATEADD(MONTH, 1, @PreviousNextAppointment ) -- monatlich
WHEN 4 THEN DATEADD(MONTH, 3, @PreviousNextAppointment ) -- quarterly
WHEN 5 THEN DATEADD(MONTH, 6, @PreviousNextAppointment ) -- halbjährig
WHEN 6 THEN DATEADD(YEAR, 1, @PreviousNextAppointment ) -- jährlich
ELSE @PreviousNextAppointment -- Fallback auf Startdatum, wenn keine gültige Perioden-ID vorhanden ist
END;
IF @NewNextAppointment > @EndDate
SET @NewNextAppointment = NULL;
DECLARE @NextExecutionDate datetimeoffset(0);
SET @NextExecutionDate = DATEADD(DAY, -@LeadTimeDays, @NewNextAppointment);
UPDATE DocContract
SET
ExecutedCycles = ExecutedCycles + 1
, NextAppointment = @NewNextAppointment 
, NextExecutionDate = @NextExecutionDate
, StatusId = CASE WHEN PendingCycles = 1 AND TerminatedOnDate IS NOT NULL  THEN 'TERMINATED' WHEN PendingCycles = 1 AND TerminatedOnDate IS NULL THEN 'FULFILLED' ELSE 'ACTIVE' END
WHERE DocId = @parxSourceDocId ;
SELECT @newxDocId AS NewDocId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
-- END xPROC271U_DocContract_CreateTargetDoc------------------------------------------------------------------------
-- xPROC400N_Production ----------------------------------------------------------------------
-- PURPOSE: Create Production for passed Article and insert Position from ArticleProduct
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 30.) INSERT INTO Production and Production Position
-- 40.) INSERT INTO ProductionPosition for Components
-- 42.) INSERT INTO ProductionPosition for ArticleProductionStepComponent as sub positions
-- 45.) INSERT INTO ProductionPositionResource for default resources
-- 50.) UPDATE COST PRICE SUM IN PRODUCTION
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC400N_Production
-- 26.06.26 03:45
@parxArticleId NVARCHAR(30),
@parxCreatedById INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
-- From Scope
DECLARE @newxProductionId INT
DECLARE @newxProductionPositionId INT
-- From Article
DECLARE @Name1 NVARCHAR(100)
DECLARE @Name2 NVARCHAR(100)
DECLARE @Matchcode NVARCHAR(50)
DECLARE @UoMId INT
DECLARE @PriceUnitId INT
DECLARE @Weight DECIMAL(19,6)
SELECT
@Name1= Name1
, @Name2= Name2
, @Matchcode = Matchcode
, @UoMId = UoMId
, @PriceUnitId = PriceUnitId
, @Weight = Weight
FROM Article WHERE Id = @parxArticleId
DECLARE @ProductionWarehouseId INT
SELECT
@ProductionWarehouseId = ProductionWarehouseId
FROM AdminCompanySetting
WHERE Id = 1
-- 30.) INSERT INTO Production and Production Position
INSERT INTO Production(
ProductId
, ProductionQuantityPlanned
, OrderConfirmationPositionId
, ProductionWarehouseId
, DateCreated
, CreatedBy
)
-- VALUES
VALUES (
@parxArticleId
, 1
, NULL
, @ProductionWarehouseId
, sysutcdatetime()
, @parxCreatedById 
)
SET @newxProductionId = SCOPE_IDENTITY()
INSERT INTO ProductionPosition(
ProductionId
, RowNumber
, PositionTypeId
, ArticleProductionStepComponentTypeId
, PositionNumber
, ArticleId
, Name1
, Name2
, PositionQuantityPlanned
, PositionQuantityOpen
, UoMId
, Progress
, WarehousingEffectiveId
)
-- VALUES
VALUES (
@newxProductionId
, 0
, 'Product'
, 1
, 0
, @parxArticleId
, @Name1
, @Name2
, 1
, 1
, @UoMId
, 0
, 1
)
SET @newxProductionPositionId = SCOPE_IDENTITY()
-- 40.) INSERT INTO ProductionPosition for Components
INSERT INTO ProductionPosition(
ProductionId
, RowNumber
, PositionTypeId
, ArticleProductionStepComponentTypeId
, PositionNumber
, ArticleId
, Name1
, Name2
, QuantityFactor
, PositionQuantityPlanned
, PositionQuantityOpen
, UoMId
, Progress
, CostPricePerUnit
, CostPriceTotal
, PredecessorTask
, WarehousingEffectiveId
)
-- VALUES
SELECT
@newxProductionId
, AP.Position
, CASE WHEN A.IsProductionTime = 1 THEN 'ProductionTime'  WHEN A.IsProductionStep = 1 THEN 'ProductionStep' ELSE 'Component' END
, AP.ArticleProductionStepComponentTypeId
, AP.Position
, AP.ComponentId
, A.Name1
, A.Name2
, AP.QuantityFactor
, AP.QuantityFactor
, AP.QuantityFactor
, A.UoMId
, 0
, ISNULL(APC.CostPrice, 0) / NULLIF(A.PriceUnitId, 0)
, ISNULL(APC.CostPrice, 0) / NULLIF(A.PriceUnitId, 0) * AP.QuantityFactor
, AP.PredecessorTaskPositionId
, APSCT.WarehousingEffective 
FROM ArticleProduct AP
LEFT JOIN Article A ON AP.ComponentId = A.Id
LEFT JOIN ArticlePriceCalculation APC ON APC.ArticleId = A.Id
LEFT JOIN ArticleUoM AU ON A.UoMId = AU.Id
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = AP.ArticleProductionStepComponentTypeId
WHERE AP.ArticleId = @parxArticleId
UPDATE PP
SET
PredecessorTask = CASE
WHEN PP.PredecessorTask IS NOT NULL
THEN CONCAT(
CAST((PredecessorPP.Id) AS NVARCHAR(10)), CurrentAP.PredecessorTaskDependencyTypeId
)
ELSE NULL
END,
RelatedPositionId = PredecessorPP.Id
FROM ProductionPosition PP
LEFT JOIN Production P ON PP.ProductionId = P.Id
LEFT JOIN ArticleProduct AP ON PP.PredecessorTask = AP.Id
LEFT JOIN ProductionPosition PredecessorPP ON PredecessorPP.ProductionId = P.Id AND PredecessorPP.ArticleId = AP.ComponentId AND PredecessorPP.PositionNumber = AP.Position
LEFT JOIN ArticleProduct CurrentAP ON P.ProductId = CurrentAP.ArticleId AND PP.ArticleId = CurrentAP.ComponentId AND PP.PositionNumber = CurrentAP.Position
LEFT JOIN Article A ON PredecessorPP.ArticleId= A.Id
LEFT JOIN ArticleUoM AU ON A.UoMId = AU.Id
WHERE PP.ProductionId = @newxProductionId AND PP.PredecessorTask IS NOT NULL
-- 42.) INSERT INTO ProductionPosition for ArticleProductionStepComponent as sub positions
INSERT INTO ProductionPosition (
ProductionId
, RowNumber
, PositionTypeId
, ArticleProductionStepComponentTypeId
, PositionNumber
, ParentPositionId
, ChildPositionNumber
, ArticleId
, Name1
, Name2
, QuantityFactor
, PositionQuantityPlanned
, PositionQuantityOpen
, UoMId
, Progress
, CostPricePerUnit
, CostPriceTotal
, WarehousingEffectiveId
)
SELECT
@newxProductionId
, AP.Position * 100000 + ROW_NUMBER() OVER (
PARTITION BY ParentPP.Id
ORDER BY APSC.Position, APSC.Id
)
, CASE
WHEN A.IsProductionTime = 1 THEN 'ProductionTime'
WHEN A.IsProductionStep = 1 THEN 'ProductionStep'
ELSE 'Component'
END
, APSC.ArticleProductionStepComponentTypeId
, ParentPP.PositionNumber
, ParentPP.Id
, ROW_NUMBER() OVER (
PARTITION BY ParentPP.Id
ORDER BY APSC.Position, APSC.Id
)
, APSC.ArticleComponentId
, A.Name1
, A.Name2
, APSC.QuantityFactor
, ParentPP.PositionQuantityPlanned * APSC.QuantityFactor
, ParentPP.PositionQuantityPlanned * APSC.QuantityFactor
, A.UoMId
, 0
, ISNULL(APC.CostPrice, 0) / NULLIF(A.PriceUnitId, 0)
, ISNULL(APC.CostPrice, 0) / NULLIF(A.PriceUnitId, 0) * ParentPP.PositionQuantityPlanned * APSC.QuantityFactor
, APSCT.WarehousingEffective 
FROM ArticleProduct AP
JOIN ProductionPosition ParentPP
ON ParentPP.ProductionId = @newxProductionId
AND ParentPP.ArticleId = AP.ComponentId
AND ParentPP.PositionNumber = AP.Position
AND ParentPP.ParentPositionId IS NULL
JOIN ArticleProductionStepComponent APSC
ON APSC.ArticleProductionStepId = AP.ComponentId
JOIN Article A
ON A.Id = APSC.ArticleComponentId
LEFT JOIN ArticlePriceCalculation APC
ON APC.ArticleId = A.Id
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = APSC.ArticleProductionStepComponentTypeId
WHERE AP.ArticleId = @parxArticleId;
-- 45.) INSERT INTO ProductionPositionResource for default resources
INSERT INTO ProductionPositionResource (
PositionId
, ResourceId
, Unit
, CreatedBy
, ModifiedBy
)
SELECT
PP.Id
, APSR.ResourceId
, 100
, @parxCreatedById
, @parxCreatedById
FROM ProductionPosition PP
JOIN Article A
ON A.Id = PP.ArticleId
JOIN ArticleProductionStepResource APSR
ON APSR.ArticleProductionStepId = PP.ArticleId
AND APSR.IsDefault = 1
JOIN Resource R
ON R.Id = APSR.ResourceId
AND R.Active = 1
WHERE PP.ProductionId = @newxProductionId
AND A.IsProductionStep = 1
AND APSR.ResourceId IS NOT NULL;
-- 50.) UPDATE COST PRICE SUM IN PRODUCTION
UPDATE Production
SET CostPriceSum = (
SELECT SUM(CostPriceTotal)
FROM ProductionPosition
WHERE ProductionId = @newxProductionId
)
WHERE Id = @newxProductionId;
-- RETURN
SELECT @newxProductionId AS NewProductionId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC400N_Production ----------------------------------------------------------------------
