CREATE OR ALTER PROCEDURE 
xPROC400U_Production_ProductionStart
-- 24.08.17
-- PURPOSE: Set Production.PlannedStart and calculate ProductionPosition.PositionPlannedStart and ProductionPosition.PositionPlannedEnd and Production.PlannedEnd
-- USAGE:
-- 20.) Set Production.PlannedStart
-- 21.) DECLARE Temporary table
-- 22.) Set ProductionPosition.PositionPlannedStart and  ProductionPosition.PositionPlannedEnd of first generation
-- 23.) Calculate and Set ProductionPosition.PositionPlannedStart AND -End for all other generations
-- 24.) Find latest End and set it as Production.PlannedEnd
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxProductionId INT,
@parxPlannedStart DATETIMEOFFSET
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 20.) Set Production.PlannedStart
UPDATE Production
SET ProductionPlannedStart = @parxPlannedStart
WHERE Id = @parxProductionId;
-- 21.) DECLARE Temporary tables
CREATE TABLE #PositionDuration (
Id int NOT NULL PRIMARY KEY
, DurationSeconds int NOT NULL
);
CREATE TABLE #UpdatedPositions (
Id int NOT NULL PRIMARY KEY
, PositionPlannedStart datetimeoffset
, PositionPlannedEnd datetimeoffset
, PredecessorTask nvarchar(20)
, Generation int
);
CREATE TABLE #ResourceDuration (
PositionResourceId int NOT NULL PRIMARY KEY
, PositionId int NOT NULL
, DurationSeconds int NULL
, Unit decimal(19,6) NULL
, WorkQuantity decimal(19,6) NOT NULL
, ResourceRate decimal(19,12) NOT NULL
, TotalRate decimal(19,12) NULL
, QuantityFormular nvarchar(4000) NOT NULL
);
-- 21.1.) Dauer je ProductionPositionResource über ArticleProductionStepResource.QuantityFormular berechnen
DECLARE @PositionResourceId int;
DECLARE @PositionId int;
DECLARE @QuantityPlanned decimal(19,6);
DECLARE @SecondsPerCycle decimal(19,6);
DECLARE @QuantityFormular nvarchar(4000);
DECLARE @Formula nvarchar(4000);
DECLARE @FormulaResult decimal(19,6);
DECLARE @Sql nvarchar(max);
DECLARE @QuantityPerCycle decimal(19,6);
DECLARE ResourceFormulaCursor CURSOR LOCAL FAST_FORWARD FOR
SELECT
PPR.Id
, PP.Id
, PP.PositionQuantityPlanned
, APST.SecondsPerCycle
, APST.QuantityPerCycle
, APST.QuantityFormular
FROM ProductionPositionResource PPR
JOIN ProductionPosition PP
ON PP.Id = PPR.PositionId
JOIN ArticleProductionStepResource APST
ON APST.ResourceId = PPR.ResourceId
AND APST.ArticleProductionStepId = PP.ArticleId
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber <> 0;
OPEN ResourceFormulaCursor;
FETCH NEXT FROM ResourceFormulaCursor
INTO
@PositionResourceId
, @PositionId
, @QuantityPlanned
, @SecondsPerCycle
, @QuantityPerCycle
, @QuantityFormular;
WHILE @@FETCH_STATUS = 0
BEGIN
SET @Formula = LTRIM(RTRIM(ISNULL(@QuantityFormular, N'')));
IF @Formula = N''
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Formula is empty.', 16, 1, @PositionResourceId);
END;
SET @Formula = REPLACE(@Formula, NCHAR(160), N'');
SET @Formula = REPLACE(@Formula, CHAR(9), N'');
SET @Formula = REPLACE(@Formula, CHAR(10), N'');
SET @Formula = REPLACE(@Formula, CHAR(13), N'');
SET @Formula = REPLACE(@Formula, N' ', N'');
SET @Formula = REPLACE(
@Formula
, N'[PP.PositionQuantityPlanned]'
, REPLACE(CONVERT(nvarchar(50), @QuantityPlanned), N',', N'.')
);
SET @Formula = REPLACE(
@Formula
, N'[QuantityPlanned]'
, REPLACE(CONVERT(nvarchar(50), @QuantityPlanned), N',', N'.')
);
SET @Formula = REPLACE(
@Formula
, N'[QuantityPerCycle]'
, REPLACE(CONVERT(nvarchar(50), @QuantityPerCycle), N',', N'.')
);
SET @Formula = REPLACE(
@Formula
, N'[SecondsPerCycle]'
, REPLACE(CONVERT(nvarchar(50), @SecondsPerCycle), N',', N'.')
);
IF @Formula LIKE N'%[^0-9.()+*/-]%'
BEGIN
RAISERROR(
'Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Formula: %s. Formula contains invalid characters.'
, 16
, 1
, @PositionResourceId
, @Formula
);
END;
BEGIN TRY
SET @Sql = N'SELECT @Result = CAST((' + @Formula + N') AS decimal(19,6));';
EXEC sp_executesql
@Sql
, N'@Result decimal(19,6) OUTPUT'
, @Result = @FormulaResult OUTPUT;
END TRY
BEGIN CATCH
DECLARE @FormulaErrorMessage nvarchar(4000) = ERROR_MESSAGE();
RAISERROR(
'Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Formula: %s. Error: %s'
, 16
, 1
, @PositionResourceId
, @Formula
, @FormulaErrorMessage
);
END CATCH;
IF @FormulaResult IS NULL
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Result is NULL.', 16, 1, @PositionResourceId);
END;
IF @FormulaResult < 0
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Result must not be negative.', 16, 1, @PositionResourceId);
END;
IF @SecondsPerCycle IS NULL OR @SecondsPerCycle <= 0
BEGIN
RAISERROR('Invalid SecondsPerCycle in ArticleProductionStepResource. PositionResourceId: %d. SecondsPerCycle must be greater than 0.', 16, 1, @PositionResourceId);
END;
IF @QuantityPerCycle IS NULL OR @QuantityPerCycle <= 0
BEGIN
RAISERROR('Invalid QuantityPerCycle in ArticleProductionStepResource. PositionResourceId: %d. QuantityPerCycle must be greater than 0.', 16, 1, @PositionResourceId);
END;
INSERT INTO #ResourceDuration (
PositionResourceId
, PositionId
, WorkQuantity
, ResourceRate
, QuantityFormular
)
VALUES (
@PositionResourceId
, @PositionId
, @FormulaResult
, CAST(@QuantityPerCycle / @SecondsPerCycle AS decimal(19,12))
, @Formula
);
FETCH NEXT FROM ResourceFormulaCursor
INTO
@PositionResourceId
, @PositionId
, @QuantityPlanned
, @SecondsPerCycle
, @QuantityPerCycle
, @QuantityFormular;
END;
CLOSE ResourceFormulaCursor;
DEALLOCATE ResourceFormulaCursor;
IF EXISTS (
SELECT
1
FROM (
SELECT
PositionId
, COUNT(DISTINCT QuantityFormular) AS FormulaCount
FROM #ResourceDuration
GROUP BY
PositionId
HAVING COUNT(DISTINCT QuantityFormular) > 1
) X
)
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. All resources of one ProductionPosition must use the same QuantityFormular.', 16, 1);
END;
UPDATE RD
SET
RD.TotalRate = X.TotalRate
FROM #ResourceDuration RD
CROSS APPLY (
SELECT
SUM(RD2.ResourceRate) AS TotalRate
FROM #ResourceDuration RD2
WHERE RD2.PositionId = RD.PositionId
) X;
IF EXISTS (
SELECT
1
FROM #ResourceDuration
WHERE TotalRate IS NULL
OR TotalRate <= 0
)
BEGIN
RAISERROR('Invalid resource rate. TotalRate must be greater than 0.', 16, 1);
END;
UPDATE RD
SET
RD.DurationSeconds = X.DurationSeconds
, RD.Unit = CAST(X.DurationSeconds * RD.ResourceRate AS decimal(19,6))
FROM #ResourceDuration RD
CROSS APPLY (
SELECT
CAST(CEILING(MAX(RD2.WorkQuantity) / MAX(RD2.TotalRate)) AS int) AS DurationSeconds
FROM #ResourceDuration RD2
WHERE RD2.PositionId = RD.PositionId
) X;
-- 21.2.) Dauer je ProductionPosition berechnen
INSERT INTO #PositionDuration (
Id
, DurationSeconds
)
SELECT
PP.Id
, CAST(ROUND(
COALESCE(
RD.ResourceDurationSeconds
, CASE AU.ProductionDurationUnitId
WHEN 'm' THEN PP.PositionQuantityPlanned * 60
WHEN 'h' THEN PP.PositionQuantityPlanned * 3600
WHEN 'd' THEN PP.PositionQuantityPlanned * 86400
ELSE 0
END
)
, 0) AS int)
FROM ProductionPosition PP
LEFT JOIN ArticleUoM AU
ON AU.Id = PP.UoMId
OUTER APPLY (
SELECT
MAX(RD.DurationSeconds) AS ResourceDurationSeconds
FROM #ResourceDuration RD
WHERE RD.PositionId = PP.Id
) RD
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber <> 0
AND (
AU.ProductionDurationUnitId IS NOT NULL
OR RD.ResourceDurationSeconds IS NOT NULL
);
-- 22.) Set ProductionPosition.PositionPlannedStart and ProductionPosition.PositionPlannedEnd of first generation
INSERT INTO #UpdatedPositions (
Id
, PositionPlannedStart
, PositionPlannedEnd
, PredecessorTask
, Generation
)
SELECT
PP.Id
, @parxPlannedStart
, DATEADD(SECOND, PD.DurationSeconds, @parxPlannedStart)
, NULL
, 1
FROM ProductionPosition PP
JOIN Production P
ON P.Id = PP.ProductionId
JOIN ArticleProduct AP
ON AP.ComponentId = PP.ArticleId
AND AP.ArticleId = P.ProductId
JOIN #PositionDuration PD
ON PD.Id = PP.Id
WHERE PP.ProductionId = @parxProductionId
AND AP.PredecessorTaskPositionId IS NULL;
-- 23.) Calculate and Set ProductionPosition.PositionPlannedStart AND -End for all other generations
DECLARE @currentGeneration INT = 1;
DECLARE @maxLevel INT = 100; -- Maximal erlaubte Ebenen, um eine Endlosschleife zu verhindern
WHILE @currentGeneration <= @maxLevel
AND EXISTS (
SELECT 1
FROM #UpdatedPositions
WHERE Generation = @currentGeneration
)
BEGIN
INSERT INTO #UpdatedPositions (
Id
, PositionPlannedStart
, PositionPlannedEnd
, PredecessorTask
, Generation
)
SELECT
PP.Id
, CASE
WHEN APDT.Id = 'SS' THEN UP.PositionPlannedStart
WHEN APDT.Id = 'FS' THEN UP.PositionPlannedEnd
WHEN APDT.Id = 'SF' THEN DATEADD(SECOND, -PD.DurationSeconds, UP.PositionPlannedStart)
WHEN APDT.Id = 'FF' THEN DATEADD(SECOND, -PD.DurationSeconds, UP.PositionPlannedEnd)
ELSE @parxPlannedStart
END
, CASE
WHEN APDT.Id = 'SS' THEN DATEADD(SECOND, PD.DurationSeconds, UP.PositionPlannedStart)
WHEN APDT.Id = 'FS' THEN DATEADD(SECOND, PD.DurationSeconds, UP.PositionPlannedEnd)
WHEN APDT.Id = 'SF' THEN UP.PositionPlannedStart
WHEN APDT.Id = 'FF' THEN UP.PositionPlannedEnd
ELSE DATEADD(SECOND, PD.DurationSeconds, @parxPlannedStart)
END
, AP.PredecessorTaskPositionId
, @currentGeneration + 1
FROM ProductionPosition PP
JOIN Production P
ON P.Id = PP.ProductionId
JOIN ArticleProduct AP
ON AP.ComponentId = PP.ArticleId
AND AP.ArticleId = P.ProductId
JOIN #UpdatedPositions UP
ON UP.Id = PP.RelatedPositionId
JOIN #PositionDuration PD
ON PD.Id = PP.Id
LEFT JOIN ArticleProductDependencyType APDT
ON APDT.Id = AP.PredecessorTaskDependencyTypeId
WHERE PP.ProductionId = @parxProductionId
AND UP.Generation = @currentGeneration
AND NOT EXISTS (
SELECT 1
FROM #UpdatedPositions ExistingUP
WHERE ExistingUP.Id = PP.Id
);
SET @currentGeneration = @currentGeneration + 1;
END;
-- 5.) Aktualisiere die Produktionspositionen mit den berechneten Werten
UPDATE PP
SET
PP.PositionPlannedStart = UP.PositionPlannedStart
, PP.PositionPlannedEnd = UP.PositionPlannedEnd
FROM ProductionPosition PP
JOIN #UpdatedPositions UP
ON UP.Id = PP.Id
WHERE PP.ProductionId = @parxProductionId;
-- 5.1.) Aktualisiere ResourceStart und ResourceEnd für verknüpfte Ressourcen
UPDATE PPR
SET
PPR.ResourceStart = PP.PositionPlannedStart
, PPR.ResourceEnd = DATEADD(
SECOND
, RD.DurationSeconds
, PP.PositionPlannedStart
)
, PPR.Unit = RD.Unit
, PPR.DateModified = SYSUTCDATETIME()
FROM ProductionPositionResource PPR
JOIN ProductionPosition PP
ON PP.Id = PPR.PositionId
JOIN #ResourceDuration RD
ON RD.PositionResourceId = PPR.Id
WHERE PP.ProductionId = @parxProductionId
AND PP.PositionPlannedStart IS NOT NULL;
-- 6.) Aktualisiere Produktionsende und Laufzeit in Stunden
UPDATE P
SET
ProductionPlannedEnd = COALESCE(X.PlannedEnd, @parxPlannedStart)
, ProductionRunSeconds = CAST(
DATEDIFF_BIG(
SECOND
, P.ProductionPlannedStart
, COALESCE(X.PlannedEnd, @parxPlannedStart)
) AS int
)
FROM Production P
CROSS APPLY (
SELECT MAX(PP.PositionPlannedEnd) AS PlannedEnd
FROM ProductionPosition PP
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber <> 0
) X
WHERE P.Id = @parxProductionId;
-- 7.) Aktualisiere RowNumber 0
UPDATE PP
SET
PP.PositionPlannedStart = P.ProductionPlannedStart
, PP.PositionPlannedEnd = P.ProductionPlannedEnd
FROM ProductionPosition PP
JOIN Production P
ON P.Id = PP.ProductionId
WHERE P.Id = @parxProductionId
AND PP.RowNumber = 0;
-- Transaktion abschließen
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
-- Fehlerbehandlung und Rollback
ROLLBACK TRANSACTION;
THROW;
END CATCH;
SET NOCOUNT OFF;
END; -- Procedure
GO
-- END xPROC400U_Production_PlannedStart----------------------------------------------------------------------------------------------------
-- xPROC400U_Production_ProductionPlannedEnd----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC400U_Production_ProductionEnd
-- PURPOSE: Update the PlannedEnd in Production and Position zero with passed value
-- 26.06.26
@parxProductionId INT,
@parxProductionPlannedEnd DATETIMEOFFSET
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 20.) Set Production.PlannedEnd
UPDATE Production
SET
ProductionPlannedEnd = @parxProductionPlannedEnd
WHERE Id = @parxProductionId;
-- 21.) Temporary tables
CREATE TABLE #PositionDuration (
Id int NOT NULL PRIMARY KEY
, DurationSeconds int NOT NULL
);
CREATE TABLE #UpdatedPositions (
Id int NOT NULL PRIMARY KEY
, PositionPlannedStart datetimeoffset NULL
, PositionPlannedEnd datetimeoffset NULL
, RelatedPositionId int NULL
, PredecessorTaskPositionId int NULL
, DependencyTypeId nvarchar(2) NULL
, Generation int NOT NULL
);
CREATE TABLE #ResourceDuration (
PositionResourceId int NOT NULL PRIMARY KEY
, PositionId int NOT NULL
, DurationSeconds int NULL
, Unit decimal(19,6) NULL
, WorkQuantity decimal(19,6) NOT NULL
, ResourceRate decimal(19,12) NOT NULL
, TotalRate decimal(19,12) NULL
, QuantityFormular nvarchar(4000) NOT NULL
);
-- 21.1.) Dauer je ProductionPositionResource über ArticleProductionStepResource.QuantityFormular berechnen
DECLARE @PositionResourceId int;
DECLARE @PositionId int;
DECLARE @PositionQuantityPlanned decimal(19,6);
DECLARE @SecondsPerCycle decimal(19,6);
DECLARE @QuantityPerCycle decimal(19,6);
DECLARE @QuantityFormular nvarchar(4000);
DECLARE @Formula nvarchar(4000);
DECLARE @FormulaResult decimal(19,6);
DECLARE @Sql nvarchar(max);
DECLARE ResourceFormulaCursor CURSOR LOCAL FAST_FORWARD FOR
SELECT
PPR.Id
, PP.Id
, PP.PositionQuantityPlanned
, APSR.SecondsPerCycle
, APSR.QuantityPerCycle
, APSR.QuantityFormular
FROM ProductionPositionResource PPR
JOIN ProductionPosition PP
ON PP.Id = PPR.PositionId
JOIN ArticleProductionStepResource APSR
ON APSR.ResourceId = PPR.ResourceId
AND APSR.ArticleProductionStepId= PP.ArticleId
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber > 0 AND APSR.ResourceId IS NOT NULL;
OPEN ResourceFormulaCursor;
FETCH NEXT FROM ResourceFormulaCursor
INTO
@PositionResourceId
, @PositionId
, @PositionQuantityPlanned
, @SecondsPerCycle
, @QuantityPerCycle
, @QuantityFormular;
WHILE @@FETCH_STATUS = 0
BEGIN
SET @Formula = LTRIM(RTRIM(ISNULL(@QuantityFormular, N'')));
IF @Formula = N''
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Formula is empty.', 16, 1, @PositionResourceId);
END;
SET @Formula = REPLACE(@Formula, NCHAR(160), N'');
SET @Formula = REPLACE(@Formula, CHAR(9), N'');
SET @Formula = REPLACE(@Formula, CHAR(10), N'');
SET @Formula = REPLACE(@Formula, CHAR(13), N'');
SET @Formula = REPLACE(@Formula, N' ', N'');
SET @Formula = REPLACE(
@Formula
, N'[PP.PositionQuantityPlanned]'
, REPLACE(CONVERT(nvarchar(50), @PositionQuantityPlanned), N',', N'.')
);
SET @Formula = REPLACE(
@Formula
, N'[QuantityPlanned]'
, REPLACE(CONVERT(nvarchar(50), @PositionQuantityPlanned), N',', N'.')
);
SET @Formula = REPLACE(
@Formula
, N'[QuantityPerCycle]'
, REPLACE(CONVERT(nvarchar(50), @QuantityPerCycle), N',', N'.')
);
SET @Formula = REPLACE(
@Formula
, N'[SecondsPerCycle]'
, REPLACE(CONVERT(nvarchar(50), @SecondsPerCycle), N',', N'.')
);
SET @Formula = REPLACE(@Formula, N',', N'.');
IF @Formula LIKE N'%[^0-9.()+*/-]%'
BEGIN
RAISERROR(
'Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Formula: %s. Formula contains invalid characters.'
, 16
, 1
, @PositionResourceId
, @Formula
);
END;
BEGIN TRY
SET @Sql = N'SELECT @Result = CAST((' + @Formula + N') AS decimal(19,6));';
EXEC sp_executesql
@Sql
, N'@Result decimal(19,6) OUTPUT'
, @Result = @FormulaResult OUTPUT;
END TRY
BEGIN CATCH
DECLARE @FormulaErrorMessage nvarchar(4000) = ERROR_MESSAGE();
RAISERROR(
'Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Formula: %s. Error: %s'
, 16
, 1
, @PositionResourceId
, @Formula
, @FormulaErrorMessage
);
END CATCH;
IF @FormulaResult IS NULL
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Result is NULL.', 16, 1, @PositionResourceId);
END;
IF @FormulaResult < 0
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. PositionResourceId: %d. Result must not be negative.', 16, 1, @PositionResourceId);
END;
IF @SecondsPerCycle IS NULL OR @SecondsPerCycle <= 0
BEGIN
RAISERROR('Invalid SecondsPerCycle in ArticleProductionStepResource. PositionResourceId: %d. SecondsPerCycle must be greater than 0.', 16, 1, @PositionResourceId);
END;
IF @QuantityPerCycle IS NULL OR @QuantityPerCycle <= 0
BEGIN
RAISERROR('Invalid QuantityPerCycle in ArticleProductionStepResource. PositionResourceId: %d. QuantityPerCycle must be greater than 0.', 16, 1, @PositionResourceId);
END;
INSERT INTO #ResourceDuration (
PositionResourceId
, PositionId
, WorkQuantity
, ResourceRate
, QuantityFormular
)
VALUES (
@PositionResourceId
, @PositionId
, @FormulaResult
, CAST(@QuantityPerCycle / @SecondsPerCycle AS decimal(19,12))
, @Formula
);
FETCH NEXT FROM ResourceFormulaCursor
INTO
@PositionResourceId
, @PositionId
, @PositionQuantityPlanned
, @SecondsPerCycle
, @QuantityPerCycle
, @QuantityFormular;
END;
CLOSE ResourceFormulaCursor;
DEALLOCATE ResourceFormulaCursor;
-- 21.1.1.) QuantityFormular muss je Arbeitsschritt identisch sein
IF EXISTS (
SELECT
1
FROM (
SELECT
PositionId
, COUNT(DISTINCT QuantityFormular) AS FormulaCount
FROM #ResourceDuration
GROUP BY
PositionId
HAVING COUNT(DISTINCT QuantityFormular) > 1
) X
)
BEGIN
RAISERROR('Invalid QuantityFormular in ArticleProductionStepResource. All resources of one ProductionPosition must use the same QuantityFormular.', 16, 1);
END;
-- 21.1.2.) Gesamtleistung je Arbeitsschritt berechnen
UPDATE RD
SET
RD.TotalRate = X.TotalRate
FROM #ResourceDuration RD
CROSS APPLY (
SELECT
SUM(RD2.ResourceRate) AS TotalRate
FROM #ResourceDuration RD2
WHERE RD2.PositionId = RD.PositionId
) X;
IF EXISTS (
SELECT
1
FROM #ResourceDuration
WHERE TotalRate IS NULL
OR TotalRate <= 0
)
BEGIN
RAISERROR('Invalid resource rate. TotalRate must be greater than 0.', 16, 1);
END;
-- 21.1.3.) Dauer und Mengenanteil je Ressource berechnen
UPDATE RD
SET
RD.DurationSeconds = X.DurationSeconds
, RD.Unit = CAST(X.DurationSeconds * RD.ResourceRate AS decimal(19,6))
FROM #ResourceDuration RD
CROSS APPLY (
SELECT
CAST(CEILING(MAX(RD2.WorkQuantity) / MAX(RD2.TotalRate)) AS int) AS DurationSeconds
FROM #ResourceDuration RD2
WHERE RD2.PositionId = RD.PositionId
) X;
-- 21.2.) Dauer je ProductionPosition berechnen
INSERT INTO #PositionDuration (
Id
, DurationSeconds
)
SELECT
PP.Id
, CAST(ROUND(
COALESCE(
RD.ResourceDurationSeconds
, CASE AU.ProductionDurationUnitId
WHEN 'm' THEN PP.PositionQuantityPlanned * 60
WHEN 'h' THEN PP.PositionQuantityPlanned * 3600
WHEN 'd' THEN PP.PositionQuantityPlanned * 86400
ELSE 0
END
)
, 0) AS int)
FROM ProductionPosition PP
LEFT JOIN ArticleUom AU
ON AU.Id = PP.UomId
OUTER APPLY (
SELECT
MAX(RD.DurationSeconds) AS ResourceDurationSeconds
FROM #ResourceDuration RD
WHERE RD.PositionId = PP.Id
) RD
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber > 0
AND (
AU.ProductionDurationUnitId IS NOT NULL
OR RD.ResourceDurationSeconds IS NOT NULL
);
-- 22.) Last generation / positions without successors
INSERT INTO #UpdatedPositions (
Id
, PositionPlannedStart
, PositionPlannedEnd
, RelatedPositionId
, PredecessorTaskPositionId
, DependencyTypeId
, Generation
)
SELECT
PP.Id
, DATEADD(SECOND, -PD.DurationSeconds, @parxProductionPlannedEnd)
, @parxProductionPlannedEnd
, PP.RelatedPositionId
, AP.PredecessorTaskPositionId
, AP.PredecessorTaskDependencyTypeId
, 1
FROM ProductionPosition PP
JOIN Production P
ON P.Id = PP.ProductionId
JOIN ArticleProduct AP
ON AP.ComponentId = PP.ArticleId
AND AP.ArticleId = P.ProductId
JOIN #PositionDuration PD
ON PD.Id = PP.Id
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber > 0
AND NOT EXISTS (
SELECT
1
FROM ProductionPosition SuccessorPP
WHERE SuccessorPP.ProductionId = PP.ProductionId
AND SuccessorPP.RowNumber > 0
AND SuccessorPP.RelatedPositionId = PP.Id
);
-- 23.) Calculate predecessors backwards
DECLARE @currentGeneration int = 1;
DECLARE @maxLevel int = 100;
WHILE @currentGeneration <= @maxLevel
AND EXISTS (
SELECT
1
FROM #UpdatedPositions
WHERE Generation = @currentGeneration
)
BEGIN
INSERT INTO #UpdatedPositions (
Id
, PositionPlannedStart
, PositionPlannedEnd
, RelatedPositionId
, PredecessorTaskPositionId
, DependencyTypeId
, Generation
)
SELECT
PredecessorPP.Id
, DATEADD(SECOND, -PD.DurationSeconds, BaseCalc.PlannedEnd)
, BaseCalc.PlannedEnd
, PredecessorPP.RelatedPositionId
, PredecessorAP.PredecessorTaskPositionId
, PredecessorAP.PredecessorTaskDependencyTypeId
, @currentGeneration + 1
FROM #UpdatedPositions UP
JOIN ProductionPosition SuccessorPP
ON SuccessorPP.Id = UP.Id
JOIN ProductionPosition PredecessorPP
ON PredecessorPP.Id = SuccessorPP.RelatedPositionId
JOIN Production P
ON P.Id = PredecessorPP.ProductionId
LEFT JOIN ArticleProduct SuccessorAP
ON SuccessorAP.ComponentId = SuccessorPP.ArticleId
AND SuccessorAP.ArticleId = P.ProductId
LEFT JOIN ArticleProduct PredecessorAP
ON PredecessorAP.ComponentId = PredecessorPP.ArticleId
AND PredecessorAP.ArticleId = P.ProductId
JOIN #PositionDuration PD
ON PD.Id = PredecessorPP.Id
CROSS APPLY (
SELECT
CASE SuccessorAP.PredecessorTaskDependencyTypeId
WHEN 'FF' THEN UP.PositionPlannedEnd
WHEN 'SF' THEN UP.PositionPlannedEnd
WHEN 'FS' THEN UP.PositionPlannedStart
WHEN 'SS' THEN UP.PositionPlannedStart
ELSE UP.PositionPlannedStart
END AS DependencyDate
) DependencyCalc
CROSS APPLY (
SELECT
CASE SuccessorAP.PredecessorTaskDependencyTypeId
WHEN 'FF' THEN DependencyCalc.DependencyDate
WHEN 'SF' THEN DATEADD(SECOND, PD.DurationSeconds, DependencyCalc.DependencyDate)
WHEN 'FS' THEN DependencyCalc.DependencyDate
WHEN 'SS' THEN DATEADD(SECOND, PD.DurationSeconds, DependencyCalc.DependencyDate)
ELSE DependencyCalc.DependencyDate
END AS PlannedEnd
) BaseCalc
WHERE UP.Generation = @currentGeneration
AND PredecessorPP.ProductionId = @parxProductionId
AND PredecessorPP.RowNumber > 0
AND NOT EXISTS (
SELECT
1
FROM #UpdatedPositions AlreadyUpdated
WHERE AlreadyUpdated.Id = PredecessorPP.Id
);
SET @currentGeneration = @currentGeneration + 1;
END;
-- 24.) Update ProductionPosition
UPDATE PP
SET
PP.PositionPlannedStart = UP.PositionPlannedStart
, PP.PositionPlannedEnd = UP.PositionPlannedEnd
FROM ProductionPosition PP
JOIN #UpdatedPositions UP
ON UP.Id = PP.Id
WHERE PP.ProductionId = @parxProductionId;
-- 24.1.) Update ProductionPositionResource
UPDATE PPR
SET
PPR.ResourceStart = PP.PositionPlannedStart
, PPR.ResourceEnd = DATEADD(
SECOND
, RD.DurationSeconds
, PP.PositionPlannedStart
)
, PPR.Unit = RD.Unit
, PPR.DateModified = SYSUTCDATETIME()
FROM ProductionPositionResource PPR
JOIN ProductionPosition PP
ON PP.Id = PPR.PositionId
JOIN #ResourceDuration RD
ON RD.PositionResourceId = PPR.Id
WHERE PP.ProductionId = @parxProductionId
AND PP.PositionPlannedStart IS NOT NULL;
-- 25.) Update PlannedStart and RunSeconds
UPDATE P
SET
P.ProductionPlannedStart = COALESCE(X.PositionPlannedStart, @parxProductionPlannedEnd)
, P.ProductionRunSeconds = CAST(
DATEDIFF_BIG(
SECOND
, COALESCE(X.PositionPlannedStart, @parxProductionPlannedEnd)
, P.ProductionPlannedEnd
) AS int
)
FROM Production P
CROSS APPLY (
SELECT
MIN(PP.PositionPlannedStart) AS PositionPlannedStart
FROM ProductionPosition PP
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber > 0
) X
WHERE P.Id = @parxProductionId;
-- 26.) Update RowNumber 0
UPDATE PP
SET
PP.PositionPlannedStart = P.ProductionPlannedStart
, PP.PositionPlannedEnd = P.ProductionPlannedEnd
FROM ProductionPosition PP
JOIN Production P
ON P.Id = PP.ProductionId
WHERE P.Id = @parxProductionId
AND PP.RowNumber = 0;
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
IF @@TRANCOUNT > 0
ROLLBACK TRANSACTION;
THROW;
END CATCH;
SET NOCOUNT OFF;
END; -- Procedure
GO
-- END xPROC400U_Production_ProductionPlannedEnd----------------------------------------------------------------------------------------------------
-- xPROC400U_Production_OrderConfirmationPositionId----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC400U_Production_OrderConfirmationPositionId
-- PURPOSE: Update the OrderConfirmationId with passed value
-- 26.06.26
@parxProductionId INT,
@parxOrderConfirmationPositionId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE Production SET OrderConfirmationPositionId = @parxOrderConfirmationPositionId WHERE Id = @parxProductionId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC400U_Production_OrderConfirmationPositionId----------------------------------------------------------------------------------------------------
-- xPROC400U_Production_ProductionQuantityAnnounced----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC400U_Production_ProductionQuantityAnnounced
-- PURPOSE: Update the QuantityAnnounced  with passed value
-- 26.06.26
@parxProductionId INT,
@parxQuantitAnnounced DECIMAL(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) Read current state for write-protection / cap validation
DECLARE @Status NVARCHAR(12), @Planned DECIMAL(19,6), @Completed DECIMAL(19,6), @CurrentAnnounced DECIMAL(19,6);
SELECT
@Status = ProductionStatusId
, @Planned = ProductionQuantityPlanned
, @Completed = ProductionQuantityCompleted
, @CurrentAnnounced = ProductionQuantityAnnounced
FROM Production
WHERE Id = @parxProductionId;
-- 20.) Only apply when the order is not closed and the passed (absolute) announced
--      quantity stays within [0, Planned - Completed].
IF @Status IS NOT NULL
AND @Status NOT IN ('done', 'manually')
AND @parxQuantitAnnounced >= 0
AND @parxQuantitAnnounced <= (@Planned - @Completed)
BEGIN
UPDATE PP
SET
PositionQuantityAnnounced = (@parxQuantitAnnounced * PP.QuantityFactor)
, PositionQuantityOrdered = PositionQuantityOrdered - (@parxQuantitAnnounced * PP.QuantityFactor) + PositionQuantityAnnounced
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective = 1;
UPDATE Production
SET
ProductionQuantityAnnounced = @parxQuantitAnnounced
, ProductionQuantityOrdered = ProductionQuantityOrdered - @parxQuantitAnnounced + ProductionQuantityAnnounced
FROM Production
WHERE Id = @parxProductionId;
END
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC400U_Production_ProductionQuantityAnnounced----------------------------------------------------------------------------------------------------
-- xPROC416U_Production_QuantityPlanned----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC416U_Production_QuantityPlanned
-- PURPOSE: Update the ProductionQuantityPlanned and ProductionQuantityOpen with passed value and update Costs
-- 26.06.26
@parxProductionId INT,
@parxQuantityPlanned DECIMAL(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE Production
SET 
ProductionQuantityOpen = @parxQuantityPlanned
, ProductionQuantityPlanned = @parxQuantityPlanned
FROM Production
WHERE Id = @parxProductionId
UPDATE ProductionPosition
SET 
PositionQuantityOpen = @parxQuantityPlanned * QuantityFactor
, PositionQuantityPlanned = @parxQuantityPlanned * QuantityFactor
, CostPriceTotal = CostPricePerUnit * QuantityFactor * @parxQuantityPlanned
FROM ProductionPosition
WHERE ProductionId = @parxProductionId
UPDATE Production
SET CostPriceSum = (
SELECT SUM(CostPriceTotal)
FROM ProductionPosition
WHERE ProductionId = @parxProductionId
)
WHERE Id = @parxProductionId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC416U_Production_QuantityPlanned----------------------------------------------------------------------------------------------------
-- xPROC417U_Production_Reserve----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC417U_Production_Reserve
-- PURPOSE: Update the QuantityReserved and QuantityOpen  with passed value and Set Status to started
-- 26.06.26
@parxProductionId INT,
@parxReservedQuantity DECIMAL(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE Production
SET 
ProductionQuantityOpen = ProductionQuantityOpen - @parxReservedQuantity
, ProductionQuantityConfirmed = ProductionQuantityConfirmed + @parxReservedQuantity
, ProductionQuantityOrdered = ProductionQuantityOrdered + @parxReservedQuantity
, ProductionStatusId = 'started'
FROM Production
WHERE Id = @parxProductionId
UPDATE PP
SET 
PositionQuantityOpen = PP.PositionQuantityOpen - (@parxReservedQuantity * PP.QuantityFactor)
, PositionQuantityConfirmed = PP.PositionQuantityConfirmed + (@parxReservedQuantity * PP.QuantityFactor)
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective != 1;
UPDATE PP
SET 
PositionQuantityOpen = PP.PositionQuantityOpen - (@parxReservedQuantity * PP.QuantityFactor)
, PositionQuantityOrdered = PP.PositionQuantityOrdered + (@parxReservedQuantity * PP.QuantityFactor)
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective = 1;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC417U_Production_Reserve----------------------------------------------------------------------------------------------------
-- xPROC418U_Production_Calculate_QuantityPick----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC418U_Production_Calculate_QuantityPick
-- PURPOSE: Calculate the Quantity that can be Picked
-- 26.06.26
@parxProductionId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
DECLARE
@QuantityConfirmed DECIMAL(19,6)
, @MinValue DECIMAL(19,6)
, @ReturnValue DECIMAL(19,6);
-- Hole Reserved-Menge aus Production
SELECT
@QuantityConfirmed = ISNULL(p.ProductionQuantityConfirmed, 0)
FROM Production p
WHERE p.Id = @parxProductionId;
-- Temporäre Tabelle mit berechneten Werten (nur Warehousing = 1)
IF OBJECT_ID('tempdb..#Calc') IS NOT NULL DROP TABLE #Calc;
SELECT
CAST(
(AQIS.NowAvailable - ISNULL(PP.PositionQuantityPick, 0)) / NULLIF(PP.QuantityFactor, 0)
AS DECIMAL(19,6)
) AS CalcValue
INTO #Calc
FROM ProductionPosition PP
JOIN ArticleProductionStepComponentType APSCT
ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
JOIN xVIEW124_ArticleQuantityInventorySum AQIS
ON AQIS.ArticleId = PP.ArticleId
WHERE PP.ProductionId = @parxProductionId
AND APSCT.WarehousingEffective = -1
AND NOT EXISTS (
SELECT 1
FROM ProductionPosition PPProduced
JOIN ArticleProductionStepComponentType APSCTProduced
ON APSCTProduced.Id = PPProduced.ArticleProductionStepComponentTypeId
WHERE PPProduced.ProductionId = PP.ProductionId
AND PPProduced.ArticleId = PP.ArticleId
AND APSCTProduced.WarehousingEffective = 1
AND PPProduced.PositionQuantityPlanned = PP.PositionQuantityPlanned
);
-- Prüfe auf negative Werte
IF EXISTS (
SELECT 1 FROM #Calc WHERE CalcValue < 0
)
BEGIN
SET @ReturnValue = 0;
END
ELSE
BEGIN
-- Kleinster Wert unterhalb QuantityConfirmed 
SELECT
@MinValue = MIN(CalcValue)
FROM #Calc
WHERE CalcValue < @QuantityConfirmed;
-- Falls kein passender Wert → fallback
IF @MinValue IS NULL
SET @MinValue = @QuantityConfirmed;
SET @ReturnValue = @MinValue;
END;
-- Temporäre Tabelle aufräumen
DROP TABLE #Calc;
SELECT @ReturnValue AS QuantityToPick;
END -- Transaction
GO
-- END xPROC418U_Production_Calculate_QuantityPick----------------------------------------------------------------------------------------------------
-- xPROC418U_Production_Pick----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC418U_Production_Pick
-- PURPOSE: Update the QuantityPick and QuantityOpen with passed value and Insert into ProductionPositionWarehousing 
-- 26.06.26
@parxProductionId INT,
@parxQuantityPick DECIMAL(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE PP
SET 
PositionQuantityPick = PP.PositionQuantityPick + (@parxQuantityPick * PP.QuantityFactor)
, PositionQuantityConfirmed = PP.PositionQuantityConfirmed - (@parxQuantityPick * PP.QuantityFactor)
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective != 1;
UPDATE Production
SET 
ProductionQuantityPick = ProductionQuantityPick + @parxQuantityPick
, ProductionQuantityConfirmed = ProductionQuantityConfirmed - @parxQuantityPick
FROM Production
WHERE Id = @parxProductionId
INSERT INTO ProductionPositionWarehousing (
ProductionPositionId
, WarehouseId
, IndividualizationTypeId
, Quantity
, WarehousingEffective
)
SELECT
PP.Id
, CASE WHEN PP.RowNumber = 0 THEN P.ProductionWarehouseId ELSE A.StandardWarehouseId END
, A.IndividualizationTypeId
, CASE WHEN A.IndividualizationTypeId = 'Serial' THEN 1 ELSE @parxQuantityPick * PP.QuantityFactor END
, 0
FROM ProductionPosition PP
LEFT JOIN Production P ON P.Id = PP.ProductionId
LEFT JOIN Article A ON PP.ArticleId = A.Id
WHERE ProductionId = @parxProductionId AND A.Warehousing = 1
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC418U_Production_Pick----------------------------------------------------------------------------------------------------
-- xPROC418U_Production_Pack----------------------------------------------------------------------------------------------------
-- PURPOSE: Pack the Items that have been in the sent to pick
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 30.) ArticleQuantity
-- 40.) WarehouseQuantity
-- 50.) ArticleIndividualizationQuantity
-- 60.) ProductionPosition
-- 63.) UPDATE ArticleIndividualizationQuantity 
-- 65.) ProductionPositionWarehousing 
-- 70.) Production
-- 90.) RETURN
-- 91.) ERROR HANDLING
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC418U_Production_Pack
-- 99.12.30
@parxProductionId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 20.) VALIDATION
DECLARE @InvalidPositions TABLE (WarehousingId INT, PositionNumber INT, ProductionPositionId INT, ArticleId NVARCHAR(30), TEXT NVARCHAR(100));
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
MIN(W.Id) AS WarehousingId,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.PositionNumber) AS PositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.Id) AS ProductionPositionId, -- Verwendet die erste DocPositionId für jede Gruppe
PP.ArticleId
, 'Insufficient warehousing stock available.'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
LEFT JOIN WarehouseQuantity WQ ON WQ.WarehouseId = W.WarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(W.BinLocationId,0) AND WQ.ArticleId = PP.ArticleId
LEFT JOIN Article A ON A.Id = PP.ArticleId
WHERE PP.ProductionId = @parxProductionId AND A.Warehousing = 1 AND W.WarehousingQuantity = 0 AND PP.RowNumber !=0 
GROUP BY PP.ArticleId, W.WarehouseId, ISNULL(W.BinLocationId,0)
HAVING
(SUM(W.Quantity) > MAX(WQ.NowAvailable)) OR
(MAX(WQ.NowAvailable) IS NULL )
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
W.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'Quantity in position does not match quantity in warehousing.'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN (
SELECT
W.ProductionPositionId,
SUM(W.Quantity) AS TotalWarehousingQuantity
FROM ProductionPositionWarehousing W
WHERE W.WarehousingQuantity = 0 
GROUP BY W.ProductionPositionId
) AS WQ ON WQ.ProductionPositionId= PP.Id
WHERE PP.ProductionId = @parxProductionId 
AND PP.PositionQuantityPick != WQ.TotalWarehousingQuantity  AND A.Warehousing = 1 AND PP.RowNumber !=0;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
W.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, W.IndividualizationTypeId + '-Number is missing'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
WHERE PP.ProductionId = @parxProductionId AND W.IndividualizationTypeId != 'None' AND W.IndividualizationNumberId IS NULL  AND PP.RowNumber !=0;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
WPP.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'A Bin Location needs to be selected with the chosen Warehouse.'
FROM ProductionPositionWarehousing WPP
LEFT JOIN ProductionPosition PP ON PP.Id = WPP.ProductionPositionId
LEFT JOIN Warehouse W ON W.Id = WPP.WarehouseId
WHERE PP.ProductionId = @parxProductionId AND W.BinLocation = 1 AND WPP.BinLocationId IS NULL ;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
MIN(W.Id) AS WarehousingId,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.PositionNumber) AS PositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.Id) AS ProductionPositionId, -- Verwendet die erste DocPositionId für jede Gruppe
MIN(PP.ArticleId)
, 'Insufficient warehousing stock available with this ' + MIN(W.IndividualizationTypeId) + ' Number.'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.WarehouseId = W.WarehouseId AND ISNULL(AIQ.BinLocationId,0) = ISNULL(W.BinLocationId,0) AND AIQ.ArticleIndividualizationId = W.IndividualizationNumberId
WHERE PP.ProductionId = @parxProductionId AND A.IndividualizationTypeId != 'None' AND W.WarehousingQuantity = 0 AND PP.RowNumber !=0
GROUP BY W.IndividualizationNumberId, W.WarehouseId, ISNULL(W.BinLocationId,0)
HAVING
(SUM(W.Quantity) > MAX(AIQ.NowAvailable)) OR
(MAX(AIQ.NowAvailable) IS NULL)
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
NULL
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'Warehousing records are missing.'
FROM ProductionPosition PP
LEFT JOIN ProductionPositionWarehousing W ON W.ProductionPositionId = PP.Id
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND A.Warehousing = 1 AND W.Id IS NULL AND APSCT.WarehousingEffective != 1;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
W.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'Serial Number exists more than once in this Production.'
FROM ProductionPositionWarehousing W
JOIN ProductionPositionWarehousing DuplicateW ON W.IndividualizationNumberId = DuplicateW.IndividualizationNumberId AND W.Id != DuplicateW.Id
JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
JOIN ProductionPosition DuplicatePP ON DuplicatePP.Id = DuplicateW.ProductionPositionId
WHERE PP.ProductionId = @parxProductionId AND DuplicatePP.ProductionId = @parxProductionId AND W.IndividualizationTypeId = 'Serial' ;
UPDATE PP
SET PP.Pending = 1 
FROM ProductionPosition PP
JOIN @InvalidPositions IP ON PP.Id = IP.ProductionPositionId;
IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
-- 60.) ProductionPosition
UPDATE PP
SET 
PositionQuantityPacked = PP.PositionQuantityPacked + PP.PositionQuantityPick
, PositionQuantityPick = 0
, Pending = 0
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective != 1
-- 63.) UPDATE ArticleIndividualizationQuantity 
;WITH UpdatedArticleIndividualizationQuantities AS
(
SELECT
PPW.IndividualizationNumberId
, PPW.WarehouseId
, ISNULL(PPW.BinLocationId, 0) AS BinLocationId
, SUM(PPW.Quantity) AS Quantity
, MIN(PP.Id) AS ProductionPositionId
FROM ProductionPositionWarehousing PPW
INNER JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
WHERE
PP.ProductionId = @parxProductionId
AND PP.RowNumber != 0
AND PPW.WarehousingQuantity = 0
AND PPW.IndividualizationNumberId IS NOT NULL
GROUP BY
PPW.IndividualizationNumberId
, PPW.WarehouseId
, ISNULL(PPW.BinLocationId, 0)
)
UPDATE AIQ
SET
AIQ.Packed = AIQ.Packed + UAIQ.Quantity
, AIQ.ProductionPosition = UAIQ.ProductionPositionId
, AIQ.InventoryCountingPosition = NULL
, AIQ.DocPosition = NULL
FROM ArticleIndividualizationQuantity AIQ
INNER JOIN UpdatedArticleIndividualizationQuantities UAIQ
ON UAIQ.IndividualizationNumberId = AIQ.ArticleIndividualizationId
AND UAIQ.WarehouseId = AIQ.WarehouseId
AND UAIQ.BinLocationId = ISNULL(AIQ.BinLocationId, 0);
-- 70.) Production
UPDATE Production
SET 
ProductionQuantityPacked = ProductionQuantityPacked + ProductionQuantityPick
, ProductionQuantityPick = 0
FROM Production
WHERE Id = @parxProductionId;
-- 90.) RETURN
-- RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidPositions) = 0 BEGIN
SELECT * FROM @InvalidPositions 
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC418U_Production_Pack----------------------------------------------------------------------------------------------------
