CREATE OR ALTER PROCEDURE 
xPROC418U_Production_Issue
-- PURPOSE: Update the QuantityIssue  with passed value and reduce QuantityPacked
-- 26.06.26
@parxProductionId INT,
@parxQuantityIssued DECIMAL(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE PP
SET 
PositionQuantityIssued = PP.PositionQuantityIssued + (@parxQuantityIssued * PP.QuantityFactor)
, PositionQuantityPacked = PP.PositionQuantityPacked - (@parxQuantityIssued * PP.QuantityFactor)
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective != 1;
UPDATE Production
SET 
ProductionQuantityIssued = ProductionQuantityIssued + @parxQuantityIssued 
, ProductionQuantityPacked = ProductionQuantityPacked - @parxQuantityIssued 
FROM Production
WHERE Id = @parxProductionId
-- 65.) ProductionPositionWarehousing
UPDATE ProductionPositionWarehousing
SET 
Issued = 1
FROM ProductionPositionWarehousing PPW
LEFT JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
LEFT JOIN Article A ON A.Id = PP.ArticleId
WHERE PP.ProductionId = @parxProductionId AND PPW.WarehousingQuantity = 0 AND A.Warehousing = 1
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC418U_Production_Issue----------------------------------------------------------------------------------------------------
