CREATE OR ALTER PROCEDURE 
xPROC418U_Production_Completed
-- 99.12.30
@parxProductionId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 20.) VALIDATION
DECLARE @InvalidPositions TABLE (WarehousingId INT, PositionNumber INT, ProductionPositionId INT, ArticleId NVARCHAR(30), TEXT NVARCHAR(100));
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
MIN(W.Id) AS WarehousingId,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.PositionNumber) AS PositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.Id) AS ProductionPositionId, -- Verwendet die erste DocPositionId für jede Gruppe
PP.ArticleId
, 'Insufficient warehousing stock available.'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
LEFT JOIN WarehouseQuantity WQ ON WQ.WarehouseId = W.WarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(W.BinLocationId,0) AND WQ.ArticleId = PP.ArticleId
LEFT JOIN Article A ON A.Id = PP.ArticleId
WHERE PP.ProductionId = @parxProductionId AND A.Warehousing = 1 AND W.WarehousingQuantity = 0 AND PP.RowNumber !=0 
GROUP BY PP.ArticleId, W.WarehouseId, ISNULL(W.BinLocationId,0)
HAVING
(SUM(W.Quantity) > MAX(WQ.Stock)) OR
(MAX(WQ.Stock) IS NULL )
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
W.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'Quantity in position does not match quantity in warehousing.'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
LEFT JOIN Production P ON P.Id = PP.ProductionId
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN (
SELECT
W.ProductionPositionId,
SUM(W.Quantity) AS TotalWarehousingQuantity
FROM ProductionPositionWarehousing W
WHERE W.WarehousingQuantity = 0 
GROUP BY W.ProductionPositionId
) AS WQ ON WQ.ProductionPositionId= PP.Id
WHERE PP.ProductionId = @parxProductionId 
AND ((P.ProductionQuantityIssued != WQ.TotalWarehousingQuantity AND PP.RowNumber =0) OR (PP.PositionQuantityIssued != WQ.TotalWarehousingQuantity AND PP.RowNumber !=0)) AND A.Warehousing = 1;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
W.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, W.IndividualizationTypeId + ' Number is missing.'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
WHERE PP.ProductionId = @parxProductionId AND W.IndividualizationTypeId != 'None' AND W.IndividualizationNumberId IS NULL ;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
WPP.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'A Bin Location needs to be selected with the chosen Warehouse.'
FROM ProductionPositionWarehousing WPP
LEFT JOIN ProductionPosition PP ON PP.Id = WPP.ProductionPositionId
LEFT JOIN Warehouse W ON W.Id = WPP.WarehouseId
WHERE PP.ProductionId = @parxProductionId AND W.BinLocation = 1 AND WPP.BinLocationId IS NULL ;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
MIN(W.Id) AS WarehousingId,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.PositionNumber) AS PositionNumber,  -- Verwendet die erste WarehousingId für jede Gruppe
MIN(PP.Id) AS ProductionPositionId, -- Verwendet die erste DocPositionId für jede Gruppe
MIN(PP.ArticleId)
, 'Insufficient warehousing stock available with this ' + MIN(W.IndividualizationTypeId) + ' Number.'
FROM ProductionPositionWarehousing W
LEFT JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.WarehouseId = W.WarehouseId AND ISNULL(AIQ.BinLocationId,0) = ISNULL(W.BinLocationId,0) AND AIQ.ArticleIndividualizationId = W.IndividualizationNumberId
WHERE PP.ProductionId = @parxProductionId AND A.IndividualizationTypeId != 'None' AND W.WarehousingQuantity = 0 AND PP.RowNumber !=0
GROUP BY W.IndividualizationNumberId, W.WarehouseId, ISNULL(W.BinLocationId,0)
HAVING
(SUM(W.Quantity) > MAX(AIQ.Stock)) OR
(MAX(AIQ.NowAvailable) IS NULL)
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
NULL
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'Warehousing records are missing.'
FROM ProductionPosition PP
LEFT JOIN ProductionPositionWarehousing W ON W.ProductionPositionId = PP.Id
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND A.Warehousing = 1 AND W.Id IS NULL AND APSCT.WarehousingEffective != 1;
INSERT INTO @InvalidPositions (WarehousingId, PositionNumber, ProductionPositionId , ArticleId, TEXT)
SELECT
W.Id
, PP.PositionNumber
, PP.Id
, PP.ArticleId
, 'Serial Number exists more than once in this Production.'
FROM ProductionPositionWarehousing W
JOIN ProductionPositionWarehousing DuplicateW ON W.IndividualizationNumberId = DuplicateW.IndividualizationNumberId AND W.Id != DuplicateW.Id
JOIN ProductionPosition PP ON PP.Id = W.ProductionPositionId
JOIN ProductionPosition DuplicatePP ON DuplicatePP.Id = DuplicateW.ProductionPositionId
WHERE PP.ProductionId = @parxProductionId AND DuplicatePP.ProductionId = @parxProductionId AND W.IndividualizationTypeId = 'Serial' ;
UPDATE PP
SET PP.Pending = 1 
FROM ProductionPosition PP
JOIN @InvalidPositions IP ON PP.Id = IP.ProductionPositionId;
IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
-- 30.) ArticleQuantity
WITH UpdatedArticleQuantities AS (
SELECT
PP.ArticleId
, SUM(W.Quantity) * PP.WarehousingEffectiveId AS QuantityIssued
, SUM(PP.PositionQuantityIssued) AS QuantityIssuedFromPosition
, MIN(PP.Id) AS ProductionPositionId
FROM ProductionPosition PP
LEFT JOIN Article A ON A.Id = PP.ArticleId
LEFT JOIN ProductionPositionWarehousing W ON W.ProductionPositionId = PP.Id
WHERE
PP.ProductionId = @parxProductionId AND (W.WarehousingQuantity = 0 OR A.Warehousing = 0)
GROUP BY
PP.ArticleId
, PP.WarehousingEffectiveId
)
UPDATE AQ
SET
AQ.Stock = CASE WHEN A.Warehousing = 1 THEN AQ.Stock + UAQ.QuantityIssued ELSE AQ.Stock END
, AQ.InventoryCountingPosition= NULL
, AQ.DocPosition = NULL
, AQ.ProductionPosition= UAQ.ProductionPositionId
FROM
ArticleQuantity AQ
JOIN UpdatedArticleQuantities UAQ ON AQ.ArticleId = UAQ.ArticleId
LEFT JOIN Article A ON A.Id = UAQ.ArticleId
-- 40.) WarehouseQuantity
--INSERT MISSING WarehouseQuantity Records
CREATE TABLE #UpdatedWarehouseQuantities (
ArticleId NVARCHAR(30),
WarehouseId INT,
BinLocationId INT,
Quantity DECIMAL(19,6),
PositionId INT
);
INSERT INTO #UpdatedWarehouseQuantities
SELECT
PP.ArticleId
, PPW.WarehouseId
, PPW.BinLocationId
, SUM(PPW.Quantity) AS TotalDifference
, MIN(PP.Id)
FROM ProductionPositionWarehousing PPW
LEFT JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
LEFT JOIN Article A ON A.Id = PP.ArticleId
WHERE PP.ProductionId = @parxProductionId AND PPW.WarehousingQuantity = 0 AND A.Warehousing = 1 AND PPW.WarehousingQuantity = 0 AND PP.RowNumber != 0
GROUP BY
PP.ArticleId, PPW.WarehouseId, PPW.BinLocationId;
INSERT INTO #UpdatedWarehouseQuantities
SELECT
PP.ArticleId
, P.ProductionWarehouseId
, PPW.BinLocationId
, SUM(PPW.Quantity * -1) AS TotalDifference
, MIN(PP.Id)
FROM ProductionPositionWarehousing PPW
LEFT JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
LEFT JOIN Production P ON P.Id = PP.ProductionId
LEFT JOIN Article A ON A.Id = PP.ArticleId
WHERE PP.ProductionId = @parxProductionId AND PPW.WarehousingQuantity = 0 AND A.Warehousing = 1 AND PPW.WarehousingQuantity = 0 AND PP.RowNumber = 0
GROUP BY
PP.ArticleId, P.ProductionWarehouseId, PPW.BinLocationId;
INSERT INTO WarehouseQuantity (WarehouseId, ArticleId, BinLocationId, InventoryCountingPosition, DocPosition, ProductionPosition, TransferPosition)
SELECT
UWQ.WarehouseId AS WarehouseId
, UWQ.ArticleId AS ArticleId
, NULLIF(ISNULL(UWQ.BinLocationId, 0),0) AS BinLocationId
, NULL
, NULL
, UWQ.PositionId
, NULL
FROM #UpdatedWarehouseQuantities UWQ
LEFT JOIN WarehouseQuantity WQ ON WQ.ArticleId = UWQ.ArticleId AND WQ.WarehouseId = UWQ.WarehouseId AND ISNULL(WQ.BinLocationId, 0) = ISNULL(UWQ.BinLocationId, 0)
WHERE WQ.ArticleId IS NULL  -- Fügt nur Datensätze hinzu, wenn kein passender WarehouseQuantity-Eintrag existiert
--Update WarehouseQuantity Records
UPDATE WQ
SET
WQ.Stock = WQ.Stock - UWQ.Quantity 
, WQ.ProductionPosition = UWQ.PositionId
, WQ.InventoryCountingPosition = NULL
, WQ.DocPosition = NULL
, WQ.TransferPosition = NULL
FROM
WarehouseQuantity WQ
JOIN
#UpdatedWarehouseQuantities UWQ ON WQ.ArticleId = UWQ.ArticleId AND WQ.WarehouseId = UWQ.WarehouseId AND ISNULL(WQ.BinLocationId, 0) = ISNULL(UWQ.BinLocationId, 0) ;
-- 50.) ArticleIndividualizationQuantity
--INSERT MISSING ArticleIndividualizationQuantity Records
CREATE TABLE #UpdatedArticleIndividualizationQuantities (
IndividualizationNumberId NVARCHAR(30),
WarehouseId INT,
BinLocationId INT,
Quantity DECIMAL(19,6),
PositionId INT
);
INSERT INTO #UpdatedArticleIndividualizationQuantities
SELECT
PPW.IndividualizationNumberId
, PPW.WarehouseId
, PPW.BinLocationId
, SUM(PPW.Quantity) AS Quantity 
, MIN(PP.Id)
FROM ProductionPositionWarehousing PPW
LEFT JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
WHERE PP.ProductionId = @parxProductionId AND PPW.WarehousingQuantity = 0 AND PPW.WarehousingQuantity = 0  AND PPW.IndividualizationNumberId IS NOT NULL AND PP.RowNumber != 0
GROUP BY
PPW.IndividualizationNumberId, PPW.WarehouseId, PPW.BinLocationId;
INSERT INTO #UpdatedArticleIndividualizationQuantities
SELECT
PPW.IndividualizationNumberId
, P.ProductionWarehouseId
, PPW.BinLocationId
, SUM(PPW.Quantity * -1) AS Quantity 
, MIN(PP.Id)
FROM ProductionPositionWarehousing PPW
LEFT JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
LEFT JOIN Production P ON P.Id = PP.ProductionId
WHERE PP.ProductionId = @parxProductionId AND PPW.WarehousingQuantity = 0 AND PPW.WarehousingQuantity = 0  AND PPW.IndividualizationNumberId IS NOT NULL AND PP.RowNumber = 0
GROUP BY
PPW.IndividualizationNumberId, P.ProductionWarehouseId, PPW.BinLocationId;
INSERT INTO ArticleIndividualizationQuantity (WarehouseId, ArticleIndividualizationId, BinLocationId, InventoryCountingPosition, DocPosition, ProductionPosition, TransferPosition)
SELECT
UAIQ.WarehouseId AS WarehouseId
, UAIQ.IndividualizationNumberId AS ArticleIndividualizationId
, NULLIF(ISNULL(UAIQ.BinLocationId, 0),0) AS BinLocationId
, NULL
, NULL
, UAIQ.PositionId AS InventoryCountingPosition
, NULL
FROM #UpdatedArticleIndividualizationQuantities UAIQ
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = UAIQ.IndividualizationNumberId AND AIQ.WarehouseId = UAIQ.WarehouseId AND ISNULL(AIQ.BinLocationId, 0) = ISNULL(UAIQ.BinLocationId, 0)
WHERE AIQ.ArticleIndividualizationId IS NULL  -- Fügt nur Datensätze hinzu, wenn kein passender WarehouseQuantity-Eintrag existiert
UPDATE AIQ
SET
AIQ.Stock = AIQ.Stock - UAIQ.Quantity
, AIQ.Packed = ISNULL(AIQ.Packed, 0) + ISNULL(UAIQ.Quantity, 0) + ISNULL(R0.QuantityRowNumber0, 0)
, AIQ.ProductionPosition = UAIQ.PositionId
, AIQ.InventoryCountingPosition = NULL
, AIQ.DocPosition = NULL
, AIQ.TransferPosition = NULL
FROM
ArticleIndividualizationQuantity AIQ
JOIN
#UpdatedArticleIndividualizationQuantities UAIQ ON AIQ.ArticleIndividualizationId = UAIQ.IndividualizationNumberId AND AIQ.WarehouseId = UAIQ.WarehouseId AND ISNULL(AIQ.BinLocationId, 0) = ISNULL(UAIQ.BinLocationId, 0)
LEFT JOIN (
SELECT
PPW.IndividualizationNumberId
, P.ProductionWarehouseId AS WarehouseId
, PPW.BinLocationId
, SUM(PPW.Quantity) AS QuantityRowNumber0
FROM ProductionPositionWarehousing PPW
JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
JOIN Production P ON P.Id = PP.ProductionId
WHERE PP.ProductionId = @parxProductionId
AND PP.RowNumber = 0
AND PPW.WarehousingQuantity = 0
AND PPW.IndividualizationNumberId IS NOT NULL
GROUP BY
PPW.IndividualizationNumberId
, P.ProductionWarehouseId
, PPW.BinLocationId
) R0
ON R0.IndividualizationNumberId = UAIQ.IndividualizationNumberId
AND R0.WarehouseId = UAIQ.WarehouseId
AND ISNULL(R0.BinLocationId, 0) = ISNULL(UAIQ.BinLocationId, 0);
DROP TABLE #UpdatedWarehouseQuantities;
DROP TABLE #UpdatedArticleIndividualizationQuantities ;
-- 60.) ProductionPosition
UPDATE PP
SET 
PositionQuantityCompleted = PP.PositionQuantityCompleted + (P.ProductionQuantityIssued* PP.QuantityFactor)
, PositionQuantityAnnounced = CASE WHEN PositionQuantityAnnounced - (P.ProductionQuantityIssued* PP.QuantityFactor) > 0 THEN PositionQuantityAnnounced -  (P.ProductionQuantityIssued* PP.QuantityFactor) ELSE 0 END
, PositionQuantityOrdered = CASE WHEN PositionQuantityAnnounced >= (P.ProductionQuantityIssued* PP.QuantityFactor) THEN PositionQuantityOrdered  ELSE PositionQuantityOrdered - (P.ProductionQuantityIssued* PP.QuantityFactor) + PositionQuantityAnnounced END
, Pending = 0
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
LEFT JOIN Production P ON P.Id = PP.ProductionId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective = 1
UPDATE PP
SET 
PositionQuantityConsumed = PP.PositionQuantityConsumed + PP.PositionQuantityIssued
, PositionQuantityIssued = 0
, Pending = 0
FROM ProductionPosition PP
LEFT JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
WHERE PP.ProductionId = @parxProductionId AND APSCT.WarehousingEffective != 1
-- 65.) ProductionPositionWarehousing
UPDATE ProductionPositionWarehousing
SET 
WarehousingEffective = CASE WHEN RowNumber = 0 THEN 1 ELSE -1 END
FROM ProductionPositionWarehousing PPW
LEFT JOIN ProductionPosition PP ON PP.Id = PPW.ProductionPositionId
WHERE PP.ProductionId = @parxProductionId AND PPW.WarehousingQuantity = 0
-- 70.) Production
UPDATE Production
SET 
ProductionQuantityCompleted = ProductionQuantityCompleted + ProductionQuantityIssued
, ProductionQuantityConsumed = ProductionQuantityConsumed + ProductionQuantityIssued
, ProductionQuantityIssued = 0
, ProductionStatusId = CASE WHEN ProductionQuantityCompleted + ProductionQuantityIssued = ProductionQuantityPlanned THEN 'done' ELSE ProductionStatusId END
, ProductionQuantityAnnounced = CASE WHEN ProductionQuantityAnnounced - ProductionQuantityIssued > 0 THEN ProductionQuantityAnnounced - ProductionQuantityIssued ELSE 0 END
, ProductionQuantityOrdered = CASE WHEN ProductionQuantityAnnounced >= ProductionQuantityIssued THEN ProductionQuantityOrdered  ELSE ProductionQuantityOrdered - ProductionQuantityIssued + ProductionQuantityAnnounced END
FROM Production
WHERE Id = @parxProductionId;
-- 90.) RETURN
-- RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidPositions) = 0 BEGIN
SELECT * FROM @InvalidPositions 
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC418U_Production_Completed----------------------------------------------------------------------------------------------------
