CREATE OR ALTER PROCEDURE 
xPROC420U_ProductionPosition_PositionStart
-- PURPOSE: Update the PlannedStart with passed value and adjust Position 0 and Production 
-- 26.06.26
@parxProductionPositionId INT,
@parxPlannedStart DATETIMEOFFSET
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @ProductionId INT
SELECT
@ProductionId = ProductionId 
FROM ProductionPosition
WHERE Id = @parxProductionPositionId
UPDATE ProductionPosition SET PositionPlannedStart = @parxPlannedStart WHERE Id = @parxProductionPositionId;
WITH MinPlannedStart AS (
SELECT MIN(PositionPlannedStart) AS MinStart
FROM ProductionPosition
WHERE ProductionId = @ProductionId
AND RowNumber > 0
AND PositionTypeId = 'ProductionTime'
)
UPDATE ProductionPosition
SET PositionPlannedStart = @parxPlannedStart
FROM MinPlannedStart
WHERE
ProductionPosition.ProductionId = @ProductionId
AND ProductionPosition.RowNumber = 0
AND @parxPlannedStart = MinPlannedStart.MinStart;
UPDATE Production
SET ProductionPlannedStart = PP.PositionPlannedStart
FROM Production P
LEFT JOIN ProductionPosition PP ON PP.ProductionId = P.Id AND PP.RowNumber = 0
WHERE (P.ProductionPlannedStart != PP.PositionPlannedStart OR P.ProductionPlannedStart IS NULL) AND P.Id = @ProductionId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
