CREATE OR ALTER PROCEDURE 
xPROC500U_WarehouseInventoryCounting_CalculatedQuantities
-- 26.06.26 03:45
@parxWarehouseInventoryCountingId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
UPDATE WarehouseInventoryCountingPosition
SET
CountedQuantity= CASE WHEN CalculatedQuantity < 0 THEN 0 ELSE CalculatedQuantity END
FROM WarehouseInventoryCountingPosition
WHERE WarehouseInventoryCountingId = @parxWarehouseInventoryCountingId
UPDATE WIC
SET
WIC.SumCountedQuantity = sub.SumCountedQuantity
FROM WarehouseInventoryCounting WIC
INNER JOIN (
SELECT
WICP.WarehouseInventoryCountingId
, SUM(WICP.CountedQuantity) AS SumCountedQuantity
FROM WarehouseInventoryCountingPosition WICP
WHERE WICP.WarehouseInventoryCountingId = @parxWarehouseInventoryCountingId
GROUP BY WICP.WarehouseInventoryCountingId
) sub ON WIC.Id = sub.WarehouseInventoryCountingId
SELECT * FROM WarehouseInventoryCountingPosition WHERE WarehouseInventoryCountingId = @parxWarehouseInventoryCountingId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
