-- xPROC500U_WarehouseInventoryCounting_Draft ----------------------------------------------------------------------
-- PURPOSE: Correct Inventory when when all entries are correct, like no negative new Quantity, no Individualization number missing, no Serialnumber violation
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 30.) WarehouseInventoryCountingPosition
-- 40.) WarehouseInventoryCounting
-- 50.) ArticleQuantity
-- 60.) WarehouseQuantity
-- 70.) ArticleIndividualizationQuantity
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC500U_WarehouseInventoryCounting_Draft
-- 26.06.26 03:45
@parxInventoryCountingId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 20.) VALIDATION
DECLARE @InvalidPositions TABLE (WarehouseInventoryCountingPositionId INT, ArticleId NVARCHAR(30), IndividualizationNumberId NVARCHAR(30), TEXT NVARCHAR(100));
INSERT INTO @InvalidPositions (WarehouseInventoryCountingPositionId, ArticleId, IndividualizationNumberId, TEXT)
SELECT
Id
, ArticleId
, IndividualizationNumberId
,'Negative new quantity is not allowed'
FROM WarehouseInventoryCountingPosition
WHERE WarehouseInventoryCountingId = @parxInventoryCountingId AND CountedQuantity < 0
INSERT INTO @InvalidPositions (WarehouseInventoryCountingPositionId, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WICP.Id
, WICP.ArticleId
, WICP.IndividualizationNumberId
, A.IndividualizationTypeId + ' Number is missing.'
FROM WarehouseInventoryCountingPosition WICP
LEFT JOIN Article A ON A.Id = WICP.ArticleId
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND A.IndividualizationTypeId != 'None' AND WICP.IndividualizationNumberId IS NULL AND WICP.CountedQuantity != 0
INSERT INTO @InvalidPositions (WarehouseInventoryCountingPositionId, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WICP.Id
, WICP.ArticleId
, WICP.IndividualizationNumberId
, 'Combination of Article and Bin Location exists more than once in this Inventory Counting.'
FROM WarehouseInventoryCountingPosition WICP
JOIN WarehouseInventoryCountingPosition DuplicateWICP ON WICP.ArticleId = DuplicateWICP.ArticleId AND ISNULL(WICP.BinLocationId,0) = ISNULL(DuplicateWICP.BinLocationId,0) AND WICP.Id != DuplicateWICP.Id
LEFT JOIN Article A ON A.Id = WICP.ArticleId
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND DuplicateWICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND A.IndividualizationTypeId = 'None'
INSERT INTO @InvalidPositions (WarehouseInventoryCountingPositionId, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WICP.Id
, WICP.ArticleId
, WICP.IndividualizationNumberId
, 'Serial number appears multiple times in this inventory count.'
FROM WarehouseInventoryCountingPosition WICP
JOIN WarehouseInventoryCountingPosition DuplicateWICP ON WICP.IndividualizationNumberId = DuplicateWICP.IndividualizationNumberId AND WICP.Id != DuplicateWICP.Id
LEFT JOIN Article A ON A.Id = WICP.ArticleId
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND DuplicateWICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND A.IndividualizationTypeId = 'Serial'
INSERT INTO @InvalidPositions (WarehouseInventoryCountingPositionId, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WICP.Id
, WICP.ArticleId
, WICP.IndividualizationNumberId
, 'The counted quantity for serial numbers must be either 0 or 1.'
FROM WarehouseInventoryCountingPosition WICP
LEFT JOIN Article A ON A.Id = WICP.ArticleId
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND A.IndividualizationTypeId = 'Serial' AND NOT (WICP.CountedQuantity = 1 OR WICP.CountedQuantity = 0)
INSERT INTO @InvalidPositions (WarehouseInventoryCountingPositionId, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WICP.Id
, WICP.ArticleId
, WICP.IndividualizationNumberId
, 'Only Articles with Warehousing can be counted'
FROM WarehouseInventoryCountingPosition WICP
LEFT JOIN Article A ON A.Id = WICP.ArticleId
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND A.Warehousing = 0
UPDATE WICP
SET WICP.Pending = 1 
FROM WarehouseInventoryCountingPosition WICP
JOIN @InvalidPositions IP ON WICP.Id = IP.WarehouseInventoryCountingPositionId ;
IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
-- 30.) WarehouseInventoryCountingPosition
UPDATE WarehouseInventoryCountingPosition 
SET
Pending = 0
WHERE WarehouseInventoryCountingId = @parxInventoryCountingId;
-- 40.) WarehouseInventoryCounting
UPDATE WarehouseInventoryCounting
SET
Draft = 0
WHERE Id = @parxInventoryCountingId;
-- 50.) ArticleQuantity
WITH UpdatedArticleQuantities AS (
SELECT
WICP.ArticleId
, SUM(WICP.DifferenceQuantity) AS TotalDifference
, MIN(WICP.Id) AS InventoryCountingPositionId
FROM
WarehouseInventoryCountingPosition WICP
WHERE
WICP.WarehouseInventoryCountingId = @parxInventoryCountingId
GROUP BY
WICP.ArticleId
)
UPDATE AQ
SET
AQ.Stock = AQ.Stock + UAQ.TotalDifference
, AQ.InventoryCountingPosition= UAQ.InventoryCountingPositionId
, AQ.DocPosition = NULL
, AQ.ProductionPosition= NULL
FROM
ArticleQuantity AQ
JOIN
UpdatedArticleQuantities UAQ ON AQ.ArticleId = UAQ.ArticleId;
-- 60.) WarehouseQuantity
--INSERT MISSING WarehouseQuantity Records
CREATE TABLE #UpdatedWarehouseQuantities (
ArticleId NVARCHAR(30),
WarehouseId INT,
BinLocationId INT,
TotalDifference DECIMAL(19,6),
PositionId INT
);
INSERT INTO #UpdatedWarehouseQuantities
SELECT
WICP.ArticleId
, WIC.WarehouseId
, WICP.BinLocationId
, SUM(WICP.DifferenceQuantity) AS TotalDifference
, MIN(WICP.Id)
FROM WarehouseInventoryCountingPosition WICP
LEFT JOIN WarehouseInventoryCounting WIC ON WIC.Id = WICP.WarehouseInventoryCountingId
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId
GROUP BY
WICP.ArticleId, WIC.WarehouseId, WICP.BinLocationId;
INSERT INTO WarehouseQuantity (WarehouseId, ArticleId, BinLocationId, InventoryCountingPosition, DocPosition, ProductionPosition, TransferPosition)
SELECT
UWQ.WarehouseId AS WarehouseId
, UWQ.ArticleId AS ArticleId
, NULLIF(ISNULL(UWQ.BinLocationId, 0),0) AS BinLocationId
, UWQ.PositionId
, NULL
, NULL
, NULL
FROM #UpdatedWarehouseQuantities UWQ
LEFT JOIN WarehouseQuantity WQ ON WQ.ArticleId = UWQ.ArticleId AND WQ.WarehouseId = UWQ.WarehouseId AND ISNULL(WQ.BinLocationId, 0) = ISNULL(UWQ.BinLocationId, 0)
WHERE WQ.ArticleId IS NULL  -- Fügt nur Datensätze hinzu, wenn kein passender WarehouseQuantity-Eintrag existiert
--Update WarehouseQuantity Records
UPDATE WQ
SET
WQ.Stock = WQ.Stock + UWQ.TotalDifference
, WQ.InventoryCountingPosition = UWQ.PositionId
, WQ.DocPosition = NULL
, WQ.ProductionPosition = NULL
, WQ.TransferPosition = NULL
FROM
WarehouseQuantity WQ
JOIN
#UpdatedWarehouseQuantities UWQ ON WQ.ArticleId = UWQ.ArticleId AND WQ.WarehouseId = UWQ.WarehouseId AND ISNULL(WQ.BinLocationId, 0) = ISNULL(UWQ.BinLocationId, 0) ;
-- 70.) ArticleIndividualizationQuantity
--INSERT MISSING ArticleIndividualizationQuantity Records
CREATE TABLE #UpdatedArticleIndividualizationQuantities (
IndividualizationNumberId NVARCHAR(30),
WarehouseId INT,
BinLocationId INT,
TotalDifference DECIMAL(19,6),
PositionId INT
);
INSERT INTO #UpdatedArticleIndividualizationQuantities
SELECT
WICP.IndividualizationNumberId
, WIC.WarehouseId
, WICP.BinLocationId
, SUM(WICP.DifferenceQuantity) AS TotalDifference
, MIN(WICP.Id)
FROM WarehouseInventoryCountingPosition WICP
LEFT JOIN WarehouseInventoryCounting WIC ON WIC.Id = WICP.WarehouseInventoryCountingId
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId AND WICP.IndividualizationNumberId IS NOT NULL
GROUP BY
WICP.IndividualizationNumberId, WIC.WarehouseId, WICP.BinLocationId;
INSERT INTO ArticleIndividualizationQuantity (WarehouseId, ArticleIndividualizationId, BinLocationId, InventoryCountingPosition, DocPosition, ProductionPosition, TransferPosition)
SELECT
UAIQ.WarehouseId AS WarehouseId
, UAIQ.IndividualizationNumberId AS ArticleIndividualizationId
, NULLIF(ISNULL(UAIQ.BinLocationId, 0),0) AS BinLocationId
, UAIQ.PositionId AS InventoryCountingPosition
, NULL
, NULL
, NULL
FROM #UpdatedArticleIndividualizationQuantities UAIQ
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = UAIQ.IndividualizationNumberId AND AIQ.WarehouseId = UAIQ.WarehouseId AND ISNULL(AIQ.BinLocationId, 0) = ISNULL(UAIQ.BinLocationId, 0)
WHERE AIQ.ArticleIndividualizationId IS NULL  -- Fügt nur Datensätze hinzu, wenn kein passender WarehouseQuantity-Eintrag existiert
UPDATE AIQ
SET
AIQ.Stock = AIQ.Stock + UAIQ.TotalDifference
, AIQ.InventoryCountingPosition = UAIQ.PositionId
, AIQ.DocPosition = NULL
, AIQ.ProductionPosition = NULL
, AIQ.TransferPosition = NULL
FROM
ArticleIndividualizationQuantity AIQ
JOIN
#UpdatedArticleIndividualizationQuantities UAIQ ON AIQ.ArticleIndividualizationId = UAIQ.IndividualizationNumberId AND AIQ.WarehouseId = UAIQ.WarehouseId AND ISNULL(AIQ.BinLocationId, 0) = ISNULL(UAIQ.BinLocationId, 0) ;
DROP TABLE #UpdatedWarehouseQuantities;
DROP TABLE #UpdatedArticleIndividualizationQuantities ;
-- 90.) RETURN
-- RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidPositions) = 0 BEGIN
SELECT * FROM @InvalidPositions 
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
