CREATE OR ALTER PROCEDURE 
xPROC501U_WarehouseInventoryRevaluation_Draft
-- 26.06.26 03:46
@parxWarehouseInventoryRevaluationId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
DECLARE @InvalidPositions TABLE (WarehouseInventoryRevaluationPositionId INT, ArticleId NVARCHAR(30), TEXT NVARCHAR(100));
INSERT INTO @InvalidPositions (WarehouseInventoryRevaluationPositionId, ArticleId, TEXT)
SELECT
Id
, ArticleId
,'Negative new value is not allowed'
FROM WarehouseInventoryRevaluationPosition
WHERE InventoryRevaluationId = @parxWarehouseInventoryRevaluationId AND NewValue < 0
INSERT INTO @InvalidPositions (WarehouseInventoryRevaluationPositionId, ArticleId, TEXT)
SELECT
WIRP.Id
, WIRP.ArticleId
, 'Article exists more than once in this Inventory Revaluation'
FROM WarehouseInventoryRevaluationPosition WIRP
JOIN WarehouseInventoryRevaluationPosition DuplicateWIRP ON WIRP.ArticleId= DuplicateWIRP.ArticleId AND WIRP.Id != DuplicateWIRP.Id
LEFT JOIN Article A ON A.Id = WIRP.ArticleId
WHERE WIRP.InventoryRevaluationId= @parxWarehouseInventoryRevaluationId AND DuplicateWIRP.InventoryRevaluationId= @parxWarehouseInventoryRevaluationId AND A.IndividualizationTypeId = 'Serial'
UPDATE WIRP
SET WIRP.Pending = 1 
FROM WarehouseInventoryRevaluationPosition WIRP
JOIN @InvalidPositions IP ON WIRP.Id = IP.WarehouseInventoryRevaluationPositionId;
IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
-- 30.) WarehouseInventoryRevaluationPosition
UPDATE WarehouseInventoryRevaluationPosition
SET
Pending = 0
WHERE InventoryRevaluationId= @parxWarehouseInventoryRevaluationId ;
-- 40.) WarehouseInventoryRevaluation
UPDATE WarehouseInventoryRevaluation
SET
Draft = 0
WHERE Id = @parxWarehouseInventoryRevaluationId ;
CREATE TABLE #TempTable (Id INT);
INSERT INTO #TempTable
SELECT
Id
FROM WarehouseInventoryRevaluationPosition WIRP
WHERE WIRP.InventoryRevaluationId= @parxWarehouseInventoryRevaluationId 
-- Variablen für die WHILE-Schleife
DECLARE @TotalRows INT = (SELECT COUNT(*) FROM #TempTable);
DECLARE @CurrentRow INT = 1;
DECLARE @CurrentId INT;
-- WHILE-Schleife zur Iteration durch die IDs
WHILE @CurrentRow <= @TotalRows
BEGIN
SELECT TOP 1 @CurrentId = Id
FROM #TempTable
ORDER BY Id;
UPDATE APC
SET
ProcurementPrice = WIRP.NewValue
FROM ArticlePriceCalculation APC
JOIN WarehouseInventoryRevaluationPosition WIRP ON WIRP.ArticleId = APC.ArticleId
WHERE WIRP.Id = @CurrentId
-- Entfernen der verarbeiteten ID
DELETE FROM #TempTable WHERE Id = @CurrentId;
-- Nächste Zeile
SET @CurrentRow = @CurrentRow + 1;
END
-- Temporäre Tabelle löschen
DROP TABLE #TempTable;
-- 90.) RETURN
-- RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidPositions) = 0 BEGIN
SELECT * FROM @InvalidPositions 
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
