-- xPROC502U_WarehouseTransfer_Draft ----------------------------------------------------------------------
-- PURPOSE: Move Articles and update WarehouseQuantity and for Individualization ArticleIndividualizationQuantity
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 30.) WarehouseInventoryCountingPosition
-- 40.) WarehouseInventoryCounting
-- 60.) WarehouseQuantity
-- 70.) ArticleIndividualizationQuantity
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC502U_WarehouseTransfer_Draft
-- 26.06.26 03:45
@parxWarehouseTransferId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @InvalidPositions TABLE (WarehouseTransferPosition INT, PositionNumber INT, ArticleId NVARCHAR(30), IndividualizationNumberId NVARCHAR(30), TEXT NVARCHAR(100));
-- 20.) VALIDATION
INSERT INTO @InvalidPositions (WarehouseTransferPosition , PositionNumber, ArticleId, IndividualizationNumberId, TEXT)
SELECT
MIN(WMP.Id)
, MIN(WMP.PositionNumber)
, WMP.ArticleId
, MIN(WMP.IndividualizationNumberId)
, 'Available stock is too low.'
FROM WarehouseTransferPosition WMP
LEFT JOIN WarehouseQuantity WQ ON WQ.WarehouseId = WMP.SourceWarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(WMP.SourceBinLocationId,0) AND WQ.ArticleId = WMP.ArticleId
WHERE WMP.WarehouseTransferId = @parxWarehouseTransferId
GROUP BY WMP.ArticleId, WMP.SourceWarehouseId, ISNULL(WMP.SourceBinLocationId,0)
HAVING
(SUM(WMP.Quantity) > MAX(WQ.NowAvailable)) OR
(MAX(WQ.NowAvailable) IS NULL)
INSERT INTO @InvalidPositions (WarehouseTransferPosition , PositionNumber, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WMP.Id
, WMP.PositionNumber
, WMP.ArticleId
, WMP.IndividualizationNumberId
, A.IndividualizationTypeId + ' Number is missing.'
FROM WarehouseTransferPosition WMP
LEFT JOIN Article A ON A.Id = WMP.ArticleId
WHERE WMP.WarehouseTransferId= @parxWarehouseTransferId AND A.IndividualizationTypeId != 'None' AND WMP.IndividualizationNumberId IS NULL
INSERT INTO @InvalidPositions (WarehouseTransferPosition , PositionNumber, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WMP.Id
, WMP.PositionNumber
, WMP.ArticleId
, WMP.IndividualizationNumberId
, 'Serial Number exists more than once in this Inventory Counting'
FROM WarehouseTransferPosition WMP
JOIN WarehouseTransferPosition DuplicateWMP ON WMP.IndividualizationNumberId = DuplicateWMP.IndividualizationNumberId AND WMP.Id != DuplicateWMP.Id
LEFT JOIN Article A ON A.Id = WMP.ArticleId
WHERE WMP.WarehouseTransferId = @parxWarehouseTransferId AND DuplicateWMP.WarehouseTransferId = @parxWarehouseTransferId AND A.IndividualizationTypeId = 'Serial'
INSERT INTO @InvalidPositions (WarehouseTransferPosition , PositionNumber, ArticleId, IndividualizationNumberId, TEXT)
SELECT
WMP.Id
, WMP.PositionNumber
, WMP.ArticleId
, WMP.IndividualizationNumberId
, 'Counted Quantity for Serial Numbers needs to be 0 or 1'
FROM WarehouseTransferPosition WMP
LEFT JOIN Article A ON A.Id = WMP.ArticleId
WHERE WMP.WarehouseTransferId = @parxWarehouseTransferId AND A.IndividualizationTypeId = 'Serial' AND NOT (WMP.Quantity= 1 OR WMP.Quantity= 0)
UPDATE WMP
SET WMP.Pending = 1 
FROM WarehouseTransferPosition WMP
JOIN @InvalidPositions IP ON WMP.Id = IP.WarehouseTransferPosition;
IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
-- 30.) WarehouseInventoryCountingPosition
UPDATE WarehouseTransferPosition 
SET
Pending = 0
WHERE WarehouseTransferId = @parxWarehouseTransferId ;
-- 40.) WarehouseInventoryCounting
UPDATE WarehouseTransfer
SET
DRAFT = 0
WHERE Id = @parxWarehouseTransferId ;
CREATE TABLE #TempTable (Id INT);
INSERT INTO #TempTable
SELECT
Id
FROM WarehouseTransferPosition WMP
WHERE WMP.WarehouseTransferId = @parxWarehouseTransferId 
-- Variablen für die WHILE-Schleife
DECLARE @TotalRows INT = (SELECT COUNT(*) FROM #TempTable);
DECLARE @CurrentRow INT = 1;
DECLARE @CurrentId INT;
-- WHILE-Schleife zur Iteration durch die IDs
WHILE @CurrentRow <= @TotalRows
BEGIN
SELECT TOP 1 @CurrentId = Id
FROM #TempTable
ORDER BY Id;
-- 60.) WarehouseQuantity
--INSERT MISSING WarehouseQuantity Records
INSERT INTO WarehouseQuantity (WarehouseId, ArticleId, BinLocationId)
SELECT
WMP.DestinationWarehouseId AS WarehouseId,
WMP.ArticleId AS ArticleId,
NULLIF(ISNULL(WMP.DestinationBinLocationId, 0),0) AS BinLocationId
FROM WarehouseTransferPosition WMP
LEFT JOIN WarehouseQuantity WQ ON WQ.ArticleId = WMP.ArticleId AND WQ.WarehouseId = WMP.DestinationWarehouseId AND ISNULL(WQ.BinLocationId, 0) = ISNULL(WMP.DestinationBinLocationId, 0)
WHERE WMP.Id = @CurrentId
AND WQ.ArticleId IS NULL  -- Fügt nur Datensätze hinzu, wenn kein passender WarehouseQuantity-Eintrag existiert
--Update WarehouseQuantity Records Reduce Quantity for Source
UPDATE WarehouseQuantity
SET
Stock = Stock - WMP.Quantity
, TransferPosition = WMP.Id
, InventoryCountingPosition = NULL
, DocPosition = NULL
, ProductionPosition = NULL
FROM WarehouseQuantity WQ
JOIN WarehouseTransferPosition WMP ON WQ.ArticleId = WMP.ArticleId AND WMP.SourceWarehouseId = WQ.WarehouseId AND ISNULL(WQ.BinLocationId, 0) = ISNULL(WMP.SourceBinLocationId, 0)
WHERE WMP.Id = @CurrentId;
--Update WarehouseQuantity Records Increase Quantity for Destination
UPDATE WarehouseQuantity
SET
Stock = Stock + WMP.Quantity
, TransferPosition = WMP.Id
, InventoryCountingPosition = NULL
, DocPosition = NULL
, ProductionPosition = NULL
FROM WarehouseQuantity WQ
JOIN WarehouseTransferPosition WMP ON WQ.ArticleId = WMP.ArticleId AND WMP.DestinationWarehouseId = WQ.WarehouseId AND ISNULL(WQ.BinLocationId, 0) = ISNULL(WMP.DestinationBinLocationId, 0)
WHERE WMP.Id = @CurrentId;
-- 70.) ArticleIndividualizationQuantity
--INSERT MISSING ArticleIndividualizationQuantity Records
INSERT INTO ArticleIndividualizationQuantity (WarehouseId, ArticleIndividualizationId, BinLocationId)
SELECT
WMP.DestinationWarehouseId AS WarehouseId,
WMP.IndividualizationNumberId AS IndividualizationNumberId,
NULLIF(ISNULL(WMP.DestinationBinLocationId, 0),0) AS BinLocationId
FROM WarehouseTransferPosition WMP
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId= WMP.IndividualizationNumberId AND AIQ.WarehouseId = WMP.DestinationWarehouseId AND ISNULL(AIQ.BinLocationId, 0) = ISNULL(WMP.DestinationBinLocationId, 0)
LEFT JOIN Article A ON A.Id = WMP.ArticleId
WHERE WMP.Id = @CurrentId AND A.IndividualizationTypeId != 'None'
AND AIQ.ArticleIndividualizationId IS NULL  -- Fügt nur Datensätze hinzu, wenn kein passender WarehouseQuantity-Eintrag existiert
--Update ArticleIndividualizationQuantity Records Reduce Quantity for Source
UPDATE ArticleIndividualizationQuantity
SET
Stock = Stock - WMP.Quantity
, TransferPosition = WMP.Id
, InventoryCountingPosition = NULL
, DocPosition = NULL
, ProductionPosition = NULL
FROM ArticleIndividualizationQuantity AIQ
JOIN WarehouseTransferPosition WMP ON AIQ.ArticleIndividualizationId = WMP.IndividualizationNumberId AND WMP.SourceWarehouseId = AIQ.WarehouseId AND ISNULL(AIQ.BinLocationId, 0) = ISNULL(WMP.SourceBinLocationId, 0)
LEFT JOIN Article A ON A.Id = WMP.ArticleId
WHERE WMP.Id = @CurrentId AND A.IndividualizationTypeId != 'None';
--Update ArticleIndividualizationQuantity Records Increase Quantity for Destination
UPDATE ArticleIndividualizationQuantity
SET
Stock = Stock + WMP.Quantity
, TransferPosition = WMP.Id
, InventoryCountingPosition = NULL
, DocPosition = NULL
, ProductionPosition = NULL
FROM ArticleIndividualizationQuantity AIQ
JOIN WarehouseTransferPosition WMP ON AIQ.ArticleIndividualizationId = WMP.IndividualizationNumberId AND WMP.DestinationWarehouseId= AIQ.WarehouseId AND ISNULL(AIQ.BinLocationId, 0) = ISNULL(WMP.DestinationBinLocationId, 0)
LEFT JOIN Article A ON A.Id = WMP.ArticleId
WHERE WMP.Id = @CurrentId AND A.IndividualizationTypeId != 'None';
-- Entfernen der verarbeiteten ID
DELETE FROM #TempTable WHERE Id = @CurrentId;
-- Nächste Zeile
SET @CurrentRow = @CurrentRow + 1;
END
-- Temporäre Tabelle löschen
DROP TABLE #TempTable;
-- 90.) RETURN
-- RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidPositions) = 0 BEGIN
SELECT * FROM @InvalidPositions 
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
