CREATE OR ALTER PROCEDURE 
xPROC520I_WarehouseInventoryCountingPosition_ArticlesFromWarehouse
-- xPROC520I_WarehouseInventoryCountingPosition_ArticlesFromWarehouse
@parxInventoryCountingId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) CALCULATE DocPosition Sums
DECLARE @WarehouseId INT
SELECT
@WarehouseId = WarehouseId 
FROM WarehouseInventoryCounting WIC
WHERE Id = @parxInventoryCountingId 
INSERT INTO WarehouseInventoryCountingPosition
(
WarehouseInventoryCountingId
, ArticleId
, BinLocationId
, CalculatedQuantity
, CountedQuantity
)
SELECT
@parxInventoryCountingId 
, WQ.ArticleId
, WQ.BinLocationId
, WQ.Stock
, 0
FROM WarehouseQuantity WQ
LEFT JOIN Article A ON A.Id = WQ.ArticleId
WHERE  WQ.WarehouseId = @WarehouseId AND A.IndividualizationTypeId = 'None' AND WQ.Stock != 0
INSERT INTO WarehouseInventoryCountingPosition
(
WarehouseInventoryCountingId
, ArticleId
, BinLocationId
, CalculatedQuantity
, CountedQuantity
, IndividualizationNumberId
)
SELECT
@parxInventoryCountingId 
, AI.ArticleId
, AIQ.BinLocationId
, AIQ.Stock
, 0
, AIQ.ArticleIndividualizationId
FROM ArticleIndividualizationQuantity AIQ
LEFT JOIN ArticleIndividualization AI ON AI.Id = AIQ.ArticleIndividualizationId
WHERE AIQ.WarehouseId = @WarehouseId AND AIQ.Stock != 0
UPDATE WIC
SET
WIC.SumCalculatedQuantity = sub.SumCalculatedQuantity
FROM WarehouseInventoryCounting WIC
INNER JOIN (
SELECT
WICP.WarehouseInventoryCountingId
, SUM(WICP.CalculatedQuantity) AS SumCalculatedQuantity
FROM WarehouseInventoryCountingPosition WICP
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId 
GROUP BY WICP.WarehouseInventoryCountingId
) sub ON WIC.Id = sub.WarehouseInventoryCountingId
-- 90.) RETURN
SELECT * FROM xVIEW520_WarehouseInventoryCountingPosition WHERE WarehouseInventoryCountingId = @parxInventoryCountingId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
