@parxInventoryCountingId 
, @parxArticleId 
, NULL
, CASE WHEN @CalculatedQuantity IS NULL THEN 0 ELSE @CalculatedQuantity END
, 0
)
SET @newxWarehouseInventoryPositionId = SCOPE_IDENTITY();
UPDATE WIC
SET
WIC.SumCalculatedQuantity = sub.SumCalculatedQuantity
FROM WarehouseInventoryCounting WIC
INNER JOIN (
SELECT
WICP.WarehouseInventoryCountingId
, SUM(WICP.CalculatedQuantity) AS SumCalculatedQuantity
FROM WarehouseInventoryCountingPosition WICP
WHERE WICP.WarehouseInventoryCountingId = @parxInventoryCountingId
GROUP BY WICP.WarehouseInventoryCountingId
) sub ON WIC.Id = sub.WarehouseInventoryCountingId
