CREATE OR ALTER PROCEDURE 
xPROC520U_WarehouseInventoryCountingPosition_ArticleId
-- PURPOSE: Update the ArticleId with passed value and get Stock values
-- 26.06.26
@parxWarehouseInventoryCountingPositionId INT,
@parxArticleId NVARCHAR(30)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @WarehouseId INT
DECLARE @BinLocationId INT
DECLARE @IndividualizationNumberId NVARCHAR(30)
DECLARE @WarehouseInventoryCountingId INT
SELECT
@WarehouseId = WIC.WarehouseId 
, @BinLocationId = WICP.BinLocationId 
, @IndividualizationNumberId = WICP.IndividualizationNumberId 
, @WarehouseInventoryCountingId = WIC.Id
FROM WarehouseInventoryCountingPosition WICP
LEFT JOIN WarehouseInventoryCounting WIC ON WICP.WarehouseInventoryCountingId = WIC.Id
WHERE WICP.Id = @parxWarehouseInventoryCountingPositionId
DECLARE @CalculatedQuantity DECIMAL(19,6)
IF @IndividualizationNumberId IS NULL BEGIN 
SELECT
@CalculatedQuantity = WQ.Stock
FROM Article A
LEFT JOIN WarehouseQuantity WQ ON A.Id = WQ.ArticleId
WHERE A.Id = @parxArticleId AND WQ.WarehouseId = @WarehouseId AND ISNULL(WQ.BinLocationId,0) = ISNULL(@BinLocationId,0)
END
ELSE BEGIN
SELECT
@CalculatedQuantity = AIQ.Stock
FROM Article A
LEFT JOIN ArticleIndividualizationQuantity AIQ ON AIQ.ArticleIndividualizationId = @IndividualizationNumberId
WHERE A.Id = @parxArticleId AND AIQ.WarehouseId = @WarehouseId AND ISNULL(AIQ.BinLocationId,0) = ISNULL(@BinLocationId,0)
END
UPDATE WarehouseInventoryCountingPosition SET
ArticleId = @parxArticleId
, CalculatedQuantity = CASE WHEN @CalculatedQuantity IS NULL THEN 0 ELSE @CalculatedQuantity END
, CountedQuantity = 0
WHERE Id = @parxWarehouseInventoryCountingPositionId
UPDATE WIC
SET
WIC.SumCountedQuantity = sub.SumCountedQuantity
, WIC.SumCalculatedQuantity= sub.SumCalculatedQuantity
FROM WarehouseInventoryCounting WIC
INNER JOIN (
SELECT
WICP.WarehouseInventoryCountingId
, SUM(WICP.CountedQuantity) AS SumCountedQuantity
, SUM(WICP.CalculatedQuantity) AS SumCalculatedQuantity
FROM WarehouseInventoryCountingPosition WICP
WHERE WICP.WarehouseInventoryCountingId = @WarehouseInventoryCountingId
GROUP BY WICP.WarehouseInventoryCountingId
) sub ON WIC.Id = sub.WarehouseInventoryCountingId
SELECT * FROM WarehouseInventoryCountingPosition WHERE Id = @parxWarehouseInventoryCountingPositionId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
