WIRP.InventoryRevaluationId
, SUM(WIRP.OldValue) AS SumOldValue
, SUM(WIRP.NewValue) AS SumNewValue
FROM WarehouseInventoryRevaluationPosition WIRP
WHERE WIRP.InventoryRevaluationId= @InventoryRevaluationId
GROUP BY WIRP.InventoryRevaluationId
) sub ON WIR.Id = sub.InventoryRevaluationId
WHERE WIR.Id = @InventoryRevaluationId;
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
-- END xPROC521D_WarehouseInventoryRevaluationPosition_Article ----------------------------------------------------------------------
-- xPROC521U_WarehouseInventoryRevaluationPosition_ArticleId----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC521U_WarehouseInventoryRevaluationPosition_ArticleId
-- PURPOSE: Update the ArticleId with passed value and Set Values to ProcurementPrice and recalculate sums
-- 26.06.26
@parxWarehouseInventoryRevaluationPositionId INT,
@parxArticleId NVARCHAR(30)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @InventoryRevaluationId INT
SELECT
@InventoryRevaluationId = InventoryRevaluationId
FROM WarehouseInventoryRevaluationPosition
WHERE Id = @parxWarehouseInventoryRevaluationPositionId
UPDATE WIRP
SET
ArticleId = @parxArticleId
, OldValue = APC.ProcurementPrice
, NewValue = APC.ProcurementPrice
FROM WarehouseInventoryRevaluationPosition WIRP
LEFT JOIN Article A ON A.Id = @parxArticleId
LEFT JOIN ArticlePriceCalculation APC ON APC.ArticleId = A.Id
WHERE WIRP.Id = @parxWarehouseInventoryRevaluationPositionId 
UPDATE WIR
SET
WIR.SumNewValue = sub.SumNewValue
, WIR.SumOldValue = sub.SumOldValue
FROM WarehouseInventoryRevaluation WIR
INNER JOIN (
SELECT
WIRP.InventoryRevaluationId
, SUM(WIRP.OldValue) AS SumOldValue
, SUM(WIRP.NewValue) AS SumNewValue
FROM WarehouseInventoryRevaluationPosition WIRP
WHERE WIRP.InventoryRevaluationId= @InventoryRevaluationId
GROUP BY WIRP.InventoryRevaluationId
) sub ON WIR.Id = sub.InventoryRevaluationId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
