CREATE OR ALTER PROCEDURE 
xPROC521U_WarehouseInventoryRevaluationPosition_NewValue
-- PURPOSE: Update the NewValue with passed value and recalculate sums
-- 26.06.26
@parxWarehouseInventoryRevaluationPositionId INT,
@parxNewValue DECIMAL(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @InventoryRevaluationId INT
SELECT
@InventoryRevaluationId = InventoryRevaluationId
FROM WarehouseInventoryRevaluationPosition
WHERE Id = @parxWarehouseInventoryRevaluationPositionId
UPDATE WarehouseInventoryRevaluationPosition
SET
NewValue = @parxNewValue
FROM WarehouseInventoryRevaluationPosition
WHERE Id = @parxWarehouseInventoryRevaluationPositionId
UPDATE WIR
SET
WIR.SumNewValue = sub.SumNewValue
FROM WarehouseInventoryRevaluation WIR
INNER JOIN (
SELECT
WIRP.InventoryRevaluationId
, SUM(WIRP.OldValue) AS SumOldValue
, SUM(WIRP.NewValue) AS SumNewValue
FROM WarehouseInventoryRevaluationPosition WIRP
WHERE WIRP.InventoryRevaluationId= @InventoryRevaluationId
GROUP BY WIRP.InventoryRevaluationId
) sub ON WIR.Id = sub.InventoryRevaluationId
SELECT * FROM xVIEW521_WarehouseInventoryRevaluationPosition WHERE Id = @parxWarehouseInventoryRevaluationPositionId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
