CREATE OR ALTER PROCEDURE 
xPROC522I_WarehouseTransferPosition_Article
-- xPROC522I_WarehouseTransferPosition_Article
@parxWarehouseTransferId INT,
@parxArticleId NVARCHAR(30)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @calxNewTransferPositionNumber INT
SELECT
@calxNewTransferPositionNumber = ISNULL(MAX(PositionNumber), 0) + 1
FROM WarehouseTransferPosition
WHERE WarehouseTransferId = @parxWarehouseTransferId
DECLARE @IndividualizationTypeId NVARCHAR(6)
SELECT
@IndividualizationTypeId = IndividualizationTypeId 
FROM Article A
WHERE Id = @parxArticleId
DECLARE @SourceWarehouseId INT
DECLARE @SourceBinLocationId INT
DECLARE @DestinationWarehouseId INT
DECLARE @DestinationBinLocationId INT
SELECT
@SourceWarehouseId = SourceWarehouseId 
, @SourceBinLocationId = SourceBinLocationId 
, @DestinationWarehouseId = DestinationWarehouseId 
, @DestinationBinLocationId = DestinationBinLocationId 
FROM WarehouseTransfer
WHERE Id = @parxWarehouseTransferId
DECLARE @newxTransferPositionId INT
-- 30.) INSERT WarehouseTransferPosition
INSERT INTO WarehouseTransferPosition
(
WarehouseTransferId
, PositionNumber
, ArticleId
, Quantity
, SourceWarehouseId
, SourceBinLocationId
, DestinationWarehouseId
, DestinationBinLocationId
, IndividualizationTypeId
)
VALUES (
@parxWarehouseTransferId
, @calxNewTransferPositionNumber 
, @parxArticleId
, 1
, @SourceWarehouseId
, @SourceBinLocationId
, @DestinationWarehouseId
, @DestinationBinLocationId
, @IndividualizationTypeId 
)
SET @newxTransferPositionId = SCOPE_IDENTITY();
-- 90.) RETURN
SELECT * FROM xVIEW522_WarehouseTransferPosition WHERE Id = @newxTransferPositionId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
