-- xPROC550_ProcurementWizard ----------------------------------------------------------------------
-- Purpose: Create Entries in Procurement Table with needed Articles
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT into Procurement for Positions
-- 21.) INSERT into Procurement for Warehouses
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC550_ProcurementWizard
-- 26.06.26 03:46
@parxProcurementTypeId NVARCHAR(4)
, @parxSelectedLocation INT = NULL
, @parxSelectedFromArticle NVARCHAR(50) = NULL
, @parxSelectedToArticle NVARCHAR(50) = NULL
, @parxSelectedFromArticleGroup INT = NULL
, @parxSelectedToArticleGroup INT = NULL
, @parxSelectedFromSupplier NVARCHAR(30) = NULL
, @parxSelectedToSupplier NVARCHAR(30) = NULL
, @parxSelectedFromCustomer NVARCHAR(30) = NULL
, @parxSelectedToCustomer NVARCHAR(30) = NULL
, @parxSelectedStockConsideration NVARCHAR(30) = NULL
, @parxSelectedSupplierPriority NVARCHAR(30) = NULL
, @parxSelectedFromWarehouseId INT = NULL
, @parxSelectedToWarehouseId INT = NULL
, @parxSelectedFromProductionNumber NVARCHAR(20) = NULL
, @parxSelectedToProductionNumber NVARCHAR(20) = NULL
AS
BEGIN
SET NOCOUNT ON;
DECLARE @TransactionSuccess BIT = 1;
BEGIN TRY
BEGIN TRANSACTION;
IF NOT EXISTS (
SELECT 1
FROM Procurement
WHERE ProductionId IS NULL AND PurchaseOrderPosId IS NULL
)
BEGIN
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @SelectedFromArticleGroupName NVARCHAR(50)
SELECT
@SelectedFromArticleGroupName = Name
FROM ArticleGroup
WHERE Id = @parxSelectedFromArticleGroup
DECLARE @SelectedToArticleGroupName NVARCHAR(50)
SELECT
@SelectedToArticleGroupName = Name
FROM ArticleGroup
WHERE Id = @parxSelectedToArticleGroup;
-- 20.) INSERT into Procurement for Positions
CREATE TABLE #TopPPPL (
ArticleId NVARCHAR(30),
PartnerId INT,
DeliveryTime INT,
UnitPrice DECIMAL(10, 2),
rnTime INT,
rnPrice INT
);
-- Einfügen der Daten in die temporäre Tabelle
INSERT INTO #TopPPPL (ArticleId, PartnerId, DeliveryTime, UnitPrice, rnTime, rnPrice)
SELECT
PPPL.ArticleId,
PPPL.PartnerId,
PPPL.DeliveryTime,
PPPL.UnitPrice,
ROW_NUMBER() OVER (PARTITION BY PPPL.ArticleId ORDER BY PPPL.DeliveryTime) AS rnTime,
ROW_NUMBER() OVER (PARTITION BY PPPL.ArticleId ORDER BY PPPL.UnitPrice) AS rnPrice
FROM
PartnerPurchasePriceList PPPL;
IF( @parxSelectedStockConsideration = 'IgnoreWarehouse') BEGIN
;WITH OrderedPositions AS (
SELECT
DP.Id                                 AS DocPositionId
, DP.ArticleId
, DP.QuantityOpen
, ISNULL(AQIS.NowAvailable, 0)          AS NowAvailable
, ROW_NUMBER() OVER (PARTITION BY DP.ArticleId ORDER BY DP.Id) AS RowNum
FROM DocPosition DP
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AQIS
ON AQIS.ArticleId = DP.ArticleId
LEFT JOIN Doc D
ON D.Id = DP.DocId
LEFT JOIN DocType DT
ON DT.Id = D.DocTypeId
LEFT JOIN Article A
ON A.Id = DP.ArticleId
LEFT JOIN ArticleGroup AG
ON AG.Id = A.ArticleGroupId
LEFT JOIN Partner P
ON P.Id = D.PartnerId
LEFT JOIN #TopPPPL PPPL
ON PPPL.ArticleId = DP.ArticleId
AND (
(@parxSelectedSupplierPriority = 'FastestSupplier'  AND PPPL.rnTime  = 1)
OR (@parxSelectedSupplierPriority = 'CheapestSupplier' AND PPPL.rnPrice = 1)
)
LEFT JOIN Partner PStandardSupplier
ON PStandardSupplier.Id = A.StandardSupplierId
LEFT JOIN Partner PartnerPPPL
ON PartnerPPPL.Id = PPPL.PartnerId
WHERE DT.IsOrderConfirmation = 1
AND (DP.StatusId = 'open' OR DP.StatusId = 'partially')
AND (A.ProcurementTypeId = @parxProcurementTypeId OR A.ProcurementTypeId = 'ask')
AND DP.RelatedPositionId IS NULL
AND (@parxSelectedLocation      IS NULL OR D.LocationId = @parxSelectedLocation)
AND (@parxSelectedFromArticle   IS NULL OR A.Matchcode >= @parxSelectedFromArticle)
AND (@parxSelectedToArticle     IS NULL OR A.Matchcode <= @parxSelectedToArticle)
AND (@SelectedFromArticleGroupName IS NULL OR AG.Name >= @SelectedFromArticleGroupName)
AND (@SelectedToArticleGroupName   IS NULL OR AG.Name <= @SelectedToArticleGroupName)
AND (@parxSelectedFromCustomer  IS NULL OR P.Matchcode >= @parxSelectedFromCustomer)
AND (@parxSelectedToCustomer    IS NULL OR P.Matchcode <= @parxSelectedToCustomer)
AND (
(@parxSelectedFromSupplier IS NULL OR @parxSelectedSupplierPriority != 'StandardSupplier')
OR (PStandardSupplier.Matchcode >= @parxSelectedFromSupplier AND @parxSelectedSupplierPriority = 'StandardSupplier')
)
AND (
(@parxSelectedToSupplier IS NULL OR @parxSelectedSupplierPriority != 'StandardSupplier')
OR (PStandardSupplier.Matchcode <= @parxSelectedToSupplier AND @parxSelectedSupplierPriority = 'StandardSupplier')
)
AND (
(@parxSelectedFromSupplier IS NULL OR @parxSelectedSupplierPriority = 'StandardSupplier')
OR (PartnerPPPL.Matchcode >= @parxSelectedFromSupplier AND @parxSelectedSupplierPriority != 'StandardSupplier')
)
AND (
(@parxSelectedToSupplier IS NULL OR @parxSelectedSupplierPriority = 'StandardSupplier')
OR (PartnerPPPL.Matchcode <= @parxSelectedToSupplier AND @parxSelectedSupplierPriority != 'StandardSupplier')
)
-- Keine OCs doppelt in Procurement:
AND NOT EXISTS (
SELECT 1
FROM Procurement P2
WHERE P2.OrderConfirmationPositionId = DP.Id
)
)
, RunningTotals AS (
SELECT
OP.*
, SUM(OP.QuantityOpen) OVER (
PARTITION BY OP.ArticleId
ORDER BY OP.RowNum
ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING
) AS CumulatedBefore
FROM OrderedPositions OP
)
, CalculatedStockUsage AS (
SELECT
RT.*
, CASE
WHEN RT.NowAvailable IS NULL THEN 0
WHEN RT.CumulatedBefore IS NULL
THEN CASE WHEN RT.QuantityOpen <= RT.NowAvailable THEN RT.QuantityOpen ELSE RT.NowAvailable END
ELSE CASE
WHEN RT.CumulatedBefore >= RT.NowAvailable THEN 0
WHEN RT.CumulatedBefore + RT.QuantityOpen <= RT.NowAvailable THEN RT.QuantityOpen
ELSE RT.NowAvailable - RT.CumulatedBefore
END
END AS StockQuantityUsed
FROM RunningTotals RT
)
INSERT INTO Procurement (
ArticleId
, ProcurementTypeId
, OrderConfirmationPositionId
, ConfirmedQuantityOpen
, SupplierId
, PurchaseOrderPosId
, Info
, StockQuantityUsed
)
SELECT
DP.ArticleId
, A.ProcurementTypeId
, DP.Id
, DP.QuantityOpen
, CASE
WHEN @parxSelectedSupplierPriority = 'StandardSupplier' THEN A.StandardSupplierId
ELSE PPPL.PartnerId
END
, NULL
, NULL
, COALESCE(CSU.StockQuantityUsed, 0)
FROM CalculatedStockUsage AS CSU
JOIN DocPosition AS DP
ON DP.Id = CSU.DocPositionId
JOIN Doc AS D
ON D.Id = DP.DocId
JOIN Article AS A
ON A.Id = DP.ArticleId
LEFT JOIN #TopPPPL AS PPPL
ON PPPL.ArticleId = DP.ArticleId
AND (
(@parxSelectedSupplierPriority = 'FastestSupplier'  AND PPPL.rnTime  = 1)
OR (@parxSelectedSupplierPriority = 'CheapestSupplier' AND PPPL.rnPrice = 1)
)
WHERE D.DocCategoryId = 'Sales';
END
-- 21.) INSERT into Procurement for Warehouses (Threshold-Modus)
IF (@parxSelectedStockConsideration NOT IN ('IgnoreWarehouse', 'ForProduction'))
BEGIN
INSERT INTO Procurement(
ArticleId
, ProcurementTypeId
, WarehouseId
, BinLocationId
, SupplierId
, PurchaseOrderPosId
, Info
, StockQuantityUsed
, ThresholdQuantity
)
SELECT
WQ.ArticleId
, A.ProcurementTypeId
, WQ.WarehouseId
, WQ.BinLocationId
, CASE WHEN @parxSelectedSupplierPriority = 'StandardSupplier' THEN A.StandardSupplierId ELSE PPPL.PartnerId END
, NULL
, NULL
, WQ.NowAvailable
, CASE
WHEN @parxSelectedStockConsideration = 'ConsiderMinimumStock'     THEN WQ.MinimumStock
WHEN @parxSelectedStockConsideration = 'ConsiderMessageThreshold' THEN WQ.MessageThreshold
WHEN @parxSelectedStockConsideration = 'ConsiderMaximumStock'     THEN WQ.MaximumStock
END
FROM WarehouseQuantity AS WQ
LEFT JOIN Article A
ON WQ.ArticleId = A.Id
LEFT JOIN ArticleGroup AG
ON A.ArticleGroupId = AG.Id
LEFT JOIN Warehouse W
ON W.Id = WQ.WarehouseId
LEFT JOIN #TopPPPL PPPL
ON PPPL.ArticleId = A.Id
AND (
(@parxSelectedSupplierPriority = 'FastestSupplier'  AND PPPL.rnTime  = 1)
OR (@parxSelectedSupplierPriority = 'CheapestSupplier' AND PPPL.rnPrice = 1)
)
WHERE (A.ProcurementTypeId = @parxProcurementTypeId OR A.ProcurementTypeId = 'ask')
AND (@parxSelectedLocation    IS NULL OR W.LocationId = @parxSelectedLocation)
AND (@parxSelectedFromArticle IS NULL OR A.Matchcode >= @parxSelectedFromArticle)
AND (@parxSelectedToArticle   IS NULL OR A.Matchcode <= @parxSelectedToArticle)
AND (@SelectedFromArticleGroupName IS NULL OR AG.Name >= @SelectedFromArticleGroupName)
AND (@SelectedToArticleGroupName   IS NULL OR AG.Name <= @SelectedToArticleGroupName)
AND (@parxSelectedFromWarehouseId IS NULL OR W.Id >= @parxSelectedFromWarehouseId)
AND (@parxSelectedToWarehouseId   IS NULL OR W.Id <= @parxSelectedToWarehouseId)
AND (
(@parxSelectedStockConsideration = 'ConsiderMinimumStock'     AND WQ.NowAvailable < WQ.MinimumStock)
OR (@parxSelectedStockConsideration = 'ConsiderMessageThreshold' AND WQ.NowAvailable < WQ.MessageThreshold)
OR (@parxSelectedStockConsideration = 'ConsiderMaximumStock'     AND WQ.NowAvailable < WQ.MaximumStock)
);
END
-- 22.) INSERT into Procurement for Production (ForProduction-Modus)
IF (@parxSelectedStockConsideration = 'ForProduction')
BEGIN
INSERT INTO Procurement (
ArticleId
, ProcurementTypeId
, OrderConfirmationPositionId
, ConfirmedQuantityOpen
, ProductionPositionId
, SupplierId
, PurchaseOrderPosId
, Info
, StockQuantityUsed
)
SELECT
PP.ArticleId
, A.ProcurementTypeId
, NULL
, PP.PositionQuantityConfirmed
, PP.Id
, CASE
WHEN @parxSelectedSupplierPriority = 'StandardSupplier' THEN A.StandardSupplierId
ELSE PPPL.PartnerId
END
, NULL
, NULL
, 0
FROM ProductionPosition PP
JOIN ArticleProductionStepComponentType APSCT ON APSCT.Id = PP.ArticleProductionStepComponentTypeId
JOIN Production PR
ON PR.Id = PP.ProductionId
JOIN Article A
ON A.Id = PP.ArticleId
LEFT JOIN ArticleGroup AG
ON AG.Id = A.ArticleGroupId
LEFT JOIN #TopPPPL PPPL
ON PPPL.ArticleId = PP.ArticleId
AND (
(@parxSelectedSupplierPriority = 'FastestSupplier'  AND PPPL.rnTime  = 1)
OR (@parxSelectedSupplierPriority = 'CheapestSupplier' AND PPPL.rnPrice = 1)
)
LEFT JOIN Partner PStandardSupplier
ON PStandardSupplier.Id = A.StandardSupplierId
LEFT JOIN Partner PartnerPPPL
ON PartnerPPPL.Id = PPPL.PartnerId
WHERE PR.ProductionStatusId IN ('open', 'released', 'started', 'parked')
AND PP.RowNumber <> 0
AND PP.PositionQuantityConfirmed > 0
AND APSCT.WarehousingEffective = -1
AND NOT EXISTS (
SELECT 1
FROM ProductionPosition PPProduced
JOIN ArticleProductionStepComponentType APSCTProduced
ON APSCTProduced.Id = PPProduced.ArticleProductionStepComponentTypeId
WHERE PPProduced.ProductionId = PP.ProductionId
AND PPProduced.ArticleId = PP.ArticleId
AND APSCTProduced.WarehousingEffective = 1
AND PPProduced.PositionQuantityConfirmed > 0
)
AND (A.ProcurementTypeId = @parxProcurementTypeId OR A.ProcurementTypeId = 'ask')
AND (@parxSelectedLocation      IS NULL OR PR.LocationId = @parxSelectedLocation)
AND (@parxSelectedFromArticle   IS NULL OR A.Matchcode >= @parxSelectedFromArticle)
AND (@parxSelectedToArticle     IS NULL OR A.Matchcode <= @parxSelectedToArticle)
AND (@SelectedFromArticleGroupName IS NULL OR AG.Name >= @SelectedFromArticleGroupName)
AND (@SelectedToArticleGroupName   IS NULL OR AG.Name <= @SelectedToArticleGroupName)
AND (
(@parxSelectedFromSupplier IS NULL OR @parxSelectedSupplierPriority != 'StandardSupplier')
OR (PStandardSupplier.Matchcode >= @parxSelectedFromSupplier AND @parxSelectedSupplierPriority = 'StandardSupplier')
)
AND (
(@parxSelectedToSupplier IS NULL OR @parxSelectedSupplierPriority != 'StandardSupplier')
OR (PStandardSupplier.Matchcode <= @parxSelectedToSupplier AND @parxSelectedSupplierPriority = 'StandardSupplier')
)
AND (
(@parxSelectedFromSupplier IS NULL OR @parxSelectedSupplierPriority = 'StandardSupplier')
OR (PartnerPPPL.Matchcode >= @parxSelectedFromSupplier AND @parxSelectedSupplierPriority != 'StandardSupplier')
)
AND (
(@parxSelectedToSupplier IS NULL OR @parxSelectedSupplierPriority = 'StandardSupplier')
OR (PartnerPPPL.Matchcode <= @parxSelectedToSupplier AND @parxSelectedSupplierPriority != 'StandardSupplier')
)
AND (@parxSelectedFromProductionNumber IS NULL OR PR.ProductionNumber >= @parxSelectedFromProductionNumber)
AND (@parxSelectedToProductionNumber   IS NULL OR PR.ProductionNumber <= @parxSelectedToProductionNumber)
-- Keine ProductionPositions doppelt in Procurement:
AND NOT EXISTS (
SELECT 1
FROM Procurement P2
WHERE P2.ProductionPositionId = PP.Id
AND P2.ArticleId = PP.ArticleId
);
END
IF OBJECT_ID('tempdb..#TopPPPL') IS NOT NULL DROP TABLE #TopPPPL;
END
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
SET @TransactionSuccess = 0;
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC550_ProcurementWizard ----------------------------------------------------------------------
-- xPROC550_ProcurementWizard_StockQuantityUsed ----------------------------------------------------------------------
-- Purpose: Create Entries in Procurement Table with needed Articles
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 22.) UPDATE Procurement
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC550_ProcurementWizard_StockQuantityUsed
-- 26.06.26 03:46
@parxProcurementId INT
, @parxNewStockQuantityUsed DECIMAL(19,6)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRY
BEGIN TRANSACTION;
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @InvalidValues  TABLE (ProcurementId INT, ArticleId NVARCHAR(30), Text NVARCHAR(100));
DECLARE @ArticleId NVARCHAR(30);
SELECT
@ArticleId = P.ArticleId
FROM dbo.Procurement AS P
WHERE P.Id = @parxProcurementId;
-- 20.) VALIDATION
INSERT INTO @InvalidValues (ProcurementId , ArticleId , TEXT)
SELECT
P.Id
, P.ArticleId
, 'Assigned quantity is higher than confirmed open'
FROM Procurement P
WHERE Id = @parxProcurementId
AND ConfirmedQuantityOpen < (@parxNewStockQuantityUsed + OrderedQuantityUsed + AnnouncedQuantityUsed)
AND OrderConfirmationPositionId IS NOT NULL
INSERT INTO @InvalidValues (ProcurementId , ArticleId , TEXT)
SELECT
P.Id
, P.ArticleId
, 'Assigned quantity is higher than threshold quantity'
FROM Procurement P
WHERE Id = @parxProcurementId
AND ThresholdQuantity < (@parxNewStockQuantityUsed + OrderedQuantityUsed + AnnouncedQuantityUsed)
AND OrderConfirmationPositionId IS NULL
INSERT INTO @InvalidValues (ProcurementId , ArticleId , TEXT)
SELECT
NULL
, P.ArticleId
, 'Assigned stock in all positions is higher than the now available stock'
FROM Procurement P
LEFT JOIN xVIEW124_ArticleQuantityInventorySum AS AQIS ON P.ArticleId = AQIS.ArticleId
WHERE ProductionId IS NULL AND PurchaseOrderPosId IS NULL AND P.ArticleId = @ArticleId
GROUP BY 
 P.ArticleId
, AQIS.NowAvailable
HAVING
COALESCE(AQIS.NowAvailable, 0)
< SUM(
CASE WHEN P.Id = @parxProcurementId
THEN COALESCE(@parxNewStockQuantityUsed, 0)
ELSE COALESCE(P.StockQuantityUsed, 0)
END
);
IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
-- 22.) UPDATE Procurement
UPDATE dbo.Procurement
SET StockQuantityUsed = @parxNewStockQuantityUsed
WHERE Id = @parxProcurementId;
END -- IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
SELECT * FROM @InvalidValues
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
-- END xPROC550_ProcurementWizard_StockQuantityUsed ----------------------------------------------------------------------
