-- xPROC551_ProcurementWizard_CreateOrder ----------------------------------------------------------------------
-- Purpose: Create Production or Purchase Orders from Records in Procurement Table
-- 10.) DECLARE, SELECT, CALCULATE
-- 14.) INSERT Procurements for Used Ordered/Announced Quantity
-- 15.) DELETE Procurements where Suggested Quantities are 0
-- 20.) For ProcurementType = buy
-- 21.) Get all Suppliers
-- 22.) CREATE all Docs
-- 23.) CREATE Doc Positions
-- 24.) UPDATE Procurement
-- 25.) UPDATE Quantities
-- 50.) For ProcurementType = make
-- 51.) CREATE Productions
-- 52.) UPDATE Procurement
-- 53.) UPDATE Quantities
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC551_ProcurementWizard_CreateOrder
-- 26.06.26 03:45
@parxProcurementTypeId NVARCHAR(4)
, @parxCreatedById INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRY
BEGIN TRANSACTION;
-- 10.) DECLARE
DECLARE @ArticleId NVARCHAR(30)
, @DocId INT
, @ProcurementId INT
, @newPositionId INT
, @Price DECIMAL(19,6)
, @DiscountPercent DECIMAL(19,6)
, @NewQuantity DECIMAL(19,6)
, @NewProductionId INT
, @PrevMaxDocId INT
, @PrevMaxDocPositionId INT
, @OrderConfirmationPositionId INT
, @ProductionSubject NVARCHAR(255);
CREATE TABLE #NewProductionResult
(
NewProductionId INT
);
-- 15.) DELETE Procurements where Suggested Quantities are 0
DELETE FROM Procurement
WHERE ProductionId IS NULL
AND PurchaseOrderPosId IS NULL
AND SuggestedQuantity = 0;
-- 20.) For ProcurementType = buy
IF @parxProcurementTypeId = 'buy'
BEGIN
CREATE TABLE #TempSupplierIds
(
SupplierId INT
);
CREATE TABLE #StoredDocIds
(
DocId INT
);
-- 21.) Get all Suppliers
INSERT INTO #TempSupplierIds (
SupplierId
)
SELECT DISTINCT
P.SupplierId
FROM Procurement AS P
WHERE P.ProductionId IS NULL
AND P.PurchaseOrderPosId IS NULL
AND P.SupplierId IS NOT NULL
AND (P.ProcurementTypeId = 'buy' OR P.ProcurementTypeId = 'ask')
AND P.SuggestedQuantity > 0;
-- 22.) CREATE all Docs
DECLARE @SupplierId INT
, @SupplierDetailId INT
, @DocTypeId NVARCHAR(35);
SELECT TOP 1
@SupplierId = SupplierId
FROM #TempSupplierIds
ORDER BY SupplierId;
SELECT TOP 1
@DocTypeId = Id
FROM DocType
WHERE InventoryStatusId = 'ordered'
ORDER BY Id;
WHILE @SupplierId IS NOT NULL
BEGIN
SELECT TOP 1
@SupplierDetailId = Id
FROM PartnerDetail
WHERE PartnerId = @SupplierId
AND PartnerTypeId = 'Supplier'
ORDER BY Id;
SELECT
@PrevMaxDocId = ISNULL(MAX(Id), 0)
FROM Doc;
EXEC dbo.xPROC200N_Doc
@parxDocCategoryId = 'Purchase'
, @parxDocTypeId = @DocTypeId
, @parxPartnerDetailId = @SupplierDetailId
, @parxEmployeeId = @parxCreatedById;
SELECT TOP 1
@DocId = D.Id
FROM Doc AS D
WHERE D.Id > @PrevMaxDocId
AND D.PartnerDetailId = @SupplierDetailId
AND D.DocTypeId = @DocTypeId
AND D.CreatedBy = @parxCreatedById
ORDER BY D.Id ASC;
INSERT INTO #StoredDocIds (
DocId
)
VALUES (
@DocId
);
DELETE FROM #TempSupplierIds
WHERE SupplierId = @SupplierId;
IF EXISTS (
SELECT 1
FROM #TempSupplierIds
)
BEGIN
SELECT TOP 1
@SupplierId = SupplierId
FROM #TempSupplierIds
ORDER BY SupplierId;
END
ELSE
BEGIN
SET @SupplierId = NULL;
END;
END;
DROP TABLE #TempSupplierIds;
-- 23.) CREATE Doc Positions
CREATE TABLE #ProcurementPositions
(
ArticleId NVARCHAR(30)
, DocId INT
, ProcurementId INT
);
INSERT INTO #ProcurementPositions (
ArticleId
, DocId
, ProcurementId
)
SELECT
P.ArticleId
, SD.DocId
, P.Id
FROM #StoredDocIds AS SD
JOIN Doc AS D
ON D.Id = SD.DocId
JOIN Procurement AS P
ON P.SupplierId = D.PartnerId
WHERE P.ProductionId IS NULL
AND P.PurchaseOrderPosId IS NULL
AND P.SupplierId IS NOT NULL
AND (P.ProcurementTypeId = 'buy' OR P.ProcurementTypeId = 'ask')
AND P.SuggestedQuantity > 0;
SELECT TOP 1
@ArticleId = ArticleId
, @DocId = DocId
, @ProcurementId = ProcurementId
FROM #ProcurementPositions
ORDER BY ProcurementId;
WHILE @ProcurementId IS NOT NULL
BEGIN
SELECT
@PrevMaxDocPositionId = ISNULL(MAX(Id), 0)
FROM DocPosition
WHERE DocId = @DocId;
EXEC dbo.xPROC220I_DocPosition_InsertArticle
@parxDocId = @DocId
, @parxArticleId = @ArticleId
, @parxComponentIds = NULL;
SELECT TOP 1
@newPositionId = DP.Id
FROM DocPosition AS DP
WHERE DP.DocId = @DocId
AND DP.Id > @PrevMaxDocPositionId
AND DP.ParentPositionId IS NULL
AND DP.ArticleId = @ArticleId
ORDER BY DP.Id ASC;
-- 24.) UPDATE Procurement
UPDATE Procurement
SET
PurchaseOrderPosId = @newPositionId
WHERE Id = @ProcurementId
AND ProductionId IS NULL
AND PurchaseOrderPosId IS NULL
AND SupplierId IS NOT NULL
AND (ProcurementTypeId = 'buy' OR ProcurementTypeId = 'ask')
AND SuggestedQuantity > 0;
-- 25.) UPDATE Quantities
SELECT
@NewQuantity = SuggestedQuantity
FROM Procurement
WHERE Id = @ProcurementId;
SELECT
@Price = Price
, @DiscountPercent = DiscountPercent
FROM DocPosition
WHERE Id = @newPositionId;
EXEC dbo.xPROC220U_DocPosition_Update
@parxDocPositionId = @newPositionId
, @parxQuantity = @NewQuantity
, @parxPrice = @Price
, @parxDiscountPercent = @DiscountPercent;
UPDATE DP
SET
PredecessorId = P.OrderConfirmationPositionId
FROM DocPosition AS DP
JOIN Procurement AS P
ON P.Id = @ProcurementId
WHERE DP.Id = @newPositionId;
DELETE FROM #ProcurementPositions
WHERE ProcurementId = @ProcurementId;
IF EXISTS (
SELECT 1
FROM #ProcurementPositions
)
BEGIN
SELECT TOP 1
@ArticleId = ArticleId
, @DocId = DocId
, @ProcurementId = ProcurementId
FROM #ProcurementPositions
ORDER BY ProcurementId;
END
ELSE
BEGIN
SET @ProcurementId = NULL;
END;
END;
DROP TABLE #ProcurementPositions;
DROP TABLE #StoredDocIds;
END;
-- 50.) For ProcurementType = make
IF @parxProcurementTypeId = 'make'
BEGIN
CREATE TABLE #TempArticles
(
ArticleId NVARCHAR(30)
, ProcurementId INT
, OrderConfirmationPositionId INT
, ProductionSubject NVARCHAR(255)
);
INSERT INTO #TempArticles (
ArticleId
, ProcurementId
, OrderConfirmationPositionId
, ProductionSubject
)
SELECT
P.ArticleId
, P.Id
, P.OrderConfirmationPositionId
, D.Subject
FROM Procurement AS P
LEFT JOIN DocPosition AS DP
ON DP.Id = P.OrderConfirmationPositionId
LEFT JOIN Doc AS D
ON D.Id = DP.DocId
WHERE P.ProductionId IS NULL
AND P.PurchaseOrderPosId IS NULL
AND (P.ProcurementTypeId = 'make' OR P.ProcurementTypeId = 'ask')
AND P.SuggestedQuantity > 0;
SELECT TOP 1
@ArticleId = ArticleId
, @ProcurementId = ProcurementId
, @OrderConfirmationPositionId = OrderConfirmationPositionId
, @ProductionSubject = ProductionSubject
FROM #TempArticles
ORDER BY ProcurementId;
WHILE @ProcurementId IS NOT NULL
BEGIN
DELETE FROM #NewProductionResult;
-- 51.) CREATE Productions
INSERT INTO #NewProductionResult (
NewProductionId
)
EXEC dbo.xPROC400N_Production
@parxArticleId = @ArticleId
, @parxCreatedById = @parxCreatedById;
SELECT
@NewProductionId = NewProductionId
FROM #NewProductionResult;
UPDATE Production
SET
OrderConfirmationPositionId = @OrderConfirmationPositionId
, Subject = @ProductionSubject
WHERE Id = @NewProductionId;
-- 52.) UPDATE Procurement
UPDATE P
SET
ProductionId = @NewProductionId
FROM Procurement AS P
WHERE P.Id = @ProcurementId
AND P.ProductionId IS NULL
AND P.PurchaseOrderPosId IS NULL
AND (P.ProcurementTypeId = 'make' OR P.ProcurementTypeId = 'ask');
-- 53.) UPDATE Quantities
SELECT
@NewQuantity = SuggestedQuantity
FROM Procurement
WHERE Id = @ProcurementId;
EXEC dbo.xPROC416U_Production_QuantityPlanned
@parxProductionId = @NewProductionId
, @parxQuantityPlanned = @NewQuantity;
DELETE FROM #TempArticles
WHERE ProcurementId = @ProcurementId;
IF EXISTS (
SELECT 1
FROM #TempArticles
)
BEGIN
SELECT TOP 1
@ArticleId = ArticleId
, @ProcurementId = ProcurementId
, @OrderConfirmationPositionId = OrderConfirmationPositionId
, @ProductionSubject = ProductionSubject
FROM #TempArticles
ORDER BY ProcurementId;
END
ELSE
BEGIN
SET @ProcurementId = NULL;
END;
END;
DROP TABLE #TempArticles;
END;
DROP TABLE #NewProductionResult;
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
IF @@TRANCOUNT > 0
BEGIN
ROLLBACK TRANSACTION;
END;
THROW;
END CATCH
END
GO
-- END xPROC551_ProcurementWizard_CreateOrder ----------------------------------------------------------------------
