-- xPROC553_Procurement_CreateProduction ----------------------------------------------------------------------
-- Purpose: Create Production or Purchase Orders from Records in Procurement Table
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT into Procurement
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC553_Procurement_CreateProduction
-- 26.06.26 03:45
@parxPositionId INT
, @parxCreatedById INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRY
BEGIN TRANSACTION;
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @ArticleId NVARCHAR(30)
, @ProcurementTypeId NVARCHAR(4)
, @ConfirmedQuantityOpen DECIMAL(19,6)
, @ProductionSubject NVARCHAR(255)
, @ProcurementId INT
, @NewProductionId INT
, @NewQuantity DECIMAL(19,6);
CREATE TABLE #NewProductionResult
(
NewProductionId INT
);
SELECT
@ArticleId = DP.ArticleId
, @ProcurementTypeId = A.ProcurementTypeId
, @ConfirmedQuantityOpen = DP.QuantityOpen
, @ProductionSubject = D.Subject
FROM DocPosition AS DP
JOIN Article AS A
ON A.Id = DP.ArticleId
LEFT JOIN Doc AS D
ON D.Id = DP.DocId
WHERE DP.Id = @parxPositionId;
-- 20.) INSERT into Procurement for the passed Position
INSERT INTO Procurement (
ArticleId
, ProcurementTypeId
, OrderConfirmationPositionId
, ConfirmedQuantityOpen
, SupplierId
, PurchaseOrderPosId
, Info
, StockQuantityUsed
)
VALUES (
@ArticleId
, @ProcurementTypeId
, @parxPositionId
, @ConfirmedQuantityOpen
, NULL
, NULL
, NULL
, 0
);
SET @ProcurementId = SCOPE_IDENTITY();
-- 50.) CREATE Production (call xPROC400N_Production)
INSERT INTO #NewProductionResult (
NewProductionId
)
EXEC dbo.xPROC400N_Production
@parxArticleId = @ArticleId
, @parxCreatedById = @parxCreatedById;
SELECT
@NewProductionId = NewProductionId
FROM #NewProductionResult;
UPDATE Production
SET
OrderConfirmationPositionId = @parxPositionId
, Subject = @ProductionSubject
WHERE Id = @NewProductionId;
-- 52.) UPDATE Procurement with the new ProductionId
UPDATE P
SET
ProductionId = @NewProductionId
FROM Procurement AS P
WHERE P.Id = @ProcurementId
AND P.ProductionId IS NULL
AND P.PurchaseOrderPosId IS NULL;
-- 53.) UPDATE Quantities (call xPROC416U_Production_QuantityPlanned)
SELECT
@NewQuantity = SuggestedQuantity
FROM Procurement
WHERE Id = @ProcurementId;
EXEC dbo.xPROC416U_Production_QuantityPlanned
@parxProductionId = @NewProductionId
, @parxQuantityPlanned = @NewQuantity;
DROP TABLE #NewProductionResult;
-- 90.) RETURN
SELECT @NewProductionId AS NewProductionId;
COMMIT TRANSACTION;
END TRY
-- 91.) ERROR HANDLING
BEGIN CATCH
IF @@TRANCOUNT > 0
BEGIN
ROLLBACK TRANSACTION;
END;
THROW;
END CATCH
END
GO
-- END xPROC553_Procurement_CreateProduction ----------------------------------------------------------------------
