CREATE OR ALTER PROCEDURE 
xPROC600U_FinancePostingDraft_ReceiptNumber
-- PURPOSE: Update the ReceiptNumber with passed value and call CheckValidity Procedure
-- 26.06.26
@parxFinancePostingDraftId INT,
@parxReceiptNumber nvarchar(50)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE FinancePostingDraft SET ReceiptNumber = @parxReceiptNumber WHERE Id = @parxFinancePostingDraftId ;
EXEC [xPROC603_FinancePostingPositionDraft_CheckValidity] @parxFinancePostingDraftId
SELECT FBD.StatusId FROM FinancePostingDraft FBD WHERE FBD.Id = @parxFinancePostingDraftId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
