--xPROC602I_FinancePostingPositionDraft_PersonalAccount--------------------------------------
-- PURPOSE: Insert Position for Partner and call CheckValidity Procedure
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT INTO FinancePostingPositionDraft
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC602I_FinancePostingPositionDraft_PersonalAccount
@parxFinancePostingDraftId INT,
@parxPartnerDetailId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @calxPositionNumber INT
SELECT
@calxPositionNumber = ISNULL(MAX(Position), 0) + 1
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId 
DECLARE @TotalDebit DECIMAL(19, 6) = 0
DECLARE @TotalForeignCurrencyDebit DECIMAL(19, 6) = 0
SELECT 
@TotalDebit =  ISNULL(SUM(Debit),0)
, @TotalForeignCurrencyDebit =  ISNULL(SUM(ForeignCurrencyDebit),0)
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId 
GROUP BY PostingId
DECLARE @TotalCredit DECIMAL(19, 6) = 0
DECLARE @TotalForeignCurrencyCredit DECIMAL(19, 6) = 0
SELECT 
@TotalCredit =  ISNULL(SUM(Credit),0)
, @TotalForeignCurrencyCredit =  ISNULL(SUM(ForeignCurrencyCredit),0)
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId 
GROUP BY PostingId
DECLARE @ForeignCurrencyId NVARCHAR(3)
DECLARE @Rate DECIMAL(19, 6) = 0
SELECT 
@ForeignCurrencyId =  ForeignCurrencyId 
, @Rate =  Rate
FROM FinancePostingDraft
WHERE Id = @parxFinancePostingDraftId 
-- 20.) INSERT INTO FinancePostingPositionDraft
INSERT INTO FinancePostingPositionDraft
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, PartnerDetailId
, BusinessPartnerNumber 
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, Archived
)
SELECT
@parxFinancePostingDraftId 
, @calxPositionNumber 
, NULL
, 'new'
, NULL
, FGP.CollectiveAccountId
, CASE WHEN PD.PartnerTypeId = 'Customer' THEN 2 ELSE 3 END
, P.Matchcode
, NULL
,  CASE WHEN @TotalCredit - @TotalDebit > 0 THEN @TotalCredit - @TotalDebit ELSE 0 END
,  CASE WHEN @TotalDebit - @TotalCredit > 0 THEN @TotalDebit - @TotalCredit ELSE 0 END
, NULL
, PD.Id
, PD.Id
, 0
, NULL
, NULL
, NULL
, 0
, PD.CostCenterId
, NULL
,  CASE WHEN @TotalCredit - @TotalDebit > 0 THEN @TotalCredit - @TotalDebit ELSE 0 END - CASE WHEN @TotalDebit - @TotalCredit > 0 THEN @TotalDebit - @TotalCredit ELSE 0 END
, PBA.VatNumber
, NULL
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit > 0 THEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit > 0 THEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit > 0 THEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit ELSE 0 END - CASE WHEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit > 0 THEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit ELSE 0 END ELSE NULL END
, 0
FROM PartnerDetail PD
LEFT JOIN Partner P ON P.Id = PD.PartnerId
LEFT JOIN FinanceGroupPartner FGP ON FGP.Id = PD.FinanceGroupPartnerDetailId
LEFT JOIN PartnerBillingAddress PBA ON PBA.Id = PD.StandardBillingAddressId
WHERE PD.Id = @parxPartnerDetailId
EXEC [xPROC603_FinancePostingPositionDraft_CheckValidity] @parxFinancePostingDraftId
SELECT * FROM FinancePostingPositionDraft WHERE PostingId = @parxFinancePostingDraftId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
-- END xPROC602I_FinancePostingPositionDraft_PersonalAccount------------------------------------
--xPROC602I_FinancePostingPositionDraft_GeneralLedgerAccount--------------------------------------
-- PURPOSE: Insert Position for Account and call CheckValidity Procedure
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT INTO FinancePostingPositionDraft First Position
-- 30.) INSERT INTO FinancePostingPositionDraft Second Position
-- 40.) INSERT INTO FinancePostingPositionDraft Third Position
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC602I_FinancePostingPositionDraft_GeneralLedgerAccount
@parxFinancePostingDraftId INT,
@parxFinanceAccountPlanId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @calxPositionNumber INT
SELECT
@calxPositionNumber = ISNULL(MAX(Position), 0) + 1
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId 
DECLARE @TotalDebit DECIMAL(19,6) = 0
DECLARE @TotalForeignCurrencyDebit DECIMAL(19, 6) = 0
SELECT 
@TotalDebit = ISNULL(SUM(Debit),0)
, @TotalForeignCurrencyDebit =  ISNULL(SUM(ForeignCurrencyDebit),0)
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId 
GROUP BY PostingId
SET @TotalDebit = CASE WHEN @TotalDebit IS NULL THEN 0 ELSE @TotalDebit END
DECLARE @TotalCredit DECIMAL(19,6) = 0
DECLARE @TotalForeignCurrencyCredit DECIMAL(19, 6) = 0
SELECT 
@TotalCredit =  ISNULL(SUM(Credit),0)
, @TotalForeignCurrencyCredit =  ISNULL(SUM(ForeignCurrencyCredit),0)
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId 
GROUP BY PostingId
SET @TotalCredit = CASE WHEN @TotalCredit IS NULL THEN 0 ELSE @TotalCredit END
DECLARE @ForeignCurrencyId NVARCHAR(3)
DECLARE @Rate DECIMAL(19, 6) = 0
SELECT 
@ForeignCurrencyId =  ForeignCurrencyId 
, @Rate =  Rate
FROM FinancePostingDraft
WHERE Id = @parxFinancePostingDraftId 
-- 20.) INSERT INTO FinancePostingPositionDraft First Position
INSERT INTO FinancePostingPositionDraft
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, PartnerDetailId
, BusinessPartnerNumber
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
)
SELECT
@parxFinancePostingDraftId 
, @calxPositionNumber 
, NULL
, 'new'
, NULL
, FAP.Id
, 1
, FAP.Name
, NULL
, CASE WHEN @TotalCredit - @TotalDebit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalCredit - @TotalDebit) * 100/(100+FTKD.TaxPercent),2) ELSE @TotalCredit - @TotalDebit END ELSE 0 END
, CASE WHEN @TotalDebit - @TotalCredit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalDebit - @TotalCredit ) * 100/(100+FTKD.TaxPercent),2) ELSE @TotalDebit - @TotalCredit  END ELSE 0 END
, NULL
, NULL
, NULL
, 0
, NULL
, FAP.TaxKeyId
, FTKD.TaxPercent
,CASE WHEN FTK.Id IS NOT NULL THEN CASE WHEN @TotalCredit - @TotalDebit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalCredit - @TotalDebit) - (@TotalCredit - @TotalDebit) * 100/(100+FTKD.TaxPercent),2) ELSE ROUND((@TotalCredit - @TotalDebit) * (FTKD.TaxPercent/100), 2) END WHEN @TotalDebit - @TotalCredit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalDebit - @TotalCredit ) - (@TotalDebit - @TotalCredit ) * 100/(100+FTKD.TaxPercent),2) ELSE ROUND((@TotalDebit - @TotalCredit) * (FTKD.TaxPercent/100), 2)  END ELSE 0 END ELSE 0 END
, FAP.CostCenterId
, FAP.CostBearerId
, CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND(@TotalDebit * 100/(100+FTKD.TaxPercent),2) ELSE @TotalDebit END - CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND(@TotalCredit * 100/(100+FTKD.TaxPercent),2) ELSE @TotalCredit END
, NULL
, NULL
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit) * 100/(100+FTKD.TaxPercent),2) ELSE @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit END ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit ) * 100/(100+FTKD.TaxPercent),2) ELSE @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit  END ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND(@TotalForeignCurrencyDebit * 100/(100+FTKD.TaxPercent),2) ELSE @TotalForeignCurrencyDebit END - CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND(@TotalForeignCurrencyCredit * 100/(100+FTKD.TaxPercent),2) ELSE @TotalForeignCurrencyCredit END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTK.Id IS NOT NULL THEN CASE WHEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit) - (@TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit) * 100/(100+FTKD.TaxPercent),2) ELSE ROUND((@TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit) * (FTKD.TaxPercent/100), 2) END WHEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit > 0 THEN CASE WHEN FTK.TaxKeyKindId = 1 OR FTK.TaxKeyKindId = 2 THEN ROUND((@TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit ) - (@TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit ) * 100/(100+FTKD.TaxPercent),2) ELSE ROUND((@TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit) * (FTKD.TaxPercent/100), 2)  END ELSE 0 END ELSE 0 END ELSE NULL END
, 0
FROM FinanceAccountPlan FAP
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = @parxFinancePostingDraftId 
LEFT JOIN FinanceTaxKeyDetail FTKD ON FAP.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
WHERE FAP.Id = @parxFinanceAccountPlanId 
AND (FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
) OR FAP.TaxKeyId IS NULL);
DECLARE @newxMainPositionId INT = SCOPE_IDENTITY();
-- 30.) INSERT INTO FinancePostingPositionDraft Second Position
INSERT INTO FinancePostingPositionDraft
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, PartnerDetailId
, BusinessPartnerNumber
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
)
SELECT
@parxFinancePostingDraftId 
, @calxPositionNumber + 1
, @newxMainPositionId
, 'new'
, NULL
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FTKD.TaxAccountId ELSE FTKD.NotDueAccountId END
, 1
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FAPT.Name ELSE FAPN.Name END
, NULL
, CASE WHEN FTK.TaxKeyKindId = 3 AND @TotalDebit - @TotalCredit > 0 THEN ROUND(FBPD.Credit * FTKD.TaxPercent/100,2) WHEN @TotalCredit - @TotalDebit> 0 THEN @TotalCredit - @TotalDebit - FBPD.Debit ELSE 0 END
, CASE WHEN FTK.TaxKeyKindId = 3 AND @TotalCredit - @TotalDebit > 0 THEN ROUND(FBPD.Debit * FTKD.TaxPercent/100,2)  WHEN @TotalDebit - @TotalCredit > 0 THEN @TotalDebit - @TotalCredit - FBPD.Credit ELSE 0 END
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, 0
, 0
, FAP.CostCenterId
, FAP.CostBearerId
, CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(@TotalCredit * FTKD.TaxPercent/100,2) ELSE @TotalDebit - FBPD.Debit END - CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(@TotalDebit * FTKD.TaxPercent/100,2) ELSE @TotalCredit - FBPD.Credit END
, NULL
, NULL
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTK.TaxKeyKindId = 3 AND @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit > 0 THEN ROUND(FBPD.ForeignCurrencyCredit * FTKD.TaxPercent/100,2) WHEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit> 0 THEN @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit - FBPD.ForeignCurrencyDebit ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTK.TaxKeyKindId = 3 AND @TotalForeignCurrencyCredit - @TotalForeignCurrencyDebit > 0 THEN ROUND(FBPD.ForeignCurrencyDebit * FTKD.TaxPercent/100,2)  WHEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit > 0 THEN @TotalForeignCurrencyDebit - @TotalForeignCurrencyCredit - FBPD.ForeignCurrencyCredit ELSE 0 END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(@TotalForeignCurrencyCredit * FTKD.TaxPercent/100,2) ELSE @TotalForeignCurrencyDebit - FBPD.ForeignCurrencyDebit END - CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(@TotalForeignCurrencyDebit * FTKD.TaxPercent/100,2) ELSE @TotalForeignCurrencyCredit - FBPD.ForeignCurrencyCredit END ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, 0
FROM FinanceAccountPlan FAP
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = @parxFinancePostingDraftId 
LEFT JOIN FinanceTaxKeyDetail FTKD ON FAP.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
LEFT JOIN FinancePostingPositionDraft FBPD ON FBPD.Id = @newxMainPositionId
WHERE FAP.Id = @parxFinanceAccountPlanId AND FBPD.TaxKeyId IS NOT NULL
AND FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
);
-- 40.) INSERT INTO FinancePostingPositionDraft Third Position
INSERT INTO FinancePostingPositionDraft
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, PartnerDetailId
, BusinessPartnerNumber
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
)
SELECT
@parxFinancePostingDraftId 
, @calxPositionNumber + 2
, @newxMainPositionId
, 'new'
, NULL
, FTKD.TaxAccountId
, 1
, FAPT.Name
, NULL
, ROUND(FBPD.Debit * FTKD.TaxPercent/100,2)
, ROUND(FBPD.Credit * FTKD.TaxPercent/100,2)
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, 0
, 0
, FAP.CostCenterId
, FAP.CostBearerId
, ROUND(@TotalDebit * FTKD.TaxPercent/100,2) - ROUND(@TotalCredit * FTKD.TaxPercent/100,2)
, NULL
, NULL
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN ROUND(FBPD.ForeignCurrencyDebit * FTKD.TaxPercent/100,2) ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN ROUND(FBPD.ForeignCurrencyCredit * FTKD.TaxPercent/100,2) ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN ROUND(@TotalForeignCurrencyDebit * FTKD.TaxPercent/100,2) - ROUND(@TotalForeignCurrencyCredit * FTKD.TaxPercent/100,2) ELSE NULL END
, CASE WHEN @ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, 0
FROM FinanceAccountPlan FAP
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = @parxFinancePostingDraftId 
LEFT JOIN FinanceTaxKeyDetail FTKD ON FAP.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
LEFT JOIN FinancePostingPositionDraft FBPD ON FBPD.Id = @newxMainPositionId
WHERE FAP.Id = @parxFinanceAccountPlanId AND FTK.TaxKeyKindId = 3
AND FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
);
EXEC [xPROC603_FinancePostingPositionDraft_CheckValidity] @parxFinancePostingDraftId
SELECT * FROM FinancePostingPositionDraft WHERE PostingId = @parxFinancePostingDraftId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
