CREATE OR ALTER PROCEDURE 
xPROC602D_FinancePostingPositionDraft
@parxFinancePostingPositionDraftId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @FinancePostingDraftId INT
SELECT
@FinancePostingDraftId = PostingId
FROM FinancePostingPositionDraft
WHERE Id = @parxFinancePostingPositionDraftId 
-- 20.) DELETE Child Positions
