-------------------------------------------------------------------------------------------------------------
@parxFinancePostingPositionDraftId INT,
@parxForeignCurrencyGrossValue DECIMAL(19,6)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @FinancePostingDraftId INT
DECLARE @parxFinancePostingDraftId INT
SELECT
@FinancePostingDraftId = PostingId
FROM FinancePostingPositionDraft
WHERE Id = @parxFinancePostingPositionDraftId 
SET @parxFinancePostingDraftId = @FinancePostingDraftId
-- 20.) UPDATE Main Position
UPDATE FBPD
SET 
GrossValue = @parxForeignCurrencyGrossValue / COALESCE(NULLIF(FBD.Rate, 0), 1)
, ForeignCurrencyGrossValue = @parxForeignCurrencyGrossValue
, Debit = CASE WHEN ISNULL(FBPD.ForeignCurrencyDebit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyCredit, 0) = 0 AND FAP.DebitSide = 1) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue  / COALESCE(NULLIF(FBD.Rate, 0), 1)
ELSE 
ROUND(@parxForeignCurrencyGrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0))  / COALESCE(NULLIF(FBD.Rate, 0), 1), 2)
END
ELSE 0 END
, ForeignCurrencyDebit = CASE WHEN ISNULL(FBPD.ForeignCurrencyDebit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyCredit, 0) = 0 AND FAP.DebitSide = 1) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue
ELSE 
ROUND(@parxForeignCurrencyGrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
, Credit = CASE WHEN ISNULL(FBPD.ForeignCurrencyCredit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyDebit, 0) = 0 AND FAP.DebitSide = 0) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue  / COALESCE(NULLIF(FBD.Rate, 0), 1)
ELSE 
ROUND(@parxForeignCurrencyGrossValue* 100/(100+ISNULL(FTKD.TaxPercent,0)) / COALESCE(NULLIF(FBD.Rate, 0), 1) ,2)
END
ELSE 0 END
, ForeignCurrencyCredit = CASE WHEN ISNULL(FBPD.ForeignCurrencyCredit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyDebit, 0) = 0 AND FAP.DebitSide = 0) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue
ELSE 
ROUND(@parxForeignCurrencyGrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
, OpenAmount = 
CASE WHEN ISNULL(FBPD.ForeignCurrencyDebit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyCredit, 0) = 0 AND FAP.DebitSide = 1) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue  / COALESCE(NULLIF(FBD.Rate, 0), 1)
ELSE 
ROUND(@parxForeignCurrencyGrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0))  / COALESCE(NULLIF(FBD.Rate, 0), 1),2)
END
ELSE 0 END
- CASE WHEN ISNULL(FBPD.ForeignCurrencyCredit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyDebit, 0) = 0 AND FAP.DebitSide = 0) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue  / COALESCE(NULLIF(FBD.Rate, 0), 1)
ELSE 
ROUND(@parxForeignCurrencyGrossValue* 100/(100+ISNULL(FTKD.TaxPercent,0)) / COALESCE(NULLIF(FBD.Rate, 0), 1) ,2)
END
ELSE 0 END
, ForeignCurrencyOpenAmount = 
CASE WHEN ISNULL(FBPD.ForeignCurrencyDebit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyCredit, 0) = 0 AND FAP.DebitSide = 1) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue
ELSE 
ROUND(@parxForeignCurrencyGrossValue* 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
- CASE WHEN ISNULL(FBPD.ForeignCurrencyCredit, 0) > 0 OR (ISNULL(FBPD.ForeignCurrencyDebit, 0) = 0 AND FAP.DebitSide = 0) THEN
CASE WHEN FBPD.TaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
@parxForeignCurrencyGrossValue
ELSE 
ROUND(@parxForeignCurrencyGrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
, TaxAmount = CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(@parxForeignCurrencyGrossValue * ISNULL(FTKD.TaxPercent,0)/100 / COALESCE(NULLIF(FBD.Rate, 0), 1) ,2)
WHEN FTK.TaxKeyKindId IS NOT NULL THEN ROUND((@parxForeignCurrencyGrossValue - @parxForeignCurrencyGrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0))) / COALESCE(NULLIF(FBD.Rate, 0), 1) ,2)
ELSE 0 END
, ForeignCurrencyTaxAmount = CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(@parxForeignCurrencyGrossValue * ISNULL(FTKD.TaxPercent,0)/100,2)
WHEN FTK.TaxKeyKindId IS NOT NULL THEN @parxForeignCurrencyGrossValue - ROUND(@parxForeignCurrencyGrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
ELSE 0 END
FROM FinancePostingPositionDraft FBPD
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = FBPD.PostingId 
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FBPD.AccountId AND FBPD.PostingPositionAccountTypeId = 1
LEFT JOIN FinanceTaxKeyDetail FTKD ON FBPD.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
WHERE FBPD.Id = @parxFinancePostingPositionDraftId
-- 30.) UPDATE Sub Position 1
UPDATE FBPD
SET 
Debit = CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ParentFBPD.Credit * ISNULL(FTKD.TaxPercent,0)/100,2)
WHEN ParentFBPD.Debit != 0 THEN
ParentFBPD.GrossValue - ParentFBPD.Debit
ELSE 0
END
, ForeignCurrencyDebit= CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ISNULL(ParentFBPD.ForeignCurrencyCredit, 0) * ISNULL(FTKD.TaxPercent,0)/100,2)
WHEN ISNULL(ParentFBPD.ForeignCurrencyDebit, 0) != 0 THEN
ParentFBPD.ForeignCurrencyGrossValue - ISNULL(ParentFBPD.ForeignCurrencyDebit, 0)
ELSE 0
END
, Credit = CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ParentFBPD.Debit * ISNULL(FTKD.TaxPercent,0)/100,2)
WHEN ParentFBPD.Credit != 0 THEN
ParentFBPD.GrossValue - ParentFBPD.Credit
ELSE 0
END
, ForeignCurrencyCredit = CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ISNULL(ParentFBPD.ForeignCurrencyDebit, 0) * ISNULL(FTKD.TaxPercent,0)/100,2)
WHEN ISNULL(ParentFBPD.ForeignCurrencyCredit, 0) != 0 THEN
ParentFBPD.ForeignCurrencyGrossValue - ISNULL(ParentFBPD.ForeignCurrencyCredit, 0)
ELSE 0
END
, OpenAmount = 
CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ParentFBPD.Credit * ISNULL(FTKD.TaxPercent,0)/100,2)
ELSE 
ParentFBPD.GrossValue - ParentFBPD.Debit
END
- CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ParentFBPD.Debit * ISNULL(FTKD.TaxPercent,0)/100,2)
ELSE 
ParentFBPD.GrossValue - ParentFBPD.Credit
END
, ForeignCurrencyOpenAmount = 
CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ISNULL(ParentFBPD.ForeignCurrencyCredit, 0) * ISNULL(FTKD.TaxPercent,0)/100,2)
ELSE 
ParentFBPD.ForeignCurrencyGrossValue - ISNULL(ParentFBPD.ForeignCurrencyDebit, 0)
END
- CASE WHEN FTK.TaxKeyKindId = 3 THEN
ROUND(ISNULL(ParentFBPD.ForeignCurrencyDebit, 0) * ISNULL(FTKD.TaxPercent,0)/100,2)
ELSE 
ParentFBPD.ForeignCurrencyGrossValue - ISNULL(ParentFBPD.ForeignCurrencyCredit, 0)
END
FROM FinancePostingPositionDraft FBPD
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = FBPD.PostingId 
LEFT JOIN FinancePostingPositionDraft ParentFBPD ON ParentFBPD.Id = @parxFinancePostingPositionDraftId
LEFT JOIN FinanceTaxKeyDetail FTKD ON ParentFBPD.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
WHERE FBPD.ParentPosition = @parxFinancePostingPositionDraftId AND FBPD.Position = ParentFBPD.Position + 1
-- 40.) UPDATE Sub Position 2
UPDATE FBPD
SET 
Debit = ROUND(ParentFBPD.Debit * FTKD.TaxPercent/100,2)
, ForeignCurrencyDebit = ROUND(ISNULL(ParentFBPD.ForeignCurrencyDebit, 0) * FTKD.TaxPercent/100,2)
, Credit = ROUND(ParentFBPD.Credit* FTKD.TaxPercent/100,2)
, ForeignCurrencyCredit = ROUND(ISNULL(ParentFBPD.ForeignCurrencyCredit, 0) * FTKD.TaxPercent/100,2)
, OpenAmount = ROUND(ParentFBPD.Debit * FTKD.TaxPercent/100,2) - ROUND(ParentFBPD.Credit* FTKD.TaxPercent/100,2)
, ForeignCurrencyOpenAmount = ROUND(ISNULL(ParentFBPD.ForeignCurrencyDebit, 0) * FTKD.TaxPercent/100,2) - ROUND(ISNULL(ParentFBPD.ForeignCurrencyCredit, 0) * FTKD.TaxPercent/100,2)
FROM FinancePostingPositionDraft FBPD
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = FBPD.PostingId 
LEFT JOIN FinancePostingPositionDraft ParentFBPD ON ParentFBPD.Id = @parxFinancePostingPositionDraftId
LEFT JOIN FinanceTaxKeyDetail FTKD ON ParentFBPD.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
WHERE FBPD.ParentPosition = @parxFinancePostingPositionDraftId AND FBPD.Position = ParentFBPD.Position + 2
EXEC [xPROC603_FinancePostingPositionDraft_CheckValidity] @parxFinancePostingDraftId
