CREATE OR ALTER PROCEDURE 
xPROC602U_FinancePostingPositionDraft_TaxKeyId
-- 26.06.26 03:46
-- PURPOSE: Update the TaxKeyId with passed value and calculate Position and Children Values
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 15.) DELETE all children
-- 17.) UPDATE Position Numbers
-- 20.) UPDATE Main Position
-- 30.) INSERT Sub Position 1
-- 40.) INSERT Sub Position 2
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxFinancePostingPositionDraftId INT,
@parxTaxKeyId NVARCHAR(3)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @FinancePostingDraftId INT
DECLARE @Position INT
DECLARE @parxFinancePostingDraftId INT
SELECT
@FinancePostingDraftId = PostingId
, @Position =  Position
FROM FinancePostingPositionDraft
WHERE Id = @parxFinancePostingPositionDraftId 
SET @parxFinancePostingDraftId = @FinancePostingDraftId
DECLARE @PositionDifference INT = 0
SELECT
@PositionDifference = COUNT(*)
FROM FinancePostingPositionDraft
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= @parxTaxKeyId
WHERE ParentPosition = @parxFinancePostingPositionDraftId 
SELECT
@PositionDifference = (ISNULL(@PositionDifference, 0) * -1) + CASE WHEN FTK.TaxKeyKindId IS NULL THEN 0 WHEN FTK.TaxKeyKindId = 3 THEN 2 ELSE 1 END
FROM FinanceTaxKey FTK
WHERE FTK.Id= @parxTaxKeyId
-- 15.) DELETE all children
DELETE FROM FinancePostingPositionDraft
WHERE ParentPosition = @parxFinancePostingPositionDraftId 
-- 17.) UPDATE Position Numbers
UPDATE FinancePostingPositionDraft
SET Position = Position + @PositionDifference
WHERE PostingId = @FinancePostingDraftId AND Position > @Position
-- 20.) UPDATE Main Position
UPDATE FinancePostingPositionDraft
SET
TaxKeyId = @parxTaxKeyId
, TaxPercent = FTKD.TaxPercent
, TaxAmount = CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(FBPD.GrossValue * ISNULL(FTKD.TaxPercent,0)/100, 2)WHEN FTK.TaxKeyKindId IS NOT NULL THEN FBPD.GrossValue - ROUND(FBPD.GrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)ELSE 0 END
, Debit = CASE WHEN FBPD.Debit > 0 OR (FBPD.Credit = 0 AND FAP.DebitSide = 1) THEN
CASE WHEN @parxTaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
FBPD.GrossValue
ELSE 
ROUND(FBPD.GrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
, Credit = CASE WHEN FBPD.Credit > 0 OR (FBPD.Debit = 0 AND FAP.DebitSide = 0) THEN
CASE WHEN @parxTaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
FBPD.GrossValue
ELSE 
ROUND(FBPD.GrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
, OpenAmount = 
CASE WHEN FBPD.Debit > 0 OR (FBPD.Credit = 0 AND (FAP.DebitSide = 1 OR FAP.DebitSide IS NULL)) THEN
CASE WHEN @parxTaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
FBPD.GrossValue
ELSE 
ROUND(FBPD.GrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
- CASE WHEN FBPD.Credit > 0 OR (FBPD.Debit = 0 AND FAP.DebitSide = 0) THEN
CASE WHEN @parxTaxKeyId IS NULL OR FTK.TaxKeyKindId = 3 THEN
FBPD.GrossValue
ELSE 
ROUND(FBPD.GrossValue * 100/(100+ISNULL(FTKD.TaxPercent,0)),2)
END
ELSE 0 END
FROM FinancePostingPositionDraft FBPD
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = FBPD.PostingId 
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FBPD.AccountId AND FBPD.PostingPositionAccountTypeId = 1
LEFT JOIN FinanceTaxKeyDetail FTKD ON @parxTaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
WHERE FBPD.Id = @parxFinancePostingPositionDraftId 
AND (FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
) OR @parxTaxKeyId IS NULL);
-- 30.) INSERT Sub Position 1
INSERT INTO FinancePostingPositionDraft
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, PartnerDetailId
, BusinessPartnerNumber
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, Archived
)
SELECT
@FinancePostingDraftId 
, @Position + 1
, @parxFinancePostingPositionDraftId
, 'new'
, NULL
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FTKD.TaxAccountId ELSE FTKD.NotDueAccountId END
, 1
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FAPT.Name ELSE FAPN.Name END
, NULL
, CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(FBPD.Credit * FTKD.TaxPercent/100,2) WHEN  FBPD.Debit != 0 THEN FBPD.GrossValue - FBPD.Debit ELSE 0 END
, CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(FBPD.Debit * FTKD.TaxPercent/100,2)  WHEN  FBPD.Credit  != 0 THEN FBPD.GrossValue - FBPD.Credit ELSE 0 END
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, 0
, 0
, FAP.CostCenterId
, FAP.CostBearerId
, CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(FBPD.Credit * FTKD.TaxPercent/100,2) WHEN  FBPD.Debit != 0 THEN FBPD.GrossValue - FBPD.Debit ELSE 0 END - CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(FBPD.Debit * FTKD.TaxPercent/100,2)  WHEN  FBPD.Credit  != 0 THEN FBPD.GrossValue - FBPD.Credit ELSE 0 END
, NULL
, NULL
, 0
FROM FinanceAccountPlan FAP
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = @FinancePostingDraftId 
LEFT JOIN FinanceTaxKeyDetail FTKD ON @parxTaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
LEFT JOIN FinancePostingPositionDraft FBPD ON FBPD.Id = @parxFinancePostingPositionDraftId
WHERE FAP.Id = FBPD.AccountId AND FBPD.TaxKeyId IS NOT NULL
AND FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
);
-- 40.) INSERT Sub Position 2
INSERT INTO FinancePostingPositionDraft
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, PartnerDetailId
, BusinessPartnerNumber
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, Archived
)
SELECT
@FinancePostingDraftId 
, @Position + 2
, @parxFinancePostingPositionDraftId
, 'new'
, NULL
, FTKD.TaxAccountId
, 1
, FAPT.Name
, NULL
, ROUND(FBPD.Debit * FTKD.TaxPercent/100,2)
, ROUND(FBPD.Credit * FTKD.TaxPercent/100,2)
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, 0
, 0
, FAP.CostCenterId
, FAP.CostBearerId
, ROUND(FBPD.Debit * FTKD.TaxPercent/100,2) - ROUND(FBPD.Credit * FTKD.TaxPercent/100,2)
, NULL
, NULL
, 0
FROM FinanceAccountPlan FAP
LEFT JOIN FinancePostingDraft FBD ON FBD.Id = @FinancePostingDraftId 
LEFT JOIN FinanceTaxKeyDetail FTKD ON @parxTaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
LEFT JOIN FinancePostingPositionDraft FBPD ON FBPD.Id = @parxFinancePostingPositionDraftId
WHERE FAP.Id = FBPD.AccountId AND FTK.TaxKeyKindId = 3
AND FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FBD.ReceiptDate
);
EXEC [xPROC603_FinancePostingPositionDraft_CheckValidity] @parxFinancePostingDraftId
-- 90.) RETURN
SELECT * FROM FinancePostingPositionDraft WHERE PostingId = @FinancePostingDraftId 
