CREATE OR ALTER PROCEDURE 
xPROC603_FinancePostingPositionDraft_CheckValidity
-- 26.06.26 03:45
-- PURPOSE: Check Validity if Draft could be posted
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxFinancePostingDraftId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE FinancePostingDraft
SET StatusId =
CASE
WHEN EXISTS (
SELECT 1
FROM FinancePostingDraft
WHERE Id = @parxFinancePostingDraftId
AND ISNULL(ReceiptNumber, '') <> ''
AND ISNULL(DocNumber, '') <> ''
AND ReceiptDate IS NOT NULL
AND PostingPeriodId IS NOT NULL
AND ISNULL(Subject, '') <> ''
)
AND EXISTS (
SELECT 1
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId
GROUP BY PostingId
HAVING SUM(ISNULL(Debit, 0)) = SUM(ISNULL(Credit, 0))
AND SUM(ISNULL(ForeignCurrencyDebit, 0)) = SUM(ISNULL(ForeignCurrencyCredit, 0))
AND SUM(ISNULL(Debit, 0)) <> 0
)
THEN 'valid'
ELSE 'new'
END
WHERE Id = @parxFinancePostingDraftId;
-- 91.) ERROR HANDLING
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
-- END xPROC603_FinancePostingPositionDraft_CheckValidity ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-- xPROC603_FinancePostingDraft_Posting
-- Creator: MH
-- Created: 2024-08-08
-- Purpose: Create a OpenItem Record for this posted Posting
-- Changed:
-- 30.) INSERT INTO FinancePosting
-- 50.) INSERT INTO FinancePostingPositions
-- 80.) CREATE FinanceOpenItem
-- 85.) UPDATE FinanceAccountPlan Balance
-- 86.) UPDATE PartnerDetail Balance
-- 87.) COPY Attachment to FinancePosting
-- 88.) COPY AttachmentFile to FinancePosting
-- 89.) UPDATE FinancePostingDraft
-- 90.) RETURN
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC603_FinancePostingDraft_Posting
@parxFinancePostingDraftId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 30.) INSERT INTO FinancePosting
DECLARE @NewPostingId INT;
DECLARE @NewAttachmentId INT;
INSERT INTO FinancePosting
(
Name
, DocNumber
, StatusId
, ReversalReferenceId
, PostingTemplateId
, DateCreated
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, BatchNumber
, SourceId
, Reversible
, FixedAssetId
, ForeignCurrencyId
, Rate
, CreatedBy
, ExportDate
)
-- VALUES FinancePosting
SELECT
Name
, DocNumber
, StatusId
, ReversalReferenceId
, PostingTemplateId
, DateCreated
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, BatchNumber
, 'manually'
, Reversible
, FixedAssetId
, ForeignCurrencyId
, Rate
, CreatedBy
, ExportDate
FROM FinancePostingDraft
WHERE Id = @parxFinancePostingDraftId
SET @NewPostingId = SCOPE_IDENTITY();
-- 50.) CREATE FinancePostingPositions
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
)
SELECT
@NewPostingId 
, Position
, ParentPosition
, 'valid'
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, CASE
WHEN Credit != 0 THEN
(SELECT TOP 1 AccountId FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId AND Debit != 0
ORDER BY Position ASC)
ELSE
(SELECT TOP 1 AccountId FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId AND Credit != 0
ORDER BY Position ASC)
END AS ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, CASE WHEN TaxKeyId IS NOT NULL THEN TaxPercent ELSE NULL END
, TaxAmount
, CostCenterId
, CostBearerId
, Debit - Credit
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
FROM FinancePostingPositionDraft
WHERE PostingId = @parxFinancePostingDraftId
-- 80.) CREATE FinanceOpenItem
IF EXISTS ( SELECT 1 FROM FinancePostingPosition WHERE PostingId = @NewPostingId AND PostingPositionAccountTypeId IN (2, 3) )
BEGIN
INSERT INTO FinanceOpenItem (
StatusId
, OpenItemOriginId
, OpenItemTypeId
, DocTypeId
, PartnerTypeId
, PartnerId
, PartnerDetailId
, PostingId 
, PostingDate
, DocDate
, DocNumber
, Amount
, ForeignCurrencyId
, Rate
, Discountable
, DueDate
, CashDiscountDate1
, CashDiscountPercentage1
, CashDiscountDate2
, CashDiscountPercentage2
, CashDiscountAmount
, OpenAmount
, Remark1
, Remark2
, ReferenceDoc
, ContraAccountId
, CostCenterId
, CostBearerId
, DunningBlock
, PaymentBlock
, DunningLevelId
, TaxSplit
, DocSplit
, TermsOfPaymentId
, Archived
, ProbabilityOfPayment
, ForeignCurrencyAmount
, ForeignCurrencyCashDiscountAmount
, ForeignCurrencyOpenAmount
)
SELECT
'open'
, 'Posting'
, CASE WHEN FBP.PostingPositionAccountTypeId = 2 AND FBP.Debit = 0 THEN 'CD' WHEN FBP.PostingPositionAccountTypeId = 2 AND FBP.Credit = 0 THEN 'CW' WHEN FBP.PostingPositionAccountTypeId = 3 AND FBP.Debit = 0 THEN 'SD' WHEN FBP.PostingPositionAccountTypeId = 3 AND FBP.Credit = 0 THEN 'SW'ELSE 'ERROR' END
, NULL
, CASE WHEN FBP.PostingPositionAccountTypeId = 2 THEN 'Customer' ELSE 'Supplier' END
, PD.PartnerId
, FBP.PartnerDetailId
, @NewPostingId
, GETDATE()
, FB.ReceiptDate
, FB.ReceiptNumber
, (FBP.Debit + FBP.Credit) * CASE WHEN (FBP.PostingPositionAccountTypeId = 2 AND FBP.Credit != 0) OR  (FBP.PostingPositionAccountTypeId = 3 AND FBP.Credit != 0) THEN -1 ELSE 1 END
, CASE WHEN FB.ForeignCurrencyId IS NOT NULL THEN FB.ForeignCurrencyId ELSE NULL END
, FB.Rate
, 1
, FB.ReceiptDate
, NULL
, NULL
, NULL
, NULL
, 0
, (FBP.Debit + FBP.Credit) * CASE WHEN (FBP.PostingPositionAccountTypeId = 2 AND FBP.Credit != 0) OR  (FBP.PostingPositionAccountTypeId = 3 AND FBP.Credit != 0) THEN -1 ELSE 1 END
, FB.Subject
, NULL
, FB.DocNumber
, FBP.ContraAccountId
, FBP.CostCenterId
, FBP.CostBearerId
, 0
, 0
, NULL
, NULL
, NULL
, NULL
, 0
, 100
, CASE WHEN FB.ForeignCurrencyId IS NOT NULL THEN (FBP.ForeignCurrencyDebit + FBP.ForeignCurrencyCredit) * CASE WHEN (FBP.PostingPositionAccountTypeId = 2 AND FBP.ForeignCurrencyCredit != 0) OR  (FBP.PostingPositionAccountTypeId = 3 AND FBP.ForeignCurrencyCredit != 0) THEN -1 ELSE 1 END ELSE NULL END
, CASE WHEN FB.ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN FB.ForeignCurrencyId IS NOT NULL THEN (FBP.ForeignCurrencyDebit + FBP.ForeignCurrencyCredit) * CASE WHEN (FBP.PostingPositionAccountTypeId = 2 AND FBP.ForeignCurrencyCredit != 0) OR  (FBP.PostingPositionAccountTypeId = 3 AND FBP.ForeignCurrencyCredit != 0) THEN -1 ELSE 1 END ELSE NULL END
FROM FinancePosting FB
LEFT JOIN FinancePostingPosition FBP ON FB.Id= FBP.PostingId AND (FBP.PostingPositionAccountTypeId = 2 OR FBP.PostingPositionAccountTypeId = 3) 
LEFT JOIN PartnerDetail PD ON PD.Id= FBP.PartnerDetailId
WHERE FB.Id= @NewPostingId;
END
-- 85.) UPDATE FinanceAccountPlan Balance
UPDATE FAP SET
FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, FAP.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL THEN ISNULL(FAP.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT AccountId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition
WHERE PostingId = @NewPostingId
GROUP BY AccountId 
) AS FBP ON FBP.AccountId = FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 86.) UPDATE PartnerDetail Balance
UPDATE PD SET
PD.Balance = PD.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, PD.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL THEN ISNULL(PD.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM PartnerDetail PD
INNER JOIN (
SELECT PartnerDetailId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition
WHERE PostingId = @NewPostingId
GROUP BY PartnerDetailId
) AS FBP ON FBP.PartnerDetailId = PD.Id
WHERE FBP.PartnerDetailId IS NOT NULL;
-- 87.) COPY Attachment to FinancePosting
DECLARE @AttachmentMap TABLE
(
OldAttachmentId int NOT NULL
, NewAttachmentId int NOT NULL
);
MERGE dbo.Attachment AS T
USING
(
SELECT
A.Id OldAttachmentId
, A.Info
, A.FollowUp
, A.AttachmentStatusId
, A.Description
FROM dbo.Attachment A
WHERE A.EntityType = 'FinancePostingDraft'
AND A.EntityId = @parxFinancePostingDraftId
) AS S
ON 1 = 0
WHEN NOT MATCHED THEN
INSERT
(
EntityType
, EntityId
, Info
, FollowUp
, AttachmentStatusId
, Description
, DateCreated
)
VALUES
(
'FinancePosting'
, @NewPostingId
, S.Info
, S.FollowUp
, S.AttachmentStatusId
, S.Description
, sysutcdatetime()
)
OUTPUT
S.OldAttachmentId
, inserted.Id
INTO @AttachmentMap
(
OldAttachmentId
, NewAttachmentId
);
-- 88.) COPY AttachmentFile to FinancePosting
INSERT INTO AttachmentFile(
AttachmentId
, ComputerFile
, Tags
, FileName
, ContentType
, Link
)
SELECT
M.NewAttachmentId
, ComputerFile
, Tags
, FileName
, ContentType
, Link
FROM AttachmentFile AF
JOIN @AttachmentMap M ON M.OldAttachmentId = AF.AttachmentId;
-- 89.) UPDATE FinancePostingDraft
UPDATE FinancePostingDraft SET
StatusId = 'posted'
WHERE Id = @parxFinancePostingDraftId
-- 90.) RETURN
SELECT @NewPostingId NewFinancePostingId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC603_FinancePostingDraft_Posting---------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC604_FinancePosting_Reversal
-------------------------------------------------------------------------------------------------------------
-- xPROC604_FinancePosting_Reversal
-- PURPOSE: Create Reversal Posting and set Status to reversed
-- 26.06.26 03:45
-------------------------------------------------------------------------------------------------------------
@parPostingId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @NewPostingId INT;
DECLARE @CurrentPostingPeriod INT 
DECLARE @NextOpenPostingPeriod INT 
SELECT
@CurrentPostingPeriod = PostingPeriodId
FROM FinancePosting FB
WHERE FB.Id = @parPostingId;
SELECT @NextOpenPostingPeriod = dbo.xFUNCTION003_GetNextOpenPostingPeriodId(@CurrentPostingPeriod);
-- Create a new Copy of the Posting and set the status to 'Reversal'
INSERT INTO FinancePosting (
[Name]
,DocNumber
,StatusId
,ReversalReferenceId
,PostingTemplateId
,DateCreated
,ReceiptNumber
,ReceiptDate
,PostingPeriodId
,Subject
,BatchNumber
,[SourceId]
, ForeignCurrencyId
, Rate
,CreatedBy
)
-- Select Data
SELECT FB.Name
, DocNumber
, 'Reversal'
,@parPostingId
,PostingTemplateId
,DateCreated
,ReceiptNumber
,ReceiptDate
,@NextOpenPostingPeriod
,CONCAT(FBS.Name, ' ', CAST((FB.Id) AS NVARCHAR(10)))
,BatchNumber
,[SourceId]
, ForeignCurrencyId
, Rate
,CreatedBy
FROM FinancePosting FB
LEFT JOIN FinancePostingStatus FBS ON FBS.Id = 'Reversal'
WHERE FB.Id = @parPostingId;
-- Get the ID of the new Posting
SET @NewPostingId = SCOPE_IDENTITY();
-- OLD Posting: Set the ReversalReferenceId to the ID of the new Posting and the status to 'reversed'
UPDATE FinancePosting
SET ReversalReferenceId = @NewPostingId
,StatusId = 'reversed'
WHERE Id = @parPostingId;
-- NEW PostingPosition: Copy old PostingPositions and multiply the debit and credit values by -1
INSERT INTO FinancePostingPosition (
PostingId
,Position
,ParentPosition
,StatusId
,ReversalReferencePositionId
,AccountId 
,AccountName
,OpenItemId
,Debit
,Credit
,ContraAccountId
,GrossValue
,DivergentPerformanceDate
,TaxKeyId
,TaxPercent
,TaxAmount
,CostCenterId
,CostBearerId
,OpenAmount
,VatNumber
,ProjectId
,Archived
,PostingPositionAccountTypeId
,PartnerDetailId
, [BusinessPartnerNumber]
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyGrossValue
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
)
-- NEW PostingPosition: Select Data
SELECT @NewPostingId
,Position
,ParentPosition
,'Reversal'
,Id
,AccountId 
,AccountName
,OpenItemId
,Debit * - 1
,Credit * - 1
,ContraAccountId
,GrossValue * - 1
,DivergentPerformanceDate
,TaxKeyId
,TaxPercent
,TaxAmount * - 1
,CostCenterId
,CostBearerId
,Debit * - 1 - Credit * - 1
,VatNumber
,ProjectId
,Archived
,PostingPositionAccountTypeId
,PartnerDetailId
, [BusinessPartnerNumber]
, ForeignCurrencyDebit * - 1
, ForeignCurrencyCredit * - 1
, ForeignCurrencyGrossValue * - 1
, ForeignCurrencyDebit * - 1 - ForeignCurrencyCredit * - 1
, ForeignCurrencyTaxAmount * - 1
FROM FinancePostingPosition
WHERE PostingId = @parPostingId;
-- UPDATE OLD PostingPosition : Set the ReversalReferenceId to the ID of the new Posting and the status to 'reversed'
UPDATE FinancePostingPosition
SET ReversalReferencePositionId = new.Id
,StatusId = 'reversed'
FROM
FinancePostingPosition old
INNER JOIN (SELECT Position, Id FROM FinancePostingPosition WHERE PostingId = @NewPostingId) new
ON old.Position = new.Position
WHERE PostingId = @parPostingId;
IF EXISTS ( SELECT 1 FROM FinancePostingPosition WHERE PostingId = @NewPostingId AND PostingPositionAccountTypeId IN (2, 3) )
BEGIN
INSERT INTO FinanceOpenItem (
StatusId
, OpenItemOriginId
, OpenItemTypeId
, DocTypeId
, PartnerTypeId
, PartnerId
, PartnerDetailId
, PostingId 
, PostingDate
, DocDate
, DocNumber
, Amount
, ForeignCurrencyId 
, Rate
, Discountable
, DueDate
, CashDiscountDate1
, CashDiscountPercentage1
, CashDiscountDate2
, CashDiscountPercentage2
, CashDiscountAmount
, OpenAmount
, Remark1
, Remark2
, ReferenceDoc
, ContraAccountId
, CostCenterId
, CostBearerId
, DunningBlock
, PaymentBlock
, DunningLevelId
, TaxSplit
, DocSplit
, TermsOfPaymentId
, Archived
, ProbabilityOfPayment
, ForeignCurrencyAmount
, ForeignCurrencyCashDiscountAmount
, ForeignCurrencyOpenAmount
)
SELECT
'open'
, 'Posting'
, CASE WHEN FBP.PostingPositionAccountTypeId = 2 AND FBP.Credit = 0 THEN 'CD' WHEN FBP.PostingPositionAccountTypeId = 2 AND FBP.Debit = 0 THEN 'CW' WHEN FBP.PostingPositionAccountTypeId = 3 AND FBP.Credit= 0 THEN 'SD' WHEN FBP.PostingPositionAccountTypeId = 3 AND FBP.Debit= 0 THEN 'SW'ELSE 'ERROR' END
, NULL
, CASE WHEN FBP.PostingPositionAccountTypeId = 2 THEN 'Customer' ELSE 'Supplier' END
, PD.PartnerId
, FBP.PartnerDetailId
, @NewPostingId 
, GETDATE()
, FB.ReceiptDate
, FB.DocNumber
, (FBP.Debit + FBP.Credit) * CASE WHEN FBP.Debit  != 0 THEN 1 ELSE -1 END
, FB.ForeignCurrencyId 
, FB.Rate
, 1
, GETDATE()
, NULL
, NULL
, NULL
, NULL
, 0
, (FBP.Debit + FBP.Credit) * CASE WHEN FBP.Debit != 0 THEN 1 ELSE -1 END
, FB.Subject
, NULL
, FB.DocNumber
, FBP.ContraAccountId
, FBP.CostCenterId
, FBP.CostBearerId
, 0
, 0
, NULL
, NULL
, NULL
, NULL
, 0
, 100
, CASE WHEN FB.ForeignCurrencyId IS NOT NULL THEN (FBP.ForeignCurrencyDebit + FBP.ForeignCurrencyCredit) * CASE WHEN FBP.ForeignCurrencyCredit != 0 THEN -1 ELSE 1 END ELSE NULL END
, CASE WHEN FB.ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, CASE WHEN FB.ForeignCurrencyId IS NOT NULL THEN (FBP.ForeignCurrencyDebit + FBP.ForeignCurrencyCredit) * CASE WHEN FBP.ForeignCurrencyCredit != 0 THEN -1 ELSE 1 END ELSE NULL END
FROM FinancePosting FB
LEFT JOIN FinancePostingPosition FBP ON FB.Id= FBP.PostingId AND (FBP.PostingPositionAccountTypeId = 2 OR FBP.PostingPositionAccountTypeId = 3) 
LEFT JOIN PartnerDetail PD ON PD.Id= FBP.PartnerDetailId
WHERE FB.Id= @NewPostingId;
END
-- 85.) UPDATE FinanceAccountPlan Balance
UPDATE FAP
SET FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, FAP.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL
THEN ISNULL(FAP.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0)
ELSE NULL END
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT AccountId , SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit
, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition
WHERE PostingId = @NewPostingId
GROUP BY AccountId 
) AS FBP ON FBP.AccountId = FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 86.) UPDATE PartnerDetail Balance
UPDATE PD
SET PD.Balance = PD.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, PD.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL
THEN ISNULL(PD.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0)
ELSE NULL END
FROM PartnerDetail PD
INNER JOIN (
SELECT PartnerDetailId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit
, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition
WHERE PostingId = @NewPostingId
GROUP BY PartnerDetailId
) AS FBP ON FBP.PartnerDetailId = PD.Id
WHERE FBP.PartnerDetailId IS NOT NULL;
SELECT * FROM FinancePosting WHERE Id = @parPostingId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC604_FinancePosting_Reversal------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC605N_FinanceTransfer
