CREATE OR ALTER PROCEDURE
xPROC605_FinanceTransferPosition_CsvImport
-------------------------------------------------------------------------------------------------------------
-- xPROC605_FinanceTransferPosition_CsvImport
-- PURPOSE: Insert Positions from passed csv file
-- 26.06.26 03:46
-------------------------------------------------------------------------------------------------------------
@parxFinanceTransferId INT,
@CsvContent NVARCHAR(MAX)
AS
BEGIN
SET NOCOUNT ON;
DECLARE @ForeignCurrencyId NVARCHAR(3);
DECLARE @FormatNameId      NVARCHAR(20);
SELECT
@ForeignCurrencyId = ForeignCurrencyId,
@FormatNameId      = ISNULL(MappingFormatNameId, N'StarMoney')
FROM dbo.FinanceTransfer
WHERE Id = @parxFinanceTransferId;
DECLARE @ColStatementDate    INT, @ColAmount         INT, @ColBalance      INT;
DECLARE @ColName             INT, @ColCategoryName   INT, @ColMessageID    INT;
DECLARE @ColTextKeyId        INT, @ColSubject        INT;
DECLARE @ColMemo1            INT, @ColMemo2          INT, @ColMemo3        INT;
DECLARE @ColMemo4            INT, @ColMemo5          INT, @ColMemo6        INT;
DECLARE @ColMemo7            INT, @ColMemo8          INT, @ColMemo9        INT;
DECLARE @ColMemo10           INT, @ColMemo11         INT, @ColMemo12       INT;
DECLARE @ColMemo13           INT, @ColMemo14         INT;
DECLARE @ColValueDate        INT, @ColEndToEndId     INT;
DECLARE @ColEntryReference   INT, @ColTransactionType INT, @ColDebitSide   INT;
DECLARE @MappingCount        INT;
DECLARE @SignAmount          INT;
DECLARE @SignBalance         INT;
DECLARE @SignTextKeyId       INT;
SELECT
@ColStatementDate   = MAX(CASE WHEN SystemColumnId = N'StatementDate'   THEN TRY_CAST(SourceTag AS INT) END),
@ColAmount          = MAX(CASE WHEN SystemColumnId = N'Amount'          THEN TRY_CAST(SourceTag AS INT) END),
@ColBalance         = MAX(CASE WHEN SystemColumnId = N'Balance'         THEN TRY_CAST(SourceTag AS INT) END),
@ColName            = MAX(CASE WHEN SystemColumnId = N'Name'            THEN TRY_CAST(SourceTag AS INT) END),
@ColCategoryName    = MAX(CASE WHEN SystemColumnId = N'CategoryName'    THEN TRY_CAST(SourceTag AS INT) END),
@ColMessageID       = MAX(CASE WHEN SystemColumnId = N'MessageID'       THEN TRY_CAST(SourceTag AS INT) END),
@ColTextKeyId       = MAX(CASE WHEN SystemColumnId = N'TextKeyId'       THEN TRY_CAST(SourceTag AS INT) END),
@ColSubject         = MAX(CASE WHEN SystemColumnId = N'Subject'         THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo1           = MAX(CASE WHEN SystemColumnId = N'Memo1'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo2           = MAX(CASE WHEN SystemColumnId = N'Memo2'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo3           = MAX(CASE WHEN SystemColumnId = N'Memo3'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo4           = MAX(CASE WHEN SystemColumnId = N'Memo4'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo5           = MAX(CASE WHEN SystemColumnId = N'Memo5'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo6           = MAX(CASE WHEN SystemColumnId = N'Memo6'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo7           = MAX(CASE WHEN SystemColumnId = N'Memo7'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo8           = MAX(CASE WHEN SystemColumnId = N'Memo8'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo9           = MAX(CASE WHEN SystemColumnId = N'Memo9'           THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo10          = MAX(CASE WHEN SystemColumnId = N'Memo10'          THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo11          = MAX(CASE WHEN SystemColumnId = N'Memo11'          THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo12          = MAX(CASE WHEN SystemColumnId = N'Memo12'          THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo13          = MAX(CASE WHEN SystemColumnId = N'Memo13'          THEN TRY_CAST(SourceTag AS INT) END),
@ColMemo14          = MAX(CASE WHEN SystemColumnId = N'Memo14'          THEN TRY_CAST(SourceTag AS INT) END),
@ColValueDate       = MAX(CASE WHEN SystemColumnId = N'ValueDate'       THEN TRY_CAST(SourceTag AS INT) END),
@ColEndToEndId      = MAX(CASE WHEN SystemColumnId = N'EndToEndId'      THEN TRY_CAST(SourceTag AS INT) END),
@ColEntryReference  = MAX(CASE WHEN SystemColumnId = N'EntryReference'  THEN TRY_CAST(SourceTag AS INT) END),
@ColTransactionType = MAX(CASE WHEN SystemColumnId = N'TransactionType' THEN TRY_CAST(SourceTag AS INT) END),
@ColDebitSide       = MAX(CASE WHEN SystemColumnId = N'DebitSide'       THEN TRY_CAST(SourceTag AS INT) END),
@SignAmount         = ISNULL(MAX(CASE WHEN SystemColumnId = N'Amount'    AND TransformationRule = N'MULTIPLYWITHMINUS1' THEN -1 END), 1),
@SignBalance        = ISNULL(MAX(CASE WHEN SystemColumnId = N'Balance'   AND TransformationRule = N'MULTIPLYWITHMINUS1' THEN -1 END), 1),
@SignTextKeyId      = ISNULL(MAX(CASE WHEN SystemColumnId = N'TextKeyId' AND TransformationRule = N'MULTIPLYWITHMINUS1' THEN -1 END), 1),
@MappingCount       = COUNT(1)
FROM dbo.SystemMapping
WHERE FormatNameId = @FormatNameId;
IF ISNULL(@MappingCount, 0) = 0
BEGIN
DECLARE @ErrMsg NVARCHAR(500) = N'No CSV column mapping configured for format ''' + @FormatNameId + N'''. Please configure the mapping in System > Mappings.';
RAISERROR(@ErrMsg, 16, 1);
RETURN;
END
BEGIN TRANSACTION
BEGIN TRY
DECLARE @RowDelimiter       NVARCHAR(2) = NULL;
DECLARE @ColumnDelimiter    NVARCHAR(1) = NULL;
DECLARE @HeaderRow          NVARCHAR(MAX);
DECLARE @Semicolon          NCHAR(1) = NCHAR(59);
DECLARE @Comma              NCHAR(1) = NCHAR(44);
DECLARE @PipeChar           NCHAR(1) = NCHAR(124);
DECLARE @RowDataCount       INT = 0;
DECLARE @DataRowCount       INT = 0;
DECLARE @ParsedRowCount     INT = 0;
DECLARE @InsertedRowCount   INT = 0;
DECLARE @DelimiterLabel     NVARCHAR(20) = N'';
DECLARE @HeaderPreview      NVARCHAR(150) = N'';
DECLARE @DiagnosticMessage  NVARCHAR(2000);
DECLARE @InlineRowSplitUsed BIT = 0;
DECLARE @ScanPos            INT;
DECLARE @PrevChar           NCHAR(1);
DECLARE @DetectedDateStart  BIT;
SET @RowDelimiter = CASE
WHEN CHARINDEX(CHAR(13) + CHAR(10), @CsvContent) > 0 THEN CHAR(13) + CHAR(10)
WHEN CHARINDEX(CHAR(10), @CsvContent) > 0             THEN CHAR(10)
WHEN CHARINDEX(CHAR(13), @CsvContent) > 0             THEN CHAR(13)
ELSE CHAR(10)
END;
DECLARE @ModifiedCsv NVARCHAR(MAX);
SET @ModifiedCsv = REPLACE(REPLACE(REPLACE(@CsvContent, CHAR(13) + CHAR(10), @PipeChar), CHAR(10), @PipeChar), CHAR(13), @PipeChar);
SET @ModifiedCsv = REPLACE(REPLACE(REPLACE(REPLACE(@ModifiedCsv, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss');
IF CHARINDEX(@PipeChar, @ModifiedCsv) = 0
BEGIN
SET @ScanPos = 2;
WHILE @ScanPos <= LEN(@ModifiedCsv) - 10
BEGIN
SET @DetectedDateStart = 0;
IF SUBSTRING(@ModifiedCsv, @ScanPos, 1) LIKE N'[0-3]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 1, 1) LIKE N'[0-9]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 2, 1) = N'/'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 3, 1) LIKE N'[0-1]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 4, 1) LIKE N'[0-9]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 5, 1) = N'/'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 6, 1) LIKE N'[1-2]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 7, 1) LIKE N'[0-9]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 8, 1) LIKE N'[0-9]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 9, 1) LIKE N'[0-9]'
AND SUBSTRING(@ModifiedCsv, @ScanPos + 10, 1) = N','
BEGIN
SET @PrevChar = SUBSTRING(@ModifiedCsv, @ScanPos - 1, 1);
IF @PrevChar = N' ' OR @PrevChar = NCHAR(9)
BEGIN
SET @ModifiedCsv = STUFF(@ModifiedCsv, @ScanPos - 1, 1, @PipeChar);
SET @InlineRowSplitUsed = 1;
SET @DetectedDateStart = 1;
END
ELSE IF @PrevChar <> @PipeChar AND @PrevChar <> N'/'
BEGIN
SET @ModifiedCsv = STUFF(@ModifiedCsv, @ScanPos, 0, @PipeChar);
SET @InlineRowSplitUsed = 1;
SET @DetectedDateStart = 1;
END
END;
SET @ScanPos = @ScanPos + CASE WHEN @DetectedDateStart = 1 THEN 11 ELSE 1 END;
END;
END;
DECLARE @RowData TABLE (
RowNumber   INT IDENTITY(1, 1),
RowContent  NVARCHAR(MAX)
);
INSERT INTO @RowData (RowContent)
SELECT value FROM STRING_SPLIT(@ModifiedCsv, @PipeChar)
WHERE value <> SPACE(0);
SELECT @RowDataCount = COUNT(1)
FROM @RowData;
SELECT @HeaderRow = RowContent
FROM @RowData
WHERE RowNumber = 1;
SET @HeaderPreview = LEFT(ISNULL(@HeaderRow, N''), 150);
SET @ColumnDelimiter = CASE
WHEN @HeaderRow IS NULL THEN @Semicolon
WHEN LEN(@HeaderRow) - LEN(REPLACE(@HeaderRow, @Semicolon, SPACE(0))) > LEN(@HeaderRow) - LEN(REPLACE(@HeaderRow, @Comma, SPACE(0))) THEN @Semicolon
WHEN LEN(@HeaderRow) - LEN(REPLACE(@HeaderRow, @Comma, SPACE(0))) > 0 THEN @Comma
ELSE @Semicolon
END;
SET @DelimiterLabel = CASE
WHEN @ColumnDelimiter = @Semicolon THEN N'semicolon'
WHEN @ColumnDelimiter = @Comma THEN N'comma'
ELSE N'unknown'
END;
CREATE TABLE #ParsedData (
RowNumber    INT,
ColumnNumber INT,
ColumnValue  NVARCHAR(MAX)
);
DECLARE @CurrentRow    NVARCHAR(MAX);
DECLARE @RowNumber     INT = 2;
DECLARE @CurrentPos    INT;
DECLARE @FieldStart    INT;
DECLARE @ColumnNumber  INT;
DECLARE @InQuotes      BIT;
DECLARE @CurrentChar   NCHAR(1);
DECLARE @NextChar      NCHAR(1);
WHILE EXISTS (SELECT 1 FROM @RowData WHERE RowNumber = @RowNumber)
BEGIN
SELECT @CurrentRow = RowContent FROM @RowData WHERE RowNumber = @RowNumber;
SET @CurrentPos = 1;
SET @FieldStart = 1;
SET @ColumnNumber = 1;
SET @InQuotes = 0;
WHILE @CurrentPos <= LEN(@CurrentRow)
BEGIN
SET @CurrentChar = SUBSTRING(@CurrentRow, @CurrentPos, 1);
SET @NextChar = CASE WHEN @CurrentPos < LEN(@CurrentRow) THEN SUBSTRING(@CurrentRow, @CurrentPos + 1, 1) ELSE NCHAR(0) END;
IF @CurrentChar = NCHAR(34)
BEGIN
IF @InQuotes = 1 AND @NextChar = NCHAR(34)
SET @CurrentPos = @CurrentPos + 1;
ELSE
SET @InQuotes = CASE WHEN @InQuotes = 1 THEN 0 ELSE 1 END;
END
ELSE IF @CurrentChar = @ColumnDelimiter AND @InQuotes = 0
BEGIN
INSERT INTO #ParsedData (RowNumber, ColumnNumber, ColumnValue)
VALUES (@RowNumber, @ColumnNumber, SUBSTRING(@CurrentRow, @FieldStart, @CurrentPos - @FieldStart));
SET @FieldStart = @CurrentPos + 1;
SET @ColumnNumber = @ColumnNumber + 1;
END;
SET @CurrentPos = @CurrentPos + 1;
END;
INSERT INTO #ParsedData (RowNumber, ColumnNumber, ColumnValue)
VALUES (@RowNumber, @ColumnNumber, CASE WHEN LEN(@CurrentRow) = 0 THEN SPACE(0) ELSE SUBSTRING(@CurrentRow, @FieldStart, LEN(@CurrentRow) - @FieldStart + 1) END);
SET @RowNumber = @RowNumber + 1;
END;
SELECT @DataRowCount = COUNT(1) FROM @RowData WHERE RowNumber >= 2;
SELECT @ParsedRowCount = COUNT(DISTINCT RowNumber) FROM #ParsedData;
INSERT INTO dbo.FinanceTransferPosition (
TransferId, Position, PostingPeriodId,
Amount, Balance,
StatementDate, [Name], CategoryName, MessageID,
ForeignCurrencyAmount, Rate,
TextKeyId, Subject,
Memo1,  Memo2,  Memo3,  Memo4,  Memo5,  Memo6,  Memo7,
Memo8,  Memo9,  Memo10, Memo11, Memo12, Memo13, Memo14,
ValueDate, EndToEndId, EntryReference, TransactionType, DebitSide
)
SELECT
r.TransferId,
r.Position,
r.PostingPeriodId,
CASE WHEN @ForeignCurrencyId IS NULL THEN r.Amount ELSE ROUND(r.Amount * ISNULL(ACR.Rate, 0), 2) END,
r.Balance,
r.StatementDate,
r.[Name],
r.CategoryName,
r.MessageID,
CASE WHEN @ForeignCurrencyId IS NULL THEN NULL ELSE r.Amount END,
ISNULL(ACR.Rate, 0),
r.TextKeyId,
r.Subject,
r.Memo1,  r.Memo2,  r.Memo3,  r.Memo4,  r.Memo5,  r.Memo6,  r.Memo7,
r.Memo8,  r.Memo9,  r.Memo10, r.Memo11, r.Memo12, r.Memo13, r.Memo14,
r.ValueDate,
r.EndToEndId,
r.EntryReference,
r.TransactionType,
r.DebitSide
FROM (
SELECT
@parxFinanceTransferId AS TransferId,
ROW_NUMBER() OVER (ORDER BY RowNumber) AS Position,
MAX(CASE WHEN ColumnNumber = @ColStatementDate THEN TRY_CAST(CONVERT(DATE, REPLACE(REPLACE(TRIM('"' FROM ColumnValue), '/', '.'), '-', '.'), 104) AS DATE) END) AS StatementDate,
MAX(CASE WHEN ColumnNumber = @ColStatementDate THEN dbo.xFUNCTION002_GetPostingPeriodIdByDate(TRY_CAST(CONVERT(DATE, REPLACE(REPLACE(TRIM('"' FROM ColumnValue), '/', '.'), '-', '.'), 104) AS DATE)) END) AS PostingPeriodId,
MAX(CASE WHEN ColumnNumber = @ColAmount THEN TRY_CAST(REPLACE(REPLACE(TRIM('"' FROM ColumnValue), '.', ''), ',', '.') AS DECIMAL(19, 6)) END) * @SignAmount AS Amount,
MAX(CASE WHEN ColumnNumber = @ColBalance THEN TRY_CAST(REPLACE(REPLACE(TRIM('"' FROM ColumnValue), '.', ''), ',', '.') AS DECIMAL(19, 6)) END) * @SignBalance AS Balance,
LEFT(MAX(CASE WHEN ColumnNumber = @ColName THEN TRIM('"' FROM ColumnValue) END), 35) AS [Name],
LEFT(MAX(CASE WHEN ColumnNumber = @ColCategoryName THEN TRIM('"' FROM ColumnValue) END), 255) AS CategoryName,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMessageID THEN TRIM('"' FROM ColumnValue) END), 255) AS MessageID,
MAX(CASE WHEN ColumnNumber = @ColTextKeyId THEN TRY_CAST(TRIM('"' FROM ColumnValue) AS INT) END) * @SignTextKeyId AS TextKeyId,
LEFT(MAX(CASE WHEN ColumnNumber = @ColSubject THEN TRIM('"' FROM ColumnValue) END), 255) AS Subject,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo1 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo1,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo2 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo2,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo3 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo3,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo4 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo4,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo5 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo5,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo6 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo6,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo7 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo7,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo8 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo8,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo9 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo9,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo10 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo10,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo11 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo11,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo12 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo12,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo13 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo13,
LEFT(MAX(CASE WHEN ColumnNumber = @ColMemo14 THEN TRIM('"' FROM ColumnValue) END), 255) AS Memo14,
MAX(CASE WHEN ColumnNumber = @ColValueDate THEN TRY_CAST(CONVERT(DATE, REPLACE(REPLACE(TRIM('"' FROM ColumnValue), '/', '.'), '-', '.'), 104) AS DATE) END) AS ValueDate,
LEFT(MAX(CASE WHEN ColumnNumber = @ColEndToEndId THEN TRIM('"' FROM ColumnValue) END), 35) AS EndToEndId,
ISNULL(LEFT(MAX(CASE WHEN ColumnNumber = @ColEntryReference THEN TRIM('"' FROM ColumnValue) END), 50), N'') AS EntryReference,
ISNULL(LEFT(MAX(CASE WHEN ColumnNumber = @ColTransactionType THEN TRIM('"' FROM ColumnValue) END), 10), N'') AS TransactionType,
CAST(ISNULL(MAX(CASE WHEN ColumnNumber = @ColDebitSide THEN TRY_CAST(TRIM('"' FROM ColumnValue) AS INT) END), 0) AS BIT) AS DebitSide
FROM #ParsedData
GROUP BY RowNumber
) AS r
LEFT JOIN dbo.AdminCurrencyRate ACR
ON ACR.ForeignCurrencyId = @ForeignCurrencyId
AND ACR.RateDate = r.StatementDate;
SET @InsertedRowCount = @@ROWCOUNT;
IF ISNULL(@InsertedRowCount, 0) = 0
BEGIN
SET @DiagnosticMessage = N'CSV import diagnostics: FormatNameId=' + ISNULL(@FormatNameId, N'<NULL>') +
N'; MappingCount=' + CONVERT(NVARCHAR(20), ISNULL(@MappingCount, 0)) +
N'; DetectedDelimiter=' + @DelimiterLabel +
N'; InlineRowSplitUsed=' + CONVERT(NVARCHAR(1), @InlineRowSplitUsed) +
N'; RowDataCount=' + CONVERT(NVARCHAR(20), ISNULL(@RowDataCount, 0)) +
N'; DataRowCount=' + CONVERT(NVARCHAR(20), ISNULL(@DataRowCount, 0)) +
N'; ParsedRowCount=' + CONVERT(NVARCHAR(20), ISNULL(@ParsedRowCount, 0)) +
N'; ColStatementDate=' + ISNULL(CONVERT(NVARCHAR(20), @ColStatementDate), N'NULL') +
N'; ColSubject=' + ISNULL(CONVERT(NVARCHAR(20), @ColSubject), N'NULL') +
N'; ColAmount=' + ISNULL(CONVERT(NVARCHAR(20), @ColAmount), N'NULL') +
N'; Header=' + ISNULL(@HeaderPreview, N'<NULL>');
RAISERROR(@DiagnosticMessage, 16, 1);
RETURN;
END;
DROP TABLE #ParsedData;
PRINT 'CSV data processed successfully.';
COMMIT;
END TRY
BEGIN CATCH
IF OBJECT_ID(N'tempdb..#ParsedData') IS NOT NULL DROP TABLE #ParsedData;
ROLLBACK;
THROW;
END CATCH
END;
GO
--- END xPROC605_FinanceTransferPosition_CsvImport--------------------------------------------------------------------------
