CREATE OR ALTER PROCEDURE
xPROC605_FinanceTransferPosition_CamtImport
-------------------------------------------------------------------------------------------------------------
--xPROC605_FinanceTransferPosition_CamtImport
-- PURPOSE: Insert Positions from passed xml file
-- 26.06.26 03:45
-------------------------------------------------------------------------------------------------------------
@parxFinanceTransferId INT,
@XMLContent XML
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
DECLARE @ReceiptNumber NVARCHAR(50), @ReceiptDate DATETIMEOFFSET;
DECLARE @BeginningBalance NUMERIC(19,6), @EndingBalance NUMERIC(19,6);
--DECLARE @BalanceFactor INT;
DECLARE @BeginningBalanceFactor INT, @EndingBalanceFactor INT;
WITH XMLNAMESPACES (DEFAULT 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02', 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02' AS ns)
SELECT
@ReceiptNumber = Entry.value('(ns:MsgId)[1]', 'VARCHAR(MAX)'),
@ReceiptDate   = Entry.value('(ns:CreDtTm)[1]', 'DATETIMEOFFSET')
FROM @XmlContent.nodes('/ns:Document/ns:BkToCstmrStmt/ns:GrpHdr') AS Entries(Entry);
WITH XMLNAMESPACES (DEFAULT 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02', 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02' AS ns)
SELECT
--@BalanceFactor = CASE WHEN Entry.value('(ns:CdtDbtInd)[1]', 'VARCHAR(MAX)') = 'DBIT' THEN -1 ELSE 1 END
@BeginningBalanceFactor = CASE
WHEN Entry.value('(ns:Tp/ns:CdOrPrtry/ns:Cd)[1]', 'VARCHAR(MAX)') = 'PRCD'
THEN CASE WHEN Entry.value('(ns:CdtDbtInd)[1]', 'VARCHAR(MAX)') = 'DBIT' THEN -1 ELSE 1 END
ELSE @BeginningBalanceFactor
END,
@EndingBalanceFactor = CASE
WHEN Entry.value('(ns:Tp/ns:CdOrPrtry/ns:Cd)[1]', 'VARCHAR(MAX)') = 'CLBD'
THEN CASE WHEN Entry.value('(ns:CdtDbtInd)[1]', 'VARCHAR(MAX)') = 'DBIT' THEN -1 ELSE 1 END
ELSE @EndingBalanceFactor
END
FROM @XmlContent.nodes('/ns:Document/ns:BkToCstmrStmt/ns:Stmt/ns:Bal') AS Entries(Entry);
WITH XMLNAMESPACES (DEFAULT 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02', 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02' AS ns)
SELECT
@BeginningBalance = @XmlContent.value('(/ns:Document/ns:BkToCstmrStmt/ns:Stmt/ns:Bal[ns:Tp/ns:CdOrPrtry/ns:Cd="PRCD"]/ns:Amt[@Ccy="EUR"])[1]', 'DECIMAL(19,6)'),
@EndingBalance = @XmlContent.value('(/ns:Document/ns:BkToCstmrStmt/ns:Stmt/ns:Bal[ns:Tp/ns:CdOrPrtry/ns:Cd="CLBD"]/ns:Amt[@Ccy="EUR"])[1]', 'DECIMAL(19,6)');
WITH XMLNAMESPACES (DEFAULT 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02', 'urn:iso:std:iso:20022:tech:xsd:camt.053.001.02' AS ns)
SELECT
@parxFinanceTransferId AS TransferId
, ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS Position
, dbo.xFUNCTION002_GetPostingPeriodIdByDate(TRY_CAST(CONVERT(DATE, CONVERT(DATE, Entry.value('(ns:BookgDt/ns:Dt)[1]', 'DATE')), 104) AS DATE)) AS PostingPeriodId
, @ReceiptNumber AS StatementID
, TxDetails.value('(ns:TxDtls/ns:Refs/ns:Prtry/ns:Ref)[1]', 'VARCHAR(100)') AS EntryReference  --Ntry.NtryDtls.TxDtls.Refs.Prtry.Ref
, IIF(Entry.value('(ns:CdtDbtInd)[1]', 'VARCHAR(10)') = 'DBIT', -1, 1) * Entry.value('(ns:Amt[@Ccy="EUR"])[1]', 'DECIMAL(19,6)') AS Amount --Ntry.NtryDtls.Amt
, Entry.value('(ns:Amt/@Ccy)[1]', 'VARCHAR(10)') CurrencyId --Ntry.NtryDtls.Amt
, IIF(Entry.value('(ns:CdtDbtInd)[1]', 'VARCHAR(10)') = 'DBIT', 1, 0) AS DebitSide --Ntry.NtryDtls.CdtDbtInd
, Entry.value('(ns:BookgDt/ns:Dt)[1]', 'DATE') AS ValueDate --Ntry.NtryDtls.BookgDt.Dt
, Entry.value('(ns:BkTxCd/ns:Prtry/ns:Cd)[1]', 'VARCHAR(10)') AS TransactionType --Ntry.NtryDtls.BkTxCd.Prtry.Cd
, TxDetails.value('(ns:TxDtls/ns:RmtInf/ns:Ustrd)[1]', 'VARCHAR(255)') AS Memo1 --Ntry.NtryDtls.TxDtls.RmtInf.Ustrd
, TxDetails.value('(ns:RmtInf/ns:Strd/ns:CdtrRefInf/ns:Ref)[1]', 'VARCHAR(255)') AS Memo2 --Ntry.NtryDtls.RmtInf.Strd.CdtrRefInf.Ref   ===> Missing
, TxDetails.value('(ns:TxDtls/ns:Refs/ns:Prtry/ns:Ref)[1]', 'VARCHAR(35)') AS MandateReference --Ntry.NtryDtls.TxDtls.Refs.Prtry.Ref
, TxDetails.value('(ns:TxDtls/ns:Refs/ns:TxId)[1]', 'VARCHAR(40)') AS Reference --Ntry.NtryDtls.TxDtls.Refs.TxId ===> Missing
, TxDetails.value('(ns:TxDtls/ns:RltdPties/ns:CdtrAcct/ns:Id/ns:IBAN)[1]', 'VARCHAR(40)') AS BankTransactionCode --Ntry.NtryDtls.TxDtls.RltdPties.CdtrAcct.Id.IBAN
, TxDetails.value('(ns:TxDtls/ns:Refs/ns:EndToEndId)[1]', 'VARCHAR(40)') AS EndToEndId --Ntry.NtryDtls.TxDtls.Refs.EndToEndId
, TxDetails.value('(ns:TxDtls/ns:RmtInf/ns:Ustrd)[1]', 'VARCHAR(255)') AS Subject --Ntry.NtryDtls.TxDtls.RmtInf.Ustrd--
, Entry.value('(ns:BookgDt/ns:Dt)[1]', 'DATE') StatementDate --Ntry.BookgDt.DtTm
,IIF(Entry.value('(ns:CdtDbtInd)[1]', 'VARCHAR(10)') = 'CRDT'
,TxDetails.value('(ns:TxDtls/ns:RltdPties/ns:Dbtr/ns:Nm)[1]', 'VARCHAR(35)')
,TxDetails.value('(ns:TxDtls/ns:RltdPties/ns:Cdtr/ns:Nm)[1]', 'VARCHAR(35)')) As Name--Ntry.NtryDtls.TxDtls.RltdPties.Dbtr.Nm OR Ntry.NtryDtls.TxDtls.RltdPties.Cdtr.Nm WHERE Value != ACCOUNT_HOLDER
INTO #CAMTDetails
FROM @XmlContent.nodes('/ns:Document/ns:BkToCstmrStmt/ns:Stmt/ns:Ntry') AS Entries(Entry)
CROSS APPLY Entry.nodes('ns:NtryDtls') AS Tx(TxDetails);
INSERT INTO [dbo].[FinanceTransferPosition] (
TransferId
, Subject
, StatementDate
, Name
, Position
, PostingPeriodId
, StatementID
, EntryReference
, Amount
, ForeignCurrencyAmount
, Rate
, DebitSide
, ValueDate
, TransactionType
, Memo1
, Memo2
, MandateReference
, Reference
, BankTransactionCode
, EndToEndId
)
SELECT
TransferId
, REPLACE(REPLACE(REPLACE(REPLACE(Subject, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
, StatementDate
, REPLACE(REPLACE(REPLACE(REPLACE(Name, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
, Position
, PostingPeriodId
, StatementID
, REPLACE(REPLACE(REPLACE(REPLACE(EntryReference, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
, CASE WHEN FT.ForeignCurrencyId IS NULL THEN CD.Amount ELSE ROUND(CD.Amount * ISNULL(ACR.Rate, 0), 2) END
, CASE WHEN FT.ForeignCurrencyId IS NULL THEN NULL ELSE CD.Amount END
, CASE WHEN FT.ForeignCurrencyId IS NULL THEN NULL ELSE ISNULL(ACR.Rate, 0) END
, DebitSide
, ValueDate
, TransactionType
, REPLACE(REPLACE(REPLACE(REPLACE(Memo1, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
, REPLACE(REPLACE(REPLACE(REPLACE(Memo2, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
, REPLACE(REPLACE(REPLACE(REPLACE(MandateReference, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
, REPLACE(REPLACE(REPLACE(REPLACE(Reference, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
, BankTransactionCode
, EndToEndId
FROM #CAMTDetails CD
LEFT JOIN FinanceTransfer FT ON FT.Id = @parxFinanceTransferId
LEFT JOIN AdminCurrencyRate ACR
ON ACR.ForeignCurrencyId = FT.ForeignCurrencyId
AND ACR.RateDate = CD.StatementDate
ORDER BY CD.Position;
UPDATE FinanceTransfer SET
ReceiptNumber = @ReceiptNumber
, ReceiptDate = @ReceiptDate
, BeginningBalance = ISNULL(@BeginningBalance,0) * @BeginningBalanceFactor --@BalanceFactor
, EndingBalance = ISNULL(@EndingBalance,0) * @EndingBalanceFactor --@BalanceFactor
FROM FinanceTransfer FT
WHERE FT.Id = @parxFinanceTransferId;
DROP TABLE #CAMTDetails;
PRINT 'CAMT data processed successfully.';
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;-- Procedure
GO
--- END xPROC605_FinanceTransferPosition_CamtImport--------------------------------------------------------------------------
