CREATE OR ALTER PROCEDURE 
xPROC606I_FinanceTransferPosition
@parxFinanceTransferId INT
-- PURPOSE: Create FinanceTransferPosition
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT FinanceTransferPosition
-- 90.) RETURN
-- 91.) ERROR HANDLING
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @calxNewPositionNumber INT
SELECT 
@calxNewPositionNumber = ISNULL(MAX(Position), 0) + 1 
FROM FinanceTransferPosition
WHERE TransferId = @parxFinanceTransferId ;
DECLARE @Rate DECIMAL(19,6)
SELECT
@Rate = Rate
FROM FinanceTransfer FT
LEFT JOIN AdminCurrencyRate ACR
ON ACR.ForeignCurrencyId = FT.ForeignCurrencyId
AND ACR.RateDate = CAST(GETDATE() AS DATE)
WHERE FT.Id = @parxFinanceTransferId
-- FROM FinancePostingPeriod
DECLARE @CurrentPostingPeriodId INT
SET @CurrentPostingPeriodId = dbo.xFUNCTION001_GetCurrentPostingPeriodId()
-- 20.) INSERT FinanceTransferPosition
INSERT INTO FinanceTransferPosition(
TransferId
, Position
, PostingPeriodId
, StatementDate
, Rate
)
VALUES
(
@parxFinanceTransferId
, @calxNewPositionNumber
, @CurrentPostingPeriodId
, GETDATE()
, @Rate
)
-- 90.) RETURN
DECLARE @newxFinanceTransferPositionId INT
SET @newxFinanceTransferPositionId = SCOPE_IDENTITY();
SELECT * FROM FinanceTransferPosition WHERE Id = @newxFinanceTransferPositionId 
-- 91.) ERROR HANDLING
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
