CREATE OR ALTER PROCEDURE 
xPROC606U_FinanceTransferPosition_StatementDate
-- PURPOSE: Update the StatementDate with passed value
-- 26.06.26
@parxFinanceTransferPositionId INT,
@parxStatementDate DATE
AS
BEGIN -- Procedure
SET NOCOUNT ON;
