CREATE OR ALTER PROCEDURE 
xPROC606U_FinanceTransferPosition_Amount
-- PURPOSE: Update the Amount with passed value
-- 26.06.26
@parxFinanceTransferPositionId INT,
@parxAmount DECIMAL(19,6)
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE FTP SET 
Amount = @parxAmount
, ForeignCurrencyAmount = CASE WHEN FT.ForeignCurrencyId IS NOT NULL THEN ROUND(@parxAmount * ISNULL(FTP.Rate, 0), 2) ELSE NULL END
FROM FinanceTransferPosition FTP
LEFT JOIN FinanceTransfer FT ON FT.Id = FTP.TransferId
LEFT JOIN AdminCurrencyRate ACR
ON ACR.ForeignCurrencyId = FT.ForeignCurrencyId
AND ACR.RateDate = FTP.StatementDate
WHERE FTP.Id = @parxFinanceTransferPositionId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC606U_FinanceTransferPosition_Amount----------------------------------------------------------------------------------------------------
