CREATE OR ALTER PROCEDURE 
xPROC607N_FinanceTransferPositionOpenItem
-- PURPOSE: Insert FinanceTransferPositionOpenItem and suggest PaymentAmount and CashDiscountAmount
@parxTransferPositionId INT,
@parxOpenItemId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- PURPOSE: Insert record into FinanceTransferPositionOpenItem with suggested values for Amount and CashDiscountAmount
INSERT INTO FinanceTransferPositionOpenItem(
TransferPositionId
, OpenItemId
, PaymentAmount
, CashDiscountAmount
, ApplicablePercent
, PermissibleAmount
, Remaining
, ForeignCurrencyPaymentAmount
, ForeignCurrencyCashDiscountAmount
, ForeignCurrencyPermissibleAmount
, ForeignCurrencyRemaining
, CurrencyDifference
)
SELECT
@parxTransferPositionId
, @parxOpenItemId
, CASE WHEN ABS(FTP.Amount)  - ABS(ISNULL(FTPAP_Sum.TotalAmount, 0)) - ABS(ISNULL(FTPOI_Sum.TotalAmount, 0)) < ABS(FOI.OpenAmount) THEN FTP.Amount  + ISNULL(FTPAP_Sum.TotalAmount, 0) + ISNULL(FTPOI_Sum.TotalAmount, 0) ELSE 
FOI.OpenAmount - (FOI.OpenAmount * 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
END * -1
, ROUND((
CASE WHEN ABS(FTP.Amount)  - ABS(ISNULL(FTPAP_Sum.TotalAmount, 0)) - ABS(ISNULL(FTPOI_Sum.TotalAmount, 0)) < ABS(FOI.OpenAmount) THEN FTP.Amount  + ISNULL(FTPAP_Sum.TotalAmount, 0) + ISNULL(FTPOI_Sum.TotalAmount, 0) ELSE 
FOI.OpenAmount - (FOI.OpenAmount * 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
END * -1
/(100- 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
)) *
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
, 2)
, CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
, ROUND((
CASE WHEN ABS(FTP.Amount)  - ABS(ISNULL(FTPAP_Sum.TotalAmount, 0)) - ABS(ISNULL(FTPOI_Sum.TotalAmount, 0)) < ABS(FOI.OpenAmount) THEN FTP.Amount  + ISNULL(FTPAP_Sum.TotalAmount, 0) + ISNULL(FTPOI_Sum.TotalAmount, 0) ELSE 
FOI.OpenAmount - (FOI.OpenAmount * 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
END * -1
/(100- 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
)) *
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
, 2)
, FOI.OpenAmount +
CASE WHEN ABS(FTP.Amount)  - ABS(ISNULL(FTPAP_Sum.TotalAmount, 0)) - ABS(ISNULL(FTPOI_Sum.TotalAmount, 0)) < ABS(FOI.OpenAmount) THEN FTP.Amount  + ISNULL(FTPAP_Sum.TotalAmount, 0) + ISNULL(FTPOI_Sum.TotalAmount, 0) ELSE 
FOI.OpenAmount - (FOI.OpenAmount * 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
END * -1 +
ROUND((
CASE WHEN ABS(FTP.Amount)  - ABS(ISNULL(FTPAP_Sum.TotalAmount, 0)) - ABS(ISNULL(FTPOI_Sum.TotalAmount, 0)) < ABS(FOI.OpenAmount) THEN FTP.Amount  + ISNULL(FTPAP_Sum.TotalAmount, 0) + ISNULL(FTPOI_Sum.TotalAmount, 0) ELSE 
FOI.OpenAmount - (FOI.OpenAmount * 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
END * -1
/(100- 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
)) *
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
, 2)
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN
FOI.ForeignCurrencyOpenAmount - (FOI.ForeignCurrencyOpenAmount* 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
ELSE NULL
END * -1
, ROUND((
CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN
FOI.ForeignCurrencyOpenAmount - (FOI.ForeignCurrencyOpenAmount* 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
ELSE NULL
