/(100- 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
)) *
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
, 2)
, ROUND((
CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN
FOI.ForeignCurrencyOpenAmount - (FOI.ForeignCurrencyOpenAmount* 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
ELSE NULL
END * -1
/(100- 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
)) *
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
, 2)
, FOI.ForeignCurrencyOpenAmount +
CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN
FOI.ForeignCurrencyOpenAmount - (FOI.ForeignCurrencyOpenAmount* 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
ELSE NULL
END * -1 +
ROUND((
CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN
FOI.ForeignCurrencyOpenAmount - (FOI.ForeignCurrencyOpenAmount* 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
/100)
ELSE NULL
END * -1
/(100- 
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
)) *
CASE
WHEN FOI.CashDiscountDate1 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate1 THEN ISNULL(FOI.CashDiscountPercentage1, 0)
WHEN FOI.CashDiscountDate2 IS NOT NULL AND FTP.StatementDate <= FOI.CashDiscountDate2 THEN ISNULL(FOI.CashDiscountPercentage2, 0)
ELSE 0
END
, 2)
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
FROM FinanceOpenItem FOI
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = @parxTransferPositionId
LEFT JOIN (
SELECT TransferPositionId, ISNULL(SUM(PaymentAmount), 0) AS TotalAmount
FROM FinanceTransferPositionOpenItem
GROUP BY TransferPositionId
) FTPOI_Sum ON FTPOI_Sum.TransferPositionId = FTP.Id
LEFT JOIN (
SELECT TransferPositionId, ISNULL(SUM(Amount), 0) AS TotalAmount
FROM FinanceTransferPositionAccountPlan
GROUP BY TransferPositionId
) FTPAP_Sum ON FTPAP_Sum.TransferPositionId = FTP.Id
WHERE FOI.Id = @parxOpenItemId
UPDATE FTP
SET
CustomerPartnerDetailId = CASE WHEN FTP.CustomerPartnerDetailId IS NULL AND FTP.SupplierPartnerDetailId IS NULL AND FOI.PartnerTypeId = 'Customer' THEN FOI.PartnerDetailId ELSE FTP.CustomerPartnerDetailId END
, SupplierPartnerDetailId = CASE WHEN FTP.CustomerPartnerDetailId IS NULL AND FTP.SupplierPartnerDetailId IS NULL AND FOI.PartnerTypeId = 'Supplier' THEN FOI.PartnerDetailId ELSE FTP.SupplierPartnerDetailId END
FROM FinanceTransferPosition FTP
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = @parxOpenItemId
WHERE FTP.Id = @parxTransferPositionId
COMMIT;
