CREATE OR ALTER PROCEDURE 
xPROC607U_FinanceTransferPositionOpenItem_Amount
-- PURPOSE: Update the Amount with passed value and calculate follow up values
@parxFinanceTransferPositionOpenItemId INT,
@parxAmount DECIMAL(19,6)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE FinanceTransferPositionOpenItem
SET
PaymentAmount = @parxAmount
, PermissibleAmount = COALESCE(ROUND((@parxAmount/(100-NULLIF(FTPOI.ApplicablePercent, 100))) * FTPOI.ApplicablePercent, 2), @parxAmount)
, Remaining = FOI.OpenAmount + @parxAmount + FTPOI.CashDiscountAmount + ISNULL(FTPOI.CurrencyDifference, 0)
FROM FinanceTransferPositionOpenItem FTPOI
LEFT JOIN FinanceOpenItem FOI ON FTPOI.OpenItemId = FOI.Id
WHERE FTPOI.Id = @parxFinanceTransferPositionOpenItemId 
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC607U_FinanceTransferPositionOpenItem_Amount-------------------------------------------
