xPROC607U_FinanceTransferPositionOpenItem_ForeignCurrencyAmount
-- PURPOSE: Update the ForeignCurrencyAmount with passed value and calculate follow up values
@parxFinanceTransferPositionOpenItemId INT,
@parxForeignCurrencyAmount DECIMAL(19,6)
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE FinanceTransferPositionOpenItem
SET
ForeignCurrencyPaymentAmount = @parxForeignCurrencyAmount 
, ForeignCurrencyPermissibleAmount = COALESCE(ROUND((@parxForeignCurrencyAmount /(100-NULLIF(FTPOI.ApplicablePercent, 100))) * FTPOI.ApplicablePercent, 2), @parxForeignCurrencyAmount)
, ForeignCurrencyRemaining = ISNULL(FOI.ForeignCurrencyOpenAmount, 0) + @parxForeignCurrencyAmount + ISNULL(FTPOI.ForeignCurrencyCashDiscountAmount, 0)
FROM FinanceTransferPositionOpenItem FTPOI
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = FTPOI.TransferPositionId
LEFT JOIN FinanceTransfer FT ON FT.Id = FTP.TransferId
LEFT JOIN FinanceOpenItem FOI ON FTPOI.OpenItemId = FOI.Id
WHERE FTPOI.Id = @parxFinanceTransferPositionOpenItemId 
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
