CREATE OR ALTER PROCEDURE 
xPROC608N_FinanceTransferPositionAccountPlan_PersonalAccount
-- PURPOSE: Insert FinanceTransferPositionAccountPlan for selected PartnerDetail and suggest Amount
@parxTransferPositionId INT,
@parxPartnerDetailId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- PURPOSE: Insert record into FinanceTransferPositionOpenItem with suggested values for Amount and CashDiscountAmount
INSERT INTO FinanceTransferPositionAccountPlan(
TransferPositionId
, AccountId
, AccountName
, PartnerDetailId
, Amount
)
SELECT
@parxTransferPositionId
, FGP.CollectiveAccountId
, P.Matchcode
, @parxPartnerDetailId
, (FTP.Amount + ISNULL(FTPOI_Sum.TotalAmount, 0) + ISNULL(FTPAP_Sum.TotalAmount, 0)) * -1
FROM PartnerDetail PD
LEFT JOIN Partner P ON P.Id = PD.PartnerId
LEFT JOIN FinanceGroupPartner FGP ON FGP.Id = PD.FinanceGroupPartnerDetailId
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = @parxTransferPositionId
LEFT JOIN (
SELECT TransferPositionId, ISNULL(SUM(PaymentAmount), 0) AS TotalAmount
FROM FinanceTransferPositionOpenItem
GROUP BY TransferPositionId
) FTPOI_Sum ON FTPOI_Sum.TransferPositionId = FTP.Id
LEFT JOIN (
SELECT TransferPositionId, ISNULL(SUM(Amount), 0) AS TotalAmount
FROM FinanceTransferPositionAccountPlan
GROUP BY TransferPositionId
) FTPAP_Sum ON FTPAP_Sum.TransferPositionId = FTP.Id
WHERE PD.Id = @parxPartnerDetailId
UPDATE FTP
SET
CustomerPartnerDetailId = CASE WHEN FTP.CustomerPartnerDetailId IS NULL AND FTP.SupplierPartnerDetailId IS NULL AND PD.PartnerTypeId = 'Customer' THEN PD.Id ELSE FTP.CustomerPartnerDetailId END
, SupplierPartnerDetailId = CASE WHEN FTP.CustomerPartnerDetailId IS NULL AND FTP.SupplierPartnerDetailId IS NULL AND PD.PartnerTypeId = 'Supplier' THEN PD.Id ELSE FTP.SupplierPartnerDetailId END
FROM FinanceTransferPosition FTP
LEFT JOIN PartnerDetail PD ON PD.Id = @parxPartnerDetailId
WHERE FTP.Id = @parxTransferPositionId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC608N_FinanceTransferPositionAccountPlan_PersonalAccount-------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC608N_FinanceTransferPositionAccountPlan_GeneralLedgerAccount
-- PURPOSE: Insert FinanceTransferPositionAccountPlan for selected Account and suggest Amount
@parxTransferPositionId INT,
@parxFinanceAccountPlanId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- PURPOSE: Insert record into FinanceTransferPositionOpenItem with suggested values for Amount and CashDiscountAmount
INSERT INTO FinanceTransferPositionAccountPlan(
TransferPositionId
, AccountId
, AccountName
, Amount
, ForeignCurrencyAmount
, TaxKeyId
)
SELECT
@parxTransferPositionId
, @parxFinanceAccountPlanId
, FAP.Name
, (FTP.Amount + ISNULL(FTPOI_Sum.TotalAmount, 0) + ISNULL(FTPAP_Sum.TotalAmount, 0)) * -1
, (FTP.ForeignCurrencyAmount + ISNULL(FTPOI_Sum.TotalForeignCurrencyAmount, 0) + ISNULL(FTPAP_Sum.TotalForeignCurrencyAmount, 0)) * -1
, FAP.TaxKeyId
FROM FinanceAccountPlan FAP
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = @parxTransferPositionId
LEFT JOIN (
SELECT TransferPositionId, ISNULL(SUM(PaymentAmount), 0) AS TotalAmount, ISNULL(SUM(ForeignCurrencyPaymentAmount), 0) AS TotalForeignCurrencyAmount
FROM FinanceTransferPositionOpenItem
GROUP BY TransferPositionId
) FTPOI_Sum ON FTPOI_Sum.TransferPositionId = FTP.Id
LEFT JOIN (
SELECT TransferPositionId, ISNULL(SUM(Amount), 0) AS TotalAmount, ISNULL(SUM(ForeignCurrencyAmount), 0) AS TotalForeignCurrencyAmount
FROM FinanceTransferPositionAccountPlan
GROUP BY TransferPositionId
) FTPAP_Sum ON FTPAP_Sum.TransferPositionId = FTP.Id
WHERE FAP.Id = @parxFinanceAccountPlanId
UPDATE FTP
SET
AccountId = CASE WHEN FTP.AccountId IS NULL THEN @parxFinanceAccountPlanId ELSE FTP.AccountId END
FROM FinanceTransferPosition FTP
WHERE FTP.Id = @parxTransferPositionId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC608N_FinanceTransferPositionAccountPlan_GeneralLedgerAccount-------------------------------------------
