CREATE OR ALTER PROCEDURE 
xPROC609_FinanceTransferPosition_Suggestion
-- xPROC609_FinanceTransferPosition_Suggestion
-- Purpose: Create a OpenItem Record for this posted Posting
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) UPDATE FinanceTransferPosition
-- 25.) Temporary Tables
-- 30.) EXEC xPROC608N_FinanceTransferPositionAccountPlan_GeneralLedgerAccount
-- 40.) EXEC xPROC607N_FinanceTransferPositionOpenItem
-------------------------------------------------------------------------------------------------------------
@parxFinanceTransferId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
CREATE TABLE #SuggestionMatch (
Id INT NOT NULL,
AccountId INT NULL,
CustomerPartnerDetailId INT NULL,
SupplierPartnerDetailId INT NULL,
Amount DECIMAL(18,4) NOT NULL,
Subject NVARCHAR(255) NOT NULL,
rn INT NOT NULL
);
INSERT INTO #SuggestionMatch (Id, AccountId, CustomerPartnerDetailId, SupplierPartnerDetailId, Amount, Subject, rn)
SELECT
FTP.Id,
FTS.AccountId,
FTS.CustomerPartnerDetailId,
FTS.SupplierPartnerDetailId,
FTP.Amount,
FTP.Subject,
ROW_NUMBER() OVER (
PARTITION BY FTP.Id
ORDER BY CASE
WHEN FTS.SuggestionFieldId = 'Name' AND FTP.Name = FTS.Id THEN 0
WHEN FTS.SuggestionFieldId = 'Subject' AND FTP.Subject = FTS.Id THEN 0
ELSE 1
END
) AS rn
FROM FinanceTransferPosition FTP
JOIN FinanceTransferSuggestion FTS
ON FTP.TransferId = @parxFinanceTransferId
AND (
(FTS.SuggestionFieldId = 'Name' AND FTP.Name COLLATE Latin1_General_CI_AS LIKE '%' + FTS.Id + '%')
OR
(FTS.SuggestionFieldId = 'Subject' AND FTP.Subject COLLATE Latin1_General_CI_AS LIKE '%' + FTS.Id + '%')
);
-- 20.) UPDATE FinanceTransferPosition
UPDATE FTP
SET
AccountId = COALESCE(SM.AccountId, FTP.AccountId),
CustomerPartnerDetailId = CASE
WHEN SM.CustomerPartnerDetailId IS NOT NULL AND SM.SupplierPartnerDetailId IS NOT NULL THEN
CASE WHEN SM.Amount >= 0 THEN SM.CustomerPartnerDetailId ELSE NULL END
WHEN SM.CustomerPartnerDetailId IS NOT NULL THEN SM.CustomerPartnerDetailId
ELSE FTP.CustomerPartnerDetailId
END,
SupplierPartnerDetailId = CASE
WHEN SM.CustomerPartnerDetailId IS NOT NULL AND SM.SupplierPartnerDetailId IS NOT NULL THEN
CASE WHEN SM.Amount < 0 THEN SM.SupplierPartnerDetailId ELSE NULL END
WHEN SM.SupplierPartnerDetailId IS NOT NULL THEN SM.SupplierPartnerDetailId
ELSE FTP.SupplierPartnerDetailId
END
FROM FinanceTransferPosition FTP
JOIN #SuggestionMatch SM ON FTP.Id = SM.Id AND SM.rn = 1;
-- 25.) Temporary Tables
CREATE TABLE #CallListAccountPlan (
TransferPositionId INT NOT NULL,
FinanceAccountPlanId INT NOT NULL
);
INSERT INTO #CallListAccountPlan (TransferPositionId, FinanceAccountPlanId)
SELECT SM.Id, SM.AccountId
FROM #SuggestionMatch AS SM
WHERE SM.rn = 1
AND SM.AccountId IS NOT NULL
AND NOT EXISTS (
SELECT 1
FROM FinanceTransferPositionAccountPlan AS FPAP
WHERE FPAP.TransferPositionId    = SM.Id
AND FPAP.AccountId = SM.AccountId
);
CREATE TABLE #CallListOpenItem (
TransferPositionId INT NOT NULL,
OpenItemId INT NOT NULL
);
INSERT INTO #CallListOpenItem (TransferPositionId, OpenItemId)
SELECT FTP.Id, FOI.Id
FROM FinanceTransferPosition AS FTP
CROSS APPLY (
SELECT TOP (1) FOI.Id
FROM FinanceOpenItem AS FOI
WHERE FOI.PartnerDetailId = COALESCE(FTP.CustomerPartnerDetailId, FTP.SupplierPartnerDetailId)
AND FOI.StatusId = 'open'
ORDER BY
CASE WHEN FTP.Subject COLLATE Latin1_General_CI_AS LIKE '%' + FOI.ReferenceDoc + '%' THEN 0 ELSE 1 END,
CASE WHEN FOI.OpenAmount =  FTP.Amount THEN 0 ELSE 1 END,
CASE WHEN FOI.OpenAmount <= FTP.Amount THEN 0 ELSE 1 END,
CASE WHEN FOI.OpenAmount <= FTP.Amount THEN FOI.OpenAmount END DESC,
CASE WHEN FOI.OpenAmount >  FTP.Amount THEN FOI.OpenAmount END ASC
) AS FOI
WHERE FTP.TransferId = @parxFinanceTransferId
AND (FTP.CustomerPartnerDetailId IS NOT NULL OR FTP.SupplierPartnerDetailId IS NOT NULL)
AND NOT EXISTS (
SELECT 1
FROM FinanceTransferPositionOpenItem AS FPOI
WHERE FPOI.TransferPositionId = FTP.Id
AND FPOI.OpenItemId         = FOI.Id
);
-- 30.) EXEC xPROC608N_FinanceTransferPositionAccountPlan_GeneralLedgerAccount
DECLARE @TransferPositionId INT, @FinanceAccountPlanId INT;
WHILE EXISTS (SELECT 1 FROM #CallListAccountPlan)
BEGIN
SELECT TOP 1 @TransferPositionId = TransferPositionId, @FinanceAccountPlanId = FinanceAccountPlanId
FROM #CallListAccountPlan;
IF NOT EXISTS (
SELECT 1
FROM FinanceTransferPositionAccountPlan AS FPAP
WHERE FPAP.TransferPositionId    = @TransferPositionId
AND FPAP.AccountId = @FinanceAccountPlanId
)
BEGIN
-- L30.50: Aufruf nur wenn noch nicht vorhanden
EXEC xPROC608N_FinanceTransferPositionAccountPlan_GeneralLedgerAccount
@parxTransferPositionId   = @TransferPositionId,
@parxFinanceAccountPlanId = @FinanceAccountPlanId;
END;
DELETE FROM #CallListAccountPlan WHERE TransferPositionId = @TransferPositionId;
END;
-- 40.) EXEC xPROC607N_FinanceTransferPositionOpenItem
DECLARE @OpenItemId INT;
WHILE EXISTS (SELECT 1 FROM #CallListOpenItem)
BEGIN
SELECT TOP 1 @TransferPositionId = TransferPositionId, @OpenItemId = OpenItemId
FROM #CallListOpenItem;
IF NOT EXISTS (
SELECT 1
FROM FinanceTransferPositionOpenItem AS FPOI
WHERE FPOI.TransferPositionId = @TransferPositionId
AND FPOI.OpenItemId         = @OpenItemId
)
BEGIN
-- L40.50: Aufruf nur wenn noch nicht vorhanden
EXEC xPROC607N_FinanceTransferPositionOpenItem
@parxTransferPositionId = @TransferPositionId,
@parxOpenItemId         = @OpenItemId;
END;
DELETE FROM #CallListOpenItem WHERE TransferPositionId = @TransferPositionId;
END;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC609_FinanceTransferPosition_Suggestion--------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC609_FinanceTransfer_Posting
-- xPROC609_FinanceTransfer_Posting
-- Purpose: Create a OpenItem Record for this posted Posting
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 25.) UPDATE FinanceTransferPositionOpenItem PreviouslyOpen and Remaining
-- 30.) CREATE FinancePosting
-- 40.) INSERT new FinanceOpenItem for Personal Accounts
-- 45.) CREATE first FinancePostingPosition for ALL
-- 51.) CREATE second FinancePostingPosition for FTPAP
-- 52.) CREATE first Tax FinancePostingPosition for FTPAP
-- 53.) CREATE second Tax FinancePostingPosition for FTPAP
-- 60.) INSERT new FinanceOpenItem
-- 61.) INSERT new FinanceOpenItem for Cash Discount
-- 70.) UPDATE original FinanceOpenItem
-- 82.) CREATE second FinancePostingPosition for FTPOI
-- 83.) CREATE FinancePostingPositions for Cash Discount for FTPOI
-- 84.) CREATE FinancePostingPositions for Cash Discount Tax for FTPOI
-- 85.) UPDATE FinanceAccountPlan Balance
-- 86.) UPDATE PartnerDetail Balance
-- 87.) UPDATE first FinancePostingPosition with ContraAccount
-- 88a.) CREATE FinancePosting for Currency Difference
-- 88b.) CREATE FinanceOpenItem for Currency Difference
-- 88c.) CREATE First FinancePostingPosition for Currency Difference
-- 88d.) CREATE Second FinancePostingPosition for Currency Difference
-- 88e.) UPDATE FinanceAccountPlan Balance
-- 88f.) UPDATE PartnerDetail Balance
-- 89.) UPDATE FinanceTransfer
-- 90.) CREATE FinanceOpenItemInternalReconciliation
-- 91.) CREATE FinanceOpenItemInternalReconciliationPositions for Inserted Open Items
-- 92.) CREATE FinanceOpenItemInternalReconciliationPositions for UpdatedOpen Items
-- 93.) CREATE FinanceOpenItemInternalReconciliationPositions for Currency Difference Open Items
-------------------------------------------------------------------------------------------------------------
@parxFinanceTransferId INT,
@parxCreatedBy INT,
@parxAcceptBalanceMismatch BIT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @InvalidValues TABLE (PositionNumber INT, TEXT NVARCHAR(100), IsError BIT);
CREATE TABLE #InsertedPostings (
PostingId INT
, TransferPositionId INT
);
CREATE TABLE #InsertedOpenItems (
OpenItemId INT
, TransferPositionId INT
, CashDiscount BIT
);
CREATE TABLE #InsertedReconciliations (
ReconciliationId INT
, TransferPositionId INT
);
CREATE TABLE #InsertedCurrencyDifferencePostings (
PostingId INT
, TransferPositionOpenItemId INT
);
CREATE TABLE #InsertedCurrencyDifferenceOpenItems (
OpenItemId INT
, TransferPositionOpenItemId INT
, CashDiscount BIT
);
-- 20.) VALIDATION
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Position has no open items or accounts assigned'
, 0
FROM FinanceTransferPosition FTP
LEFT JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceTransferPositionAccountPlan FTPAP ON FTPAP.TransferPositionId = FTP.Id
WHERE FTP.TransferId = @parxFinanceTransferId AND FTPOI.Id IS NULL AND FTPAP.Id IS NULL
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Position has no Posting period assigned'
, 0
FROM FinanceTransferPosition FTP
WHERE FTP.TransferId = @parxFinanceTransferId AND FTP.PostingPeriodId IS NULL
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Enter a subject for this position'
, 0
FROM FinanceTransferPosition FTP
WHERE FTP.TransferId = @parxFinanceTransferId AND (FTP.Subject IS NULL OR FTP.Subject = '')
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Posting Period is not open'
, 0
FROM FinanceTransferPosition FTP
LEFT JOIN FinancePostingPeriod FBP ON FBP.Id = FTP.PostingPeriodId
WHERE FTP.TransferId = @parxFinanceTransferId AND FBP.StatusId != 'open'
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Entered amount does not cover the required amount for the positions'
, 0
FROM FinanceTransferPosition FTP
OUTER APPLY (
SELECT SUM(PaymentAmount) AS TotalAmount
FROM FinanceTransferPositionOpenItem
WHERE TransferPositionId = FTP.Id
) OA
OUTER APPLY (
SELECT SUM(Amount) AS TotalAmount
FROM FinanceTransferPositionAccountPlan
WHERE TransferPositionId = FTP.Id
) AP
WHERE FTP.TransferId = @parxFinanceTransferId AND ISNULL(OA.TotalAmount, 0) + ISNULL(AP.TotalAmount, 0) != FTP.Amount * -1
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Entered amount is higher than the open amount of the open item'
, 0
FROM FinanceTransferPositionOpenItem FTPOI
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = FTPOI.TransferPositionId
WHERE FTP.TransferId = @parxFinanceTransferId AND ABS(FTPOI.PaymentAmount) - ABS(ISNULL(FTPOI.CurrencyDifference, 0)) > ABS(FOI.OpenAmount)
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Open item has been added multiple times to this position'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceTransferPositionOpenItem DuplicateFTPOI ON DuplicateFTPOI.OpenItemId = FTPOI.OpenItemId AND DuplicateFTPOI.Id != FTPOI.Id AND FTPOI.TransferPositionId = DuplicateFTPOI.TransferPositionId 
WHERE FTP.TransferId = @parxFinanceTransferId AND DuplicateFTPOI.Id IS NOT NULL
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'No cash discount possible for open items from Postings without tax key'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
WHERE FTP.TransferId = @parxFinanceTransferId AND FTPOI.CashDiscountAmount != 0
AND NOT EXISTS (
SELECT 1
FROM FinancePostingPosition FBP
WHERE FBP.PostingId = FOI.PostingId
AND FBP.TaxKeyId IS NOT NULL
);
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
0
, 'Opening balance is not equal to current balance'
, 0
FROM FinanceTransfer FT
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FT.GeneralLedgerAccountId
WHERE FT.Id = @parxFinanceTransferId AND FAP.Balance != FT.BeginningBalance AND @parxAcceptBalanceMismatch = 0
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Personal Account has been added multiple times to this position'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionAccountPlan FTPAP ON FTPAP.TransferPositionId = FTP.Id
LEFT JOIN FinanceTransferPositionAccountPlan DuplicateFTPAP ON DuplicateFTPAP.PartnerDetailId = FTPAP.PartnerDetailId AND DuplicateFTPAP.Id != FTPAP.Id AND FTPAP.TransferPositionId = DuplicateFTPAP.TransferPositionId 
WHERE FTP.TransferId = @parxFinanceTransferId AND DuplicateFTPAP.Id IS NOT NULL
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Account with an amount equal to zero can not be posted'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionAccountPlan FTPAP ON FTPAP.TransferPositionId = FTP.Id
WHERE FTP.TransferId = @parxFinanceTransferId AND FTPAP.Amount = 0
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Entered amount must have the opposite sign of the open amount'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
WHERE (FTPOI.PaymentAmount * FOI.OpenAmount) > 0 AND FTP.TransferId = @parxFinanceTransferId
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Entered cash discount amount must have the opposite sign of the open amount'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
WHERE (FTPOI.CashDiscountAmount * FOI.OpenAmount) > 0 AND FTP.TransferId = @parxFinanceTransferId
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Customer and Supplier can not be selected at the same time'
, 0
FROM FinanceTransferPosition FTP
WHERE FTP.TransferId = @parxFinanceTransferId AND FTP.CustomerPartnerDetailId IS NOT NULL AND FTP.SupplierPartnerDetailId IS NOT NULL
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Enter Currency Difference Account and Currency Difference Subject'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
WHERE FTPOI.CurrencyDifference IS NOT NULL AND FTPOI.CurrencyDifference != 0  AND FTP.TransferId = @parxFinanceTransferId AND (FTPOI.CurrencyDifferenceAccountId IS NULL OR FTPOI.CurrencyDifferenceSubject IS NULL)
INSERT INTO @InvalidValues (PositionNumber , TEXT, IsError)
SELECT
FTP.Position
, 'Remaining needs to be put as Currency Difference to proceed'
, 0
FROM FinanceTransferPosition FTP
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
WHERE FTPOI.ForeignCurrencyRemaining = 0 AND FTPOI.Remaining != 0 AND FTP.TransferId = @parxFinanceTransferId 
IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
-- 25.) UPDATE FinanceTransferPositionOpenItem PreviouslyOpen and Remaining
UPDATE FTPOI
SET 
PreviouslyOpen = FOI.OpenAmount
, Remaining = FOI.OpenAmount + FTPOI.PaymentAmount + FTPOI.CashDiscountAmount + ISNULL(FTPOI.CurrencyDifference, 0)
FROM FinanceTransferPositionOpenItem FTPOI
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = FTPOI.TransferPositionId
WHERE FTP.TransferId = @parxFinanceTransferId
