, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, Archived
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
)
-- VALUES FinancePostingPosition
SELECT
IB.PostingId
, COALESCE((SELECT MAX(Position) FROM FinancePostingPosition WHERE PostingId = IB.PostingId), 1) + ROW_NUMBER() OVER (PARTITION BY IB.PostingId ORDER BY (SELECT NULL))
, NULL
, 'valid'
, NULL
, FTPAP.AccountId
, CASE WHEN PD.PartnerTypeId = 'Customer' THEN 2 WHEN PD.PartnerTypeId = 'Supplier' THEN 3 ELSE 1 END
, CASE WHEN FTPAP.PartnerDetailId IS NOT NULL THEN P.Name1 ELSE FTPAP.AccountName END
, IOI.OpenItemId
, CASE WHEN FTP.Amount < 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.Amount) ELSE ROUND(ABS(FTPAP.Amount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END
, CASE WHEN FTP.Amount > 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.Amount) ELSE ROUND(ABS(FTPAP.Amount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END
, FT.GeneralLedgerAccountId
, 0
, NULL
, FTK.Id
, FTKD.TaxPercent
, CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(FTPAP.Amount * (FTKD.TaxPercent/100),2) WHEN FTK.TaxKeyKindId IS NOT NULL THEN FTPAP.Amount - ROUND(FTPAP.Amount * 100/(100+FTKD.TaxPercent),2) ELSE 0 END
, FTPAP.CostCenterId
, FTPAP.CostBearerId
, CASE WHEN FTP.Amount < 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.Amount) ELSE ROUND(ABS(FTPAP.Amount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END - CASE WHEN FTP.Amount > 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.Amount) ELSE ROUND(ABS(FTPAP.Amount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END
, NULL
, FTPAP.ProjectId
, PD.Id
, PD.Id
, 0
, CASE WHEN FTPAP.ForeignCurrencyAmount IS NOT NULL THEN CASE WHEN FTP.Amount < 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.ForeignCurrencyAmount) ELSE ROUND(ABS(FTPAP.ForeignCurrencyAmount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END ELSE NULL END
, CASE WHEN FTPAP.ForeignCurrencyAmount IS NOT NULL THEN CASE WHEN FTP.Amount > 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.ForeignCurrencyAmount) ELSE ROUND(ABS(FTPAP.ForeignCurrencyAmount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END ELSE NULL END
, CASE WHEN FTPAP.ForeignCurrencyAmount IS NOT NULL THEN CASE WHEN FTP.Amount < 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.ForeignCurrencyAmount) ELSE ROUND(ABS(FTPAP.ForeignCurrencyAmount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END ELSE NULL END - CASE WHEN FTPAP.ForeignCurrencyAmount IS NOT NULL THEN CASE WHEN FTP.Amount > 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(FTPAP.ForeignCurrencyAmount) ELSE ROUND(ABS(FTPAP.ForeignCurrencyAmount* 100) / (100 + ISNULL(FTKD.TaxPercent,0)), 2) END ELSE 0 END ELSE NULL END
, CASE WHEN FTPAP.ForeignCurrencyAmount IS NOT NULL THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(FTPAP.ForeignCurrencyAmount * (FTKD.TaxPercent/100),2) WHEN FTK.TaxKeyKindId IS NOT NULL THEN FTPAP.ForeignCurrencyAmount - ROUND(FTPAP.ForeignCurrencyAmount * 100/(100+FTKD.TaxPercent),2) ELSE 0 END ELSE NULL END
FROM #InsertedPostings IB
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = IB.TransferPositionId
JOIN FinanceTransferPositionAccountPlan FTPAP ON FTPAP.TransferPositionId = FTP.Id
LEFT JOIN PartnerDetail PD ON PD.Id = FTPAP.PartnerDetailId
LEFT JOIN Partner P ON P.Id = PD.PartnerId
LEFT JOIN #InsertedOpenItems IOI ON IOI.TransferPositionId = IB.TransferPositionId AND IOI.CashDiscount = 0
LEFT JOIN FinanceTransfer FT ON FT.Id = FTP.TransferId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FT.GeneralLedgerAccountId
LEFT JOIN FinanceTaxKeyDetail FTKD ON FTKD.TaxKeyId = FTPAP.TaxKeyId AND ValidFrom <= FTP.StatementDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id = FTKD.TaxKeyId
LEFT JOIN FinanceGroupPartner FGP ON FGP.Id = PD.FinanceGroupPartnerDetailId
WHERE
(FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FTP.StatementDate
) OR FTKD.Id IS NULL)
