SELECT
IB.PostingId
, COALESCE((SELECT MAX(Position) FROM FinancePostingPosition WHERE PostingId = IB.PostingId), 1) + ROW_NUMBER() OVER (PARTITION BY IB.PostingId ORDER BY (SELECT NULL))
, NULL
, 'valid'
, NULL
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FTKD.TaxAccountId ELSE FTKD.NotDueAccountId END
, 1
, CASE WHEN FTK.TaxKeyKindId != 3 THEN FAPT.Name ELSE FAPN.Name END
, IOI.OpenItemId
, CASE WHEN  SUM(FTPAP.Amount) < 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.Amount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.Amount) > 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.Amount)) - SUM(ROUND(ABS(FTPAP.Amount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END
, CASE WHEN  SUM(FTPAP.Amount) > 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.Amount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.Amount) < 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.Amount)) - SUM(ROUND(ABS(FTPAP.Amount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END
, FT.GeneralLedgerAccountId
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN  SUM(FTPAP.Amount) < 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.Amount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.Amount) > 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.Amount)) - SUM(ROUND(ABS(FTPAP.Amount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END - CASE WHEN  SUM(FTPAP.Amount) > 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.Amount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.Amount) < 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.Amount)) - SUM(ROUND(ABS(FTPAP.Amount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END
, NULL
, NULL
, NULL
, NULL
, 0
, CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) IS NOT NULL THEN CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) < 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.ForeignCurrencyAmount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.ForeignCurrencyAmount) > 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.ForeignCurrencyAmount)) - SUM(ROUND(ABS(FTPAP.ForeignCurrencyAmount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END ELSE NULL END
, CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) IS NOT NULL THEN CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) > 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.ForeignCurrencyAmount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.ForeignCurrencyAmount) < 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.ForeignCurrencyAmount)) - SUM(ROUND(ABS(FTPAP.ForeignCurrencyAmount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END ELSE NULL END
, CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) IS NOT NULL THEN CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) < 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.ForeignCurrencyAmount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.ForeignCurrencyAmount) > 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.ForeignCurrencyAmount)) - SUM(ROUND(ABS(FTPAP.ForeignCurrencyAmount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END ELSE NULL END - CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) IS NOT NULL THEN CASE WHEN  SUM(FTPAP.ForeignCurrencyAmount) > 0 AND FTK.TaxKeyKindId = 3 THEN SUM(ROUND(ABS( FTPAP.ForeignCurrencyAmount * (FTKD.TaxPercent/100)),2)) WHEN  SUM(FTPAP.ForeignCurrencyAmount) < 0 AND FTK.TaxKeyKindId != 3 THEN ABS(SUM(FTPAP.ForeignCurrencyAmount)) - SUM(ROUND(ABS(FTPAP.ForeignCurrencyAmount * 100/(100+FTKD.TaxPercent)),2)) ELSE 0 END ELSE NULL END
, CASE WHEN SUM(FTPAP.ForeignCurrencyAmount) IS NOT NULL THEN 0 ELSE NULL END
FROM #InsertedPostings IB
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = IB.TransferPositionId
JOIN FinanceTransferPositionAccountPlan FTPAP ON FTPAP.TransferPositionId = FTP.Id
LEFT JOIN PartnerDetail PD ON PD.Id = FTPAP.PartnerDetailId
LEFT JOIN #InsertedOpenItems IOI ON IOI.TransferPositionId = IB.TransferPositionId AND IOI.CashDiscount = 0
LEFT JOIN FinanceTransfer FT ON FT.Id = FTP.TransferId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceTaxKeyDetail FTKD ON FTKD.TaxKeyId = FTPAP.TaxKeyId AND ValidFrom <= FTP.StatementDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id = FTKD.TaxKeyId
LEFT JOIN FinanceAccountPlan FAPT ON FTKD.TaxAccountId = FAPT.Id
LEFT JOIN FinanceAccountPlan FAPN ON FTKD.NotDueAccountId = FAPN.Id
WHERE FTPAP.TaxKeyId IS NOT NULL AND
(FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FTP.StatementDate
) OR FTKD.Id IS NULL)
GROUP BY FTP.Id
, FT.GeneralLedgerAccountId
, IOI.OpenItemId
, FTP.Amount
, FTP.CustomerPartnerDetailId
, FTKD.TaxPercent
, FTKD.TaxAccountId
, FTKD.NotDueAccountId
, FTK.TaxKeyKindId
, ACS.CompanyCurrencyId
, FTP.Rate
, FAPT.Name
, FAPN.Name
, IB.PostingId
