-- 70.) UPDATE original FinanceOpenItem
UPDATE FinanceOpenItem
SET
StatusId = CASE
WHEN ABS(FTPOI_Sums.TotalAmount) < ABS(FOI.OpenAmount) THEN 'open'
ELSE 'closed'
END,
OpenAmount = CASE
WHEN ABS(FTPOI_Sums.TotalAmount) < ABS(FOI.OpenAmount) THEN FOI.OpenAmount + FTPOI_Sums.TotalAmount
ELSE 0
END
FROM FinanceOpenItem FOI
INNER JOIN (
SELECT
FTPOI.OpenItemId,
SUM(FTPOI.PaymentAmount) + SUM(FTPOI.CashDiscountAmount) + SUM(ISNULL(FTPOI.CurrencyDifference, 0)) AS TotalAmount
FROM FinanceTransferPositionOpenItem FTPOI
INNER JOIN FinanceTransferPosition FTP ON FTP.Id = FTPOI.TransferPositionId
WHERE FTP.TransferId = @parxFinanceTransferId
GROUP BY FTPOI.OpenItemId
) AS FTPOI_Sums ON FTPOI_Sums.OpenItemId = FOI.Id
