, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTP.Amount < 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount)) ELSE ROUND(ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount) * 100) / (100 + FTKD.TaxPercent), 2) END ELSE 0 END ELSE NULL END
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTP.Amount > 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount)) ELSE ROUND(ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount) * 100) / (100 + FTKD.TaxPercent), 2) END ELSE 0 END - CASE WHEN FTP.Amount < 0 THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount)) ELSE ROUND(ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount) * 100) / (100 + FTKD.TaxPercent), 2) END ELSE 0 END ELSE NULL END
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN CASE WHEN FTK.TaxKeyKindId = 3 THEN ROUND(ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount)) * FTKD.TaxPercent/100, 2) ELSE ROUND(ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount)) - ROUND(ABS(SUM(FTPOI.ForeignCurrencyCashDiscountAmount) * 100) / (100 + FTKD.TaxPercent), 2),2) END ELSE NULL END
