LEFT JOIN FinancePosting FB ON FB.Id = FBP.PostingId
LEFT JOIN FinanceTaxKeyDetail FTKD ON FBP.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FB.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
