, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, SourceOpenItemId
, ForeignCurrencyDebit
, ForeignCurrencyCredit
, ForeignCurrencyOpenAmount
, ForeignCurrencyTaxAmount
, Archived
)
-- VALUES FinancePostingPosition
SELECT
IB.PostingId
, ISNULL((
SELECT MAX(FPP2.Position)
FROM FinancePostingPosition FPP2
WHERE FPP2.PostingId = IB.PostingId
), 0) + ROW_NUMBER() OVER (
PARTITION BY IB.PostingId
ORDER BY (SELECT NULL)
)
, FBP.Id
, 'valid'
, NULL
, FBPPrevious.AccountId 
, 1
, FAP.Name
, IOI.OpenItemId
, CASE WHEN FBPPrevious.Credit != 0 THEN FBP.TaxAmount ELSE 0 END
, CASE WHEN FBPPrevious.Debit!= 0 THEN FBP.TaxAmount ELSE 0 END
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN FGPCustomer.CollectiveAccountId ELSE FGPSupplier.CollectiveAccountId END
, 0
, FBP.DivergentPerformanceDate
, NULL
, NULL
, 0
, FBP.CostCenterId
, FBP.CostBearerId
, CASE WHEN FBPPrevious.Credit != 0 THEN FBP.TaxAmount ELSE 0 END - CASE WHEN FBPPrevious.Debit!= 0 THEN FBP.TaxAmount ELSE 0 END
, FBP.VatNumber
, FBP.ProjectId
, NULL
, NULL
, FTPOI.OpenItemId
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN CASE WHEN FBPPrevious.Credit != 0 THEN FBP.ForeignCurrencyTaxAmount ELSE 0 END ELSE NULL END
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN CASE WHEN FBPPrevious.Debit!= 0 THEN FBP.ForeignCurrencyTaxAmount ELSE 0 END ELSE NULL END
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN CASE WHEN FBPPrevious.Credit != 0 THEN FBP.ForeignCurrencyTaxAmount ELSE 0 END - CASE WHEN FBPPrevious.Debit!= 0 THEN FBP.ForeignCurrencyTaxAmount ELSE 0 END ELSE NULL END
, CASE WHEN FOI.ForeignCurrencyId IS NOT NULL THEN 0 ELSE NULL END
, 0
FROM #InsertedPostings IB
JOIN FinancePostingPosition FBP ON FBP.PostingId = IB.PostingId AND FBP.TaxKeyId IS NOT NULL
LEFT JOIN FinancePosting FB ON IB.PostingId = FB.Id
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = IB.TransferPositionId
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id AND FTPOI.CashDiscountAmount != 0 AND FTPOI.OpenItemId = FBP.SourceOpenItemId
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
LEFT JOIN FinancePostingPosition FBPPrevious ON FBPPrevious.PostingId = FOI.PostingId AND FBPPrevious.PartnerDetailId IS NULL AND FBPPrevious.TaxPercent IS NULL
JOIN FinancePostingPosition FBPTaxKey ON FBPTaxKey.PostingId = FOI.PostingId AND FBPTaxKey.TaxKeyId IS NOT NULL
LEFT JOIN FinanceTaxKeyDetail FTKD ON FBPTaxKey.TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FB.ReceiptDate
LEFT JOIN FinanceTaxKey FTK ON FTK.Id= FTKD.TaxKeyId 
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FBPPrevious.AccountId 
LEFT JOIN PartnerDetail PDSupplier ON PDSupplier.Id = FTP.SupplierPartnerDetailId
LEFT JOIN PartnerDetail PDCustomer ON PDCustomer.Id = FTP.CustomerPartnerDetailId
LEFT JOIN FinanceGroupPartner FGPSupplier ON FGPSupplier.Id = PDSupplier.FinanceGroupPartnerDetailId
LEFT JOIN FinanceGroupPartner FGPCustomer ON FGPCustomer.Id = PDCustomer.FinanceGroupPartnerDetailId
LEFT JOIN #InsertedOpenItems IOI ON IOI.TransferPositionId = IB.TransferPositionId AND IOI.CashDiscount = 1
LEFT JOIN FinancePostingPosition FirstFBP ON FirstFBP.Position = 1 AND FirstFBP.PostingId = IB.PostingId
WHERE 
(FTKD.ValidFrom = (
SELECT MAX(ValidFrom)
FROM FinanceTaxKeyDetail
WHERE TaxKeyId = FTKD.TaxKeyId AND ValidFrom <= FB.ReceiptDate
) OR FTKD.Id IS NULL)
GROUP BY
IB.PostingId
, FBP.Id
, FBPPrevious.AccountId 
, FBPPrevious.Credit
, FBPPrevious.Debit
, FAP.Name
, IOI.OpenItemId
, FTP.CustomerPartnerDetailId
, FGPCustomer.CollectiveAccountId
, FGPSupplier.CollectiveAccountId
, FTP.Amount
, FBP.TaxAmount
, FirstFBP.Credit
, FirstFBP.Debit
, CASE WHEN FBPPrevious.Debit != 0 THEN 'NonZero' ELSE 'Zero' END
, CASE WHEN FBPPrevious.Credit != 0 THEN 'NonZero' ELSE 'Zero' END
, FTK.TaxKeyKindId
, FTKD.TaxPercent
, FBP.DivergentPerformanceDate
, FBP.CostCenterId
, FBP.CostBearerId
, FBP.VatNumber
, FBP.ProjectId
, FTPOI.OpenItemId
, FOI.ForeignCurrencyId
, FBP.ForeignCurrencyTaxAmount 
UPDATE FinanceOpenItem SET
PostingId = IB.PostingId
FROM FinanceOpenItem FOI
JOIN #InsertedOpenItems IOI ON IOI.OpenItemId = FOI.Id
JOIN #InsertedPostings IB ON IB.TransferPositionId = IOI.TransferPositionId
-- 85.) UPDATE FinanceAccountPlan Balance
UPDATE FAP
SET FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, FAP.ForeignCurrencyBalance = CASE WHEN FAP.ForeignCurrencyId IS NOT NULL THEN ISNULL(FAP.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT AccountId , SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition FBP
JOIN #InsertedPostings IB ON FBP.PostingId= IB.PostingId
GROUP BY AccountId 
) AS FBP ON FBP.AccountId = FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 86.) UPDATE PartnerDetail Balance
UPDATE PD
SET PD.Balance = PD.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, PD.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL THEN ISNULL(PD.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM PartnerDetail PD
INNER JOIN (
SELECT PartnerDetailId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition FBP
JOIN #InsertedPostings IB ON FBP.PostingId= IB.PostingId
GROUP BY PartnerDetailId
) AS FBP ON FBP.PartnerDetailId = PD.Id
WHERE FBP.PartnerDetailId IS NOT NULL;
-- 87.) UPDATE first FinancePostingPosition with ContraAccount
UPDATE FBP SET 
ContraAccountId = SecondFBP.AccountId 
FROM FinancePostingPosition FBP
JOIN #InsertedPostings IB ON IB.PostingId = FBP.PostingId
LEFT JOIN FinancePostingPosition SecondFBP ON SecondFBP.Position = 2 AND SecondFBP.PostingId = IB.PostingId
WHERE FBP.ContraAccountId IS NULL
-- 88a.) CREATE FinancePosting for Currency Difference
INSERT INTO FinancePosting (
DocNumber
, StatusId
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, BatchNumber
, SourceId
, CreatedBy
)
OUTPUT INSERTED.Id, INSERTED.BatchNumber INTO #InsertedCurrencyDifferencePostings
SELECT
FOI.DocNumber
, 'valid'
, FOI.ReferenceDoc
, FTP.StatementDate
, FTP.PostingPeriodId
, FTPOI.CurrencyDifferenceSubject
, FTPOI.Id
, 'Transfer'
, @parxCreatedBy
FROM FinanceTransferPosition FTP
LEFT JOIN FinanceTransfer FT ON FT.Id = FTP.TransferId
LEFT JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
WHERE FTP.TransferId= @parxFinanceTransferId AND FTPOI.CurrencyDifference != 0 AND FTPOI.CurrencyDifference IS NOT NULL
-- 88b.) CREATE FinanceOpenItem for Currency Difference
INSERT INTO FinanceOpenItem (
StatusId
