'closed'
, 'Transfer'
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL AND FTPOI.CurrencyDifference < 0 THEN 'CW' WHEN FTP.CustomerPartnerDetailId IS NOT NULL AND FTPOI.CurrencyDifference > 0 THEN 'CD' WHEN FTP.SupplierPartnerDetailId IS NOT NULL AND FTPOI.CurrencyDifference< 0 THEN 'SW' WHEN FTP.SupplierPartnerDetailId IS NOT NULL AND FTPOI.CurrencyDifference > 0 THEN 'SD' END
, NULL
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN 'Customer' ELSE 'Supplier' END
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN PDCustomer.PartnerId ELSE PDSupplier.PartnerId END
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN FTP.CustomerPartnerDetailId ELSE FTP.SupplierPartnerDetailId END
, FTP.StatementDate
, FTP.StatementDate
, FT.ReceiptNumber
, FTPOI.CurrencyDifference
, FOI.ForeignCurrencyId
, NULL
, 0
, FTP.StatementDate
, NULL
, NULL
, NULL
, NULL
, 0
, 0
, FTP.Memo1
, FTP.Memo2
, FTPOI.Id
, NULL
, NULL
, NULL
, 0
, 0
, NULL
, NULL
, NULL
, NULL
, 0
, 100
FROM FinanceTransferPosition FTP
LEFT JOIN FinanceTransfer FT ON FT.Id = FTP.TransferId
LEFT JOIN PartnerDetail PDSupplier ON PDSupplier.Id = FTP.SupplierPartnerDetailId
LEFT JOIN PartnerDetail PDCustomer ON PDCustomer.Id = FTP.CustomerPartnerDetailId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
WHERE FTP.TransferId= @parxFinanceTransferId AND FTPOI.CurrencyDifference != 0 AND FTPOI.CurrencyDifference IS NOT NULL
-- First Position
