IB.PostingId
, 2
, NULL
, 'valid'
, NULL
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN FGPCustomer.CollectiveAccountId ELSE FGPSupplier.CollectiveAccountId END
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN 2 ELSE 3 END
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN PCustomer.Matchcode ELSE PSupplier.Matchcode END
, NULL
, CASE WHEN FTPOI.CurrencyDifference > 0 THEN ABS(FTPOI.CurrencyDifference) ELSE 0 END
, CASE WHEN FTPOI.CurrencyDifference < 0 THEN ABS(FTPOI.CurrencyDifference) ELSE 0 END
, FTPOI.CurrencyDifferenceAccountId
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN FTPOI.CurrencyDifference > 0 THEN ABS(FTPOI.CurrencyDifference) ELSE 0 END - CASE WHEN FTPOI.CurrencyDifference < 0 THEN ABS(FTPOI.CurrencyDifference) ELSE 0 END
, NULL
, NULL
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN PDCustomer.Id ELSE PDSupplier.Id END
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN PDCustomer.Id ELSE PDSupplier.Id END
, FTPOI.OpenItemId
, 0
FROM #InsertedCurrencyDifferencePostings IB
LEFT JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.Id = IB.TransferPositionOpenItemId
LEFT JOIN FinanceTransferPosition FTP ON FTP.Id = FTPOI.TransferPositionId
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FTPOI.OpenItemId
LEFT JOIN FinanceTransfer FT ON FT.Id = FTP.TransferId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN PartnerDetail PDSupplier ON PDSupplier.Id = FTP.SupplierPartnerDetailId
LEFT JOIN PartnerDetail PDCustomer ON PDCustomer.Id = FTP.CustomerPartnerDetailId
