LEFT JOIN FinanceGroupPartner FGPCustomer ON FGPCustomer.Id = PDCustomer.FinanceGroupPartnerDetailId
LEFT JOIN Partner PSupplier ON PSupplier.Id = PDSupplier.PartnerId
LEFT JOIN Partner PCustomer ON PCustomer.Id = PDCustomer.PartnerId
-- 88e.) UPDATE FinanceAccountPlan Balance
UPDATE FAP
SET FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, FAP.ForeignCurrencyBalance = CASE WHEN FAP.ForeignCurrencyId IS NOT NULL THEN ISNULL(FAP.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT AccountId , SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition FBP
JOIN #InsertedCurrencyDifferencePostings ICDB ON FBP.PostingId= ICDB.PostingId
GROUP BY AccountId 
) AS FBP ON FBP.AccountId = FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 88f.) UPDATE PartnerDetail Balance
UPDATE PD
SET PD.Balance = PD.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
, PD.ForeignCurrencyBalance = CASE WHEN ForeignCurrencyId IS NOT NULL THEN ISNULL(PD.ForeignCurrencyBalance, 0) + ISNULL(FBP.TotalForeignCurrencyDebit - FBP.TotalForeignCurrencyCredit, 0) ELSE NULL END
FROM PartnerDetail PD
INNER JOIN (
SELECT PartnerDetailId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit, SUM(ForeignCurrencyDebit) AS TotalForeignCurrencyDebit, SUM(ForeignCurrencyCredit) AS TotalForeignCurrencyCredit
FROM FinancePostingPosition FBP
JOIN #InsertedCurrencyDifferencePostings ICDB ON FBP.PostingId= ICDB.PostingId
GROUP BY PartnerDetailId
) AS FBP ON FBP.PartnerDetailId = PD.Id
WHERE FBP.PartnerDetailId IS NOT NULL;
-- 89.) UPDATE FinanceTransfer
UPDATE FinanceTransfer SET
Draft = 0
WHERE Id = @parxFinanceTransferId
-- 90.) CREATE FinanceOpenItemInternalReconciliation
INSERT INTO FinanceOpenItemInternalReconciliation (
PartnerId
, PartnerDetailId
, DateCreated
, CreatedBy
, ModifiedBy
)
OUTPUT INSERTED.Id, INSERTED.ModifiedBy INTO #InsertedReconciliations
SELECT
CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN PDCustomer.PartnerId ELSE PDSupplier.PartnerId END
, CASE WHEN FTP.CustomerPartnerDetailId IS NOT NULL THEN FTP.CustomerPartnerDetailId ELSE FTP.SupplierPartnerDetailId END
, sysutcdatetime()
, @parxCreatedBy
, FTP.Id
FROM FinanceTransferPosition FTP
LEFT JOIN PartnerDetail PDSupplier ON PDSupplier.Id = FTP.SupplierPartnerDetailId
LEFT JOIN PartnerDetail PDCustomer ON PDCustomer.Id = FTP.CustomerPartnerDetailId
WHERE TransferId = @parxFinanceTransferId 
-- update ModifiedBy
UPDATE FinanceOpenItemInternalReconciliation SET
ModifiedBy = NULL
FROM FinanceOpenItemInternalReconciliation 
WHERE Id IN (SELECT ReconciliationId FROM #InsertedReconciliations)
-- 91.) CREATE FinanceOpenItemInternalReconciliationPositions for Inserted Open Items
INSERT INTO FinanceOpenItemInternalReconciliationPosition(
ReconciliationId
, ReconciliationPosition
, OpenItemId
, Amount
)
SELECT
IR.ReconciliationId 
, ROW_NUMBER() OVER (ORDER BY (SELECT NULL))
, IOI.OpenItemId
, CASE WHEN IOI.CashDiscount = 0 THEN FTPOI.PaymentAmount ELSE FTPOI.CashDiscountAmount END
FROM FinanceTransferPositionOpenItem FTPOI
JOIN #InsertedReconciliations IR ON IR.TransferPositionId = FTPOI.TransferPositionId
JOIN #InsertedOpenItems IOI ON IOI.TransferPositionId = FTPOI.TransferPositionId
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = IOI.OpenItemId
-- 92.) CREATE FinanceOpenItemInternalReconciliationPositions for UpdatedOpen Items
INSERT INTO FinanceOpenItemInternalReconciliationPosition(
ReconciliationId
, ReconciliationPosition
, OpenItemId
, Amount
)
SELECT
IR.ReconciliationId 
, COALESCE(MAX(FIIRP.ReconciliationPosition), 0) + ROW_NUMBER() OVER (PARTITION BY IR.ReconciliationId ORDER BY FTPOI.OpenItemId)
, FTPOI.OpenItemId
, (FTPOI.PaymentAmount + FTPOI.CashDiscountAmount + ISNULL(FTPOI.CurrencyDifference, 0)) * -1
FROM FinanceTransferPosition  FTP
JOIN FinanceTransferPositionOpenItem FTPOI ON FTPOI.TransferPositionId = FTP.Id
JOIN #InsertedReconciliations IR ON IR.TransferPositionId = FTP.Id
LEFT JOIN FinanceOpenItemInternalReconciliationPosition FIIRP ON FIIRP.ReconciliationId = IR.ReconciliationId
GROUP BY IR.ReconciliationId, FTPOI.OpenItemId, FTPOI.PaymentAmount, FTPOI.CashDiscountAmount, FTPOI.CurrencyDifference
-- 93.) CREATE FinanceOpenItemInternalReconciliationPositions for Currency Difference Open Items
INSERT INTO FinanceOpenItemInternalReconciliationPosition(
ReconciliationId
, ReconciliationPosition
, OpenItemId
, Amount
)
SELECT
IR.ReconciliationId 
, ROW_NUMBER() OVER (ORDER BY (SELECT NULL))
, IOI.OpenItemId
, FTPOI.CurrencyDifference
FROM FinanceTransferPositionOpenItem FTPOI
JOIN #InsertedReconciliations IR ON IR.TransferPositionId = FTPOI.TransferPositionId
JOIN #InsertedCurrencyDifferenceOpenItems IOI ON IOI.TransferPositionOpenItemId = FTPOI.Id
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = IOI.OpenItemId
DECLARE @DebitSum DECIMAL(19,6) = 0
DECLARE @CreditSum DECIMAL(19,6) = 0
INSERT INTO @InvalidValues (PositionNumber, TEXT, IsError)
SELECT
0
, 'SYSTEM ERROR: Debit does not equal Credit'
, 1
FROM #InsertedPostings IB
WHERE EXISTS (
SELECT 1
FROM FinancePostingPosition FBP
WHERE FBP.PostingId = IB.PostingId
GROUP BY FBP.PostingId
HAVING SUM(FBP.Debit) <> SUM(FBP.Credit)
)
IF (SELECT COUNT(*) FROM @InvalidValues ) != 0 BEGIN
BEGIN
ROLLBACK TRANSACTION
SELECT * FROM @InvalidValues;
RETURN;
END
END
END -- IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
SELECT * FROM @InvalidValues
DROP TABLE #InsertedPostings
DROP TABLE #InsertedOpenItems
DROP TABLE #InsertedReconciliations
DROP TABLE #InsertedCurrencyDifferencePostings
DROP TABLE #InsertedCurrencyDifferenceOpenItems
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC609_FinanceTransfer_Posting--------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC611_FinancePaymentWizard
-- xPROC611_FinancePaymentWizard ----------------------------------------------------------------------
-- Purpose: Create Entries in Procurement Table with needed Articles
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT into FinancePaymentPosition
-- 26.06.26 03:45
@parxCustomer BIT
, @parxSupplier BIT
, @parxSelectedFromCustomer NVARCHAR(30)
, @parxSelectedToCustomer NVARCHAR(30)
, @parxSelectedFromSupplier NVARCHAR(30)
, @parxSelectedToSupplier NVARCHAR(30)
, @parxCustomerValueCredits BIT
, @parxCustomerIncomingPayments BIT
, @parxCustomerOutgoingPayments BIT
, @parxSupplierValueCredits BIT
, @parxSupplierIncomingPayments BIT
, @parxSupplierOutgoingPayments BIT
, @parxCashDiscount BIT
, @parxDueDate DATE
, @parxPaymentDate DATE
AS
BEGIN
SET NOCOUNT ON;
DECLARE @TransactionSuccess BIT = 1;
BEGIN TRY
BEGIN TRANSACTION;
IF NOT EXISTS (
SELECT 1
FROM FinancePaymentPosition
WHERE FinancePaymentId IS NULL
)
BEGIN
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT into FinancePaymentPosition
INSERT INTO FinancePaymentPosition(
FinancePaymentId
, Position
, OpenItemId
, Amount
, CashDiscountAmount
, Purpose
, BankAccountId
, BankNumberId
)
SELECT
NULL
, ROW_NUMBER() OVER (ORDER BY FOI.Id)
, FOI.Id
, (FOI.OpenAmount -
CASE
WHEN @parxPaymentDate <= ISNULL(FOI.CashDiscountDate1, '9999-12-31') THEN ROUND(FOI.OpenAmount * ISNULL(FOI.CashDiscountPercentage1, 0) / 100,2)
WHEN @parxPaymentDate > ISNULL(FOI.CashDiscountDate1, '9999-12-31') AND @parxPaymentDate <= ISNULL(FOI.CashDiscountDate2, '9999-12-31') THEN ROUND(FOI.OpenAmount * ISNULL(FOI.CashDiscountPercentage2, 0) / 100,2)
ELSE 0
END
) * -1
, (CASE
WHEN @parxPaymentDate <= ISNULL(FOI.CashDiscountDate1, '9999-12-31') THEN ROUND(FOI.OpenAmount * ISNULL(FOI.CashDiscountPercentage1, 0) / 100,2)
WHEN @parxPaymentDate > ISNULL(FOI.CashDiscountDate1, '9999-12-31') AND @parxPaymentDate <= ISNULL(FOI.CashDiscountDate2, '9999-12-31') THEN ROUND(FOI.OpenAmount * ISNULL(FOI.CashDiscountPercentage2, 0) / 100,2)
ELSE 0
END) * -1
, FOI.ReferenceDoc
, PBA.Id
, PBA.BankId
FROM FinanceOpenItem FOI
LEFT JOIN Partner P ON FOI.PartnerId = P.Id
LEFT JOIN PartnerTermsOfPayment PTOP ON PTOP.Id = FOI.TermsOfPaymentId
LEFT JOIN PartnerBankAccount PBA ON PBA.PartnerId = P.Id AND PBA.Active = 1
WHERE ((FOI.PartnerTypeId = 'Customer' AND @parxCustomer = 1) OR (FOI.PartnerTypeId = 'Supplier' AND @parxSupplier = 1))
AND (PTOP.PaymentWizard = 1 OR PTOP.PaymentWizard IS NULL) AND FOI.StatusId = 'open' AND FOI.PaymentBlock = 0
AND (
CASE WHEN FOI.PartnerTypeId = 'Supplier' THEN @parxSelectedFromSupplier ELSE @parxSelectedFromCustomer END IS NULL
OR P.Matchcode >= CASE WHEN FOI.PartnerTypeId = 'Supplier' THEN @parxSelectedFromSupplier ELSE @parxSelectedFromCustomer END
)
AND (
CASE WHEN FOI.PartnerTypeId = 'Supplier' THEN @parxSelectedToSupplier ELSE @parxSelectedToCustomer END IS NULL
OR P.Matchcode <= CASE WHEN FOI.PartnerTypeId = 'Supplier' THEN @parxSelectedToSupplier ELSE @parxSelectedToCustomer END
)
AND (@parxCustomerValueCredits = 1 OR FOI.OpenItemTypeId != 'CC')
AND (@parxCustomerIncomingPayments = 1 OR FOI.OpenItemTypeId != 'CD')
AND (@parxCustomerOutgoingPayments = 1 OR FOI.OpenItemTypeId != 'CW')
AND (@parxSupplierValueCredits = 1 OR FOI.OpenItemTypeId != 'SC')
AND (@parxSupplierIncomingPayments = 1 OR FOI.OpenItemTypeId != 'SD')
AND (@parxSupplierOutgoingPayments = 1 OR FOI.OpenItemTypeId != 'SW')
AND (@parxDueDate >= FOI.DueDate OR ( @parxCashDiscount = 1 AND (@parxPaymentDate <= FOI.CashDiscountDate1 OR @parxDueDate <= FOI.CashDiscountDate2)))
AND NOT EXISTS (SELECT 1 FROM FinancePaymentPosition FPP WHERE FPP.OpenItemId = FOI.Id AND FPP.FinancePaymentId IS NULL)
END
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
SET @TransactionSuccess = 0;
DECLARE
@ErrorNumber INT = ERROR_NUMBER(),
@ErrorLine INT = ERROR_LINE(),
@ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
ROLLBACK TRANSACTION;
THROW;
END CATCH
END;
GO
-- END xPROC611_FinancePaymentWizard ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC612_FinancePaymentWizard_CreatePayment
-- xPROC612_FinancePaymentWizard_CreatePayment ----------------------------------------------------------------------
-- Purpose: Create Production or Purchase Orders from Records in Procurement Table
-- 10.) DECLARE, SELECT, CALCULATE
-- 15.) Check for Invalid Values
-- 20.) INSERT into FinancePayment
-- 30.) UPDATE  FinancePaymentPosition
-- 40.) UPDATE FinanceDunningPosition
-- 50.) UPDATE FinanceOpenItem
-- 55.) INSERT FinanceOpenItem per Partner
-- 57.) INSERT FinanceOpenItem per Partner for Cash Discount
-- 60.) INSERT into FinancePosting
-- 61.) INSERT into FinancePostingPosition for Interimaccount
-- 65.) INSERT into FinancePostingPosition for OpenItems
-- 67.) INSERT into FinancePostingPosition for Interimaccount for Cashdiscount
-- 69.) INSERT into FinancePostingPosition for Interimaccount for Cashdiscount Tax
-- 71.) UPDATE inserted FinancePostingPosition with Contra Account
-- 75.) UPDATE inserted FinanceOpenItems with PostingId
-- 80.) INSERT INTO FinanceOpenItemInternalReconciliation
-- 81.) INSERT INTO FinanceOpenItemInternalReconciliationPositions
-- 85.) UPDATE FinanceAccountPlan Balance
-- 90.) RETURN
-- 26.06.26 03:45
@parxPaymentDate DATE, 
@parxCompanyBankAccountId NVARCHAR(34),
@parxCreatedById INT
AS
BEGIN
SET NOCOUNT ON;
DECLARE @TransactionSuccess BIT = 1;
BEGIN TRY
BEGIN TRANSACTION;
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @InvalidValues TABLE (PositionNumber INT, TEXT NVARCHAR(100));
CREATE TABLE #InsertedPayments (
PaymentId INT,
PartnerTypeId NVARCHAR(50),
DirectDebitTypeId INT
);
CREATE TABLE #InsertedPostings (
PostingId INT,
PaymentId INT
);
CREATE TABLE #InsertedOpenItems (
OpenItemId INT,
PaymentId INT,
CashDiscountAmount DECIMAL(19,6),
PartnerDetailId INT
);
CREATE TABLE #InsertedReconciliations (
ReconciliationId INT
);
CREATE TABLE #InsertedCashDiscountPostingPositions
(
PostingId INT
, OpenItemId INT
, TaxKeyId INT
, ParentPositionId INT
);
DECLARE @CurrentPostingPeriodId INT
SET @CurrentPostingPeriodId = dbo.xFUNCTION001_GetCurrentPostingPeriodId()
-- 15.) Check for Invalid Values
INSERT INTO @InvalidValues (PositionNumber, TEXT)
SELECT 
Position
, 'Partner Bank Account Information Is Missing'
FROM FinancePaymentPosition FPP
WHERE FPP.FinancePaymentId IS NULL
AND (FPP.BankAccountId IS NULL OR FPP.BankNumberId IS NULL)
INSERT INTO @InvalidValues (PositionNumber, TEXT)
SELECT 
0
, 'Company Bank Account has no Interim Account assigned'
FROM FinanceCompanyBankAccount
WHERE Id = @parxCompanyBankAccountId AND InterimAccountId IS NULL
IF (SELECT COUNT(*) FROM @InvalidValues ) = 0 BEGIN
-- 20.) INSERT into FinancePayment
INSERT INTO FinancePayment(
PaymentDate
, DirectDebitTypeId
, CompanyBankAccountId
, Amount
, Transferred
, Info
) 
OUTPUT INSERTED.Id, 'Customer', INSERTED.DirectDebitTypeId INTO #InsertedPayments
SELECT DISTINCT
@parxPaymentDate
, PBA.DirectDebitId
, @parxCompanyBankAccountId
, 0
, 0
, NULL
FROM FinancePaymentPosition FPP
JOIN FinanceOpenItem FOI ON FOI.Id = FPP.OpenItemId
LEFT JOIN Partner P ON P.Id = FOI.PartnerId
LEFT JOIN PartnerBankAccount PBA ON PBA.PartnerId = P.Id AND PBA.Active = 1
WHERE FPP.FinancePaymentId IS NULL
AND FOI.PartnerTypeId = 'Customer'
INSERT INTO FinancePayment(
PaymentDate
, DirectDebitTypeId
, CompanyBankAccountId
, Amount
, Transferred
, Info
) 
OUTPUT INSERTED.Id, 'Supplier', INSERTED.DirectDebitTypeId INTO #InsertedPayments
SELECT DISTINCT
@parxPaymentDate
, PBA.DirectDebitId
, @parxCompanyBankAccountId
, 0
, 0
, NULL
FROM FinancePaymentPosition FPP
JOIN FinanceOpenItem FOI ON FOI.Id = FPP.OpenItemId
LEFT JOIN Partner P ON P.Id = FOI.PartnerId
LEFT JOIN PartnerBankAccount PBA ON PBA.PartnerId = P.Id AND PBA.Active = 1
WHERE FPP.FinancePaymentId IS NULL
AND FOI.PartnerTypeId = 'Supplier'
-- 30.) UPDATE  FinancePaymentPosition
UPDATE FPP
SET FPP.FinancePaymentId = IP.PaymentId
FROM FinancePaymentPosition FPP
JOIN FinanceOpenItem FOI ON FPP.OpenItemId = FOI.Id
LEFT JOIN Partner P ON P.Id = FOI.PartnerId
LEFT JOIN PartnerBankAccount PBA ON PBA.PartnerId = P.Id AND PBA.Active = 1
JOIN #InsertedPayments IP
ON FOI.PartnerTypeId = IP.PartnerTypeId
AND COALESCE(IP.DirectDebitTypeId, -1) = COALESCE(PBA.DirectDebitId, -1)
WHERE FPP.FinancePaymentId IS NULL;
-- 40.) UPDATE FinancePayment
UPDATE FP
SET FP.Amount = (
SELECT SUM(FPP.Amount)
FROM FinancePaymentPosition FPP
WHERE FPP.FinancePaymentId = FP.Id
)
FROM FinancePayment FP
JOIN #InsertedPayments IP ON FP.Id = IP.PaymentId;
-- 50.) UPDATE FinanceOpenItem
UPDATE FinanceOpenItem SET
OpenAmount = FOI.OpenAmount + FPP.Amount + FPP.CashDiscountAmount
, StatusId = CASE WHEN FOI.OpenAmount = (FPP.Amount + FPP.CashDiscountAmount) * -1 THEN 'closed' ELSE 'open' END
FROM FinanceOpenItem FOI
JOIN FinancePaymentPosition FPP ON FOI.Id = FPP.OpenItemId
JOIN #InsertedPayments IP ON IP.PaymentId = FPP.FinancePaymentId
WHERE IP.PaymentId IS NOT NULL
-- 55.) INSERT FinanceOpenItem per Partner
INSERT INTO FinanceOpenItem (
StatusId
, OpenItemOriginId
, OpenItemTypeId
, DocTypeId
, PartnerTypeId
, PartnerId
, PartnerDetailId
, PostingDate
, DocDate
, DocNumber
, Amount
, ForeignCurrencyId 
, Rate
, Discountable
, DueDate
, CashDiscountDate1
, CashDiscountPercentage1
, CashDiscountDate2
, CashDiscountPercentage2
, CashDiscountAmount
, OpenAmount
, Remark1
, Remark2
, ReferenceDoc
, ContraAccountId
, CostCenterId
, CostBearerId
, DunningBlock
, PaymentBlock
, DunningLevelId
, TaxSplit
, DocSplit
, TermsOfPaymentId
, Archived
, ProbabilityOfPayment
)
OUTPUT INSERTED.Id, INSERTED.DocNumber, INSERTED.CashDiscountAmount, INSERTED.PartnerDetailId INTO #InsertedOpenItems
SELECT 'closed'
, 'Transfer'
, CASE WHEN FOI.PartnerTypeId = 'Customer' THEN 'CD' WHEN FOI.PartnerTypeId = 'Supplier' THEN 'SW' ELSE NULL END
, NULL
, FOI.PartnerTypeId
, FOI.PartnerId
, FOI.PartnerDetailId
, @parxPaymentDate
, @parxPaymentDate
, FP.Id
, SUM(FPP.Amount)
, FOI.ForeignCurrencyId 
, FOI.Rate
, 0
, @parxPaymentDate
, NULL
, NULL
, NULL
, NULL
, SUM(FPP.CashDiscountAmount)
, 0
, FP.Id
, NULL
, FP.Id
, NULL
, NULL
, NULL
, 0
, 0
, NULL
, NULL
, NULL
, NULL
, 0
, 100
FROM FinancePaymentPosition FPP
LEFT JOIN FinancePayment FP ON FP.Id = FPP.FinancePaymentId 
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FPP.OpenItemId
LEFT JOIN PartnerDetail PD ON PD.Id = FOI.PartnerDetailId
LEFT JOIN FinanceCompanyBankAccount FCBA ON FCBA.Id = @parxCompanyBankAccountId
JOIN #InsertedPayments IP ON FPP.FinancePaymentId = IP.PaymentId
GROUP BY FOI.PartnerDetailId,
FOI.PartnerTypeId,
FOI.PartnerId,
FOI.ForeignCurrencyId ,
FOI.Rate,
FP.Id
-- 57.) INSERT FinanceOpenItem per Partner for Cash Discount
INSERT INTO FinanceOpenItem (
StatusId
, OpenItemOriginId
, OpenItemTypeId
, DocTypeId
, PartnerTypeId
, PartnerId
, PartnerDetailId
, PostingDate
, DocDate
, DocNumber
, Amount
, ForeignCurrencyId 
, Rate
, Discountable
