, CASE WHEN SUM(FPP.Amount) + SUM(FPP.CashDiscountAmount) > 0 THEN ABS(ROUND(SUM(ROUND(FPP.CashDiscountAmount,2)) * ((SUM(FBP.Debit) +SUM(FBP.Credit)) / D.TotalPriceSumGross),2)) ELSE 0 END
