-- 81.) INSERT INTO FinanceOpenItemInternalReconciliationPositions
INSERT INTO FinanceOpenItemInternalReconciliationPosition(
ReconciliationId
, ReconciliationPosition
, OpenItemId
, Amount
)
SELECT
FOIR.Id
, ROW_NUMBER() OVER (PARTITION BY FOIR.Id ORDER BY FOI.Id)
, FOI.Id
, CASE WHEN FPP.Id IS NOT NULL THEN (FPP.Amount + FPP.CashDiscountAmount) * -1 ELSE FOI.Amount END
FROM FinanceOpenItem FOI
LEFT JOIN FinancePaymentPosition FPP ON FOI.Id = FPP.OpenItemId
LEFT JOIN #InsertedPayments IP ON IP.PaymentId = FPP.FinancePaymentId
LEFT JOIN FinanceOpenItemInternalReconciliation FOIR ON FOIR.PartnerDetailId = FOI.PartnerDetailId AND FOIR.Id IN (SELECT ReconciliationId FROM #InsertedReconciliations )
WHERE FOI.Id IN (SELECT OpenItemId FROM #InsertedOpenItems) OR IP.PaymentId IS NOT NULL
-- 85.) UPDATE FinanceAccountPlan Balance
UPDATE FAP
SET FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT AccountId , SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
FROM #InsertedPostings IB
JOIN FinancePostingPosition FBP ON IB.PostingId = FBP.PostingId
GROUP BY AccountId 
) AS FBP ON FBP.AccountId = FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 86.) UPDATE PartnerDetail Balance
UPDATE PD
SET PD.Balance = PD.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
FROM PartnerDetail PD
INNER JOIN (
SELECT PartnerDetailId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
FROM #InsertedPostings IB
JOIN FinancePostingPosition FBP ON IB.PostingId = FBP.PostingId
GROUP BY PartnerDetailId
) AS FBP ON FBP.PartnerDetailId = PD.Id
WHERE FBP.PartnerDetailId IS NOT NULL;
DECLARE @DebitSum DECIMAL(19,6)
DECLARE @CreditSum DECIMAL(19,6)
SELECT
@DebitSum = SUM(Debit)
, @CreditSum = SUM(Credit)
FROM FinancePostingPosition FBP
WHERE FBP.PostingId IN (SELECT PostingId FROM #InsertedPostings)
GROUP BY
FBP.PostingId
