CREATE OR ALTER PROCEDURE 
xPROC614_FinancePaymentWizard_Amount
-- xPROC614_FinancePaymentWizard_Amount-----------------------------------------------------------------------------------------------
-- PURPOSE: Update the Amount with passed value
@parxPaymentPositionId INT,
@parxAmount DECIMAL(19,6) = NULL
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE FinancePaymentPosition 
SET 
Amount = @parxAmount  
, CashDiscountAmount = CASE WHEN XFPP.OpenAmount < 0 THEN ABS(ISNULL(XFPP.OpenAmount, 0)) - @parxAmount ELSE (ISNULL(XFPP.OpenAmount, 0) + @parxAmount) * -1 END
FROM FinancePaymentPosition FPP
LEFT JOIN xVIEW640_FinancePaymentPosition XFPP ON XFPP.Id = FPP.Id
WHERE FPP.Id = @parxPaymentPositionId;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END;
GO
-- END xPROC614_FinancePaymentWizard_Amount----------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
