CREATE OR ALTER PROCEDURE 
xPROC615_FinanceOpenItemInternalReconciliation_Posting
-- xPROC615_FinanceOpenItemInternalReconciliation_Posting
-- Creator: MH 
-- Created: 2024-08-08
-- Purpose: Create a OpenItem Record for this posted Posting
-- Changed:
-- 20.) CREATE FinanceOpenItemInternalReconciliation (HEADER)
-- 30.) CREATE FinanceOpenItemInternalReconciliationPositions (Positions)
-- 40.) UPDATE Open Items
@parxTvpFinanceOpenItemInternalReconciliation dbo.xTYPE_FinanceOpenItemInternalReconciliation READONLY,
@parxTvpFinanceOpenItemInternalReconciliationPosition dbo.xTYPE_FinanceOpenItemInternalReconciliationPosition READONLY
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 20.) CREATE FinanceOpenItemInternalReconciliation (HEADER)
INSERT INTO FinanceOpenItemInternalReconciliation
(
PartnerId
, PartnerDetailId
, DateCreated
, CreatedBy
)
-- VALUES FinancePosting
SELECT
PartnerId
, PartnerDetailId
, sysutcdatetime()
, CreatedBy
FROM @parxTvpFinanceOpenItemInternalReconciliation 
DECLARE @NewFinanceOpenItemInternalReconciliationId INT  = SCOPE_IDENTITY();
-- 30.) CREATE FinanceOpenItemInternalReconciliationPositions (Positions)
INSERT INTO FinanceOpenItemInternalReconciliationPosition
(
ReconciliationId
, ReconciliationPosition
, OpenItemId
, Amount
)
-- VALUES FinancePosting
SELECT
@NewFinanceOpenItemInternalReconciliationId
, ReconciliationPosition
, OpenItemId
, Amount
FROM @parxTvpFinanceOpenItemInternalReconciliationPosition
-- 40.) UPDATE Open Items
UPDATE FinanceOpenItem SET 
OpenAmount = OpenAmount - FOIIRP.Amount
, StatusId = CASE WHEN OpenAmount - FOIIRP.Amount = 0 THEN 'closed' ELSE StatusId END
FROM FinanceOpenItem FOI
LEFT JOIN FinanceOpenItemInternalReconciliationPosition FOIIRP ON FOIIRP.OpenItemId = FOI.Id
WHERE FOIIRP.ReconciliationId = @NewFinanceOpenItemInternalReconciliationId
SELECT @NewFinanceOpenItemInternalReconciliationId NewFinanceOpenItemInternalReconciliationId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC615_FinanceOpenItemInternalReconciliation_Posting-------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
