CREATE OR ALTER PROCEDURE 
xPROC615D_FinanceOpenItemInternalReconciliation_Deleting
-- xPROC615D_FinanceOpenItemInternalReconciliation_Deleting
-- Creator: JH 
-- Created: 2024-08-08
-- Purpose: Delete Reconciliation and update Open Items
-- Changed:
-- 70.) UPDATE FinanceOpenItems
-- 80.) DELETE FinanceOpenItemInternalReconciliationPositions
-- 81.) DELETE FinanceOpenItemInternalReconciliation
@parxFinanceOpenItemInternalReconciliationId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 70.) UPDATE FinanceOpenItems
UPDATE FinanceOpenItem SET
StatusId = 'open'
, OpenAmount = FOI.OpenAmount + FOIIRP.Amount
FROM FinanceOpenItem FOI
LEFT JOIN FinanceOpenItemInternalReconciliationPosition FOIIRP ON FOIIRP.OpenItemId = FOI.Id
WHERE FOIIRP.ReconciliationId = @parxFinanceOpenItemInternalReconciliationId
-- 80.) DELETE FinanceOpenItemInternalReconciliationPositions
DELETE FROM FinanceOpenItemInternalReconciliationPosition WHERE ReconciliationId = @parxFinanceOpenItemInternalReconciliationId
-- 81.) DELETE FinanceOpenItemInternalReconciliation
DELETE FROM FinanceOpenItemInternalReconciliation WHERE Id = @parxFinanceOpenItemInternalReconciliationId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
