CREATE OR ALTER PROCEDURE 
xPROC620_FinanceAccountInternalReconciliation_Posting
-- xPROC620_FinanceAccountInternalReconciliation_Posting
-- Creator: JH 
-- Created: 2024-12-16
-- Purpose: Create a OpenItem Record for this posted Posting
-- Changed:
-- 20.) CREATE FinanceAccountInternalReconciliation (HEADER)
-- 30.) CREATE FinanceOpenItemInternalReconciliationPositions (Positions)
-- 40.) UPDATE Open Items
@parxTvpFinanceAccountInternalReconciliation dbo.xTYPE_FinanceAccountInternalReconciliation READONLY,
@parxTvpFinanceAccountInternalReconciliationPosition dbo.xTYPE_FinanceAccountInternalReconciliationPosition READONLY
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 20.) CREATE FinanceOpenItemInternalReconciliation (HEADER)
INSERT INTO FinanceAccountInternalReconciliation
(
AccountId
, DateCreated
, CreatedBy
)
-- VALUES FinancePosting
SELECT
AccountId
, sysutcdatetime()
, CreatedBy
FROM @parxTvpFinanceAccountInternalReconciliation 
DECLARE @NewFinanceAccountInternalReconciliationId INT = SCOPE_IDENTITY();
-- 30.) CREATE FinanceAccountInternalReconciliationPositions (Positions)
INSERT INTO FinanceAccountInternalReconciliationPosition
(
ReconciliationId
, ReconciliationPosition
, PostingPositionId
, Amount
)
-- VALUES FinancePosting
SELECT
@NewFinanceAccountInternalReconciliationId
, ReconciliationPosition
, PostingPositionId
, Amount
FROM @parxTvpFinanceAccountInternalReconciliationPosition
-- 40.) UPDATE Open Items
UPDATE FinancePostingPosition SET 
OpenAmount = OpenAmount - FAIRP.Amount
FROM FinancePostingPosition FBP
LEFT JOIN FinanceAccountInternalReconciliationPosition FAIRP ON FAIRP.PostingPositionId= FBP.Id
WHERE FAIRP.ReconciliationId = @NewFinanceAccountInternalReconciliationId
SELECT @NewFinanceAccountInternalReconciliationId NewFinanceAccountInternalReconciliationId
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
