CREATE OR ALTER PROCEDURE 
xPROC630_FinanceOpeningBalance_Posting
-- Creator: JH 
-- Created: 2025-05-08
-- Purpose: Post the Postings from FinanceOpeningBalance
-- Changed:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 60.) INSERT new FinanceOpenItem for Customer and Supplier
-- 80.) CREATE FinancePosting
-- 81.) CREATE first FinancePostingPosition
-- 82.) CREATE second FinancePostingPosition
-- 85.) UPDATE FinanceAccountPlan Balance
-- 86.) UPDATE PartnerDetail Balance
-- 87.) UPDATE FinanceOpeningBalance
-- 90.) RETURN
@parxFinanceOpeningBalanceId INT,
@parxCreatedBy INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @InvalidPositions TABLE (PositionId INT, AccountId INT, AccountName NVARCHAR(30), TEXT NVARCHAR(100));
CREATE TABLE #InsertedPostings (
PostingId INT
, PositionId INT
);
DECLARE @PartnerTypeId NVARCHAR(10)
SELECT
@PartnerTypeId = PartnerTypeId 
FROM FinanceOpeningBalance
WHERE Id = @parxFinanceOpeningBalanceId 
-- 20.) VALIDATION
INSERT INTO @InvalidPositions (PositionId , AccountId , AccountName , TEXT)
SELECT
FOBP.Id
, FOBP.AccountId 
, FOBP.Name
, 'Amount has to be unequal to zero'
FROM xVIEW635_FinanceOpeningBalancePosition FOBP
WHERE FOBP.Amount = 0 AND FOBP.OpeningBalanceId = @parxFinanceOpeningBalanceId
INSERT INTO @InvalidPositions (PositionId , AccountId , AccountName , TEXT)
SELECT
0
, 0
, 0
, 'Posting Period is not open'
FROM FinanceOpeningBalance FOB
LEFT JOIN FinancePostingPeriod FBP ON FBP.Id = FOB.PostingPeriodId
WHERE FOB.Id= @parxFinanceOpeningBalanceId AND FBP.StatusId != 'open'
INSERT INTO @InvalidPositions (PositionId , AccountId , AccountName , TEXT)
SELECT
FOBP.Id
, FOBP.AccountId 
, FOBP.Name
, 'Account has been added multiple times'
FROM xVIEW635_FinanceOpeningBalancePosition FOBP
LEFT JOIN xVIEW635_FinanceOpeningBalancePosition DuplicateFOBP ON DuplicateFOBP.AccountId= FOBP.AccountId AND ISNULL(DuplicateFOBP.PartnerDetailId,-1) = ISNULL(FOBP.PartnerDetailId,-1) AND DuplicateFOBP.Id != FOBP.Id AND DuplicateFOBP.OpeningBalanceId = FOBP.OpeningBalanceId
WHERE FOBP.OpeningBalanceId = @parxFinanceOpeningBalanceId AND DuplicateFOBP.Id IS NOT NULL
INSERT INTO @InvalidPositions (PositionId , AccountId , AccountName , TEXT)
SELECT
FOBP.Id
, FOBP.AccountId 
, FOBP.Name
, 'Only Accounts assigned to Balance can be selected'
FROM xVIEW635_FinanceOpeningBalancePosition FOBP
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FOBP.AccountId
WHERE FOBP.OpeningBalanceId = @parxFinanceOpeningBalanceId AND FAP.AssignmentId != 2
IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
-- 60.) INSERT new FinanceOpenItem for Customer and Supplier
IF (@PartnerTypeId IS NOT NULL)
BEGIN
INSERT INTO FinanceOpenItem (
StatusId
, OpenItemOriginId
, OpenItemTypeId
, DocTypeId
, PartnerTypeId
, PartnerId
, PartnerDetailId
, PostingDate
, DocDate
, DocNumber
, Amount
, ForeignCurrencyId 
, Rate
, Discountable
, DueDate
, CashDiscountDate1
, CashDiscountPercentage1
, CashDiscountDate2
, CashDiscountPercentage2
, CashDiscountAmount
, OpenAmount
, Remark1
, Remark2
, ReferenceDoc
, ContraAccountId
, CostCenterId
, CostBearerId
, DunningBlock
, PaymentBlock
, DunningLevelId
, TaxSplit
, DocSplit
, TermsOfPaymentId
, Archived
, ProbabilityOfPayment
)
SELECT
'open'
, 'Posting'
, CASE WHEN @PartnerTypeId = 'Customer' THEN CASE WHEN FOBP.Amount> 0 THEN 'CI' ELSE 'CC' END ELSE CASE WHEN FOBP.Amount> 0 THEN 'SI' ELSE 'SC' END END
, NULL
, @PartnerTypeId
, PD.PartnerId
, PD.Id
, FOB.ReceiptDate
, FOB.ReceiptDate
, FOB.ReceiptNumber
, CASE WHEN @PartnerTypeId = 'Supplier' THEN FOBP.Amount * -1 ELSE FOBP.Amount END
, NULL
, 1
, 0
, FOB.ReceiptDate
, NULL
, NULL
, NULL
, NULL
, 0
, CASE WHEN @PartnerTypeId = 'Supplier' THEN FOBP.Amount * -1 ELSE FOBP.Amount END
, NULL
, NULL
, FOB.ReceiptNumber
, FOB.ContraAccountId
, NULL
, NULL
, 0
, 0
, NULL
, NULL
, NULL 
, NULL
, 0
, 100
FROM FinanceOpeningBalancePosition FOBP
LEFT JOIN FinanceOpeningBalance FOB ON FOB.Id = FOBP.OpeningBalanceId
LEFT JOIN PartnerDetail AS PD ON FOBP.PartnerDetailId = PD.Id
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
WHERE FOB.Id = @parxFinanceOpeningBalanceId
END -- IF @parxAccountType = 'Customer' OR @parxAccountType = 'Supplier'
-- 80.) CREATE FinancePosting
INSERT INTO FinancePosting (
DocNumber
, StatusId
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, CreatedBy
, SourceId
, Opening
, Name
)
OUTPUT INSERTED.Id, INSERTED.Name INTO #InsertedPostings
SELECT
FOB.ReceiptNumber
, 'valid'
, FOB.ReceiptNumber
, FOB.ReceiptDate
, FOB.PostingPeriodId
, FOB.ReceiptNumber
, @parxCreatedBy 
, 'Opening'
, 1
, FOBP.Id
FROM FinanceOpeningBalancePosition FOBP
LEFT JOIN FinanceOpeningBalance FOB ON FOB.Id = FOBP.OpeningBalanceId
WHERE FOB.Id = @parxFinanceOpeningBalanceId
-- 81.) CREATE first FinancePostingPosition
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, SourceOpenItemId
, Archived
)
-- VALUES FinancePostingPosition
SELECT
IB.PostingId 
, 1
, NULL
, 'valid'
, NULL
, CASE WHEN FOB.PartnerTypeId IS NULL THEN FOBP.AccountId ELSE FGP.CollectiveAccountId END
, 1
, CASE WHEN FOB.PartnerTypeId IS NULL THEN FAP.Name ELSE P.Matchcode END
, NULL
, CASE WHEN (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END
, CASE WHEN (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END
, FOB.ContraAccountId
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END - CASE WHEN (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END
, NULL
, NULL
, PD.Id
, PD.Id
, NULL
, 0
FROM #InsertedPostings IB
LEFT JOIN FinanceOpeningBalancePosition FOBP ON FOBP.Id = IB.PositionId
LEFT JOIN FinanceOpeningBalance FOB ON FOB.Id = FOBP.OpeningBalanceId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FOBP.AccountId
LEFT JOIN PartnerDetail AS PD ON FOBP.PartnerDetailId = PD.Id
LEFT JOIN FinanceGroupPartner FGP ON PD.FinanceGroupPartnerDetailId= FGP.Id
LEFT JOIN Partner P ON PD.PartnerId = P.Id
-- 82.) CREATE second FinancePostingPosition
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, SourceOpenItemId
, Archived
)
-- VALUES FinancePostingPosition
SELECT
IB.PostingId 
, 2
, NULL
, 'valid'
, NULL
, FOB.ContraAccountId
, 1
, FAP.Name
, NULL
, CASE WHEN (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END
, CASE WHEN (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END
, CASE WHEN FOB.PartnerTypeId IS NULL THEN FOBP.AccountId ELSE FGP.CollectiveAccountId END
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END - CASE WHEN (FOBP.Amount > 0 AND ISNULL(FOB.PartnerTypeId, 0) != 'Supplier') OR (FOBP.Amount < 0 AND ISNULL(FOB.PartnerTypeId, 0) = 'Supplier') THEN ABS(FOBP.Amount) ELSE 0 END
, NULL
, NULL
, NULL
, NULL
, NULL
, 0
FROM #InsertedPostings IB
LEFT JOIN FinanceOpeningBalancePosition FOBP ON FOBP.Id= IB.PositionId
LEFT JOIN FinanceOpeningBalance FOB ON FOB.Id = FOBP.OpeningBalanceId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FOB.ContraAccountId
LEFT JOIN PartnerDetail AS PD ON FOBP.PartnerDetailId = PD.Id
LEFT JOIN FinanceGroupPartner FGP ON PD.FinanceGroupPartnerDetailId= FGP.Id
-- 85.) UPDATE FinanceAccountPlan Balance
UPDATE FAP
SET FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT FBP.AccountId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
FROM FinancePostingPosition FBP
JOIN #InsertedPostings IB ON IB.PostingId = FBP.PostingId
GROUP BY FBP.AccountId
) AS FBP ON FBP.AccountId= FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 86.) UPDATE PartnerDetail Balance
UPDATE PD
SET PD.Balance = PD.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
FROM PartnerDetail PD
INNER JOIN (
SELECT PartnerDetailId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
FROM FinancePostingPosition FBP
JOIN #InsertedPostings IB ON IB.PostingId = FBP.PostingId
GROUP BY PartnerDetailId
) AS FBP ON FBP.PartnerDetailId = PD.Id
WHERE FBP.PartnerDetailId IS NOT NULL;
-- 87.) UPDATE FinanceOpeningBalance
UPDATE FinanceOpeningBalance
SET
Draft = 0
WHERE Id = @parxFinanceOpeningBalanceId
-- 90.) RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
SELECT * FROM @InvalidPositions 
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
--- END xPROC630_FinanceOpeningBalance_Posting------------------------------------
