SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC640N_FinanceClosingPosting
-- 26.06.26 03:45
@parxAccountantId INT,
@parxClosingAccountId INT,
@parxOpeningAccountId INT,
@parxClosingPostingPeriodId INT,
@parxOpeningPostingPeriodId INT,
@parxClosingDate DATE,
@parxOpeningDate DATE,
@parxCreatedBy INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @newxFinanceClosingPostingId INT
-- 20.) INSERT INTO FinanceClosingPosting
INSERT INTO FinanceClosingPosting(
AccountantId
, ClosingAccountId
, OpeningAccountId
, ClosingPostingPeriodId
, OpeningPostingPeriodId
, ClosingDate
, OpeningDate
, CreatedBy
)
-- VALUES
VALUES (
@parxAccountantId 
, @parxClosingAccountId
, @parxOpeningAccountId
, @parxClosingPostingPeriodId
, @parxOpeningPostingPeriodId
, @parxClosingDate
, @parxOpeningDate
, @parxCreatedBy
)
SET @newxFinanceClosingPostingId = SCOPE_IDENTITY()
INSERT INTO FinanceClosingPostingPosition(
ClosingPostingId
, AccountId
, Amount
)
SELECT
@newxFinanceClosingPostingId
, FAP.Id
, FAP.Balance
- ISNULL(SUM(CASE WHEN FB.ReceiptDate > @parxClosingDate THEN FBP.Debit ELSE 0 END), 0) + ISNULL(SUM(CASE WHEN FB.ReceiptDate > @parxClosingDate THEN FBP.Credit ELSE 0 END), 0)
FROM FinanceAccountPlan FAP
LEFT JOIN FinancePostingPosition FBP ON FBP.AccountId = FAP.Id
LEFT JOIN FinancePosting FB ON FB.Id = FBP.PostingId
WHERE FAP.Balance != 0 AND FAP.AssignmentId = 3
GROUP BY
 FAP.Id
,  FAP.Balance
HAVING FAP.Balance
- ISNULL(SUM(CASE WHEN FB.ReceiptDate > @parxClosingDate THEN FBP.Debit ELSE 0 END), 0) + ISNULL(SUM(CASE WHEN FB.ReceiptDate > @parxClosingDate THEN FBP.Credit ELSE 0 END), 0) != 0;
UPDATE FCB
SET TotalAmount = Sub.TotalAmount
FROM FinanceClosingPosting FCB
INNER JOIN (
SELECT ClosingPostingId, SUM(Amount) AS TotalAmount
FROM FinanceClosingPostingPosition
WHERE ClosingPostingId = @newxFinanceClosingPostingId
GROUP BY ClosingPostingId
) AS Sub ON FCB.Id = Sub.ClosingPostingId
WHERE FCB.Id = @newxFinanceClosingPostingId;
-- 90.) RETURN
SELECT @newxFinanceClosingPostingId AS NewFinanceClosingPostingId
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
