CREATE OR ALTER PROCEDURE 
xPROC640_FinanceClosingPosting_Posting
-- Creator: JH 
-- Created: 2025-05-08
-- Purpose: Post the Postings from FinanceClosingPosting
-- Changed:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) VALIDATION
-- 70.) CREATE FinancePosting Closing
-- 71.) CREATE first FinancePostingPosition Closing
-- 72.) CREATE second FinancePostingPosition Closing
-- 80.) CREATE FinancePosting Opening
-- 81.) CREATE first FinancePostingPosition Opening
-- 82.) CREATE second FinancePostingPosition Opening
-- 85.) UPDATE FinanceAccountPlan Balance
-- 86.) UPDATE FinanceAccountPlan Balance Opening
-- 87.) UPDATE FinanceClosingPosting
-- 90.) RETURN
@parxFinanceClosingPostingId INT,
@parxCreatedBy INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @InvalidPositions TABLE (PositionId INT, AccountId INT, AccountName NVARCHAR(30), TEXT NVARCHAR(100));
CREATE TABLE #InsertedPostings (
PostingId INT
, PositionId INT
);
CREATE TABLE #InsertedOpeningPostings (
PostingId INT
, PositionId INT
);
-- 20.) VALIDATION
INSERT INTO @InvalidPositions (PositionId , AccountId , AccountName , TEXT)
SELECT
0
, 0
, 0
, 'Closing Posting Period is not open'
FROM FinanceClosingPosting FCB
LEFT JOIN FinancePostingPeriod ClosingFBP ON ClosingFBP.Id = FCB.ClosingPostingPeriodId
WHERE FCB.Id= @parxFinanceClosingPostingId AND ClosingFBP.StatusId != 'open'
INSERT INTO @InvalidPositions (PositionId , AccountId , AccountName , TEXT)
SELECT
0
, 0
, 0
, 'Opening Posting Period is not open'
FROM FinanceClosingPosting FCB
LEFT JOIN FinancePostingPeriod OpeningFBP ON OpeningFBP.Id = FCB.OpeningPostingPeriodId
WHERE FCB.Id= @parxFinanceClosingPostingId AND OpeningFBP.StatusId != 'open'
INSERT INTO @InvalidPositions (PositionId , AccountId , AccountName , TEXT)
SELECT
FCBP.Id
, FCBP.AccountId 
, FCBP.Matchcode
, 'Account has been added multiple times'
FROM xVIEW645_FinanceClosingPostingPosition FCBP
LEFT JOIN xVIEW645_FinanceClosingPostingPosition DuplicateFCBP ON DuplicateFCBP.AccountId= FCBP.AccountId AND DuplicateFCBP.Id != FCBP.Id AND DuplicateFCBP.ClosingPostingId= FCBP.ClosingPostingId
WHERE FCBP.ClosingPostingId = @parxFinanceClosingPostingId AND DuplicateFCBP.Id IS NOT NULL
IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
-- 70.) CREATE FinancePosting Closing
INSERT INTO FinancePosting (
DocNumber
, StatusId
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, CreatedBy
, SourceId
, Closing
, Name
)
OUTPUT INSERTED.Id, INSERTED.Name INTO #InsertedPostings
SELECT
FCB.ReceiptNumber
, 'valid'
, FCB.ReceiptNumber
, FCB.ClosingDate
, FCB.ClosingPostingPeriodId
, FCB.Info
, @parxCreatedBy 
, 'Closing'
, 1
, FCBP.Id
FROM FinanceClosingPostingPosition FCBP
LEFT JOIN FinanceClosingPosting FCB ON FCB.Id = FCBP.ClosingPostingId
WHERE FCB.Id = @parxFinanceClosingPostingId
-- 71.) CREATE first FinancePostingPosition Closing
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, SourceOpenItemId
, Archived
)
-- VALUES FinancePostingPosition
SELECT
IB.PostingId 
, 1
, NULL
, 'valid'
, NULL
, FCBP.AccountId
, 1
, FAP.Name
, NULL
, CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END
, CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount) ELSE 0 END
, FCB.ClosingAccountId
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END - CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount) ELSE 0 END
, NULL
, NULL
, NULL
, NULL
, NULL
, 0
FROM #InsertedPostings IB
LEFT JOIN FinanceClosingPostingPosition FCBP ON FCBP.Id = IB.PositionId
LEFT JOIN FinanceClosingPosting FCB ON FCB.Id = FCBP.ClosingPostingId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FCBP.AccountId
-- 72.) CREATE second FinancePostingPosition Closing
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, SourceOpenItemId
, Archived
)
-- VALUES FinancePostingPosition
SELECT
IB.PostingId 
, 2
, NULL
, 'valid'
, NULL
, FCB.ClosingAccountId
, 1
, FAP.Name
, NULL
, CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount)  ELSE 0 END
, CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END
, FCBP.AccountId
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount)  ELSE 0 END - CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END
, NULL
, NULL
, NULL
, NULL
, NULL
, 0
FROM #InsertedPostings IB
LEFT JOIN FinanceClosingPostingPosition FCBP ON FCBP.Id= IB.PositionId
LEFT JOIN FinanceClosingPosting FCB ON FCB.Id = FCBP.ClosingPostingId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FCB.ClosingAccountId
-- 80.) CREATE FinancePosting Opening
INSERT INTO FinancePosting (
DocNumber
, StatusId
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, CreatedBy
, SourceId
, Opening
, Name
)
OUTPUT INSERTED.Id, INSERTED.Name INTO #InsertedOpeningPostings
SELECT
FCB.ReceiptNumber
, 'valid'
, FCB.ReceiptNumber
, FCB.OpeningDate
, FCB.OpeningPostingPeriodId
, FCB.Info
, @parxCreatedBy 
, 'Opening'
, 1
, FCBP.Id
FROM FinanceClosingPostingPosition FCBP
LEFT JOIN FinanceClosingPosting FCB ON FCB.Id = FCBP.ClosingPostingId
WHERE FCB.Id = @parxFinanceClosingPostingId
-- 81.) CREATE first FinancePostingPosition Opening
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, SourceOpenItemId
, Archived
)
-- VALUES FinancePostingPosition
SELECT
IOB.PostingId 
, 1
, NULL
, 'valid'
, NULL
, FCB.ClosingAccountId
, 1
, FAP.Name
, NULL
, CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END
, CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount) ELSE 0 END
, FCB.OpeningAccountId
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END - CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount) ELSE 0 END
, NULL
, NULL
, NULL
, NULL
, NULL
, 0
FROM #InsertedOpeningPostings IOB
LEFT JOIN FinanceClosingPostingPosition FCBP ON FCBP.Id = IOB.PositionId
LEFT JOIN FinanceClosingPosting FCB ON FCB.Id = FCBP.ClosingPostingId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FCB.ClosingAccountId
-- 82.) CREATE second FinancePostingPosition Opening
INSERT INTO FinancePostingPosition
(
PostingId
, Position
, ParentPosition
, StatusId
, ReversalReferencePositionId
, AccountId 
, PostingPositionAccountTypeId
, AccountName
, OpenItemId
, Debit
, Credit
, ContraAccountId
, GrossValue
, DivergentPerformanceDate
, TaxKeyId
, TaxPercent
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, VatNumber
, ProjectId
, PartnerDetailId
, BusinessPartnerNumber
, SourceOpenItemId
, Archived
)
-- VALUES FinancePostingPosition
SELECT
IOB.PostingId 
, 2
, NULL
, 'valid'
, NULL
, FCB.OpeningAccountId
, 1
, FAP.Name
, NULL
, CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount)  ELSE 0 END
, CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END
, FCB.ClosingAccountId
, 0
, NULL
, NULL
, NULL
, 0
, NULL
, NULL
, CASE WHEN FCBP.Amount > 0 THEN ABS(FCBP.Amount)  ELSE 0 END - CASE WHEN FCBP.Amount < 0 THEN ABS(FCBP.Amount) ELSE 0 END
, NULL
, NULL
, NULL
, NULL
, NULL
, 0
FROM #InsertedOpeningPostings IOB
LEFT JOIN FinanceClosingPostingPosition FCBP ON FCBP.Id= IOB.PositionId
LEFT JOIN FinanceClosingPosting FCB ON FCB.Id = FCBP.ClosingPostingId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceAccountPlan FAP ON FAP.Id = FCB.OpeningAccountId
-- 85.) UPDATE FinanceAccountPlan Balance Closing
UPDATE FAP
SET FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT FBP.AccountId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
FROM FinancePostingPosition FBP
JOIN #InsertedPostings IB ON IB.PostingId = FBP.PostingId
GROUP BY FBP.AccountId
) AS FBP ON FBP.AccountId= FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 86.) UPDATE FinanceAccountPlan Balance Opening
UPDATE FAP
SET FAP.Balance = FAP.Balance + ISNULL(FBP.TotalDebit - FBP.TotalCredit, 0)
FROM FinanceAccountPlan FAP
INNER JOIN (
SELECT FBP.AccountId, SUM(Debit) AS TotalDebit, SUM(Credit) AS TotalCredit
FROM FinancePostingPosition FBP
JOIN #InsertedOpeningPostings IOB ON IOB.PostingId = FBP.PostingId
GROUP BY FBP.AccountId
) AS FBP ON FBP.AccountId= FAP.Id
WHERE FBP.AccountId IS NOT NULL;
-- 87.) UPDATE FinanceClosingPosting
UPDATE FinanceClosingPosting
SET
Draft = 0
WHERE Id = @parxFinanceClosingPostingId
-- 90.) RETURN
END -- IF (SELECT COUNT(*) FROM @InvalidPositions ) = 0 BEGIN
SELECT * FROM @InvalidPositions 
COMMIT;
