CREATE OR ALTER PROCEDURE 
xPROC650_FinanceDunningWizard
-- xPROC650_FinanceDunningWizard ----------------------------------------------------------------------
-- Purpose: Create Entries in Procurement Table with needed Articles
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT into FinanceDunningPosition
-- 26.06.26 03:45
@parxSelectedFromCustomer NVARCHAR(100)
, @parxSelectedToCustomer NVARCHAR(100)
, @parxSelectedLocation INT = NULL
, @parxIncludeNegativeAmounts BIT
AS
BEGIN
SET NOCOUNT ON;
DECLARE @TransactionSuccess BIT = 1;
BEGIN TRY
BEGIN TRANSACTION;
IF NOT EXISTS (
SELECT 1
FROM FinanceDunningPosition
WHERE DunningId IS NULL
)
BEGIN
;WITH DueCustomers AS (
SELECT DISTINCT
FOI.PartnerId
, FOI.PartnerDetailId
FROM FinanceOpenItem FOI
LEFT JOIN FinanceDunningLevel FDL
ON (FDL.Id = 1 AND FOI.DunningLevelId IS NULL)
OR (FDL.Id = FOI.DunningLevelId + 1 AND FOI.DunningLevelId IS NOT NULL)
LEFT JOIN Partner P ON FOI.PartnerId = P.Id
LEFT JOIN PartnerDetail PD ON FOI.PartnerDetailId = PD.Id
WHERE
FOI.DunningBlock = 0
AND PD.DunningLock = 0
AND FOI.PartnerTypeId = 'Customer'
AND FOI.StatusId = 'open'
AND FOI.OpenItemTypeId = 'CI'                 -- nur Kundenrechnungen
AND FDL.Id <= (SELECT MAX(Id) FROM FinanceDunningLevel)
AND (@parxSelectedFromCustomer IS NULL OR P.Matchcode >= @parxSelectedFromCustomer)
AND (@parxSelectedToCustomer   IS NULL OR P.Matchcode <= @parxSelectedToCustomer)
AND (@parxSelectedLocation     IS NULL OR P.LocationId = @parxSelectedLocation)
AND (
(FOI.DunningLevelId IS NULL AND DATEADD(DAY, FDL.GoodwillDays, FOI.DueDate) < GETDATE())
OR (FOI.DunningLevelId IS NOT NULL AND FOI.NewDueDate < GETDATE())
)
)
-- 20.) INSERT into FinanceDunningPosition
INSERT INTO FinanceDunningPosition(
DunningId
, PartnerId
, PartnerDetailId
, Date
, OpenItemId
, OpenAmount
, DunningLevelId
, GoodwillDays
, Fee
, Interest
)
SELECT
NULL
, FOI.PartnerId
, FOI.PartnerDetailId
, GETDATE()
, FOI.Id
, FOI.OpenAmount
, CASE WHEN FOI.OpenItemTypeId = 'CI' THEN CASE WHEN FOI.DunningLevelId IS NULL THEN 1 ELSE FOI.DunningLevelId + 1 END ELSE NULL END
, FDL.GoodwillDays
, CASE WHEN FOI.OpenItemTypeId = 'CI' THEN FDL.Fee ELSE 0 END
, CASE WHEN FOI.OpenItemTypeId = 'CI' THEN FDL.Interest ELSE 0 END
FROM FinanceOpenItem FOI
LEFT JOIN FinanceDunningLevel FDL
ON (FDL.Id = 1 AND FOI.DunningLevelId IS NULL)
OR (FDL.Id = FOI.DunningLevelId + 1 AND FOI.DunningLevelId IS NOT NULL)
LEFT JOIN Partner P ON FOI.PartnerId = P.Id
LEFT JOIN PartnerDetail PD ON FOI.PartnerDetailId = PD.Id
INNER JOIN DueCustomers DC
ON DC.PartnerId = FOI.PartnerId
AND DC.PartnerDetailId = FOI.PartnerDetailId
WHERE
FOI.DunningBlock = 0
AND PD.DunningLock = 0
AND FOI.PartnerTypeId = 'Customer'
AND FOI.StatusId = 'open'
AND (FOI.OpenAmount > 0 OR @parxIncludeNegativeAmounts = 1)
AND FDL.Id <= (SELECT MAX(Id) FROM FinanceDunningLevel)
AND (@parxSelectedFromCustomer IS NULL OR P.Matchcode >= @parxSelectedFromCustomer)
AND (@parxSelectedToCustomer   IS NULL OR P.Matchcode <= @parxSelectedToCustomer)
AND (@parxSelectedLocation     IS NULL OR P.LocationId = @parxSelectedLocation)
AND (
(FOI.OpenItemTypeId = 'CI' AND (
(FOI.DunningLevelId IS NULL AND DATEADD(DAY, FDL.GoodwillDays, FOI.DueDate) < GETDATE())
OR (FOI.DunningLevelId IS NOT NULL AND FOI.NewDueDate < GETDATE())
))
OR FOI.OpenItemTypeId <> 'CI' 
);
END
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
SET @TransactionSuccess = 0;
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
ROLLBACK TRANSACTION;
THROW;
END CATCH
END;
GO
-- END xPROC650_FinanceDunningWizard ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC651_FinanceDunningWizard_CreateDunning
-- xPROC651_FinanceDunningWizard_CreateDunning ----------------------------------------------------------------------
-- Purpose: Create Production or Purchase Orders from Records in Procurement Table
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT into FinanceDunning
-- 30.) UPDATE  FinanceOpenItem
-- 40.) UPDATE FinanceDunningPosition
-- 26.06.26 03:45
AS
BEGIN
SET NOCOUNT ON;
DECLARE @TransactionSuccess BIT = 1;
BEGIN TRY
BEGIN TRANSACTION;
-- 20.) INSERT into FinanceDunningPosition
INSERT INTO FinanceDunning(
PartnerId
, DunningDate
, DunningLevelId
, Info
, DunningText
, GoodwillDays
, OpenAmountSum
, Fee
, Interest
, ForeignCurrencyId
, ReportTemplateId
) 
SELECT
FDP.PartnerId
, GETDATE()
, MAX(FDP.DunningLevelId)
, NULL
, FDL.DunningText
, FDL.GoodwillDays
, SUM(FDP.OpenAmount)
, SUM(FDP.Fee)
, SUM(FDP.OpenAmount * (FDP.Interest / 100) * DATEDIFF(DAY, DATEADD(DAY, 1, FOI.DueDate), GETDATE()) / 360)
, FOI.ForeignCurrencyId
, RT.ReportTemplateId
FROM FinanceDunningPosition FDP
LEFT JOIN FinanceDunningLevel FDL ON FDL.Id = (
SELECT MAX(DunningLevelId)
FROM FinanceDunningPosition
WHERE PartnerId = FDP.PartnerId AND DunningId IS NULL
)
LEFT JOIN FinanceOpenItem FOI ON FOI.Id = FDP.OpenItemId
OUTER APPLY (
SELECT TOP (1)
RT1.Id AS ReportTemplateId
FROM ReportTemplate RT1
ORDER BY
CASE WHEN RT1.ReportTypeId = N'FinanceDunningEdit' THEN 0 ELSE 1 END
, RT1.Id
) RT
WHERE
FDP.DunningId IS NULL -- Nur Positionen, bei denen Dunning IS NULL ist
GROUP BY
FDP.PartnerId,
FOI.ForeignCurrencyId,
FDL.DunningText,
FDL.GoodwillDays,
RT.ReportTemplateId;
-- 30.) UPDATE  FinanceOpenItem
UPDATE FinanceOpenItem SET
DunningLevelId = FDP.DunningLevelId
, DunningDate = FDP.Date
, NewDueDate = DATEADD(Day, FDP.GoodwillDays, FDP.Date)
FROM FinanceOpenItem FOI
JOIN FinanceDunningPosition FDP ON FDP.OpenItemId = FOI.Id
WHERE FDP.DunningId IS NULL
-- 40.) UPDATE FinanceDunningPosition
UPDATE FinanceDunningPosition SET
DunningId = FD.Id
FROM FinanceDunningPosition FDP
LEFT JOIN (
SELECT PartnerId, MAX(Id) AS Id
FROM FinanceDunning
GROUP BY PartnerId
) FD ON FD.PartnerId = FDP.PartnerId
WHERE FDP.DunningId IS NULL
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
SET @TransactionSuccess = 0;
DECLARE
@ErrorNumber INT = ERROR_NUMBER(),
@ErrorLine INT = ERROR_LINE(),
@ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
ROLLBACK TRANSACTION;
THROW;
END CATCH
END;
GO
-- END xPROC651_FinanceDunningWizard_CreateDunning ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
