CREATE OR ALTER PROCEDURE xPROC681_FinancePayment_CsvExport
-- xPROC681_FinancePayment_CsvExport ----------------------------------------------------------------------
-- Purpose: Export Finance Payment Run to CSV file
@parxFinancePaymentId INT
AS
BEGIN
SET NOCOUNT ON;
DECLARE @CsvData NVARCHAR(MAX);
BEGIN TRY
BEGIN TRANSACTION;
SELECT
FP.Id
, FP.PaymentDate
, PBA.AccountOwner
, FPP.BankAccountId
, FPP.BankNumberId
, STUFF((SELECT '/' + REPLACE(REPLACE(REPLACE(REPLACE(FPP1.Purpose, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss')
FROM FinancePaymentPosition FPP1
WHERE FPP1.FinancePaymentId = FP.Id AND FPP1.BankNumberId = FPP.BankNumberId And FPP1.BankAccountId = FPP.BankAccountId
FOR XML PATH('')), 1, 1, '') Purpose
INTO #FPP_PurposeTable
FROM FinancePayment FP
JOIN FinancePaymentPosition FPP ON FP.Id = FPP.FinancePaymentId
JOIN FinanceOpenItem FOI ON FPP.OpenItemId = FOI.Id
JOIN PartnerBankAccount PBA ON PBA.Id = FPP.BankAccountId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
WHERE FP.Id = @parxFinancePaymentId
GROUP BY FP.Id, FP.PaymentDate, PBA.AccountOwner, FPP.BankAccountId, FPP.BankNumberId
-- Add the header row
SET @CsvData = 'Offline verwalten'+ ';' +'Adressbuchuebernahme'+ ';' +'Eilauftrag'+ ';' +'Datum'+ ';' +'Beguenstigter'+ ';' +'Beguenstigter Zeile 2' + ';' +'Beguenstigter Zeile 3'+ ';' +'Beguenstigter Zeile 4'+ ';' +'Konto des Beguenstigten'+ ';' +'BLZ des Beguenstigten' + ';' +'IBAN des Beguenstigten'+ ';' +'BIC des Beguenstigten'+ ';' +'Rechnungsbetrag'+ ';' +'Skonto'+ ';' +'Waehrung' + ';' +'Betrag'+ ';' +'Verwendungszweckzeile 1'+ ';' +'Verwendungszweckzeile 2'+ ';' +'Verwendungszweckzeile 3' + ';' +'Verwendungszweckzeile 4'+ ';' +'Verwendungszweckzeile 5'+ ';' +'Verwendungszweckzeile 6'+ ';' +'Verwendungszweckzeile 7' + ';' +'Verwendungszweckzeile 8'+ ';' +'Verwendungszweckzeile 9'+ ';' +'Verwendungszweckzeile 10'+ ';' +'Verwendungszweckzeile 11' + ';' +'Verwendungszweckzeile 12'+ ';' +'Verwendungszweckzeile 13'+ ';' +'Verwendungszweckzeile 14'+ ';' +'Name des Spenders'+ ';' +'PLZ und Straße des Spenders'+ ';' +'Kontoinhaber'+ ';' +'Rechnungsnummer'+ ';' +'Turnus'+ ';' +'Ausfuehrungstag'+ ';' +'Erstmalig'+ ';' +'Letztmalig'+ ';' +'Auftrag ausfuehren am'+ ';' +'Mandatsstatus'+ ';' +'Glaeubiger-Identifikation' + ';' +'Mandatsreferenz'+ ';' +'Ausstellungsdatum'+ ';' +'Automatisch Letztmalig'+ ';' +'Textschluessel'+ ';' +'Art' + ';' +'Ende zu Ende Referenz' + ';' +'Art der Zahlung' + ';' +'Abweichender Auftraggeber' + CHAR(13) + CHAR(10);
-- Add the data rows
SELECT @CsvData = @CsvData +
STUFF(
(SELECT CHAR(13) + CHAR(10) + '0' + ';' + '0' + ';' + '0' + ';' +
CONVERT(VARCHAR,FP.PaymentDate,104) + ';' +
REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(LEFT(PBA.AccountOwner,35), ''), '"', ''), 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss') + ';' +
REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(SUBSTRING(PBA.AccountOwner,(35*1)+1, 35), ''), '"', ''), 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss') + ';' +
REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(SUBSTRING(PBA.AccountOwner,(35*2)+1, 35), ''), '"', ''), 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss') + ';' +
REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(SUBSTRING(PBA.AccountOwner,(35*3)+1, 35), ''), '"', ''), 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss') + ';' + '' + ';' + '' + ';' +
REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(FPP.BankAccountId, ''), '"', ''), 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss') + ';' +
REPLACE(ISNULL(LEFT(FPP.BankNumberId,11), ''), '"', '') + ';' +  '' + ';' +
REPLACE(ISNULL(FORMAT(0, '#,0.00', 'de-DE'), ''), '"', '') + ';' + 'EUR' + ';' +
REPLACE(ISNULL(FORMAT(ABS(SUM(FPP.Amount)), '#,0.00', 'de-DE'), ''), '"', '') + ';' +
REPLACE(ISNULL(LEFT(FPPP.Purpose, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*1)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*2)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*3)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*4)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*5)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*6)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*7)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*8)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*9)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*10)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*11)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*12)+1, 27), ''), '"', '') + ';' +
REPLACE(ISNULL(SUBSTRING(FPPP.Purpose,(27*13)+1, 27), ''), '"', '') + ';' + '' + ';' + '' + ';' + '' + ';' + '' + ';' + CASE WHEN SUM(FPP.Amount) > 0 THEN '' ELSE 'e' END+ ';' + '' + ';' + '' + ';' + '' + ';' + CASE WHEN SUM(FPP.Amount) > 0 THEN '' ELSE CONVERT(VARCHAR,FP.PaymentDate,104) END + ';' + CASE WHEN SUM(FPP.Amount) > 0 THEN '' ELSE 'ei' END + ';' + REPLACE(ISNULL(LEFT(ACS.SepaCreditorNumber, 35), ''), '"', '') + ';' + CASE WHEN SUM(FPP.Amount) > 0 THEN '' ELSE REPLACE(ISNULL(PBA.MandateReference, ''), '"', '') END + ';' + CASE WHEN SUM(FPP.Amount) > 0 THEN '' ELSE CONVERT(VARCHAR,GETDATE(),104) END + ';' + CASE WHEN SUM(FPP.Amount) > 0 THEN '' ELSE '0' END + ';' + '66' + ';' +CASE WHEN SUM(FPP.Amount) > 0 THEN 'CCS' WHEN FP.DirectDebitTypeId = 1 THEN 'CDS' ELSE 'BDD' END+ ';' + '' + ';' + '' + ';' + ''
FROM FinancePayment FP
JOIN FinancePaymentPosition FPP ON FP.Id = FPP.FinancePaymentId
JOIN FinanceOpenItem FOI ON FPP.OpenItemId = FOI.Id
JOIN PartnerBankAccount PBA ON PBA.Id = FPP.BankAccountId
JOIN #FPP_PurposeTable FPPP ON FPPP.Id = FP.Id And FPPP.PaymentDate = FP.PaymentDate And FPPP.AccountOwner = PBA.AccountOwner And FPPP.BankAccountId = FPP.BankAccountId And FPPP.BankNumberId = FPP.BankNumberId
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
WHERE FP.Id = @parxFinancePaymentId
GROUP BY FP.PaymentDate, FP.DirectDebitTypeId, PBA.AccountOwner, PBA.MandateReference, FPP.BankNumberId, FPP.BankAccountId, ACS.SepaCreditorNumber, FPPP.Purpose
FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 2, ''
);
DROP TABLE IF EXISTS #FPP_PurposeTable;
UPDATE FinancePayment SET
Transferred = 1
WHERE
Id = @parxFinancePaymentId;
COMMIT;
-- Return the CSV data as a single result set
SELECT @CsvData AS CsvData;
END TRY
BEGIN CATCH
IF XACT_STATE() <> 0
ROLLBACK;
DROP TABLE IF EXISTS #FPP_PurposeTable;
THROW;
END CATCH
END;
GO
-- END xPROC681_FinancePayment_CsvExport ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE xPROC681_FinancePayment_XmlExport
-- xPROC681_FinancePayment_XmlExport ----------------------------------------------------------------------
-- Purpose: Export Finance Payment Run to XML file
@parxFinancePaymentId INT
AS
BEGIN -- Procedure
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
UPDATE FinancePayment SET
Transferred = 1
WHERE
Id = @parxFinancePaymentId
-- 1. Root
DECLARE @XMLResult XML;
DECLARE @CreateDate1 NVARCHAR(20), @CreateDate2 NVARCHAR(20), @NoOfFinancePosition INT;
SELECT @CreateDate1 = FORMAT(GETDATE(), 'dd-MM-yyyy-HH-mm-ss'),  @CreateDate2 = FORMAT(GETDATE(), 'yyyy-MM-ddTHH:mm:ss');
SELECT @NoOfFinancePosition = COUNT(*) FROM FinancePaymentPosition WHERE FinancePaymentId = @parxFinancePaymentId;
WITH XMLNAMESPACES('http://www.w3.org/2001/XMLSchema-instance' AS xsi, 'http://www.w3.org/2001/XMLSchema' AS xsd, DEFAULT 'urn:iso:std:iso:20022:tech:xsd:pain.001.001.09')
-- 2. Document Context
SELECT @XMLResult = (
SELECT (
SELECT CONVERT(VARCHAR, @parxFinancePaymentId) + ' ' + @CreateDate1 AS 'GrpHdr/MsgId'
, @CreateDate2 AS 'GrpHdr/CreDtTm'
, @NoOfFinancePosition AS 'GrpHdr/NbOfTxs'
, CAST(FP.Amount AS DECIMAL(18,2)) AS 'GrpHdr/CtrlSum'
, ACS.CompanyName AS 'GrpHdr/InitgPty/Nm'
, (
SELECT
CONVERT(VARCHAR, @parxFinancePaymentId) + ' ' + @CreateDate1 AS 'PmtInfId'
, 'TRF' AS 'PmtMtd'
, 'true' AS 'BtchBookg'
, @NoOfFinancePosition AS 'NbOfTxs'
, CAST(FP.Amount AS DECIMAL(18,2)) AS 'CtrlSum'
, 'SEPA' AS 'PmtTpInf/SvcLvl/Cd'
, CONVERT(VARCHAR(10), FP.PaymentDate, 126) AS 'ReqdExctnDt/Dt'
, ACS.CompanyName AS 'Dbtr/Nm'
, FP.CompanyBankAccountId AS 'DbtrAcct/Id/IBAN'
, CASE WHEN FCBA.ForeignCurrencyId IS NOT NULL THEN FCBA.ForeignCurrencyId ELSE ACS.CompanyCurrencyId END AS 'DbtrAcct/Ccy'
, FCBA.BankId AS 'DbtrAgt/FinInstnId/BICFI'
, 'SLEV' AS 'ChrgBr'
, (SELECT FPP.Position AS 'PmtId/InstrId'
, 'NOTPROVIDED' AS 'PmtId/EndToEndId'
, (SELECT CASE WHEN FCBA.ForeignCurrencyId IS NOT NULL THEN FCBA.ForeignCurrencyId ELSE ACS.CompanyCurrencyId END AS "@Ccy" , CAST(FPP.Amount AS DECIMAL(18,2)) AS "text()" FOR XML PATH('InstdAmt'), TYPE) AS 'Amt'
, PBA.BankId AS 'CdtrAgt/FinInstnId/BICFI'
, PBA.AccountOwner AS 'Cdtr/Nm'
, P.Street AS 'Cdtr/PstlAdr/StrtNm'
, P.Zip AS 'Cdtr/PstlAdr/PstCd'
, P.City AS 'Cdtr/PstlAdr/TwnNm'
, P.CountryId AS 'Cdtr/PstlAdr/Ctry'
, FPP.BankAccountId AS 'CdtrAcct/Id/IBAN'
, REPLACE(REPLACE(REPLACE(REPLACE(FPP.Purpose, 'ä','ae'),'ö','oe'),'ü','ue'),'ß','ss') AS 'RmtInf/Ustrd'
FROM FinancePaymentPosition FPP
LEFT JOIN PartnerBankAccount PBA ON PBA.Id = FPP.BankAccountId
LEFT JOIN Partner P ON PBA.PartnerId = P.Id
WHERE FPP.FinancePaymentId = @parxFinancePaymentId
FOR XML PATH('CdtTrfTxInf'), TYPE)
FOR XML PATH(''), TYPE) AS 'PmtInf'
FROM FinancePayment FP
LEFT JOIN AdminCompanySetting ACS ON ACS.Id = 1
LEFT JOIN FinanceCompanyBankAccount FCBA ON FP.CompanyBankAccountId = FCBA.Id
WHERE FP.Id = @parxFinancePaymentId
FOR XML PATH('CstmrCdtTrfInitn'), ROOT('Document'), TYPE
));
-- Return the XML result
SELECT @XMLResult AS XMLResult;
--  End Procedure
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
DECLARE @ErrorNumber INT = ERROR_NUMBER(), @ErrorLine INT = ERROR_LINE(), @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END -- Transaction
GO
-- END xPROC681_FinancePayment_XmlExport ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
