CREATE OR ALTER PROCEDURE 
xPROC695_FinanceFixedAssetWizard
-- xPROC695_FinanceFixedAssetWizard ----------------------------------------------------------------------
-- Purpose: Create Entries in Procurement Table with needed Articles
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT into FinanceDunningPosition
-- 26.06.26 03:45
@parxAssetNumberFrom NVARCHAR(100)
, @parxAssetNumberTo NVARCHAR(100)
, @parxSelectedLocationId INT = NULL
, @PostingPeriodId INT
AS
BEGIN
SET NOCOUNT ON;
DECLARE @TransactionSuccess BIT = 1;
BEGIN TRY
BEGIN TRANSACTION;
-- 10.) DECLARE, SELECT, CALCULATE
DECLARE @SelectedPostingPeriodFiscalYearPeriod INT;
SELECT @SelectedPostingPeriodFiscalYearPeriod = FiscalYearPeriod
FROM FinancePostingPeriod
WHERE Id = @PostingPeriodId;
-- 20.) INSERT into FinanceFixedAssetDepreciationPlan
INSERT INTO FinanceFixedAssetDepreciationPlan (
FixedAssetId
, DepreciationTypeId
, PostingPeriodId
, [Year]
, [Month]
, DepreciationAmount
, DepreciationAccountId
, AssetAccountId
, ReceiptDate
, CostCenterId
, CostBearerId
, Info
, IsPosted
)
SELECT
V.Id
, V.DepreciationTypeId
, V.PostingPeriodId
, V.DepreciationYear
, V.DepreciationMonth
, ISNULL(V.DepreciationAmount, 0)
, V.DepreciationAccountId
, V.AssetAccountId
, EOMONTH(DATEFROMPARTS(V.DepreciationYear, V.DepreciationMonth, 1))
, V.CostCenterId
, V.CostBearerId
, V.Info
, 0
FROM xVIEW695_FinanceFixedAsset V
WHERE V.PostingPeriodId IS NOT NULL
AND V.DepreciationYear IS NOT NULL
AND V.DepreciationMonth IS NOT NULL
AND V.FiscalYearPeriod <= @SelectedPostingPeriodFiscalYearPeriod
AND V.StatusId = 'ACTIVE'
AND V.DepreciationAccountId IS NOT NULL
AND V.AssetAccountId IS NOT NULL
-- Filter by AssetNumber range
AND (@parxAssetNumberFrom IS NULL OR V.AssetNumber >= @parxAssetNumberFrom)
AND (@parxAssetNumberTo   IS NULL OR V.AssetNumber <= @parxAssetNumberTo)
-- Filter by Location
AND (@parxSelectedLocationId IS NULL OR V.LocationId = @parxSelectedLocationId)
-- Do not insert if a record with the same FixedAssetId, Year and Month already exists
AND NOT EXISTS (
SELECT 1
FROM FinanceFixedAssetDepreciationPlan DP
WHERE DP.FixedAssetId = V.Id
AND DP.[Year] = V.DepreciationYear
AND DP.[Month] = V.DepreciationMonth
);
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
SET @TransactionSuccess = 0;
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
ROLLBACK TRANSACTION;
THROW;
END CATCH
END;
GO
-- END xPROC650_FinanceDunningWizard ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC696_FinanceFixedAssetWizard_Posting
-- xPROC696_FinanceFixedAssetWizard_Posting ----------------------------------------------------------------------
-- Purpose: Create Postings for each FinanceFixedAssetDepreciationPlan that is not posted yet
-- Per unposted plan record: 1x FinancePosting + 2x FinancePostingPosition (Debit + Credit)
-- Then mark plan records as posted
-- 10.) DECLARE @InvalidValues, pre-validation
-- 20.) INSERT FinancePosting (MERGE)
-- 30.) INSERT FinancePostingPosition Debit (Abschreibungskonto)
-- 40.) INSERT FinancePostingPosition Credit (Anlagenkonto)
-- 50.) Post-validation: Debit = Credit
-- 60.) UPDATE FinanceFixedAssetDepreciationPlan (IsPosted, PostingId)
-- 26.03.10 16:41
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRY
BEGIN TRANSACTION;
-- 10.) DECLARE validation table and pre-validate
DECLARE @InvalidValues TABLE (
PositionNumber INT,
TEXT NVARCHAR(500),
IsError BIT
);
-- Check: DepreciationAccountId must not be NULL
INSERT INTO @InvalidValues (PositionNumber, TEXT, IsError)
SELECT
DP.Id
, N'Depreciation account is missing for asset: ' + FA.AssetNumber
, 1
FROM FinanceFixedAssetDepreciationPlan DP
INNER JOIN FinanceFixedAsset FA ON FA.Id = DP.FixedAssetId
WHERE DP.IsPosted = 0 AND DP.DepreciationAccountId IS NULL;
-- Check: AssetAccountId must not be NULL
INSERT INTO @InvalidValues (PositionNumber, TEXT, IsError)
SELECT
DP.Id
, N'Asset account is missing for asset: ' + FA.AssetNumber
, 1
FROM FinanceFixedAssetDepreciationPlan DP
INNER JOIN FinanceFixedAsset FA ON FA.Id = DP.FixedAssetId
WHERE DP.IsPosted = 0 AND DP.AssetAccountId IS NULL;
-- Check: DepreciationAmount must be > 0
INSERT INTO @InvalidValues (PositionNumber, TEXT, IsError)
SELECT
DP.Id
, N'Depreciation amount is zero for asset: ' + FA.AssetNumber
, 1
FROM FinanceFixedAssetDepreciationPlan DP
INNER JOIN FinanceFixedAsset FA ON FA.Id = DP.FixedAssetId
WHERE DP.IsPosted = 0 AND DP.DepreciationAmount = 0;
-- If pre-validation errors exist, rollback and return
IF (SELECT COUNT(*) FROM @InvalidValues) != 0
BEGIN
ROLLBACK TRANSACTION;
SELECT * FROM @InvalidValues;
RETURN;
END
-- DECLARE temp table to map PlanId -> new PostingId
DECLARE @InsertedPostings TABLE (
PostingId INT,
PlanId INT
);
-- 20.) INSERT FinancePosting per unposted DepreciationPlan record
-- Use MERGE to capture both INSERTED.Id and SOURCE columns
MERGE INTO FinancePosting AS Target
USING (
SELECT
DP.Id AS PlanId
, FA.AssetNumber
, DP.PostingPeriodId
, EOMONTH(DATEFROMPARTS(DP.[Year], DP.[Month], 1)) AS ReceiptDate
, CASE
WHEN FA.CyclePeriodId = 'YEARLY'
THEN N'AfA ' + CAST(DP.[Year] AS NVARCHAR(4)) + N' ' + FA.AssetNumber
ELSE N'AfA ' + CAST(DP.[Year] AS NVARCHAR(4)) + N'-' + RIGHT('0' + CAST(DP.[Month] AS NVARCHAR(2)), 2) + N' ' + FA.AssetNumber
END AS Subject
FROM FinanceFixedAssetDepreciationPlan DP
INNER JOIN FinanceFixedAsset FA ON FA.Id = DP.FixedAssetId
WHERE DP.IsPosted = 0
) AS Source
ON 1 = 0  -- never match, always insert
WHEN NOT MATCHED THEN
INSERT (
DocNumber
, StatusId
, ReceiptNumber
, ReceiptDate
, PostingPeriodId
, Subject
, SourceId
, Reversible
)
VALUES (
Source.AssetNumber
, 'valid'
, Source.AssetNumber
, Source.ReceiptDate
, Source.PostingPeriodId
, Source.Subject
, 'ASSET'
, 0
)
OUTPUT INSERTED.Id, Source.PlanId INTO @InsertedPostings (PostingId, PlanId);
-- 30.) INSERT first FinancePostingPosition (Debit / Soll = Abschreibungskonto)
INSERT INTO FinancePostingPosition (
PostingId
, Position
, StatusId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, Debit
, Credit
, ContraAccountId
, GrossValue
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, Archived
)
SELECT
IB.PostingId
, 1
, 'valid'
, DP.DepreciationAccountId
, 1
, ISNULL(FAPD.Name, N'')
, DP.DepreciationAmount
, 0
, DP.AssetAccountId
, 0
, 0
, DP.CostCenterId
, DP.CostBearerId
, 0
, 0
FROM @InsertedPostings IB
INNER JOIN FinanceFixedAssetDepreciationPlan DP ON DP.Id = IB.PlanId
LEFT JOIN FinanceAccountPlan FAPD ON FAPD.Id = DP.DepreciationAccountId;
-- 40.) INSERT second FinancePostingPosition (Credit / Haben = Anlagenkonto)
INSERT INTO FinancePostingPosition (
PostingId
, Position
, StatusId
, AccountId
, PostingPositionAccountTypeId
, AccountName
, Debit
, Credit
, ContraAccountId
, GrossValue
, TaxAmount
, CostCenterId
, CostBearerId
, OpenAmount
, Archived
)
SELECT
IB.PostingId
, 2
, 'valid'
, DP.AssetAccountId
, 1
, ISNULL(FAPA.Name, N'')
, 0
, DP.DepreciationAmount
, DP.DepreciationAccountId
, 0
, 0
, DP.CostCenterId
, DP.CostBearerId
, 0
, 0
FROM @InsertedPostings IB
INNER JOIN FinanceFixedAssetDepreciationPlan DP ON DP.Id = IB.PlanId
LEFT JOIN FinanceAccountPlan FAPA ON FAPA.Id = DP.AssetAccountId;
-- 50.) Post-validation: Debit must equal Credit per Posting
INSERT INTO @InvalidValues (PositionNumber, TEXT, IsError)
SELECT
0
, N'SYSTEM ERROR: Debit does not equal Credit'
, 1
FROM @InsertedPostings IB
WHERE EXISTS (
SELECT 1
FROM FinancePostingPosition FBP
WHERE FBP.PostingId = IB.PostingId
GROUP BY FBP.PostingId
HAVING SUM(FBP.Debit) <> SUM(FBP.Credit)
);
IF (SELECT COUNT(*) FROM @InvalidValues) != 0
BEGIN
ROLLBACK TRANSACTION;
SELECT * FROM @InvalidValues;
RETURN;
END
-- 60.) UPDATE FinanceFixedAssetDepreciationPlan: mark as posted and link to Posting
UPDATE DP
SET
DP.IsPosted = 1
, DP.PostingId = IB.PostingId
FROM FinanceFixedAssetDepreciationPlan DP
INNER JOIN @InsertedPostings IB ON IB.PlanId = DP.Id;
SELECT * FROM @InvalidValues;
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
ROLLBACK TRANSACTION;
THROW;
END CATCH
END;
GO
-- END xPROC696_FinanceFixedAssetWizard_Posting ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
