CREATE OR ALTER PROCEDURE 
xPROC699_FinancePostingPeriodWizard
-- xPROC699_FinancePostingPeriodWizard ----------------------------------------------------------------------
-- Purpose: 
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT INTO TempTable
-- 30.) CSV-Export
-- 80.) RETURN
-- 90.) END TRANSACTION
-- 26.06.26 03:45
@parxFiscalYearId INT,
@parxFiscalPeriodId INT,
@parxCalendarYearId INT,
@parxCalendarMonthId INT,
@parxNumberOfPeriods INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
;WITH E1(N) AS (SELECT 1 UNION ALL SELECT 1)         -- 2
, E2(N) AS (SELECT 1 FROM E1 a, E1 b)            -- 4
, E4(N) AS (SELECT 1 FROM E2 a, E2 b)            -- 16
, E8(N) AS (SELECT 1 FROM E4 a, E4 b)            -- 256
, Tally(N) AS (
SELECT TOP (@parxNumberOfPeriods)
ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1 AS N
FROM E8
)
, PeriodSequence AS (
SELECT
N
, (@parxCalendarMonthId - 1 + N) % 12 + 1 AS CalendarMonthId
, @parxCalendarYearId + ((@parxCalendarMonthId - 1 + N) / 12) AS CalendarYearId
, (@parxFiscalPeriodId - 1 + N) % 12 + 1 AS FiscalPeriodId
, @parxFiscalYearId + ((@parxFiscalPeriodId - 1 + N) / 12) AS FiscalYearId
FROM Tally
)
-- 20.) INSERT INTO Tabelle
INSERT INTO FinancePostingPeriod (
Name
, FiscalYearId
, FiscalPeriodId
, CalendarYearId
, CalendarMonthId
, StatusId
)
SELECT
CAST(p.FiscalYearId AS varchar(4)) + FORMAT(p.FiscalPeriodId, '00') + ' ' + m.Name
, p.FiscalYearId
, p.FiscalPeriodId
, p.CalendarYearId
, p.CalendarMonthId
, 'open'
FROM PeriodSequence p
JOIN AdminMonth m ON m.Id = p.CalendarMonthId
WHERE NOT EXISTS (
SELECT 1
FROM FinancePostingPeriod fbp
WHERE fbp.CalendarYearId = p.CalendarYearId
AND fbp.CalendarMonthId = p.CalendarMonthId
);
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END xPROC699_FinancePostingPeriodWizard ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE xPROC_DashboardQuantities
-- xPROC_DashboardQuantities
-- PURPOSE: Get Data for Dashboards showing Article Quantities
-- Creator: MH
-- Created: 2023-07-26
-- Changed: 
AS
BEGIN
DECLARE @DashboardQuery NVARCHAR(MAX);
--ISNULL((SELECT ' + @DocLanguage + N' FROM ReportLanguageWord WHERE ReportLanguageWordId = '''+N'of'+N'''),'''+N''') AS Vom,
SET @DashboardQuery =
N'SELECT
D.DocTypeId AS Typ,
DT.Name AS [Doc Type],
DT.InventoryStatusId,
DT.DocCategoryId AS [Sales / Purchase],
DC.Name AS DocCategoryName,
DP.Id,
D.DocNumber,
D.StatusId,
DP.ArticleId AS [Article Number],
AG.Name AS  [Article Group],
DP.Name1,
DP.Quantity,
CASE
WHEN D.WarehousingEffective = 1 THEN DP.Quantity
ELSE 0
END AS [receipted],
CASE
WHEN D.WarehousingEffective = -1 THEN DP.Quantity
ELSE 0
END AS [issued],
CASE
WHEN D.InventoryStatusId = ( '''+N'confirmed'+''' ) THEN DP.Quantity
ELSE 0
END AS [confirmed],
CASE
WHEN D.InventoryStatusId = ( '''+N'ordered'+''' ) THEN DP.Quantity
ELSE 0
END AS [ordered],
CASE
WHEN D.InventoryStatusId = ( '''+N'packed'+''' ) THEN DP.Quantity
ELSE 0
END AS [packed],
AU.Name AS ArticleUoM,
DP.Price,
D.ForeignCurrencyId AS [Foreign Currency],
DP.DiscountPercent,
DP.QuantityDiscountPercent,
DP.DocDiscountPercent,
DP.TotalPrice,
convert(Date, D.DeliveryDate) AS [Delivery Date],
D.ShippingDate,
D.PartnerId AS Account,
D.DocDate,
P.Name1 AS PartnerName1,
P.Matchcode,
STR(dbo.xFUNCTION_REPORT_GetConfirmedQuantity(DP.Id,0,D.DocTypeId),19,A.DecimalPlacesQuantitiesId) AS [to deliver],
0 AS [zu erhalten], --to receive
DP.QuantityOpen,
DP.ShippingDate,
DP.StatusId,
DP.PositionTypeId,
DP.PositionNumber,
DP.ProfitAmount,
DP.ProfitPercent/100 AS ProfitPercent,
DP.CostPriceTotal,
DPT.Name AS PositionTypeName,
PD.Id AS BusinessPartnerNumber,
DPS.Name AS PositionStatusName
FROM
Doc D
JOIN DocType DT ON DT.Id = D.DocTypeId
JOIN DocCategory DC ON DC.Id = DT.DocCategoryId
JOIN DocPosition DP ON D.Id = DP.DocId
JOIN DocPositionType DPT ON DPT.Id = DP.PositionTypeId
JOIN DocPositionStatus DPS ON DPS.Id = DP.StatusId
JOIN ArticleUoM AU ON AU.Id = DP.UoMId
JOIN Article A ON A.Id = DP.ArticleId
JOIN ArticleGroup AG ON AG.Id = A.ArticleGroupId
JOIN Partner P ON D.PartnerId = P.Id
JOIN PartnerDetail PD
ON D.PartnerId = PD.PartnerId
AND PD.PartnerTypeId = CASE
WHEN DT.DocCategoryId = ''Sales'' THEN ''Customer''
WHEN DT.DocCategoryId = ''Purchase'' THEN ''Supplier''
ELSE PD.PartnerTypeId  -- Optional: Standardwert, falls keine Übereinstimmung
END'
EXEC sp_executesql @DashboardQuery;
END;
GO
-- END xPROC_DashboardQuantities---------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC_DashboardCashflow
-- xPROC_DashboardCashflow ----------------------------------------------------------------------
-- PURPOSE: Get Data for Cashflow Grid
-- USAGE:
-- 10.) CREATE Table
-- 20.) WHILE Loop to fill the Table
-- 90.) RETURN
-- 91.) ERROR HANDLING
-- 26.06.26 03:46
@parxDays INT
AS
BEGIN
SET NOCOUNT ON;
-- 10.) CREATE Table
CREATE TABLE #DailyValues(
DateDay DATE,
OpenValue DECIMAL(18,2),
CloseValue DECIMAL(18,2),
HighValue DECIMAL(18,2),
LowValue DECIMAL(18,2)
);
-- 20.) WHILE Loop to fill the Table
DECLARE @Counter INT = 0;
DECLARE @BanksTotal DECIMAL(18,2);
SELECT @BanksTotal = SUM(FAP.Balance) FROM FinanceAccountPlan FAP WHERE  FAP.AccountTypeId = 1;
WHILE @Counter < @parxDays BEGIN
INSERT INTO #DailyValues ( DateDay, OpenValue, CloseValue, HighValue, LowValue)
VALUES(
DATEADD(DAY, @Counter, CAST(GETDATE() AS DATE))
, (SELECT ISNULL(SUM(ProbableAmount),0) FROM FinanceOpenItem WHERE DueDate <= DATEADD(DAY, @Counter - 1, CAST(GETDATE() AS DATE))) + ISNULL(@BanksTotal,0)
, (SELECT ISNULL(SUM(ProbableAmount),0) FROM FinanceOpenItem WHERE DueDate <= DATEADD(DAY, @Counter, CAST(GETDATE() AS DATE))) + ISNULL(@BanksTotal,0)
, (SELECT ISNULL(SUM(ProbableAmount),0) FROM FinanceOpenItem WHERE DueDate < DATEADD(DAY, @Counter, CAST(GETDATE() AS DATE)) OR (DueDate = DATEADD(DAY, @Counter, CAST(GETDATE() AS DATE)) AND ProbableAmount> 0)) + ISNULL(@BanksTotal,0)
, (SELECT ISNULL(SUM(ProbableAmount),0) FROM FinanceOpenItem WHERE DueDate < DATEADD(DAY, @Counter, CAST(GETDATE() AS DATE)) OR (DueDate = DATEADD(DAY, @Counter, CAST(GETDATE() AS DATE)) AND ProbableAmount < 0)) + ISNULL(@BanksTotal,0)
);
SET @Counter = @Counter + 1;
END
-- 90.) RETURN
SELECT
DateDay,
OpenValue,
CloseValue,
HighValue,
LowValue
FROM
#DailyValues
ORDER BY
DateDay;
-- Clean up by dropping the temporary table
DROP TABLE #DailyValues;
END;
GO
-- END xPROC_DashboardCashflow ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC_Dashboard_OpenItemList
-- xPROC_Dashboard_OpenItemList ----------------------------------------------------------------------
-- PURPOSE: Get Data for OpenItem Dashboard for passed date
-- USAGE:
-- 10.) CREATE Table
-- 20.) INSERT in #DisplayedValues 
-- 90.) RETURN
-- 91.) ERROR HANDLING
-- 26.06.26 03:45
@parxDate DATE
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION
BEGIN TRY
-- 10.) CREATE Table
CREATE TABLE #DisplayedValues(
BusinessPartnerNumber INT
, Matchcode NVARCHAR(100)
, OpenItemTypeName NVARCHAR(30)
, DocDate DATE
, ReferenceDoc NVARCHAR(50)
, DueDate DATE
, CashDiscountDate1 DATE
, CashDiscountDate2 DATE
, Amount DECIMAL(19,6)
, OpenAmount DECIMAL(19,6)
, OpenItemId INT
, PartnerTypeName NVARCHAR(20)
);
-- 20.) INSERT in #DisplayedValues FROM xVIEW604_FinanceOpenItemHistoryList
WITH CTE_LatestValues AS (
SELECT
BusinessPartnerNumber,
Matchcode,
OpenItemTypeName,
DocDate,
ReferenceDoc,
DueDate,
CashDiscountDate1,
CashDiscountDate2,
Amount,
StatusId,
CalculatedAmountOpen,
FOIHL.Id AS OpenItemId,
PT.Name,
PaymentDocDate,
ROW_NUMBER() OVER (
PARTITION BY FOIHL.Id
ORDER BY PaymentDocDate DESC
) AS RowNum,
ROW_NUMBER() OVER (
PARTITION BY FOIHL.Id
ORDER BY PaymentDocDate ASC
) AS RowNumASC
FROM xVIEW604_FinanceOpenItemHistoryList FOIHL
LEFT JOIN PartnerType PT ON PT.Id = FOIHL.PartnerTypeId
WHERE
(((CalculatedAmountOpen != 0 AND PaymentDocDate <= @parxDate AND DocDate <= @parxDate) OR (CalculatedAmountOpen = 0 AND FOIHL.RowNum = 1 AND PaymentDocDate > @parxDate AND DocDate <= @parxDate)) 
AND NOT EXISTS (
SELECT 1
FROM xVIEW604_FinanceOpenItemHistoryList AS innerFOIHL
WHERE innerFOIHL.CalculatedAmountOpen = 0
AND innerFOIHL.PaymentDocDate <= @parxDate AND FOIHL.Id = innerFOIHL.Id
)
)
)
INSERT INTO #DisplayedValues (BusinessPartnerNumber, Matchcode, OpenItemTypeName, DocDate, ReferenceDoc, DueDate, CashDiscountDate1, CashDiscountDate2, Amount, OpenAmount, OpenItemId, PartnerTypeName )
SELECT
CTE.BusinessPartnerNumber
, CTE.Matchcode
, CTE.OpenItemTypeName
, CTE.DocDate
, CTE.ReferenceDoc
, CTE.DueDate
, CTE.CashDiscountDate1
, CTE.CashDiscountDate2
, CTE.Amount
, CASE WHEN CTE.CalculatedAmountOpen = 0 AND CTE.RowNum = 1 AND CTE.RowNumASC = 1 THEN CTE.Amount ELSE CTE.CalculatedAmountOpen END
, CTE.OpenItemId 
, CTE.Name
FROM CTE_LatestValues CTE
LEFT JOIN CTE_LatestValues CTEZERO ON CTE.OpenItemId = CTEZERO.OpenItemId AND CTEZERO.CalculatedAmountOpen = 0
WHERE (CTE.CalculatedAmountOpen != 0 AND
CTE.PaymentDocDate <= @parxDate
AND CTE.DocDate <= @parxDate AND (CTEZERO.PaymentDocDate > @parxDate OR CTEZERO.PaymentDocDate IS NULL) AND ((CTE.RowNum = 1 AND CTE.StatusId = 'open') OR (CTE.RowNum = 2 AND CTE.StatusId = 'closed'))) OR (CTE.CalculatedAmountOpen = 0 AND CTE.PaymentDocDate > @parxDate AND CTE.DocDate <= @parxDate AND CTE.RowNumASC = 1)
-- 30.) INSERT in #DisplayedValues FROM FinanceOpenItem
INSERT INTO #DisplayedValues (BusinessPartnerNumber, Matchcode, OpenItemTypeName, DocDate, ReferenceDoc, DueDate, CashDiscountDate1, CashDiscountDate2, Amount, OpenAmount, OpenItemId, PartnerTypeName )
SELECT
VW.BusinessPartnerNumber
, VW.Matchcode
, FOIT.Name
, DocDate
, ReferenceDoc
, DueDate
, CashDiscountDate1
, CashDiscountDate2
, Amount
, Amount
, FOI.Id
, PT.Name
FROM FinanceOpenItem FOI
JOIN xVIEW150_PartnerJoinPartnerDetail VW ON FOI.PartnerDetailId = VW.Id
LEFT JOIN FinanceOpenItemType FOIT ON FOIT.Id= FOI.OpenItemTypeId
LEFT JOIN PartnerType PT ON PT.Id = FOI.PartnerTypeId
WHERE FOI.DocDate <= @parxDate
AND FOI.StatusId = 'open'
AND NOT EXISTS (
SELECT 1
FROM #DisplayedValues DV
WHERE DV.OpenItemId= FOI.Id
);
-- 90.) RETURN
SELECT *
FROM #DisplayedValues
-- Clean up by dropping the temporary table
DROP TABLE #DisplayedValues;
COMMIT;
END TRY
BEGIN CATCH
ROLLBACK;
THROW;
END CATCH
END; -- Procedure
GO
-- END xPROC_Dashboard_OpenItemList ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE OR ALTER PROCEDURE [dbo].[xPROC_ReportTaxDetail]
-- xPROC_ReportTaxDetail
-- PURPOSE: Get Data for Tax Report 
-- Creator: MH
-- Created: 2023-07-26
-- Changed: 
-- 
@id Bigint
AS
BEGIN
DECLARE @query NVARCHAR(MAX);
DECLARE @DocLanguage NVARCHAR(MAX);
SELECT @DocLanguage = 'de' FROM Doc D WHERE D.Id = @id;
SET @query ='
SELECT
DP.DocId,
DP.TaxKeyId,
FTK.Name AS TaxName,
ISNULL(D.ForeignCurrencyId, ACS.CompanyCurrencyId) AS Currency,
FORMAT(DP.TaxPercent,'+'''N2'','''+@DocLanguage+''') AS TaxPercent,
CASE WHEN D.ForeignCurrencyId IS NOT NULL
THEN FORMAT(SUM(DP.ForeignCurrencyPrice * DP.Quantity),'+'''N2'','''+@DocLanguage+''')
ELSE FORMAT(SUM(DP.TotalPrice),'+'''N2'','''+@DocLanguage+''') END AS TotalSum,
CASE WHEN D.ForeignCurrencyId IS NOT NULL
THEN FORMAT(SUM(DP.Tax * D.Rate),'+'''N2'','''+@DocLanguage+''')
ELSE FORMAT(SUM(DP.Tax),'+'''N2'','''+@DocLanguage+''') END AS TaxSum,
N''Vom'' AS Vom,
N''% MwSt. aus'' AS Taxoutof,
D.LanguageId
FROM dbo.DocPosition AS DP
INNER JOIN dbo.Doc AS D ON DP.DocId = D.Id AND D.Id = ' + CONVERT(VARCHAR(MAX), @id) + N' INNER JOIN dbo.FinanceTaxKey AS FTK ON DP.TaxKeyId = FTK.Id
And FTK.TaxKeyKindId <> 3
CROSS JOIN dbo.AdminCompanySetting AS ACS
WHERE DP.PositionTypeId NOT IN ( '''+N'Alternative'+N''''+','''+N'Optional'+N''''+','''+N'Possible'+N''''+','''+N'Rejected'+N''''+')
GROUP BY DP.DocId, DP.TaxKeyId,DP.TaxPercent, FTK.Name, D.ForeignCurrencyId,ACS.CompanyCurrencyId, D.LanguageId, D.DocDate'
EXEC sp_executesql @query;
END;
GO
-------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE OR ALTER PROCEDURE [dbo].[xPROC_ReportPositionInfo]
-- xPROC_ReportPositionInfo
-- PURPOSE: Get Data for Doc Report Positions
-- Creator: MH
-- Created: 2023-07-26
-- Changed: 
@id Bigint
AS
BEGIN
DECLARE @query NVARCHAR(MAX);
DECLARE @DocLanguage NVARCHAR(MAX), @DocType NVARCHAR(MAX);
SELECT @DocLanguage = 'de', @DocType = D.DocTypeId FROM Doc D WHERE D.Id = @id;
SET @query ='
SELECT TOP (100) PERCENT
DP.Id AS DocPosId,
ISNULL(DP.DocId, D.Id) DocId,
DP.PositionTypeId,
DP.PositionNumber,
CASE WHEN CAST(ISNULL(DP.ParentPositionId,0) AS NVARCHAR(5)) = CAST(0 AS NVARCHAR(5)) OR CAST(ISNULL(DP.ChildPositionNumber,0) AS NVARCHAR(5)) = CAST(0 AS NVARCHAR(5))
THEN CAST(DP.PositionNumber AS NVARCHAR(5)) ELSE CONCAT(DP.PositionNumber,N'''+'.'+N''',DP.ChildPositionNumber) END as Child_Position_Sequence,
ROW_NUMBER() OVER(Partition BY ISNULL(PredDoc.DocId, D.Id) ORDER BY DP.PositionNumber, D.Id) as Position_Sequence,
DP.ParentPositionId,
DP.ChildPositionNumber,
DP.StatusId,
DP.ArticleId,
DP.Name1,
DP.Name2,
Round(DP.Quantity * power(10, O.DecimalPlacesQuantitiesId), 0) / power(10, O.DecimalPlacesQuantitiesId) AS Quantity,
Round(dbo.xFUNCTION_REPORT_GetConfirmedQuantity(DP.Id,0,D.DocTypeId) * power(10, O.DecimalPlacesQuantitiesId), 0) / power(10, O.DecimalPlacesQuantitiesId) AS QuantityOpen,
DP.UoMId,
DP.DeliveryDate,
CONVERT(DATE,DP.DeliveryDate) AS DivDate,
CASE WHEN D.ForeignCurrencyId IS NOT NULL
THEN FORMAT(DP.ForeignCurrencyPrice,'+'''N2'','''+@DocLanguage+''')
ELSE FORMAT(DP.Price,'+'''N2'','''+@DocLanguage+''') END Price,
CASE WHEN D.ForeignCurrencyId IS NOT NULL
THEN FORMAT(XDP.TotalPriceForeignCurrency,'+'''N2'','''+@DocLanguage+''')
ELSE FORMAT(DP.TotalPrice,'+'''N2'','''+@DocLanguage+''') END TotalPrice,
DP.PredecessorId,
DP.[Level],
DP.PositionLabel,
DP.CatalogNumberId,
DP.Dissolve,
DP.PositionWeight,
DP.ProjectId,
DP.Start,
DP.Stop,
DP.PriceUnitId,
FORMAT(DP.CostPriceTotal,'+'''N2'','''+@DocLanguage+''') CostPriceTotal,
FORMAT(DP.DiscountPercent,'+'''N2'','''+@DocLanguage+''') DiscountPercent,
FORMAT(DP.QuantityDiscountPercent,'+'''N2'','''+@DocLanguage+''') QuantityDiscountPercent,
FORMAT(DP.DocDiscountPercent,'+'''N2'','''+@DocLanguage+''') DocDiscountPercent,
FORMAT(DP.DiscountedPrice,'+'''N2'','''+@DocLanguage+''') DiscountedPrice,
DP.RevenueEffective,
DP.Revenue,
DP.SalesPersonId,
FORMAT(DP.CommissionPercent,'+'''N2'','''+@DocLanguage+''') CommissionPercent,
FORMAT(DP.CommissionAmount,'+'''N2'','''+@DocLanguage+''') CommissionAmount,
FORMAT(DP.ProfitAmount,'+'''N2'','''+@DocLanguage+''') ProfitAmount,
FORMAT(DP.ProfitPercent,'+'''N2'','''+@DocLanguage+''') ProfitPercent,
DP.FinanceGroupArticleId AS FinanceGroupId,
DP.TaxKeyId,
DP.TaxPercent,
ISNULL((SELECT TOP (1) TaxPercent FROM dbo.FinanceTaxKeyDetail AS FTKD WHERE (TaxKeyId = DP.TaxKeyId) AND (ValidFrom <= D.DocDate) ORDER BY ValidFrom DESC), 0) AS Tax,
DP.AccountId,
DP.CostCenterId,
DP.CostBearerId,
DP.Warehousing,
DP.WarehousingEffective,
Round(DP.WarehousingQuantity * power(10, O.DecimalPlacesQuantitiesId), 0) / power(10, O.DecimalPlacesQuantitiesId) AS WarehousingQuantity,
O.Name1 AS ArticleName1,
O.Name2 AS ArticleName2,
OG.Name AS ArticleGroupName,
OU.Name AS ArticleUoMName,
OU.UoMEnglish AS ArticleUoMNameEnglish,
ISNULL(PredDoc.DocId, D.Id) AS ParentDocId,
ISNULL(PredDoc.DocNumber, D.DocNumber) AS ParentDocNum,
PredDoc.DocTypeId AS ParentDocType,
PredDoc.PredecessorId AS ParentPredecessorId,
ISNULL(CONVERT(VARCHAR(10), PredDoc.DocDate, 104), N'''+'-'+N''') AS ParentDocDate,
Round(dbo.xFUNCTION_REPORT_GetConfirmedQuantity(DP.Id,1,D.DocTypeId) * power(10, O.DecimalPlacesQuantitiesId), 0) / power(10, O.DecimalPlacesQuantitiesId) AS OrderedQuantity,
REPLACE(REPLACE(DPIT.InfoText,'+N'''<p>'+N''''+N','+N''''+N'''),'+N'''</p>'+N''''+N','+N''''+N''') InfoText,
REPLACE(REPLACE(DPOT.OrderText,'+N'''<p>'+N''''+N','+N''''+N'''),'+N'''</p>'+N''''+N','+N''''+N''') OrderText,
O.DecimalPlacesQuantitiesId
FROM dbo.DocPosition AS DP
RIGHT OUTER JOIN dbo.Doc AS D ON DP.DocId = D.Id AND UPPER(DP.PositionTypeId) <> N'''+N'AUTO'+N'''' +N'
LEFT OUTER JOIN dbo.DocPositionInfoText DPIT ON DP.Id = DPIT.DocPositionId
LEFT OUTER JOIN dbo.DocPositionOrderText DPOT ON DP.Id = DPOT.DocPositionId
LEFT OUTER JOIN (SELECT D1.DocTypeId, D1.DocNumber, D1.DocDate, DP1.Id, DP1.DocId, DP1.PredecessorId FROM dbo.DocPosition AS DP1 INNER JOIN dbo.Doc AS D1 ON DP1.DocId = D1.Id) AS PredDoc ON DP.PredecessorId = PredDoc.Id
LEFT OUTER JOIN dbo.Article AS O ON O.Id = DP.ArticleId
LEFT OUTER JOIN dbo.ArticleGroup AS OG ON O.ArticleGroupId = OG.Id
LEFT OUTER JOIN dbo.ArticleUoM AS OU ON O.UoMId = OU.Id
LEFT OUTER JOIN dbo.FinanceTaxKey AS FTK ON DP.TaxKeyId = FTK.Id
LEFT JOIN xVIEW_DocPosition XDP ON XDP.Id = DP.Id
WHERE D.Id = ' + CONVERT(VARCHAR(MAX), @id) +N'
ORDER BY DP.RowNumber'
--SELECT @query
EXEC sp_executesql @query;
END;
GO
------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE OR ALTER PROCEDURE xPROC_DunningReport
-- xPROC_ReportPositionInfo
-- PURPOSE: Get Data for Dunning Report 
-- Creator: MH
-- Created: 2023-07-26
-- Changed: 
@id Bigint
AS
BEGIN
DECLARE @QueryText NVARCHAR(MAX);
DECLARE @DocLanguage NVARCHAR(MAX), @DocType NVARCHAR(MAX);
SELECT @DocLanguage = 'de';
SET @QueryText =
N'SELECT
FD.Id DunningId
, FD.PartnerId
, CONVERT(VARCHAR(10), FD.DunningDate, 104) DunningDate
, FD.DunningLevelId
, FD.Info
, FD.DunningText
, FD.GoodwillDays TotalGoodwillDays
, FD.OpenAmountSum
, FD.Fee TotalFee
, FD.Interest TotalInterest
, FD.TotalDue
, ISNULL(FD.ForeignCurrencyId,ACS.CompanyCurrencyId) ForeignCurrencyId
, FDP.PartnerDetailId
, FDP.Date
, FDP.OpenItemId
, FDP.OpenAmount
, FDP.DunningLevelId PositionDunningLevelId
, FDP.GoodwillDays PositionGoodwillDays
, FDP.Fee PositionFee
, FOI.OpenAmount * (FDP.Interest / 100) * DATEDIFF(DAY, DATEADD(DAY, 1, FOI.DueDate), GETDATE()) / 360 AS PositionInterest
, ACS.CompanyName AS CompanyMatchcode
, ACS.Name2 AS CompanyName2
, ACS.Name3 AS CompanyName3
, ACS.Street AS CompanyStreet
, ACS.City AS CompanyCity
, ACS.Zip AS CompanyZip
, AC.Country AS CompanyCountry
, P.Name1 AS PartnerName1
, P.Name2 AS PartnerName2
, P.Street AS PartnerStreet
, P.Zip AS PartnerZip
, P.City AS PartnerCity
, P.CountryId AS PartnerCountryId
, P.Matchcode AS PartnerMatchcode
, P.PartnerGroupId
, P.Tel1 AS PartnerTel1
, P.Tel2 AS PartnerTel2
, P.Mobile AS PartnerMobile
, P.Fax AS PartnerFax
, P.Email AS PartnerEmail
, P.LanguageId AS PartnerLanguageId
, PBA.VatNumber AS PartnerVatNumber
, PBA.TaxNumber AS PartnerTaxNumber
, P.Matchcode
, ISNULL(P.Name1,'''+N''')+ISNULL(CHAR(10)+P.Name2,'''+N''')+ISNULL(CHAR(10)+P.Street,'''+N''')+ISNULL(CHAR(10)+P.Zip,'''+N''')+ISNULL(CHAR(32)+P.City,'''+N''')+ISNULL(CHAR(10)+AC2.Country,'''+N''') PartnerAddress
, P.Name1
, P.Name2
, P.Street
, P.Zip
, P.City
, P.CountryId
, AC2.Country AS PartnerCountryName
, P.Gln AS PartnerGln
, P.Eori AS PartnerEORI
, PD.Id AS BusinessPartnerNumber
, FOI.DocNumber
, FOI.Amount DocAmount
, CONVERT(VARCHAR(10), FOI.DocDate, 104) DocDate
, CONVERT(VARCHAR(10), FOI.DueDate, 104) DueDate
, FDL.Info DunningLevelInfo
FROM
FinanceDunning FD
JOIN FinanceDunningPosition FDP ON FD.Id = FDP.DunningId AND FD.Id = ' + CONVERT(NVARCHAR(MAX), @id) + N'
JOIN FinanceDunningLevel FDL ON FD.DunningLevelId = FDL.Id
JOIN FinanceOpenItem FOI ON FOI.Id = FDP.OpenItemId
CROSS JOIN AdminCompanySetting AS ACS
JOIN AdminCountry AS AC ON ACS.CountryId = AC.Id
JOIN dbo.Partner AS P ON FD.PartnerId = P.Id JOIN dbo.AdminCountry AS AC2 ON P.CountryId = AC2.Id
JOIN PartnerDetail PD ON PD.PartnerId = P.Id And PD.PartnerTypeId = ''Customer''
JOIN dbo.PartnerBillingAddress AS PBA ON PBA.Id = PD.StandardBillingAddressId ';
EXEC sp_executesql @QueryText;
END;
GO
------END -------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
