GO
CREATE OR ALTER PROCEDURE
[dbo].[xPROC_AnnualBalanceSheetAccountVerification] (
-- xPROC_AnnualBalanceSheetAccountVerification
-- PURPOSE: Get Data for Account Verification for the Balance
-- Creator: MH
-- Created: 2023-07-26
-- Changed: 
@parxDate NVARCHAR(10)
, @HideZeroValueAccounts CHAR = 'Y'
)
AS
BEGIN
DECLARE @BalanceDate DATE;
DECLARE @QueryText NVARCHAR(MAX);
DECLARE @CompanyLanguage NVARCHAR(MAX);
DECLARE @CompanyCurrency NVARCHAR(MAX);
DECLARE @Profit NUMERIC(19,6);
SELECT @CompanyLanguage = ACS.CountryId, @CompanyCurrency = ACS.CompanyCurrencyId FROM AdminCompanySetting ACS;
SET @BalanceDate = CONVERT(DATE, @parxDate, 104);
SELECT
@Profit = -1*SUM(B.Balance)
FROM FinanceProfitLossGroup FPLG1
JOIN FinanceProfitLossGroup FPLG2 ON FPLG2.ParentId = FPLG1.Id And FPLG1.ParentId IS NULL
JOIN FinanceProfitLossGroup FPLG3 ON FPLG3.ParentId = FPLG2.Id
JOIN FinanceProfitLossGroup FPLG4 ON FPLG4.ParentId = FPLG3.Id
LEFT JOIN FinanceAccountPlan FAP ON FAP.ProfitLossGroupId = FPLG4.Id
LEFT JOIN
(
SELECT
FBP.AccountId
, SUM(FBP.Debit - FBP.Credit) Balance
FROM FinancePosting FB
JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
WHERE
FB.ReceiptDate <= @BalanceDate AND (FB.Closing = 0 OR YEAR(FB.ReceiptDate) != YEAR(@BalanceDate))
GROUP BY FBP.AccountId
) B ON B.AccountId = FAP.Id;
SELECT
FBG1.Id BalanceSheetSection
, FBG1.Name GroupName1
, FBG2.Id Group2Id
, FBG2.Name GroupName2
, FBG3.Id Group3Id
, FBG3.Name GroupName3
, FBG4.Id Group4Id
, FBG4.Name GroupName4
, FAP.AccountNumber
, FAP.Name AccountName
, (CASE WHEN FBG1.Id = 2 THEN -1 ELSE 1 END) * ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId WHERE FB.ReceiptDate <= @BalanceDate And (FB.Closing = 0 OR YEAR(FB.ReceiptDate) != YEAR(@BalanceDate)) And FBP.AccountId = FAP.Id),0) Balance
, @CompanyCurrency Currency
, CONVERT(VARCHAR(10), @BalanceDate, 104) UptoDate
INTO #BalanceTable
FROM FinanceBalanceGroup FBG1
JOIN FinanceBalanceGroup FBG2 ON FBG2.ParentId = FBG1.Id And FBG1.ParentId IS NULL
JOIN FinanceBalanceGroup FBG3 ON FBG3.ParentId = FBG2.Id
JOIN FinanceBalanceGroup FBG4 ON FBG4.ParentId = FBG3.Id
JOIN FinanceAccountPlan FAP ON FBG4.Id = FAP.BalanceGroupId
WHERE FAP.AssignmentId = 2
And FAP.Active = 1
UNION ALL
SELECT
2 BalanceSheetSection
, 'Passiva' GroupName1
, 8 Group2Id
, 'Eigenkapital' GroupName2
, 26 Group3Id
, 'Bilanzgewinn / Bilanzverlust' GroupName3
, 71 Group4Id
, 'Jahresüberschuss / Jahresfehlbetrag' GroupName4
, 0 AccountNumber
, IIF(ISNULL(@Profit,0) >= 0,'Jahresüberschuss','Jahresverlust')AccountName
, ISNULL(@Profit,0) Balance
, @CompanyCurrency Currency
, CONVERT(VARCHAR(10), @BalanceDate, 104) UptoDate
SELECT * FROM #BalanceTable BT
WHERE
(CASE
WHEN @HideZeroValueAccounts = 'Y' And ISNULL(BT.Balance,0) <> 0 THEN 1
WHEN @HideZeroValueAccounts = 'Y' And ISNULL(BT.Balance,0) =  0 THEN 0
WHEN @HideZeroValueAccounts = 'N' THEN 1 END) = 1
DROP TABLE #BalanceTable
END;
GO
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE OR ALTER PROCEDURE
xPROC_AnnualProfitLoss
-- xPROC_AnnualProfitLoss
-- PURPOSE: Get Data for P&L List
-- Creator: MH
-- Created: 2023-07-26
-- Changed: 
(
@parxFromPeriod NVARCHAR(6)
, @parxToPeriod NVARCHAR(6)
, @HideZeroValueAccounts CHAR = 'Y'
)
AS
BEGIN
DECLARE
@FromDate DATE
, @ToDate DATE
, @CompanyLanguage NVARCHAR(MAX)
, @CompanyCurrency NVARCHAR(MAX)
, @FromPeriodName NVARCHAR(100)
, @ToPeriodName NVARCHAR(100)
, @FromPostingPeriodId INT
, @ToPostingPeriodId INT
, @PreFromPeriod NVARCHAR(6)
, @PreToPeriod NVARCHAR(6);
SELECT @PreFromPeriod = CONVERT(VARCHAR, LEFT(@parxFromPeriod, 4)-1) + CONVERT(VARCHAR, RIGHT(@parxFromPeriod, 2));
SELECT @PreToPeriod = CONVERT(VARCHAR, LEFT(@parxToPeriod, 4)-1) + CONVERT(VARCHAR, RIGHT(@parxToPeriod, 2));
SELECT @FromPostingPeriodId = FBP.Id, @FromPeriodName = FBP.Name
FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @parxFromPeriod;
SELECT @ToPostingPeriodId = FBP.Id, @ToPeriodName = FBP.Name
FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @parxToPeriod;
SELECT @FromDate = DATEFROMPARTS(FBP.FiscalYearId, FBP.FiscalPeriodId, 1) FROM FinancePostingPeriod FBP WHERE FBP.Id = @FromPostingPeriodId
SELECT @ToDate = EOMONTH(DATEFROMPARTS(FBP.FiscalYearId, FBP.FiscalPeriodId, 1)) FROM FinancePostingPeriod FBP WHERE FBP.Id = @ToPostingPeriodId
SELECT @CompanyLanguage = ACS.CountryId, @CompanyCurrency = ACS.CompanyCurrencyId FROM AdminCompanySetting ACS;
SELECT
FPLG1.Id GroupId1
, FPLG1.Name GroupName1
, FPLG2.Id GroupId2
, FPLG2.Name GroupName2
, FPLG3.Id GroupId3
, FPLG3.Name GroupName3
, FPLG4.Id GroupId4
, FPLG4.Name GroupName4
, FAP.AccountNumber
, FAP.Name AccountName
, -1* ISNULL(B.Balance,0) Balance
, @CompanyCurrency Currency
, CONVERT(VARCHAR(10), @FromDate, 104) FromDate
, CONVERT(VARCHAR(10), @ToDate, 104) ToDate
, @FromPeriodName FromPeriodName
, @ToPeriodName ToPeriodName
INTO #PLTable
FROM FinanceProfitLossGroup FPLG1
JOIN FinanceProfitLossGroup FPLG2 ON FPLG2.ParentId = FPLG1.Id And FPLG1.ParentId IS NULL
JOIN FinanceProfitLossGroup FPLG3 ON FPLG3.ParentId = FPLG2.Id
JOIN FinanceProfitLossGroup FPLG4 ON FPLG4.ParentId = FPLG3.Id
LEFT JOIN FinanceAccountPlan FAP ON FAP.ProfitLossGroupId = FPLG4.Id
LEFT JOIN
(
SELECT
FBP.AccountId
, SUM(FBP.Debit - FBP.Credit) Balance
FROM FinancePosting FB
JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId And @ToPostingPeriodId And FB.Closing = 0 --And FB.Opening = 0
GROUP BY FBP.AccountId
) B ON B.AccountId = FAP.Id
SELECT * FROM #PLTable PLT
WHERE
(CASE
WHEN @HideZeroValueAccounts = 'Y' And ISNULL(PLT.Balance,0) <> 0 THEN 1
WHEN @HideZeroValueAccounts = 'Y' And ISNULL(PLT.Balance,0) =  0 THEN 0
WHEN @HideZeroValueAccounts = 'N' THEN 1 END) = 1
ORDER BY 1, 3, 5, 7
DROP TABLE #PLTable;
END; -- Procedure
GO
-----------------END xPROC_AnnualProfitLoss ----------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE OR ALTER PROCEDURE
[dbo].[xPROC_BusinessPerformanceEvaluation]
-- xPROC_BusinessPerformanceEvaluation
-- PURPOSE: Get Data for BPE
-- Creator: JH
-- Created: 2025-02-04
-- Changed: 
(
@parxFromPeriod NVARCHAR(6)
, @parxToPeriod NVARCHAR(6)
, @HideZeroValueAccounts CHAR = 'Y'
)
AS
BEGIN
DECLARE @FromDate DATE, @ToDate DATE, @PreviousYearFromDate DATE, @PreviousYearToDate DATE;
DECLARE @CompanyLanguage NVARCHAR(MAX), @CompanyName NVARCHAR(MAX);
DECLARE @CompanyCurrency NVARCHAR(MAX);
DECLARE @FromPostingPeriodId INT, @ToPostingPeriodId INT, @PreFromPostingPeriodId INT, @PreToPostingPeriodId INT
DECLARE @PreFromPeriod NVARCHAR(6), @PreToPeriod NVARCHAR(6)
SELECT @PreFromPeriod = CONVERT(VARCHAR, LEFT(@parxFromPeriod, 4)-1) + CONVERT(VARCHAR, RIGHT(@parxFromPeriod, 2))
SELECT @PreToPeriod = CONVERT(VARCHAR, LEFT(@parxToPeriod, 4)-1) + CONVERT(VARCHAR, RIGHT(@parxToPeriod, 2))
SELECT @FromPostingPeriodId = FBP.Id FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @parxFromPeriod
SELECT @ToPostingPeriodId = FBP.Id FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @parxToPeriod
SELECT @PreFromPostingPeriodId = FBP.Id FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @PreFromPeriod
SELECT @PreToPostingPeriodId = FBP.Id FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @PreToPeriod
--SELECT @FromDate = DATEFROMPARTS(FBP.FiscalYearId, IIF(FBP.FiscalPeriodId=0,1,IIF(FBP.FiscalPeriodId=13,12,FBP.FiscalPeriodId)), 1) FROM FinancePostingPeriod FBP WHERE FBP.Id = @FromPostingPeriodId
SELECT @FromDate = DATEFROMPARTS(FBP.FiscalYearId, FBP.FiscalPeriodId, 1) FROM FinancePostingPeriod FBP WHERE FBP.Id = @FromPostingPeriodId
--SELECT @ToDate = EOMONTH(DATEFROMPARTS(FBP.FiscalYearId, IIF(FBP.FiscalPeriodId=0,1,IIF(FBP.FiscalPeriodId=13,12,FBP.FiscalPeriodId)), 1)) FROM FinancePostingPeriod FBP WHERE FBP.Id = @ToPostingPeriodId
SELECT @ToDate = EOMONTH(DATEFROMPARTS(FBP.FiscalYearId, FBP.FiscalPeriodId, 1)) FROM FinancePostingPeriod FBP WHERE FBP.Id = @ToPostingPeriodId
IF @PreFromPostingPeriodId IS NULL AND @PreToPostingPeriodId IS NULL
BEGIN
SET @PreFromPostingPeriodId = 0;
SET @PreToPostingPeriodId = 0;
END;
IF @PreFromPostingPeriodId IS NOT NULL AND @PreToPostingPeriodId IS NULL
BEGIN
SET @PreToPostingPeriodId = @PreFromPostingPeriodId;
END;
IF @PreFromPostingPeriodId IS NULL AND @PreToPostingPeriodId IS NOT NULL
BEGIN
SET @PreFromPostingPeriodId = @PreToPostingPeriodId;
END;
SELECT @CompanyLanguage = ACS.CountryId, @CompanyCurrency = ACS.CompanyCurrencyId, @CompanyName = ACS.CompanyName FROM AdminCompanySetting ACS;
SELECT
CONVERT(VARCHAR, @FromDate, 104) FromDate
, CONVERT(VARCHAR, @ToDate, 104) ToDate
, @CompanyName CompanyName
, FBAG1.Id IdLevel1
, FBAG1.Name NameLevel1
, FBAG2.Id IdLevel2
, FBAG2.Name NameLevel2
, FBAG3.Id IdLevel3
, FBAG3.Name NameLevel3
, FAP.Id
, FAP.Name
, FAP.Matchcode
, -1*ISNULL(PY.PrevYearBalance,0) PrevYearBalance
, -1*ISNULL(CY.CurYearBalance,0) CurYearBalance
INTO #BPETable
FROM
FinanceBusinessAssessmentGroup FBAG1
JOIN FinanceBusinessAssessmentGroup FBAG2 ON FBAG2.ParentId = FBAG1.Id
JOIN FinanceBusinessAssessmentGroup FBAG3 ON FBAG3.ParentId = FBAG2.Id
JOIN FinanceAccountPlan FAP ON FAP.BusinessAssessmentGroupId = FBAG3.Id
LEFT JOIN
(
SELECT
FBP.AccountId
, SUM(FBP.Debit - FBP.Credit) CurYearBalance
FROM FinancePosting FB
JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId And @ToPostingPeriodId
And FB.Closing = 0
GROUP BY FBP.AccountId
) CY ON CY.AccountId = FAP.Id
LEFT JOIN
(
SELECT
FBP.AccountId
, SUM(FBP.Debit - FBP.Credit) PrevYearBalance
FROM FinancePosting FB
JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @PreFromPostingPeriodId And @PreToPostingPeriodId
And FB.Closing = 0
GROUP BY FBP.AccountId
) PY ON PY.AccountId = FAP.Id
WHERE FBAG1.ParentId IS NULL
ORDER BY
FBAG1.Id, FBAG2.Id,FBAG3.Id, FAP.Id;
SELECT * FROM #BPETable BPE
ORDER BY 4, 6, 8;
DROP TABLE #BPETable;
END;
GO
-----------------END xPROC_BusinessPerformanceEvaluation ----------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE OR ALTER PROCEDURE
[dbo].[xPROC_BalanceSheet_TTable]
-- xPROC_BalanceSheet_TTable
-- PURPOSE: Get Data for Balance Sheet
-- Creator: JH
-- Created: 2025-02-04
-- Changed: 
(
@parxDate NVARCHAR(10)
)
AS
BEGIN
DECLARE @CurYearBalanceDate DATE, @PreYearBalanceDate DATE;
DECLARE @CompanyName NVARCHAR(MAX);
DECLARE @CompanyCurrency NVARCHAR(MAX);
DECLARE @CurYearProfit NUMERIC(19,6), @PreYearProfit NUMERIC(19,6);
SELECT
@CompanyName = ACS.CompanyName
, @CompanyCurrency = ACS.CompanyCurrencyId
FROM AdminCompanySetting ACS WHERE ACS.Id = 1;
SET @CurYearBalanceDate = CONVERT(DATE, @parxDate, 104)
SET @PreYearBalanceDate = EOMONTH(DATEFROMPARTS(YEAR(DATEADD(YY, -1, @CurYearBalanceDate)), 12,31));
SELECT
@PreYearProfit = -1*SUM(B.Balance)
FROM FinanceProfitLossGroup FPLG1
JOIN FinanceProfitLossGroup FPLG2 ON FPLG2.ParentId = FPLG1.Id And FPLG1.ParentId IS NULL
JOIN FinanceProfitLossGroup FPLG3 ON FPLG3.ParentId = FPLG2.Id
JOIN FinanceProfitLossGroup FPLG4 ON FPLG4.ParentId = FPLG3.Id
LEFT JOIN FinanceAccountPlan FAP ON FAP.ProfitLossGroupId = FPLG4.Id
LEFT JOIN
(
SELECT
FBP.AccountId
, SUM(FBP.Debit - FBP.Credit) Balance
FROM FinancePosting FB
JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.ReceiptDate <= @PreYearBalanceDate
GROUP BY FBP.AccountId
) B ON B.AccountId = FAP.Id;
SELECT
@CurYearProfit = -1*SUM(B.Balance)
FROM FinanceProfitLossGroup FPLG1
JOIN FinanceProfitLossGroup FPLG2 ON FPLG2.ParentId = FPLG1.Id And FPLG1.ParentId IS NULL
JOIN FinanceProfitLossGroup FPLG3 ON FPLG3.ParentId = FPLG2.Id
JOIN FinanceProfitLossGroup FPLG4 ON FPLG4.ParentId = FPLG3.Id
LEFT JOIN FinanceAccountPlan FAP ON FAP.ProfitLossGroupId = FPLG4.Id
LEFT JOIN
(
SELECT
FBP.AccountId
, SUM(FBP.Debit - FBP.Credit) Balance
FROM FinancePosting FB
JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.ReceiptDate <= @CurYearBalanceDate
GROUP BY FBP.AccountId
) B ON B.AccountId = FAP.Id;
SELECT
FBG1.Id Level1Id,
FBG1.Name Level1Name,
FBG2.Id Level2Id,
FBG2.Name Level2Name
, (CASE WHEN FBG1.Id = 2 THEN -1 ELSE 1 END) * ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId And FB.ReceiptDate <= @CurYearBalanceDate And FBP.AccountId = FAP.Id),0) CurBalance
, (CASE WHEN FBG1.Id = 2 THEN -1 ELSE 1 END) * ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId And FB.ReceiptDate <= @PreYearBalanceDate And FBP.AccountId = FAP.Id),0) PreBalance
INTO #BalanceTable1
FROM FinanceBalanceGroup FBG1
JOIN FinanceBalanceGroup FBG2 ON FBG2.ParentId = FBG1.Id And FBG1.ParentId IS NULL
JOIN FinanceBalanceGroup FBG3 ON FBG3.ParentId = FBG2.Id
JOIN FinanceBalanceGroup FBG4 ON FBG4.ParentId = FBG3.Id
JOIN FinanceAccountPlan FAP ON FBG4.Id = FAP.BalanceGroupId
WHERE FBG1.Id = 1 And FAP.AssignmentId = 2
SELECT
ROW_NUMBER() OVER(ORDER BY BT1.Level2Id) Id
, CASE
WHEN BT1.Level2Id = 3 THEN 'A'
WHEN BT1.Level2Id = 4 THEN 'B'
WHEN BT1.Level2Id = 5 THEN 'C'
WHEN BT1.Level2Id = 6 THEN 'D'
WHEN BT1.Level2Id = 7 THEN 'E'
ELSE ''
END RowId
, BT1.Level1Id
, BT1.Level1Name
, BT1.Level2Id
, BT1.Level2Name
, SUM(BT1.CurBalance) CurBalance
, SUM(BT1.PreBalance) PreBalance
INTO #BalanceTable3
FROM #BalanceTable1 BT1
GROUP BY
BT1.Level1Id
, BT1.Level1Name
, BT1.Level2Id
, BT1.Level2Name
HAVING SUM(BT1.CurBalance) <> 0 OR SUM(BT1.PreBalance) <> 0
SELECT
FBG1.Id Level1Id,
FBG1.Name Level1Name,
FBG2.Id Level2Id,
FBG2.Name Level2Name
, (CASE WHEN FBG1.Id = 2 THEN -1 ELSE 1 END) * ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId And FB.ReceiptDate <= @CurYearBalanceDate And FBP.AccountId = FAP.Id),0) CurBalance
, (CASE WHEN FBG1.Id = 2 THEN -1 ELSE 1 END) * ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId And FB.ReceiptDate <= @PreYearBalanceDate And FBP.AccountId = FAP.Id),0) PreBalance
INTO #BalanceTable2
FROM FinanceBalanceGroup FBG1
JOIN FinanceBalanceGroup FBG2 ON FBG2.ParentId = FBG1.Id And FBG1.ParentId IS NULL
JOIN FinanceBalanceGroup FBG3 ON FBG3.ParentId = FBG2.Id
JOIN FinanceBalanceGroup FBG4 ON FBG4.ParentId = FBG3.Id
JOIN FinanceAccountPlan FAP ON FBG4.Id = FAP.BalanceGroupId
WHERE FBG1.Id = 2 And FAP.AssignmentId = 2
SELECT
ROW_NUMBER() OVER(ORDER BY BT2.Level2Id) Id
, CASE
WHEN BT2.Level2Id = 8 THEN 'A'
WHEN BT2.Level2Id = 9 THEN 'B'
WHEN BT2.Level2Id = 10 THEN 'C'
WHEN BT2.Level2Id = 11 THEN 'D'
ELSE ''
END RowId
, BT2.Level1Id
, BT2.Level1Name
, BT2.Level2Id
, BT2.Level2Name
, SUM(BT2.CurBalance) CurBalance
, SUM(BT2.PreBalance) PreBalance
INTO #BalanceTable4
FROM #BalanceTable2 BT2
GROUP BY
BT2.Level1Id
, BT2.Level1Name
, BT2.Level2Id
, BT2.Level2Name
HAVING SUM(BT2.CurBalance) <> 0 OR SUM(BT2.PreBalance) <> 0
UNION ALL
SELECT
9999 Id
, 'E' RowId
, NULL Level1Id
, '' Level1Name
, NULL Level2Id
, IIF(ISNULL(@CurYearProfit,0) >= 0 ,'Jahresüberschuss','Jahresverlust') Level2Name
, ISNULL(@CurYearProfit,0) CurBalance
, ISNULL(@PreYearProfit,0) PreBalance
SELECT
BT3.RowId+'.' AktivaRowId
, UPPER(BT3.Level1Name) ActivaHeading
, BT3.Level2Name ActivaSubHeading
, BT3.CurBalance ActivaCurBal
, BT3.PreBalance ActivaPreBal
, BT4.RowId+'.' PassivaRowId
, UPPER(BT4.Level1Name) PassivaHeading
, BT4.Level2Name PassivaSubHeading
, BT4.CurBalance PassivaCurBal
, BT4.PreBalance PassivaPreBal
, @CompanyCurrency Currency
, @CompanyName CompanyName
, CONVERT(VARCHAR(10), @CurYearBalanceDate, 104) CurYearBalDate
, CONVERT(VARCHAR(10), @PreYearBalanceDate, 104) PreYearBalDate
FROM #BalanceTable3 BT3 FULL OUTER JOIN #BalanceTable4 BT4 ON BT3.Id = BT4.Id
DROP TABLE #BalanceTable1
DROP TABLE #BalanceTable2
DROP TABLE #BalanceTable3
DROP TABLE #BalanceTable4
END;
GO
-----------------END xPROC_BalanceSheet_TTable ----------------------------------------------
