CREATE OR ALTER PROCEDURE
xPROC_TrialBalance
-- xPROC_TrialBalance
-- PURPOSE: Get Data for Trial Balance
-- Creator: JH
-- Created: 2025-04-14
-- Changed:
-- PURPOSE: This procedure generate the trial balance based on the given periods and other supplied parameters.
(
@parxFromPeriod NVARCHAR(6)
, @parxToPeriod NVARCHAR(6)
, @HideZeroValueAccounts CHAR = 'Y'
, @parxAccount CHAR = 'Y'
, @parxCustomer CHAR = 'Y'
, @parxSupplier CHAR = 'Y'
)
AS
BEGIN
DECLARE
@FromDate DATE
, @ToDate DATE
, @CompanyLanguage NVARCHAR(MAX)
, @CompanyCurrency NVARCHAR(MAX)
, @FromPeriodName NVARCHAR(100)
, @ToPeriodName NVARCHAR(100)
, @FromPostingPeriodId INT
, @ToPostingPeriodId INT
, @FiscalYear INT
, @LastOfPreviousYearPostingPeriodId INT
, @CurrentYearFirstPostingPeriodId INT;
SELECT @FromPostingPeriodId = FBP.Id, @FromPeriodName = FBP.Name, @FiscalYear = FBP.FiscalYearId
FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @parxFromPeriod;
SELECT TOP 1 @CurrentYearFirstPostingPeriodId = FBP.Id FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearId = @FiscalYear ORDER BY FBP.FiscalPeriodId;
SELECT TOP 1 @LastOfPreviousYearPostingPeriodId = FBP.Id FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearId = (@FiscalYear-1) ORDER BY FBP.FiscalPeriodId DESC;
SELECT @ToPostingPeriodId = FBP.Id, @ToPeriodName = FBP.Name
FROM FinancePostingPeriod FBP WHERE FBP.FiscalYearPeriod = @parxToPeriod;
SELECT @FromDate = DATEFROMPARTS(FBP.FiscalYearId, FBP.FiscalPeriodId, 1) FROM FinancePostingPeriod FBP WHERE FBP.Id = @FromPostingPeriodId
SELECT @ToDate = EOMONTH(DATEFROMPARTS(FBP.FiscalYearId, FBP.FiscalPeriodId, 1)) FROM FinancePostingPeriod FBP WHERE FBP.Id = @ToPostingPeriodId
SELECT @CompanyLanguage = ACS.CountryId, @CompanyCurrency = ACS.CompanyCurrencyId FROM AdminCompanySetting ACS;
SELECT
1 SecId
, 'Sachkonten' SectionType
, FAG.Id
, FAG.Name FAGroupName
, FAP.AccountNumber
, FAP.Name AccountName
, ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2
And FB.PostingPeriodId <= @LastOfPreviousYearPostingPeriodId And FBP.AccountId = FAP.Id),0) +
ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2
And FB.Opening = 1 And FB.PostingPeriodId BETWEEN @CurrentYearFirstPostingPeriodId AND @ToPostingPeriodId  And FBP.AccountId = FAP.Id),0) OpeningBalance
, ISNULL(( SELECT SUM(FBP.Debit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId AND @ToPostingPeriodId And FBP.AccountId = FAP.Id And FB.Opening = 0 And FB.Closing = 0),0) PeriodDrBalance
, ISNULL(( SELECT SUM(FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId AND @ToPostingPeriodId And FBP.AccountId = FAP.Id And FB.Opening = 0 And FB.Closing = 0),0) PeriodCrBalance
, ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
LEFT JOIN FinancePostingPeriod PeriodFB ON PeriodFB.Id = FB.PostingPeriodId
LEFT JOIN FinancePostingPeriod PeriodTo ON PeriodTo.Id = @ToPostingPeriodId
WHERE
FB.PostingPeriodId <= @ToPostingPeriodId AND PeriodFB.FiscalYearId = PeriodTo.FiscalYearId And FB.Closing = 0
And FBP.AccountId = FAP.Id),0) +
ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2
And FB.PostingPeriodId <= @LastOfPreviousYearPostingPeriodId And FBP.AccountId = FAP.Id),0) ClosingBalance
, @CompanyCurrency Currency
, CONVERT(VARCHAR(10), @FromDate, 104) FromDate
, CONVERT(VARCHAR(10), @ToDate, 104) ToDate
, @FromPeriodName FromPeriodName
, @ToPeriodName ToPeriodName
INTO #TBTable
FROM FinanceAccountPlan FAP
JOIN FinanceAccountGroup FAG ON FAP.AccountGroupId = FAG.Id
WHERE @parxAccount = 'Y';
SELECT
2 SecId
, 'Debitoren' SectionType
, P.Id Id
, '' FAGroupName
, PD.Id AS BusinessPartnerNumber
, P.Name1 AccountName
, ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId <= @LastOfPreviousYearPostingPeriodId And FBP.PartnerDetailId = PD.Id
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2 ),0) +
ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.Opening = 1 And FB.PostingPeriodId BETWEEN @CurrentYearFirstPostingPeriodId AND @ToPostingPeriodId And FBP.PartnerDetailId = PD.Id
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2 ),0)  OpeningBalance
, ISNULL(( SELECT SUM(FBP.Debit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId AND @ToPostingPeriodId And FBP.PartnerDetailId = PD.Id And FB.Opening = 0 And FB.Closing = 0
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2),0) PeriodDrBalance
, ISNULL(( SELECT SUM(FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId AND @ToPostingPeriodId And FBP.PartnerDetailId = PD.Id And FB.Opening = 0 And FB.Closing = 0
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2),0) PeriodCrBalance
, ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
LEFT JOIN FinancePostingPeriod PeriodFB ON PeriodFB.Id = FB.PostingPeriodId
LEFT JOIN FinancePostingPeriod PeriodTo ON PeriodTo.Id = @ToPostingPeriodId
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2
WHERE
FB.PostingPeriodId <= @ToPostingPeriodId AND PeriodFB.FiscalYearId = PeriodTo.FiscalYearId And FB.Closing = 0
And FBP.PartnerDetailId = PD.Id
),0) +
ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId <= @LastOfPreviousYearPostingPeriodId And FBP.PartnerDetailId = PD.Id
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2 ),0) 
ClosingBalance
, @CompanyCurrency Currency
, CONVERT(VARCHAR(10), @FromDate, 104) FromDate
, CONVERT(VARCHAR(10), @ToDate, 104) ToDate
, @FromPeriodName FromPeriodName
, @ToPeriodName ToPeriodName
INTO #CTBTable
FROM
Partner P
JOIN PartnerDetail PD ON P.Id = PD.PartnerId And PD.PartnerTypeId = 'Customer'
WHERE @parxCustomer = 'Y';
SELECT
3 SecId
, 'Kreditoren' SectionType
, P.Id Id
, '' FAGroupName
, PD.Id AS BusinessPartnerNumber
, P.Name1 AccountName
, ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId <= @LastOfPreviousYearPostingPeriodId And FBP.PartnerDetailId = PD.Id
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2 ),0) +
ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.Opening = 1 And FB.PostingPeriodId BETWEEN @CurrentYearFirstPostingPeriodId AND @ToPostingPeriodId And FBP.PartnerDetailId = PD.Id
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2 ),0) OpeningBalance
, ISNULL(( SELECT SUM(FBP.Debit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId AND @ToPostingPeriodId And FBP.PartnerDetailId = PD.Id And FB.Opening = 0 And FB.Closing = 0
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2),0) PeriodDrBalance
, ISNULL(( SELECT SUM(FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId BETWEEN @FromPostingPeriodId AND @ToPostingPeriodId And FBP.PartnerDetailId = PD.Id And FB.Opening = 0 And FB.Closing = 0
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2),0) PeriodCrBalance
, ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB
JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
LEFT JOIN FinancePostingPeriod PeriodFB ON PeriodFB.Id = FB.PostingPeriodId
LEFT JOIN FinancePostingPeriod PeriodTo ON PeriodTo.Id = @ToPostingPeriodId
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2
WHERE
FB.PostingPeriodId <= @ToPostingPeriodId
AND PeriodFB.FiscalYearId = PeriodTo.FiscalYearId
And FB.Closing = 0
And FBP.PartnerDetailId = PD.Id
),0) +
ISNULL(( SELECT SUM(FBP.Debit - FBP.Credit) FROM FinancePosting FB JOIN FinancePostingPosition FBP ON FB.Id = FBP.PostingId
And FB.PostingPeriodId <= @LastOfPreviousYearPostingPeriodId And FBP.PartnerDetailId = PD.Id
JOIN FinanceAccountPlan FAP1 ON FBP.AccountId = FAP1.Id
JOIN FinanceAccountAssignment FAA ON FAP1.AssignmentId = FAA.Id And FAP1.AssignmentId = 2 ),0)
ClosingBalance
, @CompanyCurrency Currency
, CONVERT(VARCHAR(10), @FromDate, 104) FromDate
, CONVERT(VARCHAR(10), @ToDate, 104) ToDate
, @FromPeriodName FromPeriodName
, @ToPeriodName ToPeriodName
INTO #STBTable
FROM
Partner P
JOIN PartnerDetail PD ON P.Id = PD.PartnerId And PD.PartnerTypeId = 'Supplier'
WHERE @parxSupplier = 'Y';
SELECT *
FROM
(
SELECT * FROM #TBTable
UNION ALL
SELECT * FROM #CTBTable
UNION ALL
SELECT * FROM #STBTable
) TBT
WHERE
(CASE
WHEN @HideZeroValueAccounts = 'Y' And (ISNULL(TBT.OpeningBalance,0) <> 0 OR ISNULL(TBT.PeriodDrBalance,0) <> 0 OR ISNULL(TBT.PeriodCrBalance,0) <> 0 OR ISNULL(TBT.ClosingBalance,0) <> 0) THEN 1
WHEN @HideZeroValueAccounts = 'Y' And ISNULL(TBT.PeriodCrBalance,0) =  0 AND ISNULL(TBT.PeriodDrBalance,0) = 0 AND ISNULL(TBT.OpeningBalance,0) = 0 AND ISNULL(TBT.ClosingBalance,0) = 0 THEN 0
WHEN @HideZeroValueAccounts = 'N' THEN 1 END) = 1
ORDER BY 1,3,5
DROP TABLE #TBTable;
DROP TABLE #CTBTable;
DROP TABLE #STBTable;
END; -- Procedure
GO
-----------------END xPROC_BalanceSheet_TTable ----------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC740_CalendarWorkingDay_Wizard
--  ----------------------------------------------------------------------
-- PURPOSE: Create Records for given range with given Times for CalendarWorkingDay
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) INSERT INTO CalendarWorkingDay
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxCalendarNameId INT
, @parxStartDate DATE
, @parxEndDate DATE
, @parxMondayStart TIME
, @parxMondayEnd TIME
, @parxTuesdayStart TIME
, @parxTuesdayEnd TIME
, @parxWednesdayStart TIME
, @parxWednesdayEnd TIME
, @parxThursdayStart TIME
, @parxThursdayEnd TIME
, @parxFridayStart TIME
, @parxFridayEnd TIME
, @parxSaturdayStart TIME
, @parxSaturdayEnd TIME
, @parxSundayStart TIME
, @parxSundayEnd TIME
AS
BEGIN
SET NOCOUNT ON;
SET XACT_ABORT ON;
BEGIN TRANSACTION;
BEGIN TRY
-- 10.) DECLARE, SELECT, CALCULATE
SET DATEFIRST 1;  -- Montag = 1
-- 15.) Resolve Server Time Zone (Name für AT TIME ZONE ermitteln)
DECLARE
@UseTimeZone SYSNAME = NULL
, @RegTzKey NVARCHAR(128) = NULL
, @curOffsetStr NVARCHAR(6) = RIGHT(CONVERT(VARCHAR(34), SYSDATETIMEOFFSET(), 127), 6); -- z.B. +02:00
-- Versuch 1: Registry (Windows) → echter TimeZoneKeyName, z.B. 'W. Europe Standard Time'
BEGIN TRY
EXEC master.dbo.xp_regread
'HKEY_LOCAL_MACHINE'
, 'SYSTEM\CurrentControlSet\Control\TimeZoneInformation'
, 'TimeZoneKeyName'
, @RegTzKey OUTPUT;
SET @UseTimeZone = NULLIF(REPLACE(@RegTzKey, CHAR(0), ''), '');
END TRY
BEGIN CATCH
-- Ignorieren, Fallback 2
END CATCH;
-- Versuch 2: Fallback über aktuellen Offset (nicht eindeutig, aber brauchbar)
IF @UseTimeZone IS NULL
BEGIN
SELECT TOP (1) @UseTimeZone = name
FROM sys.time_zone_info
WHERE current_utc_offset = @curOffsetStr
ORDER BY name;
END
-- Versuch 3: Letzter Fallback
IF @UseTimeZone IS NULL
BEGIN
SET @UseTimeZone = 'UTC';
END
;WITH N AS
(
SELECT TOP (DATEDIFF(DAY, @parxStartDate, @parxEndDate) + 1)
ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1 AS n
FROM master..spt_values
)
, DateRange AS
(
SELECT
DATEADD(day, n, CAST(@parxStartDate AS date)) AS d
FROM N
)
-- 20.) INSERT INTO CalendarWorkingDay (DST-sicher, pro Datum umgerechnet; nur wenn Start/Ende vorhanden)
INSERT INTO CalendarWorkingDay
(
CalendarNameId
, WorkingDayStart
, WorkingDayEnd
)
SELECT
@parxCalendarNameId
, CAST((WT.StartLocal) AT TIME ZONE @UseTimeZone AT TIME ZONE 'UTC' AS datetimeoffset(0))
, CAST((WT.EndLocal  ) AT TIME ZONE @UseTimeZone AT TIME ZONE 'UTC' AS datetimeoffset(0))
FROM DateRange DR
CROSS APPLY (
SELECT
CASE DATEPART(weekday, DR.d)
WHEN 1 THEN CASE WHEN @parxMondayStart    IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxMondayStart    ), CAST(DR.d AS datetime2(0))) END
WHEN 2 THEN CASE WHEN @parxTuesdayStart   IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxTuesdayStart   ), CAST(DR.d AS datetime2(0))) END
WHEN 3 THEN CASE WHEN @parxWednesdayStart IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxWednesdayStart ), CAST(DR.d AS datetime2(0))) END
WHEN 4 THEN CASE WHEN @parxThursdayStart  IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxThursdayStart  ), CAST(DR.d AS datetime2(0))) END
WHEN 5 THEN CASE WHEN @parxFridayStart    IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxFridayStart    ), CAST(DR.d AS datetime2(0))) END
WHEN 6 THEN CASE WHEN @parxSaturdayStart  IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxSaturdayStart  ), CAST(DR.d AS datetime2(0))) END
WHEN 7 THEN CASE WHEN @parxSundayStart    IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxSundayStart    ), CAST(DR.d AS datetime2(0))) END
END AS StartLocal
,   CASE DATEPART(weekday, DR.d)
WHEN 1 THEN CASE WHEN @parxMondayEnd      IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxMondayEnd      ), CAST(DR.d AS datetime2(0))) END
WHEN 2 THEN CASE WHEN @parxTuesdayEnd     IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxTuesdayEnd     ), CAST(DR.d AS datetime2(0))) END
WHEN 3 THEN CASE WHEN @parxWednesdayEnd   IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxWednesdayEnd   ), CAST(DR.d AS datetime2(0))) END
WHEN 4 THEN CASE WHEN @parxThursdayEnd    IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxThursdayEnd    ), CAST(DR.d AS datetime2(0))) END
WHEN 5 THEN CASE WHEN @parxFridayEnd      IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxFridayEnd      ), CAST(DR.d AS datetime2(0))) END
WHEN 6 THEN CASE WHEN @parxSaturdayEnd    IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxSaturdayEnd    ), CAST(DR.d AS datetime2(0))) END
WHEN 7 THEN CASE WHEN @parxSundayEnd      IS NULL THEN NULL ELSE DATEADD(SECOND, DATEDIFF(SECOND, CAST('00:00:00' AS time), @parxSundayEnd      ), CAST(DR.d AS datetime2(0))) END
END AS EndLocal
) WT
WHERE WT.StartLocal IS NOT NULL
AND   WT.EndLocal   IS NOT NULL
AND NOT EXISTS (
SELECT 1
FROM CalendarWorkingDay cw
WHERE cw.CalendarNameId = @parxCalendarNameId
AND   CAST(cw.WorkingDayStart AS date) = DR.d
);
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber  INT             = ERROR_NUMBER()
, @ErrorLine    INT           = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000)= ERROR_MESSAGE();
IF XACT_STATE() <> 0
BEGIN
ROLLBACK TRANSACTION;
END
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC750_EmailAnswer
-- 99.12.30 00:00
--  ----------------------------------------------------------------------
-- PURPOSE: If OnAnswerClicked> 
-- Old Email: Seen = TRUE
-- Create new Email
-- Move Sender to Receiver
-- Copy Id to AnsweredParentId
-- Change Folder to Drafts
-- Add Prefix in Subject: "RE: "
-- Copy Cc
-- USAGE:
-- 10.) INSERT INTO EMAIL
-- 30.) UPDATE Original Email to Seen = true
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxEmailId INT
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRANSACTION;
BEGIN TRY
DECLARE @ServerTzOffset INT;
SET @ServerTzOffset = DATEPART(TZOFFSET, SYSDATETIMEOFFSET());
-- 10.) INSERT INTO EMAIL
INSERT INTO Email(
EmailAccountId
, EmailFolderId
, ReceivedDateTime
, SenderName
, SenderEmail
, Receiver
, Cc
, Bcc
, Subject
, BodyHtml
, BodyText
, MimeRaw
, Remark
, Pop3Ident
, ImapIdent
, Seen
, EntryDateTime
, IsSent
, SentDateTime
, NumOfSendingTries
, PrioHigh
, FollowUp
, Done
, MessageId
, AnsweredParentId
, ForwardedParentId
, Importance
, Tag
)
SELECT
EmailAccountId
, 3
, sysutcdatetime()
, EA.Name
, EA.EmailAddress
, SenderEmail
, Cc
, NULL
, LEFT(CONCAT(N'RE: ', Subject), 255)
, ISNULL(EA.Signature, N'') + N'<div style="border-top:1px solid #808080;padding-top:4px;">' + '<b>From:</b> ' + ISNULL(SenderEmail,   N'') + '<br>'  + '<b>Sent:</b> ' + CASE WHEN ReceivedDateTime IS NOT NULL THEN CONVERT(NVARCHAR(20), SWITCHOFFSET(ReceivedDateTime, @ServerTzOffset), 120) ELSE CONVERT(NVARCHAR(20), SWITCHOFFSET(SentDateTime, @ServerTzOffset), 120) END + '<br>'  + '<b>To:</b> ' + ISNULL(Receiver, N'') + '<br>'  + '<b>Subject:</b> ' + ISNULL(Subject,  N'') + '<br><br>' + ISNULL(BodyHtml, N'')
, '<b>From:</b> ' + SenderEmail + '<br>' + '<b>Sent:</b> ' + CONVERT(NVARCHAR(20), SWITCHOFFSET(ReceivedDateTime, @ServerTzOffset), 120) + '<br>' + '<b>To:</b> ' + Receiver + '<br>' + '<b>Subject:</b> ' + Subject + '<br><br>' + BodyHtml
, NULL
, NULL
, NULL
, NULL
, 1
, sysutcdatetime()
, 0
, NULL
, 0
, 0
, NULL
, 0
, NULL
, @parxEmailId
, NULL
, NULL
, NULL
FROM Email E
LEFT JOIN EmailAccount EA ON EA.Id = E.EmailAccountId
WHERE E.Id = @parxEmailId
DECLARE @newxEmailId INT;
SET @newxEmailId = SCOPE_IDENTITY();
-- 30.) UPDATE Original Email to Seen = true
UPDATE Email SET
Seen = 1
WHERE Id = @parxEmailId
-- 90.) RETURN
-- RETURN
SELECT @newxEmailId AS NewEmailId 
-- 91.) ERROR HANDLING
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
DECLARE
@ErrorNumber INT = ERROR_NUMBER()
, @ErrorLine INT = ERROR_LINE()
, @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
ROLLBACK TRANSACTION;
THROW;
END CATCH
END
GO
-- END  ----------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON; 
GO
CREATE OR ALTER PROCEDURE 
xPROC750_EmailForward
-- 99.12.30 00:00
-- PURPOSE:  If OnForwardClicked> 
-- Old Email: Seen = TRUE
-- Create new Email
-- Copy Id to ForwardedParentId
-- Change Folder to Drafts
-- Add Prefix in Subject: "FW: "
-- Copy Attachments
-- USAGE:
-- 10.) INSERT INTO EMAIL
-- 21.) CREATE new Attachments (INSERT, SELECT)
-- 30.) UPDATE Original Email to Seen = true
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxEmailId INT
AS
BEGIN
