, LEFT(CONCAT(N'FW: ', Subject), 255)
, ISNULL(EA.Signature, N'') + N'<div style="border-top:1px solid #808080;padding-top:4px;">' + '<b>From:</b> ' + ISNULL(SenderEmail,   N'') + '<br>'  + '<b>Sent:</b> ' + CASE WHEN ReceivedDateTime IS NOT NULL THEN CONVERT(NVARCHAR(20), SWITCHOFFSET(ReceivedDateTime, @ServerTzOffset), 120) ELSE CONVERT(NVARCHAR(20), SWITCHOFFSET(SentDateTime, @ServerTzOffset), 120) END + '<br>'  + '<b>To:</b> ' + ISNULL(Receiver, N'') + '<br>'  + '<b>Subject:</b> ' + ISNULL(Subject,  N'') + '<br><br>' + ISNULL(BodyHtml, N'')
, '<b>From:</b> ' + SenderEmail + '<br>' + '<b>Sent:</b> ' + CONVERT(NVARCHAR(20), SWITCHOFFSET(ReceivedDateTime, @ServerTzOffset), 120) + '<br>' + '<b>To:</b> ' + Receiver + '<br>' + '<b>Subject:</b> ' + Subject + '<br><br>' + BodyText
, NULL
