CREATE OR ALTER PROCEDURE 
xPROC900U_ExtraFields
-- 26.06.26 03:45
-- PURPOSE: E.g. saving value of Article.XTEST or Partner.XY
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 20.) Format the field value based on the data type
-- 30.) Build the dynamic SQL string for the update
-- 40.) Execute the dynamic SQL
-- 90.) RETURN
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxTableName         NVARCHAR(256),
@parxFilterField       NVARCHAR(256),
@parxFilterValue       NVARCHAR(MAX),
@parxFieldName         NVARCHAR(256),
@parxFieldValue        NVARCHAR(MAX) = NULL,
@parxFieldValueBinary  VARBINARY(MAX) = NULL,
@parxDataType          NVARCHAR(50)
AS
BEGIN
SET NOCOUNT ON;
DECLARE @dt NVARCHAR(50) = UPPER(@parxDataType);
DECLARE @SQL NVARCHAR(MAX);
DECLARE @ParamDef NVARCHAR(MAX);
-- FIX 1: Properly quote schema-qualified table names (dbo.Article -> [dbo].[Article])
DECLARE @QuotedTable NVARCHAR(512) =
CASE WHEN PARSENAME(@parxTableName, 2) IS NOT NULL
THEN QUOTENAME(PARSENAME(@parxTableName, 2)) + N'.'
ELSE N''
END + QUOTENAME(PARSENAME(@parxTableName, 1));
-- FIX 2: Look up filter column data type so @pkey is CAST to the correct type
--        (avoids implicit NVARCHAR->INT/GUID conversions, prevents index scans)
DECLARE @FilterColType NVARCHAR(128);
SELECT @FilterColType =
CASE
WHEN tp.name IN ('varchar','nvarchar','char','nchar','text','ntext')
THEN N'NVARCHAR(MAX)'
WHEN tp.name IN ('decimal','numeric')
THEN tp.name + N'(' + CAST(c.precision AS NVARCHAR(10)) + N',' + CAST(c.scale AS NVARCHAR(10)) + N')'
ELSE tp.name
END
FROM sys.columns c
JOIN sys.types tp ON c.system_type_id = tp.system_type_id AND c.user_type_id = tp.user_type_id
WHERE c.object_id = OBJECT_ID(@parxTableName)
AND c.name = @parxFilterField;
IF @FilterColType IS NULL
THROW 50002, 'Filter column not found in the specified table.', 1;
DECLARE @WhereClause NVARCHAR(500) =
N'WHERE ' + QUOTENAME(@parxFilterField) + N' = CAST(@pkey AS ' + @FilterColType + N')';
BEGIN TRANSACTION;
BEGIN TRY
IF (@dt = 'VARBINARYMAX')
BEGIN
SET @SQL = N'UPDATE ' + @QuotedTable + N'
SET ' + QUOTENAME(@parxFieldName) + N' = @pval ' + 
@WhereClause + N';';
SET @ParamDef = N'@pval VARBINARY(MAX), @pkey NVARCHAR(MAX)';
EXEC sp_executesql @SQL, @ParamDef, @pval=@parxFieldValueBinary, @pkey=@parxFilterValue;
COMMIT TRANSACTION;
RETURN;
END
-- NULL handling: set the column to NULL explicitly.
IF (@parxFieldValue IS NULL)
BEGIN
SET @SQL = N'UPDATE ' + @QuotedTable + N'
SET ' + QUOTENAME(@parxFieldName) + N' = NULL ' + 
@WhereClause + N';';
SET @ParamDef = N'@pkey NVARCHAR(MAX)';
EXEC sp_executesql @SQL, @ParamDef, @pkey=@parxFilterValue;
COMMIT TRANSACTION;
RETURN;
END
-- Non-null: cast inside SQL based on declared @dt
DECLARE @AssignExpr NVARCHAR(200);
IF (@dt IN ('NVARCHAR','NVARCHARMAX'))
SET @AssignExpr = N'@pval';  -- direct assign as NVARCHAR
ELSE IF (@dt = 'XML')
SET @AssignExpr = N'CAST(@pval AS XML)';
ELSE IF (@dt = 'INT')
SET @AssignExpr = N'CAST(@pval AS INT)';
ELSE IF (@dt = 'DECIMAL')
SET @AssignExpr = N'CAST(@pval AS DECIMAL(19,6))';
ELSE IF (@dt = 'GUID')
SET @AssignExpr = N'CAST(@pval AS UNIQUEIDENTIFIER)';
ELSE IF (@dt = 'BIT')
SET @AssignExpr = N'CAST(@pval AS BIT)';
-- FIX 3: Use CONVERT instead of TRY_CONVERT so invalid input is rejected (not silently NULLed)
ELSE IF (@dt = 'DATE')
SET @AssignExpr = N'CONVERT(DATE, @pval, 126)';
ELSE IF (@dt = 'DATETIME')
SET @AssignExpr = N'CONVERT(DATETIME, @pval, 126)';
ELSE IF (@dt = 'DATETIMEOFFSET')
SET @AssignExpr = N'CONVERT(DATETIMEOFFSET, @pval, 126)';
ELSE
THROW 50001, 'Unsupported data type.', 1;
SET @SQL = N'UPDATE ' + @QuotedTable + N'
SET ' + QUOTENAME(@parxFieldName) + N' = ' + @AssignExpr + N' ' + 
@WhereClause + N';';
SET @ParamDef = N'@pval NVARCHAR(MAX), @pkey NVARCHAR(MAX)';
EXEC sp_executesql @SQL, @ParamDef, @pval=@parxFieldValue, @pkey=@parxFilterValue;
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
IF XACT_STATE() <> 0 ROLLBACK TRANSACTION;
DECLARE @ErrorNumber INT = ERROR_NUMBER(),
@ErrorLine   INT = ERROR_LINE(),
@ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END
GO
-- END xPROC900U_ExtraFields ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC900_GetExtraFieldsData
-- 26.06.26 03:46
-- PURPOSE: Return selected record to get Extra Fields values from there
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxTableName NVARCHAR(MAX),
@parxFilterField NVARCHAR(MAX),
@parxFilterValue NVARCHAR(MAX),
@parxMode NVARCHAR(20) = N'FILTER'  -- 'FILTER' (default) | 'DEFAULTS' | 'ALL'
AS
BEGIN
SET NOCOUNT ON;
BEGIN TRY
DECLARE @SchemaName SYSNAME = ISNULL(PARSENAME(@parxTableName, 2), 'dbo');
DECLARE @TableName  SYSNAME = PARSENAME(@parxTableName, 1);
IF @TableName IS NULL
BEGIN
THROW 50001, 'Invalid @parxTableName. Provide [schema].[table] or [table].', 1;
END
-- Ensure table exists
IF NOT EXISTS (
SELECT 1
FROM sys.tables t
JOIN sys.schemas s ON s.schema_id = t.schema_id
WHERE t.name = @TableName AND s.name = @SchemaName
)
BEGIN
THROW 50002, 'Table not found.', 1;
END
DECLARE @FullName NVARCHAR(600) =
QUOTENAME(@SchemaName) + N'.' + QUOTENAME(@TableName);
----------------------------------------------------------------------
-- Branch 1: @parxMode = 'DEFAULTS' → return one row of defaults/nulls
----------------------------------------------------------------------
IF @parxMode = N'DEFAULTS'
BEGIN
/*
Build: SELECT
CAST((<default_expr>) AS <type>) AS [ColA],
CAST(NULL AS <type>)              AS [ColB], ...
FROM (VALUES(1)) v(x);
- If a column has a default constraint, use its definition.
- Otherwise return NULL.
- Exclude computed columns; identity columns will typically have no default → NULL.
*/
DECLARE @ColList NVARCHAR(MAX);
;WITH Cols AS
(
SELECT
c.column_id,
c.name                             AS ColName,
c.is_computed,
c.is_identity,
t.name                             AS TypeName,
c.max_length,
c.precision,
c.scale,
dc.definition                      AS DefaultDef
FROM sys.columns c
JOIN sys.types t
ON t.user_type_id = c.user_type_id
LEFT JOIN sys.default_constraints dc
ON dc.parent_object_id = c.object_id
AND dc.parent_column_id = c.column_id
JOIN sys.tables tb
ON tb.object_id = c.object_id
JOIN sys.schemas sc
ON sc.schema_id = tb.schema_id
WHERE tb.name = @TableName
AND sc.name = @SchemaName
AND c.is_computed = 0  -- skip computed columns
),
Types AS
(
SELECT
column_id,
ColName,
DefaultDef,
TypeDecl =
CASE
WHEN TypeName IN (N'nchar', N'nvarchar')
THEN TypeName + N'(' + CASE WHEN max_length = -1 THEN N'max' ELSE CONVERT(NVARCHAR(10), max_length/2) END + N')'
WHEN TypeName IN (N'char', N'varchar', N'binary', N'varbinary')
THEN TypeName + N'(' + CASE WHEN max_length = -1 THEN N'max' ELSE CONVERT(NVARCHAR(10), max_length) END + N')'
WHEN TypeName IN (N'decimal', N'numeric')
THEN TypeName + N'(' + CONVERT(NVARCHAR(10), precision) + N',' + CONVERT(NVARCHAR(10), scale) + N')'
ELSE TypeName
END
FROM Cols
)
SELECT @ColList =
STRING_AGG('
CAST(' +
COALESCE(NULLIF(DefaultDef, N''), N'NULL') +
N' AS ' + TypeDecl + N') AS ' + QUOTENAME(ColName)
, N', ')
WITHIN GROUP (ORDER BY column_id)
FROM Types;
-- If the table has zero (non-computed) columns (unlikely), fall back safely
IF @ColList IS NULL OR LTRIM(RTRIM(@ColList)) = N''
BEGIN
-- Return an empty result set with no columns
DECLARE @EmptySQL NVARCHAR(MAX) = N'SELECT TOP (0) * FROM ' + @FullName + N';';
EXEC sys.sp_executesql @EmptySQL;
END
ELSE
BEGIN
DECLARE @DefaultSQL NVARCHAR(MAX) = N'SELECT ' + @ColList + N' FROM (VALUES(1)) v(x);';
EXEC sys.sp_executesql @DefaultSQL;
END
RETURN;
END
----------------------------------------------------------------------
-- Branch 2: normal data retrieval
--  * 'ALL'    → all rows
--  * 'FILTER' → WHERE [@parxFilterField] = @p (parameterized)
----------------------------------------------------------------------
DECLARE @SQL NVARCHAR(MAX) = N'SELECT * FROM ' + @FullName;
IF @parxMode = N'FILTER'
BEGIN
-- Validate the column exists in the table
IF NOT EXISTS
(
SELECT 1
FROM sys.columns c
JOIN sys.tables t  ON t.object_id = c.object_id
JOIN sys.schemas s ON s.schema_id = t.schema_id
WHERE t.name = @TableName
AND s.name = @SchemaName
AND c.name = @parxFilterField
)
BEGIN
THROW 50003, 'Filter column not found in target table.', 1;
END
SET @SQL += N' WHERE ' + QUOTENAME(@parxFilterField) + N' = @p';
EXEC sys.sp_executesql @SQL, N'@p NVARCHAR(MAX)', @p = @parxFilterValue;
END
ELSE IF @parxMode = N'ALL'
BEGIN
EXEC sys.sp_executesql @SQL;
END
ELSE
BEGIN
THROW 50004, 'Invalid @parxMode. Use FILTER, DEFAULTS, or ALL.', 1;
END
END TRY
BEGIN CATCH
DECLARE @ErrorNumber INT = ERROR_NUMBER(),
@ErrorLine   INT = ERROR_LINE(),
@ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
RAISERROR('Error Number: %d, Row: %d, Message: %s', 16, 1, @ErrorNumber, @ErrorLine, @ErrorMessage);
THROW;
END CATCH
END
GO
-- END xPROC900_GetExtraFieldsData ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC900_DeleteExtraField
-- 26.06.26 03:45
-- PURPOSE: Return selected record to get Extra Fields values from there
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@parxTableName NVARCHAR(MAX),
@parxFilterField NVARCHAR(MAX)
AS
BEGIN
SET NOCOUNT ON;
SET XACT_ABORT ON;
DECLARE @SQL nvarchar(max);
DECLARE @ConstraintName sysname;
DECLARE @SchemaName sysname = ISNULL(PARSENAME(@parxTableName, 2), N'dbo');
DECLARE @TableName sysname = PARSENAME(@parxTableName, 1);
DECLARE @FullTableName nvarchar(517) = QUOTENAME(@SchemaName) + N'.' + QUOTENAME(@TableName);
BEGIN TRANSACTION;
BEGIN TRY
SELECT @ConstraintName = dc.name
FROM sys.default_constraints AS dc
INNER JOIN sys.columns AS c
ON c.column_id = dc.parent_column_id
AND c.object_id = dc.parent_object_id
INNER JOIN sys.tables AS t
ON t.object_id = dc.parent_object_id
INNER JOIN sys.schemas AS s
ON s.schema_id = t.schema_id
WHERE
s.name = @SchemaName
AND t.name = @TableName
AND c.name = @parxFilterField;
IF @ConstraintName IS NOT NULL
BEGIN
SET @SQL =
N'ALTER TABLE ' + @FullTableName +
N' DROP CONSTRAINT ' + QUOTENAME(@ConstraintName) + N';';
EXEC sys.sp_executesql @SQL;
END;
DECLARE UniqueConstraintCursor CURSOR LOCAL FAST_FORWARD FOR
SELECT uc.name
FROM sys.key_constraints AS uc
INNER JOIN sys.tables AS t
ON uc.parent_object_id = t.object_id
INNER JOIN sys.schemas AS s
ON s.schema_id = t.schema_id
INNER JOIN sys.index_columns AS ic
ON uc.unique_index_id = ic.index_id
AND uc.parent_object_id = ic.object_id
INNER JOIN sys.columns AS c
ON c.object_id = t.object_id
AND c.column_id = ic.column_id
WHERE
uc.type = 'UQ'
AND s.name = @SchemaName
AND t.name = @TableName
AND c.name = @parxFilterField;
OPEN UniqueConstraintCursor;
FETCH NEXT FROM UniqueConstraintCursor INTO @ConstraintName;
WHILE @@FETCH_STATUS = 0
BEGIN
SET @SQL =
N'ALTER TABLE ' + @FullTableName +
N' DROP CONSTRAINT ' + QUOTENAME(@ConstraintName) + N';';
EXEC sys.sp_executesql @SQL;
FETCH NEXT FROM UniqueConstraintCursor INTO @ConstraintName;
END;
CLOSE UniqueConstraintCursor;
DEALLOCATE UniqueConstraintCursor;
SET @SQL =
N'ALTER TABLE ' + @FullTableName +
N' DROP COLUMN ' + QUOTENAME(@parxFilterField) + N';';
EXEC sys.sp_executesql @SQL;
COMMIT TRANSACTION;
END TRY
BEGIN CATCH
IF CURSOR_STATUS('local', 'UniqueConstraintCursor') >= -1
BEGIN
CLOSE UniqueConstraintCursor;
DEALLOCATE UniqueConstraintCursor;
END;
IF @@TRANCOUNT > 0
ROLLBACK TRANSACTION;
THROW;
END CATCH;
END;
GO
-- END xPROC900_DeleteExtraField ----------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
-------------------------------------------------------------------------------------------------------------
SET ANSI_NULLS ON; SET QUOTED_IDENTIFIER ON;
GO
CREATE OR ALTER PROCEDURE 
xPROC910_RecompileDependentViews
-- 26.06.26 03:45
-- PURPOSE: Return selected record to get Extra Fields values from there
-- USAGE:
-- 10.) DECLARE, SELECT, CALCULATE
-- 91.) ERROR HANDLING
-------------------------------------------------------------------------------------------------------------
@TableName NVARCHAR(255) = ''
AS
BEGIN
DECLARE @viewName NVARCHAR(255)
DECLARE view_cursor CURSOR
FOR
SELECT name
FROM sys.VIEWS
WHERE (@TableName = '' OR OBJECT_DEFINITION(OBJECT_ID) LIKE '%' + @TableName + '%')
OPEN view_cursor
FETCH NEXT
FROM view_cursor
INTO @viewName
WHILE @@FETCH_STATUS = 0
BEGIN
EXEC sp_refreshview @viewName
FETCH NEXT
FROM view_cursor
INTO @viewName
END
CLOSE view_cursor
DEALLOCATE view_cursor
END
GO
-- END xPROC910_RecompileDependentViews ----------------------------------------------------------------------
