SET NOCOUNT ON;
SET DATEFIRST 1;
;WITH N AS
(
SELECT TOP (DATEDIFF(DAY, '2025-01-01', '2026-12-31') + 1)
ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1 AS n
FROM master..spt_values
)
, DateRange AS
(
SELECT
DATEADD(day, n, CAST('2025-01-01' AS date)) AS d
FROM N
)
INSERT INTO CalendarWorkingDay
(
CalendarNameId
, WorkingDayStart
, WorkingDayEnd
)
SELECT
1
, CASE
WHEN DATEPART(weekday, d) = 1 THEN DATEADD(hour, 8, CAST(d AS datetimeoffset(0)))  -- Monday     08:00
WHEN DATEPART(weekday, d) = 2 THEN DATEADD(hour, 8, CAST(d AS datetimeoffset(0)))  -- Tuesday    08:00
WHEN DATEPART(weekday, d) = 3 THEN DATEADD(hour, 8, CAST(d AS datetimeoffset(0)))  -- Wednesday  08:00
WHEN DATEPART(weekday, d) = 4 THEN DATEADD(hour, 8, CAST(d AS datetimeoffset(0)))  -- Thursday   08:00
WHEN DATEPART(weekday, d) = 5 THEN DATEADD(hour, 8, CAST(d AS datetimeoffset(0)))  -- Friday     08:00
WHEN DATEPART(weekday, d) = 6 THEN DATEADD(hour, 8, CAST(d AS datetimeoffset(0)))  -- Saturday   08:00
WHEN DATEPART(weekday, d) = 7 THEN DATEADD(hour, 8, CAST(d AS datetimeoffset(0)))  -- Sunday     08:00
ELSE NULL
END
, CASE
WHEN DATEPART(weekday, d) = 1 THEN DATEADD(hour, 16, CAST(d AS datetimeoffset(0))) -- Monday     16:00
WHEN DATEPART(weekday, d) = 2 THEN DATEADD(hour, 16, CAST(d AS datetimeoffset(0))) -- Tuesday    16:00
WHEN DATEPART(weekday, d) = 3 THEN DATEADD(hour, 16, CAST(d AS datetimeoffset(0))) -- Wednesday  16:00
WHEN DATEPART(weekday, d) = 4 THEN DATEADD(hour, 16, CAST(d AS datetimeoffset(0))) -- Thursday   16:00
WHEN DATEPART(weekday, d) = 5 THEN DATEADD(hour, 14, CAST(d AS datetimeoffset(0))) -- Friday     14:00
WHEN DATEPART(weekday, d) = 6 THEN DATEADD(hour, 10, CAST(d AS datetimeoffset(0))) -- Saturday   10:00
WHEN DATEPART(weekday, d) = 7 THEN DATEADD(hour, 10, CAST(d AS datetimeoffset(0))) -- Sunday     10:00
ELSE NULL
END
FROM DateRange
WHERE DATEPART(weekday, d) BETWEEN 1 AND 7;
SELECT
A.Id,
A.Name1,
A.Matchcode
FROM dbo.Article A
LEFT JOIN dbo.ArticlePriceCalculation APC ON A.Id = APC.ArticleId
WHERE APC.ArticleId IS NULL;
SELECT
A.Id,
A.Name1,
A.Matchcode
FROM dbo.Article A
LEFT JOIN dbo.ArticleQuantity AQ ON A.Id = AQ.ArticleId
WHERE AQ.ArticleId IS NULL;
